/* ── FIX GLOBAL NAVBAR + WORKSPACE STACK ── */

/* Remove fake full-screen behavior */
.workspace-page {
  min-height: 0 !important;
  height: auto !important;
}

/* Let workspace fill remaining space under navbar */
body {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

/* Assuming your global navbar is top-level */
body > *:not(.workspace-page) {
  flex-shrink: 0;
}

/* Workspace takes remaining space ONLY */
.workspace-page {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-height: 0;
}

/* Fix internal shell */
.workspace-page .wp-shell {
  height: 100%;
  min-height: 0;
}

/* Prevent internal overflow issues */
.workspace-page .wp-body,
.workspace-page .wp-main {
  min-height: 0;
}
