/* ── Favorite / workspace button ────────────────────────────── */
.favorite-btn {
  background: rgba(255,255,255,0.06);
  border: 1px solid rgba(255,255,255,0.1);
  color: #64748b;
  width: 32px;
  height: 32px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 0.8rem;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
  flex-shrink: 0;
}
.favorite-btn:hover {
  color: #facc15;
  border-color: #facc15;
  background: rgba(250,204,21,0.1);
}

/* ── Category tag inside card ────────────────────────────────── */
.tool-category {
  font-size: 0.72rem;
  font-weight: 500;
  color: #60a5fa;
  background: rgba(96,165,250,0.1);
  border-radius: 6px;
  padding: 2px 8px;
  display: inline-block;
  margin-bottom: 6px;
}

/* ── Tool description ────────────────────────────────────────── */
.tool-description {
  font-size: 0.82rem;
  color: #94a3b8;
  line-height: 1.5;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

/* ── Card footer ─────────────────────────────────────────────── */
.tool-footer {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: auto;
  padding-top: 12px;
  border-top: 1px solid rgba(255,255,255,0.06);
}

/* ── Details / Visit buttons ─────────────────────────────────── */
.details-btn {
  flex: 1;
  text-align: center;
  padding: 8px;
  border-radius: 8px;
  font-size: 0.8rem;
  font-weight: 500;
  color: #94a3b8;
  border: 1px solid rgba(255,255,255,0.1);
  background: transparent;
  text-decoration: none;
  transition: all 0.2s;
}
.details-btn:hover {
  border-color: #60a5fa;
  color: #60a5fa;
}
.visit-btn {
  flex: 1;
  text-align: center;
  padding: 8px;
  border-radius: 8px;
  font-size: 0.8rem;
  font-weight: 600;
  color: #fff;
  background: linear-gradient(135deg, #3b82f6, #8b5cf6);
  text-decoration: none;
  transition: opacity 0.2s, transform 0.1s;
}
.visit-btn:hover {
  opacity: 0.88;
  transform: translateY(-1px);
}

/* ── Like button ─────────────────────────────────────────────── */
.like-btn {
  display: flex;
  align-items: center;
  gap: 5px;
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.1);
  color: #94a3b8;
  font-family: 'Poppins', sans-serif;
  font-size: 0.78rem;
  padding: 7px 10px;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
}
.like-btn:hover,
.like-btn.liked {
  background: rgba(239,68,68,0.1);
  border-color: #ef4444;
  color: #ef4444;
}

/* ── Badge row ───────────────────────────────────────────────── */
.badge-row {
  position: absolute;
  top: 12px;
  right: 12px;
  display: flex;
  gap: 4px;
  z-index: 1;
}
.badge {
  font-size: 0.62rem;
  font-weight: 700;
  padding: 3px 7px;
  border-radius: 6px;
  letter-spacing: 0.02em;
}
.badge-trending { background: rgba(251,146,60,0.2);  color: #fb923c; border: 1px solid rgba(251,146,60,0.3); }
.badge-new      { background: rgba(34,197,94,0.15);  color: #22c55e; border: 1px solid rgba(34,197,94,0.25); }
.badge-popular  { background: rgba(167,139,250,0.15);color: #a78bfa; border: 1px solid rgba(167,139,250,0.25); }

/* ── Tools hero (override old) ───────────────────────────────── */
.tools-hero {
  text-align: center;
  padding: 48px 0 24px;
  margin-bottom: 0;
}
.tools-hero h1 {
  font-size: clamp(1.8rem, 4vw, 2.8rem);
  font-weight: 700;
  background: linear-gradient(135deg, #60a5fa, #a78bfa, #f472b6);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 8px;
}
.tools-hero p { color: #94a3b8; font-size: 1rem; }

/* ── Search wrapper ──────────────────────────────────────────── */
.search-wrapper {
  display: flex;
  align-items: center;
  background: rgba(255,255,255,0.05);
  border: 1.5px solid rgba(255,255,255,0.12);
  border-radius: 14px;
  padding: 0 16px;
  max-width: 700px;
  margin: 0 auto 20px;
  transition: border-color 0.2s, box-shadow 0.2s;
}
.search-wrapper:focus-within {
  border-color: #60a5fa;
  box-shadow: 0 0 0 3px rgba(96,165,250,0.15);
}
.search-wrapper .search-icon {
  color: #64748b;
  font-size: 1rem;
  margin-right: 10px;
  flex-shrink: 0;
}
.search-wrapper input {
  flex: 1;
  background: transparent;
  border: none;
  outline: none;
  color: #f1f5f9;
  font-family: 'Poppins', sans-serif;
  font-size: 0.95rem;
  padding: 14px 0;
}
.search-wrapper input::placeholder { color: #475569; }
.search-btn {
  background: linear-gradient(135deg, #3b82f6, #8b5cf6);
  border: none;
  color: #fff;
  font-family: 'Poppins', sans-serif;
  font-size: 0.85rem;
  font-weight: 600;
  padding: 8px 18px;
  border-radius: 9px;
  cursor: pointer;
  transition: opacity 0.2s, transform 0.1s;
  flex-shrink: 0;
}
.search-btn:hover { opacity: 0.9; transform: translateY(-1px); }

/* ── Live search suggestions ─────────────────────────────────── */
.search-pos { position: relative; flex: 1; }
.search-suggestions {
  position: absolute;
  top: calc(100% + 6px);
  left: 0; right: 0;
  background: #1e2535;
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 12px;
  overflow: hidden;
  z-index: 200;
  box-shadow: 0 12px 40px rgba(0,0,0,0.4);
}
.suggestion-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 16px;
  text-decoration: none;
  transition: background 0.15s;
}
.suggestion-item:hover { background: rgba(255,255,255,0.06); }
.suggestion-item img   { width: 28px; height: 28px; border-radius: 6px; object-fit: cover; }
.suggestion-item span  { font-size: 0.85rem; color: #e2e8f0; }
.suggestion-item small { font-size: 0.72rem; color: #60a5fa; margin-left: auto; }

/* ── Sort bar ────────────────────────────────────────────────── */
.sort-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  max-width: 700px;
  margin: 0 auto 20px;
  flex-wrap: wrap;
}
.sort-label { color: #64748b; font-size: 0.78rem; font-weight: 500; white-space: nowrap; }
.sort-btn {
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.1);
  color: #94a3b8;
  font-family: 'Poppins', sans-serif;
  font-size: 0.78rem;
  padding: 5px 13px;
  border-radius: 20px;
  cursor: pointer;
  transition: all 0.2s;
}
.sort-btn:hover,
.sort-btn.active {
  background: rgba(96,165,250,0.15);
  border-color: #60a5fa;
  color: #60a5fa;
}

/* ── Category filter pills (override old) ────────────────────── */
.category-filter {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  justify-content: center;
  margin-bottom: 32px;
}
.category-btn {
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.1);
  color: #94a3b8;
  font-family: 'Poppins', sans-serif;
  font-size: 0.8rem;
  font-weight: 500;
  padding: 6px 16px;
  border-radius: 20px;
  text-decoration: none;
  transition: all 0.2s;
  cursor: pointer;
}
.category-btn:hover,
.category-btn.active {
  background: rgba(96,165,250,0.15);
  border-color: #60a5fa;
  color: #60a5fa;
}

/* ── AI Recommend box (override old) ─────────────────────────── */
.ai-recommend-box {
  background: linear-gradient(135deg, rgba(96,165,250,0.08), rgba(167,139,250,0.08));
  border: 1px solid rgba(96,165,250,0.2);
  border-radius: 16px;
  padding: 24px;
  margin-bottom: 32px;
}
.ai-recommend-box h2 {
  font-size: 1.1rem;
  font-weight: 600;
  color: #e2e8f0;
  margin-bottom: 4px;
}
.ai-recommend-box > p { color: #64748b; font-size: 0.85rem; margin-bottom: 16px; }
.ai-recommend-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: 12px;
}
.ai-rec-card {
  display: flex;
  align-items: center;
  gap: 12px;
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 10px;
  padding: 12px;
  text-decoration: none;
  transition: all 0.2s;
}
.ai-rec-card:hover {
  background: rgba(255,255,255,0.08);
  border-color: rgba(96,165,250,0.3);
  transform: translateY(-2px);
}
.ai-rec-card img    { width: 36px; height: 36px; border-radius: 8px; object-fit: cover; flex-shrink: 0; }
.ai-rec-info        { flex: 1; min-width: 0; }
.ai-rec-info h4     { font-size: 0.85rem; font-weight: 600; color: #e2e8f0; margin: 0 0 2px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.ai-rec-info p      { font-size: 0.72rem; color: #64748b; margin: 0; }
.ai-rec-use         { font-size: 0.72rem; font-weight: 600; color: #60a5fa; white-space: nowrap; flex-shrink: 0; }

/* ── Trending strip (tools page) ─────────────────────────────── */
.trending-section   { margin-bottom: 32px; }
.section-header     { display: flex; align-items: center; justify-content: space-between; margin-bottom: 16px; }
.section-header h2  { font-size: 1.1rem; font-weight: 600; color: #e2e8f0; }
.section-header a   { font-size: 0.8rem; color: #60a5fa; text-decoration: none; }
.section-header a:hover { text-decoration: underline; }
.trending-strip {
  display: flex;
  gap: 12px;
  overflow-x: auto;
  padding-bottom: 8px;
  scrollbar-width: thin;
  scrollbar-color: rgba(255,255,255,0.1) transparent;
}
.trending-strip::-webkit-scrollbar         { height: 4px; }
.trending-strip::-webkit-scrollbar-thumb   { background: rgba(255,255,255,0.1); border-radius: 4px; }
.trending-chip {
  display: flex;
  align-items: center;
  gap: 8px;
  background: rgba(251,146,60,0.1);
  border: 1px solid rgba(251,146,60,0.25);
  border-radius: 10px;
  padding: 8px 14px;
  text-decoration: none;
  flex-shrink: 0;
  transition: all 0.2s;
}
.trending-chip:hover   { background: rgba(251,146,60,0.18); transform: translateY(-1px); }
.trending-chip img     { width: 26px; height: 26px; border-radius: 6px; object-fit: cover; }
.trending-chip span    { font-size: 0.82rem; font-weight: 500; color: #fde68a; }

/* ── Tools grid ──────────────────────────────────────────────── */
.tools-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 20px;
  margin-bottom: 48px;
}

/* ── No tools empty state ────────────────────────────────────── */
.no-tools { grid-column: 1/-1; text-align: center; padding: 60px 20px; color: #475569; }
.no-tools i   { font-size: 2.5rem; margin-bottom: 16px; display: block; }
.no-tools h3  { font-size: 1.1rem; color: #64748b; margin-bottom: 8px; }

/* ── Trending page ───────────────────────────────────────────── */
.trending-hero        { text-align: center; padding: 48px 0 32px; }
.trending-hero h1     { font-size: clamp(1.8rem,4vw,2.8rem); font-weight: 700; margin-bottom: 8px; color: #f1f5f9; }
.trending-hero h1 span {
  background: linear-gradient(135deg, #fb923c, #f472b6);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.trending-hero p      { color: #94a3b8; font-size: 0.95rem; }

.live-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  background: rgba(239,68,68,0.12);
  border: 1px solid rgba(239,68,68,0.25);
  color: #f87171;
  font-size: 0.72rem;
  font-weight: 600;
  padding: 4px 12px;
  border-radius: 20px;
  margin-top: 12px;
}
.live-dot {
  width: 7px;
  height: 7px;
  background: #ef4444;
  border-radius: 50%;
  animation: livepulse 1.2s ease-in-out infinite;
}
@keyframes livepulse {
  0%,100% { opacity:1; transform:scale(1); }
  50%      { opacity:.5; transform:scale(.85); }
}

.trending-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 20px;
  margin-bottom: 48px;
}

.trend-card {
  background: rgba(255,255,255,0.03);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 18px;
  padding: 22px;
  display: flex;
  flex-direction: column;
  gap: 14px;
  position: relative;
  overflow: hidden;
  transition: all 0.25s;
}
.trend-card:hover        { transform: translateY(-4px); box-shadow: 0 16px 48px rgba(0,0,0,0.35); }
.trend-card:nth-child(1) { border-color: rgba(251,191,36,0.25); }
.trend-card:nth-child(1):hover { box-shadow: 0 16px 48px rgba(251,191,36,0.12); }
.trend-card:nth-child(2) { border-color: rgba(148,163,184,0.2); }
.trend-card:nth-child(3) { border-color: rgba(251,146,60,0.2); }
.trend-card:nth-child(3):hover { box-shadow: 0 16px 48px rgba(251,146,60,0.1); }

.card-header  { display: flex; align-items: center; gap: 14px; }

/* Rank badge (override old .rank) */
.rank-badge {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  border-radius: 12px;
  font-size: 1rem;
  font-weight: 800;
  flex-shrink: 0;
}
.rank-1     { background: linear-gradient(135deg,#fbbf24,#f59e0b); color: #1a1a1a; }
.rank-2     { background: linear-gradient(135deg,#94a3b8,#64748b); color: #fff; }
.rank-3     { background: linear-gradient(135deg,#fb923c,#ea580c); color: #fff; }
.rank-other { background: rgba(255,255,255,0.07); color: #64748b; font-size: 0.85rem; }

.tool-logo-wrap             { position: relative; flex-shrink: 0; }
.tool-logo-wrap img         { width: 52px; height: 52px; border-radius: 14px; object-fit: cover; border: 1px solid rgba(255,255,255,0.1); }
.trending-fire              { position: absolute; bottom: -4px; right: -4px; font-size: 0.75rem; line-height: 1; background: #1a1a2e; border-radius: 50%; padding: 2px; }

.card-meta      { flex: 1; min-width: 0; }
.card-meta h3   { font-size: 1rem; font-weight: 600; color: #f1f5f9; margin: 0 0 4px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.card-meta .cat-tag { font-size: 0.7rem; font-weight: 500; color: #60a5fa; background: rgba(96,165,250,0.1); border-radius: 6px; padding: 2px 8px; display: inline-block; }

.score-row      { display: flex; align-items: center; gap: 8px; }
.score-bar-wrap { flex: 1; height: 4px; background: rgba(255,255,255,0.08); border-radius: 4px; overflow: hidden; }
.score-bar      { height: 100%; border-radius: 4px; background: linear-gradient(90deg,#fb923c,#f472b6); transition: width 0.6s ease; }
.score-label    { font-size: 0.72rem; color: #94a3b8; white-space: nowrap; }
.score-value    { font-size: 0.72rem; font-weight: 600; color: #fb923c; white-space: nowrap; }

.card-desc {
  font-size: 0.82rem;
  color: #94a3b8;
  line-height: 1.55;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.card-footer {
  display: flex;
  align-items: center;
  gap: 8px;
  padding-top: 12px;
  border-top: 1px solid rgba(255,255,255,0.06);
  margin-top: auto;
}
.open-btn {
  flex: 1.4;
  text-align: center;
  padding: 9px;
  border-radius: 9px;
  font-size: 0.8rem;
  font-weight: 700;
  color: #fff;
  background: linear-gradient(135deg,#fb923c,#f472b6);
  text-decoration: none;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  transition: opacity 0.2s, transform 0.1s;
}
.open-btn:hover { opacity: 0.88; transform: translateY(-1px); }
.stat-chip {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 0.72rem;
  color: #64748b;
  padding: 8px 10px;
  border-radius: 9px;
  border: 1px solid rgba(255,255,255,0.07);
  white-space: nowrap;
}

/* Old .rank override (trending page used old class) */
.rank {
  background: linear-gradient(135deg,#fbbf24,#f59e0b);
  color: #1a1a1a;
  font-size: 0.75rem;
  font-weight: 800;
  padding: 4px 10px;
  border-radius: 8px;
}

/* click-count upgrade */
.click-count { font-size: 0.75rem; color: #fb923c; font-weight: 500; margin-top: 4px; }

/* ── Empty state (trending) ──────────────────────────────────── */
.empty-state      { text-align: center; padding: 80px 20px; color: #475569; }
.empty-state i    { font-size: 3rem; margin-bottom: 20px; display: block; opacity: 0.4; }
.empty-state h3   { font-size: 1.2rem; color: #64748b; margin-bottom: 8px; }
.empty-state p    { font-size: 0.85rem; }
.empty-state a    { color: #60a5fa; text-decoration: none; }
.empty-state a:hover { text-decoration: underline; }

/* ── Responsive ──────────────────────────────────────────────── */
@media (max-width: 768px) {
  .tools-grid, .trending-grid { grid-template-columns: repeat(auto-fill, minmax(260px, 1fr)); }
  .ai-recommend-grid { grid-template-columns: 1fr 1fr; }
  .sort-bar { justify-content: flex-start; }
}
@media (max-width: 480px) {
  .tools-grid, .trending-grid { grid-template-columns: 1fr; }
  .ai-recommend-grid { grid-template-columns: 1fr; }
  .tool-footer { flex-wrap: wrap; }
  .like-btn { flex: 1 0 100%; justify-content: center; }
}

/* 🔥 TOOL PAGE CLICK FIX (CRITICAL) */
.tool-card,
.tool-footer,
.details-btn,
.visit-btn,
.like-btn,
.favorite-btn {
  position: relative !important;
  z-index: 50 !important;
  pointer-events: auto !important;
}

/* prevent overlays blocking */
.tools-grid,
.container,
.section {
  z-index: 1;
}
/* ==========================================================
   AQUIPLEX — RESPONSIVE OVERRIDES (mobile-first fixes)
   Targets: 320px, 375px, 414px, 768px, 1024px
   ========================================================== */

/* ── Prevent ALL horizontal overflow globally ── */
html, body {
  max-width: 100%;
  overflow-x: hidden;
}

/* ── Header: prevent overflow, ensure logo shrinks ── */
.main-header {
  overflow: visible;
}
.header-container {
  overflow: visible;
  flex-wrap: nowrap;
  min-width: 0;
}
.logo {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 0;
  flex-shrink: 0;
}
.logo-img {
  width: 28px;
  height: 28px;
  flex-shrink: 0;
  object-fit: contain;
}
.logo-text {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* ── Mobile menu: proper positioning and scroll ── */
.mobile-menu {
  position: absolute !important;
  top: 70px;
  left: 0;
  width: 100%;
  max-height: calc(100vh - 70px);
  overflow-y: auto;
  overflow-x: hidden;
  box-sizing: border-box;
  z-index: 9998;
  border-top: 1px solid rgba(255,255,255,0.07);
  border-bottom: 1px solid rgba(255,255,255,0.07);
}

/* ── Nav-more dropdown z-index fix ── */
.nav-more { z-index: 100; }
.dropdown  { z-index: 10000; }

/* ── Grid: prevent minmax overflow on tiny screens ── */
.grid {
  grid-template-columns: repeat(auto-fill, minmax(min(240px, 100%), 1fr));
}
.tools-grid {
  grid-template-columns: repeat(auto-fill, minmax(min(280px, 100%), 1fr));
}
.trending-grid {
  grid-template-columns: repeat(auto-fill, minmax(min(300px, 100%), 1fr));
}

/* ── Container fluid on small screens ── */
.container {
  width: 100%;
  box-sizing: border-box;
}
.tool-page {
  box-sizing: border-box;
  width: 100%;
}

/* ── Card buttons: touch-friendly min sizes ── */
.details-btn,
.visit-btn,
.like-btn,
.favorite-btn,
.open-btn {
  min-height: 36px;
  min-width: 44px;
}

/* ── Trending chip strip: no overflow ── */
.trending-strip {
  max-width: 100%;
}

/* ── Sort bar: prevent overflow ── */
.sort-bar {
  max-width: 100%;
  box-sizing: border-box;
}

/* ─────────────────────────────────────────
   768px — tablet
───────────────────────────────────────── */
@media (max-width: 768px) {
  /* header-actions fully hidden, only logo + toggle visible */
  .header-container { padding: 0 14px; gap: 10px; }

  /* Ensure mobile menu full-width with comfortable tap targets */
  .mobile-menu { padding: 16px 14px; gap: 10px; }
  .mobile-menu a { font-size: 15px; padding: 12px 10px; min-height: 44px; display: flex; align-items: center; }

  /* tool cards 2-col on tablet */
  .tools-grid, .trending-grid {
    grid-template-columns: repeat(auto-fill, minmax(min(220px, 100%), 1fr));
  }

  /* hero text size */
  .hero h1 { font-size: clamp(26px, 7vw, 36px); }

  /* ai-recommend-grid already 1x1 in existing rules; ensure no bleed */
  .ai-recommend-grid { max-width: 100%; }
}

/* ─────────────────────────────────────────
   480px — large phone
───────────────────────────────────────── */
@media (max-width: 480px) {
  .container { padding: 16px; }
  .tool-page  { padding: 24px 16px; }

  /* 1-col grids */
  .tools-grid, .trending-grid, .grid {
    grid-template-columns: 1fr;
  }

  /* card buttons full row on small phones */
  .tool-actions { flex-wrap: wrap; }
  .details-btn, .visit-btn { flex: 1 1 calc(50% - 5px); text-align: center; }

  /* card footer wrap */
  .card-footer { flex-wrap: wrap; gap: 6px; }
  .open-btn { flex: 1 1 100%; }

  /* hero text */
  .hero h1 { font-size: clamp(22px, 8vw, 28px); }
  .hero { padding: 80px 16px 40px; }

  /* section headings */
  .section h2 { font-size: clamp(18px, 6vw, 24px); }
}

/* ─────────────────────────────────────────
   375px — standard phone
───────────────────────────────────────── */
@media (max-width: 375px) {
  .header-container { padding: 0 12px; }
  .logo-text { font-size: 16px; }
  .container { padding: 12px; }
  .tool-card { padding: 14px 12px; }
  .btn { padding: 8px 10px; font-size: 12px; }
  .trend-card { padding: 16px; }

  /* stat chips: smaller */
  .stat-chip { padding: 6px 8px; font-size: 0.68rem; }

  /* nav plan badge: hide on very small screens */
  .nav-plan-badge { display: none; }
}

/* ─────────────────────────────────────────
   320px — minimum supported width
───────────────────────────────────────── */
@media (max-width: 320px) {
  .header-container { padding: 0 10px; }
  .logo-text { font-size: 14px; }
  .container { padding: 10px; }
  .tool-card { padding: 12px 10px; }

  /* hide upgrade link to save space */
  .nav-upgrade-link { display: none; }
}

/* ============================================================
   AQUIPLEX — LANDING PAGE CSS v3 · CINEMATIC EDITION
   Premium AI OS · Mobile-First · Futuristic
   ============================================================ */

@import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;500;600;700;800&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;1,9..40,300&display=swap');

/* ===== RESET ===== */
*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

/* ===== TOKENS ===== */
:root {
  --bg:             #03040d;
  --bg-deep:        #01020a;
  --bg-elevated:    #070a1a;
  --panel:          rgba(7, 10, 26, 0.6);
  --panel-hover:    rgba(10, 14, 35, 0.85);

  --cyan:           #00e5ff;
  --cyan-dim:       #00b8d4;
  --blue:           #4488ff;
  --indigo:         #5c6ef8;
  --violet:         #9b6dff;
  --teal:           #00d4aa;

  --cyan-05:        rgba(0, 229, 255, 0.05);
  --cyan-08:        rgba(0, 229, 255, 0.08);
  --cyan-12:        rgba(0, 229, 255, 0.12);
  --cyan-20:        rgba(0, 229, 255, 0.20);
  --cyan-35:        rgba(0, 229, 255, 0.35);
  --cyan-50:        rgba(0, 229, 255, 0.50);

  --border:         rgba(0, 229, 255, 0.08);
  --border-md:      rgba(0, 229, 255, 0.16);
  --border-hi:      rgba(0, 229, 255, 0.32);

  --text:           #e8f4ff;
  --text-2:         rgba(190, 215, 240, 0.60);
  --text-3:         rgba(140, 175, 215, 0.35);

  --font-display:   'Syne', system-ui, sans-serif;
  --font-body:      'DM Sans', system-ui, sans-serif;

  --ease-out:       cubic-bezier(0.16, 1, 0.3, 1);
  --ease-in-out:    cubic-bezier(0.45, 0, 0.25, 1);
  --ease-spring:    cubic-bezier(0.34, 1.56, 0.64, 1);
  --t-fast:         0.15s;
  --t-mid:          0.28s;
  --t-slow:         0.55s;

  --r-sm:           8px;
  --r-md:           12px;
  --r-lg:           18px;
  --r-xl:           28px;
  --r-pill:         100px;
}

/* ===== BASE ===== */
html {
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  max-width: 100vw;
  overflow-x: clip;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font-body);
  font-size: 15px;
  line-height: 1.65;
  overflow-x: hidden;
  min-height: 100vh;
  max-width: 100vw;
}

*, *::before, *::after {
  max-width: 100%;
}

/* ===== FIXED BACKGROUND CANVAS ===== */
.bg-canvas {
  position: fixed;
  inset: 0;
  z-index: -10;
  overflow: hidden;
  pointer-events: none;
}

.bg-base {
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse 80% 60% at 20% 0%,   rgba(0, 100, 255, 0.12) 0%, transparent 55%),
    radial-gradient(ellipse 60% 50% at 80% 90%,   rgba(120, 80, 255, 0.10) 0%, transparent 55%),
    radial-gradient(ellipse 100% 80% at 50% 50%,  #050815 0%, var(--bg) 100%);
}

.bg-grid {
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(0, 229, 255, 0.04) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0, 229, 255, 0.04) 1px, transparent 1px);
  background-size: 60px 60px;
  mask-image: radial-gradient(ellipse 90% 80% at 50% 25%, black 10%, transparent 100%);
  animation: gridDrift 30s linear infinite;
}

@keyframes gridDrift {
  0%   { background-position: 0 0; }
  100% { background-position: 60px 60px; }
}

.orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  will-change: transform;
  filter: blur(80px);
}

.orb-1 {
  width: min(900px, 120vw);
  height: min(900px, 120vw);
  background: radial-gradient(circle, rgba(0, 100, 255, 0.18) 0%, transparent 60%);
  top: -350px;
  left: -250px;
  animation: orbA 22s var(--ease-in-out) infinite alternate;
}

.orb-2 {
  width: min(700px, 110vw);
  height: min(700px, 110vw);
  background: radial-gradient(circle, rgba(100, 80, 255, 0.14) 0%, transparent 60%);
  bottom: -200px;
  right: -200px;
  animation: orbB 28s var(--ease-in-out) infinite alternate;
}

.orb-3 {
  width: min(500px, 80vw);
  height: min(500px, 80vw);
  background: radial-gradient(circle, rgba(0, 229, 255, 0.09) 0%, transparent 60%);
  top: 55%;
  left: 55%;
  animation: orbA 18s var(--ease-in-out) infinite alternate-reverse;
}

.orb-4 {
  width: min(400px, 70vw);
  height: min(400px, 70vw);
  background: radial-gradient(circle, rgba(0, 200, 150, 0.07) 0%, transparent 60%);
  top: 30%;
  right: -100px;
  animation: orbB 24s var(--ease-in-out) infinite alternate;
}

@keyframes orbA {
  0%   { transform: translate(0, 0) scale(1); }
  100% { transform: translate(60px, 40px) scale(1.08); }
}
@keyframes orbB {
  0%   { transform: translate(0, 0) scale(1); }
  100% { transform: translate(-50px, -35px) scale(1.06); }
}

.noise {
  position: absolute;
  inset: 0;
  pointer-events: none;
  opacity: 0.025;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 512 512' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.75' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  background-size: 200px;
}

/* ===== PARTICLES ===== */
.particles {
  position: fixed;
  inset: 0;
  z-index: -7;
  pointer-events: none;
  overflow: hidden;
  max-width: 100vw;
}

.particles span {
  position: absolute;
  background: var(--cyan);
  border-radius: 50%;
  opacity: 0;
  animation: rise linear infinite;
  box-shadow: 0 0 8px rgba(0, 229, 255, 0.7), 0 0 20px rgba(0, 229, 255, 0.3);
}

@keyframes rise {
  0%   { opacity: 0; transform: translateY(60px) scale(0.4); }
  8%   { opacity: 0.7; }
  50%  { opacity: 0.3; }
  92%  { opacity: 0.15; }
  100% { opacity: 0; transform: translateY(-70vh) scale(1.4); }
}

/* ===== CURSOR GLOW ===== */
.cursor-glow {
  position: fixed;
  width: 380px;
  height: 380px;
  background: radial-gradient(circle, rgba(0, 229, 255, 0.06), transparent 65%);
  pointer-events: none;
  border-radius: 50%;
  transform: translate(-50%, -50%);
  z-index: 1;
  will-change: left, top;
  transition: opacity 0.3s;
}

/* ===== ENTRANCE ANIMATIONS ===== */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(28px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}

@keyframes scaleIn {
  from { opacity: 0; transform: scale(0.94) translateY(16px); }
  to   { opacity: 1; transform: scale(1) translateY(0); }
}

[style*="--d"] {
  opacity: 0;
  animation: fadeUp 0.8s var(--ease-out) forwards;
}

[style*="--d:0"] { animation-delay: 0.08s; }
[style*="--d:1"] { animation-delay: 0.20s; }
[style*="--d:2"] { animation-delay: 0.34s; }
[style*="--d:3"] { animation-delay: 0.50s; }
[style*="--d:4"] { animation-delay: 0.68s; }
[style*="--d:5"] { animation-delay: 0.88s; }

/* ===== SCROLL REVEAL ===== */
.reveal {
  opacity: 0;
  transform: translateY(32px);
  transition: opacity 0.7s var(--ease-out), transform 0.7s var(--ease-out);
  transition-delay: var(--sd, 0s);
}

.reveal.visible {
  opacity: 1;
  transform: translateY(0);
}

/* ===== NAVBAR ===== */
.navbar {
  position: fixed;
  width: 100%;
  top: 0;
  z-index: 1000;
  height: 60px;
  padding: 0 clamp(16px, 4vw, 32px);
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: transparent;
  transition: background var(--t-mid) var(--ease-in-out),
              border-color var(--t-mid),
              backdrop-filter var(--t-mid);
  border-bottom: 1px solid transparent;
}

.navbar.scrolled {
  background: rgba(3, 4, 13, 0.80);
  backdrop-filter: blur(28px);
  -webkit-backdrop-filter: blur(28px);
  border-bottom-color: var(--border);
}

.logo {
  display: flex;
  align-items: center;
  gap: 9px;
  text-decoration: none;
  flex-shrink: 0;
}

.logo img {
  height: 28px;
  object-fit: contain;
  filter: drop-shadow(0 0 10px rgba(0, 229, 255, 0.5));
  transition: filter var(--t-mid);
}

.logo:hover img {
  filter: drop-shadow(0 0 18px rgba(0, 229, 255, 0.85));
}

.nav-wordmark {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 15px;
  letter-spacing: 0.02em;
  color: var(--text);
}

.nav-tag {
  font-size: 8.5px;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--cyan);
  border: 1px solid var(--cyan-20);
  background: var(--cyan-05);
  padding: 2px 7px;
  border-radius: 4px;
  opacity: 0.75;
}

.nav-links {
  display: flex;
  align-items: center;
  gap: 2px;
}

.nav-link {
  padding: 7px 13px;
  border-radius: var(--r-sm);
  color: var(--text-2);
  text-decoration: none;
  font-family: var(--font-body);
  font-size: 13px;
  font-weight: 400;
  transition: color var(--t-fast), background var(--t-fast);
}

.nav-link:hover {
  color: var(--text);
  background: var(--cyan-05);
}

.nav-buttons {
  display: flex;
  gap: 8px;
  align-items: center;
}

.btn-ghost {
  padding: 8px 17px;
  border-radius: var(--r-sm);
  color: var(--text-2);
  text-decoration: none;
  font-family: var(--font-body);
  font-size: 13px;
  font-weight: 400;
  background: transparent;
  border: 1px solid transparent;
  transition: color var(--t-fast), border-color var(--t-fast), background var(--t-fast);
  cursor: pointer;
  white-space: nowrap;
}

.btn-ghost:hover {
  color: var(--text);
  border-color: var(--border-md);
  background: var(--cyan-05);
}

.btn-nav-cta {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 8px 18px;
  border-radius: var(--r-sm);
  background: linear-gradient(135deg, rgba(0,229,255,0.12), rgba(90,100,255,0.12));
  border: 1px solid var(--border-md);
  color: var(--cyan);
  text-decoration: none;
  font-family: var(--font-display);
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.01em;
  transition: all var(--t-mid) var(--ease-out);
  cursor: pointer;
  white-space: nowrap;
  position: relative;
  overflow: hidden;
}

.btn-nav-cta::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(0,229,255,0.12), rgba(90,100,255,0.12));
  opacity: 0;
  transition: opacity var(--t-fast);
}

.btn-nav-cta:hover {
  border-color: var(--border-hi);
  box-shadow: 0 0 24px rgba(0,229,255,0.2);
  transform: translateY(-1px);
}

.btn-nav-cta:hover::before { opacity: 1; }

.btn-arrow {
  transition: transform var(--t-fast) var(--ease-out);
  display: inline-block;
}

.btn-nav-cta:hover .btn-arrow { transform: translateX(3px); }

/* ===== HERO ===== */
.hero {
  min-height: 100vh;
  min-height: 100dvh;
  display: grid;
  grid-template-columns: 1fr 1fr;
  align-items: center;
  gap: 0;
  padding: 100px clamp(24px, 6vw, 80px) 60px;
  position: relative;
  overflow: hidden;
}

.hero-left {
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: flex-start;
  gap: 0;
  max-width: 580px;
}

.hero-right {
  display: flex;
  justify-content: center;
  align-items: center;
  position: relative;
}

/* Announce pill */
.hero-announce {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 6px 14px 6px 10px;
  border-radius: var(--r-pill);
  background: rgba(0, 229, 255, 0.05);
  border: 1px solid var(--border-md);
  color: var(--text-2);
  font-family: var(--font-body);
  font-size: 12.5px;
  font-weight: 400;
  letter-spacing: 0.01em;
  margin-bottom: 28px;
  backdrop-filter: blur(8px);
  position: relative;
  overflow: hidden;
}

.hero-announce::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, transparent, rgba(0,229,255,0.04), transparent);
  animation: shimmer 3s ease infinite;
}

@keyframes shimmer {
  0%   { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

.announce-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--cyan);
  box-shadow: 0 0 10px var(--cyan);
  flex-shrink: 0;
  animation: pulse-dot 2.5s ease infinite;
}

@keyframes pulse-dot {
  0%, 100% { opacity: 1; box-shadow: 0 0 10px var(--cyan); }
  50%       { opacity: 0.6; box-shadow: 0 0 4px var(--cyan); }
}

.announce-text {
  color: rgba(0, 229, 255, 0.85);
  font-weight: 500;
}

/* Hero title */
.hero-title {
  font-family: var(--font-display);
  font-size: clamp(2.8rem, 5.5vw, 5rem);
  font-weight: 800;
  line-height: 1.05;
  letter-spacing: -0.025em;
  color: var(--text);
  margin-bottom: 24px;
  max-width: 520px;
}

.hero-title .line-1 {
  display: block;
  color: var(--text);
}

.hero-title .line-accent {
  display: block;
  background: linear-gradient(135deg, var(--cyan) 0%, var(--blue) 40%, var(--violet) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  position: relative;
}

/* Hero sub */
.hero-sub {
  font-family: var(--font-body);
  font-size: clamp(1rem, 1.8vw, 1.15rem);
  font-weight: 300;
  color: var(--text-2);
  line-height: 1.7;
  max-width: 440px;
  margin-bottom: 40px;
}

/* CTAs */
.hero-ctas {
  display: flex;
  align-items: center;
  gap: 14px;
  flex-wrap: wrap;
  margin-bottom: 44px;
}

.btn-primary {
  display: inline-flex;
  align-items: center;
  gap: 9px;
  padding: 14px 28px;
  border-radius: var(--r-md);
  background: linear-gradient(135deg, var(--cyan) 0%, var(--blue) 100%);
  color: #03040d;
  font-family: var(--font-display);
  font-size: 14px;
  font-weight: 700;
  letter-spacing: 0.01em;
  text-decoration: none;
  border: none;
  cursor: pointer;
  transition: all var(--t-mid) var(--ease-out);
  position: relative;
  overflow: hidden;
  box-shadow: 0 0 0 0 rgba(0,229,255,0);
}

.btn-primary::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(255,255,255,0.15), transparent);
  opacity: 0;
  transition: opacity var(--t-fast);
}

.btn-primary:hover {
  transform: translateY(-2px) scale(1.02);
  box-shadow: 0 8px 32px rgba(0,229,255,0.4), 0 0 0 1px rgba(0,229,255,0.2);
}

.btn-primary:hover::after { opacity: 1; }
.btn-primary:active { transform: translateY(0) scale(0.99); }

.btn-secondary {
  display: inline-flex;
  align-items: center;
  gap: 9px;
  padding: 13px 26px;
  border-radius: var(--r-md);
  background: transparent;
  border: 1px solid var(--border-md);
  color: var(--text);
  font-family: var(--font-display);
  font-size: 14px;
  font-weight: 600;
  letter-spacing: 0.01em;
  text-decoration: none;
  cursor: pointer;
  transition: all var(--t-mid) var(--ease-out);
  backdrop-filter: blur(8px);
}

.btn-secondary:hover {
  border-color: var(--border-hi);
  background: var(--cyan-05);
  box-shadow: 0 4px 24px rgba(0,229,255,0.10);
  transform: translateY(-1px);
}

.btn-secondary svg {
  transition: transform var(--t-fast) var(--ease-out);
}
.btn-secondary:hover svg { transform: translateX(3px); }

/* Hero metrics strip */
.hero-metrics {
  display: flex;
  align-items: center;
  gap: 28px;
  padding-top: 8px;
}

.metric-item {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.metric-val {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 700;
  color: var(--text);
  line-height: 1;
}

.metric-label {
  font-size: 11px;
  font-weight: 400;
  color: var(--text-3);
  letter-spacing: 0.02em;
}

.metric-sep {
  width: 1px;
  height: 28px;
  background: var(--border);
  flex-shrink: 0;
}

/* ===== HERO VISUAL (animated AI window) ===== */
.hero-visual {
  position: relative;
  width: 100%;
  max-width: 560px;
  animation: heroFloat 6s var(--ease-in-out) infinite alternate;
  opacity: 0;
  animation: heroFloat 6s var(--ease-in-out) 0.9s infinite alternate, fadeUp 0.9s var(--ease-out) 0.9s forwards;
}

@keyframes heroFloat {
  0%   { transform: translateY(0px) rotate(0deg); }
  100% { transform: translateY(-14px) rotate(0.4deg); }
}

.visual-window {
  background: rgba(7, 10, 26, 0.7);
  border: 1px solid var(--border-md);
  border-radius: var(--r-xl);
  padding: 0;
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  overflow: hidden;
  box-shadow:
    0 0 0 1px rgba(0,229,255,0.06),
    0 32px 80px rgba(0,0,0,0.6),
    0 0 80px rgba(0, 100, 255, 0.08),
    inset 0 1px 0 rgba(255,255,255,0.06);
  position: relative;
}

.visual-window::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(0,229,255,0.4), transparent);
}

.visual-titlebar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px 18px;
  border-bottom: 1px solid var(--border);
  background: rgba(0,0,0,0.2);
}

.visual-dots {
  display: flex;
  gap: 6px;
}

.visual-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
}

.visual-dot:nth-child(1) { background: rgba(255, 90, 90, 0.7); }
.visual-dot:nth-child(2) { background: rgba(255, 190, 50, 0.7); }
.visual-dot:nth-child(3) { background: rgba(50, 215, 100, 0.7); }

.visual-tab-row {
  display: flex;
  gap: 2px;
}

.visual-tab {
  font-family: var(--font-body);
  font-size: 11px;
  color: var(--text-3);
  padding: 4px 12px;
  border-radius: 6px;
  cursor: default;
  letter-spacing: 0.01em;
}

.visual-tab.active {
  background: var(--cyan-08);
  border: 1px solid var(--border);
  color: var(--cyan);
}

.visual-body {
  padding: 16px;
  min-height: 280px;
  display: flex;
  flex-direction: column;
  gap: 10px;
}

/* Chat bubbles */
.chat-msg {
  display: flex;
  gap: 10px;
  align-items: flex-start;
  opacity: 0;
  transform: translateY(8px);
  transition: opacity 0.4s ease, transform 0.4s ease;
}

.chat-msg.show { opacity: 1; transform: translateY(0); }

.chat-avatar {
  width: 26px;
  height: 26px;
  border-radius: 50%;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
}

.chat-avatar.aqua {
  background: linear-gradient(135deg, var(--cyan), var(--blue));
  color: #03040d;
  font-family: var(--font-display);
  box-shadow: 0 0 12px rgba(0,229,255,0.3);
}

.chat-avatar.user {
  background: rgba(255,255,255,0.08);
  color: var(--text-2);
  border: 1px solid var(--border);
}

.chat-bubble {
  padding: 9px 13px;
  border-radius: 14px;
  font-family: var(--font-body);
  font-size: 12.5px;
  line-height: 1.55;
  max-width: 82%;
}

.chat-bubble.user-bubble {
  background: var(--cyan-08);
  border: 1px solid var(--border);
  color: var(--text);
  border-top-left-radius: 4px;
}

.chat-bubble.aqua-bubble {
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.06);
  color: var(--text-2);
  border-top-left-radius: 4px;
}

/* Typing indicator */
.typing-dots {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 2px 0;
}

.typing-dot {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: var(--cyan);
  opacity: 0.5;
  animation: typingBounce 1.2s ease infinite;
}

.typing-dot:nth-child(2) { animation-delay: 0.2s; }
.typing-dot:nth-child(3) { animation-delay: 0.4s; }

@keyframes typingBounce {
  0%, 60%, 100% { transform: translateY(0); opacity: 0.5; }
  30%            { transform: translateY(-5px); opacity: 1; }
}

/* Code block in chat */
.chat-code {
  background: rgba(0,0,0,0.4);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 10px 12px;
  font-family: 'Courier New', monospace;
  font-size: 11px;
  color: var(--cyan);
  line-height: 1.5;
  max-width: 82%;
  margin-left: 36px;
}

.code-line { display: block; }
.code-comment { color: var(--text-3); }
.code-keyword { color: #ff8c8c; }
.code-string  { color: #98dba8; }
.code-fn      { color: var(--cyan); }

/* Status bar */
.visual-status {
  padding: 10px 16px;
  border-top: 1px solid var(--border);
  display: flex;
  align-items: center;
  gap: 8px;
  background: rgba(0,0,0,0.15);
}

.status-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: #00cc88;
  box-shadow: 0 0 8px #00cc88;
  animation: pulse-dot 2s ease infinite;
}

.status-text {
  font-size: 11px;
  color: var(--text-3);
  font-family: var(--font-body);
}

/* Floating mini cards */
.float-card {
  position: absolute;
  background: rgba(7, 10, 26, 0.85);
  border: 1px solid var(--border-md);
  border-radius: var(--r-md);
  padding: 12px 16px;
  backdrop-filter: blur(20px);
  box-shadow: 0 12px 40px rgba(0,0,0,0.5);
  pointer-events: none;
  animation: floatCard var(--fc-dur, 5s) var(--ease-in-out) var(--fc-del, 0s) infinite alternate;
}

@keyframes floatCard {
  0%   { transform: translateY(0) rotate(var(--fc-rot-start, -1deg)); }
  100% { transform: translateY(-10px) rotate(var(--fc-rot-end, 1deg)); }
}

.float-card-1 {
  top: -18px;
  right: -24px;
  --fc-dur: 6s;
  --fc-del: 0.5s;
  --fc-rot-start: -1deg;
  --fc-rot-end: 0.5deg;
}

.float-card-2 {
  bottom: 20px;
  left: -28px;
  --fc-dur: 7s;
  --fc-del: 1.2s;
  --fc-rot-start: 1deg;
  --fc-rot-end: -0.5deg;
}

.float-label {
  font-family: var(--font-body);
  font-size: 10.5px;
  color: var(--text-3);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  margin-bottom: 4px;
}

.float-val {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 700;
  color: var(--text);
  line-height: 1;
}

.float-sub {
  font-size: 10.5px;
  color: var(--text-3);
  margin-top: 2px;
}

.float-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  font-size: 10px;
  font-weight: 600;
  color: #00cc88;
  background: rgba(0,204,136,0.1);
  border: 1px solid rgba(0,204,136,0.2);
  padding: 2px 7px;
  border-radius: 4px;
  margin-top: 5px;
}

/* ===== DIVIDER ===== */
.divider {
  width: 100%;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--border-md) 30%, var(--border-md) 70%, transparent);
  margin: 0;
}

/* ===== SECTION SHARED ===== */
.section-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 clamp(20px, 5vw, 60px);
}

.section-eyebrow {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-family: var(--font-display);
  font-size: 10.5px;
  font-weight: 700;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--cyan);
  margin-bottom: 16px;
}

.section-eyebrow::before {
  content: '';
  display: block;
  width: 20px;
  height: 1px;
  background: var(--cyan);
  opacity: 0.7;
}

.section-title {
  font-family: var(--font-display);
  font-size: clamp(1.9rem, 3.5vw, 3rem);
  font-weight: 800;
  line-height: 1.1;
  letter-spacing: -0.02em;
  color: var(--text);
  margin-bottom: 16px;
}

.section-sub {
  font-family: var(--font-body);
  font-size: clamp(0.95rem, 1.5vw, 1.05rem);
  color: var(--text-2);
  max-width: 540px;
  line-height: 1.7;
}

/* ===== PILLARS SECTION ===== */
.pillars {
  padding: 100px 0;
  overflow: hidden;
}

.pillars-header {
  text-align: center;
  max-width: 620px;
  margin: 0 auto 64px;
}

.pillars-header .section-eyebrow {
  justify-content: center;
}

.pillars-header .section-sub {
  margin: 0 auto;
  text-align: center;
}

.pillars-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1px;
  background: var(--border);
  border: 1px solid var(--border);
  border-radius: var(--r-xl);
  overflow: hidden;
}

.pillar-card {
  background: var(--bg-deep);
  padding: 40px 36px;
  display: flex;
  flex-direction: column;
  gap: 0;
  position: relative;
  overflow: hidden;
  cursor: default;
  transition: background var(--t-mid);
}

.pillar-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 2px;
  background: var(--pc-color, transparent);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.5s var(--ease-out);
}

.pillar-card:hover::before {
  transform: scaleX(1);
}

.pillar-card:hover {
  background: rgba(7, 10, 26, 0.95);
}

.pillar-card.pc-aqua { --pc-color: linear-gradient(90deg, var(--cyan), var(--blue)); }
.pillar-card.pc-workspace { --pc-color: linear-gradient(90deg, var(--blue), var(--indigo)); }
.pillar-card.pc-builder { --pc-color: linear-gradient(90deg, var(--indigo), var(--violet)); }

.pillar-icon-wrap {
  width: 52px;
  height: 52px;
  border-radius: var(--r-md);
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 24px;
  font-size: 22px;
  position: relative;
  overflow: hidden;
}

.pc-aqua .pillar-icon-wrap {
  background: linear-gradient(135deg, rgba(0,229,255,0.12), rgba(68,136,255,0.12));
  border: 1px solid rgba(0,229,255,0.2);
  box-shadow: 0 0 20px rgba(0,229,255,0.08);
}

.pc-workspace .pillar-icon-wrap {
  background: linear-gradient(135deg, rgba(68,136,255,0.12), rgba(92,110,248,0.12));
  border: 1px solid rgba(68,136,255,0.2);
  box-shadow: 0 0 20px rgba(68,136,255,0.08);
}

.pc-builder .pillar-icon-wrap {
  background: linear-gradient(135deg, rgba(92,110,248,0.12), rgba(155,109,255,0.12));
  border: 1px solid rgba(155,109,255,0.2);
  box-shadow: 0 0 20px rgba(155,109,255,0.08);
}

.pillar-label {
  font-family: var(--font-display);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  margin-bottom: 8px;
}

.pc-aqua .pillar-label     { color: var(--cyan); }
.pc-workspace .pillar-label { color: var(--blue); }
.pc-builder .pillar-label   { color: var(--violet); }

.pillar-name {
  font-family: var(--font-display);
  font-size: 1.35rem;
  font-weight: 700;
  letter-spacing: -0.01em;
  color: var(--text);
  margin-bottom: 12px;
  line-height: 1.2;
}

.pillar-desc {
  font-family: var(--font-body);
  font-size: 0.9rem;
  color: var(--text-2);
  line-height: 1.7;
  margin-bottom: 28px;
  flex: 1;
}

.pillar-features {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-bottom: 28px;
}

.pillar-feat {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12.5px;
  color: var(--text-2);
}

.pillar-feat-dot {
  width: 4px;
  height: 4px;
  border-radius: 50%;
  flex-shrink: 0;
}

.pc-aqua .pillar-feat-dot     { background: var(--cyan); }
.pc-workspace .pillar-feat-dot { background: var(--blue); }
.pc-builder .pillar-feat-dot   { background: var(--violet); }

.pillar-cta {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  font-family: var(--font-display);
  font-size: 12.5px;
  font-weight: 600;
  text-decoration: none;
  letter-spacing: 0.01em;
  transition: gap var(--t-fast) var(--ease-out);
  width: fit-content;
}

.pc-aqua .pillar-cta     { color: var(--cyan); }
.pc-workspace .pillar-cta { color: var(--blue); }
.pc-builder .pillar-cta   { color: var(--violet); }

.pillar-cta:hover { gap: 11px; }

/* ===== HOW IT WORKS ===== */
.how {
  padding: 100px 0;
  position: relative;
}

.how-inner {
  max-width: 1100px;
  margin: 0 auto;
  padding: 0 clamp(20px, 5vw, 60px);
}

.how-header {
  text-align: center;
  max-width: 580px;
  margin: 0 auto 72px;
}

.how-header .section-eyebrow { justify-content: center; }
.how-header .section-sub { margin: 0 auto; text-align: center; }

.steps {
  display: grid;
  grid-template-columns: 1fr auto 1fr auto 1fr;
  align-items: start;
  gap: 0;
}

.step {
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--r-xl);
  padding: 36px 32px;
  position: relative;
  transition: border-color var(--t-mid), transform var(--t-mid) var(--ease-out);
}

.step:hover {
  border-color: var(--border-md);
  transform: translateY(-4px);
}

.step-num {
  font-family: var(--font-display);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--text-3);
  margin-bottom: 20px;
}

.step-icon {
  font-size: 28px;
  margin-bottom: 16px;
  display: block;
}

.step h3 {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 700;
  letter-spacing: -0.01em;
  color: var(--text);
  margin-bottom: 10px;
}

.step p {
  font-size: 0.88rem;
  color: var(--text-2);
  line-height: 1.65;
}

.step-connector {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 24px;
  margin-top: 60px;
  color: var(--text-3);
  flex-shrink: 0;
}

.step-connector::before {
  content: '';
  display: block;
  width: 40px;
  height: 1px;
  background: linear-gradient(90deg, var(--border-md), var(--border));
}

/* ===== USE CASES ===== */
.usecases {
  padding: 100px 0;
  overflow: hidden;
}

.usecases-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 clamp(20px, 5vw, 60px);
}

.usecases-header {
  text-align: center;
  max-width: 580px;
  margin: 0 auto 64px;
}

.usecases-header .section-eyebrow { justify-content: center; }
.usecases-header .section-sub { margin: 0 auto; text-align: center; }

.usecase-tabs {
  display: flex;
  justify-content: center;
  gap: 4px;
  flex-wrap: wrap;
  margin-bottom: 48px;
}

.uc-tab {
  padding: 8px 18px;
  border-radius: var(--r-pill);
  font-family: var(--font-body);
  font-size: 13px;
  font-weight: 400;
  color: var(--text-2);
  background: transparent;
  border: 1px solid var(--border);
  cursor: pointer;
  transition: all var(--t-fast);
}

.uc-tab:hover { color: var(--text); border-color: var(--border-md); }

.uc-tab.active {
  color: var(--cyan);
  background: var(--cyan-08);
  border-color: var(--border-md);
  font-weight: 500;
}

.usecase-panels { position: relative; }

.usecase-panel {
  display: none;
  grid-template-columns: 1fr 1fr;
  gap: 48px;
  align-items: center;
}

.usecase-panel.active {
  display: grid;
  animation: fadeIn 0.35s var(--ease-out) forwards;
}

.uc-content {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.uc-title {
  font-family: var(--font-display);
  font-size: 1.6rem;
  font-weight: 700;
  letter-spacing: -0.02em;
  color: var(--text);
  line-height: 1.2;
}

.uc-desc {
  font-family: var(--font-body);
  font-size: 0.95rem;
  color: var(--text-2);
  line-height: 1.75;
}

.uc-chips {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.uc-chip {
  padding: 5px 12px;
  border-radius: var(--r-pill);
  border: 1px solid var(--border-md);
  font-size: 12px;
  color: var(--text-2);
  background: var(--cyan-05);
}

.uc-cta {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  color: var(--cyan);
  font-family: var(--font-display);
  font-size: 13px;
  font-weight: 600;
  text-decoration: none;
  width: fit-content;
  transition: gap var(--t-fast) var(--ease-out);
}

.uc-cta:hover { gap: 12px; }

.uc-visual {
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--r-xl);
  padding: 28px;
  min-height: 280px;
  position: relative;
  overflow: hidden;
}

.uc-visual::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--border-md), transparent);
}

/* ===== METRICS BAND ===== */
.metrics-band {
  padding: 72px 0;
  border-top: 1px solid var(--border);
  border-bottom: 1px solid var(--border);
  background: rgba(0,0,0,0.2);
  overflow: hidden;
  position: relative;
}

.metrics-band::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse 80% 100% at 50% 50%, rgba(0,229,255,0.03), transparent);
}

.metrics-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 0;
  max-width: 900px;
  margin: 0 auto;
  padding: 0 clamp(20px, 5vw, 60px);
}

.metric-cell {
  text-align: center;
  padding: 24px 20px;
  position: relative;
}

.metric-cell:not(:last-child)::after {
  content: '';
  position: absolute;
  right: 0; top: 20%; bottom: 20%;
  width: 1px;
  background: var(--border);
}

.metric-num {
  font-family: var(--font-display);
  font-size: clamp(2rem, 4vw, 3rem);
  font-weight: 800;
  letter-spacing: -0.03em;
  line-height: 1;
  background: linear-gradient(135deg, var(--text) 0%, var(--cyan) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 8px;
}

.metric-desc {
  font-family: var(--font-body);
  font-size: 13px;
  color: var(--text-2);
  line-height: 1.4;
}

/* ===== TOOLS SECTION ===== */
.tools {
  padding: 100px 0;
}

.tools-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 clamp(20px, 5vw, 60px);
}

.tools-header {
  text-align: center;
  max-width: 580px;
  margin: 0 auto 60px;
}

.tools-header .section-eyebrow { justify-content: center; }
.tools-header .section-sub { margin: 0 auto; text-align: center; }

.tools-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 12px;
}

.tool-card {
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--r-lg);
  padding: 24px 22px;
  text-decoration: none;
  display: flex;
  flex-direction: column;
  gap: 12px;
  transition: all var(--t-mid) var(--ease-out);
  position: relative;
  overflow: hidden;
}

.tool-card::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, var(--cyan-05), transparent);
  opacity: 0;
  transition: opacity var(--t-mid);
}

.tool-card:hover {
  border-color: var(--border-md);
  transform: translateY(-3px);
  box-shadow: 0 12px 32px rgba(0,0,0,0.4);
}

.tool-card:hover::after { opacity: 1; }

.tool-icon {
  font-size: 22px;
  line-height: 1;
}

.tool-name {
  font-family: var(--font-display);
  font-size: 0.9rem;
  font-weight: 700;
  color: var(--text);
  letter-spacing: -0.005em;
}

.tool-desc {
  font-size: 12px;
  color: var(--text-3);
  line-height: 1.5;
  flex: 1;
}

.tool-arrow {
  font-size: 14px;
  color: var(--text-3);
  align-self: flex-end;
  transition: transform var(--t-fast) var(--ease-out), color var(--t-fast);
}

.tool-card:hover .tool-arrow {
  transform: translate(3px, -3px);
  color: var(--cyan);
}

/* ===== FINAL CTA ===== */
.cta-final {
  padding: 120px 0;
  text-align: center;
  position: relative;
  overflow: hidden;
}

.cta-glow {
  position: absolute;
  width: 600px;
  height: 600px;
  background: radial-gradient(circle, rgba(0, 229, 255, 0.08), transparent 65%);
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  pointer-events: none;
  border-radius: 50%;
  animation: orbA 8s var(--ease-in-out) infinite alternate;
}

.cta-inner {
  max-width: 700px;
  margin: 0 auto;
  padding: 0 clamp(20px, 5vw, 40px);
  position: relative;
}

.cta-title {
  font-family: var(--font-display);
  font-size: clamp(2.2rem, 5vw, 4rem);
  font-weight: 800;
  letter-spacing: -0.025em;
  line-height: 1.07;
  color: var(--text);
  margin-bottom: 20px;
}

.cta-title em {
  font-style: italic;
  background: linear-gradient(135deg, var(--cyan) 0%, var(--blue) 50%, var(--violet) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.cta-sub {
  font-family: var(--font-body);
  font-size: 1.05rem;
  color: var(--text-2);
  line-height: 1.7;
  max-width: 520px;
  margin: 0 auto 40px;
}

.cta-buttons {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 14px;
  flex-wrap: wrap;
  margin-bottom: 28px;
}

.btn-cta {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 16px 36px;
  border-radius: var(--r-md);
  background: linear-gradient(135deg, var(--cyan) 0%, var(--blue) 100%);
  color: #03040d;
  font-family: var(--font-display);
  font-size: 15px;
  font-weight: 700;
  letter-spacing: 0.01em;
  text-decoration: none;
  transition: all var(--t-mid) var(--ease-out);
  position: relative;
  overflow: hidden;
  box-shadow: 0 4px 24px rgba(0,229,255,0.25);
}

.btn-cta:hover {
  transform: translateY(-3px) scale(1.02);
  box-shadow: 0 12px 40px rgba(0,229,255,0.45);
}

.btn-cta:active { transform: translateY(0) scale(0.99); }

.cta-note {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  color: var(--text-3);
}

.online-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: #00cc88;
  box-shadow: 0 0 8px #00cc88;
  animation: pulse-dot 2.5s ease infinite;
  flex-shrink: 0;
}

/* ===== SEO SECTION ===== */
.seo-landing-section {
  max-width: 860px;
  margin: 0 auto;
  padding: 80px 24px 60px;
  color: var(--text-3);
  line-height: 1.85;
  font-family: var(--font-body);
  border-top: 1px solid var(--border);
}

.seo-landing-section h2 {
  font-size: clamp(1.2rem, 3vw, 1.6rem);
  color: rgba(255,255,255,0.75);
  margin: 0 0 14px;
  font-weight: 600;
  font-family: var(--font-display);
}

.seo-landing-section h3 {
  font-size: clamp(1rem, 2.5vw, 1.2rem);
  color: rgba(255,255,255,0.6);
  margin: 36px 0 10px;
  font-weight: 500;
  font-family: var(--font-display);
}

.seo-landing-section p {
  margin: 0 0 16px;
  font-size: clamp(0.875rem, 2vw, 0.95rem);
  color: var(--text-3);
}

.seo-landing-nav {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 36px;
  padding-top: 32px;
  border-top: 1px solid var(--border);
}

.seo-landing-nav a {
  color: var(--text-3);
  text-decoration: none;
  font-size: 12.5px;
  border: 1px solid var(--border);
  padding: 6px 14px;
  border-radius: var(--r-sm);
  transition: color 0.2s, border-color 0.2s;
}

.seo-landing-nav a:hover {
  color: var(--text-2);
  border-color: var(--border-md);
}

/* ===== FOOTER ===== */
.footer {
  padding: 32px 24px;
  text-align: center;
  border-top: 1px solid var(--border);
  background: rgba(0,0,0,0.2);
}

.footer p {
  font-size: 12px;
  color: var(--text-3);
  font-family: var(--font-body);
}

/* =============================================================
   RESPONSIVE — TABLET
   ============================================================= */
@media (max-width: 1024px) {
  .hero {
    grid-template-columns: 1fr;
    text-align: center;
    align-items: flex-start;
    padding: 120px clamp(20px, 5vw, 40px) 60px;
    gap: 60px;
  }

  .hero-left {
    align-items: center;
    max-width: 100%;
  }

  .hero-sub { max-width: 100%; }

  .hero-right {
    justify-content: center;
    max-width: 540px;
    margin: 0 auto;
    width: 100%;
  }

  .hero-metrics { justify-content: center; }

  .pillars-grid {
    grid-template-columns: 1fr;
  }

  .steps {
    grid-template-columns: 1fr;
    gap: 0;
  }

  .step-connector {
    padding: 16px 0;
    margin-top: 0;
    justify-content: flex-start;
    padding-left: 40px;
  }

  .step-connector::before {
    width: 1px;
    height: 30px;
    background: linear-gradient(180deg, var(--border-md), var(--border));
  }

  .usecase-panel { grid-template-columns: 1fr; }
  .uc-visual { display: none; }

  .metrics-grid { grid-template-columns: repeat(2, 1fr); }

  .metric-cell:nth-child(2)::after { display: none; }

  .tools-grid { grid-template-columns: repeat(2, 1fr); }

  .nav-links { display: none; }
}

/* =============================================================
   RESPONSIVE — MOBILE
   ============================================================= */
@media (max-width: 640px) {
  :root {
    --r-xl: 20px;
    --r-lg: 14px;
  }

  .hero {
    padding: 100px 20px 60px;
    gap: 48px;
  }

  .hero-title {
    font-size: clamp(2.2rem, 10vw, 3rem);
  }

  .hero-sub { font-size: 0.95rem; }

  .hero-ctas {
    flex-direction: column;
    align-items: center;
    width: 100%;
    gap: 10px;
  }

  .btn-primary, .btn-secondary {
    width: 100%;
    justify-content: center;
    padding: 15px 24px;
  }

  .hero-metrics {
    gap: 18px;
    flex-wrap: wrap;
    justify-content: center;
  }

  .metric-val { font-size: 16px; }

  .hero-right { display: none; }

  .pillars-grid {
    border-radius: var(--r-lg);
  }

  .pillar-card { padding: 30px 24px; }

  .how, .pillars, .usecases, .tools { padding: 72px 0; }

  .how-header, .pillars-header, .usecases-header, .tools-header { margin-bottom: 48px; }

  .steps { gap: 0; }

  .step { padding: 28px 22px; }

  .metrics-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 0;
  }

  .metric-cell:nth-child(2)::after { display: none; }
  .metric-cell:nth-child(4)::after { display: none; }

  .tools-grid { grid-template-columns: repeat(2, 1fr); gap: 8px; }

  .tool-card { padding: 18px 16px; }

  .cta-final { padding: 80px 0; }

  .cta-buttons { flex-direction: column; align-items: center; width: 100%; }

  .btn-cta { width: 100%; max-width: 340px; justify-content: center; }

  .usecase-tabs { gap: 6px; }
  .uc-tab { font-size: 12px; padding: 7px 14px; }

  .float-card-1, .float-card-2 { display: none; }

  .visual-window { border-radius: var(--r-lg); }

  .announce-text { display: none; }
}

/* ===== ACCESSIBILITY ===== */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

/* ==========================================================
   AQUIPLEX LANDING — RESPONSIVE OVERRIDES
   ========================================================== */

/* ── Prevent horizontal overflow ── */
html, body { max-width: 100%; overflow-x: hidden; }

/* ── Landing navbar: add mobile hamburger toggle support ── */
.nav-mobile-toggle {
  display: none;
  background: none;
  border: 1px solid rgba(255,255,255,0.12);
  color: var(--text-2);
  border-radius: var(--r-sm);
  width: 36px;
  height: 36px;
  align-items: center;
  justify-content: center;
  font-size: 18px;
  cursor: pointer;
  flex-shrink: 0;
  z-index: 1001;
  transition: border-color var(--t-fast), color var(--t-fast);
}
.nav-mobile-toggle:hover { border-color: var(--cyan-20); color: var(--text); }

/* Landing mobile nav drawer */
.nav-mobile-drawer {
  display: none;
  flex-direction: column;
  position: fixed;
  top: 60px;
  left: 0;
  width: 100%;
  background: rgba(3, 4, 13, 0.97);
  backdrop-filter: blur(28px);
  -webkit-backdrop-filter: blur(28px);
  border-bottom: 1px solid var(--border);
  padding: 20px 20px 24px;
  gap: 6px;
  z-index: 999;
  max-height: calc(100vh - 60px);
  overflow-y: auto;
  box-sizing: border-box;
}
.nav-mobile-drawer.open { display: flex; }

.nav-mobile-drawer .nav-link {
  display: block;
  padding: 13px 16px;
  font-size: 15px;
  border-radius: var(--r-sm);
  color: var(--text-2);
  text-decoration: none;
  border-bottom: 1px solid var(--border);
}
.nav-mobile-drawer .nav-link:last-of-type { border-bottom: none; }
.nav-mobile-drawer .nav-link:hover { background: var(--cyan-05); color: var(--text); }

.nav-mobile-drawer-btns {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px solid var(--border);
}
.nav-mobile-drawer-btns .btn-ghost,
.nav-mobile-drawer-btns .btn-nav-cta {
  display: flex;
  justify-content: center;
  padding: 13px 20px;
  font-size: 14px;
  width: 100%;
  text-align: center;
  box-sizing: border-box;
}

/* ─────────────────────────────────────────
   1024px — tablet
───────────────────────────────────────── */
@media (max-width: 1024px) {
  /* nav-links hidden at 1024 (already done), show toggle */
  .nav-mobile-toggle { display: flex; }
  .nav-buttons { display: none; }

  /* hero: already stacks at 1024 ✓ — tighten spacing */
  .hero { padding: 100px clamp(16px, 5vw, 40px) 60px; }

  /* section containers: safe padding */
  .section-container { padding: 0 clamp(16px, 4vw, 40px); }
  .how-inner { padding: 0 clamp(16px, 4vw, 40px); }

  /* metrics grid: 2-col ✓ already — add padding fix */
  .metrics-grid { padding: 0; }
}

/* ─────────────────────────────────────────
   768px — large phones / small tablets
───────────────────────────────────────── */
@media (max-width: 768px) {
  .navbar { padding: 0 16px; }

  /* hero */
  .hero { padding: 90px 16px 50px; gap: 40px; }
  .hero-title { font-size: clamp(2.2rem, 9vw, 3.2rem); }
  .hero-sub   { font-size: 0.95rem; }
  .hero-ctas  { flex-direction: column; align-items: stretch; width: 100%; gap: 10px; }
  .btn-primary, .btn-secondary { width: 100%; justify-content: center; text-align: center; }

  /* metrics: wrap on small screens */
  .hero-metrics { flex-wrap: wrap; gap: 14px; }

  /* pillar grid: already 1-col ✓, fix padding */
  .pillar-card { padding: 32px 24px; }

  /* steps */
  .step { padding: 24px 20px; }

  /* tools grid */
  .tools-grid { grid-template-columns: repeat(2, 1fr); gap: 10px; }
  .tool-card  { padding: 16px 14px; }

  /* usecase tabs: wrap */
  .usecase-tabs { flex-wrap: wrap; gap: 6px; }
  .uc-tab       { font-size: 12px; padding: 7px 14px; }

  /* section containers */
  .section-container { padding: 0 16px; }
  .how-inner { padding: 0 16px; }

  /* cta final */
  .cta-final  { padding: 80px 0; }
  .cta-inner  { padding: 0 16px; }
  .cta-buttons { flex-direction: column; align-items: stretch; }
  .btn-cta    { width: 100%; max-width: 100%; justify-content: center; }

  /* SEO section */
  .seo-landing-section { padding: 60px 16px 40px; }
}

/* ─────────────────────────────────────────
   640px — already handled above ✓
   Small extra fixes
───────────────────────────────────────── */
@media (max-width: 640px) {
  /* float cards already hidden ✓ — also hide floating orbs that cause overflow */
  .cta-glow { display: none; }

  /* tools 1-col below 480, 2-col at 640 is fine */
  .tools-grid { grid-template-columns: repeat(2, 1fr); gap: 8px; }

  /* metrics grid wrap more aggressively */
  .metrics-grid { grid-template-columns: repeat(2, 1fr); }

  /* step connector vertical */
  .step { padding: 24px 18px; }
}

/* ─────────────────────────────────────────
   480px — small phones
───────────────────────────────────────── */
@media (max-width: 480px) {
  .hero { padding: 80px 14px 40px; }
  .tools-grid { grid-template-columns: 1fr; gap: 8px; }
  .metrics-grid { grid-template-columns: repeat(2, 1fr); }
  .pillar-card { padding: 28px 20px; }
  .tool-card { padding: 14px 12px; }
  .step { padding: 20px 16px; }
}

/* ─────────────────────────────────────────
   375px — standard phone
───────────────────────────────────────── */
@media (max-width: 375px) {
  .navbar { padding: 0 12px; }
  .nav-wordmark { font-size: 13px; }
  .hero { padding: 76px 12px 36px; }
  .section-container { padding: 0 12px; }
  .how-inner { padding: 0 12px; }
  .cta-inner { padding: 0 12px; }
  .seo-landing-section { padding: 48px 12px 32px; }
  .metrics-grid { grid-template-columns: repeat(2, 1fr); gap: 0; }
}

/* ─────────────────────────────────────────
   320px — minimum
───────────────────────────────────────── */
@media (max-width: 320px) {
  .nav-wordmark { font-size: 12px; }
  .nav-tag { display: none; }
  .hero-title { font-size: 2rem; }
  .hero { padding: 72px 10px 32px; }
  .section-container { padding: 0 10px; }
  .pillar-card { padding: 22px 16px; }
  .tool-card { padding: 12px 10px; }
}

/* ═══════════════════════════════════════════════════════════════════
   AQUIPLEX PLATFORM DESIGN SYSTEM — v1
   Scope: all classes prefixed `px-` so this file can coexist with
   legacy styles.css during migration. Pages opting fully in add
   class="px-page" to <body>.
   Palette: ink charcoal / warm paper. Single steel-aqua accent.
   Type: Inter (UI) + Newsreader (display).
   ═══════════════════════════════════════════════════════════════════ */

:root {
  /* ink (dark) — default */
  --px-bg:            #0b0e12;
  --px-surface:       #11151b;
  --px-surface-2:     #171c24;
  --px-line:          rgba(255,255,255,0.07);
  --px-line-strong:   rgba(255,255,255,0.12);
  --px-text:          #e8ecf1;
  --px-text-2:        #9aa4b2;
  --px-text-3:        #667085;
  --px-accent:        #4fa3b8;
  --px-accent-strong: #6fbdd0;
  --px-accent-ink:    #0b0e12;
  --px-danger:        #e5726b;
  --px-success:       #6fbf8f;
  --px-warning:       #d8a35a;

  --px-radius-sm: 6px;
  --px-radius:    10px;
  --px-radius-lg: 14px;

  --px-shadow-sm: 0 1px 2px rgba(0,0,0,0.25);
  --px-shadow:    0 8px 30px rgba(0,0,0,0.35);
  --px-shadow-lg: 0 24px 60px rgba(0,0,0,0.45);

  --px-font-sans: 'Inter', ui-sans-serif, system-ui, -apple-system, 'Segoe UI', sans-serif;
  --px-font-display: 'Newsreader', Georgia, 'Times New Roman', serif;
  --px-font-mono: 'JetBrains Mono', ui-monospace, 'SF Mono', Menlo, monospace;

  --px-w-content: 1120px;
  --px-w-narrow:  720px;

  /* fluid spacing scale (8px system, scales with viewport) */
  --px-gutter:   clamp(20px, 4.5vw, 24px);
  --px-space-sec: clamp(64px, 10vw, 96px);   /* between major sections */
  --px-space-blk: clamp(32px, 6vw, 48px);    /* between blocks in a page */
  --px-space-el:  clamp(20px, 4vw, 28px);    /* inside/around elements */

  --px-ease: cubic-bezier(0.25, 0.1, 0.25, 1);
  --px-t-fast: 120ms;
  --px-t: 180ms;
}

.px-light {
  --px-bg:            #fafaf8;
  --px-surface:       #ffffff;
  --px-surface-2:     #f3f3f0;
  --px-line:          #e8e6e1;
  --px-line-strong:   #d8d5cf;
  --px-text:          #17191d;
  --px-text-2:        #5c6470;
  --px-text-3:        #8a919c;
  --px-accent:        #106b7e;
  --px-accent-strong: #0d5967;
  --px-accent-ink:    #ffffff;
  --px-shadow-sm: 0 1px 2px rgba(23,25,29,0.06);
  --px-shadow:    0 8px 30px rgba(23,25,29,0.08);
  --px-shadow-lg: 0 24px 60px rgba(23,25,29,0.12);
}

/* ── Base (opt-in pages only) ─────────────────────────────────────── */
body.px-page {
  margin: 0;
  background: var(--px-bg);
  color: var(--px-text);
  font-family: var(--px-font-sans);
  font-size: 15px;
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
  padding-top: 0;
}
body.px-page *, body.px-page *::before, body.px-page *::after { box-sizing: border-box; }
body.px-page a { color: inherit; text-decoration: none; }
body.px-page ::selection { background: rgba(79,163,184,0.28); }
body.px-page img, body.px-page svg { max-width: 100%; height: auto; }
body.px-page.px-menu-open { overflow: hidden; }

html { -webkit-text-size-adjust: 100%; text-size-adjust: 100%; }

/* one visible, consistent focus ring for every interactive element */
body.px-page a:focus-visible,
body.px-page button:focus-visible,
body.px-page summary:focus-visible,
body.px-page [tabindex]:focus-visible {
  outline: 2px solid var(--px-accent);
  outline-offset: 2px;
  border-radius: var(--px-radius-sm);
}

body.px-page h1, body.px-page h2, body.px-page h3 {
  margin: 0;
  font-weight: 600;
  letter-spacing: -0.02em;
  line-height: 1.2;
}

@media (prefers-reduced-motion: reduce) {
  .px-page *, .px-page *::before, .px-page *::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

/* ── Layout primitives ────────────────────────────────────────────── */
.px-container { max-width: var(--px-w-content); margin: 0 auto; padding: 0 var(--px-gutter); }
.px-narrow    { max-width: var(--px-w-narrow);  margin: 0 auto; padding: 0 var(--px-gutter); }
.px-section   { padding: var(--px-space-sec) 0; }
.px-section + .px-section { border-top: 1px solid var(--px-line); }

.px-eyebrow {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--px-text-3);
  margin-bottom: 16px;
}

.px-display {
  font-family: var(--px-font-display);
  font-weight: 500;
  letter-spacing: -0.015em;
}

/* signature: waterline — a hairline that carries a single slow light pass */
.px-waterline {
  height: 1px;
  border: 0;
  margin: 0;
  background: linear-gradient(90deg,
    transparent 0%,
    var(--px-line-strong) 20%,
    var(--px-line-strong) 80%,
    transparent 100%);
  position: relative;
  overflow: hidden;
}
.px-waterline::after {
  content: '';
  position: absolute;
  top: 0; left: -30%;
  width: 30%; height: 1px;
  background: linear-gradient(90deg, transparent, var(--px-accent), transparent);
  animation: px-waterline-pass 7s var(--px-ease) infinite;
  opacity: 0.7;
}
@keyframes px-waterline-pass {
  0%, 60% { left: -30%; }
  100%    { left: 130%; }
}

/* ── Buttons ──────────────────────────────────────────────────────── */
.px-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 9px 18px;
  border-radius: var(--px-radius-sm);
  border: 1px solid transparent;
  font-family: var(--px-font-sans);
  font-size: 14px;
  font-weight: 500;
  line-height: 1.2;
  cursor: pointer;
  white-space: nowrap;
  transition: background var(--px-t-fast) var(--px-ease),
              border-color var(--px-t-fast) var(--px-ease),
              color var(--px-t-fast) var(--px-ease),
              transform var(--px-t-fast) var(--px-ease);
  user-select: none;
}
.px-btn:active { transform: scale(0.985); }
.px-btn:focus-visible { outline: 2px solid var(--px-accent); outline-offset: 2px; }

.px-btn-primary { background: var(--px-text); color: var(--px-bg); }
.px-btn-primary:hover { background: var(--px-text-2); }
.px-light .px-btn-primary { background: #17191d; color: #fff; }
.px-light .px-btn-primary:hover { background: #2b2f36; }

.px-btn-accent { background: var(--px-accent); color: var(--px-accent-ink); }
.px-btn-accent:hover { background: var(--px-accent-strong); }

.px-btn-secondary {
  background: transparent;
  border-color: var(--px-line-strong);
  color: var(--px-text);
}
.px-btn-secondary:hover { border-color: var(--px-text-3); background: var(--px-surface-2); }

.px-btn-ghost { background: transparent; color: var(--px-text-2); }
.px-btn-ghost:hover { color: var(--px-text); background: var(--px-surface-2); }

.px-btn { min-height: 36px; }
.px-btn-lg { padding: 12px 24px; font-size: 15px; border-radius: var(--px-radius-sm); min-height: 44px; }
.px-btn-sm { padding: 6px 12px; font-size: 13px; min-height: 30px; }
.px-btn[disabled], .px-btn.is-loading { opacity: 0.55; pointer-events: none; }

/* loading state — inline spinner, label stays for layout stability */
.px-btn.is-loading::before {
  content: '';
  width: 13px; height: 13px;
  border: 2px solid currentColor;
  border-top-color: transparent;
  border-radius: 50%;
  animation: px-btn-spin 0.7s linear infinite;
}
@keyframes px-btn-spin { to { transform: rotate(360deg); } }

/* full-width helper (mobile CTAs, card actions) */
.px-btn-block { width: 100%; }

/* centered/stacking action rows — replaces ad-hoc inline flex rows */
.px-btn-row { display: flex; gap: 12px; flex-wrap: wrap; }
.px-btn-row.center { justify-content: center; }
@media (max-width: 480px) {
  .px-btn-row { flex-direction: column; align-items: stretch; }
  .px-btn-row .px-btn { width: 100%; }
}

/* touch devices: every control meets the 44px target without changing desktop */
@media (pointer: coarse) {
  .px-btn { min-height: 44px; }
  .px-btn-sm { min-height: 40px; }
  .px-nav-burger { width: 44px; height: 44px; }
  .px-nav-avatar-btn { width: 36px; height: 36px; }
}

/* ── Cards ────────────────────────────────────────────────────────── */
.px-card {
  background: var(--px-surface);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius-lg);
  transition: border-color var(--px-t) var(--px-ease);
}
.px-card-hover:hover { border-color: var(--px-line-strong); }
.px-card-pad { padding: clamp(18px, 3.5vw, 24px); }

/* mobile density — one rule set so every card tightens identically */
@media (max-width: 600px) {
  .px-founder { padding: 22px 20px; }
  .pack-card { padding: 22px 20px; }
  .px-stat { padding: 15px 16px; }
  .px-feature { padding: 24px 20px; }
  .px-free-callout { padding: 20px; }
}

/* ── Inputs ───────────────────────────────────────────────────────── */
.px-input, .px-select, .px-textarea {
  width: 100%;
  background: var(--px-surface);
  border: 1px solid var(--px-line-strong);
  border-radius: var(--px-radius-sm);
  color: var(--px-text);
  font-family: var(--px-font-sans);
  font-size: 14px;
  padding: 10px 12px;
  transition: border-color var(--px-t-fast) var(--px-ease), box-shadow var(--px-t-fast) var(--px-ease);
}
.px-input::placeholder, .px-textarea::placeholder { color: var(--px-text-3); }
.px-input:focus, .px-select:focus, .px-textarea:focus {
  outline: none;
  border-color: var(--px-accent);
  box-shadow: 0 0 0 3px rgba(79,163,184,0.18);
}
.px-label {
  display: block;
  font-size: 13px;
  font-weight: 500;
  color: var(--px-text-2);
  margin-bottom: 6px;
}

/* ── Badges ───────────────────────────────────────────────────────── */
.px-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: 11.5px;
  font-weight: 600;
  letter-spacing: 0.04em;
  padding: 3px 10px;
  border-radius: 999px;
  border: 1px solid var(--px-line-strong);
  color: var(--px-text-2);
  background: var(--px-surface);
}
.px-badge-accent { border-color: rgba(79,163,184,0.4); color: var(--px-accent-strong); }
.px-light .px-badge-accent { color: var(--px-accent); }
.px-badge-dot {
  width: 6px; height: 6px; border-radius: 50%;
  background: var(--px-success);
}

/* ── Tables ───────────────────────────────────────────────────────── */
.px-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 14px;
}
.px-table th {
  text-align: left;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--px-text-3);
  padding: 10px 16px;
  border-bottom: 1px solid var(--px-line-strong);
}
.px-table td {
  padding: 12px 16px;
  border-bottom: 1px solid var(--px-line);
  color: var(--px-text-2);
}
.px-table td:first-child { color: var(--px-text); }
.px-table tr:last-child td { border-bottom: 0; }

/* ═══════════════════════════════════════════════════════════════════
   NAV — self-contained, safe on legacy pages
   ═══════════════════════════════════════════════════════════════════ */
.px-nav {
  position: fixed;
  top: 0; left: 0; right: 0;
  height: 60px;
  z-index: 9999;
  background: color-mix(in srgb, var(--px-bg) 82%, transparent);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
  border-bottom: 1px solid var(--px-line);
  font-family: var(--px-font-sans);
  font-size: 14px;
}
body:not(.px-page) .px-nav {
  /* legacy pages: keep dark ink even if page bg differs */
  --px-bg: #0b0e12;
}
.px-nav-inner {
  max-width: var(--px-w-content);
  margin: 0 auto;
  height: 100%;
  padding: 0 max(var(--px-gutter), env(safe-area-inset-right)) 0 max(var(--px-gutter), env(safe-area-inset-left));
  display: flex;
  align-items: center;
  gap: 28px;
}
.px-nav-logo {
  display: flex;
  align-items: center;
  gap: 9px;
  color: var(--px-text) !important;
  text-decoration: none !important;
  flex-shrink: 0;
}
.px-nav-logo img { width: 22px; height: 22px; object-fit: contain; }
.px-nav-wordmark {
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.14em;
}
.px-nav-links {
  display: flex;
  align-items: center;
  gap: 4px;
  flex: 1;
}
.px-nav-link {
  padding: 6px 11px;
  border-radius: var(--px-radius-sm);
  color: var(--px-text-2) !important;
  text-decoration: none !important;
  font-weight: 450;
  transition: color var(--px-t-fast) var(--px-ease), background var(--px-t-fast) var(--px-ease);
}
.px-nav-link:hover { color: var(--px-text) !important; background: var(--px-surface-2); }

.px-nav-more { position: relative; }
.px-nav-more > button {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  background: none;
  border: 0;
  font: inherit;
  padding: 6px 11px;
  border-radius: var(--px-radius-sm);
  color: var(--px-text-2);
  cursor: pointer;
}
.px-nav-more > button:hover { color: var(--px-text); background: var(--px-surface-2); }
.px-nav-more svg { transition: transform var(--px-t-fast) var(--px-ease); }
.px-nav-more.open svg { transform: rotate(180deg); }
.px-nav-dropdown {
  position: absolute;
  top: calc(100% + 8px);
  left: 0;
  min-width: 190px;
  background: var(--px-surface);
  border: 1px solid var(--px-line-strong);
  border-radius: var(--px-radius);
  box-shadow: var(--px-shadow);
  padding: 6px;
  display: none;
}
.px-nav-more.open .px-nav-dropdown { display: block; animation: px-pop var(--px-t) var(--px-ease); }
@keyframes px-pop {
  from { opacity: 0; transform: translateY(-4px); }
  to   { opacity: 1; transform: translateY(0); }
}
.px-nav-dropdown a {
  display: block;
  padding: 8px 11px;
  border-radius: var(--px-radius-sm);
  color: var(--px-text-2) !important;
  text-decoration: none !important;
  font-size: 13.5px;
}
.px-nav-dropdown a:hover { color: var(--px-text) !important; background: var(--px-surface-2); }

.px-nav-actions {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-shrink: 0;
}
.px-nav-plan {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.08em;
  padding: 3px 9px;
  border-radius: 999px;
  border: 1px solid var(--px-line-strong);
  color: var(--px-text-2) !important;
  text-decoration: none !important;
}
.px-nav-plan:hover { border-color: var(--px-text-3); color: var(--px-text) !important; }
.px-nav-plan.plan-pro, .px-nav-plan.plan-team, .px-nav-plan.plan-starter {
  border-color: rgba(79,163,184,0.45);
  color: var(--px-accent-strong) !important;
}

.px-nav-avatar-btn {
  width: 30px; height: 30px;
  border-radius: 50%;
  border: 1px solid var(--px-line-strong);
  background: var(--px-surface-2);
  color: var(--px-text);
  font-size: 12px;
  font-weight: 600;
  font-family: var(--px-font-sans);
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  transition: border-color var(--px-t-fast) var(--px-ease);
}
.px-nav-avatar-btn:hover { border-color: var(--px-accent); }
.px-nav-user { position: relative; }
.px-nav-user-dropdown {
  position: absolute;
  top: calc(100% + 10px);
  right: 0;
  min-width: 220px;
  background: var(--px-surface);
  border: 1px solid var(--px-line-strong);
  border-radius: var(--px-radius);
  box-shadow: var(--px-shadow);
  padding: 6px;
  display: none;
}
.px-nav-user-dropdown.open { display: block; animation: px-pop var(--px-t) var(--px-ease); }
.px-nav-user-meta { padding: 9px 11px 4px; }
.px-nav-user-email {
  font-size: 12.5px;
  color: var(--px-text-2);
  word-break: break-all;
}
.px-nav-user-planrow { padding: 4px 11px 9px; }
.px-nav-divider { height: 1px; background: var(--px-line); margin: 6px 4px; }
.px-nav-item {
  display: block;
  padding: 8px 11px;
  border-radius: var(--px-radius-sm);
  color: var(--px-text-2) !important;
  text-decoration: none !important;
  font-size: 13.5px;
}
.px-nav-item:hover { color: var(--px-text) !important; background: var(--px-surface-2); }

.px-nav-burger {
  display: none;
  background: none;
  border: 1px solid var(--px-line-strong);
  border-radius: var(--px-radius-sm);
  width: 34px; height: 34px;
  color: var(--px-text);
  cursor: pointer;
  align-items: center;
  justify-content: center;
}
.px-nav-mobile {
  display: none;
  position: fixed;
  top: 60px; left: 0; right: 0;
  max-height: calc(100vh - 60px);
  max-height: calc(100dvh - 60px);
  overflow-y: auto;
  overscroll-behavior: contain;
  -webkit-overflow-scrolling: touch;
  background: var(--px-bg);
  border-bottom: 1px solid var(--px-line-strong);
  padding: 16px var(--px-gutter) calc(24px + env(safe-area-inset-bottom));
  z-index: 9998;
}
body:not(.px-page) .px-nav-mobile { background: #0b0e12; }
.px-nav-mobile.open { display: block; animation: px-pop var(--px-t) var(--px-ease); }
.px-nav-mobile a {
  display: flex;
  align-items: center;
  min-height: 44px;
  color: var(--px-text-2) !important;
  text-decoration: none !important;
  font-size: 15px;
  border-radius: var(--px-radius-sm);
  padding: 0 8px;
}
.px-nav-mobile a:hover { color: var(--px-text) !important; background: var(--px-surface-2); }
.px-nav-mobile .px-btn { width: 100%; margin-bottom: 8px; min-height: 44px; }
.px-nav-mobile-divider { height: 1px; background: var(--px-line); margin: 12px 0; }

@media (max-width: 860px) {
  .px-nav-links { display: none; }
  .px-nav-actions .px-nav-plan { display: none; }
  .px-nav-actions .px-btn { display: none; }
  .px-nav-burger { display: inline-flex; }
  .px-nav-inner { gap: 12px; justify-content: space-between; }
}

/* legacy pages have body padding-top:70px for the old 70px header;
   new header is 60px — compensate visually is unnecessary; safe. */

/* ═══════════════════════════════════════════════════════════════════
   FOOTER
   ═══════════════════════════════════════════════════════════════════ */
.px-footer {
  border-top: 1px solid var(--px-line);
  padding: clamp(40px, 7vw, 56px) 0 calc(40px + env(safe-area-inset-bottom));
  font-family: var(--px-font-sans);
  font-size: 13.5px;
  background: var(--px-bg);
}
body:not(.px-page) .px-footer { --px-bg: #0b0e12; color: #9aa4b2; }
.px-footer-grid {
  max-width: var(--px-w-content);
  margin: 0 auto;
  padding: 0 var(--px-gutter);
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: 40px;
}
.px-footer-brand { display: flex; align-items: center; gap: 9px; margin-bottom: 14px; }
.px-footer-brand img { width: 20px; height: 20px; }
.px-footer-brand span { font-size: 12.5px; font-weight: 600; letter-spacing: 0.14em; color: var(--px-text); }
.px-footer-tagline { color: var(--px-text-3); max-width: 260px; line-height: 1.55; }
.px-footer h4 {
  margin: 0 0 14px;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--px-text-3);
}
.px-footer-col a {
  display: block;
  color: var(--px-text-2) !important;
  text-decoration: none !important;
  padding: 4px 0;
  transition: color var(--px-t-fast) var(--px-ease);
}
.px-footer-col a:hover { color: var(--px-text) !important; }
.px-footer-bottom {
  max-width: var(--px-w-content);
  margin: 40px auto 0;
  padding: 20px 24px 0;
  border-top: 1px solid var(--px-line);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  color: var(--px-text-3);
}
.px-footer-socials { display: flex; gap: 14px; }
.px-footer-socials a { color: var(--px-text-3) !important; display: inline-flex; }
.px-footer-socials a:hover { color: var(--px-text) !important; }
@media (max-width: 760px) {
  .px-footer-grid { grid-template-columns: 1fr 1fr; gap: 32px 24px; }
  .px-footer-grid > div:first-child { grid-column: 1 / -1; }
  .px-footer-col a { padding: 6px 0; }
  .px-footer-bottom {
    flex-direction: column;
    align-items: flex-start;
    gap: 14px;
    margin-top: 32px;
  }
}

/* ═══════════════════════════════════════════════════════════════════
   AUTH
   ═══════════════════════════════════════════════════════════════════ */
.px-auth-wrap {
  min-height: 100vh;
  min-height: 100svh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: clamp(84px, 14vw, 100px) var(--px-gutter) clamp(40px, 8vw, 60px);
}
.px-auth-card {
  width: 100%;
  max-width: 380px;
}
.px-auth-card h1 {
  font-size: 22px;
  margin-bottom: 6px;
}
.px-auth-sub { color: var(--px-text-2); font-size: 14px; margin: 0 0 28px; }
.px-auth-google {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  width: 100%;
  padding: 10px 0;
  border: 1px solid var(--px-line-strong);
  border-radius: var(--px-radius-sm);
  background: var(--px-surface);
  color: var(--px-text) !important;
  text-decoration: none !important;
  font-size: 14px;
  font-weight: 500;
  transition: border-color var(--px-t-fast) var(--px-ease), background var(--px-t-fast) var(--px-ease);
}
.px-auth-google:hover { border-color: var(--px-text-3); background: var(--px-surface-2); }
.px-auth-google img { width: 16px; height: 16px; }
.px-auth-divider {
  display: flex;
  align-items: center;
  gap: 12px;
  margin: 22px 0;
  color: var(--px-text-3);
  font-size: 12px;
}
.px-auth-divider::before, .px-auth-divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--px-line);
}
.px-auth-form { display: flex; flex-direction: column; gap: 12px; }
.px-auth-error {
  background: color-mix(in srgb, var(--px-danger) 10%, transparent);
  border: 1px solid color-mix(in srgb, var(--px-danger) 35%, transparent);
  color: var(--px-danger);
  border-radius: var(--px-radius-sm);
  padding: 9px 12px;
  font-size: 13px;
  margin-bottom: 14px;
}
.px-auth-switch {
  margin-top: 24px;
  font-size: 13.5px;
  color: var(--px-text-2);
  text-align: center;
}
.px-auth-switch a { color: var(--px-accent-strong) !important; font-weight: 500; }
.px-light .px-auth-switch a { color: var(--px-accent) !important; }

/* ═══════════════════════════════════════════════════════════════════
   LANDING
   ═══════════════════════════════════════════════════════════════════ */
.px-hero {
  padding: clamp(116px, 18vw, 168px) 0 clamp(56px, 10vw, 88px);
  text-align: center;
}
.px-hero h1 {
  font-family: var(--px-font-display);
  font-size: clamp(33px, 6.5vw, 68px);
  font-weight: 500;
  letter-spacing: -0.02em;
  line-height: 1.08;
  max-width: 820px;
  margin: 0 auto 22px;
}
.px-hero-sub {
  font-size: clamp(15px, 2.2vw, 17px);
  color: var(--px-text-2);
  max-width: 560px;
  margin: 0 auto clamp(28px, 5vw, 36px);
  line-height: 1.65;
}
.px-hero-ctas {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
  margin-bottom: 20px;
}
@media (max-width: 480px) {
  .px-hero-ctas { flex-direction: column; align-items: stretch; max-width: 320px; margin-left: auto; margin-right: auto; }
  .px-hero-ctas .px-btn { width: 100%; }
}
.px-hero-note { font-size: 13px; color: var(--px-text-3); }

/* product frame */
.px-frame-wrap { padding: 40px 0 0; }
.px-frame {
  max-width: 960px;
  margin: 0 auto;
  border: 1px solid var(--px-line-strong);
  border-radius: var(--px-radius-lg);
  background: var(--px-surface);
  box-shadow: var(--px-shadow-lg);
  overflow: hidden;
  text-align: left;
}
.px-frame-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 11px 16px;
  border-bottom: 1px solid var(--px-line);
  background: var(--px-surface-2);
}
.px-frame-dot { width: 9px; height: 9px; border-radius: 50%; background: var(--px-line-strong); }
.px-frame-url {
  margin-left: 10px;
  font-size: 12px;
  color: var(--px-text-3);
  font-family: var(--px-font-mono);
}
.px-frame-body { display: grid; grid-template-columns: 200px 1fr; min-height: 380px; }
.px-frame-side {
  border-right: 1px solid var(--px-line);
  padding: 16px 12px;
  font-size: 12.5px;
  color: var(--px-text-3);
  background: var(--px-surface);
}
.px-frame-side-item { padding: 7px 10px; border-radius: var(--px-radius-sm); margin-bottom: 2px; }
.px-frame-side-item.active { background: var(--px-surface-2); color: var(--px-text); }
.px-frame-main { padding: 28px 32px; }
.px-frame-msg { max-width: 460px; margin-bottom: 18px; }
.px-frame-msg-user {
  margin-left: auto;
  background: var(--px-surface-2);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius);
  padding: 10px 14px;
  font-size: 13.5px;
  color: var(--px-text);
  width: fit-content;
}
.px-frame-msg-label {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--px-text-3);
  margin-bottom: 8px;
}
.px-frame-msg-body { font-size: 13.5px; color: var(--px-text-2); line-height: 1.7; }
.px-frame-step { display: flex; align-items: center; gap: 8px; padding: 3px 0; }
.px-frame-check {
  width: 14px; height: 14px;
  border-radius: 50%;
  background: color-mix(in srgb, var(--px-success) 18%, transparent);
  color: var(--px-success);
  font-size: 9px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
@media (max-width: 720px) {
  .px-frame-body { grid-template-columns: 1fr; min-height: 0; }
  .px-frame-side { display: none; }
  .px-frame-main { padding: 20px 18px; }
  .px-frame-msg { max-width: 100%; }
}

/* trust strip */
.px-trust {
  padding: 48px 0;
  border-top: 1px solid var(--px-line);
}
.px-trust p {
  text-align: center;
  font-size: 12px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--px-text-3);
  margin: 0 0 24px;
}
.px-trust-row {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: clamp(22px, 5vw, 48px) clamp(24px, 5vw, 48px);
  flex-wrap: wrap;
  opacity: 0.55;
}
.px-trust-row span {
  font-size: 15px;
  font-weight: 600;
  letter-spacing: 0.02em;
  color: var(--px-text-2);
}

/* section headers */
.px-sec-head { max-width: 640px; margin-bottom: clamp(36px, 6.5vw, 56px); }
.px-sec-head.center { margin-left: auto; margin-right: auto; text-align: center; }
.px-sec-head h2 {
  font-family: var(--px-font-display);
  font-size: clamp(28px, 3.6vw, 38px);
  font-weight: 500;
  margin-bottom: 14px;
}
.px-sec-head p { color: var(--px-text-2); font-size: 15.5px; margin: 0; line-height: 1.65; }

/* features */
.px-feature-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1px;
  background: var(--px-line);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius-lg);
  overflow: hidden;
}
.px-feature {
  background: var(--px-bg);
  padding: 32px 28px;
  transition: background var(--px-t) var(--px-ease);
}
.px-feature:hover { background: var(--px-surface); }
.px-feature-icon {
  width: 34px; height: 34px;
  border: 1px solid var(--px-line-strong);
  border-radius: var(--px-radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--px-accent-strong);
  margin-bottom: 18px;
}
.px-light .px-feature-icon { color: var(--px-accent); }
.px-feature h3 { font-size: 15.5px; margin-bottom: 8px; font-weight: 600; }
.px-feature p { font-size: 13.5px; color: var(--px-text-2); line-height: 1.65; margin: 0; }
@media (max-width: 900px) { .px-feature-grid { grid-template-columns: 1fr 1fr; } }
@media (max-width: 600px) { .px-feature-grid { grid-template-columns: 1fr; } }

/* how it works — a real sequence, numbering earns its place */
.px-steps { display: grid; grid-template-columns: repeat(3, 1fr); gap: 40px; }
.px-step-num {
  font-family: var(--px-font-mono);
  font-size: 12px;
  color: var(--px-text-3);
  margin-bottom: 14px;
  display: block;
}
.px-step h3 { font-size: 16px; margin-bottom: 8px; }
.px-step p { font-size: 14px; color: var(--px-text-2); line-height: 1.65; margin: 0; }
@media (max-width: 760px) { .px-steps { grid-template-columns: 1fr; gap: 32px; } }

/* FAQ */
.px-faq { max-width: 720px; margin: 0 auto; }
.px-faq details {
  border-bottom: 1px solid var(--px-line);
  padding: 4px 0;
}
.px-faq summary {
  cursor: pointer;
  list-style: none;
  padding: 18px 0;
  font-size: 15px;
  font-weight: 500;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
}
.px-faq summary::-webkit-details-marker { display: none; }
.px-faq summary::after {
  content: '+';
  color: var(--px-text-3);
  font-size: 18px;
  font-weight: 300;
  transition: transform var(--px-t) var(--px-ease);
}
.px-faq details[open] summary::after { transform: rotate(45deg); }
.px-faq details p {
  margin: 0;
  padding: 0 0 20px;
  color: var(--px-text-2);
  font-size: 14px;
  line-height: 1.7;
  max-width: 620px;
}

/* CTA */
.px-cta { text-align: center; padding: clamp(72px, 12vw, 120px) 0; }
.px-cta h2 {
  font-family: var(--px-font-display);
  font-size: clamp(26px, 4vw, 44px);
  font-weight: 500;
  margin-bottom: 16px;
}
.px-cta p { color: var(--px-text-2); margin: 0 0 32px; }

/* scroll reveal */
.px-reveal {
  opacity: 0;
  transform: translateY(14px);
  transition: opacity 0.55s var(--px-ease), transform 0.55s var(--px-ease);
}
.px-reveal.in { opacity: 1; transform: translateY(0); }
@media (prefers-reduced-motion: reduce) {
  .px-reveal { opacity: 1; transform: none; }
}

/* ═══════════════════════════════════════════════════════════════════
   DASHBOARD (home)
   ═══════════════════════════════════════════════════════════════════ */
.px-dash { padding: clamp(84px, 13vw, 108px) 0 clamp(56px, 10vw, 80px); }
.px-dash-head { margin-bottom: clamp(24px, 5vw, 36px); }
.px-dash-head h1 { font-size: 24px; letter-spacing: -0.02em; margin-bottom: 6px; }
.px-dash-head p { color: var(--px-text-2); margin: 0; font-size: 14.5px; }

.px-quick-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 14px;
  margin-bottom: var(--px-space-blk);
}
.px-quick {
  display: block;
  background: var(--px-surface);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius-lg);
  padding: 22px;
  text-decoration: none !important;
  color: var(--px-text) !important;
  transition: border-color var(--px-t) var(--px-ease), transform var(--px-t) var(--px-ease);
}
.px-quick:hover { border-color: var(--px-line-strong); transform: translateY(-1px); }
.px-quick-icon {
  width: 32px; height: 32px;
  border: 1px solid var(--px-line-strong);
  border-radius: var(--px-radius-sm);
  display: flex; align-items: center; justify-content: center;
  color: var(--px-accent-strong);
  margin-bottom: 14px;
}
.px-light .px-quick-icon { color: var(--px-accent); }
.px-quick h3 { font-size: 15px; margin-bottom: 5px; }
.px-quick p { font-size: 13px; color: var(--px-text-2); margin: 0; line-height: 1.55; }
@media (max-width: 760px) {
  .px-quick-grid { grid-template-columns: 1fr; gap: 10px; }
  .px-quick { display: flex; align-items: center; gap: 14px; padding: 14px 16px; }
  .px-quick-icon { margin-bottom: 0; flex-shrink: 0; }
  .px-quick h3 { margin-bottom: 2px; }
}

.px-dash-sec { margin-bottom: clamp(20px, 4vw, 28px); }
.px-dash-sec:last-child { margin-bottom: 0; }
.px-dash-sec-head {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  margin-bottom: 18px;
}
.px-dash-sec-head h2 { font-size: 16px; font-weight: 600; }
.px-dash-sec-head a { font-size: 13px; color: var(--px-text-2) !important; }
.px-dash-sec-head a:hover { color: var(--px-text) !important; }

.px-tool-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 14px;
}
.px-tool {
  background: var(--px-surface);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius);
  padding: 18px;
  display: block;
  text-decoration: none !important;
  color: var(--px-text) !important;
  transition: border-color var(--px-t) var(--px-ease);
}
.px-tool:hover { border-color: var(--px-line-strong); }
.px-tool-top { display: flex; align-items: center; gap: 10px; margin-bottom: 10px; }
.px-tool-logo {
  width: 28px; height: 28px;
  border-radius: var(--px-radius-sm);
  object-fit: cover;
  background: var(--px-surface-2);
  border: 1px solid var(--px-line);
}
.px-tool h3 { font-size: 14px; font-weight: 550; margin: 0; }
.px-tool p {
  font-size: 12.5px;
  color: var(--px-text-2);
  margin: 0;
  line-height: 1.55;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
@media (max-width: 980px) { .px-tool-grid { grid-template-columns: 1fr 1fr; } }
@media (max-width: 560px) { .px-tool-grid { grid-template-columns: 1fr; } }

.px-pill-row { display: flex; flex-wrap: wrap; gap: 8px; }
.px-pill {
  padding: 6px 14px;
  border: 1px solid var(--px-line-strong);
  border-radius: 999px;
  font-size: 13px;
  color: var(--px-text-2) !important;
  text-decoration: none !important;
  transition: border-color var(--px-t-fast) var(--px-ease), color var(--px-t-fast) var(--px-ease);
}
.px-pill:hover { border-color: var(--px-text-3); color: var(--px-text) !important; }

/* ═══════════════════════════════════════════════════════════════════
   PRICING
   ═══════════════════════════════════════════════════════════════════ */
.px-pricing-hero { padding: clamp(104px, 16vw, 148px) 0 clamp(40px, 7vw, 56px); text-align: center; }
.px-pricing-hero h1 {
  font-family: var(--px-font-display);
  font-size: clamp(30px, 5vw, 52px);
  font-weight: 500;
  margin: 18px 0 16px;
}
.px-pricing-hero p {
  color: var(--px-text-2);
  font-size: 16px;
  max-width: 480px;
  margin: 0 auto;
  line-height: 1.65;
}
.px-free-callout {
  max-width: 680px;
  margin: 48px auto 0;
  background: var(--px-surface);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius-lg);
  padding: 22px 28px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 20px;
  text-align: left;
}
.px-free-callout h3 { font-size: 15px; margin-bottom: 4px; }
.px-free-callout p { font-size: 13.5px; color: var(--px-text-2); margin: 0; }
@media (max-width: 600px) { .px-free-callout { flex-direction: column; align-items: flex-start; } }

.pack-card {
  background: var(--px-surface);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius-lg);
  padding: 28px 24px;
  position: relative;
  transition: border-color var(--px-t) var(--px-ease), transform var(--px-t) var(--px-ease);
}
.pack-card:hover { border-color: var(--px-line-strong); transform: translateY(-2px); }
.pack-card.popular { border-color: var(--px-accent); }
.popular-badge, .best-deal-badge {
  position: absolute;
  top: 16px; right: 16px;
  font-size: 10.5px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 3px 9px;
  border-radius: 999px;
}
.popular-badge { background: var(--px-accent); color: var(--px-accent-ink); }
.best-deal-badge {
  border: 1px solid var(--px-line-strong);
  color: var(--px-text-2);
}
.pack-price {
  font-size: 30px;
  font-weight: 600;
  letter-spacing: -0.02em;
}
.pack-credits-line { color: var(--px-text-2); font-size: 14px; margin: 4px 0 2px; }
.pack-name {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--px-text-3);
  margin-bottom: 14px;
}
.pack-meta { font-size: 12.5px; color: var(--px-text-3); margin-bottom: 20px; }
.btn-pack {
  width: 100%;
  padding: 10px 0;
  border-radius: var(--px-radius-sm);
  border: 1px solid var(--px-line-strong);
  background: transparent;
  color: var(--px-text);
  font-family: var(--px-font-sans);
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: background var(--px-t-fast) var(--px-ease), border-color var(--px-t-fast) var(--px-ease);
}
.btn-pack:hover { background: var(--px-surface-2); border-color: var(--px-text-3); }
.pack-card.popular .btn-pack {
  background: var(--px-accent);
  border-color: var(--px-accent);
  color: var(--px-accent-ink);
}
.pack-card.popular .btn-pack:hover { background: var(--px-accent-strong); }
.btn-pack[disabled] { opacity: 0.6; cursor: default; }

.packs-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 16px;
  max-width: var(--px-w-content);
  margin: 0 auto;
  padding: 0 var(--px-gutter);
}

.px-credit-table-sec { max-width: 640px; margin: clamp(56px, 10vw, 88px) auto clamp(64px, 11vw, 96px); padding: 0 var(--px-gutter); }
.px-credit-table-sec h2 {
  font-family: var(--px-font-display);
  font-size: 26px;
  font-weight: 500;
  text-align: center;
  margin-bottom: 28px;
}

/* toast */
.toast {
  position: fixed;
  bottom: calc(24px + env(safe-area-inset-bottom));
  left: 50%;
  max-width: calc(100vw - 2 * var(--px-gutter));
  transform: translate(-50%, 12px);
  background: var(--px-surface);
  border: 1px solid var(--px-line-strong);
  border-radius: var(--px-radius);
  box-shadow: var(--px-shadow);
  color: var(--px-text);
  font-family: var(--px-font-sans);
  font-size: 13.5px;
  padding: 11px 18px;
  opacity: 0;
  pointer-events: none;
  transition: opacity var(--px-t) var(--px-ease), transform var(--px-t) var(--px-ease);
  z-index: 10000;
}
.toast.success, .toast.error { opacity: 1; transform: translate(-50%, 0); }
.toast.error { border-color: color-mix(in srgb, var(--px-danger) 45%, transparent); color: var(--px-danger); }

/* ═══════════════════════════════════════════════════════════════════
   PLATFORM v1.1 — workspace, account, blog, project engine components
   ═══════════════════════════════════════════════════════════════════ */

/* ── Workspace dashboard ─────────────────────────────────────────── */
.px-dash-grid {
  display: grid;
  grid-template-columns: 2fr 1fr;
  gap: 20px;
  align-items: start;
}
@media (max-width: 900px) { .px-dash-grid { grid-template-columns: 1fr; } }

.px-continue {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 20px 24px;
  background: var(--px-surface);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius-lg);
  padding: var(--px-space-el);
  margin-bottom: clamp(16px, 3vw, 24px);
  flex-wrap: wrap;
}
.px-continue h2 { font-size: 18px; margin-bottom: 6px; }
.px-continue p { color: var(--px-text-2); font-size: 14px; margin: 0; max-width: 460px; }
.px-continue-actions { display: flex; gap: 10px; flex-wrap: wrap; }
@media (max-width: 600px) {
  .px-continue { flex-direction: column; align-items: stretch; }
  .px-continue-actions { flex-direction: column; }
  .px-continue-actions .px-btn { width: 100%; }
}

.px-list { display: flex; flex-direction: column; }
.px-list-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 14px;
  padding: 10px 12px;
  border-radius: var(--px-radius-sm);
  transition: background var(--px-t-fast) var(--px-ease);
}
.px-list-row:hover { background: var(--px-surface-2); }
.px-list-row + .px-list-row { border-top: 1px solid var(--px-line); }
.px-list-title {
  font-size: 14px;
  font-weight: 500;
  color: var(--px-text);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.px-list-sub { font-size: 12.5px; color: var(--px-text-3); white-space: nowrap; }

.px-empty {
  padding: 24px 14px;
  text-align: center;
  color: var(--px-text-3);
  font-size: 13.5px;
}
.px-empty a { color: var(--px-accent-strong) !important; }

.px-stat-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 14px;
}
@media (max-width: 480px) { .px-stat-grid { gap: 10px; } }
.px-stat {
  background: var(--px-surface);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius);
  padding: 18px 20px;
}
.px-stat-label {
  font-size: 11.5px;
  font-weight: 600;
  letter-spacing: 0.07em;
  text-transform: uppercase;
  color: var(--px-text-3);
  margin-bottom: 8px;
}
.px-stat-value { font-size: 24px; font-weight: 600; letter-spacing: -0.02em; }
.px-stat-sub { font-size: 12.5px; color: var(--px-text-3); margin-top: 4px; }

.px-bar-track {
  height: 5px;
  background: var(--px-surface-2);
  border-radius: 999px;
  overflow: hidden;
  margin-top: 12px;
}
.px-bar-fill {
  height: 100%;
  background: var(--px-accent);
  border-radius: 999px;
  transition: width 400ms var(--px-ease);
}
.px-bar-fill.warning { background: var(--px-warning); }
.px-bar-fill.full { background: var(--px-danger); }

/* ── Account pages (wallet / billing) ────────────────────────────── */
.px-account { padding: clamp(84px, 13vw, 108px) 0 clamp(64px, 11vw, 96px); }
.px-account .px-dash-head { margin-bottom: clamp(22px, 4vw, 28px); }

.px-usage-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 12px;
}
.px-usage-item {
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius-sm);
  padding: 13px 15px;
  background: var(--px-bg);
}
.px-usage-item .u-label { font-size: 12.5px; font-weight: 550; margin-bottom: 5px; }
.px-usage-item .u-val { font-size: 13px; color: var(--px-text-2); }
.px-usage-item .u-bar {
  height: 4px;
  background: var(--px-surface-2);
  border-radius: 999px;
  overflow: hidden;
  margin: 8px 0 6px;
}
.px-usage-item .u-fill { height: 100%; background: var(--px-accent); border-radius: 999px; }
.px-usage-item .u-fill.full { background: var(--px-danger); }
.px-usage-item .u-note { font-size: 11.5px; color: var(--px-text-3); }

.status-pill {
  display: inline-block;
  padding: 2px 9px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  border: 1px solid var(--px-line-strong);
  color: var(--px-text-2);
}
.status-pill.completed, .status-pill.success { border-color: color-mix(in srgb, var(--px-success) 45%, transparent); color: var(--px-success); }
.status-pill.pending { border-color: color-mix(in srgb, var(--px-warning) 45%, transparent); color: var(--px-warning); }
.status-pill.failed { border-color: color-mix(in srgb, var(--px-danger) 45%, transparent); color: var(--px-danger); }

.px-skel {
  display: inline-block;
  height: 14px;
  width: 90px;
  border-radius: 6px;
  background: linear-gradient(90deg, var(--px-surface-2) 25%, var(--px-surface) 50%, var(--px-surface-2) 75%);
  background-size: 300% 100%;
  animation: px-shimmer 1.4s ease infinite;
}
.px-skel.wide { width: 100%; height: 40px; display: block; margin-bottom: 8px; }
@keyframes px-shimmer { 0% { background-position: 100% 0; } 100% { background-position: -100% 0; } }

.px-txn-credit { color: var(--px-success); font-variant-numeric: tabular-nums; }
.px-txn-debit  { color: var(--px-danger);  font-variant-numeric: tabular-nums; }

/* ── State blocks (errors / empty) ───────────────────────────────── */
.px-state {
  text-align: center;
  padding: 36px 20px;
  color: var(--px-text-2);
  font-size: 14px;
  line-height: 1.65;
}
.px-state .px-btn { margin-top: 14px; }

/* ── Blog ─────────────────────────────────────────────────────────── */
.px-blog-list { display: grid; grid-template-columns: 1fr; gap: 0; max-width: var(--px-w-narrow); margin: 0 auto; }
.px-blog-item {
  display: block;
  padding: 26px 4px;
  border-bottom: 1px solid var(--px-line);
  transition: opacity var(--px-t-fast) var(--px-ease);
}
.px-blog-item:hover h2 { color: var(--px-accent-strong); }
.px-blog-item h2 {
  font-size: 19px;
  font-weight: 600;
  letter-spacing: -0.01em;
  margin-bottom: 8px;
  transition: color var(--px-t-fast) var(--px-ease);
}
.px-blog-item p { color: var(--px-text-2); font-size: 14px; line-height: 1.65; margin: 0 0 10px; }
.px-blog-meta { font-size: 12.5px; color: var(--px-text-3); }

.px-prose { max-width: var(--px-w-narrow); margin: 0 auto; }
.px-prose h1 {
  font-family: var(--px-font-display);
  font-size: clamp(28px, 4.5vw, 40px);
  font-weight: 500;
  line-height: 1.15;
  margin-bottom: 14px;
}
.px-prose-body { font-size: 16px; line-height: 1.8; color: var(--px-text-2); white-space: pre-wrap; }
.px-prose-body p { margin: 0 0 18px; }

/* ── Page hero (about / founders / blog index) ────────────────────── */
.px-page-hero { padding: clamp(104px, 16vw, 148px) 0 clamp(44px, 8vw, 64px); }
.px-page-hero.center { text-align: center; }
.px-page-hero h1 {
  font-family: var(--px-font-display);
  font-size: clamp(29px, 5vw, 48px);
  font-weight: 500;
  margin: 14px 0 16px;
  letter-spacing: -0.01em;
}
.px-page-hero p {
  color: var(--px-text-2);
  font-size: 16px;
  line-height: 1.7;
  max-width: 560px;
  margin: 0;
}
.px-page-hero.center p { margin: 0 auto; }

.px-founder-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 20px;
  max-width: 860px;
  margin: 0 auto;
}
.px-founder {
  background: var(--px-surface);
  border: 1px solid var(--px-line);
  border-radius: var(--px-radius-lg);
  padding: 30px 28px;
}
.px-founder .name { font-size: 17px; font-weight: 600; margin-bottom: 3px; }
.px-founder .role {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.07em;
  text-transform: uppercase;
  color: var(--px-accent-strong);
  margin-bottom: 16px;
}
.px-founder .desc { font-size: 14px; color: var(--px-text-2); line-height: 1.7; margin-bottom: 18px; }
.px-founder .links { display: flex; gap: 14px; }
.px-founder .links a { font-size: 13px; color: var(--px-text-2) !important; border-bottom: 1px solid var(--px-line-strong); padding-bottom: 1px; }
.px-founder .links a:hover { color: var(--px-text) !important; border-color: var(--px-text-3); }

/* ── Error pages ──────────────────────────────────────────────────── */
.px-error-wrap {
  min-height: 100vh;
  min-height: 100svh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 32px var(--px-gutter);
}
.px-error-code {
  font-family: var(--px-font-display);
  font-size: clamp(72px, 14vw, 120px);
  font-weight: 500;
  line-height: 1;
  color: var(--px-text);
  margin: 0 0 10px;
}
.px-error-wrap h1 { font-size: 19px; margin-bottom: 8px; }
.px-error-wrap p { color: var(--px-text-2); font-size: 14.5px; max-width: 380px; margin: 0 0 26px; line-height: 1.65; }

@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700&family=Syne:wght@400;600;700;800&family=JetBrains+Mono:wght@400;500&display=swap');

*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

:root {
  --void: #020408;
  --deep: #04080f;
  --surface: rgba(8,16,32,0.85);
  --surface-2: rgba(12,22,42,0.9);
  --glass: rgba(255,255,255,0.03);
  --glass-border: rgba(255,255,255,0.07);
  --cyan: #00d4ff;
  --cyan-dim: rgba(0,212,255,0.12);
  --cyan-glow: rgba(0,212,255,0.25);
  --violet: #7c3aed;
  --violet-bright: #a78bfa;
  --violet-dim: rgba(124,58,237,0.15);
  --emerald: #10b981;
  --emerald-dim: rgba(16,185,129,0.12);
  --gold: #f59e0b;
  --text-primary: #f0f4ff;
  --text-secondary: rgba(200,215,245,0.6);
  --text-dim: rgba(150,170,210,0.35);
  --font-display: 'Syne', sans-serif;
  --font-body: 'Space Grotesk', sans-serif;
  --font-mono: 'JetBrains Mono', monospace;
  --ease-spring: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-smooth: cubic-bezier(0.4, 0, 0.2, 1);
  --max-w: 1100px;
}

html { scroll-behavior: smooth; }

body {
  background: var(--void);
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: 16px;
  line-height: 1.6;
  overflow-x: hidden;
  -webkit-font-smoothing: antialiased;
  cursor: none;
}

/* ── CUSTOM CURSOR ── */
#cursor {
  position: fixed;
  width: 10px; height: 10px;
  background: var(--cyan);
  border-radius: 50%;
  pointer-events: none;
  z-index: 99999;
  transform: translate(-50%, -50%);
  transition: width 0.2s, height 0.2s, opacity 0.2s;
  mix-blend-mode: screen;
}
#cursor-ring {
  position: fixed;
  width: 36px; height: 36px;
  border: 1px solid rgba(0,212,255,0.4);
  border-radius: 50%;
  pointer-events: none;
  z-index: 99998;
  transform: translate(-50%, -50%);
  transition: transform 0.12s var(--ease-smooth), width 0.3s, height 0.3s, border-color 0.3s;
}
body:has(a:hover) #cursor, body:has(button:hover) #cursor { width: 20px; height: 20px; }
body:has(a:hover) #cursor-ring, body:has(button:hover) #cursor-ring { width: 56px; height: 56px; border-color: rgba(0,212,255,0.2); }

@media (pointer: coarse) { #cursor, #cursor-ring { display: none; } body { cursor: auto; } }

/* ── NOISE TEXTURE ── */
body::before {
  content: '';
  position: fixed; inset: 0;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.03'/%3E%3C/svg%3E");
  pointer-events: none; z-index: 1; opacity: 0.4;
}

/* ── AMBIENT BACKGROUND ── */
.ambient { position: fixed; inset: 0; pointer-events: none; z-index: 0; overflow: hidden; }

.ambient-orb {
  position: absolute; border-radius: 50%; filter: blur(130px);
  opacity: 0; animation: orbIn 2s var(--ease-spring) forwards;
}
.ambient-orb-1 {
  width: 1100px; height: 700px;
  background: radial-gradient(ellipse, rgba(0,212,255,0.07) 0%, transparent 65%);
  top: -200px; left: 50%; transform: translateX(-60%);
  animation-delay: 0.3s;
  animation: orbIn 2s var(--ease-spring) 0.3s forwards, orb1Float 18s ease-in-out infinite 2.3s;
}
.ambient-orb-2 {
  width: 700px; height: 700px;
  background: radial-gradient(circle, rgba(124,58,237,0.1) 0%, transparent 65%);
  top: 25%; right: -150px;
  animation-delay: 0.7s;
  animation: orbIn 2s var(--ease-spring) 0.7s forwards, orb2Float 22s ease-in-out infinite 2.7s;
}
.ambient-orb-3 {
  width: 600px; height: 600px;
  background: radial-gradient(circle, rgba(0,212,255,0.05) 0%, transparent 65%);
  bottom: 0; left: -100px;
  animation-delay: 1s;
  animation: orbIn 2s var(--ease-spring) 1s forwards, orb3Float 26s ease-in-out infinite 3s;
}
.ambient-orb-4 {
  width: 500px; height: 500px;
  background: radial-gradient(circle, rgba(16,185,129,0.07) 0%, transparent 65%);
  top: 60%; right: 20%;
  animation-delay: 1.2s;
  animation: orbIn 2s var(--ease-spring) 1.2s forwards, orb4Float 20s ease-in-out infinite 3.2s;
}

@keyframes orbIn { to { opacity: 1; } }
@keyframes orb1Float { 0%,100%{transform:translateX(-60%) translateY(0)} 50%{transform:translateX(-55%) translateY(-40px)} }
@keyframes orb2Float { 0%,100%{transform:translateY(0) translateX(0)} 50%{transform:translateY(-50px) translateX(-30px)} }
@keyframes orb3Float { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-35px)} }
@keyframes orb4Float { 0%,100%{transform:translateY(0) scale(1)} 50%{transform:translateY(-45px) scale(1.05)} }

/* ── GRID UNDERLAY ── */
.grid-underlay {
  position: fixed; inset: 0; pointer-events: none; z-index: 0;
  background-image:
    linear-gradient(rgba(0,212,255,0.025) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0,212,255,0.025) 1px, transparent 1px);
  background-size: 80px 80px;
  mask-image: radial-gradient(ellipse 90% 60% at 50% 0%, black 0%, transparent 80%);
}

/* ── SHARED SECTION STRUCTURE ── */
.section-wrap {
  position: relative; z-index: 2;
  padding: 120px 24px;
}
.section-inner { max-width: var(--max-w); margin: 0 auto; }

.section-header { text-align: center; margin-bottom: 64px; }

.eyebrow {
  display: inline-flex; align-items: center; gap: 8px;
  font-size: 10.5px; font-weight: 600; letter-spacing: 0.18em; text-transform: uppercase;
  color: var(--cyan);
  background: rgba(0,212,255,0.06);
  border: 1px solid rgba(0,212,255,0.2);
  padding: 5px 16px; border-radius: 100px;
  margin-bottom: 20px;
  font-family: var(--font-mono);
}
.eyebrow-dot {
  width: 5px; height: 5px; border-radius: 50%;
  background: var(--cyan);
  box-shadow: 0 0 8px var(--cyan);
  animation: pulseDot 2.5s ease-in-out infinite;
}
@keyframes pulseDot { 0%,100%{opacity:1;transform:scale(1)} 50%{opacity:0.4;transform:scale(0.6)} }

.section-heading {
  font-family: var(--font-display);
  font-size: clamp(2rem, 4vw, 3rem);
  font-weight: 800;
  line-height: 1.15;
  letter-spacing: -0.025em;
  color: var(--text-primary);
  margin-bottom: 16px;
}
.section-heading .g {
  background: linear-gradient(135deg, #00d4ff 0%, #a78bfa 50%, #10b981 100%);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
  background-size: 200%;
  animation: gradientShift 6s ease infinite;
}
@keyframes gradientShift { 0%,100%{background-position:0%} 50%{background-position:100%} }

.section-sub {
  color: var(--text-secondary);
  font-size: 1.05rem;
  max-width: 520px;
  margin: 0 auto;
  line-height: 1.75;
  font-weight: 300;
}

.os-divider {
  border: none;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(0,212,255,0.12), rgba(124,58,237,0.12), transparent);
  max-width: 900px;
  margin: 0 auto;
  position: relative; z-index: 2;
}

/* ════════════════════════════════
   HERO
════════════════════════════════ */
.hero-os {
  position: relative; z-index: 2;
  min-height: 100svh;
  display: grid;
  grid-template-columns: 1fr 1fr;
  align-items: center;
  gap: 60px;
  max-width: var(--max-w);
  margin: 0 auto;
  padding: 140px 24px 80px;
}

.hero-left {
  opacity: 0;
  animation: heroLeft 1s var(--ease-spring) 0.4s forwards;
}
.hero-right {
  opacity: 0;
  animation: heroRight 1s var(--ease-spring) 0.6s forwards;
}
@keyframes heroLeft { to { opacity: 1; transform: translateY(0); } from { transform: translateY(30px); } }
@keyframes heroRight { to { opacity: 1; transform: translateY(0); } from { transform: translateY(40px); } }

/* Status badge */
.hero-badge {
  display: inline-flex; align-items: center; gap: 10px;
  font-family: var(--font-mono);
  font-size: 11px; font-weight: 500; letter-spacing: 0.1em;
  color: var(--cyan);
  background: rgba(0,212,255,0.05);
  border: 1px solid rgba(0,212,255,0.18);
  padding: 7px 16px; border-radius: 100px;
  margin-bottom: 36px;
}
.badge-dot {
  width: 6px; height: 6px; border-radius: 50%;
  background: #10b981;
  box-shadow: 0 0 10px #10b981;
  animation: livePulse 2s ease-in-out infinite;
}
@keyframes livePulse {
  0%,100% { box-shadow: 0 0 10px #10b981; transform: scale(1); }
  50% { box-shadow: 0 0 20px #10b981, 0 0 40px rgba(16,185,129,0.3); transform: scale(1.2); }
}

/* Headline */
.hero-headline {
  font-family: var(--font-display);
  font-size: clamp(2.8rem, 5.5vw, 4.2rem);
  font-weight: 800;
  line-height: 1.05;
  letter-spacing: -0.035em;
  color: var(--text-primary);
  margin-bottom: 28px;
}
.hero-headline .g {
  background: linear-gradient(135deg, #00d4ff 0%, #818cf8 40%, #c084fc 70%, #00d4ff 100%);
  background-size: 300%;
  -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
  animation: gradShift 5s ease infinite;
}
@keyframes gradShift { 0%,100%{background-position:0%} 50%{background-position:100%} }

.hero-sub {
  font-size: 1.1rem;
  color: var(--text-secondary);
  line-height: 1.75;
  margin-bottom: 44px;
  max-width: 480px;
  font-weight: 300;
}

/* CTA buttons */
.hero-ctas { display: flex; gap: 14px; flex-wrap: wrap; align-items: center; }

.btn-hero-primary {
  display: inline-flex; align-items: center; gap: 10px;
  padding: 15px 30px;
  background: linear-gradient(135deg, #00d4ff 0%, #6366f1 100%);
  color: #fff;
  font-family: var(--font-display);
  font-size: 15px; font-weight: 700;
  border-radius: 12px;
  text-decoration: none;
  position: relative; overflow: hidden;
  box-shadow: 0 0 40px rgba(0,212,255,0.3), 0 4px 24px rgba(0,0,0,0.4);
  transition: box-shadow 0.3s, transform 0.2s;
}
.btn-hero-primary::before {
  content: '';
  position: absolute; inset: 0;
  background: linear-gradient(135deg, rgba(255,255,255,0.15), transparent);
  opacity: 0;
  transition: opacity 0.3s;
}
.btn-hero-primary:hover { box-shadow: 0 0 60px rgba(0,212,255,0.5), 0 8px 32px rgba(0,0,0,0.4); transform: translateY(-2px); }
.btn-hero-primary:hover::before { opacity: 1; }
.btn-hero-primary svg { width: 16px; height: 16px; }

.btn-hero-ghost {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 15px 26px;
  background: var(--glass);
  color: var(--text-secondary);
  font-family: var(--font-body);
  font-size: 15px; font-weight: 500;
  border: 1px solid var(--glass-border);
  border-radius: 12px;
  text-decoration: none;
  backdrop-filter: blur(12px);
  transition: background 0.2s, color 0.2s, border-color 0.2s, transform 0.2s;
}
.btn-hero-ghost:hover { background: rgba(255,255,255,0.07); color: var(--text-primary); border-color: rgba(0,212,255,0.25); transform: translateY(-1px); }

/* ── HERO VISUAL (RIGHT) ── */
.hero-visual-wrap {
  position: relative;
}

.hero-visual-glow {
  position: absolute;
  width: 120%; height: 120%;
  top: -10%; left: -10%;
  background: radial-gradient(ellipse 60% 60% at 50% 50%, rgba(0,212,255,0.08), transparent);
  pointer-events: none;
  animation: glowPulse 4s ease-in-out infinite;
}
@keyframes glowPulse { 0%,100%{opacity:0.6} 50%{opacity:1} }

.hero-visual {
  position: relative;
  background: linear-gradient(145deg, rgba(8,16,32,0.9), rgba(4,8,20,0.95));
  border: 1px solid rgba(0,212,255,0.12);
  border-radius: 24px;
  padding: 0;
  overflow: hidden;
  box-shadow: 0 40px 100px rgba(0,0,0,0.6), 0 0 0 1px rgba(255,255,255,0.03), inset 0 1px 0 rgba(255,255,255,0.07);
  transform-style: preserve-3d;
  transform: perspective(1200px) rotateY(-6deg) rotateX(2deg);
  transition: transform 0.6s var(--ease-spring);
}
.hero-visual:hover { transform: perspective(1200px) rotateY(-2deg) rotateX(1deg); }

/* Top shimmer line */
.hero-visual::before {
  content: '';
  position: absolute; top: 0; left: 0; right: 0; height: 1px;
  background: linear-gradient(90deg, transparent 5%, rgba(0,212,255,0.6) 40%, rgba(124,58,237,0.6) 65%, transparent 95%);
  z-index: 5;
}

/* Title bar */
.visual-titlebar {
  display: flex; align-items: center; gap: 8px;
  padding: 14px 20px;
  background: rgba(0,212,255,0.03);
  border-bottom: 1px solid rgba(255,255,255,0.05);
}
.visual-dot { width: 8px; height: 8px; border-radius: 50%; }
.visual-dot:nth-child(1) { background: #ff5f57; }
.visual-dot:nth-child(2) { background: #febc2e; }
.visual-dot:nth-child(3) { background: #28c840; }
.visual-tab {
  margin-left: 12px;
  font-family: var(--font-mono);
  font-size: 10px; color: var(--text-dim);
  background: rgba(0,212,255,0.05);
  border: 1px solid rgba(0,212,255,0.1);
  padding: 3px 12px; border-radius: 6px;
}
.visual-tab.active { color: var(--cyan); background: rgba(0,212,255,0.08); border-color: rgba(0,212,255,0.25); }

/* Chat area */
.visual-chat {
  padding: 20px;
  display: flex; flex-direction: column; gap: 14px;
  min-height: 240px;
}

.visual-msg {
  display: flex; flex-direction: column; gap: 6px;
  padding: 12px 16px;
  border-radius: 14px;
  font-size: 13px; line-height: 1.55;
  animation: msgIn 0.4s var(--ease-spring) both;
}
.visual-msg.user {
  background: rgba(0,212,255,0.08);
  border: 1px solid rgba(0,212,255,0.15);
  color: rgba(200,230,255,0.8);
  align-self: flex-end;
  max-width: 85%;
}
.visual-msg.aqua {
  background: rgba(255,255,255,0.03);
  border: 1px solid rgba(255,255,255,0.07);
  color: var(--text-secondary);
  max-width: 95%;
}
.visual-msg-label {
  font-family: var(--font-mono);
  font-size: 10px; font-weight: 600;
  color: var(--cyan); letter-spacing: 0.05em;
}
.visual-check { color: #10b981; }

@keyframes msgIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

.visual-cursor {
  display: inline-block; width: 2px; height: 13px;
  background: var(--cyan);
  border-radius: 1px;
  animation: blink 1.2s ease-in-out infinite;
  vertical-align: middle; margin-left: 3px;
}
@keyframes blink { 0%,100%{opacity:1} 50%{opacity:0} }

/* Workspace strip */
.visual-strip {
  display: flex; gap: 8px; align-items: center;
  padding: 12px 20px 16px;
  border-top: 1px solid rgba(255,255,255,0.05);
  background: rgba(0,0,0,0.2);
}
.ws-chip {
  display: flex; align-items: center; gap: 6px;
  font-family: var(--font-mono);
  font-size: 10.5px; color: var(--text-dim);
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.07);
  padding: 5px 12px; border-radius: 8px;
  transition: all 0.2s;
}
.ws-chip.active {
  color: var(--cyan);
  background: rgba(0,212,255,0.08);
  border-color: rgba(0,212,255,0.2);
  box-shadow: 0 0 12px rgba(0,212,255,0.15);
}

/* Floating card decorations */
.hero-float-card {
  position: absolute;
  background: var(--surface-2);
  border: 1px solid rgba(0,212,255,0.15);
  border-radius: 14px;
  padding: 10px 16px;
  font-family: var(--font-mono);
  font-size: 11px;
  backdrop-filter: blur(16px);
  box-shadow: 0 16px 40px rgba(0,0,0,0.4);
  animation: floatCard 5s ease-in-out infinite;
}
.hero-float-card.card-1 {
  bottom: -20px; left: -30px;
  color: #10b981;
  border-color: rgba(16,185,129,0.2);
  background: rgba(16,185,129,0.05);
  animation-delay: 0s;
}
.hero-float-card.card-2 {
  top: -15px; right: -20px;
  color: var(--violet-bright);
  border-color: rgba(167,139,250,0.2);
  background: rgba(124,58,237,0.08);
  animation-delay: 1.5s;
}
@keyframes floatCard { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-10px)} }


/* ════════════════════════════════
   SECTION 2 — PILLARS
════════════════════════════════ */
.pillars-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 24px;
}

.pillar-card {
  position: relative;
  background: linear-gradient(145deg, rgba(8,16,32,0.8), rgba(4,8,20,0.9));
  border: 1px solid var(--glass-border);
  border-radius: 24px;
  padding: 36px 28px;
  overflow: hidden;
  transition: transform 0.35s var(--ease-spring), box-shadow 0.35s, border-color 0.3s;
  cursor: default;
}
.pillar-card::before {
  content: '';
  position: absolute; inset: 0; border-radius: 24px;
  opacity: 0;
  transition: opacity 0.4s;
}
.pillar-card:hover { transform: translateY(-8px); }

.card-aqua { border-color: rgba(0,212,255,0.1); }
.card-aqua::before { background: radial-gradient(ellipse at 30% 0%, rgba(0,212,255,0.06), transparent 60%); }
.card-aqua:hover { border-color: rgba(0,212,255,0.3); box-shadow: 0 24px 60px rgba(0,212,255,0.1), 0 0 0 1px rgba(0,212,255,0.15); }
.card-aqua:hover::before { opacity: 1; }

.card-workspace { border-color: rgba(124,58,237,0.1); }
.card-workspace::before { background: radial-gradient(ellipse at 30% 0%, rgba(124,58,237,0.08), transparent 60%); }
.card-workspace:hover { border-color: rgba(167,139,250,0.3); box-shadow: 0 24px 60px rgba(124,58,237,0.1), 0 0 0 1px rgba(124,58,237,0.15); }
.card-workspace:hover::before { opacity: 1; }

.card-builder { border-color: rgba(16,185,129,0.1); }
.card-builder::before { background: radial-gradient(ellipse at 30% 0%, rgba(16,185,129,0.07), transparent 60%); }
.card-builder:hover { border-color: rgba(16,185,129,0.3); box-shadow: 0 24px 60px rgba(16,185,129,0.1), 0 0 0 1px rgba(16,185,129,0.1); }
.card-builder:hover::before { opacity: 1; }

/* Top accent line per card */
.card-aqua::after { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 1px; background: linear-gradient(90deg, transparent, rgba(0,212,255,0.5), transparent); }
.card-workspace::after { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 1px; background: linear-gradient(90deg, transparent, rgba(167,139,250,0.5), transparent); }
.card-builder::after { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 1px; background: linear-gradient(90deg, transparent, rgba(16,185,129,0.5), transparent); }

.pillar-icon {
  font-size: 28px; margin-bottom: 20px;
  display: inline-flex; align-items: center; justify-content: center;
  width: 56px; height: 56px; border-radius: 16px;
}
.ai-icon { background: rgba(0,212,255,0.08); border: 1px solid rgba(0,212,255,0.15); }
.ws-icon { background: rgba(124,58,237,0.1); border: 1px solid rgba(124,58,237,0.2); }
.pb-icon { background: rgba(16,185,129,0.08); border: 1px solid rgba(16,185,129,0.15); }

.pillar-label {
  font-family: var(--font-mono);
  font-size: 10px; font-weight: 600; letter-spacing: 0.12em; text-transform: uppercase;
  margin-bottom: 10px;
}
.cyan { color: var(--cyan); }
.violet { color: var(--violet-bright); }
.emerald { color: var(--emerald); }

.pillar-name {
  font-family: var(--font-display);
  font-size: 1.5rem; font-weight: 700;
  letter-spacing: -0.02em;
  margin-bottom: 14px;
  color: var(--text-primary);
}

.pillar-desc {
  font-size: 0.92rem; color: var(--text-secondary);
  line-height: 1.65; margin-bottom: 20px; font-weight: 300;
}

.pillar-tags {
  display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 28px;
}
.pillar-tag {
  font-family: var(--font-mono);
  font-size: 10px; font-weight: 500;
  color: var(--text-dim);
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.08);
  padding: 4px 10px; border-radius: 6px;
}

.pillar-cta {
  display: inline-flex; align-items: center; gap: 8px;
  font-size: 13.5px; font-weight: 600;
  text-decoration: none;
  transition: gap 0.2s, opacity 0.2s;
}
.pillar-cta:hover { opacity: 0.8; gap: 12px; }
.pillar-cta-arrow { transition: transform 0.2s; }
.pillar-cta:hover .pillar-cta-arrow { transform: translateX(4px); }
.cyan-cta { color: var(--cyan); }
.violet-cta { color: var(--violet-bright); }
.emerald-cta { color: var(--emerald); }


/* ════════════════════════════════
   SECTION 3 — USE CASES
════════════════════════════════ */
.usecases-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 18px;
}

.usecase-card {
  position: relative;
  display: flex; align-items: center; gap: 20px;
  background: var(--glass);
  border: 1px solid var(--glass-border);
  border-radius: 18px;
  padding: 24px;
  text-decoration: none;
  overflow: hidden;
  transition: all 0.3s var(--ease-spring);
  group: true;
}
.usecase-card::before {
  content: '';
  position: absolute; inset: 0;
  background: linear-gradient(135deg, rgba(0,212,255,0.04), transparent);
  opacity: 0; transition: opacity 0.3s;
}
.usecase-card:hover { border-color: rgba(0,212,255,0.25); transform: translateY(-3px); box-shadow: 0 16px 40px rgba(0,0,0,0.3); }
.usecase-card:hover::before { opacity: 1; }

.usecase-card.wide { grid-column: span 2; }

.usecase-icon-wrap {
  font-size: 26px; flex-shrink: 0;
  width: 52px; height: 52px;
  background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08);
  border-radius: 14px;
  display: flex; align-items: center; justify-content: center;
  transition: background 0.2s, border-color 0.2s;
}
.usecase-card:hover .usecase-icon-wrap { background: rgba(0,212,255,0.07); border-color: rgba(0,212,255,0.2); }

.usecase-text { flex: 1; }
.uc-title { font-weight: 600; font-size: 0.95rem; margin-bottom: 5px; color: var(--text-primary); }
.uc-desc { font-size: 0.83rem; color: var(--text-secondary); font-weight: 300; line-height: 1.5; }

.usecase-arrow {
  color: var(--text-dim); font-size: 18px;
  transition: color 0.2s, transform 0.2s;
