"use strict";

/**
 * middleware/asyncHandler.js — Error-safe async route wrapper + response helpers
 */

/**
 * asyncHandler — wraps async route handlers to catch all unhandled rejections.
 * Forwards errors to Express error middleware instead of crashing.
 *
 * @param {Function} fn  async (req, res, next) handler
 */
function asyncHandler(fn) {
  return function (req, res, next) {
    Promise.resolve(fn(req, res, next)).catch(next);
  };
}

/**
 * Standardized success response
 * @param {Response} res
 * @param {any}      data
 * @param {string}   [message]
 * @param {number}   [status=200]
 */
function sendSuccess(res, data, message, status = 200) {
  const body = { success: true };
  if (message !== undefined) body.message = message;
  if (data    !== undefined) body.data    = data;
  return res.status(status).json(body);
}

/**
 * Standardized error response
 * @param {Response} res
 * @param {string}   error
 * @param {number}   [status=500]
 */
function sendError(res, error, status = 500) {
  return res.status(status).json({ success: false, error });
}

/**
 * Global Express error handler — mount LAST in app.
 */
function globalErrorHandler(err, req, res, next) { // eslint-disable-line no-unused-vars
  const { createLogger } = require("../utils/logger");
  const log = createLogger("ERROR_HANDLER");
  log.error(err.message, err.stack);

  if (res.headersSent) return next(err);

  const status = err.status || err.statusCode || 500;
  const message =
    err.code === "LIMIT_FILE_SIZE"        ? "File too large. Maximum 10 MB." :
    err.message?.includes("not found")    ? err.message :
    err.message?.includes("Unauthorized") ? err.message :
    "Internal server error";

  return res.status(status).json({ success: false, error: message });
}

module.exports = { asyncHandler, sendSuccess, sendError, globalErrorHandler };

"use strict";
/**
 * middleware/usage/checkUsage.js
 * AQUIPLEX — Pure credit validation helper.
 *
 * NEVER calls next(). NEVER touches Express req/res lifecycle.
 * Safe to call from routes, sockets, services, cron — anywhere.
 *
 * Usage (non-Express):
 *   const { checkUsage } = require("../middleware/usage/checkUsage");
 *   const result = await checkUsage({ userId, actionType: "chat_message" });
 *   if (!result.allowed) { return { error: result.error, message: result.message }; }
 *   req.creditContext = result.creditContext;
 *
 * Returns:
 *   { allowed: true,  cost, actionType, creditContext: { refund, commit, balanceAfter, ... } }
 *   { allowed: false, status, error, message, ...extra }
 */

const User                              = require("../../models/User");
const { getActionCost }                 = require("../../utils/credits/packs");
const { deductCredits, refundCredits }  = require("../../services/credits/wallet.service");
const {
  hasUnlimitedAccess,
  unlimitedAccessReason,
} = require("../../utils/credits/unlimitedAccess");
const { createLogger } = require("../../utils/logger");

const log = createLogger("CHECK_USAGE");

// ── Auth helper (safe for non-Express too — just returns null if no req) ──────

function getUid(req) {
  return (
    req?.session?.userId    ||
    req?.session?.user?._id ||
    req?.user?._id          ||
    req?.user?.id           ||
    null
  );
}

// ── Pure validator ────────────────────────────────────────────────────────────

/**
 * checkUsage({ userId, actionType, deductOnEntry })
 *
 * @param {string}  userId        — Mongo user _id string
 * @param {string}  actionType    — key from CREDIT_COSTS (e.g. "chat_message")
 * @param {boolean} deductOnEntry — true: deduct now + expose refund(); false: check-only, expose commit()
 *
 * @returns {Promise<CheckResult>}
 *
 * CheckResult (allowed):
 *   { allowed: true, cost, actionType, creditContext: { userId, cost, actionType,
 *     deducted, unlimited, refund(), commit(), balanceAfter } }
 *
 * CheckResult (blocked):
 *   { allowed: false, status: 401|402, error: string, message: string, ...extra }
 */
async function checkUsage({ userId, actionType, deductOnEntry = true }) {
  // ── 1. Auth ──────────────────────────────────────────────────────────────
  if (!userId) {
    return {
      allowed: false,
      status:  401,
      error:   "LOGIN_REQUIRED",
      message: "Please sign in to continue.",
    };
  }

  const user = await User.findById(userId);
  if (!user) {
    return {
      allowed: false,
      status:  401,
      error:   "USER_NOT_FOUND",
      message: "User account not found. Please sign in again.",
    };
  }

  // ── 2. Lazy daily reset ──────────────────────────────────────────────────
  const wasReset = user.resetFreeCreditsIfNeeded();
  if (wasReset) {
    log.info(`[checkUsage] daily IST reset fired userId=${userId} email=${user.email} newFree=${user.wallet.freeCredits}`);
    await user.save();
  }

  // ── 3. Resolve cost ──────────────────────────────────────────────────────
  const cost  = getActionCost(actionType);
  const total = user.wallet.freeCredits + user.wallet.paidCredits;

  // ── 4. Unlimited bypass ──────────────────────────────────────────────────
  const unlimited = hasUnlimitedAccess(user);
  if (unlimited) {
    const reason = unlimitedAccessReason(user);
    log.info("[checkUsage] unlimited bypass granted", { email: user.email, reason });
    return {
      allowed: true,
      cost,
      actionType,
      creditContext: {
        userId,
        cost,
        actionType,
        deducted:  false,
        unlimited: true,
        refund:    () => Promise.resolve(),
        commit:    () => Promise.resolve(),
        balanceAfter: {
          freeCredits:     user.wallet.freeCredits,
          paidCredits:     user.wallet.paidCredits,
          total,
          isUnlimited:     true,
          unlimitedReason: reason,
        },
      },
    };
  }

  // ── 5. Insufficient credits ──────────────────────────────────────────────
  if (cost > 0 && total < cost) {
    log.warn("[checkUsage] insufficient credits", { userId, email: user.email, total, cost, actionType });
    return {
      allowed:      false,
      status:       402,
      error:        "INSUFFICIENT_CREDITS",
      message:      "You don't have enough credits. Top up your wallet to continue.",
      upgradeUrl:   "/wallet",
      freeCredits:  user.wallet.freeCredits,
      paidCredits:  user.wallet.paidCredits,
      totalCredits: total,
      costRequired: cost,
      actionType,
      cta:          "Buy Credits",
    };
  }

  // ── 6. Free action (cost === 0) ──────────────────────────────────────────
  if (cost === 0) {
    return {
      allowed: true,
      cost:    0,
      actionType,
      creditContext: {
        userId,
        cost:      0,
        actionType,
        deducted:  false,
        unlimited: false,
        refund:    () => Promise.resolve(),
        commit:    () => Promise.resolve(),
      },
    };
  }

  // ── 7. Deduct on entry (default) ─────────────────────────────────────────
  if (deductOnEntry) {
    const deductResult = await deductCredits(userId, cost, actionType);
    log.info(`[checkUsage] DEBIT userId=${userId} cost=${cost} actionType=${actionType} remaining=${deductResult.balanceAfter?.total}`);

    return {
      allowed: true,
      cost,
      actionType,
      creditContext: {
        userId,
        cost,
        actionType,
        deducted: true,
        refund: () => {
          log.warn(`[checkUsage] REFUND issued userId=${userId} cost=${cost} actionType=${actionType}`);
          return refundCredits(userId, cost, `${actionType}_failed`);
        },
        commit:       () => Promise.resolve(), // already deducted
        balanceAfter: deductResult.balanceAfter,
      },
    };
  }

  // ── 8. Check-only mode — caller must call commit() after success ──────────
  return {
    allowed: true,
    cost,
    actionType,
    creditContext: {
      userId,
      cost,
      actionType,
      deducted: false,
      refund:   () => Promise.resolve(),
      commit:   () => deductCredits(userId, cost, actionType),
    },
  };
}

module.exports = { checkUsage, getUid };

"use strict";
/**
 * middleware/usage/usageGuard.js
 * AQUIPLEX — Express middleware wrapper for credit checking.
 *
 * This file ONLY handles Express plumbing: calling next(), sending res.
 * All validation logic lives in checkUsage.js.
 *
 * Usage (Express routes only):
 *   router.post('/generate', usageGuard('full_app_gen'), handler)
 *   router.post('/chat',     usageGuard((req) => req.body.mode === 'deep' ? 'deep_research' : 'chat_message'), handler)
 *
 * For non-Express callers (sockets, services, cron):
 *   const { checkUsage } = require("./checkUsage");
 *   const result = await checkUsage({ userId, actionType: "chat_message" });
 *
 * After guard passes:
 *   req.creditContext = { userId, cost, actionType, deducted, refund(), commit(), balanceAfter }
 */

const { checkUsage, getUid } = require("./checkUsage");
const { createLogger }       = require("../../utils/logger");

const log = createLogger("USAGE_MW");

function usageGuard(actionTypeOrFn = "default", options = {}) {
  const deductOnEntry = options.deductOnEntry !== false;

  return async (req, res, next) => {
    try {
      const userId = getUid(req);
      const actionType = typeof actionTypeOrFn === "function"
        ? actionTypeOrFn(req)
        : actionTypeOrFn;

      log.info(`[usageGuard] checking userId=${userId} actionType=${actionType} route=${req.originalUrl}`);

      const result = await checkUsage({ userId, actionType, deductOnEntry });

      if (!result.allowed) {
        const { allowed, status, ...body } = result;
        return res.status(status || 500).json(body);
      }

      req.creditContext = result.creditContext;
      log.info(`[usageGuard] PASS userId=${userId} actionType=${actionType} cost=${result.cost} route=${req.originalUrl}`);
      next();

    } catch (err) {
      log.error("[usageGuard] unexpected error:", err.message, "\n", err.stack);
      return res.status(500).json({
        error:   "USAGE_CHECK_FAILED",
        message: "We couldn't verify your usage right now. Please try again in a moment.",
      });
    }
  };
}

module.exports = { usageGuard };

"use strict";
/**
 * middleware/usage/featureGuard.js
 * AQUIPLEX — Per-feature daily limit enforcement for free users.
 *
 * Usage:
 *   router.post('/generate-image', featureGuard('imageGen'), handler)
 *
 * Features: imageGen | codeMode | webSearch | websiteGen | websiteEdit
 *
 * On pass:  req.featureContext = { feature, used, limit, user }
 *           Call req.featureContext.commit() AFTER successful action to increment.
 * On block: 429 JSON with friendly message + upgrade CTA.
 *
 * Unlimited users bypass all limits.
 */

const User = require("../../models/User");
const { createLogger } = require("../../utils/logger");
const { getISTDateStr } = require("../../utils/date/getISTDayRange");

const log = createLogger("FEATURE_GUARD");

const FEATURE_LABELS = {
  imageGen:    "image generation",
  codeMode:    "code mode",
  webSearch:   "web search",
  websiteGen:  "website generation",
  websiteEdit: "website editing",
};

function getUid(req) {
  return (
    req.session?.userId    ||
    req.session?.user?._id ||
    req.user?._id          ||
    req.user?.id           ||
    null
  );
}

function featureGuard(feature) {
  return async (req, res, next) => {
    if (typeof next !== "function") {
      log.error("[FeatureGuard] CRITICAL: next is not a function — featureGuard called outside middleware chain. Route:", req?.originalUrl);
      return res?.status?.(500)?.json?.({ error: "MIDDLEWARE_CONFIG_ERROR" });
    }
    const uid = getUid(req);
    if (!uid) {
      return res.status(401).json({ error: "LOGIN_REQUIRED", message: "Please sign in to continue." });
    }

    try {
      const user = await User.findById(uid);
      if (!user) return res.status(401).json({ error: "USER_NOT_FOUND" });

      // Lazy resets
      const walletReset = user.resetFreeCreditsIfNeeded();
      const usageReset  = user.resetDailyUsageIfNeeded();
      if (walletReset || usageReset) await user.save();

      const { allowed, used, limit } = user.checkFeatureLimit(feature);

      if (!allowed) {
        const label = FEATURE_LABELS[feature] || feature;
        log.warn(`[FeatureGuard] limit reached feature=${feature} userId=${uid} used=${used}/${limit}`);
        return res.status(429).json({
          error:       "DAILY_LIMIT_REACHED",
          feature,
          featureLabel: label,
          used,
          limit,
          remaining:   0,
          message:     `You've used all ${limit} free ${label}${limit === 1 ? "" : "s"} for today.`,
          detail:      `Your free daily allowance resets at midnight. Buy credits to continue now.`,
          upgradeUrl:  "/wallet",
          resetAt:     user.wallet.freeResetAt,
          cta:         "Buy Credits",
        });
      }

      req.featureContext = {
        feature,
        used,
        limit,
        remaining: limit - used,
        userId: String(uid),
        commit: async () => {
          // FIXED: Single atomic write avoids double-increment race from two-query pattern.
          // Try matched-date $inc first; if stale/missing, reset then set feature=1.
          const today = getISTDateStr();
          const matched = await User.findOneAndUpdate(
            { _id: uid, "dailyUsage.date": today },
            { $inc: { [`dailyUsage.${feature}`]: 1 } },
            { new: false }
          );
          if (!matched) {
            await User.findOneAndUpdate(
              { _id: uid },
              {
                $set: {
                  "dailyUsage.date":        today,
                  "dailyUsage.imageGen":    0,
                  "dailyUsage.codeMode":    0,
                  "dailyUsage.webSearch":   0,
                  "dailyUsage.websiteGen":  0,
                  "dailyUsage.websiteEdit": 0,
                  [`dailyUsage.${feature}`]: 1,
                },
              }
            );
          }
          log.info(`[FeatureGuard] commit feature=${feature} userId=${uid} date=${today}`);
        },
      };

      next();
    } catch (err) {
      log.error("[featureGuard] unexpected error:", err.message, "\n", err.stack);
      return res.status(500).json({
        error:   "FEATURE_CHECK_FAILED",
        message: "We couldn't check your daily usage right now. Please try again in a moment.",
      });
    }
  };
}

module.exports = { featureGuard, FEATURE_LABELS };

"use strict";
/**
 * services/billing/razorpay.service.js
 * AQUIPLEX v2 — Razorpay Orders API + Standard Checkout integration.
 *
 * Uses ONLY:
 *   - Razorpay Orders API (POST /v1/orders)
 *   - Standard Checkout (frontend SDK)
 *   - Payment verification (HMAC-SHA256)
 *
 * Does NOT use: subscriptions, recurring, mandates, autopay, tokenization.
 *
 * RACE PROTECTION:
 *   verifyPayment uses findOneAndUpdate with status filter as atomic guard.
 *   Two concurrent calls for the same orderId: only one transitions from
 *   created/pending → success. The other gets null back and returns alreadyProcessed.
 */

const Razorpay = require("razorpay");
const crypto   = require("crypto");
const User     = require("../../models/User");
const Payment  = require("../../models/Payment");
const { getPackById } = require("../../utils/credits/packs");
const { createLogger } = require("../../utils/logger");

const log = createLogger("RAZORPAY");

// ── Razorpay client (lazy-init, singleton) ────────────────────────────────────

let _rzp = null;
function getRzp() {
  if (_rzp) return _rzp;
  const keyId     = process.env.RAZORPAY_KEY_ID;
  const keySecret = process.env.RAZORPAY_KEY_SECRET;
  if (!keyId || !keySecret) throw new Error("RAZORPAY credentials not configured in env");
  _rzp = new Razorpay({ key_id: keyId, key_secret: keySecret });
  return _rzp;
}

// ── Create Razorpay order ─────────────────────────────────────────────────────

/**
 * createOrder
 * Creates a Razorpay order and a local Payment document.
 *
 * Returns { orderId, amount, currency, packId, packName, credits, keyId }
 * for the frontend Razorpay Standard Checkout config.
 */
async function createOrder(userId, packId) {
  const user = await User.findById(userId);
  if (!user) throw new Error("USER_NOT_FOUND");

  const pack = getPackById(packId);
  if (!pack) throw new Error("INVALID_PACK");

  const amountPaise = pack.priceINR * 100;

  // Create Razorpay order
  const rzpOrder = await getRzp().orders.create({
    amount:   amountPaise,
    currency: "INR",
    receipt:  `aqx_${userId.toString().slice(-8)}_${Date.now()}`,
    notes: {
      userId:  userId.toString(),
      packId,
      credits: pack.credits.toString(),
      source:  "aquiplex_wallet",
    },
  });

  // Persist Payment record.
  // IMPORTANT: webhookId and razorpayPaymentId are intentionally omitted here.
  // Setting them to null/undefined would defeat the sparse unique index.
  const payment = await Payment.create({
    user:             userId,
    packId,
    amountPaise,
    creditsToAdd:     pack.credits,
    razorpayOrderId:  rzpOrder.id,
    status:           "created",
    metadata: {
      packName:  pack.name,
      priceINR:  pack.priceINR,
      rzpReceipt: rzpOrder.receipt,
    },
  });

  log.info(`Order created: rzpOrderId=${rzpOrder.id} user=${userId} pack=${packId} amount=₹${pack.priceINR}`);

  return {
    orderId:     rzpOrder.id,
    paymentDbId: payment._id.toString(),
    amount:      amountPaise,
    currency:    "INR",
    packId,
    packName:    pack.name,
    credits:     pack.credits,
    priceINR:    pack.priceINR,
    keyId:       process.env.RAZORPAY_KEY_ID,
    prefill: {
      email:   user.billingEmail || user.email,
      contact: user.phone || "",
    },
  };
}

// ── Verify payment signature (called from frontend after checkout) ─────────────

/**
 * verifyPayment
 * Verifies Razorpay signature, atomically marks payment success, credits wallet.
 *
 * Razorpay signs: HMAC-SHA256(orderId + "|" + paymentId, key_secret)
 *
 * ATOMIC RACE PROTECTION:
 *   Uses findOneAndUpdate with status: {$in: ["created","pending"]} as a guard.
 *   Only ONE concurrent call can transition the payment to "pending".
 *   If payment is already "success", returns alreadyProcessed without crediting.
 *
 * Returns { verified: true, credits, balanceAfter } or throws.
 */
async function verifyPayment(razorpayOrderId, razorpayPaymentId, razorpaySignature, userId) {
  // 1. Verify signature
  const expectedSig = crypto
    .createHmac("sha256", process.env.RAZORPAY_KEY_SECRET)
    .update(`${razorpayOrderId}|${razorpayPaymentId}`)
    .digest("hex");

  if (expectedSig !== razorpaySignature) {
    log.warn(`Signature mismatch: orderId=${razorpayOrderId} user=${userId}`);
    throw new Error("INVALID_SIGNATURE");
  }

  // 2. Check if already successfully processed (idempotent return)
  const alreadyDone = await Payment.findOne({
    razorpayOrderId,
    status: "success",
  });
  if (alreadyDone) {
    log.info(`verifyPayment: already processed orderId=${razorpayOrderId}`);
    return { verified: true, alreadyProcessed: true, credits: alreadyDone.creditsToAdd };
  }

  // 3. Atomically transition status to "pending" — only one call wins this race.
  //    If another concurrent verify call already claimed this, result is null.
  const claimed = await Payment.findOneAndUpdate(
    {
      razorpayOrderId,
      user:   userId,
      status: { $in: ["created", "pending"] },
    },
    {
      $set: {
        razorpayPaymentId,
        razorpaySignature,
        status: "pending",  // mark as in-progress
        paidAt: new Date(),
      },
    },
    { new: true }
  );

  if (!claimed) {
    // Could be: wrong userId, invalid orderId, or concurrent call already claimed it.
    const anyMatch = await Payment.findOne({ razorpayOrderId });
    if (!anyMatch) throw new Error("PAYMENT_NOT_FOUND");
    // It exists but we couldn't claim it — concurrent verify already handling it
    log.warn(`verifyPayment: could not claim payment orderId=${razorpayOrderId} — may be concurrent or wrong user`);
    throw new Error("PAYMENT_PROCESSING");
  }

  // 4. Mark status success
  await Payment.findByIdAndUpdate(claimed._id, { $set: { status: "success" } });

  // 5. Credit wallet (addPaidCredits is also idempotent via creditedAt atomic guard)
  const { addPaidCredits } = require("../credits/wallet.service");
  const result = await addPaidCredits(userId, claimed.creditsToAdd, claimed._id, claimed.packId);

  log.info(`Payment verified: orderId=${razorpayOrderId} user=${userId} credits=${claimed.creditsToAdd}`);

  return {
    verified:     true,
    credits:      claimed.creditsToAdd,
    packId:       claimed.packId,
    balanceAfter: result.balanceAfter || null,
  };
}

// ── Webhook signature verification ───────────────────────────────────────────

/**
 * verifyWebhookSignature
 * Razorpay signs webhook with HMAC-SHA256(rawBody, RAZORPAY_WEBHOOK_SECRET).
 * Digest is hex-encoded.
 */
function verifyWebhookSignature(rawBody, signature) {
  const secret = process.env.RAZORPAY_WEBHOOK_SECRET;
  if (!secret) throw new Error("RAZORPAY_WEBHOOK_SECRET not set");

  const digest = crypto
    .createHmac("sha256", secret)
    .update(rawBody)
    .digest("hex");

  return digest === signature;
}

// ── Get payment status from Razorpay (for reconciliation) ────────────────────

async function fetchRazorpayPayment(razorpayPaymentId) {
  return getRzp().payments.fetch(razorpayPaymentId);
}

async function fetchRazorpayOrder(razorpayOrderId) {
  return getRzp().orders.fetch(razorpayOrderId);
}

// ── Get user payment history ──────────────────────────────────────────────────

async function getUserPaymentHistory(userId, limit = 20) {
  return Payment.find({ user: userId })
    .sort({ createdAt: -1 })
    .limit(limit)
    .lean();
}

module.exports = {
  createOrder,
  verifyPayment,
  verifyWebhookSignature,
  fetchRazorpayPayment,
  fetchRazorpayOrder,
  getUserPaymentHistory,
};

"use strict";
/**
 * services/billing/webhook.handler.js
 * AQUIPLEX v2 — Razorpay webhook processor.
 *
 * Razorpay fires these events for one-time payments:
 *   payment.captured  → credit wallet (primary flow)
 *   payment.failed    → mark payment failed, notify
 *   order.paid        → backup confirmation (use if payment.captured missed)
 *   refund.processed  → deduct refunded credits
 *
 * Idempotency:
 *   Every processed webhook is recorded in WebhookLog with unique idempotencyKey.
 *   Duplicate deliveries are silently skipped.
 *
 * Note: Frontend verifyPayment is the PRIMARY credit path.
 * Webhook is the BACKUP/audit path for payments that complete but frontend fails.
 */

const Payment    = require("../../models/Payment");
const WebhookLog = require("../../models/WebhookLog");
const { addPaidCredits } = require("../credits/wallet.service");
const { createLogger }   = require("../../utils/logger");

const log = createLogger("WEBHOOK");

// ── Main dispatcher ───────────────────────────────────────────────────────────

async function handleWebhookEvent(event, payload) {
  // Build idempotency key from event + payment ID
  const paymentEntity = payload?.payload?.payment?.entity;
  const orderEntity   = payload?.payload?.order?.entity;
  const refundEntity  = payload?.payload?.refund?.entity;

  const uniqueId =
    paymentEntity?.id ||
    orderEntity?.id   ||
    refundEntity?.id  ||
    JSON.stringify(payload).slice(0, 64);

  const idempotencyKey = `${event}:${uniqueId}`;

  // Idempotency check
  try {
    await WebhookLog.create({ idempotencyKey, event, payload });
  } catch (e) {
    if (e.code === 11000) {
      log.info(`Duplicate webhook skipped: ${idempotencyKey}`);
      return { skipped: true };
    }
    throw e;
  }

  log.info(`Webhook: ${event} key=${idempotencyKey}`);

  try {
    let result;
    switch (event) {
      case "payment.captured":
        result = await onPaymentCaptured(paymentEntity);
        break;

      case "order.paid":
        result = await onOrderPaid(orderEntity, paymentEntity);
        break;

      case "payment.failed":
        result = await onPaymentFailed(paymentEntity);
        break;

      case "refund.processed":
        result = await onRefundProcessed(refundEntity);
        break;

      default:
        log.info(`Unhandled webhook event: ${event}`);
        result = { handled: false };
    }

    await WebhookLog.updateOne({ idempotencyKey }, { handled: true });
    return result;

  } catch (err) {
    await WebhookLog.updateOne({ idempotencyKey }, { error: err.message });
    throw err;
  }
}

// ── payment.captured ──────────────────────────────────────────────────────────

async function onPaymentCaptured(entity) {
  if (!entity) return { handled: false, reason: "NO_ENTITY" };

  const { id: rzpPaymentId, order_id: rzpOrderId } = entity;

  const payment = await Payment.findOne({ razorpayOrderId: rzpOrderId });
  if (!payment) {
    log.warn(`Webhook payment.captured: no Payment found for orderId=${rzpOrderId}`);
    return { handled: false, reason: "PAYMENT_NOT_FOUND" };
  }

  // Already credited (frontend verify already ran)
  if (payment.creditedAt || payment.status === "success") {
    log.info(`payment.captured: already processed orderId=${rzpOrderId}`);
    return { handled: true, alreadyProcessed: true };
  }

  // Mark payment success
  await Payment.findByIdAndUpdate(payment._id, {
    razorpayPaymentId: rzpPaymentId,
    status:            "success",
    paidAt:            new Date(),
  });

  // Credit wallet
  const result = await addPaidCredits(
    payment.user,
    payment.creditsToAdd,
    payment._id,
    payment.packId
  );

  log.info(`payment.captured: credited user=${payment.user} credits=${payment.creditsToAdd}`);
  return { handled: true, credited: payment.creditsToAdd, ...result };
}

// ── order.paid (backup path) ──────────────────────────────────────────────────

async function onOrderPaid(orderEntity, paymentEntity) {
  // Delegate to payment.captured logic
  return onPaymentCaptured(paymentEntity || { id: null, order_id: orderEntity?.id });
}

// ── payment.failed ────────────────────────────────────────────────────────────

async function onPaymentFailed(entity) {
  if (!entity) return { handled: false };

  const { order_id: rzpOrderId, error_description } = entity;

  await Payment.findOneAndUpdate(
    { razorpayOrderId: rzpOrderId, status: { $in: ["created", "pending"] } },
    { status: "failed", failureReason: error_description || "Payment failed" }
  );

  log.info(`payment.failed: orderId=${rzpOrderId} reason=${error_description}`);
  return { handled: true };
}

// ── refund.processed ──────────────────────────────────────────────────────────

async function onRefundProcessed(entity) {
  if (!entity) return { handled: false };

  // Note: We DO NOT deduct credits on refund in v2.
  // Refund is a financial event — credits already consumed cannot be taken back
  // (user may have used them). Admin can manually adjust via admin panel.
  // Just log the event.
  log.info(`refund.processed: refundId=${entity.id} amount=${entity.amount}`);
  return { handled: true, note: "Credits not deducted on refund by policy" };
}

module.exports = { handleWebhookEvent };

