const Bundle = require("../models/Bundle");

async function runBundle(bundleId, generateAI) {
  const bundle = await Bundle.findById(bundleId);
  if (!bundle) throw new Error("Bundle not found");

  bundle.status = "running";
  await bundle.save();

  const results = [];
  for (let i = 0; i < bundle.steps.length; i++) {
    const step = bundle.steps[i];
    try {
      const raw = await generateAI([
        { role: "system", content: `You are an expert project executor. Execute this step and produce a detailed deliverable.` },
        { role: "user",   content: `Project: ${bundle.title}\nGoal: ${bundle.goal}\n\nStep ${i + 1}: ${step.title}\n${step.description}` },
      ], { temperature: 0.6, maxTokens: 1200 });

      results.push({ stepIndex: i, title: step.title, content: raw, status: "completed" });

      // Update progress
      if (bundle.progress && bundle.progress[i]) {
        bundle.progress[i].status      = "completed";
        bundle.progress[i].completedAt = new Date();
      }
    } catch (err) {
      results.push({ stepIndex: i, title: step.title, content: "", status: "failed", error: err.message });
      if (bundle.progress && bundle.progress[i]) {
        bundle.progress[i].status = "failed";
      }
    }
  }

  bundle.status = "completed";
  bundle.outputs = results.map((r, i) => ({
    stepIndex:  r.stepIndex,
    title:      r.title,
    content:    r.content,
    executedAt: new Date(),
  }));
  await bundle.save();

  return bundle;
}

module.exports = { runBundle };

/**
 * AQUA Identity Smart Router
 * ─────────────────────────────────────────────────────────────────────────────
 * Three jobs:
 *
 *   1. detectIdentityIntent(query) — is this question about Aquiplex/AQUA
 *      itself, and if so, which topic(s)? Runs BEFORE heavy retrieval so the
 *      chat pipeline can skip project/vector retrieval and inject the expanded
 *      identity context instead.
 *
 *   2. answerFromIdentity(query) — a deterministic, well-composed answer built
 *      straight from the structured profile (no LLM). This is:
 *        • the guaranteed grounded answer the refusal-guard substitutes if the
 *          model ever hedges on an identity question, and
 *        • what the automated tests assert against (no network needed in CI).
 *
 *   3. isRefusal(text) — does an answer contain a "I don't know / not familiar
 *      / no source" style refusal? Used by the guard and by the tests that
 *      enforce the spec's FAILURE CONDITIONS.
 *
 * Detection rule (kept simple + robust):
 *   isSelf = mentions "aqua"/"aquiplex"  OR  (addresses the assistant with
 *            "you"/"your"/"yourself"  AND  matches ≥1 identity topic).
 *   The second-person requirement is what keeps user-memory questions out:
 *   "what is MY favorite language" has no self-noun and no "you/your", so it
 *   is never mistaken for an identity question.
 */
import { getIdentityProfile } from './identityLoader.js';

// ── self-reference signals ────────────────────────────────────────────────────
const SELF_NOUN     = /\b(aqua|aquiplex)\b/i;
const SECOND_PERSON = /\b(you|your|yours|yourself)\b/i;
// First-person redirect ("my", "I") — when present WITHOUT a self-noun and
// WITHOUT second-person, the question is about the user, not AQUA.
const FIRST_PERSON  = /\b(my|mine|myself|i['’]?m|i\s+(am|have|want|need))\b/i;

// ── topic patterns ────────────────────────────────────────────────────────────
// Each topic name matches a renderer in identityContext.R.
const TOPIC_PATTERNS = {
  vision:          [/\bvision\b/i],
  mission:         [/\bmission\b/i, /\bpurpose\b/i],
  values:          [/\b(core\s+)?values?\b/i, /\bprinciples?\b/i],
  capabilities:    [/\bcapabilit/i, /\bwhat\s+can\s+you\s+do\b/i, /\bwhat\s+do\s+you\s+do\b/i, /\b(able|ability)\s+to\s+do\b/i, /\byour\s+features?\b/i, /\bwhat\s+are\s+you\s+capable\b/i],
  files:           [/\b(files?|file\s*types?|formats?|documents?)\b[\s\S]{0,30}\b(process|handle|read|support|upload|accept|ingest|parse)\b/i,
                    /\b(process|handle|read|support|upload|accept|ingest|parse)\b[\s\S]{0,30}\b(files?|documents?|formats?)\b/i],
  differentiators: [/\bdifferent(iat)?/i, /\bunique\b/i, /\bstand\s?out\b/i, /\bwhat\s+makes\s+(you|aqua)\b/i, /\bwhy\s+(use|choose|pick)\b/i, /\bbetter\s+than\b/i, /\byour\s+edge\b/i],
  founders:        [/\bfound(er|ers|ed)\b/i, /\bwho\s+(made|created|started|owns)\s+aquiplex\b/i, /\bwho['’]?s?\s+behind\b/i],
  creator:         [/\bwho\s+(built|made|created|developed|designed)\s+(you|aqua)\b/i, /\bbuilt\s+by\b/i, /\byour\s+(creator|maker|developer|builder)\b/i, /\bwho\s+are\s+you\s+(built|made|created)\s+by\b/i],
  roadmap:         [/\broad\s?map\b/i, /\bwhat['’]?s\s+next\b/i, /\bfuture\s+plans?\b/i, /\bupcoming\b/i, /\bwhat\s+are\s+you\s+(building|planning)\b/i],
  models:          [/\bmodels?\b/i, /\bllms?\b/i, /\bwhich\s+ai\b/i, /\bwhat\s+ai\b/i, /\bproviders?\b/i, /\bpowered\s+by\b/i, /\bunder\s+the\s+hood\b/i],
  products:        [/\bproducts?\b/i, /\bofferings?\b/i, /\bwhat\s+do\s+you\s+(offer|sell)\b/i],
  pricing:         [/\bpric(e|es|ing)\b/i, /\bcost\b/i, /\bhow\s+much\b/i, /\bplans?\b/i, /\bsubscription\b/i, /\bfree\s+tier\b/i],
  limitations:     [/\blimitations?\b/i, /\bwhat\s+can['’]?t\s+you\b/i, /\bcannot\s+you\b/i, /\bweakness(es)?\b/i, /\bdrawbacks?\b/i, /\bconstraints?\b/i],
  company:         [/\baquiplex\b/i],
  overview:        [/\b(what|who)\s+is\s+(aqua|aquiplex)\b/i, /\b(who|what)\s+are\s+you\b/i, /\btell\s+me\s+about\s+(yourself|aqua|aquiplex)\b/i, /\bwhat['’]?s\s+aqua\b/i, /\bintroduce\s+yourself\b/i],
};

// Topics that are only meaningful as questions ABOUT the assistant, so a bare
// self-noun isn't required if the user is clearly addressing "you".
const SELF_OWNED_TOPICS = new Set([
  'vision', 'mission', 'values', 'capabilities', 'files', 'differentiators',
  'creator', 'roadmap', 'models', 'products', 'pricing', 'limitations',
]);

/**
 * @param {string} query
 * @returns {{ isSelf: boolean, topics: string[], score: number }}
 */
export function detectIdentityIntent(query) {
  const q = (query ?? '').trim();
  if (!q) return { isSelf: false, topics: [], score: 0 };

  const matched = [];
  for (const [topic, patterns] of Object.entries(TOPIC_PATTERNS)) {
    if (patterns.some(re => re.test(q))) matched.push(topic);
  }

  const hasSelfNoun = SELF_NOUN.test(q);
  const hasSecond   = SECOND_PERSON.test(q);
  const hasFirst    = FIRST_PERSON.test(q);

  // 'creator'/'company'/'overview' already require self-context in their
  // patterns; the self-owned topics can rely on second-person addressing.
  const selfOwnedHit = matched.some(t => SELF_OWNED_TOPICS.has(t));
  const contextHit   = matched.includes('creator') || matched.includes('company') || matched.includes('overview');

  let isSelf = false;
  if (hasSelfNoun) {
    isSelf = matched.length > 0;                       // e.g. "What is Aquiplex?", "What makes AQUA different?"
  } else if (contextHit) {
    isSelf = true;                                     // e.g. "Who built you?", "Who founded Aquiplex?"
  } else if (selfOwnedHit && hasSecond && !hasFirst) {
    isSelf = true;                                     // e.g. "What is your vision?", "What can you do?"
  }

  if (!isSelf) return { isSelf: false, topics: [], score: 0 };

  // Order topics deterministically and drop 'company' when a more specific
  // topic exists (company == bare aquiplex mention, low signal).
  let topics = matched;
  if (topics.length > 1) topics = topics.filter(t => t !== 'company');
  if (topics.length === 0) topics = ['overview'];

  const score = Math.min(1, 0.5 + 0.15 * topics.length + (hasSelfNoun ? 0.2 : 0));
  return { isSelf: true, topics: dedupe(topics), score: +score.toFixed(2) };
}

// ── deterministic grounded answer ─────────────────────────────────────────────

/**
 * Compose a natural-language answer for an identity question, straight from the
 * structured profile. Returns null if the query isn't an identity question.
 *
 * This never contains a refusal phrase for information present in the profile —
 * that's the whole point, and the tests assert it.
 *
 * @param {string} query
 * @param {object} [profile]
 * @returns {string|null}
 */
export function answerFromIdentity(query, profile = getIdentityProfile()) {
  const intent = detectIdentityIntent(query);
  if (!intent.isSelf) return null;
  return composeAnswer(intent.topics, profile);
}

/** Compose from an explicit topic list (used by answerFromIdentity + guard). */
export function composeAnswer(topics, profile = getIdentityProfile()) {
  const c = profile.company, a = profile.assistant;
  const t = new Set(topics && topics.length ? topics : ['overview']);
  const blocks = [];

  const one = (topic) => t.has(topic);

  if (one('overview') || one('company')) {
    blocks.push(`I'm ${a.fullName ?? a.name}, the first-party AI built by ${c.name}. ${c.description}`);
  }
  if (one('vision'))  blocks.push(`Our vision: ${c.vision}`);
  if (one('mission')) blocks.push(`Our mission: ${c.mission}`);
  if (one('values')) {
    const vals = c.coreValues ?? [];
    if (vals.length) blocks.push(`Our core values are:\n${vals.map(v => `• ${v.name}${v.detail ? ` — ${v.detail}` : ''}`).join('\n')}`);
  }
  if (one('capabilities')) {
    const caps = a.capabilities ?? [];
    if (caps.length) blocks.push(`Here's what I can do:\n${caps.map(x => `• ${x}`).join('\n')}`);
  }
  if (one('files')) {
    const f = a.processableFiles;
    if (f) {
      const parts = [];
      if (f.code?.length)      parts.push(`code repositories (${f.code.join(', ')})`);
      if (f.documents?.length) parts.push(`documents (${f.documents.join(', ')})`);
      if (f.media?.length)     parts.push(`media (${f.media.join(', ')})`);
      blocks.push(`I can process ${parts.join(', ')}.${f.note ? ` ${f.note}` : ''}`);
    }
  }
  if (one('differentiators')) {
    const d = a.differentiators ?? [];
    if (d.length) blocks.push(`What makes ${a.name} different:\n${d.map(x => `• ${x}`).join('\n')}`);
  }
  if (one('creator')) {
    blocks.push(`I was built by ${a.builtBy ?? c.name} as its first-party AI.`);
  }
  if (one('founders')) {
    const f = profile.founders ?? [];
    if (f.length) blocks.push(`${c.name} was founded by ${f.map(x => x.name).join(' and ')}.`);
  }
  if (one('products')) {
    const pr = profile.products ?? [];
    if (pr.length) blocks.push(`${c.name} products:\n${pr.map(x => `• ${x.name}${x.description ? ` — ${x.description}` : ''}`).join('\n')}`);
  }
  if (one('models')) {
    const m = profile.models;
    if (m) {
      const provs = (m.providers ?? []).map(p => `${p.name} (${(p.models ?? []).join(', ')})`).join('; ');
      blocks.push(`${m.summary}${provs ? ` I route across: ${provs}.` : ''}${m.routing ? ` ${m.routing}` : ''}`);
    }
  }
  if (one('roadmap')) {
    const r = (profile.roadmap ?? []).filter(ph => (ph.items ?? []).length);
    if (r.length) blocks.push(`Roadmap:\n${r.map(ph => `${ph.phase}:\n${ph.items.map(i => `  • ${i}`).join('\n')}`).join('\n')}`);
  }
  if (one('limitations')) {
    const l = a.limitations ?? [];
    if (l.length) blocks.push(`My limitations:\n${l.map(x => `• ${x}`).join('\n')}`);
  }
  if (one('pricing')) {
    blocks.push(`Pricing isn't part of my current profile — please check with the ${c.name} team or the website for current plans.`);
  }

  // Fallback: if somehow nothing composed, give the elevator overview so we
  // never return an empty string for a detected identity question.
  if (!blocks.length) {
    blocks.push(`I'm ${a.fullName ?? a.name}, the first-party AI built by ${c.name}. ${c.description} Our vision: ${c.vision}`);
  }
  return blocks.join('\n\n');
}

// ── refusal detection (enforces spec FAILURE CONDITIONS) ──────────────────────

const REFUSAL_PATTERNS = [
  /\bi\s+don['’]?t\s+know\b/i,
  /\bi\s+do\s+not\s+know\b/i,
  /\bi['’]?m\s+not\s+(sure|familiar)\b/i,
  /\bi\s+am\s+not\s+(sure|familiar)\b/i,
  /\bi\s+don['’]?t\s+have\s+(any\s+)?(information|info|details?|knowledge|data)\b/i,
  /\bi\s+don['’]?t\s+have\s+(a\s+)?(verifiable\s+)?source\b/i,
  /\bno\s+(verifiable\s+)?source\b/i,
  /\bi\s+(can['’]?t|cannot)\s+(find|verify|confirm)\b/i,
  /\bnot\s+familiar\s+with\b/i,
  /\bi\s+have\s+no\s+(information|knowledge|record)\b/i,
  /\bi\s+don['’]?t\s+have\s+access\s+to\b/i,
  /\bunable\s+to\s+find\b/i,
];

/**
 * True if `text` contains a refusal / "I don't know" style phrase. Used by the
 * refusal-guard (chat.js) and by the tests enforcing the FAILURE CONDITIONS.
 * @param {string} text
 * @returns {boolean}
 */
export function isRefusal(text) {
  if (!text) return false;
  return REFUSAL_PATTERNS.some(re => re.test(text));
}

function dedupe(arr) { return [...new Set(arr)]; }

export { TOPIC_PATTERNS as _topicPatterns, REFUSAL_PATTERNS as _refusalPatterns };

/**
 * AQUA Identity Loader
 * ─────────────────────────────────────────────────────────────────────────────
 * Loads the structured brand/self-knowledge profile ONCE, validates it, and
 * caches it in memory. There is exactly one source of truth for everything
 * AQUA knows about Aquiplex and AQUA, and it lives in ./data/*.json — never
 * hardcoded inside a prompt string.
 *
 * Performance (per spec):
 *   • Load once, cache in memory. No disk read on the hot path.
 *   • getIdentityProfile() is O(1) after first call.
 *
 * Editability (per spec):
 *   • Edit ./data/company.json (vision, mission, values…) → the change
 *     propagates everywhere: every injected prompt and every direct answer.
 *   • updateIdentityProfile(patch) applies a runtime override (in-memory by
 *     default; optionally persisted to ./data/overrides.json) WITHOUT editing
 *     or clobbering the base files. Overrides are deep-merged last.
 *
 * Versioning (per spec):
 *   • Every profile carries _identity = { version, revision, contentHash, loadedAt }.
 *   • revision bumps on each successful updateIdentityProfile().
 *
 * Resilience:
 *   • A missing/corrupt data file is logged and skipped — never throws on boot.
 *     AQUA must never fail to know itself because one JSON file was malformed.
 */
import fs   from 'fs';
import path from 'path';
import crypto from 'crypto';
import { fileURLToPath } from 'url';

const __dir        = path.dirname(fileURLToPath(import.meta.url));
const dataDir      = path.join(__dir, 'data');
const overridePath = path.join(dataDir, 'overrides.json');

export const IDENTITY_VERSION = '1.0.0';

// Base data files → the key they populate on the merged profile.
const FILES = {
  company:   'company.json',
  assistant: 'assistant.json',
  founders:  'founders.json',
  products:  'products.json',
  roadmap:   'roadmap.json',
  models:    'models.json',
  faq:       'faq.json',
};

let _cache          = null;   // merged, frozen profile
let _revision       = 0;      // bumps on updateIdentityProfile()
let _memoryOverride = null;   // non-persisted runtime override

// ── low-level IO ──────────────────────────────────────────────────────────────

function readJson(file, { required = false, silent = false } = {}) {
  try {
    return JSON.parse(fs.readFileSync(path.join(dataDir, file), 'utf8'));
  } catch (err) {
    // ENOENT on an optional file we expect to usually be absent (overrides) is
    // not worth a line on every boot; a PARSE error always is.
    const isMissing = err.code === 'ENOENT';
    if (required)            console.error(`[IDENTITY] Failed to read required data file ${file}: ${err.message}`);
    else if (!(silent && isMissing)) console.warn(`[IDENTITY] Optional data file ${file} ${isMissing ? 'missing' : 'invalid'} — skipping${isMissing ? '' : ` (${err.message})`}`);
    return null;
  }
}

// Deep-merge b into a (arrays/scalars from b win; objects merge). Pure.
function deepMerge(a, b) {
  if (Array.isArray(b) || b === null || typeof b !== 'object') return b;
  const out = (a && typeof a === 'object' && !Array.isArray(a)) ? { ...a } : {};
  for (const [k, v] of Object.entries(b)) out[k] = deepMerge(out[k], v);
  return out;
}

function deepFreeze(obj) {
  if (obj && typeof obj === 'object' && !Object.isFrozen(obj)) {
    Object.values(obj).forEach(deepFreeze);
    Object.freeze(obj);
  }
  return obj;
}

// ── validation (minimal, non-throwing) ────────────────────────────────────────
// Guarantees the fields the context builder + router depend on exist (with
// safe fallbacks) so downstream code never has to null-check its own brand.
function validate(profile) {
  const problems = [];
  const c = profile.company   ?? {};
  const a = profile.assistant ?? {};
  if (!c.name)    { problems.push('company.name missing');   c.name = 'Aquiplex'; }
  if (!c.vision)    problems.push('company.vision missing');
  if (!c.mission)   problems.push('company.mission missing');
  if (!a.name)    { problems.push('assistant.name missing'); a.name = 'AQUA'; }
  if (!a.builtBy)   a.builtBy = c.name;
  if (!Array.isArray(a.capabilities) || a.capabilities.length === 0) problems.push('assistant.capabilities empty');
  profile.company = c;
  profile.assistant = a;
  if (problems.length) console.warn(`[IDENTITY] Profile validation notes: ${problems.join('; ')}`);
  return profile;
}

// ── build (single path; applies disk override then in-memory override) ────────

function build() {
  const merged = {};
  for (const [key, file] of Object.entries(FILES)) {
    const required = key === 'company' || key === 'assistant';
    const data = readJson(file, { required });
    if (data == null) continue;
    if      (key === 'founders') merged.founders = data.founders ?? [];
    else if (key === 'products') merged.products = data.products ?? [];
    else if (key === 'roadmap')  merged.roadmap  = data.roadmap  ?? [];
    else                         merged[key]     = data;
  }

  // Overrides deep-merged last so they win: disk override, then in-memory.
  const diskOverride = readJson('overrides.json', { silent: true });
  let withOverride = diskOverride ? deepMerge(merged, diskOverride) : merged;
  if (_memoryOverride) withOverride = deepMerge(withOverride, _memoryOverride);

  const validated = validate(withOverride);

  const contentHash = crypto.createHash('sha1')
    .update(JSON.stringify(validated)).digest('hex').slice(0, 12);

  validated._identity = {
    version:  IDENTITY_VERSION,
    revision: _revision,
    contentHash,
    loadedAt: new Date().toISOString(),
  };

  return deepFreeze(validated);
}

// ── public API ────────────────────────────────────────────────────────────────

/**
 * The cached, frozen, merged identity profile. Loads on first call, then
 * serves from memory. Safe to call on every request.
 * @returns {Readonly<object>}
 */
export function getIdentityProfile() {
  if (!_cache) {
    _cache = build();
    console.log(`[IDENTITY] Loaded profile v${_cache._identity.version} (${_cache._identity.contentHash}) — ${_cache.assistant.name} by ${_cache.company.name}`);
  }
  return _cache;
}

/**
 * Force a re-read of all data files (hot reload in dev, or after editing
 * ./data/*.json). Same revision, fresh content.
 * @returns {Readonly<object>}
 */
export function reloadIdentity() {
  _cache = null;
  const p = getIdentityProfile();
  console.log('[IDENTITY] Reloaded profile from disk');
  return p;
}

/**
 * Admin update. Deep-merges `patch` as a runtime override WITHOUT editing the
 * base data files. Bumps the revision. This is the single helper the spec asks
 * for — changing the vision/roadmap never means touching a prompt.
 *
 * @param {object}  patch                - partial profile, e.g. { company: { vision: '…' } }
 * @param {object}  [opts]
 * @param {boolean} [opts.persist=false] - also write the accumulated override to ./data/overrides.json
 * @returns {Readonly<object>} the new cached profile
 */
export function updateIdentityProfile(patch, { persist = false } = {}) {
  if (!patch || typeof patch !== 'object' || Array.isArray(patch)) {
    throw new Error('updateIdentityProfile(patch): patch must be a plain object');
  }

  if (persist) {
    // Accumulate against any existing override file so successive updates stack.
    const nextOverride = deepMerge(readJson('overrides.json') ?? {}, patch);
    try {
      fs.writeFileSync(overridePath, JSON.stringify(nextOverride, null, 2));
      console.log('[IDENTITY] Persisted override → data/overrides.json');
    } catch (err) {
      console.error(`[IDENTITY] Failed to persist override: ${err.message}`);
    }
  } else {
    _memoryOverride = deepMerge(_memoryOverride ?? {}, patch);
  }

  _revision += 1;
  _cache = null;
  return getIdentityProfile();
}

/** Test/diagnostic helper — clears cache + in-memory override + revision. */
export function _resetForTests() {
  _cache = null;
  _revision = 0;
  _memoryOverride = null;
}

/**
 * AQUA Identity & Self-Knowledge Layer — automated tests (node:test).
 * Run: node --test src/identity/tests/identityLayer.test.js
 *
 * Enforces the spec directly:
 *   • Every required identity prompt is DETECTED and produces a grounded answer.
 *   • FAILURE CONDITIONS: no answer to a self-question may contain "I don't
 *     know" / "I'm not familiar" / "I don't have information" / "I don't have a
 *     source" (or siblings). Asserted for every required prompt.
 *   • No false positives: user-memory / coding / opinion / general questions do
 *     NOT trigger the identity path.
 *   • The compact identity block is injected on EVERY request (always-on).
 *   • updateIdentityProfile() propagates without touching prompts.
 *   • promptBuilder injects identity on every prompt, expanded + directive on
 *     a self-question.
 *
 * Tests are profile-driven: expected facts are read FROM the loaded profile, so
 * editing ./data/*.json can't silently break the mechanism these tests cover.
 */
import { test } from 'node:test';
import assert   from 'node:assert/strict';

import {
  getIdentityProfile, updateIdentityProfile, reloadIdentity, _resetForTests,
  detectIdentityIntent, answerFromIdentity, composeAnswer, isRefusal,
  buildIdentityInjection, compactBlock, IDENTITY_VERSION,
} from '../index.js';
import { buildSystemPrompt } from '../../core/promptBuilder.js';

// The 12 prompts the spec requires to ALL pass.
const REQUIRED_PROMPTS = [
  'What is Aquiplex?',
  'What is your vision?',
  'What is your mission?',
  'What are your capabilities?',
  'Who built you?',
  'What makes AQUA different?',
  'What can you do?',
  'What files can you process?',
  'What is your roadmap?',
  'What are your core values?',
  'Who founded Aquiplex?',
  'What AI models do you use?',
];

// The exact phrases the spec says must FAIL the build if present in a
// self-answer, plus the router's broader refusal set.
const BANNED_PHRASES = [
  "i don't know",
  "i'm not familiar",
  "i don't have information",
  "i don't have a source",
];

// ── profile loads + shape ─────────────────────────────────────────────────────

test('profile loads, is cached, and is versioned', () => {
  _resetForTests();
  const p = getIdentityProfile();
  assert.equal(p._identity.version, IDENTITY_VERSION);
  assert.ok(p._identity.contentHash, 'contentHash present');
  assert.equal(p.company.name, 'Aquiplex');
  assert.equal(p.assistant.name, 'AQUA');
  assert.ok(p.company.vision && p.company.mission, 'vision + mission present');
  assert.ok(Array.isArray(p.assistant.capabilities) && p.assistant.capabilities.length > 0);
  // Same frozen object on second call (cached).
  assert.equal(getIdentityProfile(), p);
  assert.ok(Object.isFrozen(p), 'profile is frozen');
});

// ── every required prompt is detected + answered + refusal-free ───────────────

for (const q of REQUIRED_PROMPTS) {
  test(`required prompt is detected + grounded: "${q}"`, () => {
    const intent = detectIdentityIntent(q);
    assert.equal(intent.isSelf, true, `"${q}" must be detected as a self-question`);
    assert.ok(intent.topics.length > 0, 'at least one topic');

    const ans = answerFromIdentity(q);
    assert.ok(ans && ans.trim().length > 0, 'non-empty grounded answer');

    // FAILURE CONDITIONS — no refusal phrasing in a self-answer.
    assert.equal(isRefusal(ans), false, `answer must not be a refusal: "${ans}"`);
    const lower = ans.toLowerCase();
    for (const banned of BANNED_PHRASES) {
      assert.ok(!lower.includes(banned), `answer must not contain "${banned}"`);
    }
  });
}

// ── the answers actually contain the right facts (profile-driven) ─────────────

test('answers carry the expected facts from the profile', () => {
  const p = getIdentityProfile();
  const has = (q, needle) =>
    assert.ok(answerFromIdentity(q).toLowerCase().includes(String(needle).toLowerCase()),
      `answer to "${q}" should mention "${needle}"`);

  has('What is Aquiplex?', 'aquiplex');
  has('What is your vision?', p.company.vision.slice(0, 24));
  has('What is your mission?', p.company.mission.slice(0, 24));
  has('What are your capabilities?', p.assistant.capabilities[0].slice(0, 16));
  has('Who built you?', p.company.name);
  has('What makes AQUA different?', p.assistant.differentiators[0].slice(0, 16));
  has('What files can you process?', p.assistant.processableFiles.documents[0]); // e.g. PDF
  has('What are your core values?', p.company.coreValues[0].name.slice(0, 10));
  has('Who founded Aquiplex?', p.founders[0].name);
  has('What AI models do you use?', p.models.providers[0].name);   // Groq
  has('What AI models do you use?', p.models.providers[1].name);   // Gemini

  // roadmap: first non-empty phase's first item
  const phase = (p.roadmap ?? []).find(ph => (ph.items ?? []).length);
  has('What is your roadmap?', phase.items[0].slice(0, 16));
});

// ── no false positives ────────────────────────────────────────────────────────

const NON_IDENTITY = [
  'what is my favorite language?',       // user-memory recall (has "my")
  'what are my core values?',            // user, not AQUA
  'write a function to sort an array',   // coding
  'how do I add rate limiting?',         // coding/how-to
  'what do you think about React?',      // opinion (has "you" but no identity topic)
  'What is the capital of France?',      // general QA
  'summarize this document',             // task
  'explain how promises work',           // research
];

for (const q of NON_IDENTITY) {
  test(`non-identity query does NOT trigger: "${q}"`, () => {
    const intent = detectIdentityIntent(q);
    assert.equal(intent.isSelf, false, `"${q}" must NOT be a self-question`);
    assert.equal(answerFromIdentity(q), null, 'no grounded answer for non-identity query');
  });
}

// ── always-on compact injection ───────────────────────────────────────────────

test('compact identity block is injected on EVERY request (intent = null)', () => {
  const p = getIdentityProfile();
  const block = buildIdentityInjection(null);
  assert.ok(block.includes('SELF-KNOWLEDGE'), 'has the self-knowledge header');
  assert.ok(block.includes(p.assistant.name), 'names AQUA');
  assert.ok(block.includes(p.company.name), 'names Aquiplex');
  assert.ok(block.toLowerCase().includes('vision'), 'includes vision line');
  assert.ok(block.toLowerCase().includes('mission'), 'includes mission line');
  // Compact-only: no confidence directive when there is no self-intent.
  assert.ok(!block.includes('IDENTITY DIRECTIVE'), 'no directive without intent');
});

test('expanded injection adds the topic section + confidence directive', () => {
  const intent = detectIdentityIntent('What is your roadmap?');
  const block = buildIdentityInjection(intent);
  assert.ok(block.includes('IDENTITY DIRECTIVE'), 'directive present on self-question');
  assert.ok(/roadmap/i.test(block), 'roadmap section present');
});

// ── refusal detector ──────────────────────────────────────────────────────────

test('isRefusal flags hedges and passes real answers', () => {
  assert.equal(isRefusal("I don't know what Aquiplex is."), true);
  assert.equal(isRefusal("I'm not familiar with that product."), true);
  assert.equal(isRefusal("I don't have information about that."), true);
  assert.equal(isRefusal("I don't have a verifiable source for this."), true);
  assert.equal(isRefusal('Aquiplex is an AI Operating System.'), false);
  assert.equal(isRefusal(''), false);
});

// ── admin update propagates without touching prompts ──────────────────────────

test('updateIdentityProfile propagates to answers + bumps revision, then resets', () => {
  const before = getIdentityProfile();
  const beforeRev = before._identity.revision;

  const NEW_VISION = 'A test vision string unique-token-42.';
  updateIdentityProfile({ company: { vision: NEW_VISION } });

  const after = getIdentityProfile();
  assert.equal(after.company.vision, NEW_VISION, 'in-memory override applied');
  assert.equal(after._identity.revision, beforeRev + 1, 'revision bumped');
  assert.ok(answerFromIdentity('What is your vision?').includes('unique-token-42'),
    'the new vision flows into the direct answer');
  assert.ok(buildIdentityInjection(null).includes('unique-token-42'),
    'the new vision flows into the injected compact block');

  // Reset back to disk truth for any later tests / suites.
  _resetForTests();
  assert.notEqual(getIdentityProfile().company.vision, NEW_VISION, 'reset restores disk profile');
});

// ── promptBuilder integration ─────────────────────────────────────────────────

test('buildSystemPrompt injects identity on every prompt (non-self turn)', () => {
  _resetForTests();
  const { prompt, modules } = buildSystemPrompt('coding', '', '', '', '', null);
  assert.ok(modules.includes('identity'), 'identity module listed');
  assert.ok(prompt.includes('SELF-KNOWLEDGE'), 'identity text present in a coding prompt');
  assert.ok(!prompt.includes('IDENTITY DIRECTIVE'), 'no directive on a non-self turn');
});

test('buildSystemPrompt expands identity + directive on a self-question', () => {
  const intent = detectIdentityIntent('What is your mission?');
  const { prompt, modules } = buildSystemPrompt('conversation', '', '', '', '', intent);
  assert.ok(modules.includes('identity+'), 'expanded identity module listed');
  assert.ok(prompt.includes('IDENTITY DIRECTIVE'), 'directive injected on self-question');
  assert.ok(/mission/i.test(prompt), 'mission section present');
});

test('composeAnswer handles multi-topic questions', () => {
  const ans = composeAnswer(['vision', 'mission']);
  assert.ok(/vision/i.test(ans) && /mission/i.test(ans), 'both sections present');
});

// Mirrors the exact guard in chat.js — proves the end-to-end guarantee: if the
// model EVER hedges on a self-question, the grounded profile answer replaces it,
// so a response containing a banned phrase can never reach the user.
test('refusal guard replaces a hedged self-answer (the hard guarantee)', () => {
  for (const q of REQUIRED_PROMPTS) {
    const intent = detectIdentityIntent(q);
    let finalAnswer = "I'm not familiar with that and I don't have a verifiable source.";
    assert.equal(isRefusal(finalAnswer), true, 'precondition: draft is a refusal');
    if (intent.isSelf && isRefusal(finalAnswer)) finalAnswer = answerFromIdentity(q);
    assert.equal(isRefusal(finalAnswer), false, `guard must clear the refusal for "${q}"`);
    for (const banned of BANNED_PHRASES) {
      assert.ok(!finalAnswer.toLowerCase().includes(banned), `no "${banned}" after guard`);
    }
  }
});

// Ensure a clean profile for any suite that runs after this file.
test('teardown: restore disk profile', () => {
  _resetForTests();
  reloadIdentity();
  assert.equal(getIdentityProfile().company.name, 'Aquiplex');
});

