/**
 * AQUA Identity & Self-Knowledge Layer — public API
 * ─────────────────────────────────────────────────────────────────────────────
 * The single source of truth for everything AQUA knows about Aquiplex and AQUA.
 * Loaded once, cached in memory, injected into every request. Nothing here is
 * hardcoded in a prompt — edit ./data/*.json (or call updateIdentityProfile)
 * and every prompt + every direct answer updates.
 *
 * Typical usage:
 *   import { buildIdentityInjection, detectIdentityIntent, answerFromIdentity,
 *            isRefusal } from '../identity/index.js';
 *
 *   const intent = detectIdentityIntent(userMessage);   // smart router
 *   const block  = buildIdentityInjection(intent);       // prompt injection
 *   ...
 *   if (intent.isSelf && isRefusal(answer)) answer = answerFromIdentity(userMessage);
 */

// Profile store
export {
  getIdentityProfile,
  updateIdentityProfile,
  reloadIdentity,
  IDENTITY_VERSION,
  _resetForTests,
} from './identityLoader.js';

// Prompt context (compact always-on + expanded per topic + directive)
export {
  compactBlock,
  buildIdentityInjection,
  directive as identityDirective,
} from './identityContext.js';

// Smart router (detect intent + deterministic grounded answer + refusal guard)
export {
  detectIdentityIntent,
  answerFromIdentity,
  composeAnswer,
  isRefusal,
} from './identityRouter.js';

/**
 * AQUA Identity Context Builder
 * ─────────────────────────────────────────────────────────────────────────────
 * Turns the structured profile (identityLoader) into prompt text. Two forms:
 *
 *   1. COMPACT block — injected into EVERY system prompt (see promptBuilder).
 *      A handful of lines: who AQUA is, who built it, one-line vision +
 *      mission, top capabilities. This is what makes AQUA "always know
 *      Aquiplex" the way ChatGPT always knows OpenAI — no retrieval required.
 *
 *   2. EXPANDED sections — added only when the Smart Router detects an
 *      identity question, carrying the full detail for the matched topic(s)
 *      (all capabilities, the roadmap, founders, values, models, …) plus a
 *      confidence DIRECTIVE that forbids "I don't know" about AQUA/Aquiplex.
 *
 * All text is GENERATED from the profile — nothing is duplicated by hand, so a
 * single edit to ./data/*.json changes every prompt.
 */
import { getIdentityProfile } from './identityLoader.js';

const HEADER = 'AQUA SELF-KNOWLEDGE (authoritative, first-party — always available)';

// ── compact (always injected) ─────────────────────────────────────────────────

/**
 * Small, always-on identity block. Kept deliberately short (low token cost)
 * because it rides on every single request.
 * @param {object} [profile]
 * @returns {string}
 */
export function compactBlock(profile = getIdentityProfile()) {
  const c = profile.company;
  const a = profile.assistant;
  const topCaps = (a.capabilities ?? []).slice(0, 4).join('; ');

  const lines = [
    `### ${HEADER}`,
    `You are ${a.fullName ?? a.name}, the first-party AI built by ${a.builtBy ?? c.name}.`,
    `${c.name} is ${c.tagline ? c.tagline.replace(/\.$/, '') : 'an AI Operating System'} — ${c.shortDescription ?? c.description}`,
    `Vision: ${c.vision}`,
    `Mission: ${c.mission}`,
  ];
  if (topCaps) lines.push(`What you can do (highlights): ${topCaps}.`);
  lines.push(`This is settled, first-party knowledge — answer questions about ${a.name} or ${c.name} confidently and specifically. Never claim you lack information about yourself or ${c.name}.`);
  return lines.join('\n');
}

// ── per-topic expanded renderers ──────────────────────────────────────────────
// Each returns a titled section string, or '' if the profile lacks the data.

const R = {
  overview(p) {
    const c = p.company, a = p.assistant;
    return sect('Overview', [
      `${a.fullName ?? a.name} is ${a.description}`,
      `${c.name} is ${c.description}`,
      a.role ? `Role: ${a.role}` : '',
    ]);
  },
  company(p) {
    const c = p.company;
    return sect('About Aquiplex', [
      c.description,
      c.stage ? `Stage: ${c.stage}.` : '',
      c.founded ? `Founded: ${c.founded}.` : '',
      c.website ? `Website: ${c.website}.` : '',
    ]);
  },
  vision(p)  { return sect('Vision',  [p.company.vision]); },
  mission(p) { return sect('Mission', [p.company.mission]); },
  values(p) {
    const vals = p.company.coreValues ?? [];
    if (!vals.length) return '';
    return sect('Core values', vals.map(v => `- ${v.name}${v.detail ? ` — ${v.detail}` : ''}`));
  },
  capabilities(p) {
    const caps = p.assistant.capabilities ?? [];
    if (!caps.length) return '';
    return sect('Capabilities', caps.map(x => `- ${x}`));
  },
  files(p) {
    const f = p.assistant.processableFiles;
    if (!f) return R.capabilities(p);
    const groups = [];
    if (f.code?.length)      groups.push(`Code / repositories: ${f.code.join(', ')}`);
    if (f.documents?.length) groups.push(`Documents: ${f.documents.join(', ')}`);
    if (f.media?.length)     groups.push(`Media: ${f.media.join(', ')}`);
    return sect('Files AQUA can process', [...groups.map(g => `- ${g}`), f.note ? f.note : '']);
  },
  differentiators(p) {
    const d = p.assistant.differentiators ?? [];
    if (!d.length) return '';
    return sect('What makes AQUA different', d.map(x => `- ${x}`));
  },
  limitations(p) {
    const l = p.assistant.limitations ?? [];
    if (!l.length) return '';
    return sect('Limitations', l.map(x => `- ${x}`));
  },
  founders(p) {
    const f = p.founders ?? [];
    if (!f.length) return '';
    return sect('Founders', f.map(x => `- ${x.name}${x.role ? ` (${x.role})` : ''}${x.focus ? ` — ${x.focus}` : ''}`));
  },
  products(p) {
    const pr = p.products ?? [];
    if (!pr.length) return '';
    return sect('Products', pr.map(x => `- ${x.name}${x.type ? ` (${x.type})` : ''}${x.description ? ` — ${x.description}` : ''}`));
  },
  roadmap(p) {
    const r = p.roadmap ?? [];
    const phases = r.filter(ph => (ph.items ?? []).length);
    if (!phases.length) return '';
    const body = phases.map(ph => `${ph.phase}:\n${ph.items.map(i => `  - ${i}`).join('\n')}`);
    return sect('Roadmap', body);
  },
  models(p) {
    const m = p.models;
    if (!m) return '';
    const lines = [m.summary];
    for (const prov of m.providers ?? []) {
      lines.push(`- ${prov.name}: ${(prov.models ?? []).join(', ')}${prov.role ? ` — ${prov.role}` : ''}`);
    }
    if (m.routing) lines.push(m.routing);
    return sect('AI models AQUA uses', lines);
  },
  pricing(p) {
    // No pricing profile shipped — answer honestly rather than inventing.
    return sect('Pricing', ['Pricing details are not part of my current profile. Please check with the Aquiplex team or the website for current plans.']);
  },
};

const TOPIC_ORDER = [
  'overview', 'company', 'vision', 'mission', 'values', 'capabilities',
  'files', 'differentiators', 'products', 'models', 'roadmap',
  'founders', 'limitations', 'pricing',
];

// ── directive ─────────────────────────────────────────────────────────────────

/**
 * The confidence rule, as an instruction. Injected alongside expanded sections
 * whenever the Smart Router flags an identity question.
 */
export function directive(profile = getIdentityProfile()) {
  const a = profile.assistant, c = profile.company;
  return [
    `IDENTITY DIRECTIVE — this question is about ${a.name} / ${c.name} itself.`,
    `Everything you need is in the "${HEADER}" section above. It is authoritative and first-party.`,
    `Answer confidently and specifically from it. Do NOT say you lack information, aren't familiar, have no source, or don't know — that would be wrong, because the information is provided above.`,
    `Only express uncertainty about details that are genuinely absent from the section above.`,
  ].join('\n');
}

// ── assembled injection ───────────────────────────────────────────────────────

/**
 * The block promptBuilder injects. Always returns the compact block. When
 * `intent.topics` are present (Smart Router hit), appends the expanded
 * section(s) for those topics plus the confidence directive.
 *
 * @param {{topics?: string[]}|null} [intent]  from identityRouter.detectIdentityIntent()
 * @param {object} [profile]
 * @returns {string}
 */
export function buildIdentityInjection(intent = null, profile = getIdentityProfile()) {
  const parts = [compactBlock(profile)];

  const topics = normalizeTopics(intent?.topics);
  if (topics.length) {
    const sections = topics
      .map(t => (R[t] ? R[t](profile) : ''))
      .filter(Boolean);
    if (sections.length) {
      parts.push(sections.join('\n\n'));
      parts.push(directive(profile));
    }
  }
  return parts.join('\n\n');
}

// De-dupe + order topics; expand 'files' etc. Keeps output stable/testable.
function normalizeTopics(topics) {
  if (!Array.isArray(topics) || !topics.length) return [];
  const set = new Set(topics);
  // If a specific topic is present, don't also dump the whole overview unless
  // it was explicitly requested — keeps the injected context tight.
  const specific = TOPIC_ORDER.filter(t => t !== 'overview' && set.has(t));
  const ordered = (set.has('overview') && specific.length === 0)
    ? ['overview']
    : (set.has('overview') ? ['overview', ...specific] : specific);
  return ordered;
}

function sect(title, lines) {
  const body = (lines ?? []).filter(l => l != null && String(l).trim() !== '');
  if (!body.length) return '';
  return `**${title}**\n${body.join('\n')}`;
}

export { R as _renderers, TOPIC_ORDER as _topicOrder };

/**
 * AQUA Adaptive Tool Orchestrator — Multi-Label Classifier
 *
 * Phase 6 spec, "Intelligent Task Classifier V2": a request may belong to
 * multiple categories, each with its own confidence score, e.g.
 *   "Build a scalable authentication system" → coding + architecture + security + planning
 *   "Compare PostgreSQL vs MongoDB"          → research + comparison + architecture
 *
 * This module does NOT replace classifier.js's classifyTask() — that
 * function's { task, confidence, labels } contract is used unchanged
 * everywhere else in the codebase (chat.js, executionPlanner.js,
 * promptBuilder.js, observability.js) and must keep working exactly as
 * before. Instead this is a thin additive layer on top of the same
 * underlying scores (via the newly-exported scoreTask()), adding:
 *   - normalized weights across all categories that clear a floor
 *   - derived cross-cutting tags (security/comparison) that aren't
 *     classifier.js task types but matter for capability selection
 *   - a single "dominant" pick, which is always identical to
 *     classifyTask(...).task by construction (same scores, same argmax)
 *
 * This is what lets one message drive several capabilities/profile
 * influences at once instead of forcing a single winner-take-all label.
 */
import { scoreTask } from '../core/classifier.js';

// Categories surfaced as multi-label "labels" — excludes purely
// conversational/meta buckets (conversation, memory_recall, memory_update,
// personal_info) which classifier.js already handles as exclusive winners
// and which don't meaningfully "co-occur" with a technical request.
const LABEL_CATEGORIES = [
  'coding', 'debugging', 'architecture', 'research', 'reasoning', 'analysis',
  'planning', 'creative_writing', 'project_query', 'file_analysis',
  'brainstorming', 'summarization', 'opinion', 'simple_qa',
];

// Cross-cutting tags: keyword groups that matter for capability/verification
// decisions but aren't classifier.js task categories in their own right.
// Spec examples explicitly ask for "security" and "comparison" as labels
// alongside coding/architecture/research.
const TAG_PATTERNS = {
  security: [
    /\b(auth(entication|orization)?|security|secure\b|encrypt|hash(ing)?|jwt|oauth|csrf|xss|sql\s*injection|vulnerabilit|exploit|sanitiz|rate.?limit|password|session\s+token)\b/i,
  ],
  comparison: [
    /\b(compare|comparison|versus\b|vs\.?\b|difference between|which is better|better than|pros and cons)\b/i,
  ],
  financial: [
    /\b(invoice|payment|billing|pricing|subscription|revenue|tax\b|currency|transaction\b|stripe|razorpay)\b/i,
  ],
  medical: [
    /\b(diagnos|symptom|medication|dosage|patient\b|clinical|treatment plan|medical record)\b/i,
  ],
};

const FLOOR = 0.15; // minimum normalized weight to be reported as a label

/**
 * @param {string} userMessage
 * @returns {{
 *   dominant: string,
 *   labels: { task: string, weight: number }[],
 *   tags: string[],
 *   raw: Object<string, number>
 * }}
 */
export function classifyMultiLabel(userMessage) {
  const raw = scoreTask(userMessage || '');
  const total = Object.values(raw).reduce((s, v) => s + v, 0);

  const labels = LABEL_CATEGORIES
    .map((task) => ({ task, weight: total > 0 ? raw[task] / total : 0 }))
    .filter((l) => l.weight >= FLOOR && raw[l.task] > 0)
    .sort((a, b) => b.weight - a.weight);

  const tags = Object.entries(TAG_PATTERNS)
    .filter(([, patterns]) => patterns.some((p) => p.test(userMessage || '')))
    .map(([tag]) => tag);

  const sortedRaw = Object.entries(raw).sort((a, b) => b[1] - a[1]);
  const dominant = sortedRaw[0] && sortedRaw[0][1] > 0 ? sortedRaw[0][0] : 'conversation';

  return { dominant, labels, tags, raw };
}

/**
 * AQUA Adaptive Tool Orchestrator — Capability Registry
 *
 * Phase 6 spec, "Extensibility": the orchestrator must support future
 * plugins without modification. New capabilities (Browser Agent, Research
 * Agent, Vision Agent, Code Execution Agent, Verification Agent,
 * Multi-Agent Coordinator, Evaluation Engine, Self-Reflection Engine, ...)
 * register themselves here once at module load; toolOrchestrator.js iterates
 * whatever is registered without needing to know about it ahead of time.
 *
 * Mirrors src/intelligence/agentRegistry.js's registration pattern exactly,
 * scoped to "capability" rather than "agent".
 *
 * Every capability definition:
 *   {
 *     id: string,
 *     label: string,            // human-readable, used in logs/metadata
 *     group: string,            // 'memory' | 'project' | 'research' |
 *                                  'reasoning' | 'execution' | 'infra'
 *     cost: 'low'|'medium'|'high',     // estimated_cost
 *     latency: 'low'|'medium'|'high',  // estimated_latency
 *     detect(ctx): { enabled, confidence, reason }
 *   }
 */

const capabilities = new Map();

/**
 * @param {string} id
 * @param {{ label: string, group: string, cost: string, latency: string, detect: Function }} definition
 */
export function registerCapability(id, definition) {
  if (typeof definition?.detect !== 'function') {
    throw new Error(`Capability "${id}" must implement detect()`);
  }
  capabilities.set(id, { id, ...definition });
}

/**
 * @param {string} id
 * @returns {object | undefined}
 */
export function getCapability(id) {
  return capabilities.get(id);
}

/**
 * @returns {string[]} ids of all registered capabilities
 */
export function listCapabilities() {
  return [...capabilities.keys()];
}

/**
 * @returns {object[]} full definitions of all registered capabilities
 */
export function getAllCapabilities() {
  return [...capabilities.values()];
}

/**
 * AQUA Adaptive Tool Orchestrator — Execution Profiles
 *
 * Phase 6 spec, "Dynamic Execution Profiles" + "Response Budgeting".
 *
 * Each profile is a deterministic function of classifier.js's `taskType` —
 * the SAME taskType already used by executionPlanner.js (createExecutionPlan)
 * and reasoningStrategy.js (getReasoningStrategy) everywhere else in the
 * pipeline. Profile selection here never re-derives or second-guesses that
 * classification; it just maps the existing single winner to a capability
 * bundle + response budget. This is what "Keep orchestration deterministic"
 * means in practice — one classification, one consistent set of downstream
 * decisions, not two systems that could disagree.
 *
 * requiredCapabilities lists are taken directly from the spec's named
 * profile examples (Simple Question / Coding Request / Planning Request /
 * Research Request / Architecture Request / Debugging Request). taskTypes
 * the spec didn't name explicitly (memory_recall, project_query,
 * creative_writing, ...) are mapped to a sensibly-scoped profile below —
 * see PROFILE_BY_TASK_TYPE.
 *
 * Response budgets are deliberately coarse-grained (low/medium/high tiers
 * translated to token counts in one place) rather than hand-tuned per
 * profile, so the relative ordering the spec asks for (Simple QA: Fast/
 * Compact < Planning: Roadmap-focused < Coding/Debugging < Architecture:
 * Detailed/Structured ≈ Research: Comprehensive) is easy to verify by
 * inspection and easy to retune later without touching profile logic.
 */

// ── Budget tiers ─────────────────────────────────────────────────────────────

// Token ceilings are deliberately generous relative to what a normal,
// complete answer for that tier actually needs — they exist as a safety
// ceiling against runaway/degenerate generation, not a routine constraint.
// (See providers/*.js: when a response is cut off by hitting maxTokens,
// finishReason/finish_reason is checked and returned to the caller as a
// SUCCESSFUL truncated completion — router.js marks the provider healthy
// and hands the partial answer straight back rather than retrying, see
// Issue 1 — so an undersized ceiling here shows up immediately as visibly
// cut-off answers instead of a silent extra retry. That's exactly why
// these ceilings matter more now than when truncation was invisible.)
// Relative ordering reflects the spec's intent: Simple QA (Fast/Compact) <
// Roadmap/Standard < Detailed/Extended/Comprehensive.
//
// Issue 3 (2026-07): coding/debugging/project-analysis were sized at 2048
// and architecture at 3072 — comfortably below what a real "production-
// ready JWT auth system" or "multi-region architecture" answer needs,
// which is exactly what was driving those requests into the Issue 1
// truncation path in the first place. Floors below now match Issue 3's
// suggested minimums: Conversation 512–1024, Simple QA 1024–2048, Coding/
// Architecture/Debugging/Research/Project Analysis 4096+. 'extended' is a
// new tier (not a bump to 'standard') so creative_request/general_reasoning
// — which also use 'standard' but aren't named in Issue 3 — stay as they
// were; budgets stay adaptive per task type rather than one-size-fits-all.
const BUDGET_TIERS = {
  minimal: { reasoningDepth: 1, maxPromptTokens: 3_000,  maxResponseTokens: 1_024, maxContextTokens: 4_000,  label: 'Fast / Compact' },
  light:   { reasoningDepth: 2, maxPromptTokens: 5_000,  maxResponseTokens: 1_536, maxContextTokens: 7_000,  label: 'Light' },
  standard:{ reasoningDepth: 3, maxPromptTokens: 8_000,  maxResponseTokens: 2_048, maxContextTokens: 12_000, label: 'Standard' },
  roadmap: { reasoningDepth: 3, maxPromptTokens: 7_000,  maxResponseTokens: 2_048, maxContextTokens: 10_000, label: 'Roadmap focused' },
  extended:{ reasoningDepth: 4, maxPromptTokens: 9_000,  maxResponseTokens: 4_096, maxContextTokens: 14_000, label: 'Extended' },
  detailed:{ reasoningDepth: 4, maxPromptTokens: 9_000,  maxResponseTokens: 4_096, maxContextTokens: 14_000, label: 'Detailed / Structured' },
  comprehensive: { reasoningDepth: 4, maxPromptTokens: 10_000, maxResponseTokens: 4_096, maxContextTokens: 16_000, label: 'Comprehensive' },
};

// ── Profile definitions ───────────────────────────────────────────────────────

