/**
 * AQUA Adaptive Tool Orchestrator — Verification Strategy
 *
 * Phase 6 spec, "Verification Strategy": do NOT perform expensive
 * second-pass reasoning for every request. Only enable verification if
 * complexity is high, risk is high, or the request is architecture,
 * security, financial, medical, or large-code-generation in nature.
 *
 * This module only decides WHETHER verification is warranted — it never
 * performs verification itself. The actual second pass is intentionally
 * left unimplemented ("Design this so a future LLM-based verification pass
 * can be plugged in without changing the architecture"): the plug-in seam
 * already exists in src/intelligence/agentRegistry.js, which today has zero
 * agents registered. toolOrchestrator.js checks getAgent('verification')
 * when this strategy says verification is enabled; while no such agent is
 * registered, that's a no-op, which is exactly the spec's "otherwise skip
 * verification" — so this stays a pure decision function with zero added
 * LLM calls until a future phase registers a real verification agent.
 */

const LARGE_CODE_GENERATION_CHARS = 1200; // heuristic: long coding asks tend to mean multi-file/non-trivial output

/**
 * @param {{ taskType: string, complexity: string, tags: string[], userMessage: string }} input
 * @returns {{ enabled: boolean, reasons: string[], reason: string }}
 */
export function shouldVerify({ taskType, complexity, tags = [], userMessage = '' }) {
  const reasons = [];

  if (complexity === 'high') reasons.push('complexity is high');
  if (taskType === 'architecture') reasons.push('architecture request');
  if (tags.includes('security')) reasons.push('security request');
  if (tags.includes('financial')) reasons.push('financial reasoning');
  if (tags.includes('medical')) reasons.push('medical reasoning');
  if (taskType === 'coding' && userMessage.length > LARGE_CODE_GENERATION_CHARS) {
    reasons.push('large code generation');
  }

  // "Risk is high" — not its own independent signal but a label for the
  // case where multiple sensitive-domain tags stack on one request, which
  // is strictly riskier than any one of them alone.
  const sensitiveTagCount = ['security', 'financial', 'medical'].filter((t) => tags.includes(t)).length;
  if (sensitiveTagCount >= 2) reasons.push('risk is high (multiple sensitive domains)');

  const enabled = reasons.length > 0;
  return {
    enabled,
    reasons,
    reason: enabled
      ? reasons.join('; ')
      : 'No high-complexity/high-risk signal present — verification skipped to avoid unnecessary second-pass reasoning.',
  };
}

/**
 * AQUA Adaptive Tool Orchestrator — Main Entry Point
 *
 * Phase 6 spec. Sits immediately after task classification and immediately
 * before the existing Execution Planner stage:
 *
 *   User → Task Classification → [Adaptive Tool Orchestrator] →
 *   Execution Planner → Internal Intelligence → Prompt Builder →
 *   Provider Router → LLM → Response
 *
 * orchestrate() is a pure, synchronous, deterministic function: same inputs
 * always produce the same decision, no LLM calls, no I/O. It computes:
 *   - the dominant execution profile (src/orchestrator/executionProfiles.js)
 *   - per-capability enabled/disabled/confidence/reason/cost/latency
 *     (src/orchestrator/capabilityRegistry.js + capabilities.js)
 *   - the response budget for this profile
 *   - the verification decision (src/orchestrator/verificationStrategy.js)
 *   - a multi-label breakdown + cross-cutting tags for richer logging
 *     (src/orchestrator/multiLabelClassifier.js)
 *
 * It does NOT itself decide what chat.js actually skips — that integration
 * stays in chat.js, deliberately conservative (see comments there) so this
 * module can evolve independently without risking the "do not break
 * memory / project retrieval / existing APIs" non-functional requirements.
 */
import './capabilities.js'; // side-effect: registers every capability definition
import { getAllCapabilities } from './capabilityRegistry.js';
import { classifyMultiLabel } from './multiLabelClassifier.js';
import { selectProfile } from './executionProfiles.js';
import { shouldVerify } from './verificationStrategy.js';
import { getEffectiveComplexity } from '../core/classifier.js';
import { getAgent } from '../intelligence/agentRegistry.js';

/**
 * @param {{
 *   userMessage: string,
 *   taskType: string,        // classifier.js's classifyTask(...).task — single source of truth
 *   confidence: number,      // classifyTask(...).confidence
 *   hasWorkspaceId: boolean,
 * }} input
 * @returns {object} orchestration decision (see shape below)
 */
export function orchestrate({ userMessage, taskType, confidence, hasWorkspaceId }) {
  // Derived via the same function executionPlanner.js's createExecutionPlan()
  // uses a moment later in the pipeline — see getEffectiveComplexity's
  // docstring. Lets this run genuinely *before* the Execution Planner stage
  // (per the spec's pipeline diagram) without ever disagreeing with it.
  const complexity = getEffectiveComplexity(taskType, confidence);

  const multiLabel = classifyMultiLabel(userMessage);
  const profile     = selectProfile(taskType);
  const verification = shouldVerify({ taskType, complexity, tags: multiLabel.tags, userMessage });

  const requiredSet = new Set(profile.requiredCapabilities);
  const ctx = {
    taskType, complexity, confidence, hasWorkspaceId,
    requiredSet, profileLabel: profile.label, verification, multiLabel,
  };

  const capabilities = getAllCapabilities().map((cap) => {
    const decision = cap.detect(ctx);
    return {
      id: cap.id,
      label: cap.label,
      group: cap.group,
      estimated_cost: cap.cost,
      estimated_latency: cap.latency,
      enabled: decision.enabled,
      confidence: Number((decision.confidence ?? 0).toFixed(2)),
      reason: decision.reason,
    };
  });

  const enabled  = capabilities.filter((c) => c.enabled);
  const skipped  = capabilities.filter((c) => !c.enabled);

  // Verification's *capability* entry already reflects shouldVerify()'s
  // decision (capabilities.js wires it via an override), but the seam for
  // an eventual LLM-based verification agent lives here: if/when a future
  // phase calls registerAgent('verification', {...}) against
  // src/intelligence/agentRegistry.js, this is where toolOrchestrator would
  // hand off to it. Today agentRegistry has nothing registered, so this is
  // always a no-op — exactly the spec's "otherwise skip verification".
  const verificationAgent = verification.enabled ? getAgent('verification') : undefined;

  const estimatedCost    = roughTier(enabled, 'estimated_cost');
  const estimatedLatency = roughTier(enabled, 'estimated_latency');

  return {
    profile: { id: profile.id, label: profile.label, description: profile.description },
    budget: profile.budget,
    complexity,
    capabilities,
    enabled,
    skipped,
    estimatedCost,
    estimatedLatency,
    confidence,
    reasoningDepth: profile.budget.reasoningDepth,
    verification: { enabled: verification.enabled, reason: verification.reason, agentAvailable: !!verificationAgent },
    memoryUsed: enabled.some((c) => c.group === 'memory'),
    repositoryUsed: enabled.some((c) => c.id === 'repository_understanding'),
    researchUsed: enabled.some((c) => c.group === 'research'),
    multiLabel,
  };
}

// Cheapest-common-denominator tier across enabled capabilities — used only
// for the rolled-up "Estimated Cost: Medium" style summary line in logs.
function roughTier(enabledCapabilities, field) {
  const order = { low: 0, medium: 1, high: 2 };
  const names = ['low', 'medium', 'high'];
  if (!enabledCapabilities.length) return 'low';
  const max = enabledCapabilities.reduce((m, c) => Math.max(m, order[c[field]] ?? 0), 0);
  return names[max];
}

/**
 * Renders the orchestration decision in the spec's exact [ORCHESTRATOR] log
 * format ("Logging" section). Internal-only — never sent to the client; see
 * chat.js, which logs this server-side and exposes a separate, smaller
 * metadata object on the response for debugging APIs.
 *
 * @param {object} decision  result of orchestrate()
 * @returns {string}
 */
export function formatOrchestratorLog(decision) {
  const enabledNames = decision.enabled.map((c) => c.label).join('\n');
  const skippedNames = decision.skipped.map((c) => c.label).join('\n');
  const reasonParts = [decision.profile.description];
  if (decision.verification.enabled) {
    reasonParts.push(`Verification enabled: ${decision.verification.reason}.`);
  }

  return [
    '[ORCHESTRATOR]',
    `Profile = ${decision.profile.label}`,
    '',
    'Enabled:',
    enabledNames || '(none)',
    '',
    'Skipped:',
    skippedNames || '(none)',
    '',
    `Estimated Cost:\n${capitalize(decision.estimatedCost)}`,
    '',
    `Estimated Latency:\n${capitalize(decision.estimatedLatency)}`,
    '',
    `Reason:\n${reasonParts.join(' ')}`,
  ].join('\n');
}

function capitalize(s) {
  return s ? s[0].toUpperCase() + s.slice(1) : s;
}

/**
 * Groq Provider v3
 *
 * Changes from v2:
 * - Model ID no longer hardcoded — pulled from the central Model Registry
 *   (Issue 5). llama-3.3-70b-versatile (the old hardcoded default) was
 *   announced deprecated by Groq on 2026-06-17; registry now defaults to
 *   openai/gpt-oss-120b (Groq's own recommended replacement — also faster
 *   and cheaper), with openai/gpt-oss-20b and the old llama model kept as
 *   ordered fallbacks.
 * - Added a per-request fallback loop across those candidate models
 *   (Issue 4/12): a single dead/rate-limited model no longer fails the
 *   whole Groq call — only exhausting every candidate does.
 * - TRUNCATED_MAX_TOKENS is no longer thrown (Issue 1). Hitting the output
 *   cap is a successful completion — returns { text, truncated: true,
 *   finishReason: 'length' } so it's never counted as a provider failure.
 * - Shared error classifier (providerErrors.js, Issue 4) replaces the
 *   inline status checks.
 *
 * Preserved from v2:
 * - Client cached per key (HTTP connection reuse).
 * - signal.aborted check before starting each race.
 * - Key rotation skips cooled keys.
 */

import Groq from 'groq-sdk';
import {
  getCandidateModels, markModelWorking, markModelUnavailable,
} from './modelRegistry.js';
import { classifyProviderError } from './providerErrors.js';

function getKeys() {
  return [
    process.env.GROQ_API_KEY_1,
    process.env.GROQ_API_KEY_2,
    process.env.GROQ_API_KEY_3,
    process.env.GROQ_API_KEY_4,
  ].filter(Boolean);
}

/** Startup validation (Issue 6) — does this provider have any usable key at all? */
export function hasConfiguredKeys() {
  return getKeys().length > 0;
}

let keyIndex = 0;
const keyCooldowns = new Map();
const clientCache  = new Map();

function onCooldown(key) {
  const until = keyCooldowns.get(key);
  return until ? Date.now() < until : false;
}

function applyCooldown(key, ms) {
  keyCooldowns.set(key, Date.now() + ms);
}

function getClient(key) {
  if (!clientCache.has(key)) {
    clientCache.set(key, new Groq({ apiKey: key }));
  }
  return clientCache.get(key);
}

function nextKey() {
  const keys = getKeys();
  if (!keys.length) throw new Error('No Groq keys configured');
  for (let i = 0; i < keys.length; i++) {
    const k = keys[keyIndex];
    keyIndex = (keyIndex + 1) % keys.length;
    if (!onCooldown(k)) return k;
  }
  throw new Error('All Groq keys on cooldown');
}

/**
 * @param {string} systemPrompt
 * @param {Array<{role:string,content:string}>} messages
 * @param {AbortSignal} [signal]
 * @param {number} [maxTokens] - Phase 6 Response Budgeting: caps output length.
 *   Clamped against the registry's maxOutputTokens for whichever model is
 *   actually selected.
 * @returns {Promise<{ text: string, truncated: boolean, finishReason: string }>}
 */
export async function generateGroq(systemPrompt, messages, signal, maxTokens) {
  if (signal?.aborted) throw new Error('TIMEOUT');

  const candidates = getCandidateModels('groq');
  if (!candidates.length) throw new Error('All Groq models permanently unavailable');

  let lastError;

  for (const modelEntry of candidates) {
    const modelId  = modelEntry.modelId;
    const capTokens = maxTokens ? Math.min(maxTokens, modelEntry.maxOutputTokens) : maxTokens;

    let key;
    try {
      key = nextKey();
    } catch (e) {
      // No usable key at all — true for every model too, stop here.
      throw e;
    }

    const client = getClient(key);
    const chatMessages = [
      ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
      ...messages.map(m => ({ role: m.role, content: m.content })),
    ];

    console.log(`[GROQ] model=${modelId} key=...${key.slice(-4)}`);

    const req = client.chat.completions.create({
      model:    modelId,
      messages: chatMessages,
      ...(capTokens ? { max_tokens: capTokens } : {}),
    });
    // Demo-stability fix: if the timeout wins the Promise.race below, `req`
    // keeps running detached. Should it later REJECT (network drop, 5xx),
    // that becomes an unhandled promise rejection — which is FATAL on
    // modern Node (default --unhandled-rejections=throw) and would crash
    // the whole server mid-request. Subscribing a no-op handler marks any
    // late rejection as handled; the race path is unaffected.
    Promise.resolve(req).catch(() => {});

    let result;
    try {
      result = signal
        ? await Promise.race([
            req,
            new Promise((_, rej) => {
              if (signal.aborted) return rej(new Error('TIMEOUT'));
              signal.addEventListener('abort', () => rej(new Error('TIMEOUT')), { once: true });
            }),
          ])
        : await req;
    } catch (err) {
      if (err.message === 'TIMEOUT') throw err; // router's budget spent — propagate immediately

      lastError = err;
      const { type, status } = classifyProviderError(err);

      if (type === 'model_not_found') {
        markModelUnavailable('groq', modelId, `${status ?? ''} ${err.message}`.trim());
        continue; // next candidate model
      }
      if (type === 'rate_limit') {
        console.log(`[GROQ] model=${modelId} key=...${key.slice(-4)} rate limited → 90s cooldown`);
        applyCooldown(key, 90_000);
        continue;
      }
      if (type === 'auth') {
        console.log(`[GROQ] key=...${key.slice(-4)} auth error → 24h cooldown`);
        applyCooldown(key, 86_400_000);
        continue;
      }
      console.log(`[GROQ] model=${modelId} error type=${type} status=${status} msg=${err.message}`);
      continue; // server_error / network / unknown — try next candidate model
    }

    const finishReason = result?.choices?.[0]?.finish_reason;
    const text = result?.choices?.[0]?.message?.content;

    // ── Issue 1: hitting the output-token cap is SUCCESS, not failure ──
    if (capTokens && finishReason === 'length') {
      if (!text || !text.trim()) {
        lastError = new Error('Groq returned empty truncated response');
        continue; // nothing usable — try next candidate model
      }
      console.log(`[GROQ] model=${modelId} hit maxTokens=${capTokens} cap — returning partial as successful completion`);
      markModelWorking('groq', modelId);
      return { text, truncated: true, finishReason: 'length' };
    }

    if (!text) {
      lastError = new Error('Groq returned empty response');
      continue;
    }

    markModelWorking('groq', modelId);
    return { text, truncated: false, finishReason: finishReason ?? 'stop' };
  }

  throw lastError ?? new Error('All Groq attempts exhausted');
}

/**
 * Streaming variant (Day 3 — Real Streaming).
 *
 * Same key rotation / model-registry fallback semantics as generateGroq,
 * with one hard rule: model/key fallback only happens BEFORE the first
 * delta reaches onDelta. Once a single token has been emitted the client
 * has already seen it — a mid-stream failure is surfaced as an
 * interrupted-partial result (never silently retried on another model,
 * which would restart the answer under the user's cursor).
 *
 * @param {string} systemPrompt
 * @param {Array<{role:string,content:string}>} messages
 * @param {AbortSignal} [signal]      - abort = TIMEOUT (router budget) or client cancel
 * @param {number} [maxTokens]
 * @param {(delta: string) => void} onDelta - called per content token
 * @returns {Promise<{ text:string, truncated:boolean, finishReason:string, streamed:true }>}
 */
export async function streamGroq(systemPrompt, messages, signal, maxTokens, onDelta) {
  if (signal?.aborted) throw new Error('TIMEOUT');

  const candidates = getCandidateModels('groq');
  if (!candidates.length) throw new Error('All Groq models permanently unavailable');

  let lastError;

  for (const modelEntry of candidates) {
    const modelId   = modelEntry.modelId;
    const capTokens = maxTokens ? Math.min(maxTokens, modelEntry.maxOutputTokens) : maxTokens;

    let key;
    try { key = nextKey(); } catch (e) { throw e; }
    const client = getClient(key);

    const chatMessages = [
      ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
      ...messages.map(m => ({ role: m.role, content: m.content })),
    ];

    console.log(`[GROQ] stream model=${modelId} key=...${key.slice(-4)}`);

    let stream;
    try {
      stream = await client.chat.completions.create(
        {
          model:    modelId,
          messages: chatMessages,
          stream:   true,
          ...(capTokens ? { max_tokens: capTokens } : {}),
        },
        { signal }, // SDK aborts the underlying request when the router/client cancels
      );
    } catch (err) {
      if (signal?.aborted || err.name === 'AbortError') throw new Error('TIMEOUT');
      lastError = err;
      const { type, status } = classifyProviderError(err);
      if (type === 'model_not_found') { markModelUnavailable('groq', modelId, `${status ?? ''} ${err.message}`.trim()); continue; }
      if (type === 'rate_limit')      { applyCooldown(key, 90_000);  continue; }
      if (type === 'auth')            { applyCooldown(key, 86_400_000); continue; }
      console.log(`[GROQ] stream open failed model=${modelId} type=${type} msg=${err.message}`);
      continue;
    }

    let text = '';
    let finishReason = null;
    try {
      for await (const chunk of stream) {
        if (signal?.aborted) throw new Error('TIMEOUT');
        const delta = chunk?.choices?.[0]?.delta?.content;
        finishReason = chunk?.choices?.[0]?.finish_reason ?? finishReason;
        if (delta) { text += delta; onDelta(delta); }
      }
    } catch (err) {
      // Mid-stream failure: the client already saw `text` — return it as an
      // interrupted partial rather than restarting on another model.
      if (text) {
        console.log(`[GROQ] stream interrupted after ${text.length} chars model=${modelId}: ${err.message}`);
        return { text, truncated: true, finishReason: 'interrupted', streamed: true };
      }
      if (signal?.aborted || err.name === 'AbortError' || err.message === 'TIMEOUT') throw new Error('TIMEOUT');
      lastError = err;
      continue; // nothing emitted yet — safe to try next candidate model
    }

    if (!text.trim()) { lastError = new Error('Groq stream returned empty response'); continue; }

    markModelWorking('groq', modelId);
    const truncated = capTokens && finishReason === 'length';
    return { text, truncated: !!truncated, finishReason: truncated ? 'length' : (finishReason ?? 'stop'), streamed: true };
  }

  throw lastError ?? new Error('All Groq stream attempts exhausted');
}

/**
 * AQUA Provider Router v4
 *
 * Changes from v3 (Issue 1/7/8/9):
 *   6. callProvider()/generateText() now handle the { text, truncated,
 *      finishReason } shape gemini.js/groq.js/openrouter.js return.
 *      finishReason="length" (the output-token budget was hit) is treated
 *      as a SUCCESSFUL completion: markSuccess (not markFailure), no
 *      validateResponse reject-path, no retry on another provider — the
 *      partial answer is returned immediately with truncated=true so the
 *      client can offer "Continue". Previously providers threw
 *      TRUNCATED_MAX_TOKENS for this case, which this same catch block
 *      treated identically to a timeout/network/5xx failure — marking the
 *      provider unhealthy and burning through the whole fallback chain for
 *      a request that had actually succeeded.
 *
 * Changes from v2:
 *   1. toTry = ranked (ALL healthy providers, not just top 3)
 *      Previously: slice(0, 3) → if Groq/Gemini/OpenRouter[0] all fail → HARD TIMEOUT
 *      Now: exhausts every healthy provider before giving up
 *
 *   2. taskType accepted from caller (chat.js already classified)
 *      Avoids double classification — classifyTask runs once per request total
 *      Falls back to internal classification if not provided (backward compat)
 *
 *   3. QUALITY table extended: memory_recall, memory_update, planning columns
 *
 *   4. Degraded mode logging improved — clearly logs WHICH providers are unhealthy
 *
 * Phase 4 addition (additive, optional):
 *   5. generateText() accepts an optional executionPlan — its complexity tier
 *      biases provider order (strategy.js) and timeout budget (timeoutManager.js).
 *      Omitting the param reproduces pre-Phase-4 behavior exactly.
 */

import { classifyTask }        from '../core/classifier.js';
import { getProviderStrategy } from '../core/strategy.js';
import {
  isProviderHealthy, markSuccess, markFailure, getHealthScore,
} from '../core/health.js';
import { validateResponse }    from '../core/validator.js';
import { getTimeout }          from '../core/timeoutManager.js';
import { generateGemini, streamGemini }         from './gemini.js';
import { generateGroq, streamGroq }             from './groq.js';
import { generateOpenRouter, streamOpenRouter } from './openrouter.js';

// ── Provider quality matrix ───────────────────────────────────────────────────
// 0–100: capability of this provider for this task type.
// Empirical + benchmark-driven. Update as models improve.

const QUALITY = {
  gemini: {
    conversation:          68, personal_info:         68, simple_qa:             80,
    opinion:               74, brainstorming:         85, summarization:         84,
    debugging:             88, coding:                90, architecture:          96,
    research:              95, reasoning:             91, analysis:              92,
    planning:              89, creative_writing:      85, file_analysis:         90,
    agent_task:            88, memory_recall:         80, memory_update:         75,
  },
  groq: {
    conversation:          95, personal_info:         92, simple_qa:             88,
    opinion:               82, brainstorming:         79, summarization:         79,
    debugging:             80, coding:                80, architecture:          70,
    research:              72, reasoning:             75, analysis:              74,
    planning:              74, creative_writing:      78, file_analysis:         70,
    agent_task:            70, memory_recall:         95, memory_update:         92,
  },
  openrouter: {
    conversation:          65, personal_info:         65, simple_qa:             70,
    opinion:               70, brainstorming:         70, summarization:         75,
    debugging:             75, coding:                75, architecture:          75,
    research:              78, reasoning:             72, analysis:              76,
    planning:              72, creative_writing:      72, file_analysis:         72,
    agent_task:            72, memory_recall:         70, memory_update:         68,
  },
};


// ── Scoring ───────────────────────────────────────────────────────────────────

function scoreProvider(provider, taskType) {
  if (!isProviderHealthy(provider)) return 0;
  const quality = QUALITY[provider]?.[taskType] ?? 70;
  const health  = getHealthScore(provider);
  return (quality * 0.55) + (health * 0.45);
}

function rankProviders(taskType, complexity) {
  const order  = getProviderStrategy(taskType, complexity);
  const scored = order.map(p => ({ provider: p, score: scoreProvider(p, taskType) }));
  const active = scored.filter(x => x.score > 0).sort((a, b) => b.score - a.score);

  if (!active.length) {
    // All providers unhealthy — degraded mode: attempt all anyway
    const unhealthy = scored.map(x => x.provider).join(', ');
    console.warn(`[ROUTER] ⚠ All providers unhealthy (${unhealthy}) — degraded mode`);
    return scored.map(x => ({ ...x, score: 1 }));
  }

  return active;
}

// ── Utilities ─────────────────────────────────────────────────────────────────

function timedAbort(ms) {
  const ctrl = new AbortController();
  const t    = setTimeout(() => ctrl.abort(), ms);
  return { signal: ctrl.signal, clear: () => clearTimeout(t) };
}

async function callProvider(provider, systemPrompt, messages, signal, maxTokens) {
  const start = Date.now();
  let result; // { text, truncated, finishReason } — see Issue 1
  if      (provider === 'gemini')     result = await generateGemini(systemPrompt, messages, signal, maxTokens);
  else if (provider === 'groq')       result = await generateGroq(systemPrompt, messages, signal, maxTokens);
  else                                result = await generateOpenRouter(systemPrompt, messages, signal, maxTokens);
  return { ...result, latency: Date.now() - start };
}

// ── Main entry ────────────────────────────────────────────────────────────────

/**
 * Generate a response, trying all healthy providers in ranked order.
 *
 * @param {string} userMessage    - raw user message
 * @param {string} systemPrompt   - from promptBuilder (already includes memory block)
 * @param {Array}  messages       - [{role, content}] context window
 * @param {object} ctx            - observability context
 * @param {string} [preTaskType]  - if caller already classified, pass it to avoid re-classifying
 * @param {object} [executionPlan] - Phase 4: from executionPlanner.js — { complexity, ... }.
 *                                   Optional; omitting it reproduces pre-Phase-4 behavior exactly.
 * @param {object} [responseBudget] - Phase 6: from orchestrator's execution profile —
 *                                   { maxResponseTokens, ... }. Optional; omitting it
 *                                   reproduces pre-Phase-6 behavior exactly (no max_tokens
 *                                   sent to any provider, response length fully model-driven).
 * @returns {Promise<object>}
 */
export async function generateText(userMessage, systemPrompt, messages, ctx = {}, preTaskType, executionPlan, responseBudget) {
  const requestId = ctx.requestId ?? 'unknown';
  const complexity = executionPlan?.complexity; // undefined → strategy.js / timeoutManager.js no-op defaults
  const maxTokens = responseBudget?.maxResponseTokens; // undefined → providers omit the field entirely

  // ── 1. Classify (skip if caller already did it) ──────────────────────────────
  let taskType, confidence, labels;
  if (preTaskType) {
    taskType   = preTaskType;
    confidence = 1.0;
    labels     = [preTaskType];
  } else {
    ({ task: taskType, confidence, labels } = classifyTask(userMessage));
    console.log(`[CLASSIFIER] task=${taskType} conf=${confidence.toFixed(2)} labels=[${labels}] req=${requestId}`);
  }

  // ── 2. Rank ALL healthy providers ────────────────────────────────────────────
  // FIX: was ranked.slice(0, 3) — only 3 attempts max.
  // Now: tries EVERY healthy provider before giving up.
  const ranked = rankProviders(taskType, complexity);
  console.log(`[ROUTER] providers=[${ranked.map(r => `${r.provider}(${r.score.toFixed(0)})`).join(', ')}] task=${taskType} complexity=${complexity ?? 'n/a'} maxTokens=${maxTokens ?? 'n/a'} req=${requestId}`);

  const promptLength = systemPrompt.length + messages.reduce((s, m) => s + m.content.length, 0);
  const fallbackChain = [];
  let   finalError;

  // ── 3. Try each provider in order ────────────────────────────────────────────
  for (const { provider, score } of ranked) {
    const timeoutMs         = getTimeout(taskType, provider, promptLength, complexity);
    const { signal, clear } = timedAbort(timeoutMs);

    console.log(`[PROVIDER] → ${provider} score=${score.toFixed(0)} timeout=${timeoutMs}ms task=${taskType}`);

    try {
      const { text, truncated, finishReason, latency } = await callProvider(provider, systemPrompt, messages, signal, maxTokens);
      clear();

      // ── Issue 1/7/8/9: max-output-tokens is a SUCCESSFUL completion ─────────────
      // The provider did its job and ran out of output budget — it did not fail.
      // Never validate-reject it, never markFailure, never retry another
      // provider: return the partial answer immediately, exactly as generated.
      if (truncated) {
        markSuccess(provider, latency);
        fallbackChain.push({ provider, outcome: 'success', truncated: true, latencyMs: latency });
        ctx.attempts?.push({ provider, outcome: 'success', truncated: true, latencyMs: latency, score });

        console.log(`[ROUTER] ✓ ${provider} (truncated, finishReason=length) latency=${latency}ms score=${score.toFixed(0)} req=${requestId}`);

        return {
          provider, text, taskType, latency, score, confidence, labels, fallbackChain,
          truncated: true, finishReason: 'length',
        };
      }

      // ── Validate (normal, non-truncated completions only) ───────────────────────
      const vr = validateResponse(text, userMessage, taskType);

      if (!vr.valid) {
        console.log(`[VALIDATOR] ${provider} → invalid (${vr.reason}) — trying next`);
        markFailure(provider, vr.reason);
        fallbackChain.push({ provider, outcome: 'invalid', reason: vr.reason, latencyMs: latency });
        ctx.attempts?.push({ provider, outcome: 'invalid', reason: vr.reason, latencyMs: latency, score });
        continue;
      }

      markSuccess(provider, latency);
      fallbackChain.push({ provider, outcome: 'success', latencyMs: latency });
      ctx.attempts?.push({ provider, outcome: 'success', latencyMs: latency, score });

      console.log(`[ROUTER] ✓ ${provider} latency=${latency}ms score=${score.toFixed(0)} req=${requestId}`);

      return {
        provider, text, taskType, latency, score, confidence, labels, fallbackChain,
        truncated: false, finishReason: finishReason ?? 'stop',
      };

    } catch (err) {
      clear();
      finalError = err;
      const reason = err.message === 'TIMEOUT'
        ? `timeout(${timeoutMs}ms)`
        : (err.message ?? 'unknown');

      console.log(`[ROUTER] ✗ ${provider} reason=${reason}`);
      markFailure(provider, reason);
      fallbackChain.push({ provider, outcome: 'failed', reason, latencyMs: null });
      ctx.attempts?.push({ provider, outcome: 'failed', reason, score });
    }
  }

  // Every provider exhausted
  const chain = fallbackChain.map(f => `${f.provider}:${f.outcome}`).join(' → ');
  throw finalError ?? new Error(`All providers exhausted | task=${taskType} | chain=${chain}`);
}

// ── Streaming entry (Day 3 — Real Streaming) ─────────────────────────────────

async function callProviderStream(provider, systemPrompt, messages, signal, maxTokens, onDelta) {
  const start = Date.now();
  let result;
  if      (provider === 'gemini')     result = await streamGemini(systemPrompt, messages, signal, maxTokens, onDelta);
  else if (provider === 'groq')       result = await streamGroq(systemPrompt, messages, signal, maxTokens, onDelta);
  else                                result = await streamOpenRouter(systemPrompt, messages, signal, maxTokens, onDelta);
  return { ...result, latency: Date.now() - start };
}

/**
 * generateTextStream — same ranking / health / fallback semantics as
 * generateText, streamed. Contract:
 *
 *   • Provider fallback happens ONLY before the first token reaches the
 *     client (onEvent 'token'). Once a token is emitted, a mid-stream
 *     failure surfaces as a truncated/interrupted result, never a silent
 *     retry that restarts the answer under the user's cursor.
 *   • Per-provider timeout covers time-to-first-token (router budget from
 *     timeoutManager, unchanged). After the first token, a rolling stall
 *     timer (STALL_MS, reset on every delta) replaces it — long answers
 *     must not be killed by a budget sized for whole request/response
 *     round trips.
 *   • clientSignal (SSE socket closed / Stop pressed) aborts the active
 *     provider immediately and throws CLIENT_ABORTED with whatever partial
 *     text accumulated attached (err.partialText) so the route can persist
 *     what the user actually saw.
 *   • validateResponse is skipped for streamed output — tokens are already
 *     on screen; rejecting a fully-rendered answer and re-running it on a
 *     different provider would be strictly worse UX than keeping it.
 *
 * @param {object}   args                 same fields as generateText, plus:
 * @param {AbortSignal} [args.clientSignal] fired when the HTTP client disconnects
 * @param {(event: object) => void} args.onEvent
 *        { type:'provider_attempt', provider, score, attempt }
 *        { type:'provider_failed',  provider, reason }
 *        { type:'token', text }
 */
export async function generateTextStream({
  userMessage, systemPrompt, messages, ctx = {},
  preTaskType, executionPlan, responseBudget,
  clientSignal, onEvent,
}) {
  const requestId  = ctx.requestId ?? 'unknown';
  const complexity = executionPlan?.complexity;
  const maxTokens  = responseBudget?.maxResponseTokens;
  const STALL_MS   = 45_000; // rolling inter-token stall budget

  let taskType = preTaskType, confidence = 1.0, labels = [preTaskType];
  if (!preTaskType) {
    ({ task: taskType, confidence, labels } = classifyTask(userMessage));
  }

  const ranked = rankProviders(taskType, complexity);
  console.log(`[ROUTER] stream providers=[${ranked.map(r => `${r.provider}(${r.score.toFixed(0)})`).join(', ')}] task=${taskType} complexity=${complexity ?? 'n/a'} req=${requestId}`);

  const promptLength  = systemPrompt.length + messages.reduce((s, m) => s + m.content.length, 0);
  const fallbackChain = [];
  let   finalError;
  let   attempt = 0;

  for (const { provider, score } of ranked) {
    if (clientSignal?.aborted) {
      const err = new Error('CLIENT_ABORTED');
      err.partialText = '';
      throw err;
    }

    attempt += 1;
    const firstTokenBudget = getTimeout(taskType, provider, promptLength, complexity);
    const ctrl = new AbortController();

    // Wire client disconnect straight into the provider call.
    const onClientAbort = () => ctrl.abort();
    clientSignal?.addEventListener('abort', onClientAbort, { once: true });

    let stallTimer  = setTimeout(() => ctrl.abort(), firstTokenBudget); // covers time-to-first-token
    let tokenCount  = 0;
    let partialText = '';

    const onDelta = (delta) => {
      tokenCount += 1;
      partialText += delta;
      // First token swaps the budget model: fixed TTFT budget → rolling stall timer.
      clearTimeout(stallTimer);
      stallTimer = setTimeout(() => ctrl.abort(), STALL_MS);
      onEvent({ type: 'token', text: delta });
    };

    console.log(`[PROVIDER] → ${provider} (stream) score=${score.toFixed(0)} ttft-budget=${firstTokenBudget}ms task=${taskType}`);
    onEvent({ type: 'provider_attempt', provider, score: +score.toFixed(1), attempt });

    try {
      const { text, truncated, finishReason, latency } =
        await callProviderStream(provider, systemPrompt, messages, ctrl.signal, maxTokens, onDelta);
      clearTimeout(stallTimer);
      clientSignal?.removeEventListener('abort', onClientAbort);

      markSuccess(provider, latency);
      const outcome = { provider, outcome: 'success', truncated: !!truncated, latencyMs: latency };
      fallbackChain.push(outcome);
      ctx.attempts?.push({ ...outcome, score });
      console.log(`[ROUTER] ✓ ${provider} (stream${truncated ? `, ${finishReason}` : ''}) latency=${latency}ms tokens=${tokenCount} req=${requestId}`);

      return {
        provider, text, taskType, latency, score, confidence, labels, fallbackChain,
        truncated: !!truncated, finishReason: finishReason ?? 'stop',
      };
    } catch (err) {
      clearTimeout(stallTimer);
      clientSignal?.removeEventListener('abort', onClientAbort);

      // Client walked away (Stop button / closed tab) — not a provider failure.
      if (clientSignal?.aborted) {
        const abortErr = new Error('CLIENT_ABORTED');
        abortErr.partialText = partialText;
        throw abortErr;
      }

      finalError = err;
      const reason = err.message === 'TIMEOUT'
        ? (tokenCount === 0 ? `timeout(${firstTokenBudget}ms ttft)` : `stall(${STALL_MS}ms)`)
        : (err.message ?? 'unknown');

      // Tokens already reached the client — cannot silently retry. Providers
      // return interrupted partials themselves for most mid-stream errors;
      // this covers the stall-abort path.
      if (tokenCount > 0) {
        console.log(`[ROUTER] ⚠ ${provider} stream interrupted after ${tokenCount} tokens (${reason}) — returning partial req=${requestId}`);
        markFailure(provider, reason);
        fallbackChain.push({ provider, outcome: 'interrupted', reason, latencyMs: null });
        ctx.attempts?.push({ provider, outcome: 'interrupted', reason, score });
        return {
          provider, text: partialText, taskType, latency: null, score, confidence, labels, fallbackChain,
          truncated: true, finishReason: 'interrupted',
        };
      }

      console.log(`[ROUTER] ✗ ${provider} (stream, pre-token) reason=${reason}`);
      markFailure(provider, reason);
      fallbackChain.push({ provider, outcome: 'failed', reason, latencyMs: null });
      ctx.attempts?.push({ provider, outcome: 'failed', reason, score });
      onEvent({ type: 'provider_failed', provider, reason });
      // fall through to next ranked provider — client hasn't seen anything yet
    }
  }

  const chain = fallbackChain.map(f => `${f.provider}:${f.outcome}`).join(' → ');
  throw finalError ?? new Error(`All providers exhausted | task=${taskType} | chain=${chain}`);
}

/**
 * AQUA OpenRouter Provider v4
 *
 * Changes from v3 (Issue 4 — the core production bug this version fixes):
 *   Previously, generateOpenRouter() picked ONE model, tried it ONCE, and
 *   on ANY failure — including a 404 on that single model — threw straight
 *   up to router.js. router.js's catch block then called
 *   markFailure('openrouter', ...), decrementing the WHOLE PROVIDER's
 *   health/circuit-breaker state for a problem scoped to one dead model.
 *   Worse, OpenRouter's other 6 registered models never even got a chance
 *   — the very next request would fall back to a completely different
 *   PROVIDER (Gemini/Groq) instead of trying openrouter's next model.
 *
 *   Fixed: this now loops across every currently-available OpenRouter
 *   model (from the central registry, src/providers/modelRegistry.js) for
 *   a single request. A 404/429/5xx on one model marks ONLY that model
 *   and moves to the next candidate — openrouter's provider-level health
 *   is untouched unless every model is exhausted or the failure is
 *   genuinely provider-scoped (bad key / network — see below). Model
 *   selection itself still uses the pre-existing round-robin cursor
 *   (registry's `rotate: true` for this provider) so load keeps spreading
 *   across free-tier per-model rate limits even when everything is healthy.
 *
 * Other changes:
 *   - Model IDs no longer hardcoded here — central registry (Issue 5).
 *     Full list refreshed against OpenRouter's live free catalog
 *     (2026-07-02) — see modelRegistry.js's header for the ones removed.
 *   - Shared error classifier (providerErrors.js, Issue 4) distinguishes
 *     404 / 429 / 401-403 / 5xx / network — auth and network failures are
 *     genuinely provider-scoped (a bad key or dead connection doesn't get
 *     better by trying a different model with the same key), so those
 *     still propagate immediately as real provider failures. Only
 *     model-scoped errors (404/429/5xx) retry within this call.
 *   - TRUNCATED_MAX_TOKENS is no longer thrown (Issue 1) — hitting the
 *     output cap returns { text, truncated: true, finishReason: 'length' }
 *     as a successful completion.
 */

import OpenAI from 'openai';
import {
  getCandidateModels, markModelRateLimited, markModelTempFailed, markModelUnavailable,
} from './modelRegistry.js';
import { classifyProviderError } from './providerErrors.js';

// ── Key rotation ───────────────────────────────────────────────────────────────

function getKeys() {
  return [
    process.env.OPENROUTER_API_KEY_1,
    process.env.OPENROUTER_API_KEY_2,
    process.env.OPENROUTER_API_KEY_3,
    process.env.OPENROUTER_API_KEY_4,
  ].filter(Boolean);
}

/** Startup validation (Issue 6) — does this provider have any usable key at all? */
export function hasConfiguredKeys() {
  return getKeys().length > 0;
}

let keyIndex = 0;

function nextKey() {
  const keys = getKeys();
  if (!keys.length) throw new Error('No OpenRouter keys configured');
  const key = keys[keyIndex];
  keyIndex  = (keyIndex + 1) % keys.length;
  return key;
}

const clientCache = new Map();

function getClient(key) {
  if (!clientCache.has(key)) {
    clientCache.set(key, new OpenAI({
      apiKey:  key,
      // Overridable for corporate proxies / gateways / integration tests.
      baseURL: process.env.OPENROUTER_BASE_URL || 'https://openrouter.ai/api/v1',
    }));
  }
  return clientCache.get(key);
}

// ── Generate ───────────────────────────────────────────────────────────────────

/**
 * @param {string} systemPrompt
 * @param {Array<{role,content}>} messages
 * @param {AbortSignal} [signal]
 * @param {number} [maxTokens] - Phase 6 Response Budgeting: caps output length.
 *   Clamped per-model against the registry's maxOutputTokens.
 * @returns {Promise<{ text: string, truncated: boolean, finishReason: string }>}
 */
export async function generateOpenRouter(systemPrompt, messages, signal, maxTokens) {
  if (signal?.aborted) throw new Error('TIMEOUT');

  const candidates = getCandidateModels('openrouter');
  if (!candidates.length) throw new Error('All OpenRouter models permanently unavailable');

  const key    = nextKey();
  const client = getClient(key);

  const chatMessages = [
    ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
    ...messages.map(m => ({ role: m.role, content: m.content })),
  ];

  let lastError;
  // Bounded so a fully-degraded registry can't turn into an unbounded loop
  // — never more attempts than models actually available this call.
  const attemptLimit = Math.min(candidates.length, 5);

  for (let i = 0; i < attemptLimit; i++) {
    const modelId   = candidates[i].modelId;
    const capTokens = maxTokens ? Math.min(maxTokens, candidates[i].maxOutputTokens) : maxTokens;

    if (signal?.aborted) throw new Error('TIMEOUT');

    console.log(`[OPENROUTER] model=${modelId} key=...${key.slice(-4)} (${i + 1}/${attemptLimit})`);

    const req = client.chat.completions.create({
      model:    modelId,
      messages: chatMessages,
      ...(capTokens ? { max_tokens: capTokens } : {}),
    });
    // Demo-stability fix: a lost Promise.race leaves `req` running detached;
    // a late rejection would be an unhandled rejection — fatal on modern
    // Node — and would crash the server mid-request. No-op handler marks it
    // handled; race path unaffected. (Same fix in groq.js / gemini.js.)
    Promise.resolve(req).catch(() => {});

    let result;
    try {
      result = signal
        ? await Promise.race([
            req,
            new Promise((_, rej) => {
              if (signal.aborted) return rej(new Error('TIMEOUT'));
              signal.addEventListener('abort', () => rej(new Error('TIMEOUT')), { once: true });
            }),
          ])
        : await req;
    } catch (err) {
      if (err.message === 'TIMEOUT') throw err; // router's budget spent — propagate immediately

      lastError = err;
      const { type, status } = classifyProviderError(err);

      // ── Model-scoped failures (Issue 4): only disable THIS model, try the next one ──
      if (type === 'model_not_found') {
        markModelUnavailable('openrouter', modelId, `${status ?? ''} ${err.message}`.trim());
        continue;
      }
      if (type === 'rate_limit') {
        markModelRateLimited('openrouter', modelId, 120_000);
        continue;
      }
      if (type === 'server_error') {
        markModelTempFailed('openrouter', modelId, 45_000);
        continue;
      }

      // ── Provider/key-scoped failures: trying a different model with the
      // same bad key/connection won't help — this genuinely IS a provider
      // failure, so propagate immediately (router.js correctly marks
      // openrouter's health for these, per Issue 4's differentiation).
      console.log(`[OPENROUTER] key=...${key.slice(-4)} model=${modelId} error type=${type} status=${status} msg=${err.message}`);
      throw err;
    }

    const finishReason = result?.choices?.[0]?.finish_reason;
    const text = result?.choices?.[0]?.message?.content;

    // ── Issue 1: hitting the output-token cap is SUCCESS, not failure ──
    if (capTokens && finishReason === 'length') {
      if (!text || !text.trim()) {
        lastError = new Error(`OpenRouter: model ${modelId} returned empty truncated response`);
        continue;
      }
      console.log(`[OPENROUTER] model=${modelId} hit maxTokens=${capTokens} cap — returning partial as successful completion`);
      return { text, truncated: true, finishReason: 'length' };
    }

    if (!text) {
      lastError = new Error(`OpenRouter: model ${modelId} returned empty response`);
      continue;
    }

    return { text, truncated: false, finishReason: finishReason ?? 'stop' };
  }

  throw lastError ?? new Error('All OpenRouter models exhausted for this request');
}

/**
 * Streaming variant (Day 3 — Real Streaming).
 *
 * Same registry-driven model fallback and error scoping as
 * generateOpenRouter, with the streaming rule: model fallback only BEFORE
 * the first emitted delta; mid-stream failures return the partial as
 * finishReason='interrupted'.
 *
 * @param {(delta: string) => void} onDelta
 * @returns {Promise<{ text:string, truncated:boolean, finishReason:string, streamed:true }>}
 */
export async function streamOpenRouter(systemPrompt, messages, signal, maxTokens, onDelta) {
  if (signal?.aborted) throw new Error('TIMEOUT');

  const candidates = getCandidateModels('openrouter');
  if (!candidates.length) throw new Error('All OpenRouter models permanently unavailable');

  const key    = nextKey();
  const client = getClient(key);

  const chatMessages = [
    ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
    ...messages.map(m => ({ role: m.role, content: m.content })),
  ];

  let lastError;
  const attemptLimit = Math.min(candidates.length, 5);

  for (let i = 0; i < attemptLimit; i++) {
    const modelId   = candidates[i].modelId;
    const capTokens = maxTokens ? Math.min(maxTokens, candidates[i].maxOutputTokens) : maxTokens;

    if (signal?.aborted) throw new Error('TIMEOUT');
    console.log(`[OPENROUTER] stream model=${modelId} key=...${key.slice(-4)} (${i + 1}/${attemptLimit})`);

    let stream;
    try {
      stream = await client.chat.completions.create(
        {
          model:    modelId,
          messages: chatMessages,
          stream:   true,
          ...(capTokens ? { max_tokens: capTokens } : {}),
        },
        { signal },
      );
    } catch (err) {
      if (signal?.aborted || err.name === 'AbortError') throw new Error('TIMEOUT');
      lastError = err;
      const { type, status } = classifyProviderError(err);
      if (type === 'model_not_found') { markModelUnavailable('openrouter', modelId, `${status ?? ''} ${err.message}`.trim()); continue; }
      if (type === 'rate_limit')      { markModelRateLimited('openrouter', modelId, 120_000); continue; }
      if (type === 'server_error')    { markModelTempFailed('openrouter', modelId, 45_000);   continue; }
      // Provider/key-scoped failure — a different model won't help.
      throw err;
    }

    let text = '';
    let finishReason = null;
    try {
      for await (const chunk of stream) {
        if (signal?.aborted) throw new Error('TIMEOUT');
        const delta = chunk?.choices?.[0]?.delta?.content;
        finishReason = chunk?.choices?.[0]?.finish_reason ?? finishReason;
        if (delta) { text += delta; onDelta(delta); }
      }
    } catch (err) {
      if (text) {
        console.log(`[OPENROUTER] stream interrupted after ${text.length} chars model=${modelId}: ${err.message}`);
        return { text, truncated: true, finishReason: 'interrupted', streamed: true };
      }
      if (signal?.aborted || err.name === 'AbortError' || err.message === 'TIMEOUT') throw new Error('TIMEOUT');
      lastError = err;
      continue;
    }

    if (!text.trim()) { lastError = new Error(`OpenRouter: model ${modelId} stream returned empty response`); continue; }

    const truncated = capTokens && finishReason === 'length';
    return { text, truncated: !!truncated, finishReason: truncated ? 'length' : (finishReason ?? 'stop'), streamed: true };
  }

  throw lastError ?? new Error('All OpenRouter stream attempts exhausted');
}

import { test, describe } from 'node:test';
import assert from 'node:assert/strict';
import {
  getCandidateModels, pickModel, getModelSpec,
  markModelUnavailable, markModelRateLimited, markModelTempFailed, markModelWorking,
  validateEntry, validateRegistryOnStartup, getRegistrySnapshot,
  __resetForTests,
} from '../modelRegistry.js';

describe('modelRegistry.js — candidate selection', () => {
  test('every provider has at least one candidate model by default', () => {
    __resetForTests();
    for (const p of ['gemini', 'groq', 'openrouter']) {
      assert.ok(getCandidateModels(p).length > 0, `${p} should have candidates`);
    }
  });

  test('gemini/groq (rotate:false) always prefer the first entry in listed order', () => {
    __resetForTests();
    const first = pickModel('gemini').modelId;
    // Calling repeatedly should not rotate a non-rotating provider.
    assert.equal(pickModel('gemini').modelId, first);
    assert.equal(pickModel('gemini').modelId, first);
  });

  test('unknown provider returns an empty candidate list, not a throw', () => {
    __resetForTests();
    assert.deepEqual(getCandidateModels('not_a_provider'), []);
    assert.equal(pickModel('not_a_provider'), null);
  });

  test('getModelSpec returns the full entry for clamping maxTokens', () => {
    __resetForTests();
    const spec = getModelSpec('groq', 'openai/gpt-oss-120b');
    assert.ok(spec);
    assert.equal(spec.provider, 'groq');
    assert.ok(spec.maxOutputTokens > 0);
  });
});

describe('modelRegistry.js — Issue 4: model-scoped failures never touch siblings', () => {
  test('marking one OpenRouter model deprecated removes ONLY that model from candidates', () => {
    __resetForTests();
    const before = getCandidateModels('openrouter').map(m => m.modelId);
    const target = before[0];

    markModelUnavailable('openrouter', target, 'test 404');

    const after = getCandidateModels('openrouter').map(m => m.modelId);
    assert.ok(!after.includes(target), 'deprecated model should be excluded');
    for (const id of before) {
      if (id !== target) assert.ok(after.includes(id), `sibling model ${id} should remain available`);
    }
    assert.equal(after.length, before.length - 1);
  });

  test('marking a model unavailable never disables a different provider\u2019s models', () => {
    __resetForTests();
    const geminiBefore = getCandidateModels('gemini').length;
    markModelUnavailable('openrouter', getCandidateModels('openrouter')[0].modelId, 'test 404');
    assert.equal(getCandidateModels('gemini').length, geminiBefore);
  });

  test('deprecation is permanent — does not self-heal over time', (t) => {
    __resetForTests();
    t.mock.timers.enable({ apis: ['Date'] });
    const target = getCandidateModels('groq')[0].modelId;
    markModelUnavailable('groq', target, 'test 404');
    t.mock.timers.tick(365 * 24 * 60 * 60 * 1000); // one year later
    assert.ok(!getCandidateModels('groq').map(m => m.modelId).includes(target));
  });

  test('rate-limited model self-heals after its cooldown expires', (t) => {
    __resetForTests();
    t.mock.timers.enable({ apis: ['Date'] });
    const target = getCandidateModels('openrouter')[0].modelId;

    markModelRateLimited('openrouter', target, 120_000);
    assert.ok(!getCandidateModels('openrouter').map(m => m.modelId).includes(target));

    t.mock.timers.tick(121_000);
    assert.ok(getCandidateModels('openrouter').map(m => m.modelId).includes(target), 'should self-heal after cooldown');
  });

  test('temp-failed model self-heals after its cooldown expires', (t) => {
    __resetForTests();
    t.mock.timers.enable({ apis: ['Date'] });
    const target = getCandidateModels('openrouter')[1].modelId;

    markModelTempFailed('openrouter', target, 45_000);
    assert.ok(!getCandidateModels('openrouter').map(m => m.modelId).includes(target));

    t.mock.timers.tick(46_000);
    assert.ok(getCandidateModels('openrouter').map(m => m.modelId).includes(target));
  });

  test('markModelWorking clears a rate-limited/temp-failed state immediately', () => {
    __resetForTests();
    const target = getCandidateModels('openrouter')[0].modelId;
    markModelRateLimited('openrouter', target, 999_999);
    assert.ok(!getCandidateModels('openrouter').map(m => m.modelId).includes(target));
    markModelWorking('openrouter', target);
    assert.ok(getCandidateModels('openrouter').map(m => m.modelId).includes(target));
  });

  test('a deprecated model cannot be revived by markModelTempFailed/markModelRateLimited (deprecation wins)', () => {
    __resetForTests();
    const target = getCandidateModels('groq')[0].modelId;
    markModelUnavailable('groq', target, 'test 404');
    markModelTempFailed('groq', target, 1); // should be a no-op against a deprecated entry
    assert.ok(!getCandidateModels('groq').map(m => m.modelId).includes(target));
  });

  test('exhausting every OpenRouter model leaves an empty candidate list, not a throw', () => {
    __resetForTests();
    for (const m of getCandidateModels('openrouter')) {
      markModelUnavailable('openrouter', m.modelId, 'test 404');
    }
    assert.deepEqual(getCandidateModels('openrouter'), []);
    assert.equal(pickModel('openrouter'), null);
  });
});

describe('modelRegistry.js — OpenRouter rotation', () => {
  test('rotate:true providers cycle through candidates rather than always returning the same one', () => {
    __resetForTests();
    const seen = new Set();
    for (let i = 0; i < 10; i++) {
      seen.add(getCandidateModels('openrouter')[0].modelId);
    }
    assert.ok(seen.size > 1, 'rotation should surface more than one model as the top pick across calls');
  });
});

describe('modelRegistry.js — Issue 6: startup validation', () => {
  test('validateEntry accepts a well-formed entry', () => {
    const problems = validateEntry({
      provider: 'groq', modelId: 'x', maxOutputTokens: 4096, contextWindow: 8192, capabilities: ['chat'],
    }, 'groq');
    assert.deepEqual(problems, []);
  });

  test('validateEntry flags a missing modelId without throwing', () => {
    const problems = validateEntry({
      provider: 'groq', modelId: '', maxOutputTokens: 4096, contextWindow: 8192, capabilities: ['chat'],
    }, 'groq');
    assert.ok(problems.length > 0);
  });

  test('validateEntry flags invalid maxOutputTokens/contextWindow', () => {
    const problems = validateEntry({
      provider: 'groq', modelId: 'x', maxOutputTokens: -1, contextWindow: 0, capabilities: ['chat'],
    }, 'groq');
    assert.ok(problems.some(p => p.includes('maxOutputTokens')));
    assert.ok(problems.some(p => p.includes('contextWindow')));
  });

  test('validateEntry flags a provider mismatch', () => {
    const problems = validateEntry({
      provider: 'gemini', modelId: 'x', maxOutputTokens: 4096, contextWindow: 8192, capabilities: ['chat'],
    }, 'groq');
    assert.ok(problems.some(p => p.includes('provider mismatch')));
  });

  test('validateEntry never throws on garbage input', () => {
    assert.doesNotThrow(() => validateEntry(null, 'groq'));
    assert.doesNotThrow(() => validateEntry(undefined, 'groq'));
    assert.doesNotThrow(() => validateEntry({}, 'groq'));
  });

  test('validateRegistryOnStartup never throws and reports the real registry as fully valid', () => {
    __resetForTests();
    const result = validateRegistryOnStartup();
    assert.equal(typeof result.validCount, 'number');
    assert.equal(typeof result.disabledCount, 'number');
    assert.equal(result.disabledCount, 0, 'the real registry should have no malformed entries');
    assert.ok(result.validCount > 0);
  });

  test('validateRegistryOnStartup is idempotent (safe to call multiple times)', () => {
    __resetForTests();
    const r1 = validateRegistryOnStartup();
    const r2 = validateRegistryOnStartup();
    assert.deepEqual(r1, r2);
  });
});

describe('modelRegistry.js — introspection', () => {
  test('getRegistrySnapshot returns every provider with an array of model summaries', () => {
    __resetForTests();
    const snap = getRegistrySnapshot();
    for (const p of ['gemini', 'groq', 'openrouter']) {
      assert.ok(Array.isArray(snap[p]));
      assert.ok(snap[p].length > 0);
      assert.ok('modelId' in snap[p][0]);
      assert.ok('status' in snap[p][0]);
    }
  });

  test('snapshot reflects a deprecated model\u2019s status without needing to be re-fetched from candidates', () => {
    __resetForTests();
    const target = getCandidateModels('groq')[0].modelId;
    markModelUnavailable('groq', target, 'test 404');
    const snap = getRegistrySnapshot();
    const entry = snap.groq.find(m => m.modelId === target);
    assert.equal(entry.status, 'deprecated');
  });
});

import { test, describe } from 'node:test';
import assert from 'node:assert/strict';
import { classifyProviderError, extractStatus } from '../providerErrors.js';

function errWith(overrides) {
  return Object.assign(new Error(overrides.message ?? 'boom'), overrides);
}

describe('providerErrors.js — Issue 4: differentiate failure types', () => {
  test('404 status → model_not_found', () => {
    assert.equal(classifyProviderError(errWith({ status: 404 })).type, 'model_not_found');
  });

  test('"model not found" message with no status → model_not_found', () => {
    assert.equal(classifyProviderError(errWith({ message: 'Error: model not found' })).type, 'model_not_found');
  });

  test('"no endpoints" / "deprecated" hints → model_not_found', () => {
    assert.equal(classifyProviderError(errWith({ message: 'No endpoints found for this model' })).type, 'model_not_found');
    assert.equal(classifyProviderError(errWith({ message: 'This model has been deprecated' })).type, 'model_not_found');
  });

  test('429 status → rate_limit', () => {
    assert.equal(classifyProviderError(errWith({ status: 429 })).type, 'rate_limit');
  });

  test('401/403 status → auth', () => {
    assert.equal(classifyProviderError(errWith({ status: 401 })).type, 'auth');
    assert.equal(classifyProviderError(errWith({ status: 403 })).type, 'auth');
  });

  test('5xx status → server_error', () => {
    assert.equal(classifyProviderError(errWith({ status: 500 })).type, 'server_error');
    assert.equal(classifyProviderError(errWith({ status: 503 })).type, 'server_error');
  });

  test('known network error codes → network', () => {
    assert.equal(classifyProviderError(errWith({ code: 'ECONNREFUSED' })).type, 'network');
    assert.equal(classifyProviderError(errWith({ code: 'ETIMEDOUT' })).type, 'network');
    assert.equal(classifyProviderError(errWith({ code: 'ENOTFOUND' })).type, 'network');
  });

  test('"fetch failed" with no status → network', () => {
    assert.equal(classifyProviderError(errWith({ message: 'fetch failed' })).type, 'network');
  });

  test('router\u2019s own TIMEOUT sentinel → timeout, distinct from network', () => {
    assert.equal(classifyProviderError(errWith({ message: 'TIMEOUT' })).type, 'timeout');
  });

  test('INVALID_RESPONSE sentinel → invalid_response', () => {
    assert.equal(classifyProviderError(errWith({ message: 'INVALID_RESPONSE' })).type, 'invalid_response');
  });

  test('unrecognized error → unknown, never throws', () => {
    assert.equal(classifyProviderError(errWith({ message: 'something weird happened' })).type, 'unknown');
    assert.doesNotThrow(() => classifyProviderError(null));
    assert.doesNotThrow(() => classifyProviderError(undefined));
    assert.equal(classifyProviderError(null).type, 'unknown');
  });

  test('status is read from status, statusCode, response.status, or httpError.status', () => {
    assert.equal(extractStatus({ status: 404 }), 404);
    assert.equal(extractStatus({ statusCode: 429 }), 429);
    assert.equal(extractStatus({ response: { status: 500 } }), 500);
    assert.equal(extractStatus({ httpError: { status: 401 } }), 401);
    assert.equal(extractStatus({}), null);
  });

  test('404 status takes priority even if the message also contains rate-limit-like text', () => {
    // Guards against message-sniffing accidentally overriding an explicit status.
    const { type } = classifyProviderError(errWith({ status: 404, message: 'rate limited, please retry' }));
    assert.equal(type, 'model_not_found');
  });
});

/**
 * AQUA Provider Errors — Shared Error Classification
 *
 * Root problem (Issue 4/12): each provider file categorized failures with
 * its own ad-hoc if/else chain, and OpenRouter's single-model 404s were
 * propagated as if the whole provider had failed — incorrectly dragging
 * openrouter's provider-level health/circuit breaker down for a problem
 * scoped to one model. This module is the single source of truth for
 * "what kind of failure was this", shared by gemini.js / groq.js /
 * openrouter.js so a dead model is never confused with a dead provider.
 *
 * Categories (Issue 4's explicit list):
 *   model_not_found  — 404 / "model not found" / "no endpoints" / "deprecated"
 *   rate_limit       — 429
 *   auth             — 401 / 403
 *   server_error     — 5xx
 *   network          — no HTTP status at all (DNS/connect/abort/fetch failure)
 *   timeout          — our own AbortController fired (router's timeout budget)
 *   invalid_response — not a transport error; caller got a response with no
 *                      usable content (empty body) — same call site that used
 *                      to throw "X returned empty response"
 *   unknown          — anything else; still a genuine failure, just uncategorized
 *
 * Only `timeout`, `network`, `auth`, `server_error`, `rate_limit`,
 * `invalid_response`, and `unknown` are genuine failures per Issue 1's list.
 * `model_not_found` is ALSO a genuine failure — just one that must stay
 * scoped to the specific model, never the provider (see Issue 4 §"Only
 * disable the specific model").
 */

const NOT_FOUND_HINTS = [
  'not found', 'no endpoints', 'model not available', 'no allowed providers',
  'is not a valid model', 'does not exist',
];

const DEPRECATED_HINTS = ['deprecated', 'decommissioned', 'has been retired', 'no longer available'];

const NETWORK_ERROR_CODES = new Set([
  'ECONNREFUSED', 'ENOTFOUND', 'ECONNRESET', 'ETIMEDOUT', 'EAI_AGAIN',
  'ECONNABORTED', 'EPIPE', 'EHOSTUNREACH',
]);

/** Extract an HTTP status code from whatever shape the SDK wrapped it in. */
export function extractStatus(err) {
  return (
    err?.status ??
    err?.statusCode ??
    err?.httpError?.status ??
    err?.response?.status ??
    null
  );
}

/**
 * @param {Error} err
 * @returns {{ type: 'model_not_found'|'rate_limit'|'auth'|'server_error'|
 *             'network'|'timeout'|'invalid_response'|'unknown', status: number|null }}
 */
export function classifyProviderError(err) {
  if (!err) return { type: 'unknown', status: null };
  if (err.message === 'TIMEOUT') return { type: 'timeout', status: null };
  if (err.message === 'INVALID_RESPONSE') return { type: 'invalid_response', status: null };

  const status = extractStatus(err);
  const msg    = String(err.message ?? '').toLowerCase();
  const code   = err.code ?? err.cause?.code;

  if (status === 404 || NOT_FOUND_HINTS.some(h => msg.includes(h)) || DEPRECATED_HINTS.some(h => msg.includes(h))) {
    return { type: 'model_not_found', status: status ?? 404 };
  }
  if (status === 429) return { type: 'rate_limit', status };
  if (status === 401 || status === 403) return { type: 'auth', status };
  if (status != null && status >= 500) return { type: 'server_error', status };
  if (code && NETWORK_ERROR_CODES.has(code)) return { type: 'network', status: null };
  if (status == null && (msg.includes('fetch failed') || msg.includes('network') || err.name === 'FetchError')) {
    return { type: 'network', status: null };
  }
  return { type: 'unknown', status };
}

/** Human-readable one-liner for logs — keeps log format consistent across providers. */
export function describeError(classification, context = '') {
  const { type, status } = classification;
  const statusPart = status ? ` status=${status}` : '';
  return `${type}${statusPart}${context ? ` (${context})` : ''}`;
}

/**
 * AQUA Model Registry (Issue 5)
 *
 * Single source of truth for every model ID AQUA can call, across all three
 * providers. Before this module, model IDs were hardcoded inline in
 * gemini.js/groq.js (one literal string each) and duplicated as a bare
 * array in openrouter.js — three different places to update, three
 * different ad-hoc "is this model still alive" mechanisms.
 *
 * This registry:
 *   1. Defines every model's identity + capabilities in one place (schema
 *      below matches Issue 5's spec exactly).
 *   2. Owns per-model AVAILABILITY state (Issue 4): working / rate_limited /
 *      temp_failed / deprecated, each with its own cooldown — so a single
 *      dead OpenRouter model never has to be conflated with "OpenRouter is
 *      down" ever again. Provider-level health (src/core/health.js) stays
 *      completely separate and is never touched by a model-level event.
 *   3. Provides startup validation (Issue 6): malformed entries are
 *      disabled + logged, never thrown — one bad entry can't break a
 *      provider or block boot.
 *
 * Model list last verified 2026-07-02. OpenRouter's free catalog in
 * particular churns fast (providers rotate free slots weekly) — that's
 * exactly why every model here is behind the same self-healing 404
 * handling instead of being trusted to stay valid forever. Re-verify
 * against https://openrouter.ai/models?order=newest and
 * https://console.groq.com/docs/models periodically.
 */

// ── Registry schema ──────────────────────────────────────────────────────────
// provider, modelId, capabilities, contextWindow, maxOutputTokens,
// supportsStreaming, supportsVision, supportsTools, supportsJSON,
// supportsReasoning, costTier, enabled, health — per Issue 5.

function model(overrides) {
  return {
    provider:           overrides.provider,
    modelId:            overrides.modelId,
    capabilities:       overrides.capabilities ?? ['chat'],
    contextWindow:      overrides.contextWindow ?? 32_000,
    maxOutputTokens:    overrides.maxOutputTokens ?? 4_096,
    supportsStreaming:  overrides.supportsStreaming ?? true,
    supportsVision:     overrides.supportsVision ?? false,
    supportsTools:      overrides.supportsTools ?? false,
    supportsJSON:       overrides.supportsJSON ?? true,
    supportsReasoning:  overrides.supportsReasoning ?? false,
    costTier:           overrides.costTier ?? 'free',
    enabled:            overrides.enabled ?? true,
    note:               overrides.note,
    // Mutable at runtime by markModel*() below — never touched by hand.
    health: { status: 'working', until: 0, lastError: null },
  };
}

// Rotate = true → pickModel() cycles through candidates round-robin even
// when all are healthy (spreads load across free-tier rate limits — this
// is openrouter.js's pre-existing modelCursor behavior, preserved as-is).
// Rotate = false → pickModel() always prefers the first available entry,
// falling through in listed order (primary → fallback → fallback...),
// which is the right behavior for gemini/groq's small curated lists.
const PROVIDER_LISTS = {
  gemini: {
    rotate: false,
    models: [
      model({
        provider: 'gemini', modelId: 'gemini-2.5-flash',
        capabilities: ['chat', 'reasoning', 'vision', 'tools'],
        contextWindow: 1_048_576, maxOutputTokens: 65_536,
        supportsVision: true, supportsTools: true, supportsReasoning: true,
        costTier: 'free',
        note: 'Primary. GA, confirmed current as of 2026-06-30. Google\'s stated shutdown horizon is 2026-10-16 — gemini-3.5-flash is registered below as the pre-vetted fallback for when it starts 404ing.',
      }),
      model({
        provider: 'gemini', modelId: 'gemini-3.5-flash',
        capabilities: ['chat', 'reasoning', 'vision', 'tools'],
        contextWindow: 1_048_576, maxOutputTokens: 65_536,
        supportsVision: true, supportsTools: true, supportsReasoning: true,
        costTier: 'free',
        note: 'Fallback. GA since 2026-05-19, no announced shutdown date at time of writing.',
      }),
    ],
  },
  groq: {
    rotate: false,
    models: [
      model({
        provider: 'groq', modelId: 'openai/gpt-oss-120b',
        capabilities: ['chat', 'reasoning', 'tools'],
        contextWindow: 131_072, maxOutputTokens: 65_536,
        supportsTools: true, supportsReasoning: true,
        costTier: 'free',
        note: 'Primary. Groq\'s own recommended replacement for llama-3.3-70b-versatile (deprecation announced 2026-06-17) — also faster (500 t/s vs 280 t/s) and cheaper.',
      }),
      model({
        provider: 'groq', modelId: 'openai/gpt-oss-20b',
        capabilities: ['chat', 'reasoning', 'tools'],
        contextWindow: 131_072, maxOutputTokens: 65_536,
        supportsTools: true, supportsReasoning: true,
        costTier: 'free',
        note: 'Fallback — smaller/faster (~1000 t/s) sibling of the primary.',
      }),
      model({
        provider: 'groq', modelId: 'llama-3.3-70b-versatile',
        capabilities: ['chat', 'tools'],
        contextWindow: 131_072, maxOutputTokens: 32_768,
        supportsTools: true,
        costTier: 'free',
        note: 'Tertiary safety net only. Groq announced deprecation 2026-06-17; still live at time of writing but do not promote back to primary.',
      }),
    ],
  },
  openrouter: {
    rotate: true, // preserves the pre-existing modelCursor load-spreading behavior
    models: [
      model({
        provider: 'openrouter', modelId: 'openai/gpt-oss-120b:free',
        capabilities: ['chat', 'reasoning', 'tools'], contextWindow: 131_072,
        maxOutputTokens: 8_192, supportsTools: true, supportsReasoning: true,
      }),
      model({
        provider: 'openrouter', modelId: 'z-ai/glm-4.5-air:free',
        capabilities: ['chat', 'reasoning', 'tools'], contextWindow: 131_072,
        maxOutputTokens: 8_192, supportsTools: true, supportsReasoning: true,
      }),
      model({
        provider: 'openrouter', modelId: 'nvidia/nemotron-3-super-120b-a12b:free',
        capabilities: ['chat', 'reasoning'], contextWindow: 1_000_000,
        maxOutputTokens: 8_192, supportsReasoning: true,
      }),
      model({
        provider: 'openrouter', modelId: 'google/gemma-4-31b-it:free',
        capabilities: ['chat'], contextWindow: 262_144, maxOutputTokens: 8_192,
      }),
      model({
        provider: 'openrouter', modelId: 'openai/gpt-oss-20b:free',
        capabilities: ['chat', 'reasoning', 'tools'], contextWindow: 131_072,
        maxOutputTokens: 8_192, supportsTools: true, supportsReasoning: true,
      }),
      model({
        provider: 'openrouter', modelId: 'moonshotai/kimi-k2.6:free',
        capabilities: ['chat', 'reasoning'], contextWindow: 262_144,
        maxOutputTokens: 8_192, supportsReasoning: true,
      }),
      model({
        provider: 'openrouter', modelId: 'nvidia/nemotron-nano-9b-v2:free',
        capabilities: ['chat'], contextWindow: 131_072, maxOutputTokens: 8_192,
      }),
    ],
  },
};

let openrouterCursor = 0;

// ── Availability ──────────────────────────────────────────────────────────────

function isAvailable(entry) {
  if (!entry.enabled) return false;
  const h = entry.health;
  if (h.status === 'deprecated') return false;
  if ((h.status === 'rate_limited' || h.status === 'temp_failed') && h.until) {
    if (Date.now() < h.until) return false;
    h.status = 'working'; // cooldown expired — self-heal
    h.until  = 0;
  }
  return true;
}

function findEntry(provider, modelId) {
  return PROVIDER_LISTS[provider]?.models.find(m => m.modelId === modelId) ?? null;
}

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * @param {string} provider
 * @returns {object|null} the best available model entry for this provider,
 *   or null if every model is currently unavailable (caller should treat
 *   that as a provider-level failure — every candidate has been exhausted).
 */
export function pickModel(provider) {
  const list = getCandidateModels(provider);
  return list[0] ?? null;
}

/**
 * @param {string} provider
 * @returns {object[]} every currently-available model for this provider,
 *   in the order they should be tried this call. Lets gemini.js/groq.js/
 *   openrouter.js retry the NEXT model within the same request instead of
 *   propagating a single dead model straight up to the provider-level
 *   router (see Issue 4 — "the router gracefully degrades when individual
 *   models disappear").
 */
export function getCandidateModels(provider) {
  const cfg = PROVIDER_LISTS[provider];
  if (!cfg) return [];

  const available = cfg.models.filter(isAvailable);
  if (!available.length) return [];

  if (!cfg.rotate) return available; // preference order, as listed

  // Rotate: start from the cursor position among AVAILABLE entries so a
  // deprecated/cooling model never "eats" a rotation slot.
  const startIdx = openrouterCursor % available.length;
  openrouterCursor = (openrouterCursor + 1) % Math.max(cfg.models.length, 1);
  return [...available.slice(startIdx), ...available.slice(0, startIdx)];
}

/** @returns {object|null} full registry entry, e.g. to clamp maxTokens against maxOutputTokens. */
export function getModelSpec(provider, modelId) {
  return findEntry(provider, modelId);
}

/** Permanent — 404 / model-not-found. Never retried again this process. */
export function markModelUnavailable(provider, modelId, reason = 'not_found') {
  const entry = findEntry(provider, modelId);
  if (!entry) return;
  entry.health = { status: 'deprecated', until: 0, lastError: reason };
  console.warn(`[MODEL_REGISTRY] ${provider}/${modelId} → DEPRECATED (${reason}) — permanently skipped, provider health unaffected`);
}

/** Temporary — 429. */
export function markModelRateLimited(provider, modelId, ms = 120_000) {
  const entry = findEntry(provider, modelId);
  if (!entry) return;
  entry.health = { status: 'rate_limited', until: Date.now() + ms, lastError: 'rate_limited' };
  console.log(`[MODEL_REGISTRY] ${provider}/${modelId} → rate limited (${(ms / 1000).toFixed(0)}s)`);
}

/** Temporary — 5xx / transient. */
export function markModelTempFailed(provider, modelId, ms = 45_000) {
  const entry = findEntry(provider, modelId);
  if (!entry || entry.health.status === 'deprecated') return;
  entry.health = { status: 'temp_failed', until: Date.now() + ms, lastError: 'temp_failed' };
  console.log(`[MODEL_REGISTRY] ${provider}/${modelId} → temp failed (${(ms / 1000).toFixed(0)}s)`);
}

/** Clears a model back to working — used on a successful call. */
export function markModelWorking(provider, modelId) {
  const entry = findEntry(provider, modelId);
  if (!entry) return;
  if (entry.health.status !== 'working') {
    entry.health = { status: 'working', until: 0, lastError: null };
  }
}

// ── Startup validation (Issue 6) ─────────────────────────────────────────────

/**
 * Pure validation for a single registry entry — no side effects, safe to
 * call with synthetic data in tests. Exported separately from
 * validateRegistryOnStartup() (which runs this against the real registry
 * and mutates `enabled`) so the validation RULES themselves are directly
 * testable without needing to mutate the module-level singleton.
 *
 * @returns {string[]} list of problems; empty array means the entry is valid.
 */
export function validateEntry(entry, expectedProvider) {
  const problems = [];
  if (!entry || typeof entry !== 'object') return ['entry is not an object'];
  if (!entry.modelId || typeof entry.modelId !== 'string') problems.push('missing/invalid modelId');
  if (entry.provider !== expectedProvider) problems.push(`provider mismatch (entry says ${entry.provider})`);
  if (!Number.isFinite(entry.maxOutputTokens) || entry.maxOutputTokens <= 0) problems.push('invalid maxOutputTokens');
  if (!Number.isFinite(entry.contextWindow) || entry.contextWindow <= 0) problems.push('invalid contextWindow');
  if (!Array.isArray(entry.capabilities) || !entry.capabilities.length) problems.push('missing capabilities');
  return problems;
}

/**
 * Validates every registered model entry. Disables (enabled=false) any
 * entry that's malformed instead of throwing — one bad entry must never
 * break a provider or block server boot. Safe to call multiple times.
 *
 * @returns {{ validCount: number, disabledCount: number, issues: string[] }}
 */
export function validateRegistryOnStartup() {
  const issues = [];
  let validCount = 0, disabledCount = 0;

  for (const [provider, cfg] of Object.entries(PROVIDER_LISTS)) {
    for (const entry of cfg.models) {
      const problems = validateEntry(entry, provider);

      if (problems.length) {
        entry.enabled = false;
        disabledCount++;
        const msg = `${provider}/${entry.modelId ?? '(unknown)'}: ${problems.join(', ')}`;
        issues.push(msg);
        console.warn(`[STARTUP] ⚠ Model registry entry disabled — ${msg}`);
      } else {
        validCount++;
      }
    }

    if (!cfg.models.some(m => m.enabled)) {
      console.warn(`[STARTUP] ⚠ Provider "${provider}" has ZERO valid enabled models after validation.`);
    }
  }

  console.log(`[STARTUP] Model registry validated: ${validCount} valid, ${disabledCount} disabled.`);
  return { validCount, disabledCount, issues };
}

// ── Introspection (health endpoint) ──────────────────────────────────────────

export function getRegistrySnapshot() {
  const out = {};
  for (const [provider, cfg] of Object.entries(PROVIDER_LISTS)) {
    out[provider] = cfg.models.map(m => ({
      modelId:           m.modelId,
      enabled:           m.enabled,
      status:            m.health.status,
      cooldownRemainsS:  m.health.until && m.health.until > Date.now()
        ? +((m.health.until - Date.now()) / 1000).toFixed(0)
        : null,
      contextWindow:     m.contextWindow,
      maxOutputTokens:   m.maxOutputTokens,
      costTier:          m.costTier,
      capabilities:      m.capabilities,
    }));
  }
  return out;
}

/**
 * Test-only: restores every model's health to 'working', re-enables every
 * entry, and resets the OpenRouter rotation cursor. No production code
 * path calls this — see health.js's __resetForTests() for the same pattern.
 */
export function __resetForTests() {
  for (const cfg of Object.values(PROVIDER_LISTS)) {
    for (const entry of cfg.models) {
      entry.enabled = true;
      entry.health  = { status: 'working', until: 0, lastError: null };
    }
  }
  openrouterCursor = 0;
}

/**
 * Gemini Provider v3
 *
 * Changes from v2:
 * - Model ID no longer hardcoded inline — pulled from the central Model
 *   Registry (src/providers/modelRegistry.js, Issue 5). Registry lists a
 *   primary + fallback model; a dead primary now falls through to the
 *   fallback WITHIN this call instead of failing the whole provider.
 * - TRUNCATED_MAX_TOKENS is no longer thrown as an error (Issue 1). Hitting
 *   the output-token cap is a SUCCESSFUL completion that ran out of budget,
 *   not a failure: this now returns { text, truncated: true,
 *   finishReason: 'length' } so router.js can mark the provider healthy,
 *   skip the fallback chain, and hand the partial answer straight back.
 * - Shared error classifier (providerErrors.js, Issue 4) replaces the
 *   ad-hoc status checks — 404/model-not-found is scoped to the specific
 *   model (registry), never to the provider's health.
 *
 * Preserved from v2:
 * - Timeout is set by the router via timeoutManager (task-aware: 8-65s);
 *   this file only respects the signal passed in.
 * - GoogleGenAI client instances cached per API key (HTTP connection reuse).
 * - nextKey() loops all keys looking for a non-cooled one.
 */

import { GoogleGenAI } from '@google/genai';
import {
  getCandidateModels, markModelWorking, markModelUnavailable,
} from './modelRegistry.js';
import { classifyProviderError } from './providerErrors.js';

// ── Key management ────────────────────────────────────────────────────────────

function getKeys() {
  return [
    process.env.GEMINI_KEY_1,
    process.env.GEMINI_KEY_2,
    process.env.GEMINI_KEY_3,
    process.env.GEMINI_KEY_4,
    process.env.GEMINI_KEY_5,
    process.env.GEMINI_KEY_6,
    process.env.GEMINI_KEY_7,
    process.env.GEMINI_KEY_8,
  ].filter(Boolean);
}

/** Startup validation (Issue 6) — does this provider have any usable key at all? */
export function hasConfiguredKeys() {
  return getKeys().length > 0;
}

let keyIndex = 0;
const keyCooldowns = new Map();

// Cache clients per key — avoids creating new HTTP agents on every request
const clientCache = new Map();

function getClient(key) {
  if (!clientCache.has(key)) {
    clientCache.set(key, new GoogleGenAI({ apiKey: key }));
  }
  return clientCache.get(key);
}

function onCooldown(key) {
  const until = keyCooldowns.get(key);
  return until ? Date.now() < until : false;
}

function applyCooldown(key, ms) {
  keyCooldowns.set(key, Date.now() + ms);
}

/**
 * Pick next non-cooled key, cycling through all available.
 * Throws if all keys are on cooldown.
 */
function nextKey() {
  const keys = getKeys();
  if (!keys.length) throw new Error('No Gemini keys configured');

  for (let i = 0; i < keys.length; i++) {
    const k = keys[keyIndex];
    keyIndex = (keyIndex + 1) % keys.length;
    if (!onCooldown(k)) return k;
  }
  throw new Error('All Gemini keys on cooldown');
}

// ── Message format ────────────────────────────────────────────────────────────

function toContents(messages) {
  return messages.map(m => ({
    role:  m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }],
  }));
}

// ── Generate ──────────────────────────────────────────────────────────────────

/**
 * @param {string} systemPrompt
 * @param {Array<{role:string,content:string}>} messages
 * @param {AbortSignal} [signal]  — fired by router's timedAbort (task-aware)
 * @param {number} [maxTokens] - Phase 6 Response Budgeting: caps output length.
 *   Clamped against the registry's maxOutputTokens for whichever model is
 *   actually selected. Omitted entirely → field is not sent to the API.
 * @returns {Promise<{ text: string, truncated: boolean, finishReason: string }>}
 */
export async function generateGemini(systemPrompt, messages, signal, maxTokens) {
  const keys = getKeys();
  if (!keys.length) throw new Error('No Gemini keys configured');

  const candidates = getCandidateModels('gemini');
  if (!candidates.length) throw new Error('All Gemini models permanently unavailable');

  let lastError;

  for (const modelEntry of candidates) {
    const modelId  = modelEntry.modelId;
    const capTokens = maxTokens ? Math.min(maxTokens, modelEntry.maxOutputTokens) : maxTokens;
    const maxAttempts = Math.min(keys.length, 3);

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      // Bail immediately if caller already aborted
      if (signal?.aborted) {
        throw new Error('TIMEOUT');
      }

      let key;
      try {
        key = nextKey();
      } catch (e) {
        lastError = e;
        break; // all keys cooled — no point trying this model further
      }

      try {
        console.log(`[GEMINI] model=${modelId} attempt=${attempt + 1}/${maxAttempts} key=...${key.slice(-4)}`);

        const ai  = getClient(key);
        const req = ai.models.generateContent({
          model:    modelId,
          contents: toContents(messages),
          ...((systemPrompt || capTokens) ? {
            config: {
              ...(systemPrompt ? { systemInstruction: systemPrompt } : {}),
              ...(capTokens ? { maxOutputTokens: capTokens } : {}),
            },
          } : {}),
        });
        // Demo-stability fix: a lost Promise.race leaves `req` running
        // detached; a late rejection would be an unhandled rejection —
        // fatal on modern Node — crashing the server mid-request. No-op
        // handler marks it handled; race path unaffected. (Same fix in
        // groq.js / openrouter.js.)
        Promise.resolve(req).catch(() => {});

        const result = signal
          ? await Promise.race([
              req,
              new Promise((_, rej) => {
                if (signal.aborted) return rej(new Error('TIMEOUT'));
                signal.addEventListener('abort', () => rej(new Error('TIMEOUT')), { once: true });
              }),
            ])
          : await req;

        const finishReason = result.candidates?.[0]?.finishReason;
        const text = result.text ?? '';

        // ── Issue 1: hitting the output-token cap is SUCCESS, not failure ──
        if (capTokens && finishReason === 'MAX_TOKENS') {
          if (!text.trim()) throw new Error('INVALID_RESPONSE'); // nothing usable came back — genuine failure
          console.log(`[GEMINI] model=${modelId} hit maxTokens=${capTokens} cap — returning partial as successful completion`);
          markModelWorking('gemini', modelId);
          return { text, truncated: true, finishReason: 'length' };
        }

        if (!text) throw new Error('INVALID_RESPONSE');

        markModelWorking('gemini', modelId);
        console.log(`[GEMINI] model=${modelId} success key=...${key.slice(-4)}`);
        return { text, truncated: false, finishReason: 'stop' };

      } catch (err) {
        // TIMEOUT comes from our AbortController — propagate immediately,
        // no point trying another key/model, the router's budget is spent.
        if (err.message === 'TIMEOUT') {
          console.log(`[GEMINI] TIMEOUT key=...${key?.slice(-4)} model=${modelId} (budget exhausted for this task)`);
          throw err;
        }

        lastError = err;
        const { type, status } = classifyProviderError(err);

        if (type === 'model_not_found') {
          markModelUnavailable('gemini', modelId, `${status ?? ''} ${err.message}`.trim());
          break; // stop burning key-attempts on a dead model — try next candidate model
        }
        if (type === 'rate_limit') {
          console.log(`[GEMINI] key=...${key.slice(-4)} rate limited → 2min cooldown`);
          applyCooldown(key, 120_000);
          continue;
        }
        if (type === 'server_error') {
          console.log(`[GEMINI] key=...${key.slice(-4)} service unavailable → 60s cooldown`);
          applyCooldown(key, 60_000);
          continue;
        }
        if (type === 'auth') {
          console.log(`[GEMINI] key=...${key.slice(-4)} auth error → 24h cooldown`);
          applyCooldown(key, 86_400_000);
          continue;
        }

        // invalid_response / network / unknown — log and retry with next key
        console.log(`[GEMINI] model=${modelId} attempt ${attempt + 1} error type=${type} status=${status} msg=${err.message}`);
      }
    }
    // exhausted every key for this model — fall through to next candidate model
  }

  throw lastError ?? new Error('All Gemini attempts exhausted');
}

/**
 * Streaming variant (Day 3 — Real Streaming).
 *
 * Same key rotation + model-registry fallback as generateGemini, with the
 * streaming rule: fallback only BEFORE the first emitted delta. Mid-stream
 * failures return the partial as finishReason='interrupted' — the client
 * has already rendered those tokens.
 *
 * @param {(delta: string) => void} onDelta
 * @returns {Promise<{ text:string, truncated:boolean, finishReason:string, streamed:true }>}
 */
export async function streamGemini(systemPrompt, messages, signal, maxTokens, onDelta) {
  const keys = getKeys();
  if (!keys.length) throw new Error('No Gemini keys configured');

  const candidates = getCandidateModels('gemini');
  if (!candidates.length) throw new Error('All Gemini models permanently unavailable');

  let lastError;

  for (const modelEntry of candidates) {
    const modelId   = modelEntry.modelId;
    const capTokens = maxTokens ? Math.min(maxTokens, modelEntry.maxOutputTokens) : maxTokens;
    const maxAttempts = Math.min(keys.length, 3);

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      if (signal?.aborted) throw new Error('TIMEOUT');

      let key;
      try { key = nextKey(); } catch (e) { lastError = e; break; }

      let stream;
      try {
        console.log(`[GEMINI] stream model=${modelId} attempt=${attempt + 1}/${maxAttempts} key=...${key.slice(-4)}`);
        const ai = getClient(key);
        stream = await ai.models.generateContentStream({
          model:    modelId,
          contents: toContents(messages),
          config: {
            ...(systemPrompt ? { systemInstruction: systemPrompt } : {}),
            ...(capTokens ? { maxOutputTokens: capTokens } : {}),
            abortSignal: signal, // SDK cancels the HTTP request on abort
          },
        });
      } catch (err) {
        if (signal?.aborted || err.name === 'AbortError') throw new Error('TIMEOUT');
        lastError = err;
        const { type, status } = classifyProviderError(err);
        if (type === 'model_not_found') { markModelUnavailable('gemini', modelId, `${status ?? ''} ${err.message}`.trim()); break; }
        if (type === 'rate_limit')      { applyCooldown(key, 120_000);   continue; }
        if (type === 'server_error')    { applyCooldown(key, 60_000);    continue; }
        if (type === 'auth')            { applyCooldown(key, 86_400_000); continue; }
        console.log(`[GEMINI] stream open failed model=${modelId} type=${type} msg=${err.message}`);
        continue;
      }

      let text = '';
      let finishReason = null;
      try {
        for await (const chunk of stream) {
          if (signal?.aborted) throw new Error('TIMEOUT');
          const delta = chunk?.text ?? '';
          finishReason = chunk?.candidates?.[0]?.finishReason ?? finishReason;
          if (delta) { text += delta; onDelta(delta); }
        }
      } catch (err) {
        if (text) {
          console.log(`[GEMINI] stream interrupted after ${text.length} chars model=${modelId}: ${err.message}`);
          return { text, truncated: true, finishReason: 'interrupted', streamed: true };
        }
        if (signal?.aborted || err.name === 'AbortError' || err.message === 'TIMEOUT') throw new Error('TIMEOUT');
        lastError = err;
        continue; // nothing emitted — safe to retry with next key
      }

      if (!text.trim()) { lastError = new Error('Gemini stream returned empty response'); continue; }

      markModelWorking('gemini', modelId);
      const truncated = capTokens && finishReason === 'MAX_TOKENS';
      return { text, truncated: !!truncated, finishReason: truncated ? 'length' : 'stop', streamed: true };
    }
  }

  throw lastError ?? new Error('All Gemini stream attempts exhausted');
}

// ── Multimodal (Day 5 — Universal Upload) ─────────────────────────────────────
//
// Image / audio / video understanding for the unified upload pipeline
// (src/upload/mediaPipeline.js). Reuses this file's key rotation, cooldowns,
// client cache, and error classification — no parallel key-management stack.
//
// parts: Gemini content parts, e.g.
//   [{ inlineData: { mimeType: 'image/png', data: '<base64>' } }, { text: 'Describe…' }]

export async function analyzeMediaWithGemini(parts, { systemPrompt, maxTokens = 2048, signal } = {}) {
  const keys = getKeys();
  if (!keys.length) throw new Error('No Gemini keys configured — media analysis unavailable');

  const candidates = getCandidateModels('gemini');
  if (!candidates.length) throw new Error('All Gemini models permanently unavailable');

  let lastError;

  for (const modelEntry of candidates) {
    const modelId = modelEntry.modelId;
    const maxAttempts = Math.min(keys.length, 3);

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      if (signal?.aborted) throw new Error('TIMEOUT');

      let key;
      try { key = nextKey(); } catch (e) { lastError = e; break; }

      try {
        console.log(`[GEMINI] media model=${modelId} attempt=${attempt + 1}/${maxAttempts} key=...${key.slice(-4)}`);
        const ai = getClient(key);
        const req = ai.models.generateContent({
          model:    modelId,
          contents: [{ role: 'user', parts }],
          config: {
            ...(systemPrompt ? { systemInstruction: systemPrompt } : {}),
            maxOutputTokens: Math.min(maxTokens, modelEntry.maxOutputTokens ?? maxTokens),
          },
        });
        Promise.resolve(req).catch(() => {}); // mark handled (same race-leak fix as generateGemini)

        const result = signal
          ? await Promise.race([
              req,
              new Promise((_, rej) => {
                if (signal.aborted) return rej(new Error('TIMEOUT'));
                signal.addEventListener('abort', () => rej(new Error('TIMEOUT')), { once: true });
              }),
            ])
          : await req;

        const text = result.text ?? '';
        if (!text.trim()) { lastError = new Error('Gemini returned empty media analysis'); continue; }

        markModelWorking('gemini', modelId);
        return { text: text.trim(), model: modelId };
      } catch (err) {
        if (signal?.aborted || err.name === 'AbortError') throw new Error('TIMEOUT');
        lastError = err;
        const { type, status } = classifyProviderError(err);
        if (type === 'model_not_found') { markModelUnavailable('gemini', modelId, `${status ?? ''} ${err.message}`.trim()); break; }
        if (type === 'rate_limit')      { applyCooldown(key, 120_000);    continue; }
        if (type === 'server_error')    { applyCooldown(key, 60_000);     continue; }
        if (type === 'auth')            { applyCooldown(key, 86_400_000); continue; }
        console.log(`[GEMINI] media analysis failed model=${modelId} type=${type} msg=${err.message}`);
        continue;
      }
    }
  }

  throw lastError ?? new Error('All Gemini media analysis attempts exhausted');
}

/**
 * AQUA Internal Intelligence Engine — Synthesizer
 *
 * Final stage of the internal pipeline. Combines Planner output,
 * Reasoning Engine output, and Critic output into one compact text
 * block — the "intelligence brief" — that promptBuilder.js injects into
 * the system prompt as a single additional module.
 *
 * Design note (additive, non-breaking):
 * Memory, project context, and conversation history are already built
 * and injected by chat.js / promptBuilder.js as their own blocks. The
 * Synthesizer does not re-embed that content here — doing so would
 * duplicate tokens already in the prompt. Instead it produces the one
 * genuinely new piece (plan + reasoning strategy + critic rubric) and
 * exposes a structured `raw` object so a future version of this module
 * can fully own prompt assembly end-to-end (per spec's long-term framing
 * of Synthesizer output as "the only prompt sent to the provider")
 * without breaking this interface.
 *
 * Deterministic: pure string templating, no LLM calls.
 */

/**
 * @param {{ plan: object, reasoning: object, critic: object, taskType: string }} input
 * @returns {{ active: boolean, text: string, raw: object }}
 */
export function synthesize({ plan, reasoning, critic, taskType }) {
  if (!plan?.active || !reasoning?.active) {
    return { active: false, text: '', raw: { plan, reasoning, critic, taskType } };
  }

  const stageNames = plan.pipeline.map(s => s.name).join(' → ');
  const lines = [
    '[Internal Reasoning Brief]',
    `Task: ${taskType}. ${reasoning.directive}`,
    `Work through these stages internally before answering: ${stageNames}.`,
    `Keep in mind: ${reasoning.checklist.join('; ')}.`,
  ];

  if (critic?.active) {
    lines.push(critic.directive);
  }

  return {
    active: true,
    text:   lines.join('\n'),
    raw:    { plan, reasoning, critic, taskType },
  };
}

/**
 * AQUA Internal Intelligence Engine — Agent Plugin Registry
 *
 * Extension point for future modules (spec section 7): Research Agent,
 * Coding Agent, Browser Agent, File Agent, Memory Agent, Tool Agent,
 * Vision Agent, Verification Agent, Planning Agent, etc.
 *
 * No agents are registered today — this phase stays deterministic and
 * single-pass per the spec's cost constraint. This registry is the seam
 * future phases plug into: a new agent calls registerAgent() once at
 * module load and the orchestrator (internalIntelligenceEngine.js) can
 * start invoking it without any other file changing.
 *
 * Consistent interface every agent module must expose:
 *   {
 *     name: string,
 *     description: string,
 *     run: async (input: object) => object   // input/output shape is
 *                                             // agent-specific; orchestrator
 *                                             // treats it as opaque today
 *   }
 */

const agents = new Map();

/**
 * @param {string} name
 * @param {{ name: string, description: string, run: Function }} definition
 */
export function registerAgent(name, definition) {
  if (typeof definition?.run !== 'function') {
    throw new Error(`Agent "${name}" must implement run()`);
  }
  agents.set(name, definition);
}

/**
 * @param {string} name
 * @returns {object | undefined}
 */
export function getAgent(name) {
  return agents.get(name);
}

/**
 * @returns {string[]} names of all registered agents
 */
export function listAgents() {
  return [...agents.keys()];
}

/**
 * AQUA Internal Intelligence Engine — Reasoning Engine
 *
 * Second stage of the internal pipeline. Chooses a reasoning strategy
 * (from strategyRegistry.js) for the plan produced by planner.js and
 * attaches it to the plan's stages.
 *
 * Strategy selection is rule-based today (taskType → strategy, with one
 * lightweight comparative-language override). To register a brand new
 * strategy, add it in strategyRegistry.js and map a taskType to it below —
 * no other file needs to change.
 *
 * Deterministic: no LLM calls.
 */

import { getStrategy } from './strategyRegistry.js';

const TASK_TO_STRATEGY = {
  coding:            'coding',
  debugging:         'debugging',
  architecture:       'architectural',
  project_query:      'architectural',
  research:           'research',
  file_analysis:      'analytical',
  planning:           'planning',
  creative_writing:   'creative',
  brainstorming:      'creative',
  reasoning:          'mathematical',
  analysis:           'analytical',
  agent_task:         'analytical',
};

const DEFAULT_STRATEGY = 'analytical';

// Cuts across task types — a comparison can show up inside coding,
// research, or architecture requests alike.
const COMPARATIVE_PATTERN = /\b(vs\.?|versus|compare|comparison|difference between|trade.?off)\b/i;

function selectStrategyName(taskType, userMessage = '') {
  if (COMPARATIVE_PATTERN.test(userMessage)) return 'comparative';
  return TASK_TO_STRATEGY[taskType] ?? DEFAULT_STRATEGY;
}

/**
 * @param {{ active: boolean, taskType: string, pipeline: Array<{name,focus}> }} plan
 * @param {string} userMessage
 * @returns {{
 *   active: boolean,
 *   strategy?: string,
 *   checklist?: string[],
 *   directive?: string,
 *   stages?: Array<{name: string, focus: string}>
 * }}
 */
export function runReasoning(plan, userMessage = '') {
  if (!plan?.active) return { active: false };

  const strategyName = selectStrategyName(plan.taskType, userMessage);
  const strategy      = getStrategy(strategyName) ?? getStrategy(DEFAULT_STRATEGY);

  return {
    active:    true,
    strategy:  strategy.name,
    checklist: strategy.checklist,
    directive: strategy.directive,
    stages:    plan.pipeline,
  };
}

/**
 * AQUA Internal Intelligence Engine — Orchestrator
 *
 * Single entry point chat.js calls. Runs the four deterministic stages
 * in sequence:
 *
 *   Planner → Reasoning Engine → Critic → Synthesizer
 *
 * Sits between the existing Phase 4 Execution Planner / Reasoning
 * Strategy modules and promptBuilder.js. Does not replace or modify
 * either of those — it adds a deeper, structured layer on top, and
 * degrades to a no-op for low-complexity requests (see planner.js) so
 * casual chat keeps its current low token cost exactly as before.
 *
 * ── Future roadmap compatibility (spec section 10) ──────────────────────
 * Each stage is a separate module with a narrow interface, so the
 * upgrades below can land without redesigning this orchestrator:
 *   - True multi-agent execution   → swap a stage's deterministic fn for
 *                                    one that calls agentRegistry.js agents
 *   - Parallel reasoning           → runReasoning() can fan out to
 *                                    multiple strategies and merge results
 *   - Self-reflection loops        → critic.js can loop reviewReasoning()
 *                                    against a draft answer
 *   - Tool / web / repo agents     → register via agentRegistry.js,
 *                                    invoked from a new pipeline stage
 *   - Verification / eval models   → slot in as a 5th stage after Critic
 * None of these require changing chat.js's call site below.
 */

import { createPlan }      from './planner.js';
import { runReasoning }    from './reasoningEngine.js';
import { reviewReasoning } from './critic.js';
import { synthesize }      from './synthesizer.js';

/**
 * @param {{ taskType: string, complexity: string, confidence?: number, userMessage: string }} input
 * @returns {{ plan: object, reasoning: object, critic: object, synthesis: object }}
 */
export function runIntelligencePipeline({ taskType, complexity, confidence = 1.0, userMessage = '' }) {
  const plan      = createPlan({ taskType, complexity, confidence });
  const reasoning = runReasoning(plan, userMessage);
  const critic    = reviewReasoning(plan, reasoning);
  const synthesis = synthesize({ plan, reasoning, critic, taskType });

  return { plan, reasoning, critic, synthesis };
}

/**
AQUA Verification Agent — Regression Tests

Covers: self-registration into agentRegistry.js, the pass/revise decision
based on the model's response, fail-open behavior on a verifier error, and
that the critique call is built from the real per-taskType risk rubric
(critic.js's getFocusRisks — single source of truth, not a second copy).

The real generateText() makes network calls to live providers, so every
test here injects a fake `generate` function via runVerification()'s
`generate` param instead of touching providers/router.js.
*/
import { test } from 'node:test';
import assert from 'node:assert/strict';
import { runVerification } from './verificationAgent.js';
import { getAgent } from './agentRegistry.js';
import { getFocusRisks } from './critic.js';

function fakeGenerate(response) {
  const calls = [];
  const fn = async (userMessage, systemPrompt, messages, ctx, preTaskType, executionPlan, responseBudget) => {
    calls.push({ userMessage, systemPrompt, messages, preTaskType, executionPlan, responseBudget });
    if (response instanceof Error) throw response;
    return { text: response, provider: 'mock-provider' };
  };
  fn.calls = calls;
  return fn;
}

// ── Self-registration ───────────────────────────────────────────────────────

test('importing the module registers a verification agent with a run() function', () => {
  const agent = getAgent('verification');
  assert.equal(agent.name, 'verification');
  assert.equal(typeof agent.run, 'function');
});

// ── Pass path ────────────────────────────────────────────────────────────────

test('draft passes through unchanged when the verifier reports no issues', async () => {
  const generate = fakeGenerate(
    'VERIFICATION_PASSED — the draft was checked against the listed risks and no material issues were found; returning it unchanged.'
  );

  const result = await runVerification({
    userMessage: 'Design an auth system',
    draftAnswer: 'Here is the original draft answer.',
    taskType:    'architecture',
    requestId:   'req-1',
    conversationId: 'conv-1',
    generate,
  });

  assert.equal(result.ran, true);
  assert.equal(result.passed, true);
  assert.equal(result.revised, false);
  assert.equal(result.finalAnswer, 'Here is the original draft answer.');
});

// ── Revision path ────────────────────────────────────────────────────────────

test('draft is replaced when the verifier finds a genuine issue', async () => {
  const corrected = 'Corrected answer: the original draft missed a required validation step.';
  const generate = fakeGenerate(corrected);

  const result = await runVerification({
    userMessage: 'Write a login endpoint',
    draftAnswer: 'Original draft with a missing check.',
    taskType:    'coding',
    generate,
  });

  assert.equal(result.ran, true);
  assert.equal(result.passed, false);
  assert.equal(result.revised, true);
  assert.equal(result.finalAnswer, corrected);
});

// ── Fail-open behavior ────────────────────────────────────────────────────────

test('a verifier error fails open: original draft is returned unchanged, not thrown', async () => {
  const generate = fakeGenerate(new Error('All providers exhausted'));

  const result = await runVerification({
    userMessage: 'Design a payment flow',
    draftAnswer: 'Original draft answer.',
    taskType:    'architecture',
    generate,
  });

  assert.equal(result.ran, false);
  assert.equal(result.revised, false);
  assert.equal(result.finalAnswer, 'Original draft answer.');
  assert.match(result.error, /All providers exhausted/);
});

// ── Rubric sourcing (no duplicate risk list) ──────────────────────────────────

test('focusRisks comes from critic.js getFocusRisks — same rubric, not a second copy', async () => {
  const generate = fakeGenerate('VERIFICATION_PASSED — the draft was checked against the listed risks and no material issues were found; returning it unchanged.');

  const result = await runVerification({
    userMessage: 'Fix this bug',
    draftAnswer: 'Draft.',
    taskType:    'coding',
    generate,
  });

  assert.deepEqual(result.focusRisks, getFocusRisks('coding'));
});

test('critique prompt includes the full risk list and both the question and draft', async () => {
  const generate = fakeGenerate('VERIFICATION_PASSED — the draft was checked against the listed risks and no material issues were found; returning it unchanged.');

  await runVerification({
    userMessage: 'UNIQUE_QUESTION_MARKER',
    draftAnswer: 'UNIQUE_DRAFT_MARKER',
    taskType:    'coding',
    generate,
  });

  const [call] = generate.calls;
  for (const risk of getFocusRisks('coding')) {
    assert.ok(call.systemPrompt.includes(risk), `expected system prompt to mention risk: ${risk}`);
  }
  assert.ok(call.messages[0].content.includes('UNIQUE_QUESTION_MARKER'));
  assert.ok(call.messages[0].content.includes('UNIQUE_DRAFT_MARKER'));
  assert.equal(call.preTaskType, 'coding');
});

/**
 * AQUA Internal Intelligence Engine — Strategy Registry
 *
 * Holds reasoning strategies that the Reasoning Engine selects between.
 * Plugin-style: registerStrategy() adds a new strategy without touching
 * any existing logic or dispatch code — satisfies the spec requirement
 * that "future strategies should be easy to register without changing
 * existing logic."
 *
 * Each strategy is plain data (checklist + directive string) — deterministic,
 * no LLM calls. Designed so a real multi-agent strategy (one that actually
 * runs its own reasoning pass) can register under the same name later
 * without changing the selection logic in reasoningEngine.js.
 */

const strategies = new Map();

/**
 * @param {string} name
 * @param {{ checklist: string[], directive: string }} definition
 */
export function registerStrategy(name, definition) {
  strategies.set(name, { name, ...definition });
}

/**
 * @param {string} name
 * @returns {{ name: string, checklist: string[], directive: string } | undefined}
 */
export function getStrategy(name) {
  return strategies.get(name);
}

export function listStrategies() {
  return [...strategies.keys()];
}

