/**
 * AQUA Internal Intelligence Engine — Planner
 *
 * First stage of the internal pipeline (sits right after the existing
 * Phase 4 Execution Planner / Reasoning Strategy modules — does not
 * replace them).
 *
 * Decomposes a classified task into a structured, stage-based plan that
 * downstream agents (Reasoning Engine, Critic, Synthesizer) can consume.
 * Output is structured data, not prose — per spec, "Planner output should
 * be structured data rather than plain text so future agents can consume it."
 *
 * Deterministic: no LLM calls. For low-complexity requests (casual chat,
 * simple Q&A, memory recall) the heavy pipeline is skipped entirely —
 * `active: false` — so cost stays flat for the bulk of everyday traffic.
 */

import { getPipeline } from './pipelineRegistry.js';

/**
 * @param {{ taskType: string, complexity: 'low'|'medium'|'high', confidence?: number, userMessage?: string }} input
 * @returns {{
 *   taskType: string,
 *   complexity: string,
 *   active: boolean,
 *   pipeline: Array<{name: string, focus: string}>,
 *   rationale: string
 * }}
 */
export function createPlan({ taskType, complexity, confidence = 1.0 }) {
  const active = complexity !== 'low';

  if (!active) {
    return {
      taskType,
      complexity,
      active: false,
      pipeline: [],
      rationale: `Low-complexity task (${taskType}) — internal pipeline skipped to avoid unnecessary overhead.`,
    };
  }

  const pipeline = getPipeline(taskType);

  return {
    taskType,
    complexity,
    active: true,
    pipeline,
    rationale: `Task classified as "${taskType}" (complexity=${complexity}, confidence=${confidence.toFixed(2)}) — running ${pipeline.length}-stage pipeline.`,
  };
}

/**
 * AQUA Internal Intelligence Engine — Verification Agent
 *
 * The real second pass that closes the loop the rest of the codebase
 * already designed for and explicitly deferred:
 *
 *   - critic.js (pre-generation) only ever picked a risk rubric and
 *     handed the FIRST-pass model a self-check directive baked into its
 *     own prompt. Its own header comment: "A deterministic, no-LLM-call
 *     module cannot actually read and judge the semantic content of a
 *     reasoning pass (that needs a model) ... built so a real critique
 *     pass (a second model call that inspects the draft answer) can slot
 *     in later under the same reviewReasoning() interface."
 *   - orchestrator/verificationStrategy.js only ever decided WHETHER
 *     verification is warranted. Its own header comment: "the plug-in
 *     seam already exists in src/intelligence/agentRegistry.js, which
 *     today has zero agents registered."
 *   - agentRegistry.js has stood empty, waiting for exactly this.
 *
 * This module is that agent. It registers itself under the name
 * 'verification' on import (side effect, same pattern
 * orchestrator/capabilities.js already uses for capability definitions).
 * chat.js calls it AFTER the main answer is generated — orchestrate()
 * itself stays pure/synchronous/no-I/O exactly as documented; it only
 * ever reports agentAvailable, it never invokes run().
 *
 * Design choices:
 *   - Reuses generateText() end-to-end (provider ranking, health
 *     tracking, full fallback chain, timeout budgeting) instead of
 *     calling a provider directly — no duplicate retry/fallback logic.
 *   - preTaskType is the REAL taskType (not a generic one) so provider
 *     ranking for the critique call still favors whichever provider is
 *     actually strong at that domain (e.g. Gemini for architecture).
 *   - The "no issues" response is a long, distinctive sentinel rather
 *     than a short token like "OK". generateText()'s validator applies
 *     task-aware minimum lengths (architecture: 50 chars) to WHATEVER
 *     text comes back, since it has no notion of "this is a verdict, not
 *     an answer" — a short sentinel would get rejected as too_short and
 *     burn through the entire fallback chain for no reason.
 *   - Fails open: any error (provider exhausted, network failure, etc.)
 *     returns the original draft untouched. Verification can only ever
 *     replace a draft for a found issue — it can never turn a working
 *     response into a failed request.
 */

import { generateText }    from '../providers/router.js';
import { createContext }   from '../core/observability.js';
import { getFocusRisks }   from './critic.js';
import { registerAgent }   from './agentRegistry.js';

const PASS_SENTINEL =
  'VERIFICATION_PASSED — the draft was checked against the listed risks and no material issues were found; returning it unchanged.';

/**
 * @param {string[]} focusRisks
 * @returns {string} system prompt for the critique call
 */
function buildCritiquePrompt(focusRisks) {
  return [
    "You are AQUA's internal verification pass. You are shown a user's question and a draft answer someone already wrote for them.",
    '',
    `Check the draft ONLY against these specific risks: ${focusRisks.join(', ')}.`,
    '',
    `If none of these specific risks are actually present, respond with EXACTLY this line and nothing else:\n"${PASS_SENTINEL}"`,
    '',
    'If one of these specific risks IS genuinely present, respond with the complete corrected replacement answer only — no preamble, no explanation of what changed, no meta-commentary about the review. Your response must be ready to send to the user exactly as-is, as a full replacement for the draft.',
    '',
    'Be conservative: only replace the draft for a real, specific problem tied to the listed risks. Do not rewrite for style, tone, or phrasing preferences.',
  ].join('\n');
}

/**
 * Run the real verification pass on a draft answer.
 *
 * @param {object} input
 * @param {string} input.userMessage    - original user question
 * @param {string} input.draftAnswer    - the first-pass generated answer
 * @param {string} input.taskType       - classifier.js taskType (single source of truth)
 * @param {string} [input.requestId]
 * @param {string} [input.conversationId]
 * @param {object} [input.responseBudget] - Phase 6 execution profile budget, reused as-is
 *                                          so the critique call inherits the same response
 *                                          size ceiling rather than inventing a new one
 * @param {Function} [input.generate]   - injection point for tests; defaults to the real
 *                                        generateText() from providers/router.js
 * @returns {Promise<{
 *   ran: boolean,
 *   passed: boolean|null,
 *   revised: boolean,
 *   finalAnswer: string,
 *   focusRisks: string[],
 *   provider?: string,
 *   latencyMs?: number,
 *   attemptCount?: number,
 *   error?: string
 * }>}
 */
export async function runVerification({
  userMessage,
  draftAnswer,
  taskType,
  requestId,
  conversationId,
  responseBudget,
  generate = generateText,
}) {
  const focusRisks = getFocusRisks(taskType);
  const critiquePrompt = buildCritiquePrompt(focusRisks);
  const critiqueMessages = [{
    role: 'user',
    content: `Original user question:\n${userMessage}\n\nDraft answer to review:\n${draftAnswer}`,
  }];

  // Separate context so this call's provider attempts/fallback chain don't
  // mix into the main generation's ctx.attempts array — chat.js's response
  // fallbackChain should describe how the ANSWER was produced, not the
  // verification pass on top of it.
  const verifyCtx = createContext({
    conversationId,
    requestId: requestId ? `${requestId}-verify` : undefined,
  });

  const start = Date.now();
  try {
    const result = await generate(
      userMessage,        // classification fallback only — preTaskType below skips it
      critiquePrompt,
      critiqueMessages,
      verifyCtx,
      taskType,            // real taskType: keeps provider ranking domain-appropriate
      undefined,           // no Phase 4 execution plan bias for the critique call itself
      responseBudget,
    );

    const text = (result.text ?? '').trim();
    const passed = text.startsWith('VERIFICATION_PASSED');

    return {
      ran: true,
      passed,
      revised: !passed,
      finalAnswer: passed ? draftAnswer : text,
      focusRisks,
      provider: result.provider,
      latencyMs: Date.now() - start,
      attemptCount: verifyCtx.attempts.length,
    };
  } catch (err) {
    console.warn(`[VERIFICATION] Verifier call failed, passing draft through unchanged: ${err.message}`);
    return {
      ran: false,
      passed: null,
      revised: false,
      finalAnswer: draftAnswer,
      focusRisks,
      error: err.message,
      attemptCount: verifyCtx.attempts.length,
    };
  }
}

registerAgent('verification', {
  name: 'verification',
  description:
    "LLM-backed second pass. Checks a draft answer against the risk rubric critic.js selects for the task type, and returns a corrected replacement only when a specific, genuine issue is found. Fails open: any error in the verifier call returns the original draft unchanged, so a broken verifier can never break or worsen a response that would otherwise have succeeded.",
  run: runVerification,
});

/**
 * AQUA Upload Classifier — Day 5 Universal Upload
 *
 * ONE upload entrypoint means SOMETHING must decide what a file actually is.
 * This module is that decision. Pure + synchronous: extension first, magic
 * bytes as a tiebreaker/verifier (a ".zip" that doesn't start with PK is
 * treated as corrupt, not silently mis-routed).
 *
 * Kinds (each maps to exactly one processing pipeline — see routes/upload.js):
 *   repository — ZIP / TAR / TAR.GZ / TGZ           → workspace ingestion
 *   source     — code / text / markdown / json / …  → inline read
 *   document   — PDF / DOCX / PPTX / XLSX / CSV / ODT / EPUB → document pipeline
 *   image      — PNG / JPEG / WEBP / GIF / SVG / HEIC → vision pipeline
 *   audio      — MP3 / WAV / M4A                     → media pipeline (Gemini)
 *   video      — MP4 / MOV / AVI                     → media pipeline (Gemini)
 *   unknown    — everything else                     → explicit rejection (never silent)
 */
import path from 'path';

// ── Extension tables ──────────────────────────────────────────────────────────

const ARCHIVE_EXTS = new Set(['.zip', '.tar', '.gz', '.tgz']);

const SOURCE_EXTS = new Set([
  '.js', '.mjs', '.cjs', '.ts', '.tsx', '.jsx', '.py', '.pyw', '.java', '.kt',
  '.go', '.rs', '.cs', '.cpp', '.cc', '.cxx', '.c', '.h', '.hpp', '.php',
  '.rb', '.swift', '.md', '.mdx', '.txt', '.json', '.yaml', '.yml', '.toml',
  '.xml', '.html', '.htm', '.css', '.scss', '.sass', '.less', '.sql',
  '.graphql', '.gql', '.proto', '.sh', '.bash', '.zsh', '.env', '.tf',
  '.vue', '.svelte', '.log', '.ini', '.cfg', '.conf', '.tsv',
]);

const DOCUMENT_EXTS = new Set(['.pdf', '.docx', '.pptx', '.xlsx', '.csv', '.odt', '.epub']);

const IMAGE_EXTS = new Set(['.png', '.jpg', '.jpeg', '.webp', '.gif', '.svg', '.heic', '.heif']);
const AUDIO_EXTS = new Set(['.mp3', '.wav', '.m4a']);
const VIDEO_EXTS = new Set(['.mp4', '.mov', '.avi']);

const MIME_BY_EXT = {
  '.png': 'image/png', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg',
  '.webp': 'image/webp', '.gif': 'image/gif', '.svg': 'image/svg+xml',
  '.heic': 'image/heic', '.heif': 'image/heif',
  '.mp3': 'audio/mpeg', '.wav': 'audio/wav', '.m4a': 'audio/mp4',
  '.mp4': 'video/mp4', '.mov': 'video/quicktime', '.avi': 'video/x-msvideo',
  '.pdf': 'application/pdf',
};

// ── Magic bytes ───────────────────────────────────────────────────────────────

function startsWith(buffer, bytes, offset = 0) {
  if (buffer.length < offset + bytes.length) return false;
  for (let i = 0; i < bytes.length; i++) {
    if (buffer[offset + i] !== bytes[i]) return false;
  }
  return true;
}

/** Best-effort binary signature sniff. Returns a hint string or null. */
export function sniffMagic(buffer) {
  if (!buffer || buffer.length < 4) return null;
  if (startsWith(buffer, [0x50, 0x4b, 0x03, 0x04]) || startsWith(buffer, [0x50, 0x4b, 0x05, 0x06])) return 'zip';
  if (startsWith(buffer, [0x1f, 0x8b])) return 'gzip';
  if (startsWith(buffer, [0x25, 0x50, 0x44, 0x46])) return 'pdf';       // %PDF
  if (startsWith(buffer, [0x89, 0x50, 0x4e, 0x47])) return 'png';
  if (startsWith(buffer, [0xff, 0xd8, 0xff])) return 'jpeg';
  if (startsWith(buffer, [0x47, 0x49, 0x46, 0x38])) return 'gif';
  if (buffer.length >= 12 && startsWith(buffer, [0x52, 0x49, 0x46, 0x46]) && startsWith(buffer, [0x57, 0x45, 0x42, 0x50], 8)) return 'webp';
  // TAR: "ustar" at offset 257
  if (buffer.length > 262 && startsWith(buffer, [0x75, 0x73, 0x74, 0x61, 0x72], 257)) return 'tar';
  return null;
}

// ── Classification ────────────────────────────────────────────────────────────

/**
 * @param {string} filename
 * @param {Buffer} [buffer] - raw bytes if available (magic verification)
 * @returns {{ kind: string, ext: string, mime: string|null, archiveFormat?: string, corrupt?: boolean }}
 */
export function classifyUpload(filename, buffer = null) {
  const base = path.basename(filename).toLowerCase();
  let ext = path.extname(base);
  // Compound extension: .tar.gz classifies as tar.gz, not bare .gz
  const isTarGz = base.endsWith('.tar.gz') || base.endsWith('.tgz');

  const magic = buffer ? sniffMagic(buffer) : null;

  // ── Repositories / archives ──
  if (ARCHIVE_EXTS.has(ext) || isTarGz) {
    let archiveFormat = null;
    if (ext === '.zip')            archiveFormat = 'zip';
    else if (isTarGz)              archiveFormat = 'tar.gz';
    else if (ext === '.tar')       archiveFormat = 'tar';
    else if (ext === '.gz')        archiveFormat = 'gz'; // single gzipped file — treated as tar.gz attempt then plain gunzip

    // Magic verification: named .zip but bytes disagree → corrupt, not misrouted.
    let corrupt = false;
    if (magic) {
      if (archiveFormat === 'zip'    && magic !== 'zip')  corrupt = true;
      if (archiveFormat === 'tar'    && magic !== 'tar')  corrupt = true;
      if ((archiveFormat === 'tar.gz' || archiveFormat === 'gz') && magic !== 'gzip') corrupt = true;
    }
    return { kind: 'repository', ext, mime: null, archiveFormat, corrupt };
  }

  if (DOCUMENT_EXTS.has(ext)) {
    const corrupt = ext === '.pdf' && magic !== null && magic !== 'pdf';
    return { kind: 'document', ext, mime: MIME_BY_EXT[ext] ?? null, corrupt };
  }
  if (IMAGE_EXTS.has(ext)) return { kind: 'image', ext, mime: MIME_BY_EXT[ext] ?? 'application/octet-stream' };
  if (AUDIO_EXTS.has(ext)) return { kind: 'audio', ext, mime: MIME_BY_EXT[ext] ?? 'application/octet-stream' };
  if (VIDEO_EXTS.has(ext)) return { kind: 'video', ext, mime: MIME_BY_EXT[ext] ?? 'application/octet-stream' };

  if (SOURCE_EXTS.has(ext) || isKnownExtensionless(base)) {
    return { kind: 'source', ext, mime: 'text/plain' };
  }

  // Unknown extension but bytes look like an archive/document → trust the bytes.
  if (magic === 'zip')  return { kind: 'repository', ext, mime: null, archiveFormat: 'zip' };
  if (magic === 'gzip') return { kind: 'repository', ext, mime: null, archiveFormat: 'tar.gz' };
  if (magic === 'tar')  return { kind: 'repository', ext, mime: null, archiveFormat: 'tar' };
  if (magic === 'pdf')  return { kind: 'document', ext: '.pdf', mime: 'application/pdf' };
  if (magic === 'png')  return { kind: 'image', ext: '.png', mime: 'image/png' };
  if (magic === 'jpeg') return { kind: 'image', ext: '.jpg', mime: 'image/jpeg' };

  return { kind: 'unknown', ext, mime: null };
}

function isKnownExtensionless(base) {
  return ['dockerfile', 'makefile', 'gemfile', 'procfile', 'license', 'readme', 'cmakelists.txt'].includes(base)
    || base.startsWith('.env');
}

export const SUPPORTED_FORMATS = {
  repository: ['zip', 'tar', 'tar.gz', 'tgz', 'folder (multi-file)'],
  source:     [...SOURCE_EXTS].map(e => e.slice(1)),
  document:   [...DOCUMENT_EXTS].map(e => e.slice(1)),
  image:      [...IMAGE_EXTS].map(e => e.slice(1)),
  audio:      [...AUDIO_EXTS].map(e => e.slice(1)),
  video:      [...VIDEO_EXTS].map(e => e.slice(1)),
};

/**
 * AQUA Archive Extractor — Day 5
 *
 * ZIP was already handled (fileIngester.extractZip, adm-zip). TAR and TAR.GZ
 * were flatly rejected. This module unifies all three behind one call:
 *
 *   extractArchive(buffer, format) → rawFiles[{ path, content, encoding? }]
 *
 * TAR is hand-rolled deliberately — the format is 512-byte header blocks +
 * padded content, ~70 lines to read safely, versus pulling in a streaming
 * dependency for a buffer we already hold in memory. GZIP uses Node's
 * built-in zlib. Zero new dependencies.
 *
 * Same safety budget as the ZIP path (entry count / per-entry size / total
 * size), same ignore-rule pre-filter, same base64 carry-through for binary
 * document formats so downstream ingestion is IDENTICAL regardless of
 * which archive format the user happened to pick.
 */
import path from 'path';
import zlib from 'zlib';
import { promisify } from 'util';
import { shouldIgnore } from '../project/fileIngester.js';
import { isDocumentExt } from '../project/documentParser.js';

const gunzip = promisify(zlib.gunzip);

// Mirrors fileIngester's ZIP caps — one budget for every archive format.
const MAX_ENTRIES     = 10_000;
const MAX_ENTRY_BYTES = 20_000_000;   // 20 MB uncompressed per entry
const MAX_TOTAL_BYTES = 300_000_000;  // 300 MB total extraction budget
const MAX_GZIP_RATIO  = 200;          // gzip bomb guard: 300 MB budget / declared compressed size

// ── TAR parsing ───────────────────────────────────────────────────────────────

function readTarString(buffer, offset, length) {
  const end = Math.min(offset + length, buffer.length);
  let nul = offset;
  while (nul < end && buffer[nul] !== 0) nul++;
  return buffer.toString('utf8', offset, nul);
}

function readTarOctal(buffer, offset, length) {
  const raw = readTarString(buffer, offset, length).trim();
  if (!raw) return 0;
  const n = parseInt(raw, 8);
  return Number.isFinite(n) ? n : 0;
}

function isZeroBlock(buffer, offset) {
  for (let i = 0; i < 512; i++) {
    if (buffer[offset + i] !== 0) return false;
  }
  return true;
}

/**
 * Parse a TAR buffer into entries. Supports ustar + GNU/PAX long names
 * (typeflag 'L' and PAX 'x' path records — both appear in real-world
 * archives produced by `tar czf` on deep trees).
 *
 * @param {Buffer} buffer
 * @returns {Array<{ name: string, data: Buffer }>}
 */
export function parseTar(buffer) {
  const entries = [];
  let offset = 0;
  let pendingLongName = null;

  while (offset + 512 <= buffer.length) {
    if (isZeroBlock(buffer, offset)) break; // end-of-archive marker

    const name     = readTarString(buffer, offset, 100);
    const size     = readTarOctal(buffer, offset + 124, 12);
    const typeflag = String.fromCharCode(buffer[offset + 156] || 0x30);
    const prefix   = readTarString(buffer, offset + 345, 155);

    const dataStart = offset + 512;
    const dataEnd   = dataStart + size;
    if (dataEnd > buffer.length) {
      throw new Error('Truncated TAR archive — entry data runs past end of file');
    }

    if (typeflag === 'L') {
      // GNU long name: data block IS the real name of the NEXT entry
      pendingLongName = buffer.toString('utf8', dataStart, dataEnd).replace(/\0+$/, '');
    } else if (typeflag === 'x' || typeflag === 'g') {
      // PAX extended header — pull path= record if present
      const pax = buffer.toString('utf8', dataStart, dataEnd);
      const m = pax.match(/\d+ path=([^\n]+)\n/);
      if (m) pendingLongName = m[1];
    } else if (typeflag === '0' || typeflag === '\0' || typeflag === '') {
      // Regular file
      let entryName = pendingLongName ?? (prefix ? `${prefix}/${name}` : name);
      pendingLongName = null;
      entryName = entryName.replace(/^\.\//, '');
      if (entryName) {
        entries.push({ name: entryName, data: buffer.subarray(dataStart, dataEnd) });
      }
    } else {
      // Directory / link / device / etc — skip, but a long name applies to it
      pendingLongName = null;
    }

    // Advance: header + data rounded up to the next 512-byte boundary
    offset = dataStart + Math.ceil(size / 512) * 512;
  }

  return entries;
}

// ── Path safety ───────────────────────────────────────────────────────────────

/** Archive entry names are attacker-controlled — normalize + reject traversal. */
function sanitizeEntryPath(name) {
  const normalized = name.replace(/\\/g, '/').replace(/^\/+/, '');
  const parts = normalized.split('/').filter(p => p && p !== '.');
  if (parts.some(p => p === '..')) return null; // zip-slip / tar-slip attempt
  return parts.join('/');
}

// ── Unified conversion: archive entries → ingestable rawFiles ─────────────────

function entriesToRawFiles(entries) {
  const files = [];
  let totalBytes = 0;
  let skippedOversize = 0;

  for (const entry of entries) {
    const entryPath = sanitizeEntryPath(entry.name);
    if (!entryPath) continue;

    if (entry.data.length > MAX_ENTRY_BYTES) { skippedOversize++; continue; }
    totalBytes += entry.data.length;
    if (totalBytes > MAX_TOTAL_BYTES) {
      throw new Error('Archive expands beyond the 300 MB extraction budget — likely includes dependencies or binaries. Trim it and retry.');
    }

    const ext = path.extname(entryPath).toLowerCase();
    if (!isDocumentExt(ext) && shouldIgnore(entryPath)) continue;

    if (isDocumentExt(ext)) {
      // Binary document — carry raw bytes as base64 (same contract as extractZip)
      files.push({ path: entryPath, content: entry.data.toString('base64'), encoding: 'base64' });
      continue;
    }

    files.push({ path: entryPath, content: entry.data.toString('utf8') });
  }

  if (skippedOversize) console.warn(`[UPLOAD] Skipped ${skippedOversize} oversize archive entries (> ${MAX_ENTRY_BYTES / 1e6} MB each)`);
  return files;
}

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Extract any supported archive format into the rawFiles shape ingestFiles()
 * consumes.
 *
 * @param {Buffer} buffer  - raw archive bytes
 * @param {'zip'|'tar'|'tar.gz'|'gz'} format
 * @returns {Promise<Array<{ path: string, content: string, encoding?: 'base64' }>>}
 * @throws {Error} corrupt archive / bomb budget exceeded / password-protected
 */
export async function extractArchive(buffer, format) {
  switch (format) {
    case 'zip': {
      const { default: AdmZip } = await import('adm-zip');
      let zip;
      try {
        zip = new AdmZip(buffer);
      } catch (err) {
        throw new Error(`Corrupted or unreadable ZIP archive: ${err.message}`);
      }
      const zipEntries = zip.getEntries();
      if (zipEntries.length > MAX_ENTRIES) {
        throw new Error(`Archive has ${zipEntries.length} entries (limit ${MAX_ENTRIES}). Remove build artifacts (node_modules, dist) before zipping.`);
      }
      const entries = [];
      for (const e of zipEntries) {
        if (e.isDirectory) continue;
        // Password-protected ZIPs: adm-zip's getData() throws or returns empty
        // on encrypted entries — surface a clear error instead of silence.
        if (e.header?.flags & 0x1) {
          throw new Error('Archive is password-protected. Remove the password and re-upload.');
        }
        const declared = e.header?.size ?? 0;
        if (declared > MAX_ENTRY_BYTES) continue; // pre-filter before decompressing
        let data;
        try { data = e.getData(); } catch { continue; }
        entries.push({ name: e.entryName, data });
      }
      return entriesToRawFiles(entries);
    }

    case 'tar': {
      const entries = parseTar(buffer);
      if (entries.length > MAX_ENTRIES) {
        throw new Error(`Archive has ${entries.length} entries (limit ${MAX_ENTRIES}).`);
      }
      return entriesToRawFiles(entries);
    }

    case 'tar.gz':
    case 'gz': {
      let inflated;
      try {
        inflated = await gunzip(buffer, { maxOutputLength: Math.min(MAX_TOTAL_BYTES, buffer.length * MAX_GZIP_RATIO) });
      } catch (err) {
        if (err.code === 'ERR_BUFFER_TOO_LARGE' || /output length/i.test(err.message)) {
          throw new Error('Gzip stream expands beyond the extraction budget — refusing to decompress.');
        }
        throw new Error(`Corrupted gzip stream: ${err.message}`);
      }
      // .tgz / .tar.gz — the inflated payload should be a TAR. A bare .gz of
      // a single file is legal too: fall back to treating the payload as one file.
      try {
        const entries = parseTar(inflated);
        if (entries.length > 0) {
          if (entries.length > MAX_ENTRIES) throw new Error(`Archive has ${entries.length} entries (limit ${MAX_ENTRIES}).`);
          return entriesToRawFiles(entries);
        }
      } catch (tarErr) {
        if (format === 'tar.gz') throw new Error(`Invalid .tar.gz: ${tarErr.message}`);
      }
      // Bare gzip of one file
      return entriesToRawFiles([{ name: 'extracted-file', data: inflated }]);
    }

    default:
      throw new Error(`Unsupported archive format: ${format}`);
  }
}

/**
