/**
 * AQUA Document Pipeline — Day 5
 *
 * Wraps + extends project/documentParser.js (PDF/DOCX/PPTX/XLSX, unchanged)
 * with three new formats — CSV, ODT, EPUB — and normalizes EVERY document
 * into one shape the rest of the platform consumes:
 *
 *   {
 *     title:     string,          // best-effort (metadata > filename)
 *     format:    string,          // 'pdf' | 'docx' | ... 
 *     metadata:  object,          // pages / sheets / slides / warnings / ...
 *     content:   string,          // full extracted text (capped)
 *     pages:     number|null,
 *     sections:  [{ heading, text }],  // coarse structural split
 *     language:  string|null,     // cheap heuristic, null when unsure
 *     truncated: boolean,
 *   }
 *
 * ODT and EPUB reuse adm-zip (already a dependency) — both are ZIP
 * containers of XML/XHTML. No new dependencies.
 */
import path from 'path';
import AdmZip from 'adm-zip';
import { parseDocument, isDocumentExt as isCoreDocumentExt } from '../project/documentParser.js';

const MAX_CONTENT_CHARS = 200_000; // richer than code files (100 KB) — documents ARE the content
export const PIPELINE_DOCUMENT_EXTS = new Set(['.pdf', '.docx', '.pptx', '.xlsx', '.csv', '.odt', '.epub']);

export function isPipelineDocumentExt(ext) {
  return PIPELINE_DOCUMENT_EXTS.has(ext);
}

// ── XML text extraction helpers ───────────────────────────────────────────────

function stripXml(xml) {
  return xml
    .replace(/<text:line-break[^>]*\/>/g, '\n')
    .replace(/<text:p[^>]*>/g, '\n')
    .replace(/<\/text:p>/g, '')
    .replace(/<(p|div|br|h[1-6]|li|tr)[^>]*>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&apos;/g, "'").replace(/&#(\d+);/g, (_, n) => String.fromCharCode(+n))
    .replace(/&amp;/g, '&')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// ── ODT ───────────────────────────────────────────────────────────────────────

function parseOdt(buffer) {
  const zip = new AdmZip(buffer);
  const contentEntry = zip.getEntry('content.xml');
  if (!contentEntry) throw new Error('Invalid ODT: content.xml missing');
  const text = stripXml(contentEntry.getData().toString('utf8'));

  let title = null;
  const metaEntry = zip.getEntry('meta.xml');
  if (metaEntry) {
    const m = metaEntry.getData().toString('utf8').match(/<dc:title>([^<]*)<\/dc:title>/);
    if (m) title = m[1].trim() || null;
  }
  return { text, meta: { title } };
}

// ── EPUB ──────────────────────────────────────────────────────────────────────

function parseEpub(buffer) {
  const zip = new AdmZip(buffer);

  // Locate the OPF via META-INF/container.xml (per spec); fall back to globbing.
  let opfPath = null;
  const container = zip.getEntry('META-INF/container.xml');
  if (container) {
    const m = container.getData().toString('utf8').match(/full-path="([^"]+)"/);
    if (m) opfPath = m[1];
  }
  const opfEntry = opfPath ? zip.getEntry(opfPath) : zip.getEntries().find(e => e.entryName.endsWith('.opf'));
  if (!opfEntry) throw new Error('Invalid EPUB: package (.opf) file missing');

  const opfXml = opfEntry.getData().toString('utf8');
  const opfDir = path.posix.dirname(opfEntry.entryName);

  const titleMatch = opfXml.match(/<dc:title[^>]*>([^<]*)<\/dc:title>/);
  const title = titleMatch ? titleMatch[1].trim() : null;

  // Spine order: itemrefs → manifest hrefs
  const manifest = {};
  for (const m of opfXml.matchAll(/<item\s+[^>]*id="([^"]+)"[^>]*href="([^"]+)"[^>]*>/g)) {
    manifest[m[1]] = m[2];
  }
  // Attribute order varies — second pass with href before id
  for (const m of opfXml.matchAll(/<item\s+[^>]*href="([^"]+)"[^>]*id="([^"]+)"[^>]*>/g)) {
    manifest[m[2]] = manifest[m[2]] ?? m[1];
  }
  const spineIds = [...opfXml.matchAll(/<itemref\s+[^>]*idref="([^"]+)"/g)].map(m => m[1]);

  const chapters = [];
  for (const id of spineIds) {
    const href = manifest[id];
    if (!href || !/\.x?html?$/i.test(href)) continue;
    const entryName = opfDir === '.' ? href : path.posix.join(opfDir, href);
    const entry = zip.getEntry(entryName) ?? zip.getEntry(decodeURIComponent(entryName));
    if (!entry) continue;
    const chapterText = stripXml(entry.getData().toString('utf8'));
    if (chapterText) chapters.push(chapterText);
  }

  if (!chapters.length) throw new Error('EPUB contains no readable chapters');
  return { text: chapters.join('\n\n'), meta: { title, chapters: chapters.length } };
}

// ── CSV (text passthrough with light structure) ───────────────────────────────

function parseCsv(buffer) {
  const text = buffer.toString('utf8').trim();
  if (!text) throw new Error('CSV is empty');
  const lines = text.split(/\r?\n/);
  return { text, meta: { rows: lines.length, columns: (lines[0] ?? '').split(',').length } };
}

// ── Section splitting + language heuristic ────────────────────────────────────

function splitSections(text) {
  // Coarse: page/slide/sheet markers already embedded by the core parser,
  // otherwise blank-line paragraphs grouped into ≤10 sections.
  const markerRe = /^-- (Page|Slide|Sheet)[^\n]*--$/m;
  if (markerRe.test(text)) {
    return text.split(/^(?=-- (?:Page|Slide|Sheet))/m)
      .map(chunk => {
        const [first, ...rest] = chunk.split('\n');
        return { heading: first.trim(), text: rest.join('\n').trim() };
      })
      .filter(s => s.text)
      .slice(0, 100);
  }
  const paras = text.split(/\n{2,}/).filter(Boolean);
  const per = Math.max(1, Math.ceil(paras.length / 10));
  const sections = [];
  for (let i = 0; i < paras.length; i += per) {
    sections.push({ heading: null, text: paras.slice(i, i + per).join('\n\n') });
  }
  return sections;
}

const LANG_MARKERS = [
  ['en', /\b(the|and|of|to|is|in|that|for|with)\b/gi],
  ['es', /\b(el|la|de|que|y|los|las|una|para)\b/gi],
  ['fr', /\b(le|la|les|des|est|dans|pour|avec|une)\b/gi],
  ['de', /\b(der|die|das|und|ist|nicht|mit|für|ein)\b/gi],
  ['hi', /[\u0900-\u097F]/g],
  ['zh', /[\u4E00-\u9FFF]/g],
];

function detectLanguage(text) {
  const sample = text.slice(0, 4000);
  let best = null, bestCount = 0;
  for (const [lang, re] of LANG_MARKERS) {
    const count = (sample.match(re) ?? []).length;
    if (count > bestCount) { best = lang; bestCount = count; }
  }
  return bestCount >= 5 ? best : null;
}

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Extract + normalize any supported document.
 *
 * @param {string} filename
 * @param {Buffer} buffer
 * @returns {Promise<{ title, format, metadata, content, pages, sections, language, truncated }>}
 * @throws on unsupported ext / corrupt file / oversize (caller shows the message)
 */
export async function processDocument(filename, buffer) {
  const ext = path.extname(filename).toLowerCase();
  if (!PIPELINE_DOCUMENT_EXTS.has(ext)) {
    throw new Error(`Unsupported document format: ${ext || '(no extension)'}`);
  }

  let text, meta = {};

  if (isCoreDocumentExt(ext)) {
    // PDF / DOCX / PPTX / XLSX — reuse the existing extractor verbatim
    const extracted = await parseDocument(ext, buffer);
    if (!extracted?.text) throw new Error('No extractable text found in document');
    text = extracted.text;
    meta = extracted.meta ?? {};
  } else if (ext === '.csv') {
    ({ text, meta } = parseCsv(buffer));
  } else if (ext === '.odt') {
    ({ text, meta } = parseOdt(buffer));
  } else if (ext === '.epub') {
    ({ text, meta } = parseEpub(buffer));
  }

  if (!text?.trim()) throw new Error('Document contains no extractable text');

  let truncated = false;
  if (text.length > MAX_CONTENT_CHARS) {
    text = text.slice(0, MAX_CONTENT_CHARS) + '\n... [truncated]';
    truncated = true;
  }

  return {
    title:     meta.title ?? path.basename(filename),
    format:    ext.slice(1),
    metadata:  meta,
    content:   text,
    pages:     meta.pages ?? meta.slideCount ?? meta.sheetCount ?? meta.chapters ?? null,
    sections:  splitSections(text),
    language:  detectLanguage(text),
    truncated,
  };
}

/**
 * AQUA Media Pipeline — Day 5
 *
 * Image / audio / video understanding via Gemini multimodal (the ONE
 * provider in the stack that accepts inline media). Every result is
 * normalized to the same document shape the rest of the platform uses,
 * so a screenshot and a PDF are indistinguishable to chat retrieval.
 *
 * Design decisions:
 * - Vision analysis + OCR happen in ONE model call (structured prompt
 *   asking for description + verbatim text + objects + chart/UI reading).
 *   Two calls would double latency and cost for zero quality gain.
 * - SVG short-circuits: it's already text — read the markup, no model call.
 * - Fail loudly: no Gemini keys / oversize media / unsupported codec each
 *   return a distinct, user-readable error. Never a silent drop.
 * - Results are content-hash cached (in-memory LRU) — re-uploading the same
 *   screenshot never pays for a second model call.
 */
import crypto from 'crypto';
import { analyzeMediaWithGemini } from '../providers/gemini.js';

// Gemini inline-data hard limit is ~20 MB of request payload; base64 inflates
// 4/3 — stay safely under.
const MAX_IMAGE_BYTES = 12_000_000;
const MAX_AV_BYTES    = 14_000_000;
const MAX_SVG_BYTES   = 2_000_000;

// ── Result cache (content-addressed) ──────────────────────────────────────────

const CACHE_MAX = 100;
const cache = new Map(); // sha256 → result

function cacheKey(buffer) {
  return crypto.createHash('sha256').update(buffer).digest('hex');
}

function cacheGet(key)      { return cache.get(key) ?? null; }
function cacheSet(key, val) {
  if (cache.size >= CACHE_MAX) cache.delete(cache.keys().next().value); // FIFO evict
  cache.set(key, val);
}

// ── Prompts ───────────────────────────────────────────────────────────────────

const IMAGE_PROMPT = `Analyze this image thoroughly. Respond in exactly this structure:

CAPTION: one-sentence description.

DESCRIPTION: detailed description of what the image shows — layout, subjects, colors, context.

TEXT (OCR): every piece of readable text in the image, verbatim, preserving structure. Write "none" if there is no text.

OBJECTS: comma-separated list of notable objects/elements.

SPECIAL: if this is a screenshot, describe the UI (app, screen, controls, state). If it is a chart/graph, read out the data. If it is a diagram or architecture drawing, explain the components and their relationships. Otherwise write "n/a".`;

const AUDIO_PROMPT = `Analyze this audio. Respond in exactly this structure:

SUMMARY: one-paragraph summary of the audio content.

TRANSCRIPT: full transcription of any speech, verbatim. Write "none" if there is no speech.

DETAILS: speakers, tone, music, notable sounds, approximate structure.`;

const VIDEO_PROMPT = `Analyze this video. Respond in exactly this structure:

SUMMARY: one-paragraph summary of what happens.

TRANSCRIPT: transcription of any speech, verbatim. Write "none" if there is no speech.

SCENES: chronological outline of key scenes/moments.

TEXT ON SCREEN: any readable on-screen text. Write "none" if there is none.`;

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * @param {string} filename
 * @param {Buffer} buffer
 * @param {string} mime   - from uploadClassifier
 * @param {'image'|'audio'|'video'} kind
 * @returns {Promise<{ title, format, metadata, content, pages, sections, language, truncated }>}
 */
export async function processMedia(filename, buffer, mime, kind) {
  // SVG is text — no model call needed, but still normalize.
  if (mime === 'image/svg+xml') {
    if (buffer.length > MAX_SVG_BYTES) throw new Error('SVG exceeds the 2 MB limit');
    const markup = buffer.toString('utf8');
    const textNodes = [...markup.matchAll(/<(?:text|tspan)[^>]*>([^<]+)</g)].map(m => m[1].trim()).filter(Boolean);
    const content = [
      `SVG vector image "${filename}" (${buffer.length} bytes).`,
      textNodes.length ? `Text in SVG: ${textNodes.join(' | ')}` : 'No text elements.',
      '',
      'Raw SVG markup (truncated to 20 KB):',
      markup.slice(0, 20_000),
    ].join('\n');
    return normalize(filename, 'svg', { analyzed: false }, content);
  }

  const limit = kind === 'image' ? MAX_IMAGE_BYTES : MAX_AV_BYTES;
  if (buffer.length > limit) {
    throw new Error(`${kind === 'image' ? 'Image' : kind === 'audio' ? 'Audio file' : 'Video'} exceeds the ${Math.round(limit / 1e6)} MB analysis limit (${(buffer.length / 1e6).toFixed(1)} MB). Compress it and retry.`);
  }

  const key = cacheKey(buffer);
  const cached = cacheGet(key);
  if (cached) {
    console.log(`[UPLOAD] Media analysis cache hit ${filename}`);
    return cached;
  }

  const prompt = kind === 'image' ? IMAGE_PROMPT : kind === 'audio' ? AUDIO_PROMPT : VIDEO_PROMPT;

  const parts = [
    { inlineData: { mimeType: mime, data: buffer.toString('base64') } },
    { text: prompt },
  ];

  let analysis;
  try {
    analysis = await analyzeMediaWithGemini(parts, {
      systemPrompt: 'You are a precise media analysis engine. Follow the requested structure exactly. Transcribe text verbatim.',
      maxTokens: kind === 'image' ? 2048 : 4096,
    });
  } catch (err) {
    throw new Error(`${kind[0].toUpperCase() + kind.slice(1)} analysis failed: ${err.message}`);
  }

  const result = normalize(
    filename,
    mime.split('/')[1] ?? kind,
    { analyzed: true, model: analysis.model, bytes: buffer.length },
    analysis.text,
  );
  cacheSet(key, result);
  return result;
}

function normalize(filename, format, metadata, content) {
  const sections = content
    .split(/\n(?=[A-Z][A-Z ()]+:)/)
    .map(chunk => {
      const m = chunk.match(/^([A-Z][A-Z ()]+):\s*([\s\S]*)$/);
      return m ? { heading: m[1].trim(), text: m[2].trim() } : { heading: null, text: chunk.trim() };
    })
    .filter(s => s.text);

  return {
    title:     filename,
    format,
    metadata,
    content,
    pages:     null,
    sections,
    language:  null,
    truncated: false,
  };
}

/**
 * AQUA Attachment Store — Day 5
 *
 * The "immediately available to the current conversation" half of the
 * universal upload contract. Every processed upload (document, image,
 * audio, video, single source file) is registered here against a
 * conversationId; chat.js's prepareTurn() pulls the registered content
 * into the system prompt on the very next turn — no re-processing, no
 * re-upload, no user action.
 *
 * Repositories are NOT stored here — they attach as a workspaceId (the
 * existing project-context path), which retrieval already handles better
 * than a flat content blob ever could.
 *
 * In-memory by design, matching conversationStore.js's persistence model
 * exactly — attachments live as long as the conversation store does.
 */
import { v4 as uuidv4 } from 'uuid';

const MAX_ATTACHMENTS_PER_CONVERSATION = 20;
const MAX_INJECTED_CHARS_TOTAL         = 120_000; // context-window protection
const MAX_INJECTED_CHARS_PER_DOC       = 60_000;

/** conversationId → [{ id, name, kind, format, title, content, metadata, sections, pages, language, truncated, uploadedAt }] */
const store = new Map();

// ── Write ─────────────────────────────────────────────────────────────────────

export function attachToConversation(conversationId, { name, kind, normalized }) {
  if (!conversationId) throw new Error('conversationId required to attach content');

  const list = store.get(conversationId) ?? [];
  if (list.length >= MAX_ATTACHMENTS_PER_CONVERSATION) {
    // Evict the oldest — a 21st upload should never hard-fail the request.
    list.shift();
    console.warn(`[UPLOAD] Attachment cap reached conversation=${conversationId} — evicted oldest`);
  }

  const attachment = {
    id:         uuidv4(),
    name,
    kind,                             // 'document' | 'image' | 'audio' | 'video' | 'source'
    format:     normalized.format,
    title:      normalized.title,
    content:    normalized.content,
    metadata:   normalized.metadata,
    sections:   normalized.sections,
    pages:      normalized.pages,
    language:   normalized.language,
    truncated:  normalized.truncated,
    uploadedAt: Date.now(),
  };

  list.push(attachment);
  store.set(conversationId, list);
  console.log(`[UPLOAD] Attached ${kind} "${name}" conversation=${conversationId} chars=${normalized.content.length}`);
  return attachment;
}

// ── Read ──────────────────────────────────────────────────────────────────────

export function getAttachments(conversationId) {
  return store.get(conversationId) ?? [];
}

export function removeAttachment(conversationId, attachmentId) {
  const list = store.get(conversationId);
  if (!list) return false;
  const idx = list.findIndex(a => a.id === attachmentId);
  if (idx === -1) return false;
  list.splice(idx, 1);
  return true;
}

export function clearAttachments(conversationId) {
  return store.delete(conversationId);
}

/** Metadata-only view — safe for API listing (no full content). */
export function serializeAttachment(a) {
  return {
    id: a.id, name: a.name, kind: a.kind, format: a.format, title: a.title,
    pages: a.pages, language: a.language, truncated: a.truncated,
    contentChars: a.content.length, uploadedAt: a.uploadedAt,
    metadata: a.metadata,
  };
}

// ── Prompt injection ──────────────────────────────────────────────────────────

const KIND_LABEL = {
  document: 'Document',
  image:    'Image (vision analysis + OCR below)',
  audio:    'Audio (transcription + analysis below)',
  video:    'Video (transcription + analysis below)',
  source:   'File',
};

/**
 * Format all conversation attachments as a system-prompt block. Newest
 * first (most recently uploaded = most likely subject of the question);
 * older attachments degrade to summaries when the total budget is hit —
 * never silently vanish, the model is TOLD what was elided.
 */
export function formatAttachmentsForPrompt(conversationId) {
  const list = getAttachments(conversationId);
  if (!list.length) return '';

  const blocks = [];
  let budget = MAX_INJECTED_CHARS_TOTAL;

  for (const a of [...list].reverse()) {
    const header = `── ${KIND_LABEL[a.kind] ?? 'Attachment'}: ${a.name}` +
      (a.pages ? ` (${a.pages} ${a.format === 'pptx' ? 'slides' : a.format === 'xlsx' ? 'sheets' : 'pages'})` : '') +
      (a.truncated ? ' [content truncated]' : '') + ' ──';

    let body = a.content;
    if (body.length > MAX_INJECTED_CHARS_PER_DOC) body = body.slice(0, MAX_INJECTED_CHARS_PER_DOC) + '\n... [truncated for context]';

    if (body.length + header.length > budget) {
      // Budget exhausted — include a stub so the model knows the file exists.
      blocks.push(`${header}\n[Content omitted to fit context — ${a.content.length} chars. Ask about "${a.name}" specifically to prioritize it.]`);
      continue;
    }

    budget -= body.length + header.length;
    blocks.push(`${header}\n${body}`);
  }

  return [
    'UPLOADED ATTACHMENTS (available in this conversation — answer questions about them directly):',
    ...blocks,
  ].join('\n\n');
}

export function getAttachmentStats() {
  let total = 0;
  for (const list of store.values()) total += list.length;
  return { conversations: store.size, attachments: total };
}

/**
 * AQUA Patch Generator
 *
 * Formats proposed multi-file changes as structured patch objects.
 * Generates unified-diff-style output for readability.
 *
 * NEVER modifies files automatically. Output is review-only.
 */

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Format a proposed change set.
 *
 * @param {{ description, reasoning, changes: Array<{file, original?, modified, explanation}> }} proposal
 * @returns {PatchResult}
 */
export function formatPatch(proposal) {
  const { description, reasoning, changes = [] } = proposal;

  const patches = changes.map(ch => ({
    file:        ch.file,
    explanation: ch.explanation ?? '',
    diff:        _diff(ch.file, ch.original ?? '', ch.modified ?? ''),
  }));

  return {
    description,
    reasoning,
    filesAffected: patches.map(p => p.file),
    patches,
    note: 'Proposed change — review carefully before applying.',
  };
}

/**
 * Render a PatchResult as a Markdown block for inclusion in LLM responses.
 */
export function formatPatchForPrompt(patchResult) {
  if (!patchResult?.patches?.length) return '';

  const lines = [
    '## Proposed Changes',
    `**${patchResult.description}**`,
    '',
    `**Reasoning:** ${patchResult.reasoning}`,
    `**Files affected:** ${patchResult.filesAffected.join(', ')}`,
  ];

  for (const p of patchResult.patches) {
    lines.push('', `### ${p.file}`);
    if (p.explanation) lines.push(p.explanation);
    lines.push('```diff', p.diff, '```');
  }

  lines.push('', `> ⚠️ ${patchResult.note}`);
  return lines.join('\n');
}

// ── Diff generation ───────────────────────────────────────────────────────────
// Day 4: delegates to diffEngine.js (real LCS + hunks) instead of the old
// greedy 4-line-lookahead scan. Same unified-diff output contract.

import { diffFile } from './diffEngine.js';

function _diff(filename, original, modified) {
  const d = diffFile(filename, original ?? '', modified ?? '');
  if (!d.stats.added && !d.stats.removed) return `// No changes in ${filename}`;
  return d.unified;
}

/**
 * AQUA Document Parser
 *
 * Real content extraction for binary document formats. Previously these
 * never reached fileParser.js at all: fileIngester.js's IGNORE_EXTS
 * dropped .pdf by explicit extension, and .docx/.pptx/.xlsx were silently
 * caught by the isBinary() heuristic on their zip-compressed bytes, since
 * the whole ingestion pipeline assumed text content (routes/project.js's
 * upload contract is JSON: { files: [{ path, content: string }] } or a
 * base64 zip — nothing here previously carried raw binary bytes safely).
 *
 * This module extracts real text so these formats can flow through the
 * exact same { path, content, lang } shape fileParser.js / projectIndex.js
 * / projectSummarizer.js / projectRetriever.js already handle generically
 * for code files — confirmed by reading all four: none of them assume a
 * code-language lang value, all fall back gracefully. No changes needed
 * in any of them.
 *
 * Supported: PDF (pdf-parse v2), DOCX (mammoth), XLSX (xlsx / SheetJS).
 * PPTX is hand-rolled rather than a new dependency: adm-zip is already in
 * package.json, and PPTX is itself a zip of XML — a full OOXML
 * relationship-graph reader is unnecessary when every real PowerPoint
 * file places slides at ppt/slides/slideN.xml, so this just globs that
 * path and sorts numerically (zip entry order is lexicographic, so
 * slide10.xml sorts before slide2.xml without this).
 *
 * Images, video, and audio are NOT handled here. That needs OCR /
 * transcription — a materially bigger dependency, and often a model
 * call rather than a local library — and was scoped out as a separate
 * phase in the original architecture audit, not attempted here.
 */
import AdmZip           from 'adm-zip';
import { PDFParse }     from 'pdf-parse';
import mammoth          from 'mammoth';
import * as XLSX        from 'xlsx';

// Raw byte ceiling BEFORE extraction. Intentionally more generous than
// fileIngester.js's MAX_FILE_SIZE (100KB), which caps EXTRACTED TEXT
// afterward — same truncation every other file type already goes
// through. Two independent caps: one on what we're willing to spend
// CPU/memory parsing, one on what we're willing to inject as context.
const MAX_DOCUMENT_BYTES = 15_000_000; // 15MB

export const DOCUMENT_EXTS = new Set(['.pdf', '.docx', '.pptx', '.xlsx']);

export function isDocumentExt(ext) {
  return DOCUMENT_EXTS.has(ext);
}

// ── PDF (pdf-parse v2 — constructor + async getText(), not the v1 pdf(buffer) API) ──

async function parsePdf(buffer) {
  const parser = new PDFParse({ data: buffer });
  try {
    const result = await parser.getText();
    return { text: result.text.trim(), pages: result.total ?? null };
  } finally {
    await parser.destroy(); // required — frees the underlying worker/memory
  }
}

// ── DOCX ──────────────────────────────────────────────────────────────────────

async function parseDocx(buffer) {
  const result = await mammoth.extractRawText({ buffer });
  return { text: result.value.trim(), warnings: result.messages.length };
}

// ── XLSX ──────────────────────────────────────────────────────────────────────

async function parseXlsx(buffer) {
  const workbook = XLSX.read(buffer, { type: 'buffer' });
  const sheets = workbook.SheetNames.map(name => {
    const csv = XLSX.utils.sheet_to_csv(workbook.Sheets[name]).trim();
    return `-- Sheet: ${name} --\n${csv}`;
  }).filter(s => !s.endsWith('--')); // drop genuinely empty sheets (header line only, no rows, produces '')

  return { text: sheets.join('\n\n').trim(), sheetCount: workbook.SheetNames.length };
}

// ── PPTX (hand-rolled: glob ppt/slides/slideN.xml via the existing adm-zip dep) ──

const SLIDE_PATH_RE = /^ppt\/slides\/slide(\d+)\.xml$/;
const TEXT_RUN_RE   = /<a:t[^>]*>(.*?)<\/a:t>/gs;

function decodeXmlEntities(s) {
  return s
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&apos;/g, "'")
    .replace(/&amp;/g, '&'); // last — must not re-decode entities produced by the others
}

function parsePptx(buffer) {
  const zip = new AdmZip(buffer);

  const slides = zip.getEntries()
    .map(entry => ({ match: entry.entryName.match(SLIDE_PATH_RE), entry }))
    .filter(x => x.match)
    .map(({ match, entry }) => ({
      num: parseInt(match[1], 10),           // numeric, not lexicographic — slide10 must sort after slide2
      xml: entry.getData().toString('utf8'),
    }))
    .sort((a, b) => a.num - b.num)
    .map(({ num, xml }) => {
      const runs = [...xml.matchAll(TEXT_RUN_RE)].map(m => decodeXmlEntities(m[1]));
      const text = runs.join(' ').replace(/\s+/g, ' ').trim();
      return { num, text };
    })
    .filter(s => s.text.length > 0)          // skip slides with no text runs (image-only, etc.)
    .map(s => `-- Slide ${s.num} --\n${s.text}`);

  return { text: slides.join('\n\n').trim(), slideCount: slides.length };
}

// ── Dispatcher ────────────────────────────────────────────────────────────────

/**
 * Extract text from a document buffer, dispatched by extension.
 *
 * @param {string} ext     - lowercase extension including the dot, e.g. '.pdf'
 * @param {Buffer} buffer  - raw file bytes (already base64-decoded by the caller)
 * @returns {Promise<{ text: string, meta: object } | null>} null if ext isn't one of DOCUMENT_EXTS
 * @throws if the buffer exceeds MAX_DOCUMENT_BYTES, or the underlying library can't parse it
 *         (corrupt file, password-protected, etc.) — caller decides how to handle (see
 *         fileIngester.js, which skips the single file and continues the batch)
 */
export async function parseDocument(ext, buffer) {
  if (!DOCUMENT_EXTS.has(ext)) return null;

  if (buffer.length > MAX_DOCUMENT_BYTES) {
    throw new Error(`Document exceeds ${MAX_DOCUMENT_BYTES}-byte limit (${buffer.length} bytes)`);
  }

  switch (ext) {
    case '.pdf': {
      const { text, pages } = await parsePdf(buffer);
      return { text, meta: { pages } };
    }
    case '.docx': {
      const { text, warnings } = await parseDocx(buffer);
      return { text, meta: { warnings } };
    }
    case '.xlsx': {
      const { text, sheetCount } = await parseXlsx(buffer);
      return { text, meta: { sheetCount } };
    }
    case '.pptx': {
      const { text, slideCount } = parsePptx(buffer);
      return { text, meta: { slideCount } };
    }
    /* istanbul ignore next -- unreachable: ext already checked against DOCUMENT_EXTS above */
    default:
      return null;
  }
}

/**
 * AQUA Workspace Manager
 *
 * Each uploaded project receives a unique workspace ID.
 * Tracks: files, directory structure, metadata, language, indexing status,
 *         summaries, and dependency graph.
 */
import { v4 as uuidv4 } from 'uuid';
import {
  saveWorkspace, loadWorkspace,
  deleteWorkspaceData, getAllWorkspaceIds, getProjectStats,
} from './projectMemory.js';

// ── Public API ────────────────────────────────────────────────────────────────

export function createWorkspace(meta = {}) {
  const id = uuidv4();
  const workspace = {
    id,
    ownerId:   meta.ownerId ?? null,   // unified owner model — memory/ownerResolver.js
    createdAt: Date.now(),
    meta,
    projectType:  null,
    files:        [],       // [{ path, lang, size, summary, parsedAt }]
    structure:    {},       // directory tree
    indexStatus:  'pending',
    summary:      null,     // project-level architecture summary
    stats:        { files: 0, languages: {} },
    indexedAt:    null,
  };
  saveWorkspace(id, workspace);
  console.log(`[PROJECT] Workspace created id=${id}`);
  return workspace;
}

export function getWorkspace(id) {
  return loadWorkspace(id);
}

export function updateWorkspace(id, updates) {
  const ws = loadWorkspace(id);
  if (!ws) return null;
  const updated = { ...ws, ...updates };
  saveWorkspace(id, updated);
  return updated;
}

export function deleteWorkspace(id) {
  const deleted = deleteWorkspaceData(id);
  if (deleted) console.log(`[PROJECT] Workspace deleted id=${id}`);
  return deleted;
}

export function listWorkspaces() {
  return getAllWorkspaceIds()
    .map(id => loadWorkspace(id))
    .filter(Boolean);
}

export { getProjectStats };

/**
 * AQUA File Parser
 *
 * Language-specific extraction using regex (no AST — zero extra dependencies).
 * Extracts: functions, classes, methods, imports, exports, interfaces, doc comments.
 * Config files produce: dependencies, scripts, keywords.
 *
 * Supported: JavaScript, TypeScript, Python, Java, Kotlin, Go, Rust, C#, PHP, JSON, Markdown.
 * Also PDF, DOCX, PPTX, XLSX — text already extracted by project/documentParser.js
 * by the time it reaches here; this just pulls a short preview into `comments`,
 * same role parseMarkdown() plays for # / ## headers.
 */
import path from 'path';

// ── Dispatcher ────────────────────────────────────────────────────────────────

/**
 * Parse a single file into structured metadata.
 *
 * @param {string} filePath
 * @param {string} content
 * @param {string} lang
 * @returns {ParsedFile}
 */
export function parseFile(filePath, content, lang) {
  const base = {
    path:         filePath,
    lang,
    size:         content.length,
    functions:    [],
    classes:      [],
    imports:      [],
    exports:      [],
    interfaces:   [],
    comments:     [],
    dependencies: [],
    keywords:     [],
  };

  try {
    switch (lang) {
      case 'javascript':
      case 'typescript':
        return { ...base, ...parseJS(content) };
      case 'python':
        return { ...base, ...parsePython(content) };
      case 'java':
      case 'kotlin':
        return { ...base, ...parseJava(content) };
      case 'go':
        return { ...base, ...parseGo(content) };
      case 'rust':
        return { ...base, ...parseRust(content) };
      case 'csharp':
        return { ...base, ...parseCSharp(content) };
      case 'php':
        return { ...base, ...parsePHP(content) };
      case 'json':
        return { ...base, ...parseJSON(filePath, content) };
      case 'markdown':
        return { ...base, ...parseMarkdown(content) };
      case 'pdf':
      case 'docx':
      case 'pptx':
      case 'xlsx':
        return { ...base, ...parseDocumentText(content) };
      default:
        return { ...base, ...parseGeneric(content) };
    }
  } catch {
    return base; // never crash on malformed file
  }
}

// ── JavaScript / TypeScript ───────────────────────────────────────────────────

function parseJS(content) {
  const functions  = [];
  const classes    = [];
  const imports    = [];
  const exports    = [];
  const interfaces = [];
  const comments   = [];
  let m;

  // ES6 imports
  const importRe = /^import\s+(?:(?:type\s+)?(?:{[^}]*}|\*\s+as\s+\w+|\w+)(?:\s*,\s*(?:{[^}]*}|\w+))?\s+from\s+)?['"]([^'"]+)['"]/gm;
  while ((m = importRe.exec(content)) !== null) push(imports, m[1]);

  // require()
  const requireRe = /require\(['"]([^'"]+)['"]\)/g;
  while ((m = requireRe.exec(content)) !== null) push(imports, m[1]);

  // Named exports
  const exportNamedRe = /^export\s+(?:default\s+)?(?:async\s+)?(?:function\s+(\w+)|class\s+(\w+)|const\s+(\w+)|let\s+(\w+)|var\s+(\w+))/gm;
  while ((m = exportNamedRe.exec(content)) !== null) {
    const name = m[1] || m[2] || m[3] || m[4] || m[5];
    if (name) push(exports, name);
  }

  // export { a, b as c }
  const exportBlockRe = /^export\s+\{([^}]+)\}/gm;
  while ((m = exportBlockRe.exec(content)) !== null) {
    m[1].split(',')
      .map(s => s.trim().replace(/\s+as\s+\w+/, '').trim())
      .filter(Boolean)
      .forEach(n => push(exports, n));
  }

  // Function declarations
  const funcDeclRe = /^(?:export\s+)?(?:async\s+)?function\s+(\w+)\s*\(/gm;
  while ((m = funcDeclRe.exec(content)) !== null) push(functions, m[1]);

  // Arrow / method functions: const foo = () =>
  const arrowRe = /^(?:export\s+)?(?:const|let|var)\s+(\w+)\s*=\s*(?:async\s+)?(?:\([^)]*\)|[\w]+)\s*=>/gm;
  while ((m = arrowRe.exec(content)) !== null) push(functions, m[1]);

  // Class declarations
  const classRe = /^(?:export\s+)?(?:abstract\s+)?class\s+(\w+)(?:\s+extends\s+([\w.]+))?/gm;
  while ((m = classRe.exec(content)) !== null) {
    classes.push({ name: m[1], extends: m[2] || null });
  }

  // TypeScript interfaces + type aliases
  const ifaceRe = /^(?:export\s+)?interface\s+(\w+)/gm;
  while ((m = ifaceRe.exec(content)) !== null) push(interfaces, m[1]);
  const typeRe  = /^(?:export\s+)?type\s+(\w+)\s*=/gm;
  while ((m = typeRe.exec(content)) !== null) push(interfaces, m[1]);

  // JSDoc first lines
  const docRe = /\/\*\*\s*\n\s*\*\s*([^\n]+)/g;
  while ((m = docRe.exec(content)) !== null) comments.push(m[1].trim().slice(0, 150));

  return { functions, classes, imports, exports, interfaces, comments };
}

// ── Python ────────────────────────────────────────────────────────────────────

function parsePython(content) {
  const functions = [];
  const classes   = [];
  const imports   = [];
  const exports   = [];
  const comments  = [];
  let m;

  const importRe = /^(?:from\s+([\w.]+)\s+import\s+[\w*, ()]+|import\s+([\w., ]+))/gm;
  while ((m = importRe.exec(content)) !== null) {
    const mod = m[1] ?? m[2]?.split(',')[0]?.trim();
    if (mod) push(imports, mod);
  }

  const funcRe = /^(?:    )*(?:async\s+)?def\s+(\w+)\s*\(/gm;
  while ((m = funcRe.exec(content)) !== null) push(functions, m[1]);

  const classRe = /^class\s+(\w+)(?:\s*\(([^)]*)\))?/gm;
  while ((m = classRe.exec(content)) !== null) {
    classes.push({ name: m[1], extends: m[2]?.trim() || null });
  }

  const allMatch = content.match(/__all__\s*=\s*\[([^\]]+)\]/);
  if (allMatch) {
    const names = allMatch[1].match(/['"](\w+)['"]/g) || [];
    names.map(n => n.replace(/['"]/g, '')).forEach(n => push(exports, n));
  }

  const docRe = /"""([^"]{0,200})/g;
  while ((m = docRe.exec(content)) !== null) {
    const first = m[1].trim().split('\n')[0].trim();
    if (first) comments.push(first.slice(0, 150));
  }

  return { functions, classes, imports, exports, comments };
}

// ── Java / Kotlin ─────────────────────────────────────────────────────────────

function parseJava(content) {
  const functions  = [];
  const classes    = [];
  const imports    = [];
  const interfaces = [];
  let m;

  const importRe = /^import\s+(?:static\s+)?([\w.]+)(?:\.\*)?;/gm;
  while ((m = importRe.exec(content)) !== null) push(imports, m[1].split('.').slice(-2).join('.'));

  const classRe = /(?:public|private|protected|abstract|final|\s)+class\s+(\w+)/g;
  while ((m = classRe.exec(content)) !== null) classes.push({ name: m[1], extends: null });

  const ifaceRe = /(?:public|private)?\s+interface\s+(\w+)/g;
  while ((m = ifaceRe.exec(content)) !== null) push(interfaces, m[1]);

  const methodRe = /(?:public|private|protected)\s+(?:static\s+)?(?:final\s+)?(?:[\w<>[\],\s]+)\s+(\w+)\s*\([^)]*\)\s*(?:throws\s+[\w,\s]+)?\s*\{/g;
  while ((m = methodRe.exec(content)) !== null) {
    const name = m[1];
    if (!['if', 'while', 'for', 'switch', 'catch', 'return'].includes(name)) push(functions, name);
  }

  return { functions, classes, imports, interfaces };
}

// ── Go ────────────────────────────────────────────────────────────────────────

function parseGo(content) {
  const functions = [];
  const imports   = [];
  let m;

  const singleImport = /^import\s+"([^"]+)"/gm;
  while ((m = singleImport.exec(content)) !== null) push(imports, m[1]);

  const blockImport = /import\s*\(([^)]+)\)/;
  const block = content.match(blockImport);
  if (block) {
    const lineRe = /"([^"]+)"/g;
    while ((m = lineRe.exec(block[1])) !== null) push(imports, m[1]);
  }

  const funcRe = /^func\s+(?:\(\w+\s+\*?\w+\)\s+)?(\w+)\s*\(/gm;
  while ((m = funcRe.exec(content)) !== null) push(functions, m[1]);

  return { functions, imports };
}

// ── Rust ──────────────────────────────────────────────────────────────────────

function parseRust(content) {
  const functions = [];
  const imports   = [];
  let m;

  const useRe = /^use\s+([\w::{},\s*]+);/gm;
  while ((m = useRe.exec(content)) !== null) {
    const top = m[1].split('::')[0].trim();
    if (top) push(imports, top);
  }

  const fnRe = /^(?:pub(?:\([^)]*\))?\s+)?(?:async\s+)?fn\s+(\w+)/gm;
  while ((m = fnRe.exec(content)) !== null) push(functions, m[1]);

  return { functions, imports };
}

// ── C# ───────────────────────────────────────────────────────────────────────

function parseCSharp(content) {
  const functions  = [];
  const classes    = [];
  const interfaces = [];
  const imports    = [];
  let m;

  const usingRe = /^using\s+([\w.]+);/gm;
  while ((m = usingRe.exec(content)) !== null) push(imports, m[1]);

  const classRe = /(?:public|private|internal|protected|abstract|sealed|\s)+class\s+(\w+)/g;
  while ((m = classRe.exec(content)) !== null) classes.push({ name: m[1], extends: null });

  const ifaceRe = /interface\s+(\w+)/g;
  while ((m = ifaceRe.exec(content)) !== null) push(interfaces, m[1]);

  const methodRe = /(?:public|private|protected|internal|static|virtual|override|async)\s+(?:[\w<>[\]?,\s]+)\s+(\w+)\s*\([^)]*\)/g;
  while ((m = methodRe.exec(content)) !== null) {
    if (!['if', 'while', 'for', 'foreach', 'switch'].includes(m[1])) push(functions, m[1]);
  }

  return { functions, classes, interfaces, imports };
}

// ── PHP ───────────────────────────────────────────────────────────────────────

function parsePHP(content) {
  const functions = [];
  const classes   = [];
  const imports   = [];
  let m;

  const useRe = /^use\s+([\w\\]+)(?:\s+as\s+\w+)?;/gm;
  while ((m = useRe.exec(content)) !== null) push(imports, m[1].split('\\').pop());

  const requireRe = /(?:require|include)(?:_once)?\s*\(?['"]([^'"]+)['"]/g;
  while ((m = requireRe.exec(content)) !== null) push(imports, m[1]);

  const classRe = /(?:abstract\s+)?class\s+(\w+)/g;
  while ((m = classRe.exec(content)) !== null) classes.push({ name: m[1], extends: null });

  const funcRe = /function\s+(\w+)\s*\(/g;
  while ((m = funcRe.exec(content)) !== null) push(functions, m[1]);

  return { functions, classes, imports };
}

// ── JSON ──────────────────────────────────────────────────────────────────────

function parseJSON(filePath, content) {
  const dependencies = [];
  const keywords     = [];

  try {
    const data = JSON.parse(content);
    const base = path.basename(filePath).toLowerCase();

    if (base === 'package.json') {
      Object.keys({ ...data.dependencies, ...data.devDependencies, ...data.peerDependencies })
        .forEach(k => push(dependencies, k));
      if (data.name)        keywords.push(data.name);
      if (data.description) keywords.push(data.description);
    }
  } catch { /* malformed JSON */ }

  return { dependencies, keywords };
}

// ── Markdown ──────────────────────────────────────────────────────────────────

function parseMarkdown(content) {
  const comments = [];
  let m;
  const h1 = /^#\s+(.+)$/gm;
  const h2 = /^##\s+(.+)$/gm;
  while ((m = h1.exec(content)) !== null) comments.push(m[1]);
  while ((m = h2.exec(content)) !== null) comments.push(m[1]);
  return { comments };
}

// ── Documents (PDF/DOCX/PPTX/XLSX — text pre-extracted by documentParser.js) ──

function parseDocumentText(content) {
  const comments = [];

  // PPTX/XLSX arrive pre-sectioned into "-- Slide N --" / "-- Sheet: name --"
  // blocks (see project/documentParser.js) — surface those headers the same
  // way parseMarkdown() surfaces # / ## headers, giving a slide/sheet outline.
  const sectionRe = /^-- (Slide \d+|Sheet: .+) --$/gm;
  let m;
  while ((m = sectionRe.exec(content)) !== null) comments.push(m[1]);

  // PDF/DOCX have no such structure — fall back to a short first-line preview.
  if (!comments.length) {
    const firstLine = content.split('\n').map(l => l.trim()).find(Boolean);
    if (firstLine) comments.push(firstLine.slice(0, 150));
  }

  return { comments: comments.slice(0, 20) }; // cap: a 200-slide deck shouldn't dominate the summary
}

// ── Generic ───────────────────────────────────────────────────────────────────

function parseGeneric(content) {
  const comments = [];
  const tagRe = /(?:\/\/|#)\s*(TODO|FIXME|HACK|NOTE|XXX):?\s*(.+)/gi;
  let m;
  while ((m = tagRe.exec(content)) !== null) {
    comments.push(`${m[1]}: ${m[2].trim().slice(0, 100)}`);
  }
  return { comments };
}

// ── Helper ────────────────────────────────────────────────────────────────────

function push(arr, value) {
  if (value && !arr.includes(value)) arr.push(value);
}

/**
 * AQUA File Ingester
 *
 * Handles ZIP archives and raw file arrays.
 * Filters ignored directories (node_modules, .git, dist, etc.).
 * Detects language per file and project type from manifest files.
 */
import path from 'path';
import { isDocumentExt, parseDocument } from './documentParser.js';

// ── Constants ─────────────────────────────────────────────────────────────────

const IGNORE_DIRS = new Set([
  'node_modules', 'vendor', 'build', 'dist', 'target', '.git',
  '__pycache__', '.next', '.nuxt', '.cache', 'coverage', '.nyc_output',
  'out', 'tmp', 'temp', 'logs', '.turbo', '.svelte-kit', '.angular',
]);

const IGNORE_EXTS = new Set([
  '.png', '.jpg', '.jpeg', '.gif', '.svg', '.ico', '.webp', '.bmp',
  '.mp4', '.mp3', '.wav', '.mov', '.avi', '.pdf', '.zip', '.tar',
  '.gz', '.rar', '.7z', '.exe', '.dll', '.so', '.dylib', '.bin',
  '.pyc', '.class', '.o', '.a', '.lib', '.wasm',
  '.ttf', '.woff', '.woff2', '.eot', '.otf',
  '.map', '.min.js', // source maps + minified bundles
  // .docx/.pptx/.xlsx deliberately not added here (never were) — same
  // reasoning as .pdf, see the base64-document check in ingestFiles():
  // ignore rules apply normally UNLESS the file is explicitly tagged
  // encoding: 'base64', which no existing caller sends today, so this
  // whole list still behaves exactly as it did before this change.
]);

const DOCUMENT_LANG = { '.pdf': 'pdf', '.docx': 'docx', '.pptx': 'pptx', '.xlsx': 'xlsx' };

const IGNORE_FILES = new Set([
  'package-lock.json', 'yarn.lock', 'pnpm-lock.yaml', 'bun.lockb',
  'poetry.lock', 'Pipfile.lock', 'Cargo.lock', 'composer.lock',
]);

const MAX_FILE_SIZE = 100_000; // 100 KB per file

const LANG_MAP = {
  '.js': 'javascript', '.mjs': 'javascript', '.cjs': 'javascript',
  '.ts': 'typescript', '.tsx': 'typescript', '.jsx': 'javascript',
  '.py': 'python',   '.pyw': 'python',
  '.java': 'java',   '.kt': 'kotlin',
  '.go': 'go',
  '.rs': 'rust',
  '.cs': 'csharp',
  '.cpp': 'cpp', '.cc': 'cpp', '.cxx': 'cpp',
  '.c': 'c',     '.h': 'cpp', '.hpp': 'cpp',
  '.php': 'php',
  '.rb': 'ruby',
  '.swift': 'swift',
  '.md': 'markdown', '.mdx': 'markdown',
  '.json': 'json',
  '.yaml': 'yaml', '.yml': 'yaml',
  '.toml': 'toml',
  '.env': 'env',
  '.sh': 'shell', '.bash': 'shell', '.zsh': 'shell',
  '.html': 'html', '.htm': 'html',
  '.css': 'css', '.scss': 'css', '.sass': 'css', '.less': 'css',
  '.sql': 'sql',
  '.graphql': 'graphql', '.gql': 'graphql',
  '.proto': 'protobuf',
  '.xml': 'xml',
  '.tf': 'terraform',
  '.vue': 'vue',
  '.svelte': 'svelte',
};

// ── Language / project detection ──────────────────────────────────────────────

export function detectLanguage(filePath) {
  const base = path.basename(filePath).toLowerCase();
  if (base === 'dockerfile')     return 'dockerfile';
  if (base === 'makefile')       return 'makefile';
  if (base === 'gemfile')        return 'ruby';
  if (base === 'procfile')       return 'shell';
  if (base.startsWith('.env'))   return 'env';
  const ext = path.extname(filePath).toLowerCase();
  return LANG_MAP[ext] ?? 'unknown';
}

export function shouldIgnore(filePath) {
  const normalised = filePath.replace(/\\/g, '/');
  const parts = normalised.split('/');
  const basename = parts[parts.length - 1];

  if (IGNORE_FILES.has(basename)) return true;
  if (basename.endsWith('.lock')) return true;

  // Ignore hidden directories (except .env files)
  for (const part of parts.slice(0, -1)) {
    if (IGNORE_DIRS.has(part)) return true;
    if (part.startsWith('.') && part !== '.github') return true;
  }

  const ext = path.extname(filePath).toLowerCase();
  if (IGNORE_EXTS.has(ext)) return true;
  // Skip minified JS
  if (basename.endsWith('.min.js') || basename.endsWith('.min.css')) return true;

  return false;
}

export function detectProjectType(files) {
  const byName = new Map(files.map(f => [path.basename(f.path).toLowerCase(), f]));
  const paths  = files.map(f => f.path.toLowerCase());

  if (byName.has('package.json')) {
    const pkgFile = byName.get('package.json');
    try {
      const pkg = JSON.parse(pkgFile.content);
      const deps = { ...pkg.dependencies, ...pkg.devDependencies };
      if (deps.next)    return 'nodejs-next';
      if (deps.react)   return 'nodejs-react';
      if (deps.express || deps.fastify || deps.koa) return 'nodejs-express';
      if (deps.vue)     return 'nodejs-vue';
    } catch { /* malformed JSON */ }
    return 'nodejs';
  }
  if (byName.has('requirements.txt') || byName.has('pyproject.toml') || byName.has('setup.py')) return 'python';
  if (byName.has('go.mod'))            return 'go';
  if (byName.has('cargo.toml'))        return 'rust';
  if (byName.has('pom.xml') || byName.has('build.gradle')) return 'java';
  if (byName.has('composer.json'))     return 'php';
  if (byName.has('gemfile'))           return 'ruby';
  if (paths.some(p => p.endsWith('.csproj') || p.endsWith('.sln'))) return 'csharp';
  if (paths.some(p => p.endsWith('.cpp') || p.endsWith('.cc')))     return 'cpp';

  return 'unknown';
}

// ── Core ingestion ────────────────────────────────────────────────────────────

/**
 * Ingest an array of { path, content } objects.
 * Applies ignore rules, size limits, and binary detection.
 *
 * content is normally UTF-8 text. For PDF/DOCX/PPTX/XLSX, callers send
 * base64-encoded raw bytes instead, tagged with encoding: 'base64' (see
 * extractZip() below, and routes/project.js's upload contract) — those
 * are routed to real extraction instead of the text-file path, which
 * would otherwise mangle or (via isBinary()) silently drop them.
 *
 * @param {Array<{path: string, content: string, encoding?: 'base64'}>} rawFiles
 * @returns {Promise<Array<{path, content, lang, size, truncated, documentMeta?}>>}
 */
export async function ingestFiles(rawFiles) {
  const results = [];

  for (const file of rawFiles) {
    if (!file?.path || !file?.content) continue;

    const ext = path.extname(file.path).toLowerCase();
    const isBase64Document = file.encoding === 'base64' && isDocumentExt(ext);

    // Ignore rules apply normally UNLESS this is an explicitly base64-tagged
    // document — that's the opt-in signal (see file header comment). A
    // .pdf/.docx/.pptx/.xlsx sent the old way (no encoding field, which is
    // every existing caller today) still hits shouldIgnore() exactly as
    // before and gets dropped — zero behavior change for anyone not using
    // the new contract.
    if (!isBase64Document && shouldIgnore(file.path)) continue;

    if (isBase64Document) {
      const entry = await ingestDocumentFile(file, ext);
      if (entry) results.push(entry);
      continue;
    }

    if (isBinary(file.content)) continue;

    const lang = detectLanguage(file.path);
    let content = file.content;
    let truncated = false;

    if (content.length > MAX_FILE_SIZE) {
      content = content.slice(0, MAX_FILE_SIZE) + '\n// ... [truncated]';
      truncated = true;
    }

    results.push({ path: file.path, content, lang, size: file.content.length, truncated });
  }

  console.log(`[Index] Ingested ${results.length} files from ${rawFiles.length} total`);
  return results;
}

/**
 * Decode + extract one base64-tagged document file. Fails open at the
 * per-file level: any problem (bad base64, corrupt/password-protected
 * document, unsupported internal structure, oversize) skips just this
 * file with a logged reason — never throws out of ingestFiles(), so one
 * bad document can't fail an entire batch upload.
 *
 * @param {{path: string, content: string}} file - content is base64
 * @param {string} ext
 * @returns {Promise<{path, content, lang, size, truncated, documentMeta}|null>}
 */
async function ingestDocumentFile(file, ext) {
  let buffer;
  try {
    buffer = Buffer.from(file.content, 'base64');
  } catch {
    console.warn(`[Index] Skipped ${file.path}: invalid base64`);
    return null;
  }

  let extracted;
  try {
    extracted = await parseDocument(ext, buffer);
  } catch (err) {
    console.warn(`[Index] Skipped ${file.path}: ${err.message}`);
    return null;
  }

  if (!extracted?.text) {
    console.warn(`[Index] Skipped ${file.path}: no extractable text`);
    return null;
  }

  let content = extracted.text;
  let truncated = false;
  if (content.length > MAX_FILE_SIZE) {
    content = content.slice(0, MAX_FILE_SIZE) + '\n... [truncated]';
    truncated = true;
  }

  return {
    path: file.path,
    content,
    lang: DOCUMENT_LANG[ext],
    size: content.length,
    truncated,
    documentMeta: extracted.meta,
  };
}

/**
 * Extract files from a base64-encoded ZIP buffer.
 *
 * @param {string} base64
 * @returns {Promise<Array<{path: string, content: string}>>}
 */
// Archive safety caps (demo stability): a hostile or simply enormous ZIP
// previously decompressed every entry into memory with no limits — a
// classic zip-bomb / memory-spike path that could OOM the process live.
const ZIP_MAX_ENTRIES        = 10_000;        // more than any sane repo after ignore rules
const ZIP_MAX_ENTRY_BYTES    = 20_000_000;    // 20 MB uncompressed per entry (documents cap at 15 MB anyway)
const ZIP_MAX_TOTAL_BYTES    = 300_000_000;   // 300 MB total uncompressed budget

export async function extractZip(base64) {
  try {
    const { default: AdmZip } = await import('adm-zip');
    const buffer = Buffer.from(base64, 'base64');
    const zip    = new AdmZip(buffer);
    const files  = [];

    const entries = zip.getEntries();
    if (entries.length > ZIP_MAX_ENTRIES) {
      throw new Error(`Archive has ${entries.length} entries (limit ${ZIP_MAX_ENTRIES}). Remove build artifacts (node_modules, dist) before zipping.`);
    }

    let totalBytes = 0;
    let skippedOversize = 0;

    for (const entry of entries) {
      if (entry.isDirectory) continue;

      // Check the DECLARED uncompressed size BEFORE decompressing — never
      // pay the memory cost for an entry we'd drop anyway.
      const declaredSize = entry.header?.size ?? 0;
      if (declaredSize > ZIP_MAX_ENTRY_BYTES) {
        skippedOversize++;
        continue;
      }
      totalBytes += declaredSize;
      if (totalBytes > ZIP_MAX_TOTAL_BYTES) {
        throw new Error('Archive expands beyond the 300 MB extraction budget — likely includes dependencies or binaries. Trim it and retry.');
      }

      const ext = path.extname(entry.entryName).toLowerCase();
      // Cheap pre-filter: never decompress entries the ingester would
      // discard anyway (node_modules, images, lockfiles, ...). Documents
      // are exempt exactly like ingestFiles()'s base64 path.
      if (!isDocumentExt(ext) && shouldIgnore(entry.entryName)) continue;
      if (isDocumentExt(ext)) {
        // Binary format — carry raw bytes through as base64. toString('utf8')
        // below would corrupt them, and ingestFiles()'s isBinary() check
        // would then silently drop the corrupted result anyway.
        files.push({ path: entry.entryName, content: entry.getData().toString('base64'), encoding: 'base64' });
        continue;
      }

      try {
        const content = entry.getData().toString('utf8');
        files.push({ path: entry.entryName, content });
      } catch {
        // Binary or encoding error — skip silently
      }
    }

    if (skippedOversize) console.warn(`[Index] Skipped ${skippedOversize} oversize ZIP entries (> ${ZIP_MAX_ENTRY_BYTES / 1e6} MB each)`);
    console.log(`[Index] Extracted ${files.length} entries from ZIP`);
    return files;
  } catch (err) {
    console.error('[PROJECT] ZIP extraction failed:', err.message);
    throw new Error('Failed to extract ZIP: ' + err.message);
  }
}

/**
 * Build a nested directory structure object from file paths.
 */
export function buildStructure(files) {
  const root = {};
  for (const file of files) {
    const parts = file.path.replace(/\\/g, '/').split('/');
    let node = root;
    for (let i = 0; i < parts.length - 1; i++) {
      if (!node[parts[i]]) node[parts[i]] = {};
      node = node[parts[i]];
    }
    node[parts[parts.length - 1]] = { _file: true, lang: file.lang, size: file.size };
  }
  return root;
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function isBinary(content) {
  const sample = content.slice(0, 512);
  let nonPrintable = 0;
  for (let i = 0; i < sample.length; i++) {
    const code = sample.charCodeAt(i);
    if (code < 9 || (code > 13 && code < 32 && code !== 27)) nonPrintable++;
  }
  return nonPrintable / Math.max(sample.length, 1) > 0.1;
}

