/**
 * AQUA Project Index — Persistence / restart-survival tests (Phase 1)
 *
 * Run: node --test src/project/tests/indexPersistence.test.js
 *
 * Proves the Phase 1 guarantee: the queryable workspace index — and the raw
 * file content the edit engine depends on — survives a process restart.
 *
 * A "restart" is simulated faithfully by importing the module TWICE with
 * distinct query strings: each import is a fresh ESM instance with independent
 * top-level state, so the second instance re-runs loadFromDisk() and must
 * reconstruct the index from the on-disk snapshot alone (nothing shared in
 * memory). The test runs in a private temp cwd so INDEX_FILE
 * (process.cwd()/.aqua-index.json) is isolated from real data.
 */
import { test, describe, before, after } from 'node:test';
import assert from 'node:assert/strict';
import fs     from 'node:fs';
import os     from 'node:os';
import path   from 'node:path';

const WS = 'ws-persist-test';
const SAMPLE = [
  {
    path: 'src/auth.js',
    lang: 'javascript',
    size: 120,
    truncated: false,
    content: [
      'import express from "express";',
      'export function login(req, res) { return authenticate(req.body); }',
      'export class SessionManager { start() {} }',
    ].join('\n'),
  },
  {
    path: 'src/util/hash.js',
    lang: 'javascript',
    size: 40,
    truncated: false,
    content: 'export function hash(x) { return x; }',
  },
];

const delay = (ms) => new Promise((r) => setTimeout(r, ms));
let tmpDir;
let originalCwd;

describe('projectIndex persistence (restart survival)', () => {
  before(() => {
    originalCwd = process.cwd();
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'aqua-index-'));
    process.chdir(tmpDir); // INDEX_FILE resolves under here at import time
  });

  after(() => {
    process.chdir(originalCwd);
    try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch { /* noop */ }
  });

  test('build persists a source snapshot to disk', async () => {
    const mod = await import('../projectIndex.js?instance=build');
    mod.buildIndex(WS, SAMPLE);

    // Live index is correct immediately.
    const live = mod.getIndex(WS);
    assert.ok(live, 'index resident after build');
    assert.equal(live.byPath.size, 2);
    assert.ok(live.byPath.get('src/auth.js').content.includes('login'), 'entry carries raw content');
    assert.ok(live.bySymbol.has('login'), 'symbol indexed');

    // Snapshot flushes (debounced 500ms).
    await delay(700);
    const file = path.join(tmpDir, '.aqua-index.json');
    assert.ok(fs.existsSync(file), '.aqua-index.json written');
    const onDisk = JSON.parse(fs.readFileSync(file, 'utf8'));
    assert.ok(Array.isArray(onDisk[WS]), 'workspace source persisted');
    assert.equal(onDisk[WS].length, 2);
    assert.ok(onDisk[WS][0].content, 'persisted source carries content (edit path depends on it)');
  });

  test('a fresh module instance rebuilds the index from disk (restart)', async () => {
    // Distinct query string → brand-new module instance → re-runs loadFromDisk.
    // NOTHING is shared with the first instance's in-memory Maps.
    const restarted = await import('../projectIndex.js?instance=restart');

    const idx = restarted.getIndex(WS);
    assert.ok(idx, 'index rebuilt from persisted source after restart');
    assert.equal(idx.byPath.size, 2, 'all files restored');
    assert.ok(
      idx.byPath.get('src/auth.js').content.includes('SessionManager'),
      'raw content restored — edit engine can hash + patch',
    );

    // Derived maps are genuinely rebuilt, not just paths.
    assert.ok(idx.bySymbol.has('login'), 'symbol map rebuilt');
    assert.ok(idx.bySymbol.has('SessionManager'), 'class symbol rebuilt');
    assert.ok(idx.byImport.has('express'), 'import map rebuilt');

    // queryIndex works end-to-end on the rebuilt index.
    const q = restarted.queryIndex(WS, { symbol: 'login' });
    assert.equal(q.files.length, 1);
    assert.equal(q.files[0].path, 'src/auth.js');
  });

  test('unknown workspace still returns null (no false positives)', async () => {
    const mod = await import('../projectIndex.js?instance=restart');
    assert.equal(mod.getIndex('does-not-exist'), null);
  });
});

/**
 * AQUA Workspace Ingestion Pipeline — Day 5 unification
 *
 * The full ingest → index → summarize → graph → analyze → persist sequence,
 * factored VERBATIM out of routes/project.js (POST /workspace/:id/files)
 * so the new unified upload endpoint (routes/upload.js) runs the IDENTICAL
 * pipeline. One implementation, two entrypoints — the "backward
 * compatibility / no duplicate implementations" requirement is structural,
 * not a promise.
 *
 * Behavior is byte-identical to the previous inline version: same step
 * order, same logging, same error semantics (throws → caller marks the
 * workspace failed).
 */
import { getWorkspace, updateWorkspace }                    from './workspaceManager.js';
import { ingestFiles, buildStructure, detectProjectType }   from './fileIngester.js';
import { buildIndex, getIndex, getIndexStats, syncSummaries } from './projectIndex.js';
import { buildDependencyGraph, serializeGraph, detectCycles } from './dependencyGraph.js';
import { enrichWithSummaries, summarizeProject }            from './projectSummarizer.js';
import { analyzeWorkspace }                                 from './workspaceAnalyzer.js';

/**
 * Run the complete ingestion pipeline for a workspace.
 *
 * @param {string} workspaceId - existing workspace (created by caller)
 * @param {Array<{path, content, encoding?}>} rawFiles
 * @param {(id: string, label: string) => void} [onStage] - real progress reporting
 * @returns {Promise<{ projectType, filesIngested, indexStats, summary, overview }>}
 * @throws {Error} with .code='NO_VALID_FILES' when filtering leaves nothing;
 *                 any other pipeline failure propagates (caller marks 'failed')
 */
export async function runWorkspaceIngestion(workspaceId, rawFiles, onStage = () => {}) {
  const workspace = getWorkspace(workspaceId);
  if (!workspace) {
    const err = new Error('Workspace not found');
    err.code = 'NO_WORKSPACE';
    throw err;
  }

  updateWorkspace(workspaceId, { indexStatus: 'indexing' });

  try {
    // 1. Ingest (filter + size-cap; PDF/DOCX/PPTX/XLSX get real extraction)
    onStage('extract', 'Extracting files…');
    const ingested = await ingestFiles(rawFiles);
    if (!ingested.length) {
      updateWorkspace(workspaceId, { indexStatus: 'failed' });
      const err = new Error('No valid source files found after filtering');
      err.code = 'NO_VALID_FILES';
      throw err;
    }

    // 2. Detect project type + build directory tree
    const projectType = detectProjectType(ingested);
    const structure   = buildStructure(ingested);

    // 3. Build symbol / import index — parseFile() runs HERE, once per file.
    onStage('index', 'Indexing repository…');
    buildIndex(workspaceId, ingested);
    console.log(`[Index] Files indexed workspace=${workspaceId}`);

    // 4. Pull parsed entries back out of the index (full parse metadata + content).
    const parsedEntries = [...getIndex(workspaceId).byPath.values()];

    // 5. Summarize from real parse metadata; patch summaries into live index.
    onStage('analyze', 'Analyzing project…');
    const enriched  = enrichWithSummaries(parsedEntries);
    const liveIndex = getIndex(workspaceId);
    for (const f of enriched) {
      const entry = liveIndex.byPath.get(f.path);
      if (entry) entry.summary = f.summary;
    }
    // Persist summaries into the durable source snapshot so a rebuilt index
    // (after restart) carries them too — see projectIndex syncSummaries.
    syncSummaries(workspaceId, enriched);

    // 6. Dependency graph from parsed imports
    buildDependencyGraph(workspaceId, enriched);
    console.log(`[GRAPH] Dependencies updated workspace=${workspaceId}`);

    // 6b. Project-level summary
    const summary = summarizeProject({ projectType }, enriched);
    console.log(`[SUMMARY] File summarized workspace=${workspaceId}`);

    // 7. Language stats
    const languages = {};
    for (const f of enriched) languages[f.lang] = (languages[f.lang] ?? 0) + 1;

    // 7b. Workspace intelligence — cached on the record; failure degrades, never fails upload.
    onStage('workspace', 'Generating workspace…');
    let overview = null;
    try {
      const graph  = serializeGraph(workspaceId);
      const cycles = detectCycles(workspaceId);
      ({ overview } = analyzeWorkspace({
        workspaceName: workspace.meta?.name,
        projectType, files: enriched, graph, cycles,
      }));
      console.log(`[ANALYZER] Overview generated workspace=${workspaceId} partial=${overview.partial} warnings=${overview.warnings.length}`);
    } catch (err) {
      console.warn(`[ANALYZER] Overview generation failed workspace=${workspaceId}:`, err.message);
    }

    // 8. Persist (metadata only — no raw content)
    const fileMetadata = enriched.map(f => ({
      path: f.path, lang: f.lang, size: f.size, summary: f.summary, parsedAt: Date.now(),
    }));
    updateWorkspace(workspaceId, {
      projectType, structure, files: fileMetadata, summary, overview,
      indexStatus: 'indexed', indexedAt: Date.now(),
      stats: { files: enriched.length, languages },
    });

    return {
      projectType,
      filesIngested: enriched.length,
      indexStats: getIndexStats(workspaceId),
      summary,
      overview,
    };
  } catch (err) {
    if (err.code !== 'NO_VALID_FILES') {
      console.error(`[PROJECT] Ingestion failed workspace=${workspaceId}:`, err.stack ?? err.message);
      updateWorkspace(workspaceId, { indexStatus: 'failed', indexError: err.message });
    }
    throw err;
  }
}

/**
 * AQUA Project Index
 *
 * Per-workspace index built from parsed files.
 * Supports retrieval by: filename/path, symbol, import, dependency, keyword.
 * Fast O(1) lookups after an O(n) build phase.
 *
 * ── Persistence (Phase 1 — Persistent Workspace Brain) ────────────────────────
 * The derived index (symbol/import/keyword maps) is REBUILDABLE, so only the
 * MINIMAL source needed to rebuild it is persisted: the ingested files
 * themselves (path + content + lang + size). That raw content lives durably
 * NOWHERE ELSE — projectMemory persists workspace *metadata* only (path/lang/
 * size/summary, no content). Before this, a restart wiped the index and there
 * was nothing to rebuild from: getIndex() returned null, so isEditIntent()
 * silently disabled editing until the user re-uploaded.
 *
 * Now: buildIndex() derives the maps in memory AND persists the source
 * snapshot (.aqua-index.json, debounced whole-file write — same tier as
 * mindStore/projectMemory). getIndex() lazily rebuilds the derived maps from
 * that snapshot on a miss (e.g. first access after a restart), so the
 * workspace brain — and the edit path that depends on entry.content — survives
 * restarts. All access is through getIndex/buildIndex, so a later move to
 * Mongo/SQLite (Phase 2) touches ONLY this file.
 *
 * NOTE: the snapshot holds full file content; it can be large for big repos.
 * That is inherent to surviving a restart with a working edit path, and is
 * bounded per-workspace. Phase 2 moves this off whole-file JSON.
 */
import fs   from 'fs';
import path from 'path';
import { parseFile } from './fileParser.js';

const INDEX_FILE = path.join(process.cwd(), '.aqua-index.json');

// workspaceId → derived Index (in-memory, rebuildable)
const indexes = new Map();
// workspaceId → source ingested files (persisted, minimal rebuildable unit)
//   [{ path, content, lang, size, truncated, summary }]
const sources = new Map();

// ── Persistence ───────────────────────────────────────────────────────────────
// Mirrors the proven mindStore/projectMemory pattern: in-memory Map + debounced
// JSON file write, loaded once on boot.

let loaded = false;
function loadFromDisk() {
  if (loaded) return;
  loaded = true;
  try {
    if (!fs.existsSync(INDEX_FILE)) return;
    const data = JSON.parse(fs.readFileSync(INDEX_FILE, 'utf8'));
    for (const [id, files] of Object.entries(data)) {
      if (Array.isArray(files)) sources.set(id, files);
    }
    console.log(`[Index] Loaded source snapshots for ${sources.size} workspace(s) from disk`);
  } catch (err) {
    console.warn('[Index] Could not load index sources from disk:', err.message);
  }
}

let saveTimer = null;
function scheduleSave() {
  if (saveTimer) return;
  saveTimer = setTimeout(() => {
    saveTimer = null;
    try {
      const data = {};
      for (const [id, files] of sources.entries()) data[id] = files;
      fs.writeFileSync(INDEX_FILE, JSON.stringify(data), 'utf8');
    } catch (err) {
      console.warn('[Index] Could not save index sources to disk:', err.message);
    }
  }, 500);
}

loadFromDisk();

// ── Build ─────────────────────────────────────────────────────────────────────

/**
 * Build (or rebuild) the index for a workspace from ingested file objects.
 *
 * @param {string} workspaceId
 * @param {Array<{path, content, lang, size, truncated, summary?}>} ingestedFiles
 * @param {{ persist?: boolean }} [opts]  persist=false when rebuilding from an
 *        already-persisted source (identical bytes → no redundant write).
 * @returns {Index}
 */
export function buildIndex(workspaceId, ingestedFiles, { persist = true } = {}) {
  const index = _deriveIndex(ingestedFiles);
  indexes.set(workspaceId, index);

  if (persist) {
    sources.set(workspaceId, ingestedFiles.map(f => ({
      path:      f.path,
      content:   f.content,
      lang:      f.lang,
      size:      f.size,
      truncated: f.truncated ?? false,
      summary:   f.summary ?? null,
    })));
    scheduleSave();
  }

  console.log(`[Index] ${ingestedFiles.length} files indexed for workspace=${workspaceId}`);
  return index;
}

/** Pure derivation — no side effects, no persistence. Shared by build + rebuild. */
function _deriveIndex(ingestedFiles) {
  const index = {
    byPath:    new Map(),   // filePath → full parsed+enriched entry
    bySymbol:  new Map(),   // symbol   → [{ path, type }]
    byImport:  new Map(),   // module   → [paths that import it]
    byKeyword: new Map(),   // keyword  → Set<path>
    builtAt:   Date.now(),
    fileCount: ingestedFiles.length,
  };

  for (const file of ingestedFiles) {
    const parsed = parseFile(file.path, file.content, file.lang);

    const entry = {
      ...parsed,
      content:   file.content,
      lang:      file.lang,
      size:      file.size,
      truncated: file.truncated ?? false,
      summary:   file.summary ?? null,
    };

    index.byPath.set(file.path, entry);
    _indexSymbols(index, parsed, file.path);
    _indexImports(index, parsed, file.path);
    _indexPathKeywords(index, file.path);
  }

  return index;
}

function _indexSymbols(index, parsed, filePath) {
  for (const fn of parsed.functions  ?? []) _addSymbol(index, fn,   filePath, 'function');
  for (const cl of parsed.classes    ?? []) {
    const name = typeof cl === 'string' ? cl : cl.name;
    if (name) _addSymbol(index, name, filePath, 'class');
  }
  for (const iface of parsed.interfaces ?? []) _addSymbol(index, iface, filePath, 'interface');
  for (const exp  of parsed.exports   ?? []) _addSymbol(index, exp,  filePath, 'export');
}

function _addSymbol(index, name, filePath, type) {
  if (!name || name.length < 2) return;
  if (!index.bySymbol.has(name)) index.bySymbol.set(name, []);
  index.bySymbol.get(name).push({ path: filePath, type });
}

function _indexImports(index, parsed, filePath) {
  for (const imp of parsed.imports ?? []) {
    if (!index.byImport.has(imp)) index.byImport.set(imp, []);
    index.byImport.get(imp).push(filePath);
  }
}

function _indexPathKeywords(index, filePath) {
  const parts = filePath.replace(/\\/g, '/').split(/[\/._\-]/g);
  for (const part of parts) {
    const kw = part.toLowerCase();
    if (kw.length < 2) continue;
    if (!index.byKeyword.has(kw)) index.byKeyword.set(kw, new Set());
    index.byKeyword.get(kw).add(filePath);
  }
}

/**
 * Persist enriched summaries back into the source snapshot so a rebuilt index
 * (after restart) carries them too. Called by the ingestion / edit pipelines
 * right after they patch summaries into the live index. Cheap: updates the
 * snapshot in place + reschedules the debounced save. Never derives anything.
 *
 * @param {string} workspaceId
 * @param {Array<{path, summary}>} enriched
 */
export function syncSummaries(workspaceId, enriched = []) {
  const src = sources.get(workspaceId);
  if (!src) return;
  const summaryByPath = new Map(enriched.map(e => [e.path, e.summary]));
  let changed = false;
  for (const f of src) {
    if (summaryByPath.has(f.path) && f.summary !== summaryByPath.get(f.path)) {
      f.summary = summaryByPath.get(f.path);
      changed = true;
    }
  }
  if (changed) scheduleSave();
}

// ── Query ─────────────────────────────────────────────────────────────────────

/**
 * Get the derived index for a workspace. If it is not resident in memory but a
 * persisted source snapshot exists (e.g. the first access after a restart),
 * the derived index is rebuilt lazily from that snapshot. This is the single
 * hook that warms the whole system (chat edit-detection, edit engine, project
 * retriever) after a restart — they all read through getIndex().
 */
export function getIndex(workspaceId) {
  const live = indexes.get(workspaceId);
  if (live) return live;

  const src = sources.get(workspaceId);
  if (src) {
    const rebuilt = buildIndex(workspaceId, src, { persist: false });
    console.log(`[Index] Rebuilt index from persisted source workspace=${workspaceId} files=${src.length}`);
    return rebuilt;
  }

  return null;
}

export function clearIndex(workspaceId) {
  const had = indexes.delete(workspaceId);
  if (sources.delete(workspaceId)) scheduleSave();
  return had;
}

/**
 * Query the index.
 *
 * @param {string} workspaceId
 * @param {{ symbol?, keyword?, importModule?, filePath? }} query
 * @returns {{ files: object[], symbols: object[], imports: string[] }}
 */
export function queryIndex(workspaceId, { symbol, keyword, importModule, filePath } = {}) {
  const index = getIndex(workspaceId);
  if (!index) return { files: [], symbols: [], imports: [] };

  const pathSet  = new Set();
  let   symbols  = [];
  let   imports  = [];

  if (symbol) {
    const hits = index.bySymbol.get(symbol) ?? [];
    hits.forEach(h => pathSet.add(h.path));
    symbols = hits;
  }

  if (keyword) {
    const hits = index.byKeyword.get(keyword.toLowerCase()) ?? new Set();
    hits.forEach(p => pathSet.add(p));
  }

  if (importModule) {
    const hits = index.byImport.get(importModule) ?? [];
    hits.forEach(p => pathSet.add(p));
    imports = hits;
  }

  if (filePath) {
    for (const [p] of index.byPath.entries()) {
      if (p.includes(filePath) || filePath.includes(p)) pathSet.add(p);
    }
  }

  const files = [...pathSet]
    .map(p => index.byPath.get(p))
    .filter(Boolean);

  return { files, symbols, imports };
}

export function getIndexStats(workspaceId) {
  const index = getIndex(workspaceId);
  if (!index) return null;
  return {
    files:     index.byPath.size,
    symbols:   index.bySymbol.size,
    imports:   index.byImport.size,
    keywords:  index.byKeyword.size,
    builtAt:   index.builtAt,
    fileCount: index.fileCount,
  };
}

/**
 * AQUA Project Memory
 *
 * Separate persistence for project workspaces.
 * Workspace INDEX data (file trees, summaries, dependency graphs) — bulky,
 * rebuildable. The OWNER-facing memory of a workspace (that it exists, its
 * summary, the works_on edge) lives in the unified Mind store via
 * memory/engine.js rememberWorkspace(). This file is a cache tier, not a
 * second user-memory store.
 * Store file: .aqua-projects.json
 */
import fs   from 'fs';
import path from 'path';

const PROJECTS_FILE = path.join(process.cwd(), '.aqua-projects.json');

// workspaceId → workspace object (metadata + serialisable index data)
const store = new Map();

// ── Persistence ───────────────────────────────────────────────────────────────

function loadFromDisk() {
  try {
    if (!fs.existsSync(PROJECTS_FILE)) return;
    const data = JSON.parse(fs.readFileSync(PROJECTS_FILE, 'utf8'));
    let count = 0;
    for (const [id, ws] of Object.entries(data)) {
      store.set(id, ws);
      count++;
    }
    console.log(`[PROJECT] Loaded ${count} workspaces from disk`);
  } catch (err) {
    console.warn('[PROJECT] Could not load projects from disk:', err.message);
  }
}

let saveTimer = null;
function scheduleSave() {
  if (saveTimer) return;
  saveTimer = setTimeout(() => {
    saveTimer = null;
    try {
      const data = {};
      for (const [id, ws] of store.entries()) data[id] = ws;
      fs.writeFileSync(PROJECTS_FILE, JSON.stringify(data, null, 2), 'utf8');
    } catch (err) {
      console.warn('[PROJECT] Could not save projects to disk:', err.message);
    }
  }, 500);
}

loadFromDisk();

// ── Public API ────────────────────────────────────────────────────────────────

export function saveWorkspace(id, workspace) {
  store.set(id, workspace);
  scheduleSave();
}

export function loadWorkspace(id) {
  return store.get(id) ?? null;
}

export function deleteWorkspaceData(id) {
  const deleted = store.delete(id);
  if (deleted) scheduleSave();
  return deleted;
}

export function getAllWorkspaceIds() {
  return [...store.keys()];
}

export function getProjectStats() {
  let totalFiles = 0;
  for (const ws of store.values()) totalFiles += ws.files?.length ?? 0;
  return { workspaces: store.size, totalFiles };
}

/**
 * AQUA Project Retriever
 *
 * Scores every file in a workspace index against the current query.
 * Returns only the most relevant files — never dumps entire project.
 * Formats the result for injection into the system prompt.
 */
import { getIndex }     from './projectIndex.js';
import { getWorkspace } from './workspaceManager.js';
import { formatOverviewForPrompt } from './workspaceAnalyzer.js';

const MAX_FILES          = 5;
const MAX_CONTENT_CHARS  = 2_000;   // per file content snippet

// Whole-repo questions ("explain this repository", "summarize the
// architecture") often share no tokens with any single file path, so
// keyword scoring returns nothing. Detect them and fall back to
// structurally important files (entry points + core modules) instead
// of returning an empty context.
const BROAD_QUERY_RE = /\b(repo(sitory)?|codebase|project|architecture|structure|overview|summar(y|ize|ise)|explain (this|the)|how (does|is) (this|it|everything)|folder|responsibilit)\b/i;

// ── Retrieval ─────────────────────────────────────────────────────────────────

/**
 * Retrieve relevant project context for a query.
 *
 * @param {string} workspaceId
 * @param {string} query
 * @param {number} [limit]
 * @returns {{ files, projectSummary, projectType, relevantSymbols, totalFiles } | null}
 */
export function retrieveProjectContext(workspaceId, query, limit = MAX_FILES) {
  const index     = getIndex(workspaceId);
  const workspace = getWorkspace(workspaceId);
  if (!index || !workspace) return null;

  const scored = [];
  for (const [filePath, meta] of index.byPath.entries()) {
    const score = _score(filePath, meta, query, index);
    if (score > 0) scored.push({ filePath, meta, score });
  }
  scored.sort((a, b) => b.score - a.score);

  let topFiles = scored.slice(0, limit);

  // Broad-query fallback: no keyword hits (or a whole-repo question with
  // weak hits) → surface entry points + most-connected core modules from
  // the cached overview so the model always has real structure to cite.
  if ((!topFiles.length || (BROAD_QUERY_RE.test(query) && topFiles.length < 3)) && workspace.overview) {
    const structural = [
      ...(workspace.overview.entryPoints ?? []),
      ...((workspace.overview.coreModules ?? []).map(c => c.file)),
    ];
    const already = new Set(topFiles.map(t => t.filePath));
    for (const p of structural) {
      if (topFiles.length >= limit) break;
      if (already.has(p)) continue;
      const meta = index.byPath.get(p);
      if (meta) { topFiles.push({ filePath: p, meta, score: 1 }); already.add(p); }
    }
    console.log(`[RETRIEVAL] Broad-query fallback applied workspace=${workspaceId} added=${topFiles.length}`);
  }

  console.log(`[RETRIEVAL] Relevant files selected workspace=${workspaceId} query="${query.slice(0, 60)}" count=${topFiles.length}`);

  const files = topFiles.map(({ filePath, meta }) => ({
    path:          filePath,
    lang:          meta.lang,
    summary:       meta.summary   ?? '',
    functions:     (meta.functions ?? []).slice(0, 10),
    classes:       (meta.classes   ?? []).map(c => typeof c === 'string' ? c : c.name).filter(Boolean).slice(0, 5),
    exports:       (meta.exports   ?? []).slice(0, 8),
    localImports:  (meta.imports   ?? []).filter(i => i.startsWith('.')).slice(0, 5),
    contentSnippet: meta.content   ? meta.content.slice(0, MAX_CONTENT_CHARS) : '',
  }));

  return {
    files,
    projectSummary:  workspace.summary ?? '',
    projectType:     workspace.projectType ?? 'unknown',
    relevantSymbols: _findSymbols(query, index),
    totalFiles:      index.byPath.size,
    overview:        workspace.overview ?? null,   // cached workspace intelligence
  };
}

// ── Scoring ───────────────────────────────────────────────────────────────────

function _score(filePath, meta, query, index) {
  let score  = 0;
  const qLow = query.toLowerCase();
  const tokens = (qLow.match(/\b[a-z][a-z0-9_]{2,}\b/g) ?? []);

  // 1. Path keyword match
  const pLow = filePath.toLowerCase();
  for (const t of tokens) {
    if (pLow.includes(t)) score += 30;
  }

  // 2. Function / symbol match
  for (const fn of meta.functions ?? []) {
    const fnL = fn.toLowerCase();
    for (const t of tokens) {
      if (fnL.includes(t) || t.includes(fnL)) score += 25;
    }
  }
  for (const cl of meta.classes ?? []) {
    const clN = (typeof cl === 'string' ? cl : cl.name ?? '').toLowerCase();
    for (const t of tokens) {
      if (clN.includes(t) || t.includes(clN)) score += 22;
    }
  }

  // 3. Export match
  for (const exp of meta.exports ?? []) {
    if (qLow.includes(exp.toLowerCase())) score += 20;
  }

  // 4. Summary keyword match
  if (meta.summary) {
    const sLow = meta.summary.toLowerCase();
    for (const t of tokens) {
      if (sLow.includes(t)) score += 10;
    }
  }

  // 5. Topic heuristics
  score += _topicBonus(qLow, filePath);

  return score;
}

function _topicBonus(qLow, filePath) {
  const p = filePath.toLowerCase();
  let b = 0;
  if (/auth(entication|orization)?/.test(qLow) && /auth|login|session|jwt|token|middleware/.test(p)) b += 40;
  if (/route|endpoint|api/.test(qLow)           && /route|controller|handler|api/.test(p))           b += 35;
  if (/database|db|model|schema|orm/.test(qLow) && /model|schema|db|database|migration/.test(p))     b += 35;
  if (/config(uration)?|setting|env/.test(qLow) && /config|setting|env|constant/.test(p))             b += 30;
  if (/test|spec/.test(qLow)                    && /test|spec|__test__/.test(p))                       b += 30;
  if (/error|exception/.test(qLow)              && /error|exception|handler|middleware/.test(p))       b += 28;
  if (/architecture|structure|overview/.test(qLow) && /readme|index|main|app|server/.test(p))         b += 25;
  if (/dead.?code|unused/.test(qLow)            && /util|helper|common/.test(p))                       b += 20;
  if (/depend(ency|encies)|import/.test(qLow)   && /package\.json|cargo|requirements|go\.mod/.test(p)) b += 30;
  return b;
}

// ── Symbol extraction from query ──────────────────────────────────────────────

function _findSymbols(query, index) {
  // Match CamelCase identifiers or known suffixes likely to be symbols
  const tokens = query.match(/\b[A-Z][a-zA-Z0-9]+|\b\w+(?:Handler|Manager|Service|Controller|Router|Model|Schema|Config|Store|Provider|Client|Server|Utils?|Helper|Factory)\b/g) ?? [];
  const found  = [];
  for (const t of tokens) {
    if (index.bySymbol.has(t)) {
      found.push({ symbol: t, locations: index.bySymbol.get(t) });
    }
  }
  return found.slice(0, 6);
}

// ── Prompt formatting ─────────────────────────────────────────────────────────

/**
 * Format retrieved context into a string for system prompt injection.
 *
 * @param {{ files, projectSummary, projectType, relevantSymbols, totalFiles }} context
 * @returns {string}
 */
export function formatProjectContext(context) {
  if (!context || !context.files?.length) return '';

  const lines = [
    '--- PROJECT CONTEXT ---',
    `Project type: ${context.projectType} | Total indexed files: ${context.totalFiles}`,
  ];

  // Condensed workspace intelligence (generated once at index time) —
  // gives the model whole-repo awareness even when only a few files are
  // retrieved: frameworks, DB, auth, entry points, endpoint inventory.
  const overviewBlock = formatOverviewForPrompt(context.overview);
  if (overviewBlock) {
    lines.push('', 'Workspace intelligence:', overviewBlock);
  }

  if (context.projectSummary) {
    lines.push('', 'Architecture overview:', context.projectSummary);
  }

  if (context.relevantSymbols?.length) {
    lines.push('', 'Relevant symbols:');
    for (const { symbol, locations } of context.relevantSymbols) {
      const locs = locations.map(l => l.path).join(', ');
      lines.push(`  ${symbol} → ${locs}`);
    }
  }

  lines.push('', 'Relevant files (ranked by query relevance):');

  for (const file of context.files) {
    lines.push('', `### ${file.path} (${file.lang})`);
    if (file.summary)     lines.push(file.summary);
    if (file.functions.length)   lines.push(`Functions: ${file.functions.join(', ')}`);
    if (file.classes.length)     lines.push(`Classes: ${file.classes.join(', ')}`);
    if (file.exports.length)     lines.push(`Exports: ${file.exports.join(', ')}`);
    if (file.localImports.length)lines.push(`Local imports: ${file.localImports.join(', ')}`);
    if (file.contentSnippet) {
      lines.push('```');
      lines.push(file.contentSnippet);
      if (file.contentSnippet.length >= MAX_CONTENT_CHARS) lines.push('// ... [truncated]');
      lines.push('```');
    }
  }

  lines.push(
    '',
    '--- END PROJECT CONTEXT ---',
    'Reference specific files, functions, and classes above when answering.',
    'If asked about files not shown, note they exist but were not retrieved for this query.',
  );

  return lines.join('\n');
}

/**
 * AQUA Diff Engine (Day 4)
 *
 * Real line-level diffing for patch-first editing:
 *   - Myers-style LCS diff (correct, not the old 4-line-lookahead greedy scan)
 *   - Hunk generation with configurable context lines (unified-diff semantics)
 *   - Structured output (per-line ops + line numbers) for rich UI rendering
 *   - Unified-diff text rendering for LLM prompts / logs / copy-paste
 *   - Per-file added/removed stats
 *
 * Pure module: no I/O, no LLM calls, no imports from the rest of the app.
 * patchGenerator.js and editEngine.js both consume it.
 */

const DEFAULT_CONTEXT = 3;

// ── LCS core ──────────────────────────────────────────────────────────────────

/**
 * Compute a minimal edit script between two line arrays.
 * Returns ops: [{ type: 'equal'|'del'|'add', oldLine?, newLine?, text }]
 * Line numbers are 1-based.
 */
export function computeLineOps(oldLines, newLines) {
  const n = oldLines.length;
  const m = newLines.length;

  // Trim common prefix/suffix first — typical edits touch a small region,
  // this keeps the DP table tiny even for large files.
  let start = 0;
  while (start < n && start < m && oldLines[start] === newLines[start]) start++;
  let endOld = n, endNew = m;
  while (endOld > start && endNew > start && oldLines[endOld - 1] === newLines[endNew - 1]) {
    endOld--; endNew--;
  }

  const midOld = oldLines.slice(start, endOld);
  const midNew = newLines.slice(start, endNew);

  const ops = [];
  for (let i = 0; i < start; i++) {
    ops.push({ type: 'equal', oldLine: i + 1, newLine: i + 1, text: oldLines[i] });
  }

  ops.push(..._lcsOps(midOld, midNew, start, start));

  const suffixLen = n - endOld;
  for (let i = 0; i < suffixLen; i++) {
    ops.push({
      type: 'equal',
      oldLine: endOld + i + 1,
      newLine: endNew + i + 1,
      text: oldLines[endOld + i],
    });
  }
  return ops;
}

function _lcsOps(a, b, oldOffset, newOffset) {
  const n = a.length, m = b.length;
  if (!n && !m) return [];

  // Guard: O(n*m) table; cap at ~4M cells then fall back to whole-block replace.
  if (n * m > 4_000_000) {
    const ops = [];
    for (let i = 0; i < n; i++) ops.push({ type: 'del', oldLine: oldOffset + i + 1, text: a[i] });
    for (let j = 0; j < m; j++) ops.push({ type: 'add', newLine: newOffset + j + 1, text: b[j] });
    return ops;
  }

  // DP LCS lengths
  const width = m + 1;
  const dp = new Uint32Array((n + 1) * width);
  for (let i = n - 1; i >= 0; i--) {
    for (let j = m - 1; j >= 0; j--) {
      dp[i * width + j] = a[i] === b[j]
        ? dp[(i + 1) * width + j + 1] + 1
        : Math.max(dp[(i + 1) * width + j], dp[i * width + j + 1]);
    }
  }

  // Backtrack
  const ops = [];
  let i = 0, j = 0;
  while (i < n && j < m) {
    if (a[i] === b[j]) {
      ops.push({ type: 'equal', oldLine: oldOffset + i + 1, newLine: newOffset + j + 1, text: a[i] });
      i++; j++;
    } else if (dp[(i + 1) * width + j] >= dp[i * width + j + 1]) {
      ops.push({ type: 'del', oldLine: oldOffset + i + 1, text: a[i] });
      i++;
    } else {
      ops.push({ type: 'add', newLine: newOffset + j + 1, text: b[j] });
      j++;
    }
  }
  while (i < n) { ops.push({ type: 'del', oldLine: oldOffset + i + 1, text: a[i] }); i++; }
  while (j < m) { ops.push({ type: 'add', newLine: newOffset + j + 1, text: b[j] }); j++; }
  return ops;
}

// ── Hunks ─────────────────────────────────────────────────────────────────────

/**
 * Group ops into unified-diff hunks with `context` equal lines around changes.
 * Unchanged stretches between hunks are omitted (the UI shows them collapsed).
 *
 * @returns {{ hunks, stats: { added, removed } }}
 */
export function buildHunks(ops, context = DEFAULT_CONTEXT) {
  const stats = { added: 0, removed: 0 };
  for (const op of ops) {
    if (op.type === 'add') stats.added++;
    else if (op.type === 'del') stats.removed++;
  }
  if (!stats.added && !stats.removed) return { hunks: [], stats };

  // Mark ops to keep (changes + context window around them)
  const keep = new Array(ops.length).fill(false);
  for (let k = 0; k < ops.length; k++) {
    if (ops[k].type !== 'equal') {
      for (let c = Math.max(0, k - context); c <= Math.min(ops.length - 1, k + context); c++) {
        keep[c] = true;
      }
    }
  }

  const hunks = [];
  let current = null;
  for (let k = 0; k < ops.length; k++) {
    if (!keep[k]) { current = null; continue; }
    const op = ops[k];
    if (!current) {
      current = {
        oldStart: op.oldLine ?? _nextOldLine(ops, k),
        newStart: op.newLine ?? _nextNewLine(ops, k),
        oldCount: 0,
        newCount: 0,
        lines: [],
      };
      hunks.push(current);
    }
    current.lines.push(op);
    if (op.type !== 'add') current.oldCount++;
    if (op.type !== 'del') current.newCount++;
  }
  return { hunks, stats };
}

function _nextOldLine(ops, k) {
  for (let i = k; i < ops.length; i++) if (ops[i].oldLine) return ops[i].oldLine;
  return 1;
}
function _nextNewLine(ops, k) {
  for (let i = k; i < ops.length; i++) if (ops[i].newLine) return ops[i].newLine;
  return 1;
}

// ── Public: full file diff ────────────────────────────────────────────────────

/**
 * Diff two file contents.
 *
 * @param {string} filePath
 * @param {string} original  '' means the file is new
 * @param {string} modified  '' means the file is deleted
 * @returns {{
 *   file, changeType: 'create'|'delete'|'modify',
 *   stats: { added, removed },
 *   hunks: Array<{ oldStart, oldCount, newStart, newCount, lines }>,
 *   unified: string,
 *   totalOldLines, totalNewLines,
 * }}
 */
export function diffFile(filePath, original = '', modified = '', context = DEFAULT_CONTEXT) {
  const changeType = !original && modified ? 'create'
                   : original && !modified ? 'delete'
                   : 'modify';

  const oldLines = original ? original.split('\n') : [];
  const newLines = modified ? modified.split('\n') : [];

  const ops = computeLineOps(oldLines, newLines);
  const { hunks, stats } = buildHunks(ops, context);

  return {
    file: filePath,
    changeType,
    stats,
    hunks,
    unified: renderUnified(filePath, hunks, changeType),
    totalOldLines: oldLines.length,
    totalNewLines: newLines.length,
  };
}

/** Render hunks as standard unified-diff text. */
export function renderUnified(filePath, hunks, changeType = 'modify') {
  const header = changeType === 'create' ? `--- /dev/null\n+++ b/${filePath}`
               : changeType === 'delete' ? `--- a/${filePath}\n+++ /dev/null`
               : `--- a/${filePath}\n+++ b/${filePath}`;
  if (!hunks.length) return `${header}\n(no changes)`;

  const out = [header];
  for (const h of hunks) {
    out.push(`@@ -${h.oldStart},${h.oldCount} +${h.newStart},${h.newCount} @@`);
    for (const line of h.lines) {
      const prefix = line.type === 'add' ? '+' : line.type === 'del' ? '-' : ' ';
      out.push(prefix + line.text);
    }
  }
  return out.join('\n');
}

/**
 * AQUA Dependency Graph
 *
 * Lightweight directed graph: file → files it imports (local only).
 * Also tracks reverse: who imports each file.
 * Tracks class inheritance chains.
 *
 * Queries:
 *   whoImports(workspaceId, filePath)  → files that depend on this file
 *   whatImports(workspaceId, filePath) → files this file depends on
 */

// workspaceId → GraphState
const graphs = new Map();

// ── Build ─────────────────────────────────────────────────────────────────────

/**
 * @param {string} workspaceId
 * @param {Array<ParsedFile>} parsedFiles
 * @returns {Graph}
 */
export function buildDependencyGraph(workspaceId, parsedFiles) {
  const graph = {
    imports:     new Map(),   // filePath → Set<filePath> (files it imports)
    importedBy:  new Map(),   // filePath → Set<filePath> (files that import it)
    inheritance: new Map(),   // className → { file, extends }
    builtAt:     Date.now(),
  };

  const pathSet = new Set(parsedFiles.map(f => f.path));

  for (const file of parsedFiles) {
    if (!graph.imports.has(file.path)) graph.imports.set(file.path, new Set());

    for (const imp of file.imports ?? []) {
      // Only track local imports (relative paths)
      if (imp.startsWith('.') || imp.startsWith('/')) {
        const resolved = _resolveLocal(file.path, imp, pathSet);
        if (resolved) {
          graph.imports.get(file.path).add(resolved);
          if (!graph.importedBy.has(resolved)) graph.importedBy.set(resolved, new Set());
          graph.importedBy.get(resolved).add(file.path);
        }
      }
    }

    // Track class inheritance
    for (const cls of file.classes ?? []) {
      const name = typeof cls === 'string' ? cls : cls.name;
      const ext  = typeof cls === 'object' ? cls.extends : null;
      if (name) graph.inheritance.set(name, { file: file.path, extends: ext });
    }
  }

  graphs.set(workspaceId, graph);
  console.log(`[GRAPH] Dependencies updated workspace=${workspaceId} files=${parsedFiles.length}`);
  return graph;
}

// Resolve a relative import path against the known file set
function _resolveLocal(fromPath, importPath, pathSet) {
  const fromDir = fromPath.replace(/\\/g, '/').split('/').slice(0, -1).join('/');
  const base    = fromDir ? `${fromDir}/${importPath}` : importPath;

  const candidates = [
    base,
    `${base}.js`,   `${base}.ts`,   `${base}.jsx`,  `${base}.tsx`,
    `${base}/index.js`, `${base}/index.ts`,
  ];

  for (const c of candidates) {
    const norm = _normPath(c);
    if (pathSet.has(norm)) return norm;
  }
  return null;
}

function _normPath(p) {
  const parts = p.replace(/\\/g, '/').split('/');
  const out = [];
  for (const part of parts) {
    if (part === '..') out.pop();
    else if (part !== '.') out.push(part);
  }
  return out.join('/');
}

// ── Query ─────────────────────────────────────────────────────────────────────

export function getGraph(workspaceId) {
  return graphs.get(workspaceId) ?? null;
}

export function clearGraph(workspaceId) {
  graphs.delete(workspaceId);
}

/** Files that import the given file */
export function whoImports(workspaceId, filePath) {
  const graph = graphs.get(workspaceId);
  return graph ? [...(graph.importedBy.get(filePath) ?? [])] : [];
}

/** Files that the given file imports */
export function whatImports(workspaceId, filePath) {
  const graph = graphs.get(workspaceId);
  return graph ? [...(graph.imports.get(filePath) ?? [])] : [];
}

/**
 * Serialise graph to adjacency list (JSON-safe, no Sets).
 * Only includes files with at least one local dependency.
 */
export function serializeGraph(workspaceId) {
  const graph = graphs.get(workspaceId);
  if (!graph) return null;

  const adj = {};
  for (const [file, deps] of graph.imports.entries()) {
    if (deps.size > 0) adj[file] = [...deps];
  }
  return adj;
}

/**
 * Detect dependency cycles using DFS.
 * Returns array of cycle paths (each path is an array of file names).
 */
export function detectCycles(workspaceId) {
  const graph = graphs.get(workspaceId);
  if (!graph) return [];

  const cycles   = [];
  const visited  = new Set();
  const inStack  = new Set();

  function dfs(node, stack) {
    visited.add(node);
    inStack.add(node);
    stack.push(node);

    for (const dep of graph.imports.get(node) ?? []) {
      if (!visited.has(dep)) {
        dfs(dep, stack);
      } else if (inStack.has(dep)) {
        const idx = stack.indexOf(dep);
        cycles.push(stack.slice(idx).concat(dep));
      }
    }

    stack.pop();
    inStack.delete(node);
  }

  for (const file of graph.imports.keys()) {
    if (!visited.has(file)) dfs(file, []);
  }

  return cycles;
}

/**
 * AQUA Project Summarizer
 *
 * Generates concise summaries from parsed file metadata.
 * Uses heuristic / structural analysis — no LLM calls.
 * This keeps the indexing pipeline synchronous and fast.
 *
 * LLM-quality summarization happens later, lazily, if needed,
 * by passing file content through the normal chat pipeline.
 */
import path from 'path';

// ── File summary ──────────────────────────────────────────────────────────────

/**
 * Generate a one-line summary for a file from its parsed metadata.
 *
 * @param {ParsedFile} parsedFile
 * @returns {string}
 */
export function summarizeFile(parsedFile) {
  const { path: filePath, lang, functions, classes, imports, exports, comments, dependencies } = parsedFile;
  const filename = path.basename(filePath);
  const parts    = [];

  // Leading doc comment gives the best purpose hint
  if (comments?.length > 0) {
    parts.push(comments[0].slice(0, 160));
  }

  const langLabel = lang && lang !== 'unknown' ? ` [${lang}]` : '';
  parts.push(`${filename}${langLabel}`);

  const classNames = (classes ?? [])
    .map(c => typeof c === 'string' ? c : c.name)
    .filter(Boolean);
  if (classNames.length) parts.push(`Classes: ${classNames.slice(0, 5).join(', ')}`);
  if (functions?.length) parts.push(`Functions: ${functions.slice(0, 8).join(', ')}`);
  if (exports?.length)   parts.push(`Exports: ${exports.slice(0, 6).join(', ')}`);
  if (dependencies?.length) parts.push(`Deps: ${dependencies.slice(0, 8).join(', ')}`);

  // Semantic role from path
  const role = _inferRole(filePath);
  if (role) parts.push(`Role: ${role}`);

  return parts.filter(Boolean).join(' | ');
}

// ── Directory summary ─────────────────────────────────────────────────────────

/**
 * Summarize a directory from file summaries within it.
 *
 * @param {string} dirPath
 * @param {Array<{path, summary}>} fileSummaries
 * @returns {string}
 */
export function summarizeDirectory(dirPath, fileSummaries) {
  const n = fileSummaries.length;
  if (n === 0) return `${dirPath}: empty`;

  const names = fileSummaries
    .slice(0, 4)
    .map(f => path.basename(f.path))
    .join(', ');

  return `${dirPath}: ${n} file${n > 1 ? 's' : ''} — ${names}${n > 4 ? ` + ${n - 4} more` : ''}`;
}

// ── Project summary ───────────────────────────────────────────────────────────

/**
 * Generate a project-level architecture summary.
 *
 * @param {{ projectType: string }} workspace
 * @param {ParsedFile[]} parsedFiles
 * @returns {string}
 */
export function summarizeProject(workspace, parsedFiles) {
  const { projectType } = workspace;
  const fileCount = parsedFiles.length;

  // Language breakdown
  const langs = {};
  for (const f of parsedFiles) langs[f.lang] = (langs[f.lang] ?? 0) + 1;
  const langStr = Object.entries(langs)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([l, n]) => `${l}(${n})`)
    .join(', ');

  // Entry points
  const entries = parsedFiles
    .filter(f => _isEntryPoint(f.path))
    .map(f => f.path)
    .slice(0, 4);

  // Top-level directories
  const topDirs = _topLevelDirs(parsedFiles.map(f => f.path));

  // Most exported symbols (could be public API)
  const allExports = parsedFiles.flatMap(f => f.exports ?? []);
  const exportCounts = {};
  for (const e of allExports) exportCounts[e] = (exportCounts[e] ?? 0) + 1;

  const lines = [
    `Type: ${projectType ?? 'unknown'} | Files: ${fileCount} | Languages: ${langStr}`,
  ];
  if (topDirs.length)  lines.push(`Top-level dirs: ${topDirs.join(', ')}`);
  if (entries.length)  lines.push(`Entry points: ${entries.join(', ')}`);

  return lines.join('\n');
}

// ── Batch enrichment ──────────────────────────────────────────────────────────

/**
 * Attach a generated summary to each parsed file.
 * Returns new array (does not mutate).
 *
 * @param {ParsedFile[]} parsedFiles
 * @returns {Array<ParsedFile & { summary: string, summaryAt: number }>}
 */
export function enrichWithSummaries(parsedFiles) {
  return parsedFiles.map(f => ({
    ...f,
    summary:   summarizeFile(f),
    summaryAt: Date.now(),
  }));
}

// ── Helpers ───────────────────────────────────────────────────────────────────

const ENTRY_BASENAMES = new Set([
  'index.js', 'index.ts', 'index.jsx', 'index.tsx',
  'main.js',  'main.ts',  'main.jsx',  'main.tsx',
  'app.js',   'app.ts',   'app.jsx',   'app.tsx',
  'server.js','server.ts','server.jsx','server.tsx',
  'main.py',  'app.py',   '__main__.py',
  'main.go',  'main.rs',  'index.html',
]);

function _isEntryPoint(filePath) {
  return ENTRY_BASENAMES.has(path.basename(filePath).toLowerCase());
}

function _topLevelDirs(paths) {
  const dirs = new Set();
  for (const p of paths) {
    const parts = p.replace(/\\/g, '/').split('/');
    if (parts.length > 1) dirs.add(parts[0]);
  }
  return [...dirs].slice(0, 8);
}

const ROLE_PATTERNS = [
  [/auth|login|session|jwt|token/i,       'authentication'],
  [/route|controller|handler/i,           'routing/controller'],
  [/model|schema|entity|orm/i,            'data model'],
  [/service|business|logic/i,             'business logic'],
  [/repo|repository|dao/i,                'data access'],
  [/middleware|interceptor|filter/i,       'middleware'],
  [/config|setting|constant|env/i,        'configuration'],
  [/util|helper|common|shared/i,          'utilities'],
  [/test|spec|__test__|\.test\.|\.spec\./i,'tests'],
  [/migration|seed/i,                     'database migration'],
  [/component|widget/i,                   'UI component'],
  [/store|redux|context|state/i,          'state management'],
  [/hook|use[A-Z]/,                       'React hook'],
];

function _inferRole(filePath) {
  for (const [pattern, role] of ROLE_PATTERNS) {
    if (pattern.test(filePath)) return role;
  }
  return null;
}

/**
 * AQUA Edit Engine (Day 4) — patch-first repository editing.
 *
 * Pipeline (proposeEdit):
 *   1. LOCATE   — reuse the existing retriever scoring + index to pick target
 *                 files; inject their FULL content (index keeps content in
 *                 memory — no rescan, no re-upload).
 *   2. GENERATE — one structured LLM call (via the existing provider router,
 *                 so ranking/fallback/circuit-breaker all apply) that returns
 *                 MINIMAL search/replace operations per file — never whole-file
 *                 regeneration unless the file is being created.
 *   3. APPLY-IN-MEMORY — operations are applied to copies of the indexed
 *                 content. Exact match first, whitespace-tolerant fuzzy match
 *                 second. A failed operation never corrupts anything — it is
 *                 reported with a reason and suggestion.
 *   4. DIFF     — diffEngine produces structured hunks + unified text + stats
 *                 for the preview UI.
 *   5. VERIFY   — deterministic static checks (bracket balance, JSON validity,
 *                 local-import resolution against the index, removed-export
 *                 breakage via the dependency graph). Warnings only when
 *                 confidence is high — no invented issues.
 *   6. RELATE   — dependency graph (whoImports) recommends files that may
 *                 need follow-up changes.
 *
 * Safe apply (applyProposal):
 *   - Proposal must exist and be in 'proposed' state.
 *   - Every target file's CURRENT index content must hash-match the content
 *     the patch was generated against (baseHash). Any mismatch → conflict,
 *     nothing is applied (atomic).
 *   - On success the index + dependency graph + workspace metadata are
 *     rebuilt through the EXISTING buildIndex/buildDependencyGraph/
 *     enrichWithSummaries pipeline — no parallel indexing system.
 *   - Previous contents are retained → revertProposal() restores them.
 *
 * NOTHING here touches disk. The workspace model is in-memory-indexed
 * uploaded source; "apply" means the index (and everything grounded on it —
 * retrieval, chat answers, future patches) now sees the edited code.
 */

import { generateText }          from '../providers/router.js';
import { createContext }         from '../core/observability.js';
import { getFocusRisks }         from '../intelligence/critic.js';
import { getIndex, buildIndex, getIndexStats, syncSummaries } from './projectIndex.js';
import { getWorkspace, updateWorkspace }       from './workspaceManager.js';
import { buildDependencyGraph, whoImports }    from './dependencyGraph.js';
import { enrichWithSummaries }   from './projectSummarizer.js';
import { diffFile }              from './diffEngine.js';
import { v4 as uuidv4 }          from 'uuid';

// ── Proposal store (in-memory, like the index it patches) ────────────────────
// workspaceId → Map<proposalId, proposal>
const proposals = new Map();

const MAX_TARGET_FILES     = 6;
const MAX_PROMPT_CHARS     = 60_000;  // total file content injected into the edit prompt
const MAX_FILE_CHARS       = 24_000;  // single file cap
const EDIT_RESPONSE_BUDGET = { maxResponseTokens: 4096 };

// ── Hashing (conflict detection) ──────────────────────────────────────────────

export function contentHash(str = '') {
  let h = 5381;
  for (let i = 0; i < str.length; i++) h = ((h << 5) + h + str.charCodeAt(i)) >>> 0;
  return h.toString(16).padStart(8, '0') + ':' + str.length;
}

// ── 1. LOCATE ─────────────────────────────────────────────────────────────────

/**
 * Pick the files most relevant to the instruction and return them with FULL
 * content from the index. Reuses the same signal the retriever uses
 * (path keywords, symbols, imports) — no new scoring system.
 */
export function locateTargetFiles(workspaceId, instruction, limit = MAX_TARGET_FILES) {
  const index = getIndex(workspaceId);
  if (!index) return { files: [], allPaths: [] };

  const words = [...new Set(
    instruction.toLowerCase().split(/[^a-z0-9_$]+/i).filter(w => w.length > 2),
  )];

  const scored = [];
  for (const [path, entry] of index.byPath.entries()) {
    let score = 0;
    const lowerPath = path.toLowerCase();
    for (const w of words) {
      if (lowerPath.includes(w)) score += 4;
      if (index.bySymbol.has(w)) {
        for (const hit of index.bySymbol.get(w)) if (hit.path === path) score += 6;
      }
    }
    // symbol names in the entry that appear in the instruction (case-sensitive identifiers)
    for (const fn of entry.functions ?? []) {
      if (fn.length > 3 && instruction.includes(fn)) score += 8;
    }
    if (entry.content) {
      let contentHits = 0;
      for (const w of words) {
        if (entry.content.toLowerCase().includes(w)) contentHits++;
      }
      score += Math.min(contentHits, 5);
    }
    if (score > 0) scored.push({ path, entry, score });
  }
  scored.sort((a, b) => b.score - a.score);

  let budget = MAX_PROMPT_CHARS;
  const files = [];
  for (const { path, entry, score } of scored) {
    if (files.length >= limit || budget <= 0) break;
    const content = (entry.content ?? '').slice(0, MAX_FILE_CHARS);
    if (!content) continue;
    files.push({ path, lang: entry.lang, content, score });
    budget -= content.length;
  }

  return { files, allPaths: [...index.byPath.keys()] };
}

// ── 2. GENERATE (LLM structured edits) ────────────────────────────────────────

function buildEditSystemPrompt(focusRisks) {
  return [
    'You are AQUA\'s repository editing engine. You produce MINIMAL, SURGICAL edits to an indexed codebase.',
    '',
    'HARD RULES:',
    '- NEVER rewrite a whole existing file. Express changes as small search/replace operations.',
    '- "search" must be copied EXACTLY from the provided file content (including indentation) and must be unique within the file. Use 2–6 lines of surrounding context to make it unique.',
    '- Only edit files whose content was provided. New files may be created with the "create" field.',
    '- Keep the existing code style of each file.',
    '- Prefer the smallest change that fully accomplishes the instruction.',
    `- Pay attention to these risk areas: ${focusRisks.join(', ')}.`,
    '',
    'Respond with ONLY a JSON object (no markdown fences, no prose) in exactly this shape:',
    '{',
    '  "summary": "one-sentence description of the change",',
    '  "reasoning": "why this approach",',
    '  "impact": "expected behavioral impact",',
    '  "risks": ["potential risk", ...],',
    '  "breakingChanges": ["breaking change", ...] ,',
    '  "edits": [',
    '    {',
    '      "file": "path/exactly/as/provided.js",',
    '      "explanation": "why this file changes",',
    '      "operations": [',
    '        { "type": "replace", "search": "exact existing snippet", "replace": "new snippet" },',
    '        { "type": "insert_after", "anchor": "exact existing snippet", "content": "new lines" },',
    '        { "type": "insert_before", "anchor": "exact existing snippet", "content": "new lines" },',
    '        { "type": "append", "content": "lines appended to end of file" }',
    '      ]',
    '    },',
    '    { "file": "path/new-file.js", "explanation": "why created", "create": "full file content" }',
    '  ]',
