  'esbuild.config.js': 'esbuild', 'tailwind.config.js': 'Tailwind CLI',
  'tailwind.config.ts': 'Tailwind CLI', 'gulpfile.js': 'Gulp',
};

const CONFIG_BASENAMES = /^(\.env|\.eslintrc|eslint\.config|\.prettierrc|prettier\.config|tsconfig|jsconfig|vite\.config|webpack\.config|next\.config|nuxt\.config|babel\.config|jest\.config|vitest\.config|tailwind\.config|postcss\.config|rollup\.config|docker-compose|dockerfile|makefile|procfile|nodemon\.json|\.nvmrc|\.editorconfig|renovate\.json|netlify\.toml|vercel\.json|fly\.toml|pyproject\.toml|setup\.py|setup\.cfg|requirements.*\.txt|go\.mod|cargo\.toml|pom\.xml|build\.gradle|composer\.json|gemfile)/i;

// Route extraction: Express/Koa/Fastify + Python decorators + Next.js API dirs
const JS_ROUTE_RE = /(?:router|app|api|server|fastify)\s*\.\s*(get|post|put|patch|delete|all|use)\s*\(\s*['"`]([^'"`]+)['"`]/g;
const PY_ROUTE_RE = /@(?:app|router|api|bp|blueprint)\.\s*(?:route\s*\(\s*['"]([^'"]+)['"](?:.*methods\s*=\s*\[([^\]]+)\])?|(get|post|put|patch|delete)\s*\(\s*['"]([^'"]+)['"])/g;
const ENV_JS_RE   = /process\.env\.([A-Z][A-Z0-9_]{1,60})|import\.meta\.env\.([A-Z][A-Z0-9_]{1,60})/g;
const ENV_PY_RE   = /os\.(?:environ(?:\.get)?|getenv)\s*[[(]\s*['"]([A-Z][A-Z0-9_]{1,60})['"]/g;
const TODO_RE     = /(?:\/\/|#|\/\*|\*|<!--)\s*(TODO|FIXME|HACK|XXX)\b[:\s]?(.{0,100})/g;

// ── Main entry ────────────────────────────────────────────────────────────────

/**
 * Analyze a workspace from already-ingested + enriched files.
 * Pure function of its inputs — no index re-reads, no filesystem access.
 *
 * @param {object} args
 * @param {string} args.workspaceName    from workspace.meta.name (may be empty)
 * @param {string} args.projectType     from detectProjectType()
 * @param {Array}  args.files           enriched ingested files [{path, content, lang, size, functions, classes, exports, imports, comments, dependencies, summary}]
 * @param {object} [args.graph]         serialized dependency graph { nodes, edges } (optional)
 * @param {Array}  [args.cycles]        dependency cycles (optional)
 * @returns {{ overview: object, warnings: string[] }}
 */
export function analyzeWorkspace({ workspaceName, projectType, files, graph, cycles }) {
  const warnings = [];
  const overview = {
    generatedAt: Date.now(),
    partial:     false,
  };

  const run = (section, fn) => {
    try {
      Object.assign(overview, fn());
    } catch (err) {
      overview.partial = true;
      warnings.push(`${section}: ${err.message}`);
      console.warn(`[ANALYZER] Section '${section}' failed:`, err.message);
    }
  };

  const manifests = _readManifests(files);

  run('identity',     () => _identity(workspaceName, projectType, files, manifests));
  run('stack',        () => _stack(files, manifests, projectType));
  run('structure',    () => _structure(files));
  run('envConfig',    () => _envAndConfig(files));
  run('entryPoints',  () => _entryAndCore(files, graph));
  run('apiRoutes',    () => ({ apiRoutes: _extractRoutes(files) }));
  run('integrations', () => _integrations(manifests));
  run('statistics',   () => _statistics(files, graph));
  run('todos',        () => _todos(files));
  run('techDebt',     () => _techDebt(files, cycles, overview));
  run('architecture', () => ({ architecture: _architecture(files, manifests, overview) }));
  run('improvements', () => ({ suggestedImprovements: _improvements(files, overview) }));
  run('questions',    () => ({ suggestedQuestions: _questions(overview) }));

  overview.warnings = warnings;
  return { overview, warnings };
}

// ── Manifest reading (package.json / requirements / etc.) ─────────────────────

function _readManifests(files) {
  const out = { pkg: null, pkgAll: [], pyDeps: [], goMod: false, cargo: false };
  for (const f of files) {
    const base = path.basename(f.path).toLowerCase();
    if (base === 'package.json') {
      try {
        const pkg = JSON.parse(f.content);
        out.pkgAll.push({ path: f.path, pkg });
        // Root package.json wins (shortest path depth)
        if (!out.pkg || f.path.split('/').length < out.pkg.depth) {
          out.pkg = { ...pkg, depth: f.path.split('/').length };
        }
      } catch { /* malformed */ }
    }
    if (base === 'requirements.txt') {
      out.pyDeps.push(...f.content.split('\n')
        .map(l => l.trim().split(/[=<>!~;\[]/)[0])
        .filter(l => l && !l.startsWith('#')));
    }
    if (base === 'pyproject.toml') out.pyProject = true;
    if (base === 'go.mod')         out.goMod = true;
    if (base === 'cargo.toml')     out.cargo = true;
  }
  // Merge dependencies from ALL package.json files (monorepos)
  out.allDeps = {};
  for (const { pkg } of out.pkgAll) {
    Object.assign(out.allDeps, pkg.dependencies ?? {}, pkg.devDependencies ?? {});
  }
  return out;
}

// ── Identity ──────────────────────────────────────────────────────────────────

function _identity(workspaceName, projectType, files, manifests) {
  const pkg = manifests.pkg;
  const name = workspaceName || pkg?.name || 'Untitled project';

  // Purpose: package.json description > README first meaningful paragraph
  let purpose = pkg?.description ?? null;
  if (!purpose) {
    const readme = files.find(f => /^readme\.mdx?$/i.test(path.basename(f.path)));
    if (readme) {
      const para = readme.content
        .split('\n')
        .map(l => l.trim())
        .find(l => l.length > 30 && !l.startsWith('#') && !l.startsWith('!') && !l.startsWith('['));
      if (para) purpose = para.slice(0, 240);
    }
  }

  const langs = _langCounts(files);
  const topLangs = Object.keys(langs).slice(0, 3).join(', ');
  const summary = `${name} is a ${_typeLabel(projectType)} project with ${files.length} source files, primarily ${topLangs || 'mixed languages'}.`;

  return { name, purpose: purpose ?? 'No description found in package.json or README.', summary, projectType };
}

function _typeLabel(t) {
  return ({
    'nodejs-next': 'Next.js', 'nodejs-react': 'React', 'nodejs-express': 'Node.js/Express',
    'nodejs-vue': 'Vue', nodejs: 'Node.js', python: 'Python', go: 'Go', rust: 'Rust',
    java: 'Java', php: 'PHP', ruby: 'Ruby', csharp: 'C#', cpp: 'C++',
  })[t] ?? (t || 'software');
}

function _langCounts(files) {
  const counts = {};
  for (const f of files) if (f.lang && f.lang !== 'unknown') counts[f.lang] = (counts[f.lang] ?? 0) + 1;
  return Object.fromEntries(Object.entries(counts).sort((a, b) => b[1] - a[1]));
}

// ── Tech stack ────────────────────────────────────────────────────────────────

function _stack(files, manifests, projectType) {
  const deps = { ...manifests.allDeps };
  for (const d of manifests.pyDeps) deps[d.toLowerCase()] = '*';

  const pick = (table) => {
    const hits = new Set();
    for (const [dep, label] of Object.entries(table)) if (deps[dep]) hits.add(label);
    return [...hits];
  };

  const frameworks = pick(FRAMEWORK_DEPS);
  if (deps.django) frameworks.push('Django');
  if (deps.flask) frameworks.push('Flask');
  if (deps.fastapi) frameworks.push('FastAPI');

  // Runtime
  const runtimes = [];
  if (manifests.pkg || projectType?.startsWith('nodejs')) {
    const engine = manifests.pkg?.engines?.node;
    runtimes.push(engine ? `Node.js ${engine}` : 'Node.js');
    if (manifests.pkg?.type === 'module') runtimes.push('ESM modules');
  }
  if (manifests.pyDeps.length || manifests.pyProject || projectType === 'python') runtimes.push('Python');
  if (manifests.goMod)  runtimes.push('Go');
  if (manifests.cargo)  runtimes.push('Rust');
  if (files.some(f => f.lang === 'typescript')) runtimes.push('TypeScript');

  // Package managers — lockfiles are filtered at ingest, so infer from manifests
  const packageManagers = [];
  if (manifests.pkg)             packageManagers.push('npm / yarn / pnpm');
  if (manifests.pyDeps.length)   packageManagers.push('pip');
  if (manifests.pyProject)       packageManagers.push('poetry / pip');
  if (manifests.goMod)           packageManagers.push('go modules');
  if (manifests.cargo)           packageManagers.push('cargo');

  // Build tools from config file presence
  const buildTools = new Set();
  for (const f of files) {
    const base = path.basename(f.path).toLowerCase();
    if (BUILD_TOOL_FILES[base]) buildTools.add(BUILD_TOOL_FILES[base]);
  }

  // Major dependencies — top runtime deps by name from root pkg
  const majorDependencies = Object.keys(manifests.pkg?.dependencies ?? {}).slice(0, 15);
  if (!majorDependencies.length && manifests.pyDeps.length) majorDependencies.push(...manifests.pyDeps.slice(0, 15));

  return {
    languages:       _langCounts(files),
    frameworks:      [...new Set(frameworks)],
    runtime:         runtimes,
    packageManagers,
    buildTools:      [...buildTools],
    frontendTech:    pick(FRONTEND_DEPS),
    backendTech:     pick(BACKEND_DEPS),
    databaseTech:    pick(DB_DEPS),
    authMethods:     _authMethods(files, deps),
    majorDependencies,
    dependencyCount: Object.keys(manifests.allDeps).length + manifests.pyDeps.length,
  };
}

function _authMethods(files, deps) {
  const methods = new Set();
  for (const [dep, label] of Object.entries(AUTH_DEPS)) if (deps[dep]) methods.add(label);
  // Path-based signals for hand-rolled auth
  const authFiles = files.filter(f => /auth|login|session|jwt/i.test(f.path));
  if (authFiles.length && !methods.size) methods.add(`Custom auth (${authFiles.length} auth-related files)`);
  return [...methods];
}

// ── Structure ─────────────────────────────────────────────────────────────────

function _structure(files) {
  const dirCounts = {};
  const dirSizes  = {};
  for (const f of files) {
    const parts = f.path.replace(/\\/g, '/').split('/');
    // Count at up to 2 levels deep
    for (const depth of [1, 2]) {
      if (parts.length > depth) {
        const dir = parts.slice(0, depth).join('/');
        dirCounts[dir] = (dirCounts[dir] ?? 0) + 1;
        dirSizes[dir]  = (dirSizes[dir] ?? 0) + (f.size ?? 0);
      }
    }
  }
  const folderStructure = Object.entries(dirCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 14)
    .map(([dir, count]) => ({ dir, files: count, bytes: dirSizes[dir] ?? 0 }));

  const largestFolders = Object.entries(dirSizes)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 6)
    .map(([dir, bytes]) => ({ dir, bytes }));

  return { folderStructure, largestFolders };
}

// ── Env vars + config files ───────────────────────────────────────────────────

function _envAndConfig(files) {
  const envVars = new Set();
  const configFiles = [];

  for (const f of files) {
    const base = path.basename(f.path);
    if (CONFIG_BASENAMES.test(base)) configFiles.push(f.path);

    if (f.lang === 'env') {
      for (const line of f.content.split('\n')) {
        const m = line.match(/^([A-Z][A-Z0-9_]+)\s*=/);
        if (m) envVars.add(m[1]);
      }
      continue;
    }
    if (['javascript', 'typescript'].includes(f.lang)) {
      for (const m of f.content.matchAll(ENV_JS_RE)) envVars.add(m[1] ?? m[2]);
    } else if (f.lang === 'python') {
      for (const m of f.content.matchAll(ENV_PY_RE)) envVars.add(m[1]);
    }
  }
  return {
    envVars: [...envVars].sort().slice(0, 40),
    configFiles: configFiles.sort().slice(0, 25),
  };
}

// ── Entry points + core modules + services ────────────────────────────────────

const ENTRY_BASENAMES = new Set([
  'index.js', 'index.ts', 'index.jsx', 'index.tsx', 'main.js', 'main.ts', 'main.jsx',
  'main.tsx', 'app.js', 'app.ts', 'app.jsx', 'app.tsx', 'server.js', 'server.ts',
  'main.py', 'app.py', '__main__.py', 'main.go', 'main.rs', 'index.html',
]);

function _entryAndCore(files, graph) {
  const entryPoints = files
    .filter(f => ENTRY_BASENAMES.has(path.basename(f.path).toLowerCase()))
    .map(f => f.path)
    .sort((a, b) => a.split('/').length - b.split('/').length)
    .slice(0, 6);

  // Core modules = most-imported files (in-degree in dependency graph).
  // serializeGraph() returns an adjacency map { file: [localDeps] } —
  // in-degree = how many files list a given file as a dependency.
  // Fallback when the graph is empty: files exporting the most symbols.
  let coreModules = [];
  if (graph && typeof graph === 'object') {
    const inDegree = {};
    for (const deps of Object.values(graph)) {
      for (const dep of deps ?? []) inDegree[dep] = (inDegree[dep] ?? 0) + 1;
    }
    coreModules = Object.entries(inDegree)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 8)
      .map(([file, importedBy]) => ({ file, importedBy }));
  }
  if (!coreModules.length) {
    coreModules = files
      .map(f => ({ file: f.path, exports: (f.exports ?? []).length }))
      .filter(x => x.exports > 0)
      .sort((a, b) => b.exports - a.exports)
      .slice(0, 8)
      .map(({ file, exports: n }) => ({ file, importedBy: 0, exports: n }));
  }

  const services = files
    .filter(f => /service|provider|client|engine|manager|store|repository/i.test(path.basename(f.path)) && !/test|spec/i.test(f.path))
    .map(f => ({ file: f.path, summary: (f.summary ?? '').split('|')[0]?.trim().slice(0, 100) }))
    .slice(0, 10);

  return { entryPoints, coreModules, importantServices: services };
}

// ── API route extraction ──────────────────────────────────────────────────────

function _extractRoutes(files) {
  const routes = [];
  for (const f of files) {
    if (['javascript', 'typescript'].includes(f.lang)) {
      for (const m of f.content.matchAll(JS_ROUTE_RE)) {
        const method = m[1].toUpperCase();
        if (method === 'USE' && !m[2].startsWith('/')) continue;
        routes.push({ method: method === 'USE' ? 'MOUNT' : method, path: m[2], file: f.path });
      }
      // Next.js file-system API routes
      if (/(?:^|\/)(?:pages|app)\/api\//.test(f.path)) {
        routes.push({ method: 'FS', path: '/' + f.path.replace(/^.*?(?:pages|app)\//, '').replace(/\.(js|ts)x?$/, '').replace(/\/route$/, ''), file: f.path });
      }
    } else if (f.lang === 'python') {
      for (const m of f.content.matchAll(PY_ROUTE_RE)) {
        const p = m[1] ?? m[4];
        const method = m[3] ? m[3].toUpperCase() : (m[2] ? m[2].replace(/['"\s]/g, '').toUpperCase() : 'GET');
        if (p) routes.push({ method, path: p, file: f.path });
      }
    }
  }
  // Dedupe, cap
  const seen = new Set();
  return routes.filter(r => {
    const k = `${r.method} ${r.path}`;
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  }).slice(0, 60);
}

// ── Integrations ──────────────────────────────────────────────────────────────

function _integrations(manifests) {
  const deps = manifests.allDeps;
  const hits = new Set();
  for (const [dep, label] of Object.entries(INTEGRATION_DEPS)) if (deps[dep]) hits.add(label);
  for (const d of manifests.pyDeps) {
    const l = d.toLowerCase();
    if (l === 'openai') hits.add('OpenAI API');
    if (l === 'anthropic') hits.add('Anthropic API');
    if (l === 'stripe') hits.add('Stripe payments');
    if (l === 'boto3') hits.add('AWS SDK');
    if (l === 'groq') hits.add('Groq API');
  }
  return { externalIntegrations: [...hits] };
}

// ── Statistics ────────────────────────────────────────────────────────────────

function _statistics(files, graph) {
  let totalBytes = 0, functions = 0, classes = 0, components = 0, interfaces = 0;
  for (const f of files) {
    totalBytes += f.size ?? 0;
    functions  += (f.functions ?? []).length;
    classes    += (f.classes ?? []).length;
    interfaces += (f.interfaces ?? []).length;
    if (/\.(jsx|tsx)$/.test(f.path) || /component/i.test(f.path)) components++;
  }
  return {
    stats: {
      fileCount:      files.length,
      totalBytes,
      totalKB:        Math.round(totalBytes / 1024),
      functions,
      classes,
      interfaces,
      components,
      dependencyEdges: graph && typeof graph === 'object'
        ? Object.values(graph).reduce((n, deps) => n + (deps?.length ?? 0), 0)
        : 0,
      configFileCount: files.filter(f => CONFIG_BASENAMES.test(path.basename(f.path))).length,
    },
  };
}

// ── TODO / FIXME ──────────────────────────────────────────────────────────────

function _todos(files) {
  const items = [];
  let count = 0;
  for (const f of files) {
    if (['json', 'markdown', 'env'].includes(f.lang)) continue;
    for (const m of f.content.matchAll(TODO_RE)) {
      count++;
      if (items.length < 20) {
        items.push({ tag: m[1].toUpperCase(), text: m[2].trim().slice(0, 90), file: f.path });
      }
    }
  }
  return { todoCount: count, todos: items };
}

// ── Technical debt heuristics ─────────────────────────────────────────────────

function _techDebt(files, cycles, overview) {
  const debt = [];
  const large = files.filter(f => (f.size ?? 0) > 40_000);
  if (large.length) debt.push(`${large.length} very large files (>40KB) — candidates for splitting: ${large.slice(0, 3).map(f => f.path).join(', ')}`);

  const truncated = files.filter(f => f.truncated);
  if (truncated.length) debt.push(`${truncated.length} files exceeded the 100KB ingest cap and were truncated during indexing.`);

  if (cycles?.length) debt.push(`${cycles.length} circular dependency chain${cycles.length > 1 ? 's' : ''} detected — e.g. ${cycles[0].slice(0, 3).join(' → ')}.`);

  if ((overview.todoCount ?? 0) > 15) debt.push(`High TODO/FIXME density (${overview.todoCount} markers) suggests deferred work accumulating.`);

  const hasTests = files.some(f => /\.(test|spec)\.[jt]sx?$|test_.*\.py|_test\.go/i.test(f.path));
  if (!hasTests) debt.push('No test files detected — the project has no automated test coverage.');

  const dupNames = _duplicateBasenames(files);
  if (dupNames.length > 5) debt.push(`${dupNames.length} duplicated file basenames across folders (e.g. ${dupNames.slice(0, 3).join(', ')}) — possible copy-paste drift.`);

  return { potentialTechDebt: debt };
}

function _duplicateBasenames(files) {
  const seen = {};
  for (const f of files) {
    const b = path.basename(f.path);
    if (b === 'index.js' || b === 'index.ts' || b === '__init__.py') continue;
    seen[b] = (seen[b] ?? 0) + 1;
  }
  return Object.entries(seen).filter(([, n]) => n > 1).map(([b]) => b);
}

// ── Architecture summary ──────────────────────────────────────────────────────

function _architecture(files, manifests, overview) {
  const has = (re) => files.some(f => re.test(f.path));
  const s = {};

  s.frontend = overview.frontendTech?.length
    ? `Built with ${overview.frontendTech.slice(0, 4).join(', ')}${has(/components?\//i) ? '; UI lives in component directories' : ''}.`
    : (has(/\.(jsx|tsx|vue|svelte)$/) ? 'Component-based frontend detected from file types.' : 'No dedicated frontend layer detected.');

  s.backend = overview.backendTech?.length
    ? `${overview.backendTech.slice(0, 4).join(', ')} power the server side${has(/routes?\//i) ? ', organized around route modules' : ''}.`
    : (has(/server|api|backend/i) ? 'Server-side code present; framework not identified from dependencies.' : 'No dedicated backend layer detected.');

  const routeCount = overview.apiRoutes?.length ?? 0;
  s.apiLayer = routeCount
    ? `${routeCount} HTTP endpoints detected${overview.apiRoutes.some(r => r.method === 'MOUNT') ? ', composed via mounted routers' : ''}.`
    : 'No HTTP endpoints detected in source.';

  s.dataLayer = overview.databaseTech?.length
    ? `Persistence via ${overview.databaseTech.join(', ')}.`
    : (has(/model|schema|store|memory|db/i) ? 'Custom data/persistence modules present (file- or memory-backed); no database driver dependency found.' : 'No data layer detected.');

  s.authFlow = overview.authMethods?.length
    ? overview.authMethods.join(', ') + '.'
    : 'No authentication mechanism detected.';

  s.storage = has(/upload|storage|s3|bucket|file/i)
    ? 'File/storage handling modules present.'
    : 'No dedicated storage layer detected.';

  s.backgroundJobs = (manifests.allDeps.bullmq || manifests.allDeps.bull || manifests.allDeps['node-cron'] || manifests.allDeps.agenda || has(/worker|queue|cron|job/i))
    ? 'Background job / scheduler code detected.'
    : 'No background job system detected.';

  // Service relationships + dependency flow from graph-derived core modules
  const core = overview.coreModules ?? [];
  s.serviceRelationships = core.length
    ? `Most depended-upon modules: ${core.slice(0, 4).map(c => `${path.basename(c.file)} (${c.importedBy || c.exports || 0})`).join(', ')}.`
    : 'Module relationships could not be derived.';

  const entries = overview.entryPoints ?? [];
  s.dependencyFlow = entries.length
    ? `Execution starts at ${entries[0]}; dependencies flow toward core modules like ${core[0]?.file ?? 'shared utilities'}.`
    : 'Entry point not identified.';

  return s;
}

// ── Suggested improvements ────────────────────────────────────────────────────

function _improvements(files, overview) {
  const out = [];
  const debt = overview.potentialTechDebt ?? [];
  if (debt.some(d => d.includes('No test files'))) out.push('Add a test suite — start with the core modules and API routes identified above.');
  if (debt.some(d => d.includes('circular')))       out.push('Break circular dependencies by extracting shared logic into a leaf module.');
  if (debt.some(d => d.includes('very large')))     out.push('Split the largest files into focused modules to improve maintainability.');
  if ((overview.todoCount ?? 0) > 0)                out.push(`Triage the ${overview.todoCount} TODO/FIXME markers — convert stale ones into tracked issues.`);
  if (!(overview.configFiles ?? []).some(c => /docker/i.test(c))) out.push('Add a Dockerfile for reproducible builds and deployment.');
  if (!(overview.envVars ?? []).length && (overview.apiRoutes ?? []).length) out.push('Externalize configuration into environment variables instead of hardcoded values.');
  if (!files.some(f => /^readme/i.test(path.basename(f.path)))) out.push('Add a README documenting setup, architecture, and entry points.');
  if ((overview.authMethods ?? []).length === 0 && (overview.apiRoutes ?? []).length > 5) out.push('API endpoints appear unauthenticated — consider adding an auth layer.');
  return out.slice(0, 6);
}

// ── Suggested questions ───────────────────────────────────────────────────────

function _questions(overview) {
  const qs = ['Explain the architecture of this project.', 'Walk me through the folder structure and what each part does.'];
  if (overview.authMethods?.length)          qs.push('How does authentication work in this codebase?');
  if (overview.apiRoutes?.length)            qs.push('Show me every API endpoint and what it does.');
  if (overview.databaseTech?.length)         qs.push(`How is data stored and accessed via ${overview.databaseTech[0]}?`);
  if (overview.entryPoints?.length)          qs.push(`Trace what happens when ${overview.entryPoints[0]} starts up.`);
  if (overview.coreModules?.length)          qs.push(`Explain what ${overview.coreModules[0].file} does and what depends on it.`);
  if (overview.externalIntegrations?.length) qs.push(`How is the ${overview.externalIntegrations[0]} integration implemented?`);
  if (overview.todoCount > 0)                qs.push('Which TODO items should I prioritize first?');
  qs.push('Where should I start if I want to add a new feature?');
  return qs.slice(0, 8);
}

// ── Condensed prompt block (for repository chat) ──────────────────────────────

/**
 * Format the cached overview into a compact block for system-prompt injection.
 * Kept small (~short paragraph scale) — detail comes from per-file retrieval.
 */
export function formatOverviewForPrompt(overview) {
  if (!overview) return '';
  const l = [];
  l.push(`Project: ${overview.name ?? 'unknown'} (${overview.projectType ?? 'unknown'})`);
  if (overview.purpose)                    l.push(`Purpose: ${overview.purpose}`);
  if (overview.frameworks?.length)         l.push(`Frameworks: ${overview.frameworks.join(', ')}`);
  if (overview.databaseTech?.length)       l.push(`Database: ${overview.databaseTech.join(', ')}`);
  if (overview.authMethods?.length)        l.push(`Auth: ${overview.authMethods.join(', ')}`);
  if (overview.entryPoints?.length)        l.push(`Entry points: ${overview.entryPoints.slice(0, 3).join(', ')}`);
  if (overview.coreModules?.length)        l.push(`Core modules: ${overview.coreModules.slice(0, 5).map(c => c.file).join(', ')}`);
  if (overview.apiRoutes?.length)          l.push(`API endpoints (${overview.apiRoutes.length}): ${overview.apiRoutes.slice(0, 12).map(r => `${r.method} ${r.path}`).join('; ')}`);
  if (overview.externalIntegrations?.length) l.push(`Integrations: ${overview.externalIntegrations.join(', ')}`);
  if (overview.stats)                      l.push(`Size: ${overview.stats.fileCount} files, ${overview.stats.totalKB}KB, ${overview.stats.functions} functions, ${overview.stats.classes} classes`);
  return l.join('\n');
}

/**
 * AQUA Mind — Prediction Engine (Layer 12)
 * ─────────────────────────────────────────────────────────────────────────────
 * Heuristic forecasts of the user's likely next needs, rebuilt after every
 * turn from working memory + goals + episode + belief profile. Predictions
 * are EPHEMERAL: they bias retrieval and appear in Mind View, but they are
 * never written into beliefs — only real evidence changes the model.
 */
import { CAPS, GOAL_STATUS } from './mindSchema.js';
import { currentFocus } from './workingMemory.js';
import { getActiveGoals } from './goalTracker.js';
import { touchMind } from './mindStore.js';

const clamp = (x) => Math.min(0.97, Math.max(0.05, x));

export function rebuildPredictions(mind, { taskType = 'conversation', workspaceId = null } = {}) {
  const preds = [];
  const focus = currentFocus(mind, 4);
  const goals = getActiveGoals(mind, 4);
  const w = mind.working;

  // 1. Deadline pressure → prep/delivery help
  if (w.deadlines.length) {
    preds.push({
      label: `Likely preparing for: ${w.deadlines[w.deadlines.length - 1].label}`,
      probability: clamp(0.6 + 0.1 * w.deadlines.length),
      basis: 'active deadline in working memory',
    });
  }

  // 2. Blockers → debugging / unblocking requests
  if (w.blockers.length) {
    preds.push({
      label: `Likely needs unblocking on: ${w.blockers[w.blockers.length - 1].text}`,
      probability: clamp(0.55 + 0.1 * w.blockers.length),
      basis: 'unresolved blocker',
    });
  }

  // 3. Task-type momentum — people continue what they were doing
  if (taskType === 'debugging') {
    preds.push({ label: 'Likely to continue debugging this issue', probability: 0.7, basis: 'current task momentum' });
  } else if (taskType === 'architecture') {
    preds.push({ label: 'Likely to request architecture / design advice', probability: 0.65, basis: 'current task momentum' });
  } else if (taskType === 'coding' || workspaceId) {
    preds.push({ label: 'Likely to request code changes in the active workspace', probability: 0.6, basis: 'coding momentum + attached workspace' });
  }

  // 4. Goal gravity — high-priority active goals attract related asks
  for (const g of goals.slice(0, 2)) {
    preds.push({
      label: `Likely working toward: ${g.title}`,
      probability: clamp(0.4 + 0.05 * g.mentions + 0.03 * g.priority),
      basis: `active goal (${g.mentions} mentions)`,
    });
  }

  // 5. Focus topics → likely subject matter (skip internal workspace: markers)
  const topicFocus = focus.filter(f => !f.topic.startsWith('workspace:'));
  if (topicFocus.length) {
    const top = topicFocus[0];
    preds.push({
      label: `Next questions likely about: ${top.topic}`,
      probability: clamp(0.35 + Math.min(0.4, top.weight / 10)),
      basis: 'dominant working-memory focus',
    });
  }

  const deduped = [];
  for (const p of preds.sort((a, b) => b.probability - a.probability)) {
    if (!deduped.some(d => d.label === p.label)) deduped.push(p);
    if (deduped.length >= CAPS.PREDICTIONS) break;
  }

  mind.predictions = deduped.map(p => ({ ...p, probability: +p.probability.toFixed(2), ts: Date.now() }));
  touchMind(mind);
  return mind.predictions;
}

/**
 * AQUA Mind Routes — Layers 17 (explainable), 18 (editable), 19 (privacy)
 * ─────────────────────────────────────────────────────────────────────────────
 * Mounted at /api/aqua/mind. Owner resolution mirrors chat:
 * req.aquaUserId when the platform session exists, else ?conversationId
 * fallback (dev/engine-standalone), else 404 — a Mind must have an owner.
 *
 *   GET    /mind                          — full model summary (Mind View data)
 *   GET    /mind/export                   — complete raw export (user owns it)
 *   GET    /mind/beliefs                  — beliefs (?dimension=&min=)
 *   GET    /mind/beliefs/:dim/:key        — one belief + explanation (Layer 17)
 *   PATCH  /mind/beliefs/:dim/:key        — correct { value } (Layer 18)
 *   POST   /mind/beliefs/:dim/:key/lock   — { locked } pin/unpin
 *   POST   /mind/beliefs/:dim/:key/temporary — { temporary }
 *   DELETE /mind/beliefs/:dim/:key        — delete one belief
 *   PATCH  /mind/goals/:id                — edit goal (status/priority/title)
 *   DELETE /mind/goals/:id                — delete goal
 *   GET    /mind/graph                    — nodes+edges (?around=nodeKey)
 *   GET    /mind/reflections              — reflection history
 *   DELETE /mind                          — erase the entire cognitive model
 *   GET    /mind/view                     — Mind View dev panel (env-gated)
 */
import express from 'express';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { resolveMindOwner, peekMind, getMind, deleteMind, exportMind, mindStats } from './mindStore.js';
import { getBeliefs, explainBelief, correctBelief, lockBelief, markTemporary, deleteBelief } from './beliefEngine.js';
import { getActiveGoals } from './goalTracker.js';
import { getEpisodes } from './episodeTracker.js';
import { neighborhood } from './relationshipGraph.js';
import { recentTimeline } from './timeline.js';
import { currentFocus } from './workingMemory.js';
import { beliefKey, GOAL_STATUS } from './mindSchema.js';
import { touchMind } from './mindStore.js';

const router = express.Router();
const __dir = path.dirname(fileURLToPath(import.meta.url));

function ownerOf(req) {
  return resolveMindOwner({
    userId: req.aquaUserId ?? null,
    conversationId: req.query.conversationId ?? req.body?.conversationId ?? null,
  });
}

function requireMind(req, res) {
  const ownerId = ownerOf(req);
  if (!ownerId) {
    res.status(400).json({ success: false, error: 'No mind owner: log in, or pass ?conversationId= for the dev fallback.' });
    return null;
  }
  const mind = peekMind(ownerId);
  if (!mind) {
    res.status(404).json({ success: false, error: `No cognitive model yet for ${ownerId} — it forms as conversations happen.` });
    return null;
  }
  return mind;
}

// ── Mind View dev panel (never exposed unless enabled) ────────────────────────
router.get('/view', (req, res) => {
  if (process.env.AQUA_MIND_VIEW !== '1') {
    return res.status(404).json({ success: false, error: 'Mind View is disabled. Set AQUA_MIND_VIEW=1 to enable.' });
  }
  try {
    const html = fs.readFileSync(path.join(__dir, 'mindView.html'), 'utf8');
    res.type('html').send(html);
  } catch {
    res.status(500).json({ success: false, error: 'mindView.html missing' });
  }
});

// ── Full model summary — the Mind View data source ────────────────────────────
router.get('/', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  res.json({
    success: true,
    ownerId: mind.ownerId,
    turnCount: mind.turnCount,
    createdAt: mind.createdAt,
    updatedAt: mind.updatedAt,
    identity:      getBeliefs(mind, { dimension: 'identity' }).map(compactBelief),
    personality:   getBeliefs(mind, { dimension: 'personality' }).map(compactBelief),
    communication: getBeliefs(mind, { dimension: 'communication' }).map(compactBelief),
    preferences:   getBeliefs(mind, { dimension: 'preferences' }).map(compactBelief),
    knowledge:     getBeliefs(mind, { dimension: 'knowledge' }).map(compactBelief),
    behavior:      getBeliefs(mind, { dimension: 'behavior' }).map(compactBelief),
    decision:      getBeliefs(mind, { dimension: 'decision' }).map(compactBelief),
    goals: Object.values(mind.goals).sort((a, b) => b.lastMentionedAt - a.lastMentionedAt),
    activeGoals: getActiveGoals(mind, 10).map(g => g.id),
    episodes: getEpisodes(mind, { limit: 10 }),
    working: { ...mind.working, focusRanked: currentFocus(mind, 8) },
    predictions: mind.predictions,
    timeline: recentTimeline(mind, 30),
    graph: {
      nodeCount: Object.keys(mind.graph.nodes).length,
      edgeCount: Object.keys(mind.graph.edges).length,
    },
    reflections: mind.reflections.slice(-5),
    lastReflectionAt: mind.lastReflectionAt,
    stats: mindStats(),
  });
});

function compactBelief(b) {
  return {
    dimension: b.dimension, key: b.key, value: b.value,
    confidence: +b.confidence.toFixed(3), evidenceCount: b.evidenceCount,
    contradictions: b.contradictions, status: b.status,
    locked: !!b.privacy?.locked, temporary: !!b.privacy?.temporary,
    source: b.privacy?.source, updatedAt: b.updatedAt,
  };
}

// ── Export (Layer 19: the user owns the model) ────────────────────────────────
router.get('/export', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  res.setHeader('Content-Disposition', `attachment; filename="aqua-mind-${Date.now()}.json"`);
  res.json(exportMind(mind.ownerId));
});

// ── Beliefs ───────────────────────────────────────────────────────────────────
router.get('/beliefs', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  const { dimension = null, min = 0 } = req.query;
  const beliefs = getBeliefs(mind, { dimension, minConfidence: Number(min) || 0, status: null })
    .map(compactBelief);
  res.json({ success: true, count: beliefs.length, beliefs });
});

router.get('/beliefs/:dim/:key', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  const belief = mind.beliefs[beliefKey(req.params.dim, req.params.key)];
  if (!belief) return res.status(404).json({ success: false, error: 'Belief not found' });
  res.json({ success: true, belief, explanation: explainBelief(belief) }); // Layer 17
});

router.patch('/beliefs/:dim/:key', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  const { value } = req.body ?? {};
  if (value === undefined) return res.status(400).json({ success: false, error: 'value is required' });
  const belief = correctBelief(mind, req.params.dim, req.params.key, value);
  res.json({ success: true, belief: compactBelief(belief) });
});

router.post('/beliefs/:dim/:key/lock', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  const belief = lockBelief(mind, req.params.dim, req.params.key, req.body?.locked !== false);
  if (!belief) return res.status(404).json({ success: false, error: 'Belief not found' });
  res.json({ success: true, belief: compactBelief(belief) });
});

router.post('/beliefs/:dim/:key/temporary', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  const belief = markTemporary(mind, req.params.dim, req.params.key, req.body?.temporary !== false);
  if (!belief) return res.status(404).json({ success: false, error: 'Belief not found' });
  res.json({ success: true, belief: compactBelief(belief) });
});

router.delete('/beliefs/:dim/:key', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  const deleted = deleteBelief(mind, req.params.dim, req.params.key);
  res.status(deleted ? 200 : 404).json({ success: deleted, deleted: `${req.params.dim}:${req.params.key}` });
});

// ── Goals ─────────────────────────────────────────────────────────────────────
router.patch('/goals/:id', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  const goal = mind.goals[req.params.id];
  if (!goal) return res.status(404).json({ success: false, error: 'Goal not found' });
  const { status, priority, title, progress, deadline } = req.body ?? {};
  if (status && Object.values(GOAL_STATUS).includes(status)) {
    goal.history.push({ status: goal.status, at: Date.now(), reason: 'user edit' });
    goal.status = status;
  }
  if (priority !== undefined) goal.priority = Math.max(1, Math.min(10, Number(priority) || goal.priority));
  if (title) goal.title = String(title).slice(0, 120);
  if (progress !== undefined) goal.progress = Math.max(0, Math.min(1, Number(progress)));
  if (deadline !== undefined) goal.deadline = deadline ? Number(deadline) : null;
  goal.updatedAt = Date.now();
  goal.privacy.source = 'correction';
  touchMind(mind);
  res.json({ success: true, goal });
});

router.delete('/goals/:id', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  if (!mind.goals[req.params.id]) return res.status(404).json({ success: false, error: 'Goal not found' });
  delete mind.goals[req.params.id];
  touchMind(mind);
  res.json({ success: true, deleted: req.params.id });
});

// ── Graph ─────────────────────────────────────────────────────────────────────
router.get('/graph', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  const { around } = req.query;
  if (around) {
    const nb = neighborhood(mind, String(around), 2, 20);
    return res.json({ success: true, ...nb });
  }
  res.json({
    success: true,
    nodes: Object.values(mind.graph.nodes),
    edges: Object.values(mind.graph.edges),
  });
});

// ── Reflections ───────────────────────────────────────────────────────────────
router.get('/reflections', (req, res) => {
  const mind = requireMind(req, res);
  if (!mind) return;
  res.json({ success: true, reflections: mind.reflections, lastReflectionAt: mind.lastReflectionAt });
});

// ── Erase the entire model ────────────────────────────────────────────────────
router.delete('/', (req, res) => {
  const ownerId = ownerOf(req);
  if (!ownerId) return res.status(400).json({ success: false, error: 'No mind owner' });
  const deleted = deleteMind(ownerId);
  res.json({ success: true, ownerId, deleted });
});

export default router;

/**
 * AQUA Mind — Retrieval Intelligence (Layer 15)
 * ─────────────────────────────────────────────────────────────────────────────
 * The LLM no longer receives isolated memories — it receives an evolving
 * COGNITIVE STATE: who the user is, how to talk to them, what they're
 * working toward right now, and what they'll likely need next.
 *
 * Selection considers: current intent (task type + query tokens), active
 * goals, working memory, identity/preferences confidence, predictions,
 * graph proximity, recency, and confidence. Output is the SMALLEST block
 * with the highest relevance — quality over quantity, hard token budget.
 *
 * The block rides the existing memoryBlock slot in promptBuilder — appended
 * after formatFactsForPrompt() output. No promptBuilder change needed.
 */
import { DIMENSIONS, GOAL_STATUS, STATUS } from './mindSchema.js';
import { getBeliefs } from './beliefEngine.js';
import { getActiveGoals } from './goalTracker.js';
import { currentFocus } from './workingMemory.js';
import { neighborhood, SELF_KEY } from './relationshipGraph.js';
import { estimateTokens } from '../core/tokenManager.js';

const DEFAULT_BUDGET_TOKENS = 450;
const MIN_CONF_TO_SHOW = 0.45;

function conf(c) { return `${Math.round(c * 100)}%`; }

function line(parts) { return parts.filter(Boolean).join(' '); }

/**
 * Build the cognitive context block.
 * @returns {{ block: string, used: object }} block='' when nothing meets the bar.
 */
export function retrieveCognitiveContext(mind, { query = '', taskType = 'conversation', budgetTokens = DEFAULT_BUDGET_TOKENS } = {}) {
  if (!mind) return { block: '', used: {} };
  const used = { identity: 0, communication: 0, preferences: 0, knowledge: 0, goals: 0, working: 0, predictions: 0, graph: 0 };
  const sections = [];
  const q = (query || '').toLowerCase();

  // ── 1. Identity & personality (always relevant, tiny) ──────────────────────
  const identity = getBeliefs(mind, { dimension: DIMENSIONS.IDENTITY, minConfidence: MIN_CONF_TO_SHOW })
    .filter(b => b.status !== STATUS.ARCHIVED).slice(0, 4);
  if (identity.length) {
    const traits = identity.map(b => `${b.key.replace(/_/g, ' ')}${typeof b.value === 'string' && b.value !== 'true' ? `: ${b.value}` : ''} (${conf(b.confidence)})`);
    sections.push(`Identity: ${traits.join(', ')}.`);
    used.identity = identity.length;
  }

  // ── 2. Communication style → directly shapes the answer ────────────────────
  const comm = getBeliefs(mind, { dimension: DIMENSIONS.COMMUNICATION, minConfidence: 0.5 }).slice(0, 3);
  if (comm.length) {
    sections.push(`Communication: ${comm.map(b => `${b.key.replace(/_/g, ' ')}=${b.value}`).join(', ')}. Match this style.`);
    used.communication = comm.length;
  }

  // ── 3. Preferences & decision style, intent-weighted ───────────────────────
  const prefLike = [
    ...getBeliefs(mind, { dimension: DIMENSIONS.PREFERENCES, minConfidence: MIN_CONF_TO_SHOW }),
    ...getBeliefs(mind, { dimension: DIMENSIONS.DECISION,    minConfidence: 0.5 }),
  ]
    .map(b => {
      let score = b.confidence;
      const keyWords = b.key.replace('tech:', '').split(/[_:]/);
      if (keyWords.some(w => w.length > 2 && q.includes(w))) score += 0.5; // query mentions it
      if (String(b.value).length > 2 && q.includes(String(b.value).toLowerCase())) score += 0.3;
      return { b, score };
    })
    .sort((a, b) => b.score - a.score)
    .slice(0, 4)
    .map(x => x.b);
  if (prefLike.length) {
    sections.push(`Preferences: ${prefLike.map(b => `${b.key.replace(/_/g, ' ')}=${JSON.stringify(b.value)} (${conf(b.confidence)})`).join('; ')}.`);
    used.preferences = prefLike.length;
  }

  // ── 4. Knowledge model → calibrate explanation depth (Layer 4 payoff) ──────
  if (['coding', 'debugging', 'architecture', 'project_query', 'research', 'analysis'].includes(taskType)) {
    const knowledge = getBeliefs(mind, { dimension: DIMENSIONS.KNOWLEDGE, minConfidence: 0.5 })
      .filter(b => {
        const term = b.key.replace('tech:', '');
        return q.includes(term) || b.confidence > 0.75;
      })
      .slice(0, 4);
    if (knowledge.length) {
      sections.push(`Known tech (skip basics): ${knowledge.map(b => b.key.replace('tech:', '')).join(', ')}.`);
      used.knowledge = knowledge.length;
    }
  }

  // ── 5. Active goals — the "why" behind the ask ──────────────────────────────
  const goals = getActiveGoals(mind, 3);
  if (goals.length) {
    const gl = goals.map(g => line([
      `"${g.title}"`,
      g.status === GOAL_STATUS.BLOCKED ? '[BLOCKED]' : null,
      g.progress > 0 ? `(~${Math.round(g.progress * 100)}%)` : null,
    ]));
    sections.push(`Active goals: ${gl.join('; ')}.`);
    used.goals = goals.length;
  }

  // ── 6. Working memory — what's on their plate right now ────────────────────
  const w = mind.working;
  const focus = currentFocus(mind, 3).map(f => f.topic).filter(t => !t.startsWith('workspace:'));
  const wmBits = [];
  if (focus.length) wmBits.push(`focus: ${focus.join(', ')}`);
  if (w.blockers.length) wmBits.push(`blocked on: ${w.blockers.map(b => b.text).slice(-2).join('; ')}`);
  if (w.deadlines.length) wmBits.push(`deadline: ${w.deadlines[w.deadlines.length - 1].label}`);
  if (w.openQuestions.length) wmBits.push(`open question: ${w.openQuestions[w.openQuestions.length - 1].text}`);
  if (wmBits.length) {
    sections.push(`Current state: ${wmBits.join(' | ')}.`);
    used.working = wmBits.length;
  }

  // ── 7. Top prediction — anticipate, don't just react ───────────────────────
  const topPred = (mind.predictions || [])[0];
  if (topPred && topPred.probability >= 0.55) {
    sections.push(`Anticipated need: ${topPred.label} (p=${topPred.probability}).`);
    used.predictions = 1;
  }

  // ── 8. Graph context only when the query names an entity ───────────────────
  if (q.length > 3) {
    const hit = Object.values(mind.graph.nodes).find(n =>
      n.key !== SELF_KEY && n.label.length > 2 && q.includes(n.label.toLowerCase()));
    if (hit) {
      const nb = neighborhood(mind, hit.key, 1, 6);
      const rel = nb.edges.slice(0, 4).map(e => {
        const from = mind.graph.nodes[e.from]?.label ?? '?';
        const to   = mind.graph.nodes[e.to]?.label ?? '?';
        return `${from} —${e.type}→ ${to}`;
      });
      if (rel.length) {
        sections.push(`Related: ${rel.join('; ')}.`);
        used.graph = rel.length;
      }
    }
  }

  if (!sections.length) return { block: '', used };

  // ── Budget enforcement: drop lowest-priority sections from the end ─────────
  // Order above is already priority order (identity → graph); trim tail-first.
  let lines = [...sections];
  const wrap = (ls) => [
    '--- COGNITIVE MODEL (inferred, confidence-weighted — not user-stated facts) ---',
    ...ls,
    'Use silently to adapt tone, depth and focus. Confidence <70% = treat as a hunch, never assert it back to the user.',
    '--- END COGNITIVE MODEL ---',
  ].join('\n');

  while (lines.length > 1 && estimateTokens(wrap(lines)) > budgetTokens) {
    lines.pop();
  }

  return { block: wrap(lines), used };
}

/**
 * AQUA Mind — Confidence Engine (Layer 11)
 * ─────────────────────────────────────────────────────────────────────────────
 * Pure math. No storage, no I/O. Every belief update flows through here so
 * confidence semantics are identical everywhere and independently testable.
 *
 * Model:
 *   support:        c' = c + rate * strength * (1 - c)      — asymptotic to 1
 *   contradiction:  c' = c * (1 - CONTRA_FACTOR * strength) — multiplicative drop,
 *                   never below CONTRA_FLOOR; history is preserved by caller.
 *   decay:          c' = c - decayRate * staleWeeks, floored by importance tier.
 *
 * Contradiction NEVER deletes: it lowers confidence and increments the
 * contradiction counter. Only repeated contradiction + decay archives a belief
 * (reflectionEngine decides), and archive ≠ delete.
 */

export const CONTRA_FACTOR = 0.45;
export const CONTRA_FLOOR  = 0.05;
export const PROMOTE_AT    = 0.80;  // + evidenceCount gate → "established"
export const PROMOTE_MIN_EVIDENCE = 3;
export const ARCHIVE_BELOW = 0.15;  // decayed under this → archive candidate

/** Support evidence. strength 0..1 (how strong this single observation is). */
export function reinforce(confidence, changeRate, strength = 1) {
  const c = clamp01(confidence);
  const s = clamp01(strength);
  return clamp01(c + changeRate * s * (1 - c));
}

/** Contradicting evidence. Lowers, never zeroes. */
export function contradict(confidence, strength = 1) {
  const c = clamp01(confidence);
  const s = clamp01(strength);
  return Math.max(CONTRA_FLOOR, c * (1 - CONTRA_FACTOR * s));
}

/**
 * Time decay applied at reflection. staleMs since lastEvidenceAt.
 * decayRate is per-week (see DIMENSION_DYNAMICS). Established beliefs
 * (promoted) get a floor so long-term knowledge doesn't evaporate.
 */
export function decay(confidence, decayRate, staleMs, { established = false } = {}) {
  if (decayRate <= 0) return clamp01(confidence);
  const weeks = Math.max(0, staleMs) / (7 * 24 * 3600 * 1000);
  const floor = established ? 0.4 : 0;
  return Math.max(floor, clamp01(confidence - decayRate * weeks));
}

export function isEstablished(belief) {
  return (belief.confidence >= PROMOTE_AT) && (belief.evidenceCount >= PROMOTE_MIN_EVIDENCE);
}

export function isArchiveCandidate(belief) {
  return belief.confidence < ARCHIVE_BELOW;
}

/**
 * Blend an explicit user statement/correction with an inferred belief.
 * Explicit input dominates but still isn't binary certainty.
 */
export function fromExplicit(prior = 0) {
  return Math.max(clamp01(prior), 0.9);
}

export function clamp01(x) {
  if (Number.isNaN(x) || !Number.isFinite(x)) return 0;
  return Math.min(1, Math.max(0, x));
}

/**
 * AQUA Mind — Timeline (Layer 10)
 * ─────────────────────────────────────────────────────────────────────────────
 * Append-only capped ring of significant events (belief flips, goal changes,
 * episode open/close, reflections). History never disappears — old entries
 * roll off the detailed ring but their effects live on in belief history and
 * evidence counts. The Mind understands how the user EVOLVES.
 */
import { CAPS } from './mindSchema.js';
import { touchMind } from './mindStore.js';

export function pushTimeline(mind, event) {
  if (!mind || !event) return;
  mind.timeline.push(event);
  if (mind.timeline.length > CAPS.TIMELINE) {
    mind.timeline.splice(0, mind.timeline.length - CAPS.TIMELINE);
  }
  touchMind(mind);
}

export function recentTimeline(mind, limit = 20, { minImportance = 0 } = {}) {
  return mind.timeline
    .filter(e => e.importance >= minImportance)
    .slice(-limit)
    .reverse();
}

/**
 * AQUA Mind Schema v1
 * ─────────────────────────────────────────────────────────────────────────────
 * Single source of truth for the persistent cognitive model ("Mind").
 *
 * NOT a replacement for memorySchema.js (flat extractable facts). The Mind
 * layer sits ABOVE it: facts are one evidence source among many; the Mind
 * holds inferred, confidence-weighted BELIEFS plus goals, working memory,
 * episodes, a relationship graph, a timeline and predictions.
 *
 * Every element carries confidence + evidence + privacy metadata.
 * Nothing in the Mind is ever binary-certain.
 */

// ── Belief dimensions ─────────────────────────────────────────────────────────
export const DIMENSIONS = Object.freeze({
  IDENTITY:      'identity',       // slow-moving: founder, engineer, systems thinker…
  PERSONALITY:   'personality',    // traits: analytical, patient, detail-hungry…
  COMMUNICATION: 'communication',  // style: terse, prefers fragments, code-first…
  PREFERENCES:   'preferences',    // implicit + explicit: minimal UI, dark themes…
  KNOWLEDGE:     'knowledge',      // skill proficiency: typescript=advanced…
  BEHAVIOR:      'behavior',       // patterns: iterates fast, tests-after, night work…
  DECISION:      'decision',       // decision style: evidence-first, risk-tolerant…
});

export const DIMENSION_LIST = Object.freeze(Object.values(DIMENSIONS));

// ── Identity trait vocabulary (inferred, never asked) ─────────────────────────
export const IDENTITY_TRAITS = Object.freeze([
  'founder', 'engineer', 'designer', 'manager', 'researcher', 'student',
  'builder', 'creative', 'systems_thinker', 'long_term_planner', 'minimalist',
]);

// ── Per-dimension dynamics ─────────────────────────────────────────────────────
// changeRate: how fast confidence moves on new evidence (identity = slowest).
// decayRate:  confidence lost per stale WEEK at reflection time (0 = permanent
//             once established; working-memory items decay elsewhere, faster).
export const DIMENSION_DYNAMICS = Object.freeze({
  [DIMENSIONS.IDENTITY]:      { changeRate: 0.12, decayRate: 0.000 },
  [DIMENSIONS.PERSONALITY]:   { changeRate: 0.14, decayRate: 0.002 },
  [DIMENSIONS.COMMUNICATION]: { changeRate: 0.18, decayRate: 0.004 },
  [DIMENSIONS.PREFERENCES]:   { changeRate: 0.16, decayRate: 0.003 },
  [DIMENSIONS.KNOWLEDGE]:     { changeRate: 0.15, decayRate: 0.002 },
  [DIMENSIONS.BEHAVIOR]:      { changeRate: 0.15, decayRate: 0.004 },
  [DIMENSIONS.DECISION]:      { changeRate: 0.14, decayRate: 0.002 },
});

// ── Element lifecycle ──────────────────────────────────────────────────────────
export const STATUS = Object.freeze({
  ACTIVE:   'active',
  ARCHIVED: 'archived',   // decayed / superseded — never deleted immediately
  LOCKED:   'locked',     // user-pinned: exempt from decay and inference updates
});

export const GOAL_STATUS = Object.freeze({
  ACTIVE:    'active',
  BLOCKED:   'blocked',
  COMPLETED: 'completed',
  ABANDONED: 'abandoned',
  STALE:     'stale',      // not mentioned for a long time — candidate for archive
});

// ── Graph vocabulary ───────────────────────────────────────────────────────────
export const NODE_TYPES = Object.freeze([
  'person', 'organization', 'project', 'goal', 'technology', 'episode', 'artifact',
]);
export const EDGE_TYPES = Object.freeze([
  'works_on', 'works_with', 'depends_on', 'part_of', 'interested_in',
  'blocks', 'related_to', 'owns', 'uses', 'targets',
]);

// ── Privacy defaults (Layer 19) ────────────────────────────────────────────────
// Every cognitive element embeds this envelope. The user owns the model.
export function defaultPrivacy() {
  return {
    visibility: 'private',      // private | workspace | organization
    retentionDays: null,        // null = indefinite (subject to decay), N = hard TTL
    temporary: false,           // true = never promoted to permanent at reflection
    locked: false,              // true = user-pinned, inference cannot modify
    source: 'inference',        // inference | explicit | correction | fact_bridge
  };
}

// ── Constructors ──────────────────────────────────────────────────────────────
let _seq = 0;
export function mindId(prefix) {
  return `${prefix}_${Date.now().toString(36)}_${(_seq++ & 0xffff).toString(36)}`;
}

/**
 * A Belief: one inferred statement about the user with confidence + evidence.
 * key is stable within a dimension (e.g. knowledge:typescript, preferences:ui_density).
 */
export function createBelief({ dimension, key, value, confidence = 0.3, source = 'inference' }) {
  const now = Date.now();
  return {
    id: mindId('bel'),
    dimension,
    key,
    value,                       // string | number | object — the belief content
    confidence,                  // 0..1, never assumed 1.0
    evidence: [],                // [{ ts, conversationId, signal, note, delta }] capped
    evidenceCount: 0,            // total observations ever (evidence[] is a window)
    contradictions: 0,
    createdAt: now,
    updatedAt: now,
    lastEvidenceAt: now,
    status: STATUS.ACTIVE,
    established: false,          // set once by reflection when confidence+evidence bar crossed
    history: [],                 // prior values — never overwritten, superseded
    privacy: { ...defaultPrivacy(), source },
  };
}

export function createGoal({ title, priority = 5, source = 'inference', confidence = 0.5 }) {
  const now = Date.now();
  return {
    id: mindId('goal'),
    title,
    priority,                    // 1..10
    progress: 0,                 // 0..1 heuristic
    deadline: null,              // ts | null
    dependencies: [],            // goal ids
    blockers: [],                // strings
    relatedProjects: [],         // workspaceIds / project names
    relatedPeople: [],
    status: GOAL_STATUS.ACTIVE,
    confidence,
    mentions: 1,
    createdAt: now,
    updatedAt: now,
    lastMentionedAt: now,
    history: [],
    privacy: { ...defaultPrivacy(), source },
  };
}

export function createEpisode({ title, conversationId }) {
  const now = Date.now();
  return {
    id: mindId('ep'),
    title,                        // "Preparing investor demo", "Debugging deploy"
    startedAt: now,
    endedAt: null,
    conversationIds: conversationId ? [conversationId] : [],
    participants: [],
    objectives: [],
    outcome: null,
    lessons: [],
    importance: 5,
    lastActivityAt: now,
    status: STATUS.ACTIVE,
    privacy: defaultPrivacy(),
  };
}

export function createNode({ type, label }) {
  return { id: mindId('nd'), type, label, createdAt: Date.now(), weight: 1, privacy: defaultPrivacy() };
}

export function createEdge({ from, to, type, note = '' }) {
  return { id: mindId('eg'), from, to, type, note, weight: 1, createdAt: Date.now(), lastSeenAt: Date.now() };
}

export function createTimelineEvent({ kind, subject, detail = '', importance = 5 }) {
  return { id: mindId('tl'), ts: Date.now(), kind, subject, detail, importance };
}

/** Empty per-user Mind. Modular sections — each subsystem owns exactly one. */
export function createEmptyMind(ownerId) {
  const now = Date.now();
  return {
    version: 2,
    ownerId,
    createdAt: now,
    updatedAt: now,
    turnCount: 0,                 // total observed turns (drives reflection cadence)
    facts: {},                    // key → Fact (schema facts — UNIFIED, was .aqua-memory.json)
    files: {},                    // fileKey → FileMemory (uploads + workspaces — Req 10)
    beliefs: {},                  // `${dimension}:${key}` → Belief
    goals: {},                    // id → Goal
    episodes: {},                 // id → Episode
    graph: { nodes: {}, edges: {} },
    timeline: [],                 // capped ring of TimelineEvents
    working: {                    // Layer 9 — volatile mental state
      focus: [],                  // [{ topic, weight, lastSeenAt }]
      blockers: [],
      deadlines: [],              // [{ label, ts, source }]
      recentDiscoveries: [],
      openQuestions: [],
      updatedAt: now,
    },
    predictions: [],              // ephemeral, rebuilt — persisted only for Mind View
    reflections: [],              // [{ ts, turnCount, learned, weakened, promoted, archived }]
    lastReflectionAt: null,
    lastReflectionTurn: 0,
  };
}

// ── Caps (avoid unbounded growth; reflection enforces) ────────────────────────
export const CAPS = Object.freeze({
  EVIDENCE_WINDOW: 12,     // evidence entries kept per belief (count is unbounded)
  HISTORY_PER_ITEM: 10,
  TIMELINE: 300,
  WORKING_FOCUS: 8,
  WORKING_LIST: 6,
  REFLECTIONS: 40,
  GOALS_ACTIVE: 25,
  GRAPH_NODES: 400,
  PREDICTIONS: 5,
});

export function beliefKey(dimension, key) {
  return `${dimension}:${key}`;
}

/**
 * AQUA Mind — Working Memory (Layer 9)
 * ─────────────────────────────────────────────────────────────────────────────
 * Volatile "what's on the user's plate RIGHT NOW": focus topics, blockers,
 * deadlines, discoveries, open questions. Changes every turn, decays in
 * hours-to-days (not weeks), and is the highest-signal input to both
 * retrieval and prediction. Nothing here is a belief — it's state.
 */
import { CAPS } from './mindSchema.js';
import { touchMind } from './mindStore.js';

const FOCUS_HALF_LIFE_MS = 36 * 3600 * 1000;   // focus weight halves every 36h
const LIST_TTL_MS        = 7 * 24 * 3600 * 1000; // blockers/discoveries/questions expire after 7d

const DISCOVERY_RE = /\b(turns out|i (?:just )?(?:found|discovered|realized|learned)|interesting[:,]|til\b)\s*(.{4,100}?)(?:[.!;]|$)/i;
const QUESTION_RE  = /\b(?:i(?:'m| am) (?:wondering|not sure)|should (?:i|we)|open question|still unsure)\b.{0,10}(.{4,100}?)(?:[.!;?]|$)/i;
const BLOCKER_RE   = /\b(?:blocked (?:on|by)|stuck on|waiting (?:on|for))\s+(.{3,80}?)(?:[.,;!]|$)/i;

function decayedWeight(item, now) {
  const age = now - (item.lastSeenAt || now);
  return (item.weight || 1) * Math.pow(0.5, age / FOCUS_HALF_LIFE_MS);
}

function upsertList(list, text, now, cap) {
  const norm = text.trim().toLowerCase();
  const hit = list.find(x => x.text.toLowerCase() === norm || x.text.toLowerCase().includes(norm) || norm.includes(x.text.toLowerCase()));
  if (hit) { hit.lastSeenAt = now; hit.count = (hit.count || 1) + 1; return; }
  list.push({ text: text.trim().slice(0, 100), addedAt: now, lastSeenAt: now, count: 1 });
  if (list.length > cap) list.splice(0, list.length - cap);
}

/**
 * Per-turn working-memory update. Consumes observer hints (tech, deadlines)
 * plus its own light parsing for discoveries/questions/blockers.
 */
export function updateWorkingMemory(mind, { userMessage = '', taskType = 'conversation', hints = {}, workspaceId = null }) {
  const w = mind.working;
  const now = Date.now();

  // Focus: task type + tech terms + workspace form the current-topic cloud
  const topics = new Set();
  if (taskType && taskType !== 'conversation') topics.add(taskType);
  for (const t of hints.tech || []) topics.add(t);
  if (workspaceId) topics.add(`workspace:${workspaceId}`);

  for (const topic of topics) {
    const existing = w.focus.find(f => f.topic === topic);
    if (existing) {
      existing.weight = decayedWeight(existing, now) + 1;
      existing.lastSeenAt = now;
    } else {
      w.focus.push({ topic, weight: 1, lastSeenAt: now });
    }
  }
  // Re-rank by decayed weight; keep top N
  w.focus = w.focus
    .map(f => ({ ...f, _w: decayedWeight(f, now) }))
    .filter(f => f._w > 0.05)
    .sort((a, b) => b._w - a._w)
    .slice(0, CAPS.WORKING_FOCUS)
    .map(({ _w, ...f }) => f);

  // Deadlines from observer hints
  for (const d of hints.deadlines || []) {
    if (!w.deadlines.some(x => x.label === d.label)) {
      w.deadlines.push({ ...d, addedAt: now });
      if (w.deadlines.length > CAPS.WORKING_LIST) w.deadlines.splice(0, w.deadlines.length - CAPS.WORKING_LIST);
    }
  }

  // Blockers / discoveries / open questions
  const b = userMessage.match(BLOCKER_RE);
  if (b?.[1]) upsertList(w.blockers, b[1], now, CAPS.WORKING_LIST);
  const d = userMessage.match(DISCOVERY_RE);
  if (d?.[2]) upsertList(w.recentDiscoveries, d[2], now, CAPS.WORKING_LIST);
  const q = userMessage.match(QUESTION_RE);
  if (q?.[1]) upsertList(w.openQuestions, q[1], now, CAPS.WORKING_LIST);

  w.updatedAt = now;
  touchMind(mind);
  return w;
}

/** Reflection-time cleanup: expire stale list items, re-decay focus. */
export function decayWorkingMemory(mind) {
  const w = mind.working;
  const now = Date.now();
  const fresh = (x) => now - (x.lastSeenAt || x.addedAt || 0) < LIST_TTL_MS;
  w.blockers          = w.blockers.filter(fresh);
  w.recentDiscoveries = w.recentDiscoveries.filter(fresh);
  w.openQuestions     = w.openQuestions.filter(fresh);
  w.deadlines         = w.deadlines.filter(x => now - (x.addedAt || 0) < 2 * LIST_TTL_MS);
  w.focus = w.focus
    .map(f => ({ ...f, _w: decayedWeight(f, now) }))
    .filter(f => f._w > 0.05)
    .map(({ _w, ...f }) => f);
  touchMind(mind);
}

export function currentFocus(mind, limit = 5) {
  const now = Date.now();
  return mind.working.focus
    .map(f => ({ topic: f.topic, weight: +decayedWeight(f, now).toFixed(2) }))
    .sort((a, b) => b.weight - a.weight)
    .slice(0, limit);
}

/**
 * AQUA Mind — Goal Tracker (Layer 5)
 * ─────────────────────────────────────────────────────────────────────────────
 * Goals are first-class living objects: detected from conversation, matched
 * fuzzily against existing goals (re-mention strengthens, not duplicates),
 * auto-progressed / completed / blocked from message cues, and marked STALE
 * by the reflection engine when unmentioned too long. Never hard-deleted by
 * inference — only the user deletes.
 */
import { createGoal, GOAL_STATUS, CAPS, createTimelineEvent } from './mindSchema.js';
import { touchMind } from './mindStore.js';
import { pushTimeline } from './timeline.js';

// Detection: explicit goal statements + working-toward phrasing.
const GOAL_PATTERNS = [
  /\bmy goal is (?:to )?(.{4,90}?)(?:[.,;!]|$)/i,
  /\bi(?:'m| am) (?:trying|working|aiming|planning) to (.{4,90}?)(?:[.,;!]|$)/i,
  /\bi want to (?:finally |eventually )?((?:ship|launch|build|finish|complete|release|migrate|raise|hire|reach|grow|refactor|rewrite|land)\b.{0,80}?)(?:[.,;!]|$)/i,
  /\bwe (?:need|want|plan) to ((?:ship|launch|build|finish|complete|release|migrate|raise|close)\b.{0,80}?)(?:[.,;!]|$)/i,
];

const DONE_RE    = /\b(finished|completed|shipped|launched|released|done with|we shipped|it'?s live|merged)\b/i;
const BLOCKED_RE = /\b(blocked (on|by)|stuck on|can'?t proceed|waiting (on|for))\b/i;
const PROGRESS_RE = /\b(made progress|almost (done|there)|halfway|nearly (done|finished)|good progress)\b/i;

const STOPWORDS = new Set(['the','a','an','to','of','for','and','or','in','on','with','our','my','it','this','that','be','is','are']);

function tokenize(s) {
  return (s || '').toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/)
    .filter(w => w.length > 2 && !STOPWORDS.has(w));
}

/** Jaccard-ish token overlap — good enough for goal re-mention matching. */
export function goalSimilarity(a, b) {
  const ta = new Set(tokenize(a));
  const tb = new Set(tokenize(b));
  if (!ta.size || !tb.size) return 0;
  let inter = 0;
  for (const w of ta) if (tb.has(w)) inter++;
  return inter / Math.min(ta.size, tb.size);
}

const MATCH_THRESHOLD = 0.5;

function findMatch(mind, title) {
  let best = null, bestScore = 0;
  for (const g of Object.values(mind.goals)) {
    if (g.status === GOAL_STATUS.ABANDONED) continue;
    const s = goalSimilarity(g.title, title);
    if (s > bestScore) { bestScore = s; best = g; }
  }
  return bestScore >= MATCH_THRESHOLD ? best : null;
}

export function detectGoalTitles(text) {
  const titles = [];
  for (const p of GOAL_PATTERNS) {
    const m = text.match(p);
    if (m?.[1]) titles.push(m[1].trim().replace(/\s+/g, ' '));
  }
  return [...new Set(titles)];
}

/**
 * Per-turn goal update. Consumes:
 *   • detected titles from this message
 *   • schema-extracted goal facts (fact bridge — reuse, no re-parse)
 *   • status cues (done/blocked/progress) applied to the best-matching goal
 */
export function trackGoals(mind, { userMessage = '', extractedFacts = [], conversationId = null, workspaceId = null }) {
  const now = Date.now();
  const changed = [];

  const titles = detectGoalTitles(userMessage);
  for (const f of extractedFacts) {
    if (f.key === 'goal' && typeof f.value === 'string') titles.push(f.value);
  }

  for (const title of titles) {
    const existing = findMatch(mind, title);
    if (existing) {
      existing.mentions += 1;
      existing.lastMentionedAt = now;
      existing.updatedAt = now;
      existing.confidence = Math.min(1, existing.confidence + 0.1);
      if (existing.status === GOAL_STATUS.STALE) existing.status = GOAL_STATUS.ACTIVE;
      if (workspaceId && !existing.relatedProjects.includes(workspaceId)) existing.relatedProjects.push(workspaceId);
      changed.push(existing);
    } else {
      const activeCount = Object.values(mind.goals).filter(g => g.status === GOAL_STATUS.ACTIVE).length;
      if (activeCount >= CAPS.GOALS_ACTIVE) continue; // reflection will make room
      const goal = createGoal({ title, source: 'inference', confidence: 0.55 });
      if (workspaceId) goal.relatedProjects.push(workspaceId);
      mind.goals[goal.id] = goal;
      pushTimeline(mind, createTimelineEvent({ kind: 'goal_created', subject: title, importance: 6 }));
      changed.push(goal);
    }
  }

  // Status cues → most relevant active goal (mentioned-title match first,
  // else most recently mentioned active goal — conversation continuity).
  const cueTarget = () => {
    for (const t of titles) {
      const g = findMatch(mind, t);
      if (g) return g;
    }
    return Object.values(mind.goals)
      .filter(g => g.status === GOAL_STATUS.ACTIVE || g.status === GOAL_STATUS.BLOCKED)
      .sort((a, b) => b.lastMentionedAt - a.lastMentionedAt)[0] || null;
  };

  if (DONE_RE.test(userMessage)) {
    const g = cueTarget();
    if (g && g.status !== GOAL_STATUS.COMPLETED) {
      g.history.push({ status: g.status, at: now, reason: 'completion cue' });
      g.status = GOAL_STATUS.COMPLETED;
      g.progress = 1;
      g.updatedAt = now;
      pushTimeline(mind, createTimelineEvent({ kind: 'goal_completed', subject: g.title, importance: 7 }));
      changed.push(g);
    }
  } else if (BLOCKED_RE.test(userMessage)) {
    const g = cueTarget();
    if (g && g.status === GOAL_STATUS.ACTIVE) {
      g.history.push({ status: g.status, at: now, reason: 'blocked cue' });
      g.status = GOAL_STATUS.BLOCKED;
      const blocker = userMessage.match(BLOCKED_RE)?.[0]?.slice(0, 60);
      if (blocker && !g.blockers.includes(blocker)) g.blockers.push(blocker);
      g.updatedAt = now;
      changed.push(g);
    }
  } else if (PROGRESS_RE.test(userMessage)) {
    const g = cueTarget();
    if (g && g.status !== GOAL_STATUS.COMPLETED) {
      g.progress = Math.min(0.9, (g.progress || 0) + 0.2);
      g.status = GOAL_STATUS.ACTIVE;
      g.updatedAt = now;
      g.lastMentionedAt = now;
      changed.push(g);
    }
  }

  if (changed.length) touchMind(mind);
  return changed;
}

export function getActiveGoals(mind, limit = 5) {
  return Object.values(mind.goals)
    .filter(g => g.status === GOAL_STATUS.ACTIVE || g.status === GOAL_STATUS.BLOCKED)
    .sort((a, b) => (b.priority - a.priority) || (b.lastMentionedAt - a.lastMentionedAt))
    .slice(0, limit);
}

/**
 * AQUA Mind — Reflection Engine (Layer 13) + Memory Decay (Layer 14)
 * ─────────────────────────────────────────────────────────────────────────────
 * Every N observed turns the Mind consolidates itself:
 *
 *   What did I learn?             → newly-promoted (established) beliefs
 *   Which assumptions weakened?   → contradiction-heavy / decayed beliefs
 *   What should become permanent? → promotion (established flag)
 *   What should be forgotten?     → decay → ARCHIVE (never immediate delete)
 *   Housekeeping                  → stale goals, quiet episodes, graph prune,
 *                                   working-memory expiry, TTL enforcement
 *
 * Runs ASYNCHRONOUSLY (setImmediate) after the response is already on its
 * way — reflection never adds latency to a turn and never appears in user
 * messages. Failures are logged and swallowed: reflection can never break
 * chat.
 */
import { DIMENSION_DYNAMICS, STATUS, GOAL_STATUS, CAPS, createTimelineEvent } from './mindSchema.js';
import { decay, isEstablished, isArchiveCandidate } from './confidence.js';
import { touchMind } from './mindStore.js';
import { pushTimeline } from './timeline.js';
import { decayWorkingMemory } from './workingMemory.js';
import { closeStaleEpisodes } from './episodeTracker.js';
import { pruneGraph } from './relationshipGraph.js';

export const REFLECT_EVERY_TURNS = 8;
const GOAL_STALE_MS = 21 * 24 * 3600 * 1000; // unmentioned 3 weeks → stale

export function shouldReflect(mind) {
  return (mind.turnCount - (mind.lastReflectionTurn || 0)) >= REFLECT_EVERY_TURNS;
}

/** Synchronous core — exported for tests. Production path uses scheduleReflection. */
export function reflect(mind) {
  const now = Date.now();
  const report = {
    ts: now,
    turnCount: mind.turnCount,
    learned: [],      // newly established
    weakened: [],     // significant confidence drops via decay/contradiction
    promoted: [],
    archived: [],
    goalsStaled: [],
    episodesClosed: 0,
    graphPruned: 0,
    expired: [],      // hard TTL (privacy.retentionDays)
  };

  // ── Beliefs: decay, promote, archive, TTL ──────────────────────────────────
  for (const [bk, b] of Object.entries(mind.beliefs)) {
    if (b.privacy?.locked || b.status === STATUS.LOCKED) continue;

    // Hard retention TTL (Layer 19)
    if (b.privacy?.retentionDays) {
      const ttlMs = b.privacy.retentionDays * 24 * 3600 * 1000;
      if (now - b.createdAt > ttlMs) {
        delete mind.beliefs[bk];
        report.expired.push(bk);
        continue;
      }
    }

    // Promotion first (evidence accumulated since last reflection), then decay.
    // b.established is a one-way flag: "became permanent knowledge" is
    // reported exactly once, whenever the bar was crossed between reflections.
    if (!b.established && isEstablished(b)) {
      b.established = true;
      report.promoted.push(bk);
      report.learned.push({ key: bk, value: b.value, confidence: +b.confidence.toFixed(2) });
      pushTimeline(mind, createTimelineEvent({ kind: 'belief_established', subject: bk, importance: 6 }));
    }

    const dyn = DIMENSION_DYNAMICS[b.dimension] ?? { decayRate: 0.003 };
    const before = b.confidence;
    b.confidence = decay(before, dyn.decayRate, now - b.lastEvidenceAt, { established: !!b.established });
    if (before - b.confidence > 0.05) report.weakened.push({ key: bk, from: +before.toFixed(2), to: +b.confidence.toFixed(2) });

    // Temporary items never persist past reflection once stale (Layer 18)
    const staleTemp = b.privacy?.temporary && now - b.lastEvidenceAt > 24 * 3600 * 1000;
    if (b.status === STATUS.ACTIVE && (isArchiveCandidate(b) || staleTemp)) {
      b.status = STATUS.ARCHIVED;   // archive first — never delete immediately
      report.archived.push(bk);
    }
  }

  // ── Goals: stale detection ─────────────────────────────────────────────────
  for (const g of Object.values(mind.goals)) {
    if (g.status === GOAL_STATUS.ACTIVE && now - g.lastMentionedAt > GOAL_STALE_MS) {
      g.history.push({ status: g.status, at: now, reason: 'reflection: unmentioned' });
      g.status = GOAL_STATUS.STALE;
      report.goalsStaled.push(g.title);
    }
  }

  // ── Housekeeping ───────────────────────────────────────────────────────────
  report.episodesClosed = closeStaleEpisodes(mind);
  report.graphPruned    = pruneGraph(mind);
  decayWorkingMemory(mind);

  // ── Record reflection (internal only — never surfaces in user messages) ────
  mind.reflections.push(report);
  if (mind.reflections.length > CAPS.REFLECTIONS) {
    mind.reflections.splice(0, mind.reflections.length - CAPS.REFLECTIONS);
  }
  mind.lastReflectionAt = now;
  mind.lastReflectionTurn = mind.turnCount;
  pushTimeline(mind, createTimelineEvent({
    kind: 'reflection', subject: `turn ${mind.turnCount}`,
    detail: `+${report.promoted.length} promoted, ${report.archived.length} archived, ${report.weakened.length} weakened`,
    importance: 4,
  }));
  touchMind(mind);

  console.log(`[MIND] REFLECTION owner=${mind.ownerId} turn=${mind.turnCount} promoted=${report.promoted.length} archived=${report.archived.length} weakened=${report.weakened.length} goalsStaled=${report.goalsStaled.length}`);
  return report;
}

/** Async, fire-and-forget, fail-safe. The only production entry point. */
export function scheduleReflection(mind) {
  if (!shouldReflect(mind)) return false;
  setImmediate(() => {
    try { reflect(mind); }
    catch (err) { console.warn('[MIND] Reflection failed (non-fatal):', err.message); }
  });
  return true;
}

/**
 * AQUA Mind — Relationship Graph (Layer 7) + Organization Memory (Layer 16)
 * ─────────────────────────────────────────────────────────────────────────────
 * Connected knowledge instead of isolated memories. Nodes: people, orgs,
 * projects, goals, technologies, episodes. Edges: typed, weighted, re-seen
 * edges strengthen. Organizations are first-class nodes whose neighborhoods
 * (teams, repos, products, shared goals) form the org memory — same graph,
 * no duplicate storage.
 *
 * Population sources (all reuse existing extraction — no new parsing pass):
 *   • schema facts (workplace, spouse, children → person/org nodes)
 *   • observer tech hints (→ technology nodes, `uses` edges)
 *   • goal tracker (→ goal nodes, `targets` edges)
 *   • workspaces (→ project nodes, `works_on` edges)
 */
import { createNode, createEdge, CAPS } from './mindSchema.js';
import { touchMind } from './mindStore.js';

function nodeKey(type, label) {
  return `${type}:${String(label).toLowerCase().trim()}`;
}

export function upsertNode(mind, type, label) {
  if (!label) return null;
  const g = mind.graph;
  const key = nodeKey(type, label);
  let node = g.nodes[key];
  if (node) {
    node.weight += 1;
    return node;
  }
  if (Object.keys(g.nodes).length >= CAPS.GRAPH_NODES) return null; // reflection prunes
  node = createNode({ type, label: String(label).trim() });
  node.key = key;
  g.nodes[key] = node;
  return node;
}

export function upsertEdge(mind, fromKey, toKey, type, note = '') {
  const g = mind.graph;
  if (!g.nodes[fromKey] || !g.nodes[toKey] || fromKey === toKey) return null;
  const ekey = `${fromKey}|${type}|${toKey}`;
  let edge = g.edges[ekey];
  if (edge) {
    edge.weight += 1;
    edge.lastSeenAt = Date.now();
    return edge;
  }
  edge = createEdge({ from: fromKey, to: toKey, type, note });
  edge.key = ekey;
  g.edges[ekey] = edge;
  return edge;
}

const SELF = 'person:__self__';
function ensureSelf(mind) {
  if (!mind.graph.nodes[SELF]) {
    const n = createNode({ type: 'person', label: 'user' });
    n.key = SELF;
    mind.graph.nodes[SELF] = n;
  }
  return mind.graph.nodes[SELF];
}

/**
 * Per-turn graph update from already-computed turn artifacts.
 */
export function updateGraph(mind, { extractedFacts = [], hints = {}, goalsTouched = [], workspaceId = null }) {
  ensureSelf(mind);
  let wrote = false;

  for (const fact of extractedFacts) {
    if (fact.key === 'workplace' && fact.value) {
      const org = upsertNode(mind, 'organization', fact.value);
      if (org) { upsertEdge(mind, SELF, org.key, 'part_of', 'workplace fact'); wrote = true; }
    }
    if ((fact.key === 'spouse' || fact.key === 'siblings' || fact.key === 'cofounder') && fact.value) {
      const rel = fact.key === 'cofounder' ? 'works_with' : (fact.key === 'spouse' ? 'related_to' : 'related_to');
      const vals = Array.isArray(fact.value) ? fact.value : [fact.value];
      for (const v of vals) {
        const name = typeof v === 'object' ? v.name : v;
        if (!name) continue;
        const p = upsertNode(mind, 'person', name);
        if (p) { upsertEdge(mind, SELF, p.key, rel, fact.key); wrote = true; }
      }
    }
    if (fact.key === 'children' && fact.value?.name) {
      const p = upsertNode(mind, 'person', fact.value.name);
      if (p) { upsertEdge(mind, SELF, p.key, 'related_to', 'family'); wrote = true; }
    }
    // v3 (Extraction Audit): projects & goals are now first-class facts — they
    // must land in the graph as nodes the user works_on / targets (Req 4/9).
    if ((fact.key === 'project') && fact.value) {
      const vals = Array.isArray(fact.value) ? fact.value : [fact.value];
      for (const v of vals) {
        const pn = upsertNode(mind, 'project', v);
        if (pn) { upsertEdge(mind, SELF, pn.key, 'works_on', 'project fact'); wrote = true; }
      }
    }
    if (fact.key === 'goal' && fact.value) {
      const vals = Array.isArray(fact.value) ? fact.value : [fact.value];
      for (const v of vals) {
        const gn = upsertNode(mind, 'goal', String(v).slice(0, 60));
        if (gn) { upsertEdge(mind, SELF, gn.key, 'targets', 'goal fact'); wrote = true; }
      }
    }
  }

  for (const tech of hints.tech || []) {
    const t = upsertNode(mind, 'technology', tech);
    if (t) { upsertEdge(mind, SELF, t.key, 'uses'); wrote = true; }
  }

  let projectNode = null;
  if (workspaceId) {
    projectNode = upsertNode(mind, 'project', workspaceId);
    if (projectNode) { upsertEdge(mind, SELF, projectNode.key, 'works_on'); wrote = true; }
    for (const tech of hints.tech || []) {
      const t = mind.graph.nodes[nodeKey('technology', tech)];
      if (t && projectNode) upsertEdge(mind, projectNode.key, t.key, 'uses');
    }
  }

  for (const goal of goalsTouched) {
    const gn = upsertNode(mind, 'goal', goal.title);
    if (gn) {
      upsertEdge(mind, SELF, gn.key, 'targets');
      if (projectNode) upsertEdge(mind, gn.key, projectNode.key, 'related_to');
      wrote = true;
    }
  }

  if (wrote) touchMind(mind);
  return wrote;
}

/** BFS neighborhood — retrieval + explainability use this. */
export function neighborhood(mind, startKey, depth = 2, maxNodes = 12) {
  const g = mind.graph;
  if (!g.nodes[startKey]) return { nodes: [], edges: [] };
  const seenN = new Set([startKey]);
  const seenE = [];
  let frontier = [startKey];
  for (let d = 0; d < depth && seenN.size < maxNodes; d++) {
    const next = [];
    for (const key of frontier) {
      for (const edge of Object.values(g.edges)) {
        const other = edge.from === key ? edge.to : edge.to === key ? edge.from : null;
        if (!other) continue;
        seenE.push(edge);
        if (!seenN.has(other) && seenN.size < maxNodes) {
          seenN.add(other);
          next.push(other);
        }
      }
    }
    frontier = next;
  }
  return {
    nodes: [...seenN].map(k => g.nodes[k]).filter(Boolean),
    edges: [...new Set(seenE)],
  };
}

/** Org memory view: an organization node + its full neighborhood. */
export function organizationView(mind, orgLabel) {
  const key = nodeKey('organization', orgLabel);
  return mind.graph.nodes[key] ? neighborhood(mind, key, 2, 20) : null;
}

/** Reflection hook: drop weakest leaf nodes when over cap. */
export function pruneGraph(mind) {
  const g = mind.graph;
  const over = Object.keys(g.nodes).length - CAPS.GRAPH_NODES;
  if (over <= 0) return 0;
  const degree = new Map();
  for (const e of Object.values(g.edges)) {
    degree.set(e.from, (degree.get(e.from) || 0) + e.weight);
    degree.set(e.to,   (degree.get(e.to)   || 0) + e.weight);
  }
  const victims = Object.values(g.nodes)
    .filter(n => n.key !== SELF)
    .sort((a, b) => ((degree.get(a.key) || 0) + a.weight) - ((degree.get(b.key) || 0) + b.weight))
    .slice(0, over);
  for (const v of victims) {
    delete g.nodes[v.key];
    for (const [ekey, e] of Object.entries(g.edges)) {
      if (e.from === v.key || e.to === v.key) delete g.edges[ekey];
    }
  }
  touchMind(mind);
  return victims.length;
}

