/**
 * AQUA Mind — Facade
 * ─────────────────────────────────────────────────────────────────────────────
 * The ONLY module the chat pipeline imports. Three calls:
 *
 *   mindObserve(owner, turn)   — inline, <1ms: signals → beliefs, goals,
 *                                working memory, episodes, graph. Called
 *                                during prepareTurn AFTER fact extraction
 *                                (reuses extractedFacts — no re-parse).
 *   mindContext(owner, q)      — inline: budgeted cognitive block for the
 *                                system prompt (rides memoryBlock slot).
 *   mindAfterTurn(owner, meta) — post-response: turn counting, prediction
 *                                rebuild, async reflection scheduling.
 *
 * Every call is fail-safe: a Mind failure logs a warning and returns a
 * neutral value — the chat pipeline can NEVER break because of the Mind.
 * owner=null (no user, no conversation) disables everything silently.
 */
import { resolveMindOwner, getMind, peekMind } from './mindStore.js';
import { observeSignals } from './beliefEngine.js';
import { observeTurn as runObservers, observeReaction } from './observers.js';
import { trackGoals } from './goalTracker.js';
import { updateWorkingMemory } from './workingMemory.js';
import { trackEpisode } from './episodeTracker.js';
import { updateGraph } from './relationshipGraph.js';
import { rebuildPredictions } from './predictionEngine.js';
import { scheduleReflection } from './reflectionEngine.js';
import { retrieveCognitiveContext } from './mindRetriever.js';

export { resolveMindOwner };

/**
 * Observe one user turn. Synchronous by design — pure heuristics, no I/O
 * beyond the debounced store save.
 * @returns {{ signals: number, goalsTouched: number }} diagnostics for logging
 */
export function mindObserve(ownerId, { userMessage, taskType, extractedFacts = [], workspaceId = null, conversationId = null }) {
  if (!ownerId) return { signals: 0, goalsTouched: 0 };
  try {
    const mind = getMind(ownerId);

    const { signals, hints } = runObservers({ userMessage, taskType, extractedFacts, workspaceId, conversationId });
    signals.push(...observeReaction({ userMessage, conversationId }));
    observeSignals(mind, signals);

    const goalsTouched = trackGoals(mind, { userMessage, extractedFacts, conversationId, workspaceId });
    updateWorkingMemory(mind, { userMessage, taskType, hints, workspaceId });
    trackEpisode(mind, { taskType, conversationId, userMessage, goalsTouched });
    updateGraph(mind, { extractedFacts, hints, goalsTouched, workspaceId });

    return { signals: signals.length, goalsTouched: goalsTouched.length };
  } catch (err) {
    console.warn('[MIND] observe failed (non-fatal):', err.message);
    return { signals: 0, goalsTouched: 0 };
  }
}

/**
 * Cognitive context for the prompt. Returns '' when the Mind is empty,
 * disabled, or nothing clears the relevance bar.
 */
export function mindContext(ownerId, { query = '', taskType = 'conversation', budgetTokens } = {}) {
  if (!ownerId) return { block: '', used: {} };
  try {
    const mind = peekMind(ownerId);          // peek: context must not create minds
    if (!mind) return { block: '', used: {} };
    return retrieveCognitiveContext(mind, { query, taskType, budgetTokens });
  } catch (err) {
    console.warn('[MIND] context failed (non-fatal):', err.message);
    return { block: '', used: {} };
  }
}

/**
 * Post-response bookkeeping. Counts the turn, rebuilds predictions, and
 * schedules async reflection when due. Cheap; reflection itself is deferred.
 */
export function mindAfterTurn(ownerId, { taskType = 'conversation', workspaceId = null } = {}) {
  if (!ownerId) return { reflected: false };
  try {
    const mind = getMind(ownerId);
    mind.turnCount += 1;
    rebuildPredictions(mind, { taskType, workspaceId });
    const reflected = scheduleReflection(mind);
    return { reflected };
  } catch (err) {
    console.warn('[MIND] afterTurn failed (non-fatal):', err.message);
    return { reflected: false };
  }
}

/**
 * AQUA Mind — Observers (the "Observe → Infer" step)
 * ─────────────────────────────────────────────────────────────────────────────
 * Turns ONE chat turn into inference SIGNALS for the belief engine.
 *
 * Deliberately zero-LLM, pure heuristics — same discipline as
 * workspaceAnalyzer: deterministic, fast (<1ms), runs inline on every turn
 * without cost. LLM-assisted observation can be added later as an
 * additional observer without changing any consumer.
 *
 * Sources fused per turn:
 *   1. classifier output      → identity / behavior signals
 *   2. message text           → communication style, knowledge, sentiment
 *   3. extracted schema facts → FACT BRIDGE: lifts the existing regex
 *      extractor's output into the cognitive model as evidence. Reuses the
 *      whole proven extraction pipeline — no duplicate extraction.
 *   4. workspace presence     → builder/behavior signals
 *
 * Never asks the user trait questions. Everything is inferred (Layer 2 rule).
 */
import { DIMENSIONS } from './mindSchema.js';

// ── 1. Task-type → trait mapping ──────────────────────────────────────────────
const TASK_TRAIT_MAP = {
  coding:           [{ key: 'engineer',          strength: 0.5 }, { key: 'builder', strength: 0.35 }],
  debugging:        [{ key: 'engineer',          strength: 0.55 }],
  architecture:     [{ key: 'systems_thinker',   strength: 0.6 }, { key: 'engineer', strength: 0.3 }],
  planning:         [{ key: 'long_term_planner', strength: 0.55 }],
  research:         [{ key: 'researcher',        strength: 0.5 }],
  analysis:         [{ key: 'researcher',        strength: 0.4 }],
  creative_writing: [{ key: 'creative',          strength: 0.5 }],
  brainstorming:    [{ key: 'creative',          strength: 0.4 }],
  project_query:    [{ key: 'builder',           strength: 0.4 }],
};

// ── 2. Text heuristics ────────────────────────────────────────────────────────
const TECH_TERMS = /\b(typescript|javascript|python|rust|golang|go|java|kotlin|swift|ruby|c\+\+|c#|sql|react|vue|svelte|angular|next\.?js|node(\.js)?|express|django|flask|fastapi|postgres(ql)?|mysql|mongodb|redis|docker|kubernetes|k8s|graphql|grpc|terraform|aws|gcp|azure|vite|webpack|tailwind)\b/gi;
const FOUNDER_HINTS = /\b((?:my|our) (?:startup|company|cofounder|co-founder|investors?|product|platform|users|customers)|fundrais|pitch deck|investor (?:demo|meeting|pitch|update)|mvp|go.to.market|runway)\b/i;
const DEADLINE_RE   = /\b(by|before|due|deadline|ship(ping)? (by|on)|launch(ing)? (by|on))\s+(tomorrow|tonight|today|this week|next week|monday|tuesday|wednesday|thursday|friday|saturday|sunday|jan(uary)?|feb(ruary)?|mar(ch)?|apr(il)?|may|jun(e)?|jul(y)?|aug(ust)?|sep(tember)?|oct(ober)?|nov(ember)?|dec(ember)?|\d)/i;
const REJECT_FLASHY = /\b(too (flashy|busy|cluttered|noisy|much)|less is more|keep it (simple|clean|minimal)|simpler|cleaner|minimal(ist)?)\b/i;
const WANTS_DETAIL  = /\b(explain in detail|deep dive|step by step|walk me through|thorough(ly)?|comprehensive)\b/i;
const WANTS_BRIEF   = /\b(tl;?dr|be brief|short answer|quick(ly)? (answer|version)|just tell me|no fluff|concise)\b/i;
const RISK_AVERSE   = /\b(don'?t break|be careful|safe(st)? (way|option)|backward.?compat|without breaking|non.?breaking)\b/i;
const RISK_TOLERANT = /\b(rewrite (it|everything|from scratch)|rip (it )?out|nuke it|start over|move fast)\b/i;

function techMentions(text) {
  const found = new Map();
  let m;
  TECH_TERMS.lastIndex = 0;
  while ((m = TECH_TERMS.exec(text)) !== null) {
    const t = m[0].toLowerCase().replace(/\.?js$/, m[0].toLowerCase() === 'next.js' || m[0].toLowerCase() === 'nextjs' ? 'js' : '');
    found.set(t, (found.get(t) || 0) + 1);
  }
  return found;
}

// ── 3. Fact bridge: schema facts → belief signals ─────────────────────────────
const FACT_TO_BELIEF = {
  favorite_language:  (f) => ({ dimension: DIMENSIONS.PREFERENCES, key: 'primary_language',  value: f.value, strength: 0.9 }),
  languages:          (f) => ({ dimension: DIMENSIONS.KNOWLEDGE,   key: 'languages',          value: f.value, strength: 0.7 }),
  favorite_framework: (f) => ({ dimension: DIMENSIONS.PREFERENCES, key: 'frameworks',         value: f.value, strength: 0.8 }),
  favorite_editor:    (f) => ({ dimension: DIMENSIONS.PREFERENCES, key: 'editor',             value: f.value, strength: 0.85 }),
  favorite_os:        (f) => ({ dimension: DIMENSIONS.PREFERENCES, key: 'os',                 value: f.value, strength: 0.85 }),
  profession:         (f) => ({ dimension: DIMENSIONS.IDENTITY,    key: 'profession',         value: f.value, strength: 0.85 }),
  workplace:          (f) => ({ dimension: DIMENSIONS.IDENTITY,    key: 'organization',       value: f.value, strength: 0.85 }),
  goal:               null, // handled by goalTracker, not beliefs
};

/**
 * Main entry: one turn → array of belief signals + side-channel hints
 * (deadlines/tech) consumed by workingMemory & goalTracker.
 */
export function observeTurn({ userMessage = '', taskType = 'conversation', extractedFacts = [], workspaceId = null, conversationId = null }) {
  const signals = [];
  const text = userMessage || '';
  const hints = { deadlines: [], tech: [], rejectedFlashy: false };

  // 1. identity/behavior from task type
  for (const t of TASK_TRAIT_MAP[taskType] || []) {
    signals.push({ dimension: DIMENSIONS.IDENTITY, key: t.key, value: true, strength: t.strength, note: `task:${taskType}`, conversationId });
  }
  if (workspaceId) {
    signals.push({ dimension: DIMENSIONS.BEHAVIOR, key: 'works_in_workspaces', value: true, strength: 0.5, note: 'attached workspace', conversationId });
  }

  // 2. founder / org hints
  if (FOUNDER_HINTS.test(text)) {
    signals.push({ dimension: DIMENSIONS.IDENTITY, key: 'founder', value: true, strength: 0.6, note: 'founder-context language', conversationId });
  }

  // 3. communication style — length & structure preferences
  const len = text.length;
  if (len > 0 && len < 120) {
    signals.push({ dimension: DIMENSIONS.COMMUNICATION, key: 'message_style', value: 'terse', strength: 0.3, note: `short message (${len} chars)`, conversationId });
  } else if (len > 900) {
    signals.push({ dimension: DIMENSIONS.COMMUNICATION, key: 'message_style', value: 'detailed', strength: 0.3, note: `long message (${len} chars)`, conversationId });
  }
  if (WANTS_BRIEF.test(text)) {
    signals.push({ dimension: DIMENSIONS.COMMUNICATION, key: 'response_length', value: 'brief', strength: 0.75, note: 'asked for brevity', conversationId });
  } else if (WANTS_DETAIL.test(text)) {
    signals.push({ dimension: DIMENSIONS.COMMUNICATION, key: 'response_length', value: 'detailed', strength: 0.7, note: 'asked for depth', conversationId });
  }

  // 4. implicit design preference (the "rejects flashy UI" case, Layer 3)
  if (REJECT_FLASHY.test(text)) {
    hints.rejectedFlashy = true;
    signals.push({ dimension: DIMENSIONS.PREFERENCES, key: 'design_style', value: 'minimal', strength: 0.7, note: 'rejected flashy/busy option', conversationId });
  }

  // 5. decision style
  if (RISK_AVERSE.test(text)) {
    signals.push({ dimension: DIMENSIONS.DECISION, key: 'risk_tolerance', value: 'cautious', strength: 0.55, note: 'asked for non-breaking/safe path', conversationId });
  } else if (RISK_TOLERANT.test(text)) {
    signals.push({ dimension: DIMENSIONS.DECISION, key: 'risk_tolerance', value: 'bold', strength: 0.55, note: 'asked for rewrite/fast path', conversationId });
  }

  // 6. knowledge model from tech mentions (Layer 4 — proficiency grows with use)
  const tech = techMentions(text);
  for (const [term, count] of tech) {
    hints.tech.push(term);
    signals.push({
      dimension: DIMENSIONS.KNOWLEDGE, key: `tech:${term}`, value: 'working_knowledge',
      strength: Math.min(0.6, 0.25 + count * 0.1), note: `mentioned ${term}`, conversationId,
    });
  }

  // 7. deadline hints → workingMemory (not a belief)
  const dl = text.match(DEADLINE_RE);
  if (dl) hints.deadlines.push({ label: dl[0].slice(0, 80), ts: null, source: 'message' });

  // 8. FACT BRIDGE — reuse the proven extractor output as high-quality evidence
  for (const fact of extractedFacts) {
    const map = FACT_TO_BELIEF[fact.key];
    if (!map) continue;
    const sig = map(fact);
    if (sig) signals.push({ ...sig, note: `extracted fact: ${fact.key}`, conversationId, source: 'fact_bridge' });
  }

  return { signals, hints };
}

/**
 * Post-response observer: user's NEXT message reacting to the previous answer.
 * Detects correction/pushback → contradiction evidence on communication fit.
 * Cheap heuristic; called with previous assistant turn context by the facade.
 */
const PUSHBACK_RE = /\b(no[,.]|that'?s (wrong|not right|not what)|you misunderstood|not what i (meant|asked)|incorrect|too long|too verbose)\b/i;
export function observeReaction({ userMessage = '', conversationId = null }) {
  const signals = [];
  if (PUSHBACK_RE.test(userMessage)) {
    signals.push({
      dimension: DIMENSIONS.COMMUNICATION, key: 'assistant_fit', value: 'aligned',
      support: false, strength: 0.5, note: 'user pushed back on previous answer', conversationId,
    });
  }
  return signals;
}

/**
 * AQUA Mind Store
 * ─────────────────────────────────────────────────────────────────────────────
 * USER-scoped persistence for cognitive models. One Mind per owner.
 *
 * Deliberately mirrors the proven longTermMemory/conversationStore pattern:
 * in-memory Map + debounced JSON file write. Single file (.aqua-mind.json)
 * per engineering requirement "avoid duplicate storage" — subsystems are
 * modular in CODE, unified in PERSISTENCE.
 *
 * Owner resolution (see resolveMindOwner):
 *   platform session → `user:<aquaUserId>`  (cross-conversation, the real goal)
 *   engine run bare  → `conv:<conversationId>` fallback so the Mind still
 *                      works in dev/demo without the platform session layer.
 *
 * NOTE (scaling / migration path): the Map+file store is the same tier the
 * rest of AQUA persistence currently uses. All access goes through this
 * module's API, so swapping to SQLite/Postgres later touches ONE file.
 */
import fs   from 'fs';
import path from 'path';
import { createEmptyMind } from './mindSchema.js';

const STORE_FILE = path.join(process.cwd(), '.aqua-mind.json');

// ownerId → Mind
const store = new Map();
let loaded = false;

function loadFromDisk() {
  if (loaded) return;
  loaded = true;
  try {
    if (!fs.existsSync(STORE_FILE)) return;
    const data = JSON.parse(fs.readFileSync(STORE_FILE, 'utf8'));
    for (const [ownerId, mind] of Object.entries(data)) store.set(ownerId, upgradeMind(mind));
    console.log(`[MIND] Loaded ${store.size} cognitive models from disk`);
  } catch (err) {
    console.warn('[MIND] Could not load from disk:', err.message);
  }
}

let saveTimer = null;
function scheduleSave() {
  if (saveTimer) return;
  saveTimer = setTimeout(() => {
    saveTimer = null;
    try {
      const data = {};
      for (const [ownerId, mind] of store.entries()) data[ownerId] = mind;
      fs.writeFileSync(STORE_FILE, JSON.stringify(data), 'utf8');
    } catch (err) {
      console.warn('[MIND] Could not save to disk:', err.message);
    }
  }, 500);
}
loadFromDisk();

/** Schema v1 → v2: facts + files live INSIDE the mind (single store). */
function upgradeMind(mind) {
  if (!mind) return mind;
  if (!mind.facts) mind.facts = {};
  if (!mind.files) mind.files = {};
  if (!mind.version || mind.version < 2) mind.version = 2;
  return mind;
}

/**
 * Resolve which Mind a request belongs to.
 * DEPRECATED shim — the ONE owner model now lives in memory/ownerResolver.js
 * (which also performs conv→user adoption). Kept for mindRoutes/back-compat;
 * logic identical, no adoption side effects here.
 */
export function resolveMindOwner({ userId = null, conversationId = null } = {}) {
  if (userId) return `user:${userId}`;
  if (conversationId) return `conv:${conversationId}`;
  return null;
}

/**
 * One-time adoption: merge a pre-login `conv:` mind into the real `user:`
 * mind, then tombstone the source. Facts merge via longTermMemory's conflict
 * resolver (caller wires that — see ownerResolver) is NOT needed here:
 * fact-level merge uses simple newer/higher-confidence-wins to avoid a
 * circular import; the same priority order the resolver applies.
 */
export function adoptMind(fromOwner, toOwner) {
  const src = store.get(fromOwner);
  if (!src || src.adoptedInto) return false;
  const dst = getMind(toOwner);

  // Facts: keep whichever is newer, else higher confidence. History preserved.
  for (const [key, fact] of Object.entries(src.facts || {})) {
    const existing = dst.facts[key];
    if (!existing) { dst.facts[key] = fact; continue; }
    const factTs = fact.ts || fact.updatedAt || 0;
    const exTs   = existing.ts || existing.updatedAt || 0;
    const incomingWins = factTs > exTs ||
      (factTs === exTs && (fact.confidence || 0) > (existing.confidence || 0));
    if (incomingWins) {
      fact.history = [...(existing.history || []), ...(fact.history || [])];
      fact.revision = Math.max(fact.revision || 1, (existing.revision || 1) + 1);
      dst.facts[key] = fact;
    }
  }

  // Beliefs: higher confidence wins; evidence concatenated (capped later by reflection).
  for (const [key, belief] of Object.entries(src.beliefs || {})) {
    const existing = dst.beliefs[key];
    if (!existing || (belief.confidence || 0) > (existing.confidence || 0)) {
      if (existing) belief.evidence = [...(existing.evidence || []), ...(belief.evidence || [])];
      dst.beliefs[key] = belief;
    }
  }

  // Goals / episodes / files: union, existing wins on id collision.
  for (const bag of ['goals', 'episodes', 'files']) {
    for (const [id, item] of Object.entries(src[bag] || {})) {
      if (!dst[bag][id]) dst[bag][id] = item;
    }
  }

  // Graph: union nodes/edges, weights added.
  for (const [k, n] of Object.entries(src.graph?.nodes || {})) {
    if (dst.graph.nodes[k]) dst.graph.nodes[k].weight += n.weight || 1;
    else dst.graph.nodes[k] = n;
  }
  for (const [k, e] of Object.entries(src.graph?.edges || {})) {
    if (dst.graph.edges[k]) dst.graph.edges[k].weight += e.weight || 1;
    else dst.graph.edges[k] = e;
  }

  dst.turnCount += src.turnCount || 0;
  src.adoptedInto = toOwner;
  src.adoptedAt = Date.now();
  touchMind(dst);
  scheduleSave();
  console.log(`[MIND] ADOPTED ${fromOwner} → ${toOwner} facts=${Object.keys(src.facts || {}).length} beliefs=${Object.keys(src.beliefs || {}).length}`);
  return true;
}

export function getMind(ownerId) {
  if (!ownerId) return null;
  let mind = store.get(ownerId);
  if (!mind) {
    mind = createEmptyMind(ownerId);
    store.set(ownerId, mind);
    console.log(`[MIND] MIND_CREATED owner=${ownerId}`);
  }
  return mind;
}

export function peekMind(ownerId) {
  return ownerId ? (store.get(ownerId) ?? null) : null;
}

/** Mark mutated + persist. Every subsystem calls this after writing. */
export function touchMind(mind) {
  if (!mind) return;
  mind.updatedAt = Date.now();
  scheduleSave();
}

export function deleteMind(ownerId) {
  const existed = store.delete(ownerId);
  if (existed) scheduleSave();
  return existed;
}

/** Layer 19 — full export. The user owns the model. */
export function exportMind(ownerId) {
  const mind = peekMind(ownerId);
  return mind ? JSON.parse(JSON.stringify(mind)) : null;
}

export function mindStats() {
  let beliefs = 0, goals = 0, episodes = 0;
  for (const m of store.values()) {
    beliefs  += Object.keys(m.beliefs  || {}).length;
    goals    += Object.keys(m.goals    || {}).length;
    episodes += Object.keys(m.episodes || {}).length;
  }
  return { minds: store.size, beliefs, goals, episodes };
}

/** Internal: stats iteration for the unified fact layer (longTermMemory). */
export function _iterateMindsForStats() {
  return store.values();
}

/** Test-only: reset in-memory state (does not touch disk). */
export function _clearAllForTests() {
  store.clear();
}

/**
 * AQUA Mind — Belief Engine (Layers 1–4, 11, 17, 18)
 * ─────────────────────────────────────────────────────────────────────────────
 * The only writer of mind.beliefs. All inference lands here as SIGNALS:
 *
 *   { dimension, key, value, strength, support, note, conversationId, source }
 *
 * Rules enforced here (and nowhere else, so they can't drift):
 *   • confidence via confidence.js — never set directly
 *   • contradiction lowers confidence and versions the old value into
 *     history — NEVER overwrites silently
 *   • locked beliefs (user-pinned) are immune to inference
 *   • every belief can explain itself from its evidence window (Layer 17)
 *   • user corrections (Layer 18) are explicit-source, high-confidence,
 *     and recorded as correction evidence
 */
import { createBelief, beliefKey, CAPS, DIMENSION_DYNAMICS, STATUS } from './mindSchema.js';
import { reinforce, contradict, fromExplicit, clamp01 } from './confidence.js';
import { touchMind } from './mindStore.js';

function valuesEqual(a, b) {
  if (a === b) return true;
  return JSON.stringify(a) === JSON.stringify(b);
}

function pushEvidence(belief, entry) {
  belief.evidence.push(entry);
  if (belief.evidence.length > CAPS.EVIDENCE_WINDOW) {
    belief.evidence.splice(0, belief.evidence.length - CAPS.EVIDENCE_WINDOW);
  }
  belief.evidenceCount += 1;
  belief.lastEvidenceAt = entry.ts;
}

function versionValue(belief, reason) {
  belief.history.push({
    value: belief.value,
    confidence: belief.confidence,
    supersededAt: Date.now(),
    reason,
  });
  if (belief.history.length > CAPS.HISTORY_PER_ITEM) {
    belief.history.splice(0, belief.history.length - CAPS.HISTORY_PER_ITEM);
  }
}

/**
 * Apply one inference signal to the Mind.
 * support=true reinforces `value`; support=false is contradicting evidence
 * against the CURRENT value.
 *
 * Same-value signal   → reinforce confidence.
 * Different value     → contradiction of old + seed/strengthen new:
 *   old confidence drops; if the incoming value's implied confidence would
 *   now exceed the old, the belief flips value (old value → history).
 */
export function observeSignal(mind, signal) {
  if (!mind || !signal?.dimension || !signal?.key) return null;
  const {
    dimension, key, value, strength = 0.6, support = true,
    note = '', conversationId = null, source = 'inference',
  } = signal;

  const dyn = DIMENSION_DYNAMICS[dimension] ?? { changeRate: 0.1 };
  const bk  = beliefKey(dimension, key);
  let belief = mind.beliefs[bk];
  const now  = Date.now();
  const ev   = { ts: now, conversationId, signal: note || key, delta: 0, support };

  // New belief
  if (!belief) {
    if (!support) return null; // can't contradict what isn't believed
    belief = createBelief({
      dimension, key, value,
      confidence: clamp01(0.25 + dyn.changeRate * strength),
      source,
    });
    ev.delta = belief.confidence;
    pushEvidence(belief, ev);
    mind.beliefs[bk] = belief;
    touchMind(mind);
    return belief;
  }

  if (belief.privacy?.locked || belief.status === STATUS.LOCKED) return belief; // user-pinned

  const before = belief.confidence;

  if (support && valuesEqual(belief.value, value)) {
    belief.confidence = reinforce(before, dyn.changeRate, strength);
  } else if (!support) {
    belief.confidence = contradict(before, strength);
    belief.contradictions += 1;
  } else {
    // Supporting a DIFFERENT value = contradiction of current + challenger
    belief.confidence = contradict(before, strength);
    belief.contradictions += 1;
    const challenger = clamp01(0.25 + dyn.changeRate * strength);
    if (challenger > belief.confidence) {
      versionValue(belief, 'superseded_by_evidence');
      belief.value = value;
      belief.confidence = challenger;
    }
  }

  ev.delta = +(belief.confidence - before).toFixed(4);
  pushEvidence(belief, ev);
  belief.updatedAt = now;
  if (belief.status === STATUS.ARCHIVED && belief.confidence > 0.3) belief.status = STATUS.ACTIVE;
  touchMind(mind);
  return belief;
}

/** Batch helper — chat pipeline emits arrays of signals per turn. */
export function observeSignals(mind, signals = []) {
  const touched = [];
  for (const s of signals) {
    const b = observeSignal(mind, s);
    if (b) touched.push(b);
  }
  return touched;
}

// ── Layer 18 — user edits ─────────────────────────────────────────────────────

/** Explicit user correction: dominates inference, fully audited. */
export function correctBelief(mind, dimension, key, value, { note = 'user correction' } = {}) {
  const bk = beliefKey(dimension, key);
  let belief = mind.beliefs[bk];
  const now = Date.now();
  if (!belief) {
    belief = createBelief({ dimension, key, value, confidence: fromExplicit(0), source: 'correction' });
    mind.beliefs[bk] = belief;
  } else {
    if (!valuesEqual(belief.value, value)) versionValue(belief, 'user_correction');
    belief.value = value;
    belief.confidence = fromExplicit(belief.confidence);
    belief.privacy.source = 'correction';
    belief.status = STATUS.ACTIVE;
  }
  pushEvidence(belief, { ts: now, conversationId: null, signal: note, delta: 0, support: true, correction: true });
  belief.updatedAt = now;
  touchMind(mind);
  return belief;
}

export function lockBelief(mind, dimension, key, locked = true) {
  const belief = mind.beliefs[beliefKey(dimension, key)];
  if (!belief) return null;
  belief.privacy.locked = locked;
  belief.updatedAt = Date.now();
  touchMind(mind);
  return belief;
}

export function markTemporary(mind, dimension, key, temporary = true) {
  const belief = mind.beliefs[beliefKey(dimension, key)];
  if (!belief) return null;
  belief.privacy.temporary = temporary;
  touchMind(mind);
  return belief;
}

/** Delete part of the model. History goes too — the user owns the model. */
export function deleteBelief(mind, dimension, key) {
  const bk = beliefKey(dimension, key);
  if (!mind.beliefs[bk]) return false;
  delete mind.beliefs[bk];
  touchMind(mind);
  return true;
}

// ── Layer 17 — explainability ─────────────────────────────────────────────────

/** "Why do you believe X?" — grounded in the evidence window, no hand-waving. */
export function explainBelief(belief) {
  if (!belief) return null;
  const supports = belief.evidence.filter(e => e.support !== false);
  const contras  = belief.evidence.filter(e => e.support === false);
  const signals  = [...new Set(supports.map(e => e.signal))].slice(0, 5);
  const convs    = new Set(belief.evidence.map(e => e.conversationId).filter(Boolean));

  const parts = [];
  parts.push(
    `Believed because of ${belief.evidenceCount} observation${belief.evidenceCount === 1 ? '' : 's'}` +
    (convs.size ? ` across ${convs.size} conversation${convs.size === 1 ? '' : 's'}` : '') + '.'
  );
  if (signals.length) parts.push(`Strongest signals: ${signals.join('; ')}.`);
  if (belief.contradictions > 0) {
    parts.push(`${belief.contradictions} contradicting observation${belief.contradictions === 1 ? '' : 's'} lowered confidence — history preserved.`);
  }
  if (belief.history.length) {
    const prev = belief.history[belief.history.length - 1];
    parts.push(`Previously believed: ${JSON.stringify(prev.value)} (superseded ${new Date(prev.supersededAt).toISOString().slice(0, 10)}).`);
  }
  if (belief.privacy?.source === 'correction') parts.push('Set explicitly by the user.');

  return {
    dimension: belief.dimension,
    key: belief.key,
    value: belief.value,
    confidence: +belief.confidence.toFixed(3),
    evidenceCount: belief.evidenceCount,
    contradictions: belief.contradictions,
    explanation: parts.join(' '),
    recentEvidence: belief.evidence.slice(-5),
    _contraCount: contras.length,
  };
}

// ── Queries ───────────────────────────────────────────────────────────────────
export function getBeliefs(mind, { dimension = null, minConfidence = 0, status = STATUS.ACTIVE } = {}) {
  return Object.values(mind.beliefs)
    .filter(b => (!dimension || b.dimension === dimension)
              && b.confidence >= minConfidence
              && (!status || b.status === status || b.status === STATUS.LOCKED))
    .sort((a, b) => b.confidence - a.confidence);
}

/**
 * AQUA Mind — Episodic Memory (Layer 8)
 * ─────────────────────────────────────────────────────────────────────────────
 * Experiences, not isolated facts. An episode is a themed arc: it opens when
 * a distinct focus emerges, accumulates conversations/objectives, and closes
 * (with an outcome) when the theme completes or goes quiet. Reflection closes
 * quiet episodes; completion cues close them with an outcome.
 *
 * Heuristic theming (zero-LLM): dominant focus topic + task type. An
 * LLM-assisted summarizer can later rewrite titles/lessons without schema
 * change.
 */
import { createEpisode, createTimelineEvent, STATUS } from './mindSchema.js';
import { touchMind } from './mindStore.js';
import { pushTimeline } from './timeline.js';
import { currentFocus } from './workingMemory.js';

const EPISODE_IDLE_CLOSE_MS = 5 * 24 * 3600 * 1000; // quiet 5 days → close
const OUTCOME_RE = /\b(shipped|launched|completed|fixed it|solved|it works now|resolved|merged|deployed)\b/i;

function activeEpisode(mind) {
  return Object.values(mind.episodes)
    .filter(e => e.status === STATUS.ACTIVE)
    .sort((a, b) => b.lastActivityAt - a.lastActivityAt)[0] || null;
}

function themeFor(mind, taskType) {
  const focus = currentFocus(mind, 2).map(f => f.topic).filter(t => !t.startsWith('workspace:'));
  if (focus.length) return focus.join(' + ');
  return taskType !== 'conversation' ? taskType : null;
}

/**
 * Per-turn episode maintenance:
 *   • continue the active episode if theme overlaps, else open a new one
 *   • record outcome cues
 */
export function trackEpisode(mind, { taskType = 'conversation', conversationId = null, userMessage = '', goalsTouched = [] }) {
  const now = Date.now();
  const theme = themeFor(mind, taskType);
  if (!theme) return null;

  let ep = activeEpisode(mind);
  const themeTokens = new Set(theme.toLowerCase().split(/[\s+]+/).filter(Boolean));
  const overlaps = ep && [...themeTokens].some(t => ep.title.toLowerCase().includes(t));

  if (ep && !overlaps && now - ep.lastActivityAt > 12 * 3600 * 1000) {
    // Theme moved on after a gap — close the old arc quietly
    closeEpisode(mind, ep, 'theme shifted');
    ep = null;
  }

  if (!ep || !overlaps) {
    ep = createEpisode({ title: `Working on ${theme}`, conversationId });
    mind.episodes[ep.id] = ep;
    pushTimeline(mind, createTimelineEvent({ kind: 'episode_opened', subject: ep.title, importance: 5 }));
  }

  if (conversationId && !ep.conversationIds.includes(conversationId)) ep.conversationIds.push(conversationId);
  for (const g of goalsTouched) {
    if (!ep.objectives.includes(g.title)) ep.objectives.push(g.title);
  }
  ep.lastActivityAt = now;

  if (OUTCOME_RE.test(userMessage)) {
    closeEpisode(mind, ep, userMessage.match(OUTCOME_RE)[0]);
  }

  touchMind(mind);
  return ep;
}

export function closeEpisode(mind, ep, outcome) {
  if (!ep || ep.status !== STATUS.ACTIVE) return;
  ep.status = STATUS.ARCHIVED;
  ep.endedAt = Date.now();
  ep.outcome = outcome || null;
  pushTimeline(mind, createTimelineEvent({ kind: 'episode_closed', subject: ep.title, detail: outcome || '', importance: 6 }));
  touchMind(mind);
}

/** Reflection hook: close episodes that went quiet. */
export function closeStaleEpisodes(mind) {
  const now = Date.now();
  let closed = 0;
  for (const ep of Object.values(mind.episodes)) {
    if (ep.status === STATUS.ACTIVE && now - ep.lastActivityAt > EPISODE_IDLE_CLOSE_MS) {
      closeEpisode(mind, ep, 'went quiet');
      closed++;
    }
  }
  return closed;
}

export function getEpisodes(mind, { activeOnly = false, limit = 10 } = {}) {
  return Object.values(mind.episodes)
    .filter(e => !activeOnly || e.status === STATUS.ACTIVE)
    .sort((a, b) => b.lastActivityAt - a.lastActivityAt)
    .slice(0, limit);
}

/**
 * AQUA Task Classifier v5
 *
 * Changes from v4 (Issue 2 — coding/architecture requests misclassified as
 * simple_qa):
 *   "Build a production-ready JWT authentication system" scored 0 against
 *   every category (no language/framework named) and fell through to
 *   classifyTask's zero-score fallback, which defaults short messages to
 *   simple_qa. coding gained a paired build/create/generate/develop +
 *   technical-object pattern plus standalone technical terms (JWT, OAuth,
 *   Express/NestJS/Fastify, database, Redis, Docker, Kubernetes,
 *   authentication, authorization, endpoint, API) and "rust" joined the
 *   language list. architecture gained multi-tenant and "authentication/
 *   authorization architecture" phrasing. See PATTERNS.coding/architecture
 *   below for the v5-tagged entries.
 *
 * Changes from v3:
 *   4. research/coding guard (Phase 6 — Adaptive Tool Orchestrator spec):
 *      The generic "explain/clarify/elaborate/describe X" research pattern
 *      had no competing bare "code"/"function" trigger in `coding`, so
 *      messages like "Explain this code" or "Describe this function"
 *      classified as research instead of coding/project_query.
 *      Fix: (a) project_query gained explicit "explain/describe this code/
 *      function/script/..." patterns, (b) a scoring guard demotes the
 *      generic explain-pattern's research contribution whenever it is the
 *      *only* research signal and a coding/debugging/project_query signal
 *      is already present.
 *   5. scoreTask() exported — raw per-category scores (same scoring used by
 *      classifyTask) for the Adaptive Tool Orchestrator's multi-label layer.
 *      Pure addition; classifyTask()'s contract/output is unchanged.
 *
 * Changes from v2:
 *   1. memory_recall / memory_update — new task types
 *      "What's my favorite language?" → memory_recall (not personal_info)
 *      "Remember that I moved to Berlin" → memory_update
 *   2. planning vs architecture fix:
 *      planning weight raised to 1.55 (was 1.3) — now beats architecture (1.5)
 *      architecture guard: presence of roadmap/sprint/backlog boosts planning
 *      New planning patterns: "design a roadmap", "plan the architecture"
 *   3. personal_info guard: "I love X" only fires if X is NOT a known tech term
 *      (prevents "I love TypeScript" → personal_info instead of coding)
 */

