// ── Weights ────────────────────────────────────────────────────────────────────

const WEIGHTS = {
  project_query:    2.0,   // Wins over generic coding/research for project questions
  memory_recall:    3.5,   // Must win for recall queries
  memory_update:    3.5,   // Must win for update/forget queries
  personal_info:    3.0,   // Wins over language keyword hits
  conversation:     2.5,
  file_analysis:    2.0,
  architecture:     1.50,
  planning:         1.55,  // FIX: raised above architecture (was 1.3)
  debugging:        1.40,
  coding:           1.20,
  reasoning:        1.20,
  research:         1.20,
  analysis:         1.10,
  creative_writing: 1.10,
  brainstorming:    1.00,
  summarization:    1.00,
  simple_qa:        1.00,
  opinion:          0.90,
};

// Tasks indicating real work — bypass "short = conversation" heuristic
const SUBSTANTIVE = new Set([
  'coding', 'architecture', 'research', 'reasoning', 'analysis',
  'creative_writing', 'file_analysis', 'debugging', 'planning',
  'brainstorming', 'summarization', 'memory_recall', 'memory_update',
  'project_query',
]);

// ── Classifier ────────────────────────────────────────────────────────────────

/**
 * Raw per-category pattern scores for a message, including the v4 guard
 * (see header comment) that demotes `research`'s generic explain/describe/
 * elaborate/clarify contribution when it's the *only* research signal and a
 * coding/debugging/project_query signal is already present.
 *
 * Exported for the Adaptive Tool Orchestrator's multi-label classifier
 * (src/orchestrator/multiLabelClassifier.js) — single source of truth for
 * scoring, shared with classifyTask() below so the two can never diverge.
 *
 * @param {string} userMessage
 * @returns {Object<string, number>}
 */
// Used only inside the v4 guard below (not a scoring pattern) — detects a
// code-context reference anywhere in the message, even when it's not
// directly adjacent to the explain/clarify verb (e.g. "clarify what's
// happening in my code below"). Safe to be broad here: it only ever
// *demotes* research's generic-explain contribution, never boosts anything,
// so over-triggering just means "don't blindly trust the generic pattern".
const CODE_CONTEXT_HINT =
  /\b(my|this|the|that)\s+(code|function|script|file|class|method|bug|error|logic|implementation|snippet|variable)\b|\bcode\s+(below|above|here|snippet)\b/i;

export function scoreTask(userMessage) {
  const msg = (userMessage || '').trim();
  const scores = {};
  for (const [task, patterns] of Object.entries(PATTERNS)) {
    let s = 0;
    for (const p of patterns) {
      if (p.test(msg)) s += WEIGHTS[task] ?? 1.0;
    }
    scores[task] = s;
  }

  // v4 guard — see classifier docstring, point 4.
  if (GENERIC_EXPLAIN_PATTERN.test(msg)) {
    const onlyGenericResearchSignal = PATTERNS.research
      .filter((p) => p !== GENERIC_EXPLAIN_PATTERN)
      .every((p) => !p.test(msg));
    const hasCodeSignal =
      scores.coding > 0 || scores.project_query > 0 || scores.debugging > 0 ||
      CODE_CONTEXT_HINT.test(msg);
    if (onlyGenericResearchSignal && hasCodeSignal) {
      scores.research *= 0.4;
    }
  }

  return scores;
}

/**
 * Classify a user message into a task type with confidence.
 *
 * @param {string} userMessage
 * @param {Array}  [history]  reserved for future context-aware classification
 * @returns {{ task: string, confidence: number, labels: string[] }}
 */
export function classifyTask(userMessage, history = []) {
  if (!userMessage || typeof userMessage !== 'string') {
    return { task: 'conversation', confidence: 1.0, labels: ['conversation'] };
  }

  const msg = userMessage.trim();
  if (!msg.length) {
    return { task: 'conversation', confidence: 1.0, labels: ['conversation'] };
  }

  // Score every category (includes v4 research/coding guard)
  const scores = scoreTask(msg);

  // Short message heuristic: unless substantive signal, default to conversation
  if (msg.length < 55) {
    const substantiveScore = [...SUBSTANTIVE].reduce((sum, t) => sum + (scores[t] ?? 0), 0);
    if (substantiveScore < 1.0) {
      return { task: 'conversation', confidence: 0.85, labels: ['conversation'] };
    }
  }

  const sorted = Object.entries(scores).sort((a, b) => b[1] - a[1]);
  const [topTask, topScore]       = sorted[0];
  const [secondTask, secondScore] = sorted[1] ?? [null, 0];

  if (topScore === 0) {
    const fallback = msg.length < 120 ? 'simple_qa' : 'research';
    return { task: fallback, confidence: 0.45, labels: [fallback] };
  }

  const gap        = topScore - (secondScore ?? 0);
  const confidence = Math.min(0.97, 0.5 + (gap / topScore) * 0.5);

  const labels = [topTask];
  if (secondTask && secondScore > 0 && secondScore >= topScore * 0.70) {
    labels.push(secondTask);
  }

  return { task: topTask, confidence, labels };
}

/** Backward-compatible single-value wrapper */
export function classifyTaskSimple(userMessage) {
  return classifyTask(userMessage).task;
}

// ── Complexity tiers (Phase 4: feeds Execution Planner) ─────────────────────
// Pure addition — does not touch PATTERNS/WEIGHTS/classifyTask above.

const COMPLEXITY_TIERS = {
  high:   ['architecture', 'research', 'planning', 'agent_task', 'analysis', 'project_query'],
  medium: ['coding', 'debugging', 'reasoning', 'creative_writing', 'brainstorming', 'summarization', 'file_analysis'],
  low:    ['conversation', 'memory_recall', 'memory_update', 'personal_info', 'simple_qa', 'opinion'],
};

const TASK_COMPLEXITY = {};
for (const [tier, tasks] of Object.entries(COMPLEXITY_TIERS)) {
  for (const t of tasks) TASK_COMPLEXITY[t] = tier;
}

/**
 * Map a task type to a complexity tier — consumed by executionPlanner.js
 * to decide multi-step handling, reasoning mode, and timeout scaling.
 *
 * @param {string} taskType
 * @returns {'low'|'medium'|'high'}
 */
export function getTaskComplexity(taskType) {
  return TASK_COMPLEXITY[taskType] ?? 'medium';
}

/**
 * getTaskComplexity() + the confidence-escalation rule executionPlanner.js's
 * createExecutionPlan() has always applied ("low classifier confidence →
 * escalate complexity one tier"). Extracted here (Phase 6) so the Adaptive
 * Tool Orchestrator (src/orchestrator/toolOrchestrator.js) — which the spec
 * runs *before* the Execution Planner — can derive the exact same
 * complexity tier createExecutionPlan() will derive a moment later, without
 * duplicating the escalation rule or requiring either module to run after
 * the other. executionPlanner.js now calls this too (see its own comment) —
 * single source of truth, used independently by two pipeline stages, the
 * same pattern classifyTask()'s output already follows everywhere else.
 *
 * @param {string} taskType
 * @param {number} [confidence] - classifyTask(...).confidence
 * @returns {'low'|'medium'|'high'}
 */
export function getEffectiveComplexity(taskType, confidence = 1.0) {
  let complexity = getTaskComplexity(taskType);
  if (confidence < 0.55) {
    if (complexity === 'low') complexity = 'medium';
    else if (complexity === 'medium') complexity = 'high';
  }
  return complexity;
}

/**
 * AQUA Startup Validation (Issue 6)
 *
 * Runs once at boot, right before the server starts listening:
 *   - Validates every entry in the central Model Registry (modelRegistry.js)
 *     and disables anything malformed.
 *   - Warns (does not fail) if a provider has zero configured API keys —
 *     that provider will simply score 0 / be skipped by the router at
 *     request time (existing degraded-mode behavior in router.js), rather
 *     than crashing startup.
 *
 * Contract: this function NEVER throws. "One invalid model must never
 * break a provider" (Issue 6) — the same principle applies to the whole
 * validation pass itself: a problem here is always a logged warning, never
 * a boot failure.
 */

import { validateRegistryOnStartup, getRegistrySnapshot } from '../providers/modelRegistry.js';
import { hasConfiguredKeys as geminiHasKeys }     from '../providers/gemini.js';
import { hasConfiguredKeys as groqHasKeys }       from '../providers/groq.js';
import { hasConfiguredKeys as openrouterHasKeys } from '../providers/openrouter.js';

export function runStartupValidation() {
  console.log('[STARTUP] Validating model registry and provider configuration...');

  let registryResult = { validCount: 0, disabledCount: 0, issues: [] };
  try {
    registryResult = validateRegistryOnStartup();
  } catch (err) {
    // Defensive only — validateRegistryOnStartup() is designed to never
    // throw, but startup must continue even if it somehow does.
    console.warn(`[STARTUP] ⚠ Model registry validation raised an error (continuing anyway): ${err.message}`);
  }

  const keyChecks = { gemini: false, groq: false, openrouter: false };
  try { keyChecks.gemini     = geminiHasKeys(); }     catch { /* no-op — treated as "no keys" */ }
  try { keyChecks.groq       = groqHasKeys(); }       catch { /* no-op */ }
  try { keyChecks.openrouter = openrouterHasKeys(); } catch { /* no-op */ }

  for (const [provider, ok] of Object.entries(keyChecks)) {
    if (!ok) {
      console.warn(`[STARTUP] ⚠ No API keys configured for provider="${provider}" — it will score 0 and be skipped until keys are added.`);
    }
  }

  if (Object.values(keyChecks).every(ok => !ok)) {
    console.warn('[STARTUP] ⚠⚠ NO providers have any configured keys — every request will fail until at least one is set.');
  }

  console.log(`[STARTUP] Ready. Registry: ${registryResult.validCount} valid / ${registryResult.disabledCount} disabled models.`);

  return { registry: registryResult, keyChecks, snapshot: getRegistrySnapshot() };
}

/**
 * AQUA Observability v2
 *
 * Changes:
 *   - createContext() now accepts { conversationId, requestId } object
 *     (was: single string conversationId — silently lost requestId separation)
 *   - logMemoryEvent() — new: records every memory lifecycle event
 *   - logCompletion() extended: memoriesExtracted, memoriesInjected fields
 *   - All log lines carry requestId + conversationId for full correlation
 *
 * Log types emitted:
 *   AQUA_REQUEST  — one per HTTP request at completion
 *   AQUA_MEMORY   — one per memory event (EXTRACTED / RETRIEVED / INJECTED / SKIPPED)
 *   AQUA_PLAN     — Phase 4: one per request, execution plan (complexity/multiStep/reasoningMode)
 */

import { v4 as uuidv4 } from 'uuid';

// ── In-memory metrics (Prometheus-ready — swap for prom-client later) ─────────

const metrics = {
  totalRequests:   0,
  totalSuccesses:  0,
  totalFailures:   0,
  byProvider:      {},  // provider → { requests, successes, failures, totalLatencyMs }
  byTask:          {},  // task     → { requests, successes, failures }
  memoryEvents:    {},  // event    → count
  latencyWindow:   [],  // last 500 request latencies (ms)
  planComplexity:  {},  // Phase 4: complexity tier → count
  intelligenceActivations: 0, // Internal Intelligence Engine: count of active runs
  orchestratorProfiles:    {}, // Phase 6: execution profile id → count
  orchestratorCapabilities: { enabled: {}, skipped: {} }, // Phase 6: capability id → count
  verificationEnabled: 0, // Phase 6: count of requests where verification was warranted
  verificationRuns:    0, // count of requests where the verification agent actually executed
  verificationRevised: 0, // of those, count where the draft was replaced
  verificationFailed:  0, // count where the verifier call itself errored (failed open)
};

// ── Recent log ring buffer (last 200 structured AQUA_REQUEST entries) ─────────
const LOG_RING_SIZE = 200;
const recentLogs    = [];

function ensureProvider(p) {
  if (!metrics.byProvider[p])
    metrics.byProvider[p] = { requests: 0, successes: 0, failures: 0, totalLatencyMs: 0 };
}

function ensureTask(t) {
  if (!metrics.byTask[t])
    metrics.byTask[t] = { requests: 0, successes: 0, failures: 0 };
}

function pushLatency(ms) {
  metrics.latencyWindow.push(ms);
  if (metrics.latencyWindow.length > 500) metrics.latencyWindow.shift();
}

// ── Request context ───────────────────────────────────────────────────────────

/**
 * Create a context object for one HTTP request.
 *
 * @param {{ conversationId: string, requestId: string } | string} [idObj]
 *   Pass an object { conversationId, requestId } from chat.js.
 *   Accepts a bare string for backward compat (treated as conversationId).
 *
 * @returns {{ requestId, conversationId, startTime, attempts }}
 */
export function createContext(idObj) {
  let conversationId, requestId;

  if (typeof idObj === 'object' && idObj !== null) {
    conversationId = idObj.conversationId || 'unknown';
    requestId      = idObj.requestId      || uuidv4();
  } else {
    // Legacy: bare string → treat as conversationId
    conversationId = idObj || 'unknown';
    requestId      = uuidv4();
  }

  return {
    requestId,
    conversationId,
    startTime: Date.now(),
    attempts:  [],
  };
}

/**
 * Record one provider attempt inside the request context.
 */
export function recordAttempt(ctx, { provider, outcome, latencyMs, reason, model, score }) {
  ctx.attempts.push({
    provider,
    outcome,
    latencyMs: latencyMs ?? null,
    reason:    reason    ?? null,
    model:     model     ?? null,
    score:     score     ?? null,
    ts:        Date.now(),
  });
}

// ── Memory event logging ───────────────────────────────────────────────────────

/**
 * Log a memory lifecycle event.
 *
 * @param {object} ctx
 * @param {'EXTRACTED'|'RETRIEVED'|'INJECTED'|'SKIPPED'|'NO_MEMORIES'} event
 * @param {string[]} details  - e.g. ['name=Ananya', 'favorite_language=Rust']
 */
export function logMemoryEvent(ctx, event, details = []) {
  // Update metric counter
  metrics.memoryEvents[event] = (metrics.memoryEvents[event] || 0) + 1;

  const entry = {
    type:           'AQUA_MEMORY',
    ts:             new Date().toISOString(),
    requestId:      ctx.requestId,
    conversationId: ctx.conversationId,
    event,
    count:          details.length,
    details,
  };

  console.log('[MEMORY]', JSON.stringify(entry));
}

// ── Plan event logging (Phase 4) ────────────────────────────────────────────

/**
 * Log an execution-plan event — one per request, right after the
 * Execution Planner runs and before generation starts.
 *
 * @param {object} ctx
 * @param {{ taskType: string, complexity: 'low'|'medium'|'high', multiStep: boolean, mode?: string, steps?: string[] }} plan
 */
export function logPlanEvent(ctx, plan) {
  metrics.planComplexity[plan.complexity] = (metrics.planComplexity[plan.complexity] || 0) + 1;

  const entry = {
    type:           'AQUA_PLAN',
    ts:             new Date().toISOString(),
    requestId:      ctx.requestId,
    conversationId: ctx.conversationId,
    taskType:       plan.taskType,
    complexity:     plan.complexity,
    multiStep:      plan.multiStep,
    reasoningMode:  plan.mode ?? null,
    stepCount:      plan.steps?.length ?? 0,
  };

  console.log('[PLAN]', JSON.stringify(entry));
}

// ── Intelligence pipeline event logging (Internal Intelligence Engine) ─────

/**
 * Log one Internal Intelligence Engine run — Planner/Reasoning Engine/
 * Critic/Synthesizer output for a single request.
 *
 * @param {object} ctx
 * @param {{ plan: object, reasoning: object, critic: object, synthesis: object }} intelligence
 */
export function logIntelligenceEvent(ctx, intelligence) {
  const active = !!intelligence?.plan?.active;
  if (active) metrics.intelligenceActivations++;

  const entry = {
    type:           'AQUA_INTELLIGENCE',
    ts:             new Date().toISOString(),
    requestId:      ctx.requestId,
    conversationId: ctx.conversationId,
    taskType:       intelligence?.plan?.taskType ?? null,
    active,
    strategy:       intelligence?.reasoning?.strategy ?? null,
    pipelineStages: intelligence?.plan?.pipeline?.map(s => s.name) ?? [],
    criticFocus:    intelligence?.critic?.focusRisks ?? [],
  };

  console.log('[INTELLIGENCE]', JSON.stringify(entry));
}

// ── Adaptive Tool Orchestrator event logging (Phase 6) ─────────────────────

/**
 * Log one Adaptive Tool Orchestrator decision — profile, capabilities
 * enabled/skipped, cost/latency estimate, verification decision. Printed in
 * the spec's literal human-readable [ORCHESTRATOR] block (see
 * src/orchestrator/toolOrchestrator.js's formatOrchestratorLog), with a
 * parallel structured entry feeding metrics — same dual approach
 * logPlanEvent/logIntelligenceEvent already use for their console output.
 *
 * Internal-only: this never reaches the client response body. chat.js's
 * JSON response carries a much smaller `orchestration` summary field for
 * its own debugging-API consumers (mirroring its existing `plan`/
 * `intelligence` diagnostic fields) — full capability reasoning text stays
 * server-side, per the spec's "should not appear in user-facing responses".
 *
 * @param {object} ctx
 * @param {object} decision        result of orchestrate()
 * @param {string} formattedBlock  result of formatOrchestratorLog(decision)
 */
export function logOrchestratorEvent(ctx, decision, formattedBlock) {
  metrics.orchestratorProfiles[decision.profile.id] =
    (metrics.orchestratorProfiles[decision.profile.id] || 0) + 1;

  for (const c of decision.enabled) {
    metrics.orchestratorCapabilities.enabled[c.id] = (metrics.orchestratorCapabilities.enabled[c.id] || 0) + 1;
  }
  for (const c of decision.skipped) {
    metrics.orchestratorCapabilities.skipped[c.id] = (metrics.orchestratorCapabilities.skipped[c.id] || 0) + 1;
  }
  if (decision.verification.enabled) metrics.verificationEnabled++;

  console.log(formattedBlock);

  const entry = {
    type:           'AQUA_ORCHESTRATOR',
    ts:             new Date().toISOString(),
    requestId:      ctx.requestId,
    conversationId: ctx.conversationId,
    profile:        decision.profile.id,
    enabledCount:   decision.enabled.length,
    skippedCount:   decision.skipped.length,
    estimatedCost:      decision.estimatedCost,
    estimatedLatency:   decision.estimatedLatency,
    verificationEnabled: decision.verification.enabled,
  };

  console.log('[ORCHESTRATOR_EVENT]', JSON.stringify(entry));
}

// ── Verification event logging (real post-generation verification pass) ────

/**
 * Log one verification pass — whether the agent actually ran, whether the
 * draft passed as-is or was replaced, and which provider produced the
 * verdict. Distinct from logOrchestratorEvent's verificationEnabled count,
 * which only records that verification was WARRANTED — this records what
 * actually happened once src/intelligence/verificationAgent.js ran.
 *
 * @param {object} ctx
 * @param {{ ran: boolean, passed: boolean|null, revised: boolean, provider?: string, latencyMs?: number, error?: string }} result
 */
export function logVerificationEvent(ctx, result) {
  if (!result?.ran) {
    if (result?.error) metrics.verificationFailed++;
    return;
  }

  metrics.verificationRuns++;
  if (result.revised) metrics.verificationRevised++;

  const entry = {
    type:           'AQUA_VERIFICATION',
    ts:             new Date().toISOString(),
    requestId:      ctx.requestId,
    conversationId: ctx.conversationId,
    passed:         result.passed,
    revised:        result.revised,
    provider:       result.provider ?? null,
    latencyMs:      result.latencyMs ?? null,
  };

  console.log('[VERIFICATION]', JSON.stringify(entry));
}

// ── Completion logging ────────────────────────────────────────────────────────

/**
 * Emit structured log line and update metrics at request completion.
 *
 * @param {object} ctx   - from createContext()
 * @param {object} data  - completion fields
 */
export function logCompletion(ctx, {
  taskType,
  classifierConfidence,
  promptModules,
  promptTokens,
  responseLength,
  selectedProvider,
  providerScore,
  validationResult,
  finalLatencyMs,
  completionReason,
  memoriesExtracted = 0,
  memoriesInjected  = 0,
  complexity        = null,  // Phase 4
  reasoningMode     = null,  // Phase 4
  error,
}) {
  const totalMs  = Date.now() - ctx.startTime;
  const chainStr = ctx.attempts
    .map(a => `${a.provider}:${a.outcome}${a.reason ? `(${a.reason})` : ''}`)
    .join(' → ');

  const entry = {
    type:                 'AQUA_REQUEST',
    ts:                   new Date().toISOString(),
    requestId:            ctx.requestId,
    conversationId:       ctx.conversationId,
    taskType,
    classifierConfidence: classifierConfidence ? +classifierConfidence.toFixed(2) : null,
    promptModules:        promptModules ?? [],
    promptTokens:         promptTokens  ?? null,
    responseLength:       responseLength ?? null,
    selectedProvider:     selectedProvider ?? null,
    providerScore:        providerScore != null ? +providerScore.toFixed(1) : null,
    fallbackChain:        chainStr,
    attempts:             ctx.attempts.length,
    totalMs,
    finalLatencyMs:       finalLatencyMs ?? null,
    validationResult:     validationResult ?? null,
    completionReason:     completionReason ?? (error ? 'error' : 'success'),
    memoriesExtracted,
    memoriesInjected,
    complexity,
    reasoningMode,
    error:                error?.message ?? null,
  };

  console.log('[AQUA]', JSON.stringify(entry));

  // ── Push into ring buffer ──────────────────────────────────────────────────
  recentLogs.push(entry);
  if (recentLogs.length > LOG_RING_SIZE) recentLogs.shift();

  // ── Update metrics ─────────────────────────────────────────────────────────
  metrics.totalRequests++;
  if (taskType) {
    ensureTask(taskType);
    metrics.byTask[taskType].requests++;
  }

  if (selectedProvider && !error) {
    metrics.totalSuccesses++;
    if (taskType) metrics.byTask[taskType].successes++;
    ensureProvider(selectedProvider);
    metrics.byProvider[selectedProvider].requests++;
    metrics.byProvider[selectedProvider].successes++;
    metrics.byProvider[selectedProvider].totalLatencyMs += finalLatencyMs || 0;
    pushLatency(totalMs);
  } else {
    metrics.totalFailures++;
    if (taskType) metrics.byTask[taskType].failures++;
    if (selectedProvider) {
      ensureProvider(selectedProvider);
      metrics.byProvider[selectedProvider].failures++;
    }
  }
}

/**
 * Return current metrics snapshot for /metrics or Prometheus scrape.
 */
export function getMetrics() {
  const lats = metrics.latencyWindow;
  const sorted = lats.slice().sort((a, b) => a - b);

  return {
    totalRequests:  metrics.totalRequests,
    totalSuccesses: metrics.totalSuccesses,
    totalFailures:  metrics.totalFailures,
    successRate:    metrics.totalRequests
      ? +(metrics.totalSuccesses / metrics.totalRequests * 100).toFixed(1)
      : null,
    avgLatencyMs:   lats.length
      ? Math.round(lats.reduce((a, b) => a + b, 0) / lats.length)
      : 0,
    p95LatencyMs:   sorted.length
      ? sorted[Math.floor(sorted.length * 0.95)] ?? 0
      : 0,
    memoryEvents:   metrics.memoryEvents,
    planComplexity: metrics.planComplexity,
    intelligenceActivations: metrics.intelligenceActivations,
    orchestratorProfiles:     metrics.orchestratorProfiles,
    orchestratorCapabilities: metrics.orchestratorCapabilities,
    verificationEnabled:      metrics.verificationEnabled,
    verificationRuns:         metrics.verificationRuns,
    verificationRevised:      metrics.verificationRevised,
    verificationFailed:       metrics.verificationFailed,
    byProvider:     Object.fromEntries(
      Object.entries(metrics.byProvider).map(([p, s]) => [p, {
        ...s,
        avgLatencyMs: s.requests ? Math.round(s.totalLatencyMs / s.requests) : 0,
      }])
    ),
    byTask: metrics.byTask,
  };
}

/**
 * Return recent AQUA_REQUEST log entries (newest last).
 * @param {number} [limit=50]
 */
export function getRecentLogs(limit = 50) {
  return recentLogs.slice(-Math.min(limit, LOG_RING_SIZE));
}

/**
 * AQUA Provider Strategy
 *
 * Maps task type → provider order.
 *
 * fast_chat   → Groq first (lowest latency, handles casual conversation well)
 * coding      → Gemini first (best code quality)
 * architecture→ Gemini first (deepest reasoning)
 * research    → Gemini first (breadth + depth)
 * reasoning   → Gemini first (chain-of-thought strength)
 * creative    → Gemini first (creative quality)
 * file/agent  → Gemini first (multimodal + context)
 */

const STRATEGIES = {
  fast_chat:        ['groq',   'gemini', 'openrouter'],
  coding:           ['gemini', 'groq',   'openrouter'],
  architecture:     ['gemini', 'openrouter', 'groq'],
  research:         ['gemini', 'openrouter', 'groq'],
  reasoning:        ['gemini', 'groq',   'openrouter'],
  creative_writing: ['gemini', 'groq',   'openrouter'],
  file_analysis:    ['gemini', 'openrouter', 'groq'],
  agent_task:       ['gemini', 'openrouter', 'groq'],
};

const DEFAULT = ['groq', 'gemini', 'openrouter'];

/**
 * @param {string} taskType
 * @param {'low'|'medium'|'high'} [complexity] - Phase 4: from executionPlanner.js
 * @returns {string[]} ranked provider order
 */
export function getProviderStrategy(taskType, complexity) {
  const order = STRATEGIES[taskType] ?? DEFAULT;

  // Phase 4: high-complexity plans always lead with the strongest reasoner,
  // even for task types not normally weighted toward Gemini.
  if (complexity === 'high' && order[0] !== 'gemini' && order.includes('gemini')) {
    return ['gemini', ...order.filter(p => p !== 'gemini')];
  }

  return order;
}

/**
 * AQUA Health Monitor v3 — Circuit Breaker
 *
 * Circuit breaker states:
 *   CLOSED    — normal operation, all requests pass through
 *   OPEN      — provider down, requests rejected immediately (no network call)
 *   HALF_OPEN — trial state after cooldown expires: ONE probe request allowed
 *               success → CLOSED   (reset consecutiveFailures, shrink cooldownCount)
 *               failure → OPEN     (longer backoff, back to waiting)
 *
 * Why this matters:
 *   Without HALF_OPEN, providers stay OPEN until manually reset.
 *   HALF_OPEN lets the system automatically rediscover working providers
 *   without risking a flood of requests during recovery.
 *
 * Health score (0–100) drives provider ranking in router.
 * Score = (successRate × 60) + 40 - latencyPenalty - failurePenalty
 */

const START_MS     = Date.now();   // server boot timestamp

const WINDOW       = 20;          // rolling window for success/latency stats
const COOLDOWN_MS  = 60_000;      // base cooldown: 1 min
const COOLDOWN_MAX = 600_000;     // cap: 10 min
const FAIL_THRESH  = 3;           // consecutive failures before OPEN

// Circuit breaker state constants
const CB_CLOSED    = 'closed';
const CB_OPEN      = 'open';
const CB_HALF_OPEN = 'half_open';

function fresh() {
  return {
    outcomes:            [],      // bool[] rolling window
    latencies:           [],      // ms[] rolling window
    consecutiveFailures: 0,
    cooldownUntil:       0,
    cooldownCount:       0,
    totalRequests:       0,
    totalSuccesses:      0,
    totalFailures:       0,
    lastSuccess:         0,
    lastFailure:         0,
    // Circuit breaker
    circuitState:        CB_CLOSED,
    halfOpenProbe:       false,   // true while a probe request is in-flight
  };
}

const state = {
  gemini:     fresh(),
  groq:       fresh(),
  openrouter: fresh(),
};

// ── Internal helpers ──────────────────────────────────────────────────────────

function successRate(s) {
  if (!s.outcomes.length) return 0.75; // optimistic default (no data yet)
  return s.outcomes.filter(Boolean).length / s.outcomes.length;
}

function avgLatencyMs(s) {
  if (!s.latencies.length) return 600;
  return s.latencies.reduce((a, b) => a + b, 0) / s.latencies.length;
}

function computeScore(s) {
  if (s.circuitState === CB_OPEN) return 0;

  const srPart      = successRate(s) * 60;          // 0–60
  const latPenalty  = Math.min(avgLatencyMs(s) / 200, 20); // 0–20
  const failPenalty = Math.min(s.consecutiveFailures * 10, 30); // 0–30

  return Math.max(0, Math.min(100, srPart + 40 - latPenalty - failPenalty));
}

function push(arr, val) {
  arr.push(val);
  if (arr.length > WINDOW) arr.shift();
}

// ── Circuit breaker transitions ───────────────────────────────────────────────

function transitionToOpen(s, provider, reason) {
  const ms = Math.min(COOLDOWN_MS * 2 ** s.cooldownCount, COOLDOWN_MAX);
  s.cooldownUntil = Date.now() + ms;
  s.cooldownCount++;
  s.circuitState  = CB_OPEN;
  s.halfOpenProbe = false;
  console.log(`[CB] ${provider} → OPEN | backoff=${(ms/1000).toFixed(0)}s | reason=${reason}`);
}

function transitionToClosed(s, provider) {
  s.circuitState        = CB_CLOSED;
  s.consecutiveFailures = 0;
  s.halfOpenProbe       = false;
  s.cooldownCount       = Math.max(0, s.cooldownCount - 1);
  console.log(`[CB] ${provider} → CLOSED (probe succeeded)`);
}

function transitionToHalfOpen(s, provider) {
  s.circuitState  = CB_HALF_OPEN;
  s.halfOpenProbe = false;
  console.log(`[CB] ${provider} → HALF_OPEN (cooldown expired, probing)`);
}

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Returns true if a request should be sent to this provider.
 * Manages HALF_OPEN probe slot — only one probe in-flight at a time.
 */
export function isProviderHealthy(provider) {
  const s = state[provider];
  if (!s) return false;

  const now = Date.now();

  switch (s.circuitState) {
    case CB_CLOSED:
      return true;

    case CB_OPEN:
      if (now >= s.cooldownUntil) {
        transitionToHalfOpen(s, provider);
        s.halfOpenProbe = true;
        return true;   // allow the one probe
      }
      return false;    // still open

    case CB_HALF_OPEN:
      if (!s.halfOpenProbe) {
        // Probe slot free — allow one more attempt
        s.halfOpenProbe = true;
        return true;
      }
      return false;    // probe already in-flight

    default:
      return false;
  }
}

/**
 * Composite health score 0–100. Used by router for ranking.
 * Returns 0 if OPEN (forces skip).
 */
export function getHealthScore(provider) {
  const s = state[provider];
  return s ? computeScore(s) : 0;
}

/**
 * Raw state snapshot for router's latency-aware scoring.
 */
export function getProviderState(provider) {
  const s = state[provider];
  if (!s) return null;
  return {
    score:               computeScore(s),
    circuitState:        s.circuitState,
    successRate:         successRate(s),
    avgLatencyMs:        avgLatencyMs(s),
    consecutiveFailures: s.consecutiveFailures,
    onCooldown:          s.circuitState === CB_OPEN,
    totalRequests:       s.totalRequests,
  };
}

export function markSuccess(provider, latencyMs) {
  const s = state[provider];
  if (!s) return;

  push(s.outcomes, true);
  if (latencyMs != null) push(s.latencies, latencyMs);
  s.totalRequests++;
  s.totalSuccesses++;
  s.lastSuccess = Date.now();

  if (s.circuitState === CB_HALF_OPEN) {
    transitionToClosed(s, provider);
  } else {
    s.consecutiveFailures = 0;
  }

  console.log(`[HEALTH] ${provider} ✓ ${latencyMs ?? '?'}ms | score=${computeScore(s).toFixed(0)} | cb=${s.circuitState}`);
}

export function markFailure(provider, reason = 'unknown') {
  const s = state[provider];
  if (!s) return;

  push(s.outcomes, false);
  s.consecutiveFailures++;
  s.totalRequests++;
  s.totalFailures++;
  s.lastFailure = Date.now();

  switch (s.circuitState) {
    case CB_HALF_OPEN:
      // Probe failed → back to OPEN with longer backoff
      s.halfOpenProbe = false;
      transitionToOpen(s, provider, `probe_failed:${reason}`);
      break;

    case CB_CLOSED:
      if (s.consecutiveFailures >= FAIL_THRESH) {
        transitionToOpen(s, provider, reason);
      } else {
        console.log(`[HEALTH] ${provider} ✗ ${s.consecutiveFailures}/${FAIL_THRESH} | reason=${reason}`);
      }
      break;

    case CB_OPEN:
      // Already open — just increment
      break;
  }
}

/**
 * Test-only: resets all in-memory health/circuit-breaker state back to
 * fresh. No production code path calls this — it exists purely so test
 * suites can exercise circuit-breaker transitions from a known-clean state
 * instead of depending on test execution order across a shared singleton.
 */
export function __resetForTests() {
  state.gemini     = fresh();
  state.groq       = fresh();
  state.openrouter = fresh();
}

export function getUptime() {
  const uptimeMs = Date.now() - START_MS;
  const s = Math.floor(uptimeMs / 1000);
  return {
    startedAt:  new Date(START_MS).toISOString(),
    uptimeMs,
    uptimeHuman: `${Math.floor(s / 3600)}h ${Math.floor((s % 3600) / 60)}m ${s % 60}s`,
  };
}

export function getHealthReport() {
  const now = Date.now();
  const out = {};
  for (const [name, s] of Object.entries(state)) {
    out[name] = {
      circuitState:        s.circuitState,
      score:               computeScore(s).toFixed(1),
      successRate:         (successRate(s) * 100).toFixed(1) + '%',
      avgLatencyMs:        avgLatencyMs(s).toFixed(0) + 'ms',
      consecutiveFailures: s.consecutiveFailures,
      cooldownRemainingS:  s.cooldownUntil > now
        ? +((s.cooldownUntil - now) / 1000).toFixed(0)
        : null,
      totalRequests:       s.totalRequests,
      totalSuccesses:      s.totalSuccesses,
      totalFailures:       s.totalFailures,
    };
  }
  return out;
}

export function estimateTokens(text) {
  return Math.ceil(text.length / 4);
}

export function buildContextWindow(
  history,
  maxTokens = 12000
) {
  const selected = [];
  let used = 0;

  for (let i = history.length - 1; i >= 0; i--) {
    const msg = history[i];
    const tokens =
      estimateTokens(msg.content);

    if (used + tokens > maxTokens)
      break;

    selected.unshift(msg);
    used += tokens;
  }

  return selected;
}

/**
 * AQUA Context Optimizer (Phase 4)
 *
 * Two jobs, both additive to the existing tokenManager.js flow:
 *
 *   1. computeContextBudget() — shrink the history token budget for
 *      higher-complexity requests, since those carry a longer system
 *      prompt (reasoning directive + task module) and need more headroom
 *      left over for the response itself.
 *
 *   2. optimizeContext() — light, lossless cleanup pass on an already
 *      -selected message window: drops empty turns and collapses exact
 *      consecutive duplicates. Never reorders or rewrites content.
 */

import { estimateTokens } from './tokenManager.js';

const BUDGET_MULTIPLIERS = { low: 1.0, medium: 0.92, high: 0.82 };
const MIN_BUDGET = 4_000;

/**
 * @param {'low'|'medium'|'high'} complexity
 * @param {number} [baseMax] - default history budget (matches tokenManager default)
 * @returns {number} adjusted token budget for buildContextWindow()
 */
export function computeContextBudget(complexity, baseMax = 12_000) {
  const mul = BUDGET_MULTIPLIERS[complexity] ?? 1.0;
  return Math.max(MIN_BUDGET, Math.round(baseMax * mul));
}

/**
 * @param {Array<{role: string, content: string}>} messages
 * @returns {{ messages: Array, stats: { kept: number, dropped: number, tokensBefore: number, tokensAfter: number } }}
 */
export function optimizeContext(messages) {
  const tokensBefore = messages.reduce((s, m) => s + estimateTokens(m?.content ?? ''), 0);
  const cleaned = [];

  for (const m of messages) {
    if (!m?.content || !m.content.trim()) continue;
    const prev = cleaned[cleaned.length - 1];
    if (prev && prev.role === m.role && prev.content === m.content) continue; // exact dupe
    cleaned.push(m);
  }

  const tokensAfter = cleaned.reduce((s, m) => s + estimateTokens(m.content ?? ''), 0);

  return {
    messages: cleaned,
    stats: {
      kept: cleaned.length,
      dropped: messages.length - cleaned.length,
      tokensBefore,
      tokensAfter,
    },
  };
}

/**
 * AQUA Timeout Manager
 *
 * ROOT FIX for Gemini cascade:
 * Previous router used TIMEOUT_MS = 8_000 for every provider and every task.
 * Gemini 2.5 Flash (with thinking) needs 20-65s for research/architecture.
 * 8s guaranteed Gemini always timed out → every request fell back to Groq.
 *
 * New behavior:
 * - Per-task base timeout (calibrated to Gemini 2.5 Flash worst-case)
 * - Per-provider multiplier (Groq is 2-3x faster → shorter budget)
 * - Prompt complexity scaling (longer prompt = more generation time)
 */

// Base timeouts in ms — calibrated so Gemini 2.5 Flash succeeds on first try
const BASE_TIMEOUTS = {
  // Instant responses
  conversation:      8_000,
  fast_chat:         8_000,
  memory:            8_000,
  personal_info:     8_000,

  // Short answers
  simple_qa:        10_000,
  opinion:          12_000,

  // Medium work
  brainstorming:    20_000,
  summarization:    25_000,
  creative_writing: 25_000,

  // Deep work (Gemini thinking enabled)
  debugging:        30_000,
  coding:           35_000,
  reasoning:        35_000,
  analysis:         40_000,
  planning:         42_000,

  // Heavy deep work — Gemini needs the runway
  file_analysis:    45_000,
  agent_task:       45_000,
  research:         55_000,
  architecture:     65_000,
};

const DEFAULT_TIMEOUT = 20_000;

/**
 * Provider multipliers.
 * Budgets are sized for Gemini. Groq completes same tasks 2-3x faster.
 * Giving Groq 65s for a fast_chat is wasteful and slows fallback on real failures.
 */
const PROVIDER_MULTIPLIERS = {
  gemini:     1.00,   // reference — budgets sized for Gemini
  groq:       0.35,   // very fast inference; keep budget tight
  openrouter: 0.65,   // varies; deepseek-v3 can be slow on complex prompts
};

/**
 * Prompt complexity multiplier.
 * Longer prompts → more context to process → longer generation.
 */
function complexityMultiplier(promptLength) {
  if (promptLength > 8_000) return 1.7;
  if (promptLength > 4_000) return 1.4;
  if (promptLength > 2_000) return 1.2;
  if (promptLength > 800)   return 1.1;
  return 1.0;
}

/**
 * Phase 4 complexity multiplier.
 * High-complexity plans (reflective reasoning, multi-step) get extra runway.
 * Default 'low' → multiplier 1.0 → identical output to pre-Phase-4 callers.
 */
const PLAN_COMPLEXITY_MULTIPLIERS = { low: 1.0, medium: 1.15, high: 1.35 };

/**
 * Compute timeout for a specific provider + task + prompt size combination.
 *
 * @param {string} taskType     - output of classifier
 * @param {string} provider     - 'gemini' | 'groq' | 'openrouter'
 * @param {number} promptLength - total char count of systemPrompt + all messages
 * @param {'low'|'medium'|'high'} [complexity] - Phase 4: from executionPlanner.js, defaults to 'low' (no-op)
 * @returns {number} timeout in ms
 */
export function getTimeout(taskType, provider = 'gemini', promptLength = 0, complexity = 'low') {
  const base     = BASE_TIMEOUTS[taskType] ?? DEFAULT_TIMEOUT;
  const provMul  = PROVIDER_MULTIPLIERS[provider] ?? 1.0;
  const compMul  = complexityMultiplier(promptLength);
  const planMul  = PLAN_COMPLEXITY_MULTIPLIERS[complexity] ?? 1.0;
  const result   = Math.round(base * provMul * compMul * planMul);

  // Hard floors: never give less than 5s (any provider) or 15s (Gemini complex tasks)
  const floor    = provider === 'gemini' && base > 20_000 ? 15_000 : 5_000;
  return Math.max(result, floor);
}

export { BASE_TIMEOUTS };

/**
 * AQUA Execution Planner (Phase 4)
 *
 * Sits right after classification. Decides:
 *   - complexity tier (low / medium / high) for this request
 *   - whether the task needs multi-step handling
 *   - a descriptive step breakdown (used for prompting/logging — this module
 *     does NOT itself make additional LLM calls or branch the pipeline)
 *
 * Downstream consumers:
 *   - reasoningStrategy.js  → picks prompting mode from complexity
 *   - contextOptimizer.js   → sizes the context budget from complexity
 *   - strategy.js / timeoutManager.js → bias provider order / timeout from complexity
 */

import { getEffectiveComplexity } from './classifier.js';

// Descriptive step templates for high-complexity task types.
// Purely informational — injected into logs / available to prompting later.
const STEP_TEMPLATES = {
  architecture: ['Clarify requirements & constraints', 'Outline component breakdown', 'Address scaling/failure modes', 'Assemble final design'],
  research:     ['Identify sub-questions', 'Gather relevant angles', 'Compare/contrast findings', 'Synthesize conclusion'],
  planning:     ['Define goal & success criteria', 'Break into phases/milestones', 'Sequence and prioritize', 'Flag risks/dependencies'],
  agent_task:   ['Identify required sub-tasks', 'Determine tool/context needs', 'Sequence execution', 'Compose final result'],
  analysis:     ['Identify what is being evaluated', 'Apply relevant criteria', 'Surface implications', 'Summarize findings'],
};

const DEFAULT_STEPS = ['Clarify scope', 'Work the problem', 'Check the result', 'Compose final answer'];

/**
 * Build an execution plan for a classified request.
 *
 * @param {string} taskType    - output of classifyTask()
 * @param {number} [confidence] - classifier confidence (0-1)
 * @returns {{ taskType: string, complexity: 'low'|'medium'|'high', multiStep: boolean, confidence: number, steps: string[] }}
 */
export function createExecutionPlan(taskType, confidence = 1.0) {
  // v2 (Phase 6): escalation rule extracted to classifier.js's
  // getEffectiveComplexity() — shared with the Adaptive Tool Orchestrator,
  // see that function's docstring. Resulting complexity value is identical
  // to the inline version this replaces.
  const complexity = getEffectiveComplexity(taskType, confidence);

  const multiStep = complexity === 'high';
  const steps = multiStep ? (STEP_TEMPLATES[taskType] ?? DEFAULT_STEPS) : [];

  return { taskType, complexity, multiStep, confidence, steps };
}

import { test, describe } from 'node:test';
import assert from 'node:assert/strict';
import {
  isProviderHealthy, markSuccess, markFailure, getHealthScore,
  getProviderState, getHealthReport, __resetForTests,
} from '../health.js';

// These tests exist because Issues 1/7/8/9 all hinge on one contract:
// router.js now calls markSuccess() — never markFailure() — when a
// provider's response was truncated by hitting the output-token budget.
// That's only a correct fix if markSuccess() genuinely never degrades
// health or trips the circuit breaker, no matter how many times it's
// called, and if markFailure() only opens the circuit for real,
// consecutive failures. This file pins that contract directly against
// health.js, independent of the provider-layer wiring.

describe('health.js — circuit breaker contract (Issues 1, 7, 8, 9)', () => {
  test('a fresh provider starts healthy, closed, with a positive score', () => {
    __resetForTests();
    assert.equal(isProviderHealthy('gemini'), true);
    assert.equal(getProviderState('gemini').circuitState, 'closed');
    assert.ok(getHealthScore('gemini') > 0);
  });

  test('markSuccess never opens the circuit no matter how many times it is called', () => {
    __resetForTests();
    for (let i = 0; i < 50; i++) markSuccess('gemini', 500);
    const s = getProviderState('gemini');
    assert.equal(s.circuitState, 'closed');
    assert.equal(s.consecutiveFailures, 0);
    assert.equal(isProviderHealthy('gemini'), true);
  });

  test('Issue 1/7: 100 consecutive truncated-but-successful completions (markSuccess) keep the provider closed and highly scored — this is the exact call router.js now makes for finishReason=length instead of markFailure', () => {
    __resetForTests();
    for (let i = 0; i < 100; i++) markSuccess('groq', 800);
    assert.equal(getProviderState('groq').circuitState, 'closed');
    assert.ok(getHealthScore('groq') > 50);
  });

  test('fewer than the failure threshold (3) keeps the circuit closed', () => {
    __resetForTests();
    markFailure('gemini', 'timeout');
    markFailure('gemini', 'timeout');
    assert.equal(getProviderState('gemini').circuitState, 'closed');
    assert.equal(isProviderHealthy('gemini'), true);
  });

  test('3 consecutive genuine failures opens the circuit and drops score to 0', () => {
    __resetForTests();
    markFailure('gemini', 'timeout');
    markFailure('gemini', 'network error');
    markFailure('gemini', 'server error');
    assert.equal(getProviderState('gemini').circuitState, 'open');
    assert.equal(isProviderHealthy('gemini'), false);
    assert.equal(getHealthScore('gemini'), 0);
  });

  test('a success in between resets the consecutive-failure count, so the circuit never opens', () => {
    __resetForTests();
    markFailure('groq', 'timeout');
    markFailure('groq', 'timeout');
    markSuccess('groq', 400); // e.g. a truncated-but-successful completion
    markFailure('groq', 'timeout');
    markFailure('groq', 'timeout');
    // Only 2 consecutive failures since the intervening success.
    assert.equal(getProviderState('groq').circuitState, 'closed');
    assert.equal(isProviderHealthy('groq'), true);
  });

  test('half-open: after cooldown expires exactly one probe is allowed; success closes the circuit', (t) => {
    __resetForTests();
    t.mock.timers.enable({ apis: ['Date'] });

    markFailure('openrouter', 'x');
    markFailure('openrouter', 'x');
    markFailure('openrouter', 'x');
    assert.equal(getProviderState('openrouter').circuitState, 'open');
    assert.equal(isProviderHealthy('openrouter'), false);

    t.mock.timers.tick(61_000); // past the 60s base cooldown

    assert.equal(isProviderHealthy('openrouter'), true, 'the single probe should be allowed');
    assert.equal(getProviderState('openrouter').circuitState, 'half_open');
    assert.equal(isProviderHealthy('openrouter'), false, 'no second probe while one is in flight');

    markSuccess('openrouter', 300);
    assert.equal(getProviderState('openrouter').circuitState, 'closed');
    assert.equal(getProviderState('openrouter').consecutiveFailures, 0);
  });

  test('half-open: a failed probe reopens the circuit', (t) => {
    __resetForTests();
    t.mock.timers.enable({ apis: ['Date'] });

    markFailure('openrouter', 'x');
    markFailure('openrouter', 'x');
    markFailure('openrouter', 'x');
    t.mock.timers.tick(61_000);
    isProviderHealthy('openrouter'); // consumes the probe slot → half_open
    markFailure('openrouter', 'probe failed');

    assert.equal(getProviderState('openrouter').circuitState, 'open');
  });

  test('getHealthReport returns every provider with well-formed fields', () => {
    __resetForTests();
    const report = getHealthReport();
    for (const p of ['gemini', 'groq', 'openrouter']) {
      assert.ok(p in report);
      assert.equal(typeof report[p].circuitState, 'string');
      assert.equal(typeof report[p].score, 'string');
      assert.equal(typeof report[p].totalRequests, 'number');
    }
  });

  test('unknown provider name is handled gracefully, never throws', () => {
    __resetForTests();
    assert.equal(isProviderHealthy('not_a_real_provider'), false);
    assert.equal(getHealthScore('not_a_real_provider'), 0);
    assert.doesNotThrow(() => markSuccess('not_a_real_provider', 100));
    assert.doesNotThrow(() => markFailure('not_a_real_provider', 'x'));
  });
});

