/**
 * AQUA Reasoning Strategy (Phase 4)
 *
 * Translates an execution plan's complexity tier into a concrete prompting
 * mode + directive string. The directive is injected into the system prompt
 * by promptBuilder.js — this module makes the decision, it doesn't touch
 * the prompt itself.
 *
 *   low    → direct     (no directive — current v3 behavior, untouched)
 *   medium → stepwise    (ask for visible step-by-step reasoning)
 *   high   → reflective  (ask for draft → self-check → refined answer)
 */

const DIRECTIVES = {
  stepwise:   'Work through this step-by-step before giving your final answer. Show the key reasoning, not just the conclusion.',
  reflective: 'Draft your initial approach, briefly check it for gaps or errors, then give a refined final answer. Keep the check concise.',
};

/**
 * @param {string} taskType
 * @param {'low'|'medium'|'high'} complexity - from createExecutionPlan()
 * @returns {{ mode: 'direct'|'stepwise'|'reflective', directive: string }}
 */
export function getReasoningStrategy(taskType, complexity) {
  if (complexity === 'high')   return { mode: 'reflective', directive: DIRECTIVES.reflective };
  if (complexity === 'medium') return { mode: 'stepwise',   directive: DIRECTIVES.stepwise };
  return { mode: 'direct', directive: '' };
}

/**
 * AQUA Prompt Builder v3
 *
 * Changes from v2:
 *   - buildSystemPrompt(taskType, memoryBlock) — accepts memory injection string
 *   - Memory block inserted between identity and task module
 *     (after "who I am", before "how to handle this task")
 *   - Module list includes 'memory' when facts are present
 */

import fs   from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { buildIdentityInjection } from '../identity/index.js';

const __dir     = path.dirname(fileURLToPath(import.meta.url));
const promptDir = path.join(__dir, '..', 'prompts');

function load(name) {
  try {
    return fs.readFileSync(path.join(promptDir, name), 'utf8').trim() || '';
  } catch {
    return '';
  }
}

// Load all task modules once at startup
const M = {
  system:       load('system.txt'),
  coding:       load('coding.txt'),
  architecture: load('architecture.txt'),
  research:     load('research.txt'),
  reasoning:    load('reasoning.txt'),
  creative:     load('creative.txt'),
  planning:     load('planning.txt'),
  project:      load('project.txt'),
};

/**
 * task → which extra modules to inject.
 * 'memory' is handled separately (dynamic, not a file).
 */
const MODULE_MAP = {
  // Minimal — identity only
  conversation:          [],
  memory_recall:         [],   // memory injected dynamically
  memory_update:         [],
  personal_info:         [],
  simple_qa:             [],
  opinion:               [],
  summarization:         [],

  // Task-specific
  coding:                ['coding'],
  debugging:             ['coding'],
  architecture:          ['architecture'],
  research:              ['research'],
  reasoning:             ['reasoning'],
  creative_writing:      ['creative'],
  planning:              ['planning'],
  analysis:              ['research'],
  brainstorming:         ['creative'],
  file_analysis:         ['research'],
  agent_task:            ['research'],
  project_query:         ['project', 'research'],
};

/**
 * Build the minimal correct system prompt for a task type.
 * Injects memory block, then reasoning directive, then optional project context.
 *
 * @param {string} taskType    - from classifyTask()
 * @param {string} [memoryBlock] - formatted facts from memoryRetriever
 * @param {string} [reasoningDirective] - Phase 4: from reasoningStrategy.js
 * @param {string} [projectContext] - Phase 5: from projectRetriever.js ('' if no workspace)
 * @param {string} [intelligenceBlock] - Internal Intelligence Engine: synthesized plan/reasoning/critic brief ('' if low-complexity / skipped)
 * @param {{isSelf:boolean, topics:string[]}|null} [identityIntent] - from identityRouter.detectIdentityIntent(); when it flags a self/brand question the FULL identity section + confidence directive are injected. When null/absent, only the compact always-on identity block is injected.
 * @returns {{ prompt: string, modules: string[] }}
 */
export function buildSystemPrompt(taskType, memoryBlock = '', reasoningDirective = '', projectContext = '', intelligenceBlock = '', identityIntent = null) {
  const modules     = MODULE_MAP[taskType] ?? [];
  const parts       = [M.system];
  const moduleNames = ['system'];

  // Identity & Self-Knowledge Layer — injected on EVERY request (compact),
  // expanded to the full profile + confidence directive when the Smart Router
  // flags a question about AQUA/Aquiplex. This is what makes AQUA always know
  // itself without retrieval; it sits right after the base system prompt and
  // before memory so brand identity is the most foundational context present.
  const identityBlock = buildIdentityInjection(identityIntent);
  if (identityBlock && identityBlock.trim()) {
    parts.push(identityBlock.trim());
    moduleNames.push(identityIntent?.isSelf ? 'identity+' : 'identity');
  }

  // Inject memory block right after identity — before task instructions
  if (memoryBlock && memoryBlock.trim()) {
    parts.push(memoryBlock);
    moduleNames.push('memory');
  }

  // Phase 4: reasoning directive (stepwise/reflective) — after memory, before task module
  if (reasoningDirective && reasoningDirective.trim()) {
    parts.push(reasoningDirective.trim());
    moduleNames.push('reasoning');
  }

  // Internal Intelligence Engine: synthesized plan/reasoning/critic brief —
  // after the simple reasoning directive, before project context.
  if (intelligenceBlock && intelligenceBlock.trim()) {
    parts.push(intelligenceBlock.trim());
    moduleNames.push('intelligence');
  }

  // Phase 5: project context — injected after reasoning directive
  if (projectContext && projectContext.trim()) {
    parts.push(projectContext.trim());
    moduleNames.push('project_context');
  }

  for (const mod of modules) {
    const content = M[mod];
    if (content) {
      parts.push('---\n\n' + content);
      moduleNames.push(mod);
    }
  }

  return {
    prompt:  parts.join('\n\n'),
    modules: moduleNames,
  };
}

/** Hot-reload prompts in dev without restart */
export function reloadPrompts() {
  for (const key of Object.keys(M)) {
    const file    = key === 'system' ? 'system.txt' : `${key}.txt`;
    const content = load(file);
    if (content) M[key] = content;
  }
  console.log('[PROMPTS] Reloaded all modules');
}

/**
 * AQUA Response Validator v2 — Intent-Aware
 *
 * ROOT FIX: previous validator had MIN_LENGTH = 5.
 * User: "Reply with only the single letter A"
 * Model: "A"
 * Old validator: REJECTED (too_short)
 * New validator: ACCEPTED (brevity intent detected)
 *
 * New rules:
 * 1. Detect brevity intent in userMessage FIRST
 * 2. If brevity requested → skip all length checks (single chars are valid)
 * 3. Otherwise use task-aware minimum lengths (not a flat MIN_LENGTH)
 * 4. Still reject: empty, error strings, safety refusals, truncated heavy responses
 */

// ── Brevity intent — user explicitly asked for short output ───────────────────

const BREVITY_PATTERNS = [
  /\breply\s+(with\s+)?(only|just)\b/i,
  /\bonly\s+(reply|respond|output|return|say|answer|write)\b/i,
  /\bone\s+(word|letter|character|sentence|line)\b/i,
  /\byes\s+or\s+no\b/i,
  /\boutput\s+(only|just)\b/i,
  /\breturn\s+(only|just)\b/i,
  /\bsingle\s+(word|letter|digit|char|sentence|number)\b/i,
  /\bjust\s+(say|output|return|respond|write|answer|give\s+me)\b/i,
  /\bshort(est)?\s+possible\b/i,
  /\bin\s+one\s+(word|sentence|line|paragraph)\b/i,
  /\bbriefly\b/i,
  /\bin\s+a\s+word\b/i,
  /\bshort answer\b/i,
  /\bjust\s+the\s+(answer|result|value|number|letter)\b/i,
];

// ── Provider / system error strings — always reject ───────────────────────────

const ERROR_PATTERNS = [
  /^(null|undefined|false)$/i,
  /^error:/i,
  /^(api error|service error|provider error)/i,
  /^(gemini|groq|openrouter|deepseek|llama)\s+(error|api)\b/i,
  /^(500|502|503|504)[\s:]/,
];

// ── Safety refusals — reject, trigger fallback ────────────────────────────────
// (Another provider may answer the same question without refusing)

const SAFETY_PATTERNS = [
  /^I('m| am) not able to help with that/i,
  /^I cannot (assist|help) with that/i,
  /violates?\s+(my\s+)?(safety|content)\s+(guidelines?|polic(y|ies))/i,
  /against\s+(my\s+)?(terms|guidelines|policies)\b/i,
  /^I('m| am) sorry.*I (can't|cannot|won't|will not) (help|assist|provide)/i,
];

// ── Truncation signals — only checked for long-form tasks ─────────────────────

const TRUNCATION_PATTERNS = [
  /\.\.\.\s*$/,
  /\[continued\]/i,
  /\[truncated\]/i,
  /\bto\s+be\s+continued\b/i,
];

// ── Task-aware minimum lengths ────────────────────────────────────────────────

const TASK_MIN_LENGTH = {
  conversation:     1,
  memory:           1,
  personal_info:    1,
  simple_qa:        1,   // "Paris" is a valid answer to a capital question
  opinion:          5,
  brainstorming:    15,
  summarization:    10,
  debugging:        15,
  coding:           10,
  reasoning:        5,
  analysis:         15,
  planning:         15,
  research:         30,
  architecture:     50,
  creative_writing: 10,
  file_analysis:    10,
};

const DEFAULT_MIN_LENGTH = 5;

// ── Exports ───────────────────────────────────────────────────────────────────

/**
 * Validate model response with intent awareness.
 *
 * @param {string} text        - model output
 * @param {string} userMessage - original user message (intent detection)
 * @param {string} taskType    - from classifier
 * @returns {{ valid: boolean, reason: string }}
 */
export function validateResponse(text, userMessage = '', taskType = '') {
  // ── Empty ──────────────────────────────────────────────────────────────────
  if (!text || typeof text !== 'string')
    return { valid: false, reason: 'empty_response' };

  const t = text.trim();
  if (!t.length)
    return { valid: false, reason: 'empty_response' };

  // ── Safety refusals (reject before brevity check) ─────────────────────────
  for (const p of SAFETY_PATTERNS) {
    if (p.test(t)) return { valid: false, reason: 'safety_refusal' };
  }

  // ── Provider error strings ─────────────────────────────────────────────────
  for (const p of ERROR_PATTERNS) {
    if (p.test(t)) return { valid: false, reason: 'provider_error_string' };
  }

  // ── Brevity intent — bypass all length checks ──────────────────────────────
  const brevityRequested = BREVITY_PATTERNS.some(p => p.test(userMessage));
  if (brevityRequested) {
    return { valid: true, reason: 'brevity_intent_matched' };
  }

  // ── Task-aware minimum length ──────────────────────────────────────────────
  const minLen = TASK_MIN_LENGTH[taskType] ?? DEFAULT_MIN_LENGTH;
  if (t.length < minLen) {
    return { valid: false, reason: `too_short_for_${taskType || 'unknown'}` };
  }

  // ── Truncation check (only for heavy long-form tasks) ─────────────────────
  const heavyTasks = ['research', 'architecture', 'coding', 'analysis', 'planning', 'debugging'];
  if (heavyTasks.includes(taskType)) {
    for (const p of TRUNCATION_PATTERNS) {
      if (p.test(t)) return { valid: false, reason: 'truncated_response' };
    }
  }

  return { valid: true };
}

/**
 * AQUA Memory Inspector Route (UNIFIED)
 * ─────────────────────────────────────────────────────────────────────────────
 * Owner-scoped: memories belong to the resolved owner (user session first,
 * conversation fallback) — never permanently to a conversationId.
 *
 *   GET    /memory                          — all facts for the caller's owner
 *   GET    /memory/inspector/:requestId     — full decision trace for one chat
 *                                             turn (Req 14: explainable memory)
 *   GET    /memory/fact/:key                — single fact + revision history
 *   DELETE /memory/fact/:key                — delete a fact
 *   DELETE /memory                          — clear the caller's facts
 *
 * Back-compat (old conversation-keyed API — resolves that conversation's
 * OWNER first, then serves owner-scoped data):
 *   GET    /memory/:conversationId
 *   GET    /memory/:conversationId/:key
 *   DELETE /memory/:conversationId[/:key]
 */
import express from 'express';
import {
  getFacts, getFact, deleteFact, clearFacts, getFactHistory,
} from '../memory/longTermMemory.js';
import { resolveOwner, getMemoryTrace } from '../memory/engine.js';
import { conversationExists, getConversationMeta } from '../memory/conversationStore.js';

const router = express.Router();

function ownerOf(req, conversationId = null) {
  return resolveOwner({
    userId: req.aquaUserId ?? null,
    conversationId: conversationId ?? req.query.conversationId ?? null,
  });
}

/** Old-style routes carried a conversationId — resolve it to its true owner. */
function ownerForLegacyConversation(req, conversationId) {
  const meta = conversationExists(conversationId) ? getConversationMeta(conversationId) : null;
  return resolveOwner({
    userId: req.aquaUserId ?? meta?.userId ?? null,
    conversationId,
  });
}

function factsPayload(ownerId) {
  const facts = getFacts(ownerId);
  return { success: true, ownerId, factCount: facts.length, facts };
}

// ── Memory Inspector: explainable per-turn trace (Req 14) ────────────────────
router.get('/inspector/:requestId', (req, res) => {
  const trace = getMemoryTrace(req.params.requestId);
  if (!trace) {
    return res.status(404).json({ success: false, error: 'No trace for that requestId (ring keeps the last 100 turns)' });
  }
  res.json({ success: true, requestId: req.params.requestId, trace });
});

// ── Owner-scoped API ─────────────────────────────────────────────────────────
router.get('/', (req, res) => {
  const ownerId = ownerOf(req);
  if (!ownerId) return res.status(400).json({ success: false, error: 'No memory owner (no session and no ?conversationId)' });
  res.json(factsPayload(ownerId));
});

router.get('/fact/:key', (req, res) => {
  const ownerId = ownerOf(req);
  if (!ownerId) return res.status(400).json({ success: false, error: 'No memory owner' });
  const fact = getFact(ownerId, req.params.key);
  if (!fact) return res.status(404).json({ success: false, error: `Fact '${req.params.key}' not found` });
  res.json({ success: true, ownerId, key: req.params.key, fact, history: getFactHistory(ownerId, req.params.key) });
});

router.delete('/fact/:key', (req, res) => {
  const ownerId = ownerOf(req);
  if (!ownerId) return res.status(400).json({ success: false, error: 'No memory owner' });
  deleteFact(ownerId, req.params.key);
  res.json({ success: true, ownerId, deleted: req.params.key });
});

router.delete('/', (req, res) => {
  const ownerId = ownerOf(req);
  if (!ownerId) return res.status(400).json({ success: false, error: 'No memory owner' });
  clearFacts(ownerId);
  res.json({ success: true, ownerId, cleared: true });
});

// ── Back-compat: conversation-keyed paths → owner-scoped data ────────────────
router.get('/:conversationId', (req, res) => {
  const ownerId = ownerForLegacyConversation(req, req.params.conversationId);
  res.json({ ...factsPayload(ownerId), conversationId: req.params.conversationId });
});

router.get('/:conversationId/:key', (req, res) => {
  const { conversationId, key } = req.params;
  const ownerId = ownerForLegacyConversation(req, conversationId);
  const fact = getFact(ownerId, key);
  if (!fact) return res.status(404).json({ success: false, error: `Fact '${key}' not found` });
  res.json({ success: true, ownerId, conversationId, key, fact, history: getFactHistory(ownerId, key) });
});

router.delete('/:conversationId/:key', (req, res) => {
  const { conversationId, key } = req.params;
  const ownerId = ownerForLegacyConversation(req, conversationId);
  deleteFact(ownerId, key);
  res.json({ success: true, ownerId, conversationId, deleted: key });
});

router.delete('/:conversationId', (req, res) => {
  const { conversationId } = req.params;
  const ownerId = ownerForLegacyConversation(req, conversationId);
  clearFacts(ownerId);
  res.json({ success: true, ownerId, conversationId, cleared: true });
});

export default router;

/**
 * AQUA Unified Upload — Day 5
 *
 * THE single upload endpoint. Users (and the frontend) never choose between
 * "chat upload" and "project upload" — everything comes here, gets
 * classified, and is routed to the right pipeline automatically.
 *
 *   POST /upload
 *     Body: {
 *       conversationId?: string,   // created if absent — returned either way
 *       files: [{ name: string, content: string }]   // content ALWAYS base64
 *     }
 *
 *   Routing (per file / per batch):
 *     ZIP / TAR / TAR.GZ          → extract → workspace ingestion → workspace card
 *     multi-file source batch     → workspace ingestion (folder drop)
 *     PDF/DOCX/PPTX/XLSX/CSV/ODT/EPUB → document pipeline → conversation attachment
 *     PNG/JPEG/WEBP/GIF/SVG/HEIC  → vision + OCR → conversation attachment
 *     MP3/WAV/M4A                 → transcription + analysis → attachment
 *     MP4/MOV/AVI                 → transcription + analysis → attachment
 *     single source file          → read → conversation attachment
 *     anything else               → explicit per-file error (never silent)
 *
 *   Response: {
 *     success, conversationId, isNewConversation,
 *     results: [{ name, kind, status: 'ready'|'failed', ... }],
 *     workspace?: { id, projectType, filesIngested, summary, overview },
 *     attachments: [ ...metadata of everything now attached to the conversation ]
 *   }
 *
 *   GET    /upload/formats                          — supported format matrix
 *   GET    /upload/attachments/:conversationId      — list attachments
 *   DELETE /upload/attachments/:conversationId/:id  — detach
 */
import express from 'express';
import path from 'path';
import { classifyUpload, SUPPORTED_FORMATS }    from '../upload/uploadClassifier.js';
import { extractArchive }                        from '../upload/archiveExtractor.js';
import { processDocument }                       from '../upload/documentPipeline.js';
import { processMedia }                          from '../upload/mediaPipeline.js';
import {
  attachToConversation, getAttachments, removeAttachment, serializeAttachment,
} from '../upload/attachmentStore.js';
import { getOrCreateConversation }               from '../memory/conversationStore.js';
import { resolveOwner, rememberFile, rememberWorkspace } from '../memory/engine.js';
import { createWorkspace }                       from '../project/workspaceManager.js';
import { runWorkspaceIngestion }                 from '../project/ingestionPipeline.js';
import { detectLanguage as detectSourceLanguage } from '../project/fileIngester.js';

const router = express.Router();

const MAX_FILES_PER_UPLOAD = 30;
const MAX_SOURCE_CHARS     = 100_000; // mirrors fileIngester MAX_FILE_SIZE

// ── POST /upload ──────────────────────────────────────────────────────────────

router.post('/', async (req, res) => {
  const { files, conversationId: requestedConversationId, workspaceName } = req.body ?? {};

  if (!Array.isArray(files) || !files.length) {
    return res.status(400).json({
      success: false,
      error:   'Body must include "files": [{ name, content }] with base64 content.',
    });
  }
  if (files.length > MAX_FILES_PER_UPLOAD) {
    return res.status(400).json({
      success: false,
      error:   `Too many files in one upload (${files.length} > ${MAX_FILES_PER_UPLOAD}). Zip the folder instead — archives ingest as a full workspace.`,
    });
  }

  // Attachments bind to a conversation — create one now if the user uploaded
  // before sending their first message (the common drag-drop-then-type flow).
  const { id: conversationId, isNew: isNewConversation } = getOrCreateConversation(
    requestedConversationId ?? null,
    { userAgent: req.headers['user-agent']?.slice(0, 80), ip: req.ip, createdBy: 'upload',
      userId: req.aquaUserId ?? null },
  );
  // Uploaded files become durable OWNER memory (Req 10) — not just
  // conversation attachments. Same owner model as chat.
  const memoryOwner = resolveOwner({ userId: req.aquaUserId ?? null, conversationId });

  // ── Decode + classify every file up front ──
  const classified = [];
  const results    = [];

  for (const f of files) {
    if (!f?.name || !f?.content) {
      results.push({ name: f?.name ?? '(unnamed)', kind: 'unknown', status: 'failed', error: 'File entry missing name or content' });
      continue;
    }
    let buffer;
    try {
      buffer = Buffer.from(f.content, 'base64');
      if (!buffer.length) throw new Error('empty');
    } catch {
      results.push({ name: f.name, kind: 'unknown', status: 'failed', error: 'Content is not valid base64' });
      continue;
    }
    const cls = classifyUpload(f.name, buffer);
    classified.push({ name: f.name, buffer, cls });
  }

  // ── Batch decision: repository experience ──
  // An archive anywhere in the batch, OR a multi-file batch that is
  // majority source files (a folder drop), becomes a workspace.
  const archives    = classified.filter(c => c.cls.kind === 'repository');
  const sourceFiles = classified.filter(c => c.cls.kind === 'source');
  const isFolderDrop = classified.length > 3 && sourceFiles.length / classified.length >= 0.6;

  let workspacePayload = null;

  if (archives.length > 0 || isFolderDrop) {
    try {
      workspacePayload = await handleRepositoryUpload({ memoryOwner,
        archives,
        sourceFiles: isFolderDrop ? sourceFiles : [],
        workspaceName: workspaceName
          ?? (archives[0]?.name.replace(/\.(zip|tar\.gz|tgz|tar|gz)$/i, '') || 'Uploaded project'),
        results,
      });
    } catch (err) {
      // Whole-repository failure is reported per archive — never silent.
      for (const a of archives) {
        if (!results.some(r => r.name === a.name)) {
          results.push({ name: a.name, kind: 'repository', status: 'failed', error: err.message });
        }
      }
    }
  }

  // Files consumed by the workspace path don't get double-processed.
  const consumed = new Set([
    ...archives.map(a => a.name),
    ...(isFolderDrop ? sourceFiles.map(s => s.name) : []),
  ]);
  const individual = classified.filter(c => !consumed.has(c.name));

  // ── Per-file routing for everything else ──
  for (const item of individual) {
    const { name, buffer, cls } = item;
    try {
      switch (cls.kind) {
        case 'document': {
          if (cls.corrupt) throw new Error('File extension and content disagree — the file appears corrupt.');
          const normalized = await processDocument(name, buffer);
          const attachment = attachToConversation(conversationId, { name, kind: 'document', normalized });
          rememberFile(memoryOwner, { name, kind: 'document', summary: (normalized.title && normalized.title !== name ? normalized.title + ' — ' : '') + normalized.content.slice(0, 240), chars: normalized.content.length, conversationId });
          results.push({ name, kind: 'document', status: 'ready', attachmentId: attachment.id, format: normalized.format, pages: normalized.pages, contentChars: normalized.content.length, truncated: normalized.truncated });
          break;
        }
        case 'image':
        case 'audio':
        case 'video': {
          const normalized = await processMedia(name, buffer, cls.mime, cls.kind);
          const attachment = attachToConversation(conversationId, { name, kind: cls.kind, normalized });
          rememberFile(memoryOwner, { name, kind: cls.kind, summary: (normalized.title && normalized.title !== name ? normalized.title + ' — ' : '') + normalized.content.slice(0, 240), chars: normalized.content.length, conversationId });
          results.push({ name, kind: cls.kind, status: 'ready', attachmentId: attachment.id, format: normalized.format, contentChars: normalized.content.length, analyzed: normalized.metadata.analyzed !== false });
          break;
        }
        case 'source': {
          let content = buffer.toString('utf8');
          let truncated = false;
          if (content.length > MAX_SOURCE_CHARS) { content = content.slice(0, MAX_SOURCE_CHARS) + '\n... [truncated]'; truncated = true; }
          const normalized = {
            title: name, format: detectSourceLanguage(name), metadata: {},
            content, pages: null, sections: [], language: null, truncated,
          };
          const attachment = attachToConversation(conversationId, { name, kind: 'source', normalized });
          rememberFile(memoryOwner, { name, kind: 'source', summary: (normalized.title && normalized.title !== name ? normalized.title + ' — ' : '') + normalized.content.slice(0, 240), chars: normalized.content.length, conversationId });
          results.push({ name, kind: 'source', status: 'ready', attachmentId: attachment.id, format: normalized.format, contentChars: content.length, truncated });
          break;
        }
        case 'repository': {
          // Only reachable if handleRepositoryUpload threw before reaching this archive
          break;
        }
        default: {
          const ext = path.extname(name) || '(no extension)';
          results.push({
            name, kind: 'unknown', status: 'failed',
            error: `Unsupported format ${ext}. Supported: repositories (zip/tar/tar.gz), documents (pdf/docx/pptx/xlsx/csv/odt/epub), images, audio, video, and source/text files.`,
          });
        }
      }
    } catch (err) {
      console.error(`[UPLOAD] Processing failed file=${name}:`, err.message);
      results.push({ name, kind: cls.kind, status: 'failed', error: err.message });
    }
  }

  const anyReady = results.some(r => r.status === 'ready') || !!workspacePayload;

  res.status(anyReady ? 200 : 422).json({
    success: anyReady,
    conversationId,
    isNewConversation,
    results,
    ...(workspacePayload ? { workspace: workspacePayload } : {}),
    attachments: getAttachments(conversationId).map(serializeAttachment),
    ...(anyReady ? {} : { error: 'No file in the upload could be processed — see per-file results.' }),
  });
});

// ── Repository experience: archive/folder → workspace, zero manual steps ──────

async function handleRepositoryUpload({ memoryOwner = null, archives, sourceFiles, workspaceName, results }) {
  // Merge every archive + loose source file into ONE raw file set (mixed
  // uploads: "here's my repo zip and also these two extra files").
  const rawFiles = [];

  for (const a of archives) {
    if (a.cls.corrupt) {
      results.push({ name: a.name, kind: 'repository', status: 'failed', error: 'Archive appears corrupt — its bytes do not match its extension.' });
      continue;
    }
    try {
      const extracted = await extractArchive(a.buffer, a.cls.archiveFormat);
      if (!extracted.length) {
        results.push({ name: a.name, kind: 'repository', status: 'failed', error: 'Archive extracted to zero usable files (only ignored/binary content).' });
        continue;
      }
      rawFiles.push(...extracted);
      results.push({ name: a.name, kind: 'repository', status: 'ready', entriesExtracted: extracted.length });
    } catch (err) {
      results.push({ name: a.name, kind: 'repository', status: 'failed', error: err.message });
    }
  }

  for (const s of sourceFiles) {
    rawFiles.push({ path: s.name, content: s.buffer.toString('utf8') });
    results.push({ name: s.name, kind: 'source', status: 'ready', routedTo: 'workspace' });
  }

  if (!rawFiles.length) {
    throw new Error('No archive in the upload could be extracted.');
  }

  // Create workspace + run the EXACT same pipeline as POST /project/workspace/:id/files
  const workspace = createWorkspace({ name: workspaceName, createdBy: 'unified-upload', ownerId: memoryOwner });
  const ingestion = await runWorkspaceIngestion(workspace.id, rawFiles);
  // Workspace becomes durable owner memory: project node + summary (Req 9/10).
  rememberWorkspace(memoryOwner, { ...workspace, summary: ingestion.summary, stats: { files: ingestion.filesIngested } });

  return {
    id:            workspace.id,
    name:          workspaceName,
    projectType:   ingestion.projectType,
    filesIngested: ingestion.filesIngested,
    indexStats:    ingestion.indexStats,
    summary:       ingestion.summary,
    overview:      ingestion.overview,
  };
}

// ── GET /upload/formats ───────────────────────────────────────────────────────

router.get('/formats', (_req, res) => {
  res.json({ success: true, formats: SUPPORTED_FORMATS });
});

// ── Attachment management ─────────────────────────────────────────────────────

router.get('/attachments/:conversationId', (req, res) => {
  res.json({
    success: true,
    conversationId: req.params.conversationId,
    attachments: getAttachments(req.params.conversationId).map(serializeAttachment),
  });
});

router.delete('/attachments/:conversationId/:attachmentId', (req, res) => {
  const removed = removeAttachment(req.params.conversationId, req.params.attachmentId);
  if (!removed) return res.status(404).json({ success: false, error: 'Attachment not found' });
  res.json({ success: true, removed: req.params.attachmentId });
});

export default router;

