/**
 * AQUA Conversations Route
 *
 * GET  /conversations         — list all conversations (id, messageCount, meta)
 * GET  /conversations/:id     — full message history for one conversation
 * DELETE /conversations/:id   — clear a conversation
 */
import express from 'express';
import {
  getAllConversations,
  getConversation,
  getConversationMeta,
  clearConversation,
  conversationExists,
} from '../memory/conversationStore.js';

const router = express.Router();

// ── List all conversations ────────────────────────────────────────────────────

router.get('/', (req, res) => {
  const all   = getAllConversations();  // Map<id, { messages, meta }>
  const limit = Math.min(parseInt(req.query.limit ?? '100', 10), 500);
  const skip  = parseInt(req.query.skip ?? '0', 10);

  // Per-user scoping: when the platform provides a session identity, only
  // return that user's conversations. Legacy rows with no userId stay
  // invisible to authenticated users (rather than leaking to everyone).
  const scopeUser = req.aquaUserId ?? null;

  const entries = [];
  for (const [id, conv] of all.entries()) {
    const owner = conv.meta?.userId ?? null;
    if (scopeUser && owner !== scopeUser) continue;
    entries.push({
      id,
      messageCount: conv.messages?.length ?? 0,
      meta:         conv.meta ?? {},
    });
  }

  // newest first (by createdAt in meta, fallback to insertion order)
  entries.sort((a, b) => (b.meta.createdAt ?? 0) - (a.meta.createdAt ?? 0));

  res.json({
    success: true,
    total:   entries.length,
    count:   Math.min(limit, Math.max(0, entries.length - skip)),
    conversations: entries.slice(skip, skip + limit),
  });
});

// ── Get one conversation ──────────────────────────────────────────────────────

router.get('/:id', (req, res) => {
  const { id } = req.params;
  if (!conversationExists(id)) {
    return res.status(404).json({ success: false, error: 'Conversation not found' });
  }
  const messages = getConversation(id);
  const meta     = getConversationMeta(id);
  res.json({
    success: true,
    id,
    meta,
    messageCount: messages.length,
    messages,
  });
});

// ── Clear a conversation ──────────────────────────────────────────────────────

router.delete('/:id', (req, res) => {
  const { id } = req.params;
  if (!conversationExists(id)) {
    return res.status(404).json({ success: false, error: 'Conversation not found' });
  }
  clearConversation(id);
  res.json({ success: true, cleared: id });
});

export default router;

/**
 * AQUA Project Intelligence Engine — HTTP Routes
 *
 * POST   /project/workspace                — create workspace
 * POST   /project/workspace/:id/files      — upload + ingest files
 * GET    /project/workspace/:id            — status + stats
 * GET    /project/workspace/:id/files      — list indexed files
 * GET    /project/workspace/:id/graph      — dependency graph
 * POST   /project/workspace/:id/query      — query index
 * DELETE /project/workspace/:id            — delete workspace
 * GET    /project/workspaces               — list all workspaces
 *
 * File upload format (JSON body):
 *   { files: [{ path: string, content: string, encoding?: 'base64' }] } — raw files array
 *   { zip: "<base64>" }                                                 — base64-encoded ZIP
 *
 * encoding: 'base64' marks binary document formats (.pdf/.docx/.pptx/.xlsx)
 * — content is their raw bytes, base64-encoded, not UTF-8 text. Omit it
 * (or omit the field) for ordinary text/code files — unchanged, exactly
 * as before. See project/fileIngester.js + project/documentParser.js.
 */
import express from 'express';
import { createWorkspace, getWorkspace, updateWorkspace, deleteWorkspace, listWorkspaces } from '../project/workspaceManager.js';
import { extractZip }                                                                      from '../project/fileIngester.js';
import { runWorkspaceIngestion }                                                           from '../project/ingestionPipeline.js';
import { getIndex, getIndexStats, queryIndex }                                             from '../project/projectIndex.js';
import { serializeGraph, detectCycles }                                                    from '../project/dependencyGraph.js';
import { formatPatch }                                                                     from '../project/patchGenerator.js';
import {
  proposeEdit, getProposal, listProposals, applyProposal, rejectProposal, revertProposal,
  serializeProposal,
} from '../project/editEngine.js';
import { whoImports, whatImports } from '../project/dependencyGraph.js';

import { resolveOwner, rememberWorkspace } from '../memory/engine.js';

const router = express.Router();

// ── Create workspace ──────────────────────────────────────────────────────────

router.post('/workspace', (req, res) => {
  const { name, description } = req.body ?? {};
  const ownerId = resolveOwner({ userId: req.aquaUserId ?? null, conversationId: req.body?.conversationId ?? null });
  const workspace = createWorkspace({ name, description, ownerId });
  rememberWorkspace(ownerId, workspace);
  res.json({
    success:   true,
    workspace: { id: workspace.id, createdAt: workspace.createdAt, indexStatus: workspace.indexStatus },
  });
});

// ── Upload + ingest files ─────────────────────────────────────────────────────

router.post('/workspace/:id/files', async (req, res) => {
  const { id } = req.params;
  const workspace = getWorkspace(id);
  if (!workspace) return res.status(404).json({ success: false, error: 'Workspace not found' });

  const { files, zip } = req.body ?? {};
  let rawFiles = [];

  if (zip) {
    try {
      rawFiles = await extractZip(zip);
    } catch (err) {
      return res.status(400).json({ success: false, error: err.message });
    }
  } else if (Array.isArray(files)) {
    rawFiles = files;
  } else {
    return res.status(400).json({
      success: false,
      error:   'Provide "files": [{ path, content }] or "zip": "<base64>"',
    });
  }

  // Day 5: the pipeline (ingest → index → summarize → graph → analyze →
  // persist) is now the shared runWorkspaceIngestion() in
  // project/ingestionPipeline.js — identical behavior, one implementation,
  // also used by the unified /upload endpoint. Error semantics preserved:
  // any failure marks the workspace 'failed' (retryable) and returns
  // structured JSON.
  try {
    const result = await runWorkspaceIngestion(id, rawFiles);
    res.json({ success: true, workspaceId: id, ...result });
  } catch (err) {
    if (err.code === 'NO_VALID_FILES') {
      return res.status(400).json({ success: false, error: err.message });
    }
    res.status(500).json({
      success: false,
      workspaceId: id,
      error: `Indexing failed: ${err.message}. The workspace was marked failed — you can retry the upload.`,
    });
  }
});

// ── Workspace status ──────────────────────────────────────────────────────────

router.get('/workspace/:id', (req, res) => {
  const workspace = getWorkspace(req.params.id);
  if (!workspace) return res.status(404).json({ success: false, error: 'Workspace not found' });
  res.json({ success: true, workspace: { ...workspace, indexStats: getIndexStats(req.params.id) } });
});

// ── File list ─────────────────────────────────────────────────────────────────

router.get('/workspace/:id/files', (req, res) => {
  const workspace = getWorkspace(req.params.id);
  if (!workspace) return res.status(404).json({ success: false, error: 'Workspace not found' });
  res.json({ success: true, workspaceId: req.params.id, files: workspace.files });
});

// ── Workspace overview (cached intelligence) ──────────────────────────────────
// Generated once at index time; this endpoint only serves the cache.
// Overview cannot be regenerated post-upload (raw content is not persisted).

router.get('/workspace/:id/overview', (req, res) => {
  const workspace = getWorkspace(req.params.id);
  if (!workspace) return res.status(404).json({ success: false, error: 'Workspace not found' });

  if (!workspace.overview) {
    return res.status(200).json({
      success:  true,
      workspaceId: req.params.id,
      overview: null,
      note: workspace.indexStatus === 'indexed'
        ? 'This workspace was indexed before overview generation existed. Re-upload to generate one.'
        : `Workspace not yet indexed (status: ${workspace.indexStatus}).`,
    });
  }
  res.json({ success: true, workspaceId: req.params.id, overview: workspace.overview });
});

// ── Dependency graph ──────────────────────────────────────────────────────────

router.get('/workspace/:id/graph', (req, res) => {
  const workspace = getWorkspace(req.params.id);
  if (!workspace) return res.status(404).json({ success: false, error: 'Workspace not found' });
  const graph  = serializeGraph(req.params.id);
  const cycles = detectCycles(req.params.id);
  res.json({ success: true, workspaceId: req.params.id, graph, cycles });
});

// ── Index query ───────────────────────────────────────────────────────────────

router.post('/workspace/:id/query', (req, res) => {
  const workspace = getWorkspace(req.params.id);
  if (!workspace) return res.status(404).json({ success: false, error: 'Workspace not found' });

  const { symbol, keyword, importModule, filePath } = req.body ?? {};
  const results = queryIndex(req.params.id, { symbol, keyword, importModule, filePath });

  res.json({
    success:     true,
    workspaceId: req.params.id,
    results: {
      files:   results.files.map(f => ({ path: f.path, lang: f.lang, summary: f.summary, functions: f.functions })),
      symbols: results.symbols,
      imports: results.imports,
    },
  });
});

// ── List all workspaces ───────────────────────────────────────────────────────

router.get('/workspaces', (req, res) => {
  const workspaces = listWorkspaces();
  res.json({
    success:    true,
    count:      workspaces.length,
    workspaces: workspaces.map(ws => ({
      id:          ws.id,
      projectType: ws.projectType,
      indexStatus: ws.indexStatus,
      fileCount:   ws.files?.length ?? 0,
      createdAt:   ws.createdAt,
      meta:        ws.meta,
    })),
  });
});

// ── Delete workspace ──────────────────────────────────────────────────────────

router.delete('/workspace/:id', (req, res) => {
  const deleted = deleteWorkspace(req.params.id);
  if (!deleted) return res.status(404).json({ success: false, error: 'Workspace not found' });
  res.json({ success: true, deleted: req.params.id });
});

// ── File content fetch ────────────────────────────────────────────────────────
// GET /project/workspace/:id/file-content?path=src/foo.js

router.get('/workspace/:id/file-content', (req, res) => {
  const workspace = getWorkspace(req.params.id);
  if (!workspace) return res.status(404).json({ success: false, error: 'Workspace not found' });

  const { path: filePath } = req.query;
  if (!filePath) return res.status(400).json({ success: false, error: 'Query param ?path= required' });

  // Day 4 fix: the in-memory index HAS full content (index.byPath entries carry
  // it — retrieval and patch editing both depend on that). Serve it when the
  // index is live so file navigation ("open this referenced file") works.
  // Persisted workspace records still store metadata only, unchanged.
  const index = getIndex(req.params.id);
  const entry = index?.byPath.get(filePath);
  if (entry) {
    return res.json({
      success:     true,
      workspaceId: req.params.id,
      file: {
        path:      filePath,
        lang:      entry.lang,
        size:      entry.size,
        summary:   entry.summary,
        content:   entry.content,
        functions: entry.functions ?? [],
        exports:   entry.exports ?? [],
        imports:   entry.imports ?? [],
        importedBy: whoImports(req.params.id, filePath),
        importsFiles: whatImports(req.params.id, filePath),
      },
    });
  }

  const meta = workspace.files?.find(f => f.path === filePath);
  if (!meta) {
    return res.status(404).json({ success: false, error: `File '${filePath}' not in index` });
  }
  // Index gone (server restarted) — metadata only.
  res.json({
    success:     true,
    workspaceId: req.params.id,
    file:        meta,
    note:        'Index is not live (server restarted since upload). Re-upload to restore file content.',
  });
});

// ── Patch proposal ────────────────────────────────────────────────────────────
// POST /project/workspace/:id/patch
// Body: { description, reasoning, changes: [{ file, original?, modified, explanation }] }

router.post('/workspace/:id/patch', (req, res) => {
  const workspace = getWorkspace(req.params.id);
  if (!workspace) return res.status(404).json({ success: false, error: 'Workspace not found' });

  const { description, reasoning, changes } = req.body ?? {};
  if (!Array.isArray(changes) || !changes.length) {
    return res.status(400).json({
      success: false,
      error: 'Body must include { description, reasoning, changes: [...] }',
    });
  }

  const patch = formatPatch({ description, reasoning, changes });
  res.json({ success: true, workspaceId: req.params.id, patch });
});

// ══════════════════════════════════════════════════════════════════════════════
// Day 4 — Patch-First Editing
// ══════════════════════════════════════════════════════════════════════════════

// ── Propose an edit ───────────────────────────────────────────────────────────
// POST /project/workspace/:id/edit   Body: { instruction }
// Runs the full pipeline: locate → LLM minimal edits → in-memory apply →
// diff → static verify → related-file recommendations. NOTHING is applied.

router.post('/workspace/:id/edit', async (req, res) => {
  const { instruction } = req.body ?? {};
  if (!instruction || typeof instruction !== 'string' || !instruction.trim()) {
    return res.status(400).json({ success: false, error: 'Body must include a non-empty "instruction" string' });
  }
  try {
    const proposal = await proposeEdit({ workspaceId: req.params.id, instruction: instruction.trim() });
    res.json({ success: true, workspaceId: req.params.id, proposal: serializeProposal(proposal) });
  } catch (err) {
    const status = err.code === 'NO_WORKSPACE' ? 404
                 : err.code === 'NOT_INDEXED' || err.code === 'NO_TARGETS' || err.code === 'BAD_EDIT_PLAN' || err.code === 'ALL_OPS_FAILED' ? 422
                 : 500;
    console.error(`[EDIT] proposal failed workspace=${req.params.id}:`, err.message);
    res.status(status).json({ success: false, error: err.message, code: err.code ?? 'EDIT_FAILED', failedOperations: err.failedOperations ?? [] });
  }
});

// ── List / fetch proposals ────────────────────────────────────────────────────

router.get('/workspace/:id/edits', (req, res) => {
  res.json({ success: true, workspaceId: req.params.id, proposals: listProposals(req.params.id) });
});

router.get('/workspace/:id/edit/:proposalId', (req, res) => {
  const p = getProposal(req.params.id, req.params.proposalId);
  if (!p) return res.status(404).json({ success: false, error: 'Proposal not found' });
  res.json({ success: true, workspaceId: req.params.id, proposal: serializeProposal(p) });
});

// ── Apply (safe, atomic, conflict-checked) ────────────────────────────────────

router.post('/workspace/:id/edit/:proposalId/apply', (req, res) => {
  const result = applyProposal(req.params.id, req.params.proposalId);
  if (!result.ok) {
    return res.status(result.conflicts ? 409 : 400).json({
      success: false, error: result.error,
      ...(result.conflicts ? { conflicts: result.conflicts, suggestion: result.suggestion } : {}),
    });
  }
  res.json({ success: true, workspaceId: req.params.id, proposal: result.proposal, indexStats: result.indexStats });
});

// ── Reject ────────────────────────────────────────────────────────────────────

router.post('/workspace/:id/edit/:proposalId/reject', (req, res) => {
  const result = rejectProposal(req.params.id, req.params.proposalId);
  if (!result.ok) return res.status(400).json({ success: false, error: result.error });
  res.json({ success: true, workspaceId: req.params.id, proposal: result.proposal });
});

// ── Revert an applied proposal ────────────────────────────────────────────────

router.post('/workspace/:id/edit/:proposalId/revert', (req, res) => {
  const result = revertProposal(req.params.id, req.params.proposalId);
  if (!result.ok) return res.status(400).json({ success: false, error: result.error });
  res.json({ success: true, workspaceId: req.params.id, proposal: result.proposal });
});

export default router;

/**
AQUA Chat Route v5 — Full memory pipeline + Real Streaming (Day 3)

Two endpoints, ONE pipeline:

  POST /chat         — original request/response JSON (unchanged contract)
  POST /chat/stream  — Server-Sent Events over POST fetch. Same pipeline,
                       tokens streamed the moment the provider emits them.

The pre-generation pipeline (classify → orchestrate → plan → intelligence →
memory extract/update → memory retrieve → project retrieve → prompt build →
context window) is factored into prepareTurn() and shared verbatim by both
endpoints — /chat behavior is byte-identical to v4, /chat/stream additionally
reports each REAL stage as it starts (no fake progress).

SSE protocol (/chat/stream):
  event: meta       { requestId, conversationId, isNewConversation }
  event: stage      { id, label }            — genuine pipeline stage starting
  event: provider   { provider, score, attempt }
  event: provider_failed { provider, reason }— pre-first-token fallback only
  event: token      { t }                    — raw text delta
  event: replace    { text }                 — verification revised the answer
  event: patch      { ...proposal }          — Day 4: patch-first edit proposal (diff hunks, stats, verification)
  event: done       { ...same diagnostics payload as POST /chat, answer included }
  event: error      { error, recoverable, fallbackChain }

Streaming guarantees:
  • Provider fallback only before the first token (see router.js
    generateTextStream). Verification, when warranted, runs AFTER the stream
    completes and emits `replace` if it revises — the draft stays visible
    meanwhile.
  • Client disconnect (Stop button / closed tab) aborts the provider call
    immediately; whatever partial text the user saw is persisted to the
    conversation so history matches the screen.
  • Both endpoints persist user + assistant turns identically.

Execution order (every request):
ID management      — single getOrCreateConversation() call, unique requestId
Classify           — once, result passed to router (no double classification)
Plan               — Phase 4: complexity tier + reasoning mode from classification
Internal Intelligence — Planner→Reasoning Engine→Critic→Synthesizer brief (no-op below medium complexity)
Extract facts      — regex extraction from user message → long-term memory
Handle forget/update — "forget my name" / "my language is now Go"
Retrieve memories  — relevant facts ranked and fetched BEFORE prompt build
Build system prompt — identity + memory block + reasoning directive + task module
Build context window — recent conversation history (short-term memory), budget scaled by plan complexity
Generate           — router with full fallback chain, biased by plan complexity
Persist messages   — user + assistant saved to conversation store
Respond            — includes conversationId so client can echo it next turn

ROOT FIX (v4 — orphan entries + impossible log sequence, see conversationStore.js):
getOrCreateConversation(id, meta) is the ONLY place that decides new-vs-existing.
*/
import express  from 'express';
import { v4 as uuidv4 } from 'uuid';
import { generateText, generateTextStream } from '../providers/router.js';
import { buildSystemPrompt }      from '../core/promptBuilder.js';
import { buildContextWindow, estimateTokens } from '../core/tokenManager.js';
import { classifyTask }           from '../core/classifier.js';
import { createContext, logMemoryEvent, logPlanEvent, logIntelligenceEvent, logOrchestratorEvent, logVerificationEvent } from '../core/observability.js';
import { createExecutionPlan }    from '../core/executionPlanner.js';
import { getReasoningStrategy }   from '../core/reasoningStrategy.js';
import { runIntelligencePipeline } from '../intelligence/internalIntelligenceEngine.js';
import { orchestrate, formatOrchestratorLog } from '../orchestrator/toolOrchestrator.js';
import { getAgent } from '../intelligence/agentRegistry.js';
import '../intelligence/verificationAgent.js'; // side-effect: registers the 'verification' agent on load
import { computeContextBudget, optimizeContext } from '../core/contextOptimizer.js';
import {
  getOrCreateConversation,
  getConversation,
  addMessage,
} from '../memory/conversationStore.js';
import { resolveOwner, memoryObserve, memoryRetrieve, memoryAfterTurn, getMemoryTrace } from '../memory/engine.js';
import { retrieveProjectContext, formatProjectContext }    from '../project/projectRetriever.js';
import { formatAttachmentsForPrompt, getAttachments }       from '../upload/attachmentStore.js';
import { proposeEdit, serializeProposal }                   from '../project/editEngine.js';
import { getIndex }                                         from '../project/projectIndex.js';
import { detectIdentityIntent, answerFromIdentity, isRefusal } from '../identity/index.js';

const router = express.Router();

// ══════════════════════════════════════════════════════════════════════════════
// Day 4 — Conversational patch-first editing
//
// "Add rate limiting." against an indexed workspace should produce an
// explained, previewable, verifiable PATCH — not a wall of regenerated code.
// Detection is deliberately conservative: imperative edit verbs only, and
// questions ("how would I add…?", trailing "?") always take the normal
// explain path. Any edit-pipeline failure falls back to the normal chat
// pipeline — an edit attempt can never make a request fail outright.
// ══════════════════════════════════════════════════════════════════════════════

const EDIT_VERB_RE = /^(please\s+|now\s+|ok(ay)?[,\s]+)*\s*(add|implement|fix|refactor|rename|update|change|remove|delete|create|modify|extract|convert|migrate|introduce|wire|hook|integrate|replace|improve|harden|clean\s*up)\b/i;
const QUESTION_RE  = /^(how|what|why|where|when|which|who|is|are|does|do|should|can|could|would|will|explain|describe|show\s+me|tell\s+me|walk\s+me)\b/i;
const EXPLAIN_ONLY_RE = /\b(don'?t\s+(edit|change|modify)|explain\s+only|no\s+patch|just\s+explain)\b/i;

function isEditIntent(userMessage, workspaceId) {
  if (!workspaceId) return false;
  if (!getIndex(workspaceId)) return false;          // index must be live — never guess-edit
  const msg = userMessage.trim();
  if (msg.endsWith('?')) return false;
  if (QUESTION_RE.test(msg)) return false;
  if (EXPLAIN_ONLY_RE.test(msg)) return false;
  return EDIT_VERB_RE.test(msg);
}

/** Human-readable explanation of a proposal — persisted as the assistant turn. */
function composePatchExplanation(p) {
  const lines = [`### ${p.summary}`, ''];
  if (p.reasoning) lines.push(`**Approach:** ${p.reasoning}`, '');
  if (p.impact)    lines.push(`**Expected impact:** ${p.impact}`, '');

  lines.push('**Files changed:**');
  for (const f of p.files) {
    const tag = f.changeType === 'create' ? 'new file' : f.changeType;
    lines.push(`- \`${f.path}\` (${tag}, +${f.stats.added} −${f.stats.removed})${f.explanation ? ` — ${f.explanation}` : ''}`);
  }

  if (p.breakingChanges?.length) {
    lines.push('', '**⚠️ Breaking changes:**');
    for (const b of p.breakingChanges) lines.push(`- ${b}`);
  }
  if (p.risks?.length) {
    lines.push('', '**Risks:**');
    for (const r of p.risks) lines.push(`- ${r}`);
  }
  if (p.relatedFiles?.length) {
    lines.push('', '**May need follow-up (imports edited files):**');
    for (const rf of p.relatedFiles) lines.push(`- \`${rf.path}\` — ${rf.reason}`);
  }
  if (p.failedOperations?.length) {
    lines.push('', '**Skipped operations:**');
    for (const fo of p.failedOperations) lines.push(`- \`${fo.file}\`: ${fo.error}`);
  }

  const v = p.verification;
  lines.push('', v.passed
    ? `**Verification:** ${v.checks.length} static checks passed.`
    : `**Verification:** ⚠️ ${v.warnings.length} warning(s) — ${v.warnings.join('; ')}`);

  lines.push('', 'Review the diff below — nothing is applied until you approve it.');
  return lines.join('\n');
}

/** Chat-response payload for an edit turn — same shape the UI already consumes. */
function buildEditResponsePayload({ requestId, conversationId, isNew, proposal, answer, workspaceId }) {
  const v = proposal.verification;
  return {
    success: true,
    requestId,
    conversationId,
    isNewConversation: isNew,
    mode: 'edit',

    provider:      proposal.provider ?? 'unknown',
    providerScore: 0,
    taskType:      'coding',
    taskLabels:    ['coding', 'edit'],
    confidence:    1,
    promptModules: ['edit-engine'],
    latencyMs:     proposal.latencyMs,
    fallbackChain: [],
    answer,
    truncated:     false,
    finishReason:  'stop',

    memory:  { extracted: 0, injected: 0, facts: [] },
    plan:    { complexity: 'complex', multiStep: true, reasoningMode: 'edit', contextTokensBefore: 0, contextTokensAfter: 0 },
    intelligence: { active: false, pipeline: [], strategy: 'patch-first-editing', criticFocus: [] },
    verification: { warranted: true, reason: 'patch static verification', ran: v.ran, passed: v.passed, revised: false },
    orchestration: {
      profile: 'edit', profileLabel: 'Patch-first editing',
      capabilitiesEnabled: ['edit_locate', 'edit_generate', 'edit_diff', 'edit_verify'],
      capabilitiesSkipped: [], estimatedCost: 'medium', estimatedLatency: 'medium',
      verificationEnabled: true, multiLabel: ['coding'], tags: ['edit'],
    },

    project: { workspaceId, contextInjected: true, filesReferenced: proposal.files.map(f => f.path) },
    patch:   serializeProposal(proposal),
  };
}

// Repo-intent override (additive): whole-repo questions ("explain this
// repository", "where is authentication") often classify as conversation/
// simple_qa, whose profiles skip project_retrieval — leaving the model
// blind to an explicitly attached workspace. If the user's words clearly
// reference the codebase, force retrieval regardless of profile.
const REPO_INTENT_RE = /\b(repo(sitory)?|codebase|this project|the project|architecture|endpoint|api route|auth(entication|orization)?|database|db|folder|module|file|function|class|component|config(uration)?|dependenc|todo|fixme|business logic|trace|refactor|implement|where (is|should)|what would break)\b/i;

/**
 * Shared pre-generation pipeline — identical for /chat and /chat/stream.
 * `onStage(id, label)` fires as each REAL stage begins (no-op for /chat);
 * only stages that actually run are reported — never fake progress.
 */
function prepareTurn({ userMessage, workspaceId, conversationId, userId = null, ctx, requestId, onStage = () => {} }) {
  // ── 1. Resolve the ONE memory owner (unified engine) ────────────────────────
  // Platform user identity when present (cross-conversation, cross-device),
  // else this conversation as a dev/standalone fallback (adopted into the
  // user's memory on first login). Null disables memory entirely.
  const memoryOwner = resolveOwner({ userId, conversationId });
  // ── 2. Classify (once — result passed to router, no double classification) ──
  onStage('classify', 'Understanding your request…');
  const { task: taskType, confidence, labels } = classifyTask(userMessage);
  console.log(`[CLASSIFIER] task=${taskType} conf=${confidence.toFixed(2)} req=${requestId}`);

  // ── 1b. Smart Router — is this a question about AQUA/Aquiplex itself? ────────
  // Runs BEFORE retrieval. When true, the Identity & Self-Knowledge Layer owns
  // the answer: project/vector retrieval is skipped (irrelevant noise for a
  // brand question) and the full identity profile + a confidence directive are
  // injected into the system prompt. A post-generation guard (see the
  // endpoints) substitutes the deterministic profile answer if the model ever
  // hedges — so AQUA can never fail to answer a question about itself.
  const identityIntent = detectIdentityIntent(userMessage);
  if (identityIntent.isSelf) {
    onStage('identity', 'Answering from self-knowledge…');
    console.log(`[IDENTITY] self-question detected topics=[${identityIntent.topics}] score=${identityIntent.score} req=${requestId}`);
  }

  // ── 2a. OBSERVE — MANDATORY, BEFORE ORCHESTRATION ───────────────────────────
  // The ONE observation pipeline (unified engine): normalize → identity /
  // preference / goal / relationship / project / fact extraction →
  // conflict-resolved storage → beliefs / goals / working memory / episodes /
  // graph. Runs for EVERY user message. The orchestrator below routes
  // EXPENSIVE stages (workspace analysis, repo scan, reasoning, critic);
  // it has no say over observation — durable memory is never optional.
  // (classifyTask above is deterministic, <1ms, zero-LLM — part of
  // normalization; observers use its taskType for trait signals.)
  onStage('memory', 'Checking memory…');
  const observed = memoryObserve(memoryOwner, {
    userMessage, taskType, workspaceId, conversationId, userId, requestId,
  });
  const extractedFacts = observed.extractedFacts;
  logMemoryEvent(ctx, 'EXTRACTED', extractedFacts.map(f => `${f.key}=${f.value}`));
  if (observed.trace.forget)     logMemoryEvent(ctx, 'DELETED', [observed.trace.forget.key]);
  if (observed.trace.correction) logMemoryEvent(ctx, 'UPDATED', [`${observed.trace.correction.key}=${observed.trace.correction.value}`]);
  if (observed.mind.signals || observed.mind.goalsTouched) {
    logMemoryEvent(ctx, 'MIND_OBSERVED', [`signals=${observed.mind.signals}`, `goals=${observed.mind.goalsTouched}`]);
  }

  // ── 2b. Adaptive Tool Orchestrator (Phase 6) ────────────────────────────────
  // Pure/deterministic, no LLM calls, no I/O — see toolOrchestrator.js.
  // Conservative integration preserved from v4: never gates memory
  // extraction/retrieval (cheap local ops); only narrows project retrieval
  // and sizes budgets. See AQUA_PHASE6_NOTES.md.
  const orchestration = orchestrate({
    userMessage,
    taskType,
    confidence,
    hasWorkspaceId: !!workspaceId,
  });
  logOrchestratorEvent(ctx, orchestration, formatOrchestratorLog(orchestration));

  // ── 2b. Execution plan + reasoning strategy (Phase 4) ───────────────────────
  const plan      = createExecutionPlan(taskType, confidence);
  const reasoning = getReasoningStrategy(taskType, plan.complexity);
  logPlanEvent(ctx, { ...plan, mode: reasoning.mode });

  // ── 2c. Internal Intelligence Engine ─────────────────────────────────────────
  const intelligence = runIntelligencePipeline({
    taskType,
    complexity: plan.complexity,
    confidence,
    userMessage,
  });
  logIntelligenceEvent(ctx, intelligence);

  // ── 3. Retrieve — the ONE retrieval pipeline (unified engine) ───────────────
  // Ranked facts + cognitive state + file memory under a single token
  // budget → one memoryBlock for the prompt. Smallest high-quality context.
  const retrieved = memoryRetrieve(memoryOwner, {
    query: userMessage, taskType, factLimit: 10, requestId,
  });
  const relevantFacts = retrieved.relevantFacts;
  const memoryBlock   = retrieved.block;
  if (relevantFacts.length) {
    logMemoryEvent(ctx, 'RETRIEVED', relevantFacts.map(f => `${f.key}=${f.value}`));
    logMemoryEvent(ctx, 'INJECTED',  relevantFacts.map(f => f.key));
  } else {
    logMemoryEvent(ctx, 'NO_MEMORIES', []);
  }
  const cognitive = { block: '', used: retrieved.cognitiveUsed };
  if (Object.values(retrieved.cognitiveUsed).some(n => n > 0)) {
    logMemoryEvent(ctx, 'MIND_INJECTED', Object.entries(retrieved.cognitiveUsed).filter(([, n]) => n > 0).map(([k, n]) => `${k}=${n}`));
  }

  // ── 5b. Retrieve project context (Phase 5, gated by orchestrator in Phase 6) ──
  let projectContext = '';
  let projectFiles   = [];
  const wantsProjectRetrieval = orchestration.enabled.some(c => c.id === 'project_retrieval');
  const repoIntent = REPO_INTENT_RE.test(userMessage);
  // Identity questions never need the codebase — skip retrieval even if the
  // repo-intent regex fired on a shared word (e.g. "architecture", "module").
  if (workspaceId && identityIntent.isSelf) {
    console.log(`[PROJECT] Skipped — identity/self-question owns this turn workspace=${workspaceId}`);
  } else if (workspaceId && (wantsProjectRetrieval || repoIntent)) {
    onStage('workspace', 'Reading workspace…');
    if (!wantsProjectRetrieval) console.log(`[PROJECT] Repo-intent override — profile=${orchestration.profile.label} skipped project_retrieval but query references the codebase workspace=${workspaceId}`);
    const rawContext = retrieveProjectContext(workspaceId, userMessage);
    if (rawContext) {
      projectContext = formatProjectContext(rawContext);
      projectFiles   = rawContext.files.map(f => f.path ?? f.name ?? String(f)).filter(Boolean);
      console.log(`[PROJECT] Context injected workspace=${workspaceId} files=${rawContext.files.length}`);
    }
  } else if (workspaceId) {
    console.log(`[PROJECT] Skipped — profile=${orchestration.profile.label} does not require project_retrieval workspace=${workspaceId}`);
  }

  // ── 5c. Conversation attachments (Day 5 — Universal Upload) ─────────────────
  // Anything uploaded via POST /upload (PDFs, images, spreadsheets, audio…)
  // is registered against this conversationId in the attachment store with
  // its content ALREADY extracted at upload time — zero re-processing here.
  // Injected unconditionally (not orchestrator-gated): a user who just
  // uploaded a file is about to ask about it; withholding it is never right.
  const conversationAttachments = getAttachments(conversationId);
  let attachmentContext = '';
  if (conversationAttachments.length) {
    onStage('attachments', 'Reading your files…');
    attachmentContext = formatAttachmentsForPrompt(conversationId);
    console.log(`[UPLOAD] Attachment context injected conversation=${conversationId} attachments=${conversationAttachments.length}`);
  }

  // ── 6. Build system prompt ────────────────────────────────────────────────────
  onStage('prompt', 'Preparing response…');
  // Attachment context rides the projectContext slot — same injection point,
  // same budget handling in promptBuilder, no signature change.
  const combinedContext = [attachmentContext, projectContext].filter(Boolean).join('\n\n');
  const { prompt: systemPrompt, modules: promptModules } = buildSystemPrompt(taskType, memoryBlock, reasoning.directive, combinedContext, intelligence.synthesis.text, identityIntent);

  // ── 7. Build context window (short-term message history) ─────────────────────
  const history    = getConversation(conversationId);
  const ctxBudget  = computeContextBudget(plan.complexity, orchestration.budget.maxContextTokens);
  const window     = buildContextWindow(history, ctxBudget);
  const { messages, stats: contextStats } = optimizeContext([...window, { role: 'user', content: userMessage }]);

  const promptTokens = estimateTokens(systemPrompt + messages.map(m => m.content).join(' '));

  return {
    taskType, confidence, labels,
    identityIntent,
    orchestration, plan, reasoning, intelligence,
    extractedFacts, relevantFacts,
    memoryOwner, mindOwner: memoryOwner, mind: { observedSignals: observed.mind.signals, goalsTouched: observed.mind.goalsTouched, contextInjected: !!memoryBlock, contextUsed: cognitive.used },
    projectContext, projectFiles,
    attachments: conversationAttachments.map(a => ({ id: a.id, name: a.name, kind: a.kind })),
    systemPrompt, promptModules,
    messages, contextStats, promptTokens,
  };
}

/** Verification pass — shared by both endpoints. Fails open by construction. */
async function runVerification({ orchestration, userMessage, draftAnswer, taskType, requestId, conversationId }) {
  let verification = { ran: false, passed: null, revised: false };
  if (orchestration.verification.enabled) {
    const verificationAgent = getAgent('verification');
    if (verificationAgent) {
      verification = await verificationAgent.run({
        userMessage,
        draftAnswer,
        taskType,
        requestId,
        conversationId,
        responseBudget: orchestration.budget,
      });
    }
  }
  return verification;
}

/** Diagnostics payload — identical shape between /chat JSON and /chat/stream `done`. */
function buildResponsePayload({
  requestId, conversationId, isNew, result, finalAnswer, taskType, confidence,
  promptModules, prep, orchestration, plan, reasoning, intelligence, verification,
  extractedFacts, relevantFacts, contextStats, workspaceId, projectContext, projectFiles,
  identityGuarded = false,
}) {
  return {
    success:        true,
    requestId,
    conversationId,
    isNewConversation: isNew,

    provider:       result.provider,
    providerScore:  +result.score.toFixed(1),
    taskType,
    taskLabels:     result.labels,
    confidence:     +confidence.toFixed(2),
    promptModules,
    latencyMs:      result.latency,
    fallbackChain:  result.fallbackChain,
    answer:         finalAnswer,
    truncated:      result.truncated ?? false,
    finishReason:   result.finishReason ?? 'stop',

    memory: {
      owner:      prep.memoryOwner ?? null,
      trace:      getMemoryTrace(requestId) ? `/memory/inspector/${requestId}` : null,
      extracted:  extractedFacts.length,
      injected:   relevantFacts.length,
      facts:      relevantFacts.map(f => ({ key: f.key, value: f.value })),
    },

    mind: prep?.mind ?? { observedSignals: 0, goalsTouched: 0, contextInjected: false, contextUsed: {} },

    plan: {
      complexity:           plan.complexity,
      multiStep:             plan.multiStep,
      reasoningMode:         reasoning.mode,
      contextTokensBefore:   contextStats.tokensBefore,
      contextTokensAfter:    contextStats.tokensAfter,
    },

    intelligence: {
      active:         intelligence.plan.active,
      pipeline:       intelligence.plan.pipeline.map(s => s.name),
      strategy:       intelligence.reasoning.strategy ?? null,
      criticFocus:    intelligence.critic.focusRisks ?? [],
    },

    verification: {
      warranted:  orchestration.verification.enabled,
      reason:     orchestration.verification.reason,
      ran:        verification.ran,
      passed:     verification.passed,
      revised:    verification.revised,
    },

    orchestration: {
      profile:            orchestration.profile.id,
      profileLabel:       orchestration.profile.label,
      capabilitiesEnabled: orchestration.enabled.map(c => c.id),
      capabilitiesSkipped: orchestration.skipped.map(c => c.id),
      estimatedCost:      orchestration.estimatedCost,
      estimatedLatency:   orchestration.estimatedLatency,
      verificationEnabled: orchestration.verification.enabled,
      multiLabel:         orchestration.multiLabel.labels,
      tags:               orchestration.multiLabel.tags,
    },

    ...(workspaceId ? {
      project: {
        workspaceId,
        contextInjected: !!projectContext,
        filesReferenced: projectFiles ?? [],
      },
    } : {}),

    // Day 5 — Universal Upload: attachments grounding this answer.
    ...(prep?.attachments?.length ? { attachments: prep.attachments } : {}),

    // Identity & Self-Knowledge Layer: present only when this turn was a
    // question about AQUA/Aquiplex itself.
    ...(prep?.identityIntent?.isSelf ? {
      identity: {
        selfQuestion: true,
        topics:       prep.identityIntent.topics,
        guardEngaged: identityGuarded,   // true only if the model hedged and we substituted
      },
    } : {}),
  };
}

// ── POST /chat — original request/response endpoint (contract unchanged) ─────
router.post('/', async (req, res) => {
  const requestId = uuidv4();
  const { id: conversationId, isNew } = getOrCreateConversation(req.body?.conversationId ?? null, {
    userAgent: req.headers['user-agent']?.slice(0, 80),
    ip:        req.ip,
    userId:    req.aquaUserId ?? null, // platform session identity (AQUIPLEX)
  });
  console.log(`[CHAT] ${isNew ? 'CONVERSATION_CREATED' : 'CONVERSATION_REUSED'} id=${conversationId} req=${requestId}`);
  const ctx = createContext({ conversationId, requestId });

  try {
    const { message, workspaceId } = req.body ?? {};
    if (!message || typeof message !== 'string' || !message.trim()) {
      return res.status(400).json({
        success: false,
        requestId,
        conversationId,
        error: 'message is required and must be a non-empty string',
      });
    }
    const userMessage = message.trim();

    // ── Day 4: patch-first editing branch ────────────────────────────────────
    if (isEditIntent(userMessage, workspaceId)) {
      try {
        const proposal = await proposeEdit({ workspaceId, instruction: userMessage, requestId, conversationId });
        const answer = composePatchExplanation(proposal);
        addMessage(conversationId, 'user',      userMessage);
        addMessage(conversationId, 'assistant', answer);
        return res.json(buildEditResponsePayload({ requestId, conversationId, isNew, proposal, answer, workspaceId }));
      } catch (err) {
        // Fall back to the normal explain pipeline — an edit attempt never
        // fails the whole request. The model will answer conversationally.
        console.warn(`[EDIT] falling back to chat pipeline (${err.code ?? 'ERROR'}): ${err.message}`);
      }
    }

    const prep = prepareTurn({ userMessage, workspaceId, conversationId, userId: req.aquaUserId ?? null, ctx, requestId });
    const {
      taskType, confidence, orchestration, plan, reasoning, intelligence,
      extractedFacts, relevantFacts, projectContext, projectFiles,
      systemPrompt, promptModules, messages, contextStats,
    } = prep;

    // ── 8. Generate — router handles ranking + fallback + circuit breaker ──────
    const result = await generateText(
      userMessage,
      systemPrompt,
      messages,
      ctx,
      taskType,
      plan,
      orchestration.budget,
    );

    // ── 8b. Verification (Phase 6 decision → real pass) ─────────────────────────
    let finalAnswer = result.text;
    const verification = await runVerification({
      orchestration, userMessage, draftAnswer: result.text, taskType, requestId, conversationId,
    });
    if (verification.revised && verification.finalAnswer) {
      finalAnswer = verification.finalAnswer;
    }
    logVerificationEvent(ctx, verification);

    // ── 8c. Identity refusal guard (spec: never "I don't know" about self) ──────
    // The compact identity block + directive make a hedge on a self-question
    // extremely unlikely, but this is the hard guarantee: if the model still
    // refused, replace the answer with the deterministic profile answer.
    let identityGuarded = false;
    if (prep.identityIntent?.isSelf && isRefusal(finalAnswer)) {
      const grounded = answerFromIdentity(userMessage);
      if (grounded) {
        console.warn(`[IDENTITY] guard engaged — model hedged on a self-question; substituting profile answer req=${requestId}`);
        finalAnswer = grounded;
        identityGuarded = true;
      }
    }

    // ── 9. Persist messages ──────────────────────────────────────────────────────
    addMessage(conversationId, 'user',      userMessage);
    addMessage(conversationId, 'assistant', finalAnswer);

    // ── 9b. Mind post-turn — predictions rebuild + async reflection when due ────
    memoryAfterTurn(prep.memoryOwner, { taskType, workspaceId });

    // ── 10. Respond ──────────────────────────────────────────────────────────────
    return res.json(buildResponsePayload({
      identityGuarded,
      requestId, conversationId, isNew, result, finalAnswer, taskType, confidence,
      promptModules, prep, orchestration, plan, reasoning, intelligence, verification,
      extractedFacts, relevantFacts, contextStats, workspaceId, projectContext, projectFiles,
    }));
  } catch (err) {
    console.error('[CHAT] Request failed:', err.message);
    ctx.attempts ??= [];
    return res.status(500).json({
      success:        false,
      requestId,
      conversationId,
      error:          err?.message ?? 'Internal server error',
      fallbackChain:  ctx.attempts.map(a => ({ provider: a.provider, outcome: a.outcome })),
    });
  }
});

// ── POST /chat/stream — Server-Sent Events (Day 3 — Real Streaming) ──────────
router.post('/stream', async (req, res) => {
  const requestId = uuidv4();
  const { id: conversationId, isNew } = getOrCreateConversation(req.body?.conversationId ?? null, {
    userAgent: req.headers['user-agent']?.slice(0, 80),
    ip:        req.ip,
    userId:    req.aquaUserId ?? null, // platform session identity (AQUIPLEX)
  });
  console.log(`[CHAT] ${isNew ? 'CONVERSATION_CREATED' : 'CONVERSATION_REUSED'} id=${conversationId} req=${requestId} (stream)`);
  const ctx = createContext({ conversationId, requestId });

  const { message, workspaceId } = req.body ?? {};
  if (!message || typeof message !== 'string' || !message.trim()) {
    return res.status(400).json({
      success: false,
      requestId,
      conversationId,
      error: 'message is required and must be a non-empty string',
    });
  }
  const userMessage = message.trim();

  // ── SSE handshake ────────────────────────────────────────────────────────────
  res.writeHead(200, {
    'Content-Type':      'text/event-stream; charset=utf-8',
    'Cache-Control':     'no-cache, no-transform',
    'Connection':        'keep-alive',
    'X-Accel-Buffering': 'no', // disable proxy buffering (nginx) — tokens must flush immediately
  });
  res.flushHeaders?.();

  let closed = false;
  const send = (event, data) => {
    if (closed || res.writableEnded) return;
    res.write(`event: ${event}\ndata: ${JSON.stringify(data)}\n\n`);
  };

  // Client disconnect (Stop button, closed tab, network drop) → abort provider.
  const clientAbort = new AbortController();
  res.on('close', () => {
    if (!res.writableEnded) {
      closed = true;
      clientAbort.abort();
      console.log(`[CHAT] client disconnected mid-stream req=${requestId}`);
    }
  });

  // Heartbeat comment every 15s keeps proxies from timing out idle stretches
  // (long verification passes, slow first token). SSE comments are invisible
  // to EventSource-style parsers.
  const heartbeat = setInterval(() => {
    if (!closed && !res.writableEnded) res.write(': hb\n\n');
  }, 15_000);

  send('meta', { requestId, conversationId, isNewConversation: isNew });

  try {
    // ── Day 4: patch-first editing branch (streamed) ─────────────────────────
    // Real pipeline stages stream as they start; the finished proposal arrives
    // as a dedicated `patch` event; the explanation arrives as answer text.
    if (isEditIntent(userMessage, workspaceId)) {
      let editHandled = false;
      try {
        const proposal = await proposeEdit({
          workspaceId, instruction: userMessage, requestId, conversationId,
          onStage: (id, label) => send('stage', { id, label }),
        });
        const answer = composePatchExplanation(proposal);
        send('workspace', { workspaceId, contextInjected: true, filesReferenced: proposal.files.map(f => f.path) });
        send('patch', serializeProposal(proposal));
        send('token', { t: answer });
        addMessage(conversationId, 'user',      userMessage);
        addMessage(conversationId, 'assistant', answer);
        send('done', buildEditResponsePayload({ requestId, conversationId, isNew, proposal, answer, workspaceId }));
        editHandled = true;
      } catch (err) {
        if (clientAbort.signal.aborted) throw err;
        console.warn(`[EDIT] falling back to chat pipeline (${err.code ?? 'ERROR'}): ${err.message}`);
      }
      if (editHandled) {
        clearInterval(heartbeat);
        closed = true;
        if (!res.writableEnded) res.end();
        return;
      }
    }

    // Pipeline stages stream to the client AS THEY START — every stage event
    // corresponds to real work beginning, never a scripted animation.
    const prep = prepareTurn({
      userMessage, workspaceId, conversationId, userId: req.aquaUserId ?? null, ctx, requestId,
      onStage: (id, label) => send('stage', { id, label }),
    });
    const {
      taskType, confidence, orchestration, plan, reasoning, intelligence,
      extractedFacts, relevantFacts, projectContext, projectFiles,
      systemPrompt, promptModules, messages, contextStats,
    } = prep;

    // Surface workspace grounding before generation so the UI can show
    // "answering from workspace X, files …" while tokens arrive.
    if (workspaceId) {
      send('workspace', {
        workspaceId,
        contextInjected: !!projectContext,
        filesReferenced: projectFiles,
      });
    }

    // ── 8. Generate (streamed) ───────────────────────────────────────────────────
    send('stage', { id: 'generate', label: 'Generating response…' });

    const result = await generateTextStream({
      userMessage,
      systemPrompt,
      messages,
      ctx,
      preTaskType:    taskType,
      executionPlan:  plan,
      responseBudget: orchestration.budget,
      clientSignal:   clientAbort.signal,
      onEvent: (ev) => {
        if (ev.type === 'token')            send('token', { t: ev.text });
        else if (ev.type === 'provider_attempt') send('provider', { provider: ev.provider, score: ev.score, attempt: ev.attempt });
        else if (ev.type === 'provider_failed')  send('provider_failed', { provider: ev.provider, reason: ev.reason });
      },
    });

    // ── 8b. Verification — runs AFTER the stream; revision replaces the draft ──
    let finalAnswer = result.text;
    let verification = { ran: false, passed: null, revised: false };
    if (orchestration.verification.enabled && !clientAbort.signal.aborted) {
      send('stage', { id: 'verify', label: 'Verifying answer…' });
      verification = await runVerification({
        orchestration, userMessage, draftAnswer: result.text, taskType, requestId, conversationId,
      });
      if (verification.revised && verification.finalAnswer) {
        finalAnswer = verification.finalAnswer;
        send('replace', { text: finalAnswer });
      }
    }
    logVerificationEvent(ctx, verification);

    // ── 8c. Identity refusal guard (spec: never "I don't know" about self) ──────
    // Runs regardless of whether verification was enabled. If the model hedged
    // on a self-question, replace with the deterministic profile answer and
    // emit `replace` so the UI swaps the draft (same mechanism verification
    // uses). The always-injected identity block makes this path rare.
    let identityGuarded = false;
    if (prep.identityIntent?.isSelf && !clientAbort.signal.aborted && isRefusal(finalAnswer)) {
      const grounded = answerFromIdentity(userMessage);
      if (grounded) {
        console.warn(`[IDENTITY] guard engaged (stream) — substituting profile answer req=${requestId}`);
        finalAnswer = grounded;
        identityGuarded = true;
        send('replace', { text: finalAnswer });
      }
    }

    // ── 9. Persist ───────────────────────────────────────────────────────────────
    addMessage(conversationId, 'user',      userMessage);
    addMessage(conversationId, 'assistant', finalAnswer);

    // ── 9b. Mind post-turn — predictions rebuild + async reflection when due ────
    memoryAfterTurn(prep.memoryOwner, { taskType, workspaceId });

    // ── 10. Done event — same diagnostics shape as POST /chat ───────────────────
    send('done', buildResponsePayload({
      requestId, conversationId, isNew, result, finalAnswer, taskType, confidence,
      promptModules, prep, orchestration, plan, reasoning, intelligence, verification,
      extractedFacts, relevantFacts, contextStats, workspaceId, projectContext, projectFiles,
      identityGuarded,
    }));
  } catch (err) {
    if (err.message === 'CLIENT_ABORTED') {
      // The user stopped generation. Persist exactly what they saw so
      // conversation history matches the screen — never lose the turn.
      const partial = err.partialText ?? '';
      addMessage(conversationId, 'user', userMessage);
      if (partial.trim()) addMessage(conversationId, 'assistant', partial);
      console.log(`[CHAT] stream aborted by client req=${requestId} persistedChars=${partial.length}`);
    } else {
      console.error('[CHAT] Stream request failed:', err.message);
      ctx.attempts ??= [];
      send('error', {
        error:         err?.message ?? 'Internal server error',
        recoverable:   true,
        requestId,
        conversationId,
        fallbackChain: ctx.attempts.map(a => ({ provider: a.provider, outcome: a.outcome })),
      });
    }
  } finally {
    clearInterval(heartbeat);
    closed = true;
    if (!res.writableEnded) res.end();
  }
});

export default router;

/**
AQUA Memory Extractor v3.1 — Orchestrator
*/
import { parseMessage } from './sentenceParser.js';
import { extractAllCandidates } from './candidateExtractor.js';
import { normalizeCandidates } from './entityNormalizer.js';
import { deduplicateIntraMessage } from './duplicateDetector.js';
import { resolveCandidates, RESOLUTION_ACTIONS } from './memoryResolver.js';
import { detectCorrection, CORRECTION_PHRASES } from './memoryConflictResolver.js';
import { getSchema, getWordIndex } from './memorySchema.js';

export { detectCorrection, CORRECTION_PHRASES } from './memoryConflictResolver.js';

/**
 * Fuzzy-resolve a user-provided key to the closest canonical schema key.
 * e.g. "preferred language" → "favorite_language", "score" → "score" (falls back)
 */
export function resolveCanonicalKey(rawKey) {
  const normalized = rawKey.toLowerCase().trim().replace(/\s+/g, '_');
  // Direct hit
  const direct = getSchema(normalized);
  if (direct) return direct.key;
  // Word-index fuzzy match — key words score 3, alias words 2, hint words 1
  const wordIndex = getWordIndex();
  const words = normalized.split('_').filter(w => w.length > 1);
  const scores = new Map();
  words.forEach((word, i) => {
    const hits = wordIndex.get(word);
    if (!hits) return;
    // Head-noun dominance: in an English key phrase the LAST word is the head
    // ("preferred language" → the *language*); modifiers come first. Weight
    // later words higher so a modifier that happens to name another key
    // (e.g. "preferred" → preferred_name) can't outrank the head noun.
    const positional = 1 + i * 0.5;
    for (const k of hits) {
      const schema = getSchema(k);
      if (!schema) continue;
      const inKey     = schema.key.split('_').includes(word);
      const inAlias   = (schema.aliases || []).some(a => a.split('_').includes(word));
      const base      = inKey ? 3 : inAlias ? 2 : 1;
      scores.set(k, (scores.get(k) || 0) + base * positional);
    }
  });
  if (scores.size === 0) return normalized;
  let best = null, bestScore = 0;
  for (const [k, score] of scores) {
    if (score > bestScore) { bestScore = score; best = k; }
  }
  return best || normalized;
}

const log = {
  info: (msg, ...args) => console.log(`[AQUA Pipeline] ${msg}`, ...args),
  debug: (msg, ...args) => console.debug(`[AQUA Pipeline] ${msg}`, ...args),
};

const FORGET_PATTERNS = [/forget (?:that )?(?:my )?(.+)/i, /don't remember (?:that )?(?:my )?(.+)/i];
const UPDATE_PATTERNS = [/(?:actually|correction|update)[,:]?\s+my ([a-zA-Z\s]+?) is now ([a-zA-Z0-9\s]+)/i];

export function extractFactsWithReport(message, ownerId = null) {
  const t0 = Date.now();
  log.info('Pipeline started', { messageLength: message.length, ownerId });

  const report = {
    candidates: 0, accepted: 0, rejected: 0, duplicates: 0,
    updated: 0, overwritten: 0, merged: 0, stored: 0,
    averageConfidence: 0, categories: new Set(), processingTimeMs: 0,
  };

  // 1. Parse — Instrumentation (Req 3): input + normalized sentences
  const parsed = parseMessage(message);
  console.log(`[EXTRACTOR] INPUT "${message.slice(0, 120)}"`);
  console.log(`[EXTRACTOR] NORMALIZED sentences=${parsed.sentences.length} correction=${parsed.isCorrection}${parsed.correctionPhrase ? ` phrase="${parsed.correctionPhrase}"` : ''} → ${JSON.stringify(parsed.sentences.map(x => x.slice(0, 60)))}`);
  if (parsed.sentences.length === 0) {
    report.processingTimeMs = Date.now() - t0;
    return { facts: [], report: finalizeReport(report) };
  }

  // 2. Extract candidates (includes Personal Statement Detector & Custom Fallback)
  const rawCandidates = extractAllCandidates(parsed);
  report.candidates = rawCandidates.length;
  if (rawCandidates.length === 0) {
    report.processingTimeMs = Date.now() - t0;
    return { facts: [], report: finalizeReport(report) };
  }

  // 3. Normalize + validate — Instrumentation: every rejection carries a reason
  const { accepted, rejected } = normalizeCandidates(rawCandidates);
  report.accepted = accepted.length;
  report.rejected += rejected.length;
  for (const r of rejected) {
    console.log(`[EXTRACTOR] REJECTED key=${r.key} value=${JSON.stringify(r.value)} reason=${r.rejectionReason}`);
  }
  if (accepted.length === 0) {
    report.processingTimeMs = Date.now() - t0;
    return { facts: [], report: finalizeReport(report) };
  }

  // 4. Intra-message dedup
  const { unique, duplicates } = deduplicateIntraMessage(accepted);
  report.duplicates += duplicates.length;
  log.debug(`Deduplicated: ${unique.length} unique, ${duplicates.length} duplicates`);

  // 5. Resolve against stored facts
  let toStore = unique;
  if (ownerId) {
    const resolved = resolveCandidates(ownerId, unique);
    toStore = [];
    for (const r of resolved) {
      console.log(`[EXTRACTOR] PROMOTION key=${r.key} action=${r.action} reason=${r.reason}${r.previousValue !== undefined ? ` previous=${JSON.stringify(r.previousValue)}` : ''}`);
      switch (r.action) {
        case RESOLUTION_ACTIONS.STORE_NEW: report.stored++; toStore.push(r); break;
        case RESOLUTION_ACTIONS.OVERWRITE:
        case RESOLUTION_ACTIONS.CORRECTION: report.overwritten++; toStore.push(r); break;
        case RESOLUTION_ACTIONS.MERGE: report.merged++; toStore.push(r); break;
        case RESOLUTION_ACTIONS.DUPLICATE: report.duplicates++; toStore.push({ ...r, _isDuplicate: true }); break;
        case RESOLUTION_ACTIONS.REJECT_LOW_CONF: report.rejected++; break;
      }
      report.categories.add(r.category);
    }
  } else {
    for (const c of unique) {
      report.stored++;
      report.categories.add(c.category);
    }
  }

  // 6. Map to legacy Fact shape
  const facts = toStore.map(toLegacyFact);

  // 7. Average confidence
  if (facts.length > 0) {
    const sum = facts.reduce((s, f) => s + (f.confidence || 0), 0);
    report.averageConfidence = sum / facts.length;
  }

  report.processingTimeMs = Date.now() - t0;
  console.log(`[EXTRACTOR] RESULT stored=${facts.length} rejected=${report.rejected} duplicates=${report.duplicates} avgConf=${report.averageConfidence.toFixed(2)} ms=${report.processingTimeMs}`);
  log.info('Pipeline finished', { finalCount: facts.length, timeMs: report.processingTimeMs });

  return { facts, report: finalizeReport(report) };
}

export function extractFacts(message) {
  const { facts } = extractFactsWithReport(message);
  return facts;
}

export function extractCandidates(message) {
  const parsed = parseMessage(message);
  const raw = extractAllCandidates(parsed);
  const { accepted } = normalizeCandidates(raw);
  return accepted;
}

export function detectMemoryUpdate(message) {
  for (const p of UPDATE_PATTERNS) {
    const m = message.match(p);
    if (m) return { isUpdate: true, key: m[1].toLowerCase().trim().replace(/\s+/g, '_'), value: m[2].trim() };
  }
  return { isUpdate: false };
}

export function detectForget(message) {
  for (const p of FORGET_PATTERNS) {
    const m = message.match(p);
    if (m) return { isForget: true, hint: m[1]?.trim() };
  }
  return { isForget: false };
}

function toLegacyFact(resolved) {
  const value = resolved.mergedValue !== undefined ? resolved.mergedValue : resolved.normalizedValue;
  return {
    key: resolved.key, value, confidence: resolved.confidence, importance: resolved.importance || 5,
    sourceText: (resolved.rawText || '').slice(0, 200), ts: resolved.ts || Date.now(), isCorrection: !!resolved.isCorrection,
    category: resolved.category, normalizedValue: resolved.normalizedValue, sentence: resolved.sentence,
    reason: resolved.reason, action: resolved.action, previousValue: resolved.previousValue, _isDuplicate: resolved._isDuplicate,
    // Memory Confidence Engine (Phase 6): self-contained provenance, carried
    // through longTermMemory's upgradeFact() metadata passthrough.
    metadata: {
      validationStatus: resolved.validationStatus || 'validated',
      entityType: resolved.category,
      sourceSentence: resolved.sentence,
      confidence: resolved.confidence,
    },
  };
}

function finalizeReport(report) {
  return { ...report, categories: Array.from(report.categories) };
}

/**
 * AQUA Conversation Store v3
 *
 * ROOT FIXES (v3 — supersedes v2):
 *   Problem1 (orphan entries): old createConversation() ALWAYS minted its
 *     own internal uuidv4(), silently discarding any id the caller passed
 *     in meta.id. chat.js kept using ITS OWN id for everything downstream
 *     (logging, addMessage, response) while the store quietly held a
 *     permanent 0-message entry under the discarded id. Every first turn
 *     left exactly one orphan behind — confirmed live via repro.
 *   Problem3 (impossible log sequence): chat.js decided CREATED vs REUSED
 *     from "did the client send an id at all", not "does this id actually
 *     exist in the store". Any brand-new caller-supplied id (custom/test
 *     id, or first-ever id under the orphan bug above) got logged as
 *     REUSED on its very first appearance — no prior CREATED log for that
 *     id ever existed. Logically impossible to reuse what was never
 *     created — confirmed live: "[CHAT] CONVERSATION_REUSED id=phase6-simple"
 *     with zero preceding CREATED line for that id anywhere.
 *
 *   FIX: getOrCreateConversation(id, meta) is the new shared layer — ONE
 *   atomic check decides existence, performs the mutation (if needed) AT
 *   THE EXACT id the caller keeps using, and emits the CREATED/REUSED log
 *   itself in the same branch. Log and mutation share one source of truth,
 *   so they can no longer disagree. chat.js is wired to call this instead
 *   of hand-rolling its own conversationExists()+createConversation()
 *   branching. createConversation() stays exported (other callers may still
 *   want "always ensure this id exists") but no longer discards meta.id and
 *   no longer clobbers an existing conversation if that id is already taken.
 *
 * ID contract:
 *   conversationId — stable across entire conversation, generated once by server
 *   requestId      — unique per HTTP request (in observability context, NOT here)
 *   sessionId      — optional: caller's concept, stored as metadata only
 */

import fs   from 'fs';
import path from 'path';
import { v4 as uuidv4 } from 'uuid';

const HISTORY_FILE          = path.join(process.cwd(), '.aqua-history.json');
const MAX_HISTORY_PER_CONV  = 200;  // rolling window cap

// Map<conversationId, { messages: Array, meta: object }>
const store = new Map();

// ── Persistence ───────────────────────────────────────────────────────────────

function loadFromDisk() {
  try {
    if (!fs.existsSync(HISTORY_FILE)) return;
    const raw  = fs.readFileSync(HISTORY_FILE, 'utf8');
    const data = JSON.parse(raw);
    let total  = 0;
    for (const [id, conv] of Object.entries(data)) {
      // Support both old format (array) and new format ({ messages, meta })
      const messages = Array.isArray(conv) ? conv : (conv.messages || []);
      const meta     = Array.isArray(conv) ? {} : (conv.meta || {});
      store.set(id, { messages, meta });
      total += messages.length;
    }
    console.log(`[STORE] Loaded ${store.size} conversations (${total} messages) from disk`);
  } catch (err) {
    console.warn('[STORE] Could not load history from disk:', err.message);
  }
}

let saveTimer = null;
function scheduleSave() {
  if (saveTimer) return;
  saveTimer = setTimeout(() => {
    saveTimer = null;
    try {
      const data = {};
      for (const [id, conv] of store.entries()) {
        data[id] = conv;
      }
      fs.writeFileSync(HISTORY_FILE, JSON.stringify(data), 'utf8');
    } catch (err) {
      console.warn('[STORE] Could not save history to disk:', err.message);
    }
  }, 500);
}

loadFromDisk();

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Ensure a conversation exists. If meta.id is supplied and already exists,
 * this is a no-op (never clobbers existing messages). If meta.id is
 * supplied and is new, the conversation is created AT THAT id (this is the
 * Problem1 fix — the old version silently minted a different id here).
 * If no meta.id is supplied, a fresh UUID is minted, matching old behavior
 * for any caller that never passed an id.
 *
 * Most callers wanting "create or get, and tell me which happened" should
 * use getOrCreateConversation() instead — it's atomic and also drives the
 * CREATED/REUSED log from the same check, so it can't disagree with itself.
 *
 * @param {object} [meta]  - optional metadata: { id, userId, sessionId, userAgent }
 * @returns {string} conversationId (the id used — caller's id if provided)
 */
export function createConversation(meta = {}) {
  const { id: requestedId, ...rest } = meta;

  if (requestedId && store.has(requestedId)) {
    console.log(`[STORE] createConversation no-op, already exists id=${requestedId}`);
    return requestedId;
  }

  const id = requestedId || uuidv4();
  store.set(id, { messages: [], meta: { createdAt: Date.now(), ...rest } });
  scheduleSave();
  console.log(`[STORE] CREATED conversation=${id}`);
  return id;
}

/**
 * Shared layer — single atomic create-or-get. THE authoritative source of
 * truth for "is this conversation new". The store mutation and the
 * CREATED/REUSED log happen together, in the same branch, so they cannot
 * diverge (this is the Problem3 fix).
 *
 * @param {string|null|undefined} id  - caller-supplied id, or falsy to mint one
 * @param {object} [meta]             - metadata for a freshly created conversation (ignored on reuse)
 * @returns {{ id: string, isNew: boolean }}
 */
export function getOrCreateConversation(id, meta = {}) {
  if (id && store.has(id)) {
    console.log(`[STORE] REUSED conversation=${id}`);
    return { id, isNew: false };
  }

  const finalId = id || uuidv4();
  store.set(finalId, { messages: [], meta: { createdAt: Date.now(), ...meta } });
  scheduleSave();
  console.log(`[STORE] CREATED conversation=${finalId}`);
  return { id: finalId, isNew: true };
}

/**
 * Check if a conversation exists.
 * Used by other routes (conversations.js, memory.js) for existence checks
 * that don't need create-on-miss semantics.
 */
export function conversationExists(id) {
  return typeof id === 'string' && id.length > 0 && store.has(id);
}

/**
 * Get message history for a conversation.
 * Returns empty array (not null) for unknown IDs.
 * Does NOT auto-create — use createConversation() explicitly.
 */
export function getConversation(id) {
  const conv = store.get(id);
  if (!conv) {
    console.warn(`[STORE] getConversation miss id=${id} — returning []`);
    return [];
  }
  return conv.messages;
}

/**
 * Append a message to a conversation.
 * Auto-creates if missing (defensive — shouldn't normally happen).
 */
export function addMessage(id, role, content) {
  if (!store.has(id)) {
    console.warn(`[STORE] addMessage: conversation ${id} not found — auto-creating`);
    store.set(id, { messages: [], meta: { autoCreated: true } });
  }

  const { messages } = store.get(id);
  messages.push({ role, content, ts: Date.now() });

  // Rolling window — keep only the last N messages
  if (messages.length > MAX_HISTORY_PER_CONV) {
    messages.splice(0, messages.length - MAX_HISTORY_PER_CONV);
  }

  scheduleSave();
  return messages;
}

/**
 * Get conversation metadata.
 */
export function getConversationMeta(id) {
  return store.get(id)?.meta || null;
}

/**
 * Clear a conversation (history + metadata).
 */
export function clearConversation(id) {
  store.delete(id);
  scheduleSave();
}

/**
 * Return all conversations (for admin/debug use only).
 */
export function getAllConversations() {
  return store;
}

/**
 * Return summary stats for health endpoint.
 */
export function getStoreStats() {
  let totalMessages = 0;
  for (const { messages } of store.values()) totalMessages += messages.length;
  return { conversations: store.size, totalMessages };
}

/**
AQUA Candidate Extractor v3.1
*/
import { MEMORY_SCHEMA, getSchema, CATEGORIES, CONFLICT_POLICIES } from './memorySchema.js';

const log = {
  debug: (msg, ...args) => console.debug(`[AQUA Extractor] ${msg}`, ...args),
};

// ── Personal Statement Detector ───────────────────────────────────────────────
function isPersonalStatement(sentence) {
  // v3 (Extraction Audit): "This is John" is a self-introduction with no
  // first-person pronoun — allow the greeting form through the gate.
  // v4 (Cognitive Identity): "Also known as CP" / "aka CP" are self-referential
  // alias declarations, also pronoun-free — let them through too.
  return /\b(i|my|me|mine|we|our|us|myself|i'm|i've|i'll|i'd)\b/i.test(sentence)
      || /^(?:hi|hey|hello|yo|greetings)?[,!.\s]*this is\b/i.test(sentence)
      || /^\s*(?:also known as|a\.?k\.?a\.?\b)/i.test(sentence);
}

// ── Confidence Adjuster ───────────────────────────────────────────────────────
function adjustConfidence(candidate, sentence) {
  let conf = candidate.confidence;
  if (/\b(maybe|perhaps|guess|think|probably|might|could be|sort of|kind of)\b/i.test(sentence)) {
    conf *= 0.8; // Hedging
  }
  if (/\b(definitely|certainly|absolutely|actually|fact is|explicitly)\b/i.test(sentence)) {
    conf = Math.min(0.99, conf + 0.05); // Explicit
  }
  candidate.confidence = parseFloat(conf.toFixed(2));
  return candidate;
}

// ── Custom Fact Extractor (Fallback) ──────────────────────────────────────────
// v2 FIX (Memory Confidence Engine): "I am building an AI" / "I am coding a
// feature" describe a transient activity, not an identity/trait — they must
// never be stored. Without this guard, extractCustomFacts's "i am X" pattern
// captured the entire remainder of the sentence as custom_trait whenever the
// schema-level name pattern didn't match first (see memorySchema.js 'intro').
const ACTIVITY_STATEMENT = /^[a-z]+ing\b/i;
// v3 (Extraction Audit): widening the fallback to "i'm X" made transient
// states ("I'm sure/tired/busy…") storable as custom_trait. Moods are not
// durable memories.
const TRANSIENT_STATE = /^(sure|tired|busy|happy|sad|fine|okay|ok|good|great|glad|sorry|ready|done|back|free|late|early|lost|stuck|confused|curious|excited|afraid|scared|bored|hungry|thirsty|sick|well|here|there|home|away|online|offline|not|no|so|just|about|almost|kind|sort)\b/i;

// v4 (Cognitive Identity): stable, collision-free key from free text. The old
// fallback stored EVERY "I'm X" trait under the single key `custom_trait` with
// an OVERWRITE policy, so two unrelated traits ("I'm a night owl", later "I'm
// left-handed") clobbered each other — and worse, any identity phrase that
// slipped past the schema landed here and was later destroyed by the next
// custom fact. Deriving the key from the value gives each trait its own field.
function customSlug(value) {
  return 'custom_' + String(value).toLowerCase()
    .replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 40);
}

function extractCustomFacts(sentence, ctx) {
  const candidates = [];
  const patterns = [
    { regex: /my ([a-z\s]+?) is ([a-z0-9\s]+)/i, keyGen: (m) => `custom_${m[1].trim().replace(/\s+/g, '_')}`, valGen: (m) => m[2].trim() },
    // Per-value key (was the single collision-prone `custom_trait`).
    { regex: /i(?:'m| am) (?:a |an )?([a-z\s]+?)(?:\s*[,.]|$)/i, keyGen: (m) => customSlug(m[1].trim()), valGen: (m) => m[1].trim(), guard: (v) => !ACTIVITY_STATEMENT.test(v) && !TRANSIENT_STATE.test(v) },
  ];

  for (const p of patterns) {
    const m = sentence.match(p.regex);
    if (m) {
      const key = p.keyGen(m);
      const value = p.valGen(m);
      if (value && value.length > 0 && (!p.guard || p.guard(value))) {
        candidates.push({
          extractor: 'custom_fallback',
          category: CATEGORIES.CUSTOM, key, value, normalizedValue: value,
          confidence: 0.7, rawText: sentence, sentence, reason: 'custom_fact',
          isCorrection: !!ctx.isCorrection, ts: ctx.ts || Date.now(),
          multiValue: false, conflictPolicy: CONFLICT_POLICIES.OVERWRITE, importance: 4,
        });
      }
    }
  }
  return candidates;
}

// ── Main Extraction Logic ─────────────────────────────────────────────────────
export function extractCandidatesFromSentence(sentence, ctx = {}) {
  if (!sentence || typeof sentence !== 'string') return [];

  // 1. Personal Statement Detector
  if (!isPersonalStatement(sentence) && !ctx.isCorrection) {
    return [];
  }

  const candidates = [];
  const seenKeys = new Set();

  // 2. Schema-based Extraction
  for (const schema of MEMORY_SCHEMA) {
    if (seenKeys.has(schema.key) && !schema.multiValue) continue;

    // Compound patterns (e.g., pets) — supports global flag for matchAll
    if (Array.isArray(schema.compoundPatterns)) {
      for (const cp of schema.compoundPatterns) {
        const isGlobal = cp.regex.flags.includes('g');
        const matches = isGlobal
          ? [...sentence.matchAll(cp.regex)]
          : (() => { const m = sentence.match(cp.regex); return m ? [m] : []; })();

        let matched = false;
        for (const m of matches) {
          try {
            const item = cp.buildItem(m);
            if (!item) continue;
            candidates.push(makeCandidate(schema, item, sentence, { reason: cp.reason, confidence: cp.confidence ?? schema.baseConfidence, ctx }));
            matched = true;
            if (!schema.multiValue) { seenKeys.add(schema.key); break; }
          } catch (err) { /* skip malformed */ }
        }
        if (matched && !schema.multiValue) break;
      }
      continue;
    }

    // Simple & MultiKey patterns
    if (!Array.isArray(schema.patterns)) continue;
    for (const pattern of schema.patterns) {
      const m = sentence.match(pattern.regex);
      if (!m) continue;

      // MultiKey support (e.g., Location Context)
      if (pattern.multiKey) {
        try {
          const transformed = pattern.transform(m);
          if (transformed && typeof transformed === 'object') {
            for (const [key, value] of Object.entries(transformed)) {
              const subSchema = getSchema(key);
              if (subSchema) {
                candidates.push(makeCandidate(subSchema, value, sentence, { reason: pattern.reason, confidence: pattern.confidence ?? subSchema.baseConfidence, ctx }));
              }
            }
          }
        } catch (err) { /* skip */ }
        seenKeys.add(schema.key);
        break;
      }

      // Standard single value
      let value;
      try {
        value = pattern.transform ? pattern.transform(m) : (m[pattern.group ?? 1] ?? '').trim();
      } catch (err) { continue; }

      if (value === undefined || value === null || value === '') continue;
      if (typeof value === 'string' && value.length < 2) continue;

      candidates.push(makeCandidate(schema, value, sentence, { reason: pattern.reason, confidence: pattern.confidence ?? schema.baseConfidence, ctx }));
      seenKeys.add(schema.key);
      break; 
    }
  }

  // 3. Custom Fact Fallback
  if (candidates.length === 0) {
    const customFacts = extractCustomFacts(sentence, ctx);
    candidates.push(...customFacts);
  }

  // 4. Dynamic Confidence Assignment
  return candidates.map(c => adjustConfidence(c, sentence));
}

export function extractAllCandidates(parsed) {
  const all = [];
  for (const sentence of parsed.sentences) {
    const cs = extractCandidatesFromSentence(sentence, {
      isCorrection: parsed.isCorrection,
      correctionPhrase: parsed.correctionPhrase,
      ts: parsed.ts,
    });
    // Instrumentation (Extraction Audit Req 3): every sentence prints what
    // matched — pattern, extractor, fact, confidence — or an explicit miss.
    if (cs.length) {
      for (const c of cs) {
        console.log(`[EXTRACTOR] MATCH sentence="${sentence.slice(0, 80)}" extractor=${c.extractor} pattern=${c.reason} → ${c.key}=${JSON.stringify(c.value)} conf=${c.confidence}`);
      }
    } else {
      console.log(`[EXTRACTOR] NO_MATCH sentence="${sentence.slice(0, 80)}" personal=${isPersonalStatement(sentence)}`);
    }
    all.push(...cs);
  }
  log.debug(`Extracted ${all.length} raw candidates from ${parsed.sentences.length} sentences`);
  return all;
}

function makeCandidate(schema, value, sentence, { reason, confidence, ctx }) {
  return {
    extractor: 'schema',
    category: schema.category, key: schema.key, value, normalizedValue: null,
    confidence, rawText: sentence, sentence, reason,
    isCorrection: !!ctx.isCorrection, correctionPhrase: ctx.correctionPhrase,
    ts: ctx.ts || Date.now(), multiValue: !!schema.multiValue,
    conflictPolicy: schema.conflictPolicy, importance: schema.importance,
  };
}

/**
 * AQUA Identity Migration — legacy `custom_trait` → canonical identity / de-collided customs
 * ─────────────────────────────────────────────────────────────────────────────
 * Runs ONCE at boot, after the store-unification migration. Idempotent: each
 * mind is flagged `_identityMigrated` and skipped on the next run.
 *
 * Before v4, three things could land in the single OVERWRITE-policy fact key
 * `custom_trait`, each destroying the last:
 *   • a role+company blob  ("the founder of Aquiplex")  — should be identity
 *   • a personal trait     ("a night owl")               — a legitimate custom
 *   • an intro name         (rare, if the schema missed it)
 *
 * This pass repairs existing data WITHOUT guessing:
 *   1. If the value has an unambiguous role-of-org shape ("[the] ROLE of/at
 *      ORG"), promote it to `profession` + `workplace` (the identity fields),
 *      through the normal conflict-resolving store (never a blind overwrite).
 *   2. Otherwise, de-collide the shared bucket into a per-value key
 *      (`custom_<slug>`) so it stops overwriting future custom facts.
 *   Nothing is dropped. Ambiguous free text (including bare names) is preserved
 *   as a custom fact rather than mis-promoted — forward extraction, now fixed,
 *   captures names correctly from here on.
 */
import { _iterateMindsForStats, touchMind } from '../mind/mindStore.js';
import { storeFact } from './longTermMemory.js';
import { CATEGORIES } from './memorySchema.js';

// Unambiguous "[the/a/an] ROLE of|at|for ORG" — the exact shape that used to
// rot inside custom_trait. Conservative on purpose: we only auto-promote when
// the structure is unmistakable.
const ROLE_OF_ORG = /^(?:the\s+|a\s+|an\s+)?([a-z][a-z\s-]{1,30}?)\s+(?:of|at|for)\s+([A-Za-z0-9][A-Za-z0-9&.'\s-]{1,40})$/i;
const FOUNDER_OF   = /^(co-?)?founder\s+of\s+([A-Za-z0-9][A-Za-z0-9&.'\s-]{1,40})$/i;

function titleCase(s) { return String(s).trim().replace(/\b\w/g, c => c.toUpperCase()); }

function structuredIdentity(text) {
  const t = String(text).trim();
  let m = t.match(FOUNDER_OF);
  if (m) return [{ key: 'profession', value: m[1] ? 'Co-founder' : 'Founder' }, { key: 'workplace', value: m[2].trim() }];
  m = t.match(ROLE_OF_ORG);
  if (m) return [{ key: 'profession', value: m[1].trim() }, { key: 'workplace', value: m[2].trim() }];
  return null;
}

function customSlug(value) {
  return 'custom_' + String(value).toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 40);
}

export function migrateIdentity() {
  let owners = 0, reclassified = 0, decollided = 0, scanned = 0;

  for (const mind of _iterateMindsForStats()) {
    if (!mind || mind._identityMigrated || mind.adoptedInto) continue;
    scanned++;
    const owner = mind.ownerId;
    const facts = mind.facts || {};
    let changed = false;

    // Only the collided shared bucket is ambiguous enough to need repair.
    const legacy = facts['custom_trait'];
    if (legacy && typeof legacy.value === 'string' && legacy.value.trim()) {
      const text = legacy.value.trim();
      const ident = structuredIdentity(text);
      if (ident) {
        for (const u of ident) {
          storeFact(owner, {
            key: u.key, value: u.value,
            confidence: Math.max(0.6, (legacy.confidence ?? 0.7)),
            importance: 8, category: CATEGORIES.WORK,
            sourceText: `migrated from custom_trait: "${text}"`,
            ts: legacy.ts || legacy.updatedAt || Date.now(),
          });
        }
        delete facts['custom_trait'];
        reclassified++; changed = true;
        console.log(`[MIGRATE] Identity: owner=${owner} promoted custom_trait "${text}" → role=${titleCase(ident[0].value)} company="${ident[1].value}"`);
      } else {
        const slug = customSlug(text);
        if (slug !== 'custom_' && !facts[slug]) facts[slug] = { ...legacy, key: slug, id: `${owner}:${slug}` };
        delete facts['custom_trait'];
        decollided++; changed = true;
        console.log(`[MIGRATE] Identity: owner=${owner} de-collided custom_trait → ${slug}`);
      }
    }

    mind._identityMigrated = true;
    if (changed) owners++;
    touchMind(mind); // persist the migration flag even when nothing changed
  }

  console.log(`[MIGRATE] Identity pass: mindsScanned=${scanned} ownersRepaired=${owners} reclassified=${reclassified} decollided=${decollided}`);
  return { owners, reclassified, decollided, scanned };
}

/**
AQUA Entity Normalizer v3.1
*/
import { getSchema, CATEGORIES } from './memorySchema.js';

const log = {
  debug: (msg, ...args) => console.debug(`[AQUA Normalizer] ${msg}`, ...args),
  warn: (msg, ...args) => console.warn(`[AQUA Normalizer] ${msg}`, ...args),
};

export function normalizeCandidates(candidates) {
  const accepted = [];
  const rejected = [];

  for (const c of candidates) {
    // Custom facts have no schema entry — accept with passthrough normalization
    if (c.category === CATEGORIES.CUSTOM) {
      const normalized = (c.value || '').trim();
      if (!normalized) {
        rejected.push({ ...c, rejectionReason: 'empty_after_normalize', validationStatus: 'rejected' });
        continue;
      }
      accepted.push({ ...c, normalizedValue: normalized, validationStatus: 'validated' });
      continue;
    }

    const schema = getSchema(c.key);
    if (!schema) {
      rejected.push({ ...c, rejectionReason: 'no_schema', validationStatus: 'rejected' });
      continue;
    }

    let normalized = c.value;
    try {
      if (typeof schema.normalizer === 'function') {
        normalized = schema.normalizer(c.value);
      }
    } catch (err) {
      rejected.push({ ...c, rejectionReason: 'normalizer_error', error: err.message, validationStatus: 'rejected' });
      continue;
    }

    if (normalized === null || normalized === undefined || normalized === '') {
      rejected.push({ ...c, rejectionReason: 'empty_after_normalize', validationStatus: 'rejected' });
      continue;
    }

    if (Array.isArray(normalized)) {
      normalized = normalized.filter((v) => v !== null && v !== undefined && v !== '');
      if (normalized.length === 0) {
        rejected.push({ ...c, rejectionReason: 'empty_array_after_normalize', validationStatus: 'rejected' });
        continue;
      }
    }

    if (typeof schema.validator === 'function') {
      try {
        if (!schema.validator(normalized)) {
          rejected.push({ ...c, normalizedValue: normalized, rejectionReason: 'validation_failed', validationStatus: 'rejected' });
          log.debug(`Rejected ${c.key} due to validation failure`, { value: normalized });
          continue;
        }
      } catch (err) {
        rejected.push({ ...c, rejectionReason: 'validator_error', error: err.message, validationStatus: 'rejected' });
        continue;
      }
    }

    accepted.push({ ...c, normalizedValue: normalized, validationStatus: 'validated' });
  }

  log.debug(`Normalized ${accepted.length} candidates, rejected ${rejected.length}`);
  return { accepted, rejected };
}

export function normalizeCandidate(candidate) {
  const { accepted, rejected } = normalizeCandidates([candidate]);
  return accepted[0] || rejected[0] || null;
}

/**
 * AQUA Memory Migration — legacy `.aqua-memory.json` → unified Mind store.
 * ─────────────────────────────────────────────────────────────────────────────
 * Runs ONCE at boot (idempotent: source file is renamed after success, so a
 * restart is a no-op). Nothing is lost:
 *
 *   conversation-keyed facts → owner-keyed facts
 *     conversation has meta.userId  → `user:<userId>`   (the real owner)
 *     otherwise                     → `conv:<convId>`   (adopted on login,
 *                                     see ownerResolver.resolveOwner)
 *
 * When several conversations of one user carried the same key, facts merge
 * through storeFact's conflict resolver — newer/higher-confidence wins,
 * history preserved. Exactly the semantics a live overwrite would have had.
 */
import fs from 'fs';
import path from 'path';
import { storeFact } from './longTermMemory.js';
import { getConversationMeta } from './conversationStore.js';
import { ownerForUser, ownerForConversation } from './ownerResolver.js';

const LEGACY_FILE = path.join(process.cwd(), '.aqua-memory.json');

export function migrateLegacyMemory() {
  if (!fs.existsSync(LEGACY_FILE)) return { migrated: false };

  let data;
  try {
    data = JSON.parse(fs.readFileSync(LEGACY_FILE, 'utf8'));
  } catch (err) {
    console.warn('[MIGRATE] Legacy memory file unreadable — leaving untouched:', err.message);
    return { migrated: false, error: err.message };
  }

  let facts = 0;
  let conversations = 0;
  let toUsers = 0;

  for (const [conversationId, factsObj] of Object.entries(data)) {
    conversations++;
    const meta = getConversationMeta(conversationId);
    const owner = meta?.userId
      ? ownerForUser(meta.userId)
      : ownerForConversation(conversationId);
    if (meta?.userId) toUsers++;

    for (const fact of Object.values(factsObj || {})) {
      storeFact(owner, { ...fact, sourceConversation: conversationId });
      facts++;
    }
  }

  const archived = `${LEGACY_FILE}.migrated-${Date.now()}`;
  try {
    fs.renameSync(LEGACY_FILE, archived);
  } catch (err) {
    console.warn('[MIGRATE] Could not archive legacy file:', err.message);
  }

  console.log(`[MIGRATE] Legacy memory unified: conversations=${conversations} facts=${facts} userOwned=${toUsers} → ${path.basename(archived)}`);
  return { migrated: true, conversations, facts, toUsers };
}

/**
 * AQUA Sentence Parser v3
 * ─────────────────────────────────────────────────────────────────────────────
 * Splits a user message into atomic sentences and detects correction intent.
 * Single pass — no repeated scans.
 */
import { detectCorrection } from './memoryConflictResolver.js';

/**
 * Split text into sentences.
 * Handles abbreviations (Mr., Dr., etc.) and common edge cases.
 * @param {string} text
 * @returns {string[]}
 */
export function splitSentences(text) {
  if (!text || typeof text !== 'string') return [];
  const cleaned = text.replace(/\s+/g, ' ').trim();
  if (!cleaned) return [];

  // Protect common abbreviations by temporarily replacing their periods
  const abbrevs = ['mr', 'mrs', 'ms', 'dr', 'prof', 'sr', 'jr', 'vs', 'etc', 'inc', 'ltd', 'co', 'corp'];
  let protected_ = cleaned;
  abbrevs.forEach((a) => {
    const re = new RegExp(`\\b${a}\\.`, 'gi');
    protected_ = protected_.replace(re, (m) => m.replace('.', '•'));
  });

  // Split on sentence-ending punctuation followed by space or end
  const raw = protected_.split(/(?<=[.!?])\s+(?=[A-Z"'])/);

  // Restore protected periods and trim
  return raw
    .map((s) => s.replace(/•/g, '.').trim())
    .filter((s) => s.length > 0);
}

/**
 * Parse a message into sentences + correction metadata.
 * Single entry point for the pipeline.
 *
 * @param {string} message
 * @returns {{
 *   sentences: string[],
 *   isCorrection: boolean,
 *   correctionPhrase: string | undefined,
 *   originalMessage: string,
 *   ts: number,
 * }}
 */
export function parseMessage(message) {
  const ts = Date.now();
  if (!message || typeof message !== 'string') {
    return { sentences: [], isCorrection: false, correctionPhrase: undefined, originalMessage: '', ts };
  }
  const trimmed = message.trim();
  const { isCorrection, phrase } = detectCorrection(trimmed);
  const sentences = splitSentences(trimmed);
  return {
    sentences,
    isCorrection,
    correctionPhrase: phrase,
    originalMessage: trimmed,
    ts,
  };
}

/**
AQUA Memory Retriever v4
─────────────────────────────────────────────────────────────────────────────
Semantic retrieval engine with multi-dimensional scoring, context budgeting, 
and grouped prompt injection.
*/
import { getFacts } from './longTermMemory.js';
import { getSchema, getSchemaByCategory, getWordIndex, CATEGORIES, SEMANTIC_CONCEPTS, CATEGORY_ALIASES } from './memorySchema.js';

// ── Recall trigger detection ──────────────────────────────────────────────────
const RECALL_PATTERNS = [
  /what(?:'s| is) my \b/i, /do you (?:remember|know|recall)/i,
  /what did i (?:say|tell you|mention)/i, /i (?:told|mentioned|said) (?:you )?(?:earlier|before|that)/i,
  /what (?:was|were|is|are) my \b/i, /remember (?:when|that) i\b/i,
  /what (?:have )?you (?:learned|know) about me/i, /tell me (?:everything )?(?:you know )?about me/i,
  /what do you know about me/i,
];

export function isMemoryQuery(query) {
  return RECALL_PATTERNS.some((p) => p.test(query));
}

// ── Intent & Semantic Detection ───────────────────────────────────────────────
const CATEGORY_INTENT_PATTERNS = [
  { pattern: /\b(preference|preferences|likes|favorites|favourites|fav)\b/i, category: CATEGORIES.PREFERENCES },
  { pattern: /\b(pet|pets|dog|cat|animal|animals)\b/i, category: CATEGORIES.PETS },
  { pattern: /\b(food|foods|meal|meals|cuisine|eat|eating)\b/i, category: CATEGORIES.FOOD },
  { pattern: /\b(family|wife|husband|spouse|partner|kid|kids|children|son|daughter|brother|sister|parent|mom|dad)\b/i, category: CATEGORIES.FAMILY },
  { pattern: /\b(work|job|career|profession|employer|company|boss)\b/i, category: CATEGORIES.WORK },
  { pattern: /\b(location|city|country|live|lives|hometown|where)\b/i, category: CATEGORIES.LOCATION },
  { pattern: /\b(hobby|hobbies|interest|interests|pastime)\b/i, category: CATEGORIES.LIFESTYLE },
  { pattern: /\b(goal|goals|objective|objectives|aim|aims|ambition)\b/i, category: CATEGORIES.GOALS },
  { pattern: /\b(language|languages|programming|coding|code)\b/i, category: CATEGORIES.PROGRAMMING },
  { pattern: /\b(framework|frameworks|library|libraries|tech stack)\b/i, category: CATEGORIES.TECHNOLOGY },
  { pattern: /\b(identity|name|age|birthday|born|pronouns)\b/i, category: CATEGORIES.IDENTITY },
];

const SEMANTIC_PATTERNS = [
  { pattern: /\b(programming|coding|tech|development)\s*(stack|setup|environment|tools)\b/i, concept: 'programming stack' },
  { pattern: /\b(food|diet|eating|meals|cuisine)\b/i, concept: 'food' },
  { pattern: /\b(family|relatives|wife|husband|kids|children|parents)\b/i, concept: 'family' },
  { pattern: /\b(travel|trips|vacations|countries visited)\b/i, concept: 'travel' },
  { pattern: /\b(enjoy|like to do|hobbies|pastimes|fun)\b/i, concept: 'enjoy' },
  { pattern: /\b(entertainment|movies|books|music|media)\b/i, concept: 'entertainment' },
  { pattern: /\b(goals|ambitions|dreams|objectives)\b/i, concept: 'goals' },
];

function detectCategoryIntent(query) {
  const matches = new Set();
  for (const { pattern, category } of CATEGORY_INTENT_PATTERNS) {
    if (pattern.test(query)) matches.add(category);
  }
  const tokens = query.toLowerCase().match(/\b[a-z]+\b/g) || [];
  for (const token of tokens) {
    if (CATEGORY_ALIASES[token]) matches.add(CATEGORY_ALIASES[token]);
  }
  return matches.size > 0 ? matches : null;
}

function detectSemanticConcepts(query) {
  const concepts = new Set();
  for (const { pattern, concept } of SEMANTIC_PATTERNS) {
    if (pattern.test(query)) concepts.add(concept);
  }
  return concepts;
}

function detectKeyIntent(query) {
  const index = getWordIndex();
  const tokens = query.toLowerCase().match(/[a-z_]+/g) || [];
  const keyScores = new Map();
  for (const token of tokens) {
    const keys = index.get(token);
    if (keys) {
      for (const key of keys) {
        keyScores.set(key, (keyScores.get(key) || 0) + 1);
      }
    }
  }
  return keyScores;
}

// ── Multi-Dimensional Scoring ─────────────────────────────────────────────────
// Returns { score, intentScore }: intentScore is the portion earned from the
// QUERY's detected intent (category / semantic concept / key tokens / value /
// hints). retrieveRelevantFacts() uses it to drop facts that matched nothing
// about a directed query — previously a high-importance food fact leaked into
// "what programming stack do I use?" purely on base importance + recency.
function scoreRelevance(fact, query, ctx) {
  let score = 0;
  let intentScore = 0;

  // 1. Base Importance & Confidence (Ensures high importance never ranks below low)
  score += (fact.importance || 5) * 15; 
  score += (fact.confidence || 0.5) * 20; 

  // 2. Explicit Recall (e.g., "What do you know about me?")
  if (ctx.isRecall && !ctx.categoryFilter && ctx.semanticConcepts.size === 0) {
    score += 1000; 
  }

  // 3. Category Filter Match
  if (ctx.categoryFilter && ctx.categoryFilter.has(fact.category)) {
    score += 500;
    intentScore += 500;
  }

  // 4. Semantic Concept Match
  for (const concept of ctx.semanticConcepts) {
    const keys = SEMANTIC_CONCEPTS[concept] || [];
    if (keys.includes(fact.key)) {
      score += 400;
      intentScore += 400;
    }
  }

  // 5. Key Intent Match (from word index)
  const keyScore = ctx.keyScores.get(fact.key) || 0;
  score += keyScore * 60;
  intentScore += keyScore * 60;

  // 6. Value-based matching
  const qLower = query.toLowerCase();
  const valueStr = typeof fact.value === 'string' 
    ? fact.value.toLowerCase() 
    : JSON.stringify(fact.value).toLowerCase();
  if (valueStr && valueStr.length > 2 && qLower.includes(valueStr)) {
    score += 150;
    intentScore += 150;
  }

  // 7. Retrieval Hints Match
  const schema = getSchema(fact.key);
  if (schema?.retrievalHints) {
    for (const hint of schema.retrievalHints) {
      if (qLower.includes(hint.toLowerCase())) {
        score += 100;
        intentScore += 100;
        break;
      }
    }
  }

  // 8. Recency Boost
  const ageMs = Date.now() - (fact.ts || fact.updatedAt || 0);
  if (ageMs < 60_000) score += 40;
  else if (ageMs < 600_000) score += 20;
  else if (ageMs < 3_600_000) score += 10;

  return { score, intentScore };
}

// ── Public retrieval API ──────────────────────────────────────────────────────
export function retrieveRelevantFacts(ownerId, query, limit = 15, { trace = null } = {}) {
  const allFacts = getFacts(ownerId);
  if (!allFacts.length) return [];

  const isRecall = isMemoryQuery(query);
  const categoryFilter = detectCategoryIntent(query);
  const semanticConcepts = detectSemanticConcepts(query);
  const keyScores = detectKeyIntent(query);

  const ctx = { isRecall, categoryFilter, semanticConcepts, keyScores };

  const scored = allFacts
    .filter((f) => (f.confidence || 0) >= 0.5)
    .map((f) => ({ fact: f, ...scoreRelevance(f, query, ctx) }))
    .sort((a, b) => b.score - a.score);

  console.log(`[MEM_RETRIEVER] MEMORY_RANKED owner=${ownerId} query="${query}" candidates=${scored.length}`);

  let threshold = 0;
  if (!isRecall && (!categoryFilter || categoryFilter.size === 0) && semanticConcepts.size === 0) {
    threshold = 50; 
  }

  // Directed-query relevance gate: when the query names a category or a
  // semantic concept ("what programming stack…", "what food…"), a fact
  // that earned ZERO intent score matched nothing about the question —
  // exclude it, no matter how important it is in general. Recall queries
  // ("what do you know about me?") and generic queries are untouched.
  const hasDirectedIntent =
    (categoryFilter && categoryFilter.size > 0) || semanticConcepts.size > 0;

  const filtered = scored.filter((x) =>
    x.score >= threshold && (!hasDirectedIntent || x.intentScore > 0));

  if (filtered.length > 0) {
    console.log(`[MEM_RETRIEVER] MEMORY_RETRIEVED owner=${ownerId} count=${filtered.length} topScore=${filtered[0].score}`);
  }

  const top = filtered.slice(0, limit);
  if (trace) {
    trace.ranking = top.map((x) => ({
      key: x.fact.key, score: x.score, intentScore: x.intentScore,
      confidence: x.fact.confidence, importance: x.fact.importance,
      reason: x.intentScore > 0 ? 'intent_match' : (isRecall ? 'recall_query' : 'importance_recency'),
    }));
    trace.consideredFacts = scored.length;
    trace.droppedByGate = scored.length - filtered.length;
  }
  return top.map((x) => x.fact);
}

// ── Prompt formatting & Grouping ──────────────────────────────────────────────
const FACT_LABELS = {
  name: 'Name', age: 'Age', birthday: 'Birthday', gender: 'Gender', ethnicity: 'Ethnicity',
  city: 'City', country: 'Country', profession: 'Profession', company: 'Company', 
  years_experience: 'Years of Experience', pets: 'Pets', favorite_language: 'Favorite Programming Language',
  least_favorite_language: 'Disliked Languages', favorite_color: 'Favorite Color', 
  favorite_food: 'Favorite Food', disliked_food: 'Disliked Food', languages: 'Programming Languages',
  favorite_editor: 'Favorite Editor', favorite_os: 'Operating System', hobbies: 'Hobbies', goal: 'Goals',
  spouse: 'Spouse', children: 'Children', frameworks: 'Frameworks', hardware: 'Hardware',
};

const CATEGORY_LABELS = {
  [CATEGORIES.IDENTITY]: 'Identity', [CATEGORIES.LOCATION]: 'Location',
  [CATEGORIES.WORK]: 'Work & Career', [CATEGORIES.EDUCATION]: 'Education',
  [CATEGORIES.FAMILY]: 'Family', [CATEGORIES.PETS]: 'Pets',
  [CATEGORIES.PREFERENCES]: 'Preferences', [CATEGORIES.TECHNOLOGY]: 'Technology & Setup',
  [CATEGORIES.PROGRAMMING]: 'Programming', [CATEGORIES.PROJECTS]: 'Projects',
  [CATEGORIES.LIFESTYLE]: 'Lifestyle & Hobbies', [CATEGORIES.TRAVEL]: 'Travel',
  [CATEGORIES.HEALTH]: 'Health & Diet', [CATEGORIES.ENTERTAINMENT]: 'Entertainment',
  [CATEGORIES.GOALS]: 'Goals & Ambitions', [CATEGORIES.FOOD]: 'Food & Drink',
  [CATEGORIES.CUSTOM]: 'Other Details',
};

export function formatFactsForPrompt(facts) {
  if (!facts || !facts.length) return '';

  const grouped = new Map();
  for (const fact of facts) {
    if (fact.value === undefined || fact.value === null || (fact.confidence || 0) < 0.55) continue;
    const cat = fact.category || CATEGORIES.CUSTOM;
    if (!grouped.has(cat)) grouped.set(cat, []);
    grouped.get(cat).push(fact);
  }

  if (grouped.size === 0) return '';

  const lines = [];
  for (const [cat, catFacts] of grouped.entries()) {
    const catLabel = CATEGORY_LABELS[cat] || cat;
    lines.push(`\n### ${catLabel}`);
    for (const f of catFacts) {
      const label = FACT_LABELS[f.key] || f.key.replace(/_/g, ' ');
      const value = formatValue(f.value);
      lines.push(`- ${label}: ${value}`);
    }
  }

  console.log(`[MEM_RETRIEVER] MEMORY_GROUPED categories=${Array.from(grouped.keys()).join(',')}`);
  console.log(`[MEM_RETRIEVER] MEMORY_SUMMARIZED facts=${facts.length} groups=${grouped.size}`);
  console.log(`[MEM_RETRIEVER] MEMORY_INJECTED facts=${facts.length}`);

  return [
    '--- USER PROFILE & MEMORY ---',
    'The following is a structured summary of what you know about the user:',
    ...lines,
    '',
    'Guidelines:',
    '- Use this memory naturally to personalize responses.',
    '- Do not narrate "I remember that..." unless explicitly asked.',
    '- If asked about these topics, rely on this profile.',
    '--- END PROFILE ---',
  ].join('\n');
}

function formatValue(v) {
  if (v === null || v === undefined) return '';
  if (Array.isArray(v)) {
    return v.map((item) => {
      if (typeof item === 'object' && item !== null) {
        const parts = [];
        if (item.name) parts.push(item.name);
        if (item.type) parts.push(`(${item.type})`);
        if (item.age !== null && item.age !== undefined) parts.push(`age ${item.age}`);
        return parts.length ? parts.join(' ') : JSON.stringify(item);
      }
      return String(item);
    }).join(', ');
  }
  if (typeof v === 'object') return JSON.stringify(v);
  return String(v);
}

/**
 * AQUA Memory Resolver v3
 * ─────────────────────────────────────────────────────────────────────────────
 * Takes normalized, deduped candidates and decides for each:
 *   • STORE_NEW       — no existing fact for this key
 *   • DUPLICATE       — same value as stored (update lastMentionedAt only)
 *   • MERGE           — append to collection (deduped)
 *   • OVERWRITE       — replace scalar value (with history)
 *   • CORRECTION      — explicit overwrite (with history)
 *   • REJECT_LOW_CONF — confidence below existing
 *
 * This is the ONLY place that compares candidates against stored facts.
 */
import { getFact } from './longTermMemory.js';
import { getSchema } from './memorySchema.js';

export const RESOLUTION_ACTIONS = Object.freeze({
  STORE_NEW:       'store_new',
  DUPLICATE:       'duplicate',
  MERGE:           'merge',
  OVERWRITE:       'overwrite',
  CORRECTION:      'correction',
  REJECT_LOW_CONF: 'reject_low_conf',
});

/**
 * Resolve a batch of candidates against existing stored facts.
 *
 * @param {string} ownerId
 * @param {Candidate[]} candidates
 * @returns {ResolvedCandidate[]}
 */
export function resolveCandidates(ownerId, candidates) {
  const resolved = [];
  for (const c of candidates) {
    resolved.push(resolveOne(ownerId, c));
  }
  return resolved;
}

function resolveOne(ownerId, candidate) {
  const existing = getFact(ownerId, candidate.key);
  const schema = getSchema(candidate.key);

  // ── No existing fact → store new ────────────────────────────────────────
  if (!existing) {
    return {
      ...candidate,
      action: RESOLUTION_ACTIONS.STORE_NEW,
      reason: 'no_existing',
    };
  }

  // ── Explicit correction → unconditional overwrite ───────────────────────
  if (candidate.isCorrection) {
    return {
      ...candidate,
      action: RESOLUTION_ACTIONS.CORRECTION,
      reason: 'explicit_correction',
      previousValue: existing.value,
    };
  }

  // ── Collection merge ────────────────────────────────────────────────────
  if (candidate.multiValue || schema?.multiValue) {
    return resolveCollection(candidate, existing);
  }

  // ── Scalar: compare normalized values ───────────────────────────────────
  const existingNorm = normalizeForCompare(existing.value);
  const incomingNorm = normalizeForCompare(candidate.normalizedValue);

  if (existingNorm === incomingNorm) {
    return {
      ...candidate,
      action: RESOLUTION_ACTIONS.DUPLICATE,
      reason: 'identical_value',
    };
  }

  // ── Recency wins ────────────────────────────────────────────────────────
  if ((candidate.ts || 0) > (existing.ts || existing.updatedAt || 0)) {
    return {
      ...candidate,
      action: RESOLUTION_ACTIONS.OVERWRITE,
      reason: 'newer_timestamp',
      previousValue: existing.value,
    };
  }

  // ── Confidence tiebreaker ───────────────────────────────────────────────
  if ((candidate.confidence || 0) > (existing.confidence || 0)) {
    return {
      ...candidate,
      action: RESOLUTION_ACTIONS.OVERWRITE,
      reason: 'higher_confidence',
      previousValue: existing.value,
    };
  }

  // ── Keep existing ───────────────────────────────────────────────────────
  return {
    ...candidate,
    action: RESOLUTION_ACTIONS.REJECT_LOW_CONF,
    reason: 'existing_wins',
  };
}

function resolveCollection(candidate, existing) {
  const existingArr = Array.isArray(existing.value) ? existing.value : [existing.value];
  const incomingArr = Array.isArray(candidate.normalizedValue)
    ? candidate.normalizedValue
    : [candidate.normalizedValue];

  const existingKeys = new Set(existingArr.map(itemIdentityKey));
  const newItems = [];
  const dupItems = [];

  for (const item of incomingArr) {
    const k = itemIdentityKey(item);
    if (existingKeys.has(k)) {
      dupItems.push(item);
    } else {
      newItems.push(item);
    }
  }

  if (newItems.length === 0) {
    // All items already present → duplicate
    return {
      ...candidate,
      action: RESOLUTION_ACTIONS.DUPLICATE,
      reason: 'collection_identical',
      mergedValue: existingArr,
    };
  }

  // Merge: existing + new
  const merged = [...existingArr, ...newItems];
  return {
    ...candidate,
    action: RESOLUTION_ACTIONS.MERGE,
    reason: dupItems.length > 0 ? 'collection_partial_merge' : 'collection_new_items',
    mergedValue: merged,
    addedItems: newItems,
    skippedDuplicates: dupItems,
  };
}

function normalizeForCompare(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v.toLowerCase().trim().replace(/\s+/g, ' ');
  if (Array.isArray(v)) return v.map(normalizeForCompare).sort().join('|');
  if (typeof v === 'object') return JSON.stringify(v, Object.keys(v).sort());
  return String(v).toLowerCase();
}

function itemIdentityKey(item) {
  if (item === null || item === undefined) return '';
  if (typeof item !== 'object') return String(item).toLowerCase().trim();
  if (item.type && item.name) return `${item.type}:${item.name}`.toLowerCase();
  const keys = Object.keys(item).sort();
  return keys.map((k) => `${k}=${item[k]}`).join('|').toLowerCase();
}

/**
 * AQUA Duplicate Detector v3
 * ─────────────────────────────────────────────────────────────────────────────
 * Detects duplicates WITHIN a single message's candidate set.
 * Cross-message duplicate detection happens in memoryResolver against stored facts.
 *
 * Rules:
 *   • Same key + same normalized value → keep highest confidence, mark as duplicate
 *   • For multiValue collections: same item (by identity) → merge
 */

/**
 * Deduplicate a list of candidates within the same message.
 * Returns { unique, duplicates }.
 *
 * @param {Candidate[]} candidates
 * @returns {{ unique: Candidate[], duplicates: Candidate[] }}
 */
export function deduplicateIntraMessage(candidates) {
  const unique = [];
  const duplicates = [];
  const seenByKey = new Map();       // key → candidate
  const seenCollectionItems = new Map(); // key → Set<itemKey>

  for (const c of candidates) {
    if (c.multiValue) {
      // Collection: dedupe by item identity
      const items = Array.isArray(c.normalizedValue) ? c.normalizedValue : [c.normalizedValue];
      const isFirst = !seenCollectionItems.has(c.key);
      if (isFirst) {
        // First encounter — push as-is and seed the seen set
        seenCollectionItems.set(c.key, new Set(items.map(itemIdentityKey)));
        seenByKey.set(c.key, c);
        unique.push(c);
        continue;
      }
      const existingSet = seenCollectionItems.get(c.key);
      const existingCand = seenByKey.get(c.key);
      const newItems = [];
      for (const item of items) {
        const itemKey = itemIdentityKey(item);
        if (existingSet.has(itemKey)) {
          duplicates.push({ ...c, _singleItem: item, rejectionReason: 'intra_message_duplicate' });
        } else {
          existingSet.add(itemKey);
          newItems.push(item);
        }
      }
      // Merge new items into existing candidate
      if (existingCand && newItems.length > 0) {
        existingCand.normalizedValue = Array.isArray(existingCand.normalizedValue)
          ? [...existingCand.normalizedValue, ...newItems]
          : [...(existingCand.normalizedValue !== null && existingCand.normalizedValue !== undefined ? [existingCand.normalizedValue] : []), ...newItems];
      }
    } else {
      // Scalar: dedupe by key
      if (seenByKey.has(c.key)) {
        const existing = seenByKey.get(c.key);
        // Keep the one with higher confidence
        if ((c.confidence || 0) > (existing.confidence || 0)) {
          // Replace
          const idx = unique.indexOf(existing);
          if (idx >= 0) unique[idx] = c;
          seenByKey.set(c.key, c);
          duplicates.push({ ...existing, rejectionReason: 'intra_message_duplicate_lower_conf' });
        } else {
          duplicates.push({ ...c, rejectionReason: 'intra_message_duplicate' });
        }
      } else {
        seenByKey.set(c.key, c);
        unique.push(c);
      }
    }
  }

  return { unique, duplicates };
}

/**
 * Produce a stable identity key for a collection item.
 * Objects: use all fields sorted; primitives: use value.
 */
function itemIdentityKey(item) {
  if (item === null || item === undefined) return '';
  if (typeof item !== 'object') return String(item).toLowerCase().trim();
  // For pet-like objects: use type+name as identity
  if (item.type && item.name) {
    return `${item.type}:${item.name}`.toLowerCase();
  }
  // Generic: sorted JSON
  const keys = Object.keys(item).sort();
  return keys.map((k) => `${k}=${item[k]}`).join('|').toLowerCase();
}

/**
 * AQUA Cognitive Identity — Acceptance Tests
 * Run: node --test src/memory/tests/identity.test.js
 *
 * Proves the v4 redesign: identity is canonical structured state, not semantic
 * recall. Runs against a TEMP cwd so the real .aqua-mind.json is never touched
 * (stores resolve their path from process.cwd() at module-load, so chdir must
 * precede the dynamic imports).
 *
 * Coverage:
 *   • extraction — every name form incl. MULTI-WORD, role+company, founded,
 *     work-at, live-in, age, call-me→preferred_name, aliases
 *   • field isolation — changing company/role never erases name (the core bug)
 *   • collection merge — aliases accumulate
 *   • retrieval BYPASS — identity answered from canonical state, never the
 *     ranker, even when crowded by higher-importance facts / tiny factLimit
 *   • cross-conversation — identity set in chat A is visible from chat B
 *   • conflict resolution — explicit correction overwrites + keeps history
 *   • custom de-collision — two unrelated "I'm a X" traits coexist
 *   • migration — legacy custom_trait blob → canonical identity / de-collided
 *   • regressions — the two headline examples from the spec
 */
import { test, before } from 'node:test';
import assert from 'node:assert/strict';
import fs from 'fs';
import os from 'os';
import path from 'path';

const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'aqua-identity-'));
const repoRoot = process.cwd();
process.chdir(tmp);

let engine, ltm, identity, mindStore, idMigrate, extractor;

before(async () => {
  engine     = await import(path.join(repoRoot, 'src/memory/engine.js'));
  ltm        = await import(path.join(repoRoot, 'src/memory/longTermMemory.js'));
  identity   = await import(path.join(repoRoot, 'src/memory/identity.js'));
  mindStore  = await import(path.join(repoRoot, 'src/mind/mindStore.js'));
  idMigrate  = await import(path.join(repoRoot, 'src/memory/identityMigration.js'));
  extractor  = await import(path.join(repoRoot, 'src/memory/memoryExtractor.js'));
});

const tick = () => new Promise(r => setTimeout(r, 4)); // ensure monotonic ts across observes
const findKey = (facts, key) => facts.find(f => f.key === key);

// ── Extraction (pure, no owner) ───────────────────────────────────────────────
test('extraction — every introduction form (incl. multi-word) yields the right identity keys', () => {
  assert.equal(findKey(extractor.extractFacts('My name is John'), 'name').value, 'John');
  assert.equal(findKey(extractor.extractFacts("I'm Chhanda Prabal Das"), 'name').value, 'Chhanda Prabal Das');
  assert.equal(findKey(extractor.extractFacts('I am Ada Lovelace, nice to meet you'), 'name').value, 'Ada Lovelace');
  assert.equal(findKey(extractor.extractFacts('This is Grace Hopper'), 'name').value, 'Grace Hopper');

  // "I'm Chhanda from Assam" must NOT absorb the trailing prepositional phrase
  const fromCase = extractor.extractFacts("I'm Chhanda from Assam");
  assert.equal(findKey(fromCase, 'name').value, 'Chhanda');

  // preferred_name is its own field
  assert.equal(findKey(extractor.extractFacts('call me Chey'), 'preferred_name').value, 'Chey');
  assert.equal(findKey(extractor.extractFacts('I go by Sam'), 'preferred_name').value, 'Sam');
  assert.equal(findKey(extractor.extractFacts('call me Chey'), 'name'), undefined); // no legal-name clobber
});

test('extraction — role + company split from a single statement', () => {
  const f1 = extractor.extractFacts("I'm the founder of Aquiplex");
  assert.equal(findKey(f1, 'profession').value, 'founder');
  assert.equal(findKey(f1, 'workplace').value, 'Aquiplex');

  const f2 = extractor.extractFacts('I founded Aquiplex');
