    ], normalizer: normalizeName, validator: validateName, multiValue: false, conflictPolicy: CONFLICT_POLICIES.OVERWRITE, importance: 9, baseConfidence: 0.95, retrievalHints: ['call me', 'nickname', 'go by', 'preferred name'] },
