export function getWordIndex() {
  if (!globalThis._aquaWordIndex) {
    const index = new Map();
    for (const entry of MEMORY_SCHEMA) {
      const words = new Set();
      entry.key.split('_').forEach(w => words.add(w));
      (entry.aliases || []).forEach(a => a.split('_').forEach(w => words.add(w)));
      (entry.retrievalHints || []).forEach(h => h.toLowerCase().split(/\s+/).forEach(w => words.add(w)));

      for (const word of words) {
        if (word.length > 1) {
          if (!index.has(word)) index.set(word, new Set());
          index.get(word).add(entry.key);
        }
      }
    }
    globalThis._aquaWordIndex = index;
  }
  return globalThis._aquaWordIndex;
}

/**
 * AQUA Identity — Canonical Structured State (v4)
 * ─────────────────────────────────────────────────────────────────────────────
 * The design premise, stated plainly:
 *
 *     Identity is NOT semantic recall. Identity is structured state.
 *
 * "What is my name?" must never depend on vector similarity, ranking scores,
 * a token budget, or which other facts happen to be important today. The
 * answer is a definite field the user told us, retrieved DIRECTLY.
 *
 * This module is a thin CANONICAL VIEW over the field-isolated fact layer
 * (longTermMemory → mind.facts). It deliberately owns NO persistence of its
 * own: each identity attribute already lives in its own fact key (`name`,
 * `preferred_name`, `profession`, `workplace`, `city`, …), which is exactly
 * what guarantees field-level independence — updating `workplace` cannot touch
 * `name`, because they are different keys with different lifecycles. What was
 * missing was (a) a canonical object assembled from those keys, and (b) a
 * retrieval path that bypasses the semantic ranker for identity questions.
 * Both live here.
 *
 * Responsibilities:
 *   getIdentity(owner)        → the canonical Identity object (present fields
 *                               only, each with value/confidence/provenance)
 *   formatIdentityBlock(id)   → authoritative, definite prompt block
 *   isIdentityQuery(query)    → "who am I / what's my name / what company…"
 *   answerIdentityQuery(id,q) → the identity card, chosen by the question,
 *                               read straight from canonical state (no ranker)
 *   IDENTITY_FACT_KEYS        → the set of fact keys this layer owns (used by
 *                               retrieval + migration to reason about identity)
 */
import { getFact } from './longTermMemory.js';

// ── Canonical field map ───────────────────────────────────────────────────────
// canonical : the stable public field name on the Identity object
// factKey   : the underlying isolated key in mind.facts (single source of data)
// kind      : 'scalar' | 'set'
// label     : how it renders in the identity block
// role/company map onto the pre-existing `profession`/`workplace` keys so the
// whole extraction + storage + conflict pipeline is reused unchanged.
export const IDENTITY_FIELDS = Object.freeze([
  { canonical: 'name',                factKey: 'name',                kind: 'scalar', label: 'Name' },
  { canonical: 'preferred_name',      factKey: 'preferred_name',      kind: 'scalar', label: 'Preferred name' },
  { canonical: 'aliases',             factKey: 'aliases',             kind: 'set',    label: 'Also known as' },
  { canonical: 'pronouns',            factKey: 'pronouns',            kind: 'scalar', label: 'Pronouns' },
  { canonical: 'age',                 factKey: 'age',                 kind: 'scalar', label: 'Age' },
  { canonical: 'birthday',            factKey: 'birthday',            kind: 'scalar', label: 'Birthday' },
  { canonical: 'role',                factKey: 'profession',          kind: 'scalar', label: 'Role' },
  { canonical: 'company',             factKey: 'workplace',           kind: 'scalar', label: 'Company' },
  { canonical: 'organization',        factKey: 'organization',        kind: 'scalar', label: 'Organization' },
  { canonical: 'education',           factKey: 'education',            kind: 'scalar', label: 'Education' },
  { canonical: 'city',                factKey: 'city',                kind: 'scalar', label: 'City' },
  { canonical: 'country',             factKey: 'country',             kind: 'scalar', label: 'Country' },
  { canonical: 'timezone',            factKey: 'timezone',            kind: 'scalar', label: 'Timezone' },
  { canonical: 'language',            factKey: 'language',            kind: 'scalar', label: 'Language' },
  { canonical: 'relationship_status', factKey: 'relationship_status', kind: 'scalar', label: 'Relationship' },
]);

export const IDENTITY_FACT_KEYS = Object.freeze(new Set(IDENTITY_FIELDS.map(f => f.factKey)));

const FIELD_BY_CANONICAL = new Map(IDENTITY_FIELDS.map(f => [f.canonical, f]));

const MIN_IDENTITY_CONF = 0.5;

// ── Canonical object ──────────────────────────────────────────────────────────
/**
 * Assemble the canonical Identity object for an owner from the isolated fact
 * keys. Absent fields are simply absent — the object shape is sparse, never a
 * grab-bag of nulls. Each present field carries its provenance.
 *
 * @returns {Object<string, { value:*, confidence:number, updatedAt:number,
 *          factKey:string, kind:string, label:string }>}
 */
export function getIdentity(ownerId) {
  const identity = {};
  if (!ownerId) return identity;
  for (const field of IDENTITY_FIELDS) {
    const fact = getFact(ownerId, field.factKey);
    if (!fact || fact.value === null || fact.value === undefined) continue;
    if (fact.value === '' || (Array.isArray(fact.value) && fact.value.length === 0)) continue;
    if ((fact.confidence ?? 1) < MIN_IDENTITY_CONF) continue;
    identity[field.canonical] = {
      value: fact.value,
      confidence: fact.confidence ?? 1,
      updatedAt: fact.updatedAt ?? fact.ts ?? 0,
      factKey: field.factKey,
      kind: field.kind,
      label: field.label,
    };
  }
  return identity;
}

export function hasIdentity(identity) {
  return !!identity && Object.keys(identity).length > 0;
}

/** Flat convenience view: { name: 'Chhanda', company: 'Aquiplex', … }. */
export function identityValues(identity) {
  const out = {};
  for (const [k, v] of Object.entries(identity || {})) out[k] = v.value;
  return out;
}

// ── Display ───────────────────────────────────────────────────────────────────
const TITLE_CASE_FIELDS = new Set(['role']); // role captured lower-case ("founder")

function titleCase(s) {
  return String(s).replace(/\b\w/g, c => c.toUpperCase());
}

function displayValue(canonical, value) {
  if (Array.isArray(value)) {
    return value.map(v => (typeof v === 'object' && v?.name ? v.name : String(v))).join(', ');
  }
  if (TITLE_CASE_FIELDS.has(canonical) && typeof value === 'string') return titleCase(value);
  return String(value);
}

/**
 * The authoritative identity block. Definite, first-person-of-the-user framing.
 * `fields` optionally restricts which fields to render (used to answer a
 * specific identity question); default renders the whole card.
 */
export function formatIdentityBlock(identity, { fields = null } = {}) {
  if (!hasIdentity(identity)) return '';
  const order = IDENTITY_FIELDS.map(f => f.canonical);
  const wanted = fields ? new Set(fields) : null;

  const lines = [];
  for (const canonical of order) {
    if (wanted && !wanted.has(canonical)) continue;
    const entry = identity[canonical];
    if (!entry) continue;
    lines.push(`- ${entry.label}: ${displayValue(canonical, entry.value)}`);
  }
  if (!lines.length) return '';

  return [
    '--- IDENTITY (user-stated, authoritative — this is who the user is) ---',
    ...lines,
    'These are durable, user-confirmed identity facts. Answer questions about the',
    "user's name, role, company, and location directly and confidently from this —",
    'never claim you do not know them.',
    '--- END IDENTITY ---',
  ].join('\n');
}

// ── Identity-query detection (retrieval bypass) ───────────────────────────────
// When any of these fire, the identity card is served straight from canonical
// state. It never rides the semantic ranker, so it cannot be crowded out by
// other high-importance facts or lost under a token budget.
const IDENTITY_QUERY_PATTERNS = [
  /\bwho am i\b/i,
  /\bwho i am\b/i,
  /\bdo you (?:remember|know) (?:me|who i am)\b/i,
  /\bremember me\b/i,
  /\bwhat (?:do|have) you (?:know|learned) about me\b/i,
  /\btell me about (?:myself|me)\b/i,
  /\bwhat(?:'s| is| are)? my name\b/i,
  /\bwhat am i called\b/i,
  /\bwhat(?:'s| is)? my (?:preferred name|nickname)\b/i,
  /\bwhat(?:'s| is)? my (?:role|job|title|profession|occupation)\b/i,
  /\bwhat(?:'s| is)? my (?:company|employer|workplace|organi[sz]ation)\b/i,
  /\bwhat company do i (?:run|own|work (?:for|at))\b/i,
  /\bwhere do i work\b/i, /\bwho do i work for\b/i,
  /\bwhat(?:'s| is)? my (?:age|birthday)\b/i, /\bhow old am i\b/i,
  /\bwhere (?:do i live|am i (?:from|based|located))\b/i,
  /\bwhat(?:'s| is)? my (?:city|country|location|timezone|hometown)\b/i,
];

export function isIdentityQuery(query) {
  const q = query || '';
  return IDENTITY_QUERY_PATTERNS.some(p => p.test(q));
}

// Map a narrow identity question to the specific canonical fields it asks for.
// A broad "who am I / about me" (or anything unmatched) → the whole card.
const QUERY_FIELD_MAP = [
  { re: /\b(name|called|nickname|preferred name)\b/i, fields: ['name', 'preferred_name', 'aliases'] },
  { re: /\b(role|job|title|profession|occupation|company|employer|workplace|organi[sz]ation|work for|work at|run|own)\b/i, fields: ['name', 'role', 'company', 'organization'] },
  { re: /\b(age|old|birthday)\b/i, fields: ['name', 'age', 'birthday'] },
  { re: /\b(live|from|based|located|city|country|location|timezone|hometown)\b/i, fields: ['name', 'city', 'country', 'timezone'] },
];

const BROAD_QUERY = /\bwho am i\b|\bwho i am\b|about me\b|remember me\b|remember (?:who i am|you)\b|learned about me\b/i;

/**
 * Answer an identity question from canonical state. Returns the identity card
 * scoped to the question (falls back to the full card for broad questions).
 * The retrieval path — NOT the ranker.
 */
export function answerIdentityQuery(identity, query) {
  if (!hasIdentity(identity)) return '';
  if (BROAD_QUERY.test(query || '')) return formatIdentityBlock(identity);
  for (const { re, fields } of QUERY_FIELD_MAP) {
    if (re.test(query || '')) {
      const block = formatIdentityBlock(identity, { fields });
      return block || formatIdentityBlock(identity);
    }
  }
  return formatIdentityBlock(identity);
}

/**
 * AQUA Unified Memory Engine — THE facade.
 * ─────────────────────────────────────────────────────────────────────────────
 * The ONLY module the chat pipeline (and upload/project routes) import for
 * memory. Everything under src/memory/* and src/mind/* is a STAGE of the
 * pipelines defined here — never called directly by routes.
 *
 *   resolveOwner(ids)                — ONE owner model (ownerResolver.js)
 *   memoryObserve(owner, turn)       — ONE observation pipeline:
 *                                        extract → forget/update → resolve →
 *                                        store facts → beliefs/goals/working/
 *                                        episodes/graph (mind observers)
 *   memoryRetrieve(owner, query)     — ONE retrieval pipeline, ONE budget:
 *                                        ranked facts + cognitive state +
 *                                        file memory → single prompt block
 *   memoryAfterTurn(owner, meta)     — predictions rebuild + reflection
 *   rememberFile / rememberWorkspace — uploads & workspaces become durable
 *                                        owner memory (Req 10)
 *   getMemoryTrace(requestId)        — Memory Inspector (Req 14): every
 *                                        decision explainable per request
 *
 * ONE store backs all of it: mindStore (.aqua-mind.json). Fail-safe: any
 * stage failure degrades to a neutral value — chat can never break on memory.
 */
import { resolveOwner, isUserOwner } from './ownerResolver.js';
import { extractFactsWithReport, detectMemoryUpdate, detectForget, resolveCanonicalKey } from './memoryExtractor.js';
import { storeFacts, storeFact, deleteFact } from './longTermMemory.js';
import { retrieveRelevantFacts, formatFactsForPrompt } from './memoryRetriever.js';
import { getIdentity, hasIdentity, formatIdentityBlock, isIdentityQuery, answerIdentityQuery } from './identity.js';
import { mindObserve, mindContext, mindAfterTurn } from '../mind/index.js';
import { getMind, peekMind, touchMind } from '../mind/mindStore.js';
import { upsertNode, upsertEdge, SELF_KEY } from '../mind/relationshipGraph.js';
import { estimateTokens } from '../core/tokenManager.js';

export { resolveOwner, isUserOwner };

const TOTAL_BUDGET_TOKENS = 800;   // one budget for the whole memory block
const MIN_COGNITIVE_BUDGET = 150;
const FILE_MEMORY_CAP = 60;        // per owner; oldest-least-referenced evicted
const FILE_SUMMARY_CHARS = 280;
const TRACE_RING_MAX = 100;

// ── Memory Inspector: per-request trace ring ─────────────────────────────────
const traces = new Map(); // requestId → trace

function beginTrace(requestId, base) {
  if (!requestId) return makeTrace(base);
  const t = makeTrace(base);
  traces.set(requestId, t);
  if (traces.size > TRACE_RING_MAX) {
    const oldest = traces.keys().next().value;
    traces.delete(oldest);
  }
  return t;
}

function makeTrace(base = {}) {
  return {
    ts: Date.now(),
    ownerId: null, userId: null, conversationId: null,
    extracted: [], rejected: [], actions: [],       // observation
    forget: null, correction: null,
    mind: { signals: 0, goalsTouched: 0 },
    ranking: [], consideredFacts: 0, droppedByGate: 0, // retrieval
    identity: null, identityQuery: false,               // canonical identity (bypass)
    retrieved: [], cognitiveUsed: {}, filesInjected: [],
    injectedTokens: 0, budgetTokens: TOTAL_BUDGET_TOKENS,
    duplicates: 0,
    notes: [],
    ...base,
  };
}

export function getMemoryTrace(requestId) {
  return traces.get(requestId) ?? null;
}

// ── ONE observation pipeline ─────────────────────────────────────────────────
/**
 * Observe one user turn. Single entry: fact extraction, explicit
 * forget/update handling, conflict-resolved storage, and cognitive
 * observation (beliefs, goals, working memory, episodes, graph) — in order,
 * sharing one extraction pass (the mind's fact bridge reuses extractedFacts).
 */
export function memoryObserve(ownerId, {
  userMessage = '', taskType = 'conversation',
  workspaceId = null, conversationId = null, userId = null, requestId = null,
} = {}) {
  const trace = beginTrace(requestId, { ownerId, userId, conversationId });
  if (!ownerId) {
    trace.notes.push('owner_null_memory_disabled');
    return { extractedFacts: [], mind: { signals: 0, goalsTouched: 0 }, trace };
  }

  let extractedFacts = [];
  try {
    // 1. Extract (parser → candidates → normalize → dedupe → resolve-vs-stored)
    const { facts, report } = extractFactsWithReport(userMessage, ownerId);
    extractedFacts = facts;
    trace.extracted = facts.map(f => ({ key: f.key, value: f.value, confidence: f.confidence, action: f.action, category: f.category }));
    trace.duplicates = report.duplicates;
    trace.rejectedCount = report.rejected;

    // 2. Store through the ONE conflict-resolving fact layer.
    //    conversationId travels as PROVENANCE only — never as the key.
    if (facts.length) {
      storeFacts(ownerId, facts.map(f => ({ ...f, sourceConversation: conversationId })), { trace });
    }

    // 3. Explicit forget
    const forgetResult = detectForget(userMessage);
    if (forgetResult.isForget && forgetResult.hint) {
      const hintKey = resolveCanonicalKey(forgetResult.hint.replace(/my\s+/i, '').trim());
      const deleted = deleteFact(ownerId, hintKey);
      trace.forget = { hint: forgetResult.hint, key: hintKey, deleted };
    }

    // 4. Explicit correction ("actually my X is now Y")
    const updateResult = detectMemoryUpdate(userMessage);
    if (updateResult.isUpdate) {
      storeFact(ownerId, {
        key: updateResult.key, value: updateResult.value,
        confidence: 0.95, importance: 9,
        sourceText: userMessage, ts: Date.now(), isCorrection: true,
      }, { trace });
      trace.correction = { key: updateResult.key, value: updateResult.value };
    }
  } catch (err) {
    console.warn('[MEMORY] fact observation failed (non-fatal):', err.message);
    trace.notes.push(`fact_stage_error:${err.message}`);
  }

  // 5. Cognitive observation — same turn, same facts, no re-parse
  const mindDiag = mindObserve(ownerId, { userMessage, taskType, extractedFacts, workspaceId, conversationId });
  trace.mind = mindDiag;

  return { extractedFacts, mind: mindDiag, trace };
}

// ── ONE retrieval pipeline ───────────────────────────────────────────────────
/**
 * Build the single memory block for the system prompt: ranked facts +
 * cognitive state + relevant file memory, under ONE token budget. Smallest
 * high-quality context — nothing dumped.
 */
export function memoryRetrieve(ownerId, {
  query = '', taskType = 'conversation',
  budgetTokens = TOTAL_BUDGET_TOKENS, factLimit = 10, requestId = null,
} = {}) {
  const trace = (requestId && traces.get(requestId)) || makeTrace({ ownerId });
  trace.budgetTokens = budgetTokens;
  if (!ownerId) return { block: '', relevantFacts: [], cognitiveUsed: {}, trace };

  // 0. IDENTITY FIRST — canonical structured state, NOT semantic recall.
  //    Assembled directly from the isolated identity fact keys and injected at
  //    the top of the memory block on EVERY turn (it is always relevant and
  //    tiny). Because it never passes through retrieveRelevantFacts(), an
  //    identity question ("what's my name?", "who am I?") can never be crowded
  //    out by other high-importance facts, dropped by the relevance gate, or
  //    lost under the token budget. On an explicit identity question the card
  //    is scoped to what was asked; otherwise the compact full card rides along.
  let identityBlock = '';
  try {
    const identity = getIdentity(ownerId);
    if (hasIdentity(identity)) {
      identityBlock = isIdentityQuery(query)
        ? answerIdentityQuery(identity, query)
        : formatIdentityBlock(identity);
      trace.identity = Object.fromEntries(
        Object.entries(identity).map(([k, v]) => [k, v.value]));
      trace.identityQuery = isIdentityQuery(query);
    }
  } catch (err) {
    console.warn('[MEMORY] identity retrieval failed (non-fatal):', err.message);
    trace.notes.push(`identity_error:${err.message}`);
  }

  let factBlock = '';
  let relevantFacts = [];
  try {
    relevantFacts = retrieveRelevantFacts(ownerId, query, factLimit, { trace });
    factBlock = formatFactsForPrompt(relevantFacts);
    trace.retrieved = relevantFacts.map(f => ({ key: f.key, value: f.value }));
  } catch (err) {
    console.warn('[MEMORY] fact retrieval failed (non-fatal):', err.message);
    trace.notes.push(`retrieve_facts_error:${err.message}`);
  }

  // Cognitive block rides whatever budget the identity card + facts leave.
  const identityTokens = estimateTokens(identityBlock);
  const factTokens = estimateTokens(factBlock);
  const cognitiveBudget = Math.max(MIN_COGNITIVE_BUDGET, budgetTokens - identityTokens - factTokens);
  const cognitive = mindContext(ownerId, { query, taskType, budgetTokens: cognitiveBudget });
  trace.cognitiveUsed = cognitive.used || {};

  // File memory — only when the query plausibly touches files.
  const fileBlock = retrieveFileMemory(ownerId, query, taskType, trace);

  const block = [identityBlock, factBlock, cognitive.block, fileBlock].filter(Boolean).join('\n\n');
  trace.injectedTokens = estimateTokens(block);
  return { block, relevantFacts, cognitiveUsed: cognitive.used || {}, trace };
}

// ── Post-turn ────────────────────────────────────────────────────────────────
export function memoryAfterTurn(ownerId, meta = {}) {
  return mindAfterTurn(ownerId, meta);
}

// ── File memory (Req 10) ─────────────────────────────────────────────────────
function fileKey(name) {
  return `file:${String(name).toLowerCase().trim()}`;
}

/**
 * Persist an uploaded attachment as durable owner memory: what it is, what
 * it contains (compact summary — NOT the full content), and where it came
 * from. Also lands in the relationship graph as an artifact the user uses.
 */
export function rememberFile(ownerId, { name, kind = 'document', summary = '', chars = 0, conversationId = null, workspaceId = null } = {}) {
  if (!ownerId || !name) return null;
  try {
    const mind = getMind(ownerId);
    const key = fileKey(name);
    const now = Date.now();
    const existing = mind.files[key];
    const entry = existing || {
      key, name, kind, uploadedAt: now, refCount: 0,
    };
    entry.kind = kind;
    entry.summary = (summary || entry.summary || '').slice(0, FILE_SUMMARY_CHARS);
    entry.chars = chars || entry.chars || 0;
    entry.conversationId = conversationId || entry.conversationId || null;
    entry.workspaceId = workspaceId || entry.workspaceId || null;
    entry.lastReferencedAt = now;
    entry.refCount = (entry.refCount || 0) + 1;
    mind.files[key] = entry;
    enforceFileCap(mind);

    const node = upsertNode(mind, 'artifact', name);
    if (node) upsertEdge(mind, SELF_KEY, node.key, 'uses', kind);
    touchMind(mind);
    console.log(`[MEMORY] FILE_REMEMBERED owner=${ownerId} name="${name}" kind=${kind}`);
    return entry;
  } catch (err) {
    console.warn('[MEMORY] rememberFile failed (non-fatal):', err.message);
    return null;
  }
}

/** Workspace (project upload) becomes a project node + file memory entry. */
export function rememberWorkspace(ownerId, workspace) {
  if (!ownerId || !workspace?.id) return;
  try {
    const mind = getMind(ownerId);
    const label = workspace.meta?.name || workspace.id;
    const node = upsertNode(mind, 'project', label);
    if (node) upsertEdge(mind, SELF_KEY, node.key, 'works_on', 'workspace');
    mind.files[`workspace:${workspace.id}`] = {
      key: `workspace:${workspace.id}`, name: label, kind: 'workspace',
      summary: workspace.summary || `${workspace.stats?.files ?? 0} files`,
      workspaceId: workspace.id, uploadedAt: workspace.createdAt || Date.now(),
      lastReferencedAt: Date.now(), refCount: 1,
    };
    enforceFileCap(mind);
    touchMind(mind);
  } catch (err) {
    console.warn('[MEMORY] rememberWorkspace failed (non-fatal):', err.message);
  }
}

function enforceFileCap(mind) {
  const keys = Object.keys(mind.files);
  if (keys.length <= FILE_MEMORY_CAP) return;
  const sorted = keys
    .map(k => [k, mind.files[k]])
    .sort((a, b) => (a[1].lastReferencedAt || 0) - (b[1].lastReferencedAt || 0));
  while (sorted.length > FILE_MEMORY_CAP) {
    const [k] = sorted.shift();
    delete mind.files[k];
  }
}

const FILE_INTENT_RE = /\b(file|files|upload(ed)?|document|pdf|spreadsheet|attachment|workspace|repo|that (doc|report|sheet))\b/i;

function retrieveFileMemory(ownerId, query, taskType, trace) {
  const mind = peekMind(ownerId);
  if (!mind || !Object.keys(mind.files || {}).length) return '';
  const q = (query || '').toLowerCase();
  const intent = FILE_INTENT_RE.test(q) || taskType === 'project_query';

  const tokens = q.match(/[a-z0-9_.-]{3,}/g) || [];
  const scored = [];
  for (const f of Object.values(mind.files)) {
    let score = 0;
    const nameLower = f.name.toLowerCase();
    if (tokens.some(t => nameLower.includes(t))) score += 3;                 // named directly
    if (intent) score += 1;                                                  // generic file intent
    if (score > 0) scored.push({ f, score });
  }
  if (!scored.length) return '';
  scored.sort((a, b) => b.score - a.score || (b.f.lastReferencedAt || 0) - (a.f.lastReferencedAt || 0));
  const top = scored.slice(0, 3).map(x => x.f);
  for (const f of top) { f.lastReferencedAt = Date.now(); f.refCount = (f.refCount || 0) + 1; }
  touchMind(mind);
  trace.filesInjected = top.map(f => f.name);

  const lines = top.map(f => `- ${f.name} (${f.kind}${f.chars ? `, ~${f.chars} chars` : ''})${f.summary ? `: ${f.summary}` : ''}`);
  return ['--- KNOWN FILES (long-term workspace memory) ---', ...lines, '--- END KNOWN FILES ---'].join('\n');
}

/**
AQUA Memory Conflict Resolver v3
─────────────────────────────────────────────────────────────────────────────
v3 additions (priority algorithm UNCHANGED):
• New actions: merge_collection, duplicate, contradiction, partial_overwrite
• resolveCollectionMerge() — deduped array merge for multiValue facts
• detectContradiction() — semantic contradiction detector (heuristic)
Priority order preserved:
explicit correction
newer timestamp
higher confidence
keep existing
*/
// ── Correction phrase list (unchanged) ────────────────────────────────────────
const DEFAULT_CORRECTION_PHRASES = [
'actually', 'actually,', 'actually my', 'no,', 'no.', 'nope', 'nope,',
'not anymore', 'i changed', "i've changed", 'i have changed', 'i switched',
"i've switched", 'i have switched', "it's now", 'it is now', 'update that',
'correction:', 'correction,', 'replace it with', 'forget that', 'instead,',
'instead.', 'from now on', 'use this instead', 'use x instead', 'my new',
'i no longer', 'i now use', 'i now prefer', 'i moved to', "i've moved to",
'i recently switched', 'wait,', 'wait no', 'scratch that', 'disregard that',
'ignore that', 'that was wrong', 'i was wrong', 'i lied', 'i meant', 'i mean,',
'previously', 'used to', 'rather',
];
const EXTRA_PHRASES = process.env.AQUA_CORRECTION_PHRASES
? process.env.AQUA_CORRECTION_PHRASES.split(',').map((p) => p.trim().toLowerCase()).filter(Boolean)
: [];
export const CORRECTION_PHRASES = [...DEFAULT_CORRECTION_PHRASES, ...EXTRA_PHRASES];
// ── Correction detection (unchanged) ──────────────────────────────────────────
export function detectCorrection(message) {
if (!message || typeof message !== 'string') return { isCorrection: false };
const lower = message.toLowerCase().trim();
for (const phrase of CORRECTION_PHRASES) {
if (
lower === phrase ||
lower.startsWith(phrase + ' ') ||
lower.startsWith(phrase + ',') ||
lower.startsWith(phrase + '.')
) {
return { isCorrection: true, phrase };
}
let searchFrom = 0;
let idx;
while ((idx = lower.indexOf(phrase, searchFrom)) !== -1) {
const charBefore = idx > 0 ? lower[idx - 1] : null;
if (charBefore === null || charBefore === ' ' || charBefore === ',' || charBefore === '.') {
const charAfter = lower[idx + phrase.length];
if (!charAfter || charAfter === ' ' || charAfter === ',' || charAfter === '.') {
return { isCorrection: true, phrase };
}
}
searchFrom = idx + 1;
}
}
return { isCorrection: false };
}
// ── Conflict resolution (priority UNCHANGED) ──────────────────────────────────
export function resolveMemoryConflict(incoming, existing) {
if (!existing) return { action: 'overwrite', reason: 'no_existing' };
if (
typeof incoming.value === 'string' &&
typeof existing.value === 'string' &&
incoming.value.toLowerCase().trim() === existing.value.toLowerCase().trim()
) {
return { action: 'keep', reason: 'identical_value' };
}
if (incoming.isCorrection) return { action: 'overwrite', reason: 'explicit_correction' };
if ((incoming.ts || 0) > (existing.ts || 0)) return { action: 'overwrite', reason: 'newer_timestamp' };
if ((incoming.confidence || 0) > (existing.confidence || 0)) return { action: 'overwrite', reason: 'higher_confidence' };
return { action: 'keep', reason: 'existing_wins' };
}
// ── v3 additions ──────────────────────────────────────────────────────────────
/**
Merge a new array of items into an existing collection, deduping by identity.
Returns { merged, added, skipped }.
*/
export function resolveCollectionMerge(existingArr, incomingArr) {
const existing = Array.isArray(existingArr) ? existingArr : (existingArr ? [existingArr] : []);
const incoming = Array.isArray(incomingArr) ? incomingArr : (incomingArr ? [incomingArr] : []);
const existingKeys = new Set(existing.map(itemKey));
const added = [];
const skipped = [];
for (const item of incoming) {
const k = itemKey(item);
if (existingKeys.has(k)) skipped.push(item);
else {
added.push(item);
existingKeys.add(k);
}
}
return { merged: [...existing, ...added], added, skipped };
}
function itemKey(item) {
if (item === null || item === undefined) return '';
if (typeof item !== 'object') return String(item).toLowerCase().trim();
if (item.type && item.name) return `${item.type}:${item.name}`.toLowerCase();
const keys = Object.keys(item).sort();
return keys.map((k) => `${k}=${item[k]}`).join('|').toLowerCase();
}
/**
Heuristic contradiction detector.
Returns { isContradiction: true, reason } if incoming semantically contradicts existing.
Used as a signal — explicit correction still takes priority.
*/
export function detectContradiction(incoming, existing) {
if (!existing || !incoming) return { isContradiction: false };
if (incoming.key !== existing.key) return { isContradiction: false };
// Same value → not a contradiction
const a = norm(incoming.value);
const b = norm(existing.value);
if (a === b) return { isContradiction: false };
// For scalar strings: different non-empty values on same key = contradiction
if (typeof incoming.value === 'string' && typeof existing.value === 'string') {
return { isContradiction: true, reason: 'scalar_value_changed' };
}
return { isContradiction: false };
}
function norm(v) {
if (v === null || v === undefined) return '';
if (typeof v === 'string') return v.toLowerCase().trim();
return JSON.stringify(v);
}

/**
 * AQUA Long-Term Memory — Fact Layer v4 (UNIFIED)
 * ─────────────────────────────────────────────────────────────────────────────
 * v4: facts live INSIDE the unified Mind store (`mind.facts`), keyed by
 * ownerId (see memory/ownerResolver.js). This module owns fact lifecycle —
 * conflict resolution, revision history, confidence, contradiction tracking —
 * but NOT persistence: mindStore.js is the single writer (.aqua-mind.json).
 *
 *   • ONE store        — no more .aqua-memory.json (see migrate.js)
 *   • ONE owner model  — ownerId (`user:<id>` | `conv:<id>`), never a bare
 *                        conversationId as a permanent key
 *   • Contradictions   — differing values update confidence + history +
 *                        contradiction count; never a blind overwrite
 *   • Support          — repeated identical evidence raises confidence
 *
 * API shape unchanged (first param was always a string key) → every caller
 * and existing test keeps working; the key is now an ownerId.
 */
import { getMind, peekMind, touchMind } from '../mind/mindStore.js';
import { resolveMemoryConflict } from './memoryConflictResolver.js';
import { RESOLUTION_ACTIONS } from './memoryResolver.js';

const MIN_CONF = 0.5;
// Confidence penalty per prior supporting observation when a contradiction
// (non-correction overwrite) arrives — the more established the old value,
// the less certain the new one starts out. Capped so recency still wins.
const CONTRADICTION_PENALTY_PER_SUPPORT = 0.03;
const CONTRADICTION_PENALTY_CAP = 0.15;

function factsOf(ownerId, { create = true } = {}) {
  if (!ownerId) return null;
  const mind = create ? getMind(ownerId) : peekMind(ownerId);
  if (!mind) return null;
  if (!mind.facts) mind.facts = {};
  return mind;
}

function buildVersionHistory(existing, reason) {
  const prevHistory = Array.isArray(existing.history) ? existing.history : [];
  return [
    ...prevHistory,
    {
      value: existing.value,
      normalizedValue: existing.normalizedValue ?? existing.value,
      ts: existing.ts,
      supersededAt: Date.now(),
      confidence: existing.confidence ?? 0.5,
      reason,
      sourceMessage: existing.sourceMessage || existing.sourceText || '',
      revision: existing.revision || 1,
    },
  ];
}

function makeFactId(ownerId, key) {
  return `${ownerId}:${key}`;
}

function upgradeFact(fact, ownerId) {
  const now = Date.now();
  return {
    id: fact.id || makeFactId(ownerId, fact.key),
    category: fact.category || null,
    key: fact.key,
    value: fact.value,
    normalizedValue: fact.normalizedValue ?? fact.value,
    confidence: fact.confidence ?? 0.5,
    importance: fact.importance ?? 5,
    createdAt: fact.createdAt || fact.ts || now,
    updatedAt: fact.updatedAt || fact.ts || now,
    lastMentionedAt: fact.lastMentionedAt || fact.ts || now,
    ts: fact.ts || now,
    sourceConversation: fact.sourceConversation || null,
    sourceMessage: fact.sourceMessage || fact.sourceText || '',
    sourceText: fact.sourceText || fact.sourceMessage || '',
    metadata: fact.metadata || {},
    revision: fact.revision ?? 1,
    history: Array.isArray(fact.history) ? fact.history : [],
    status: fact.status || 'active',
    supportCount: fact.supportCount ?? 1,       // observations agreeing with value
    contradictions: fact.contradictions ?? 0,   // times a different value arrived
  };
}

/** Reinforce: identical evidence seen again. */
function reinforce(existing, now) {
  existing.updatedAt = now;
  existing.lastMentionedAt = now;
  existing.ts = now;
  existing.confidence = Math.min(1.0, (existing.confidence || 0.5) + 0.05);
  existing.supportCount = (existing.supportCount || 1) + 1;
}

/**
 * Contradiction-aware confidence for a value REPLACING an established one.
 * Not a blind overwrite: the incoming confidence is damped in proportion to
 * how well-supported the previous value was (Acceptance Test 15). Explicit
 * corrections are exempt — the user said so.
 */
function contradictionConfidence(candidateConf, existing) {
  const penalty = Math.min(
    CONTRADICTION_PENALTY_CAP,
    (existing.supportCount || 1) * CONTRADICTION_PENALTY_PER_SUPPORT
  );
  return Math.max(MIN_CONF, (candidateConf ?? 0.5) - penalty);
}

export function storeFact(ownerId, fact, { trace = null } = {}) {
  if (!fact || (fact.confidence ?? 0) < MIN_CONF) {
    trace?.rejected?.push({ key: fact?.key, reason: 'below_min_confidence' });
    return;
  }
  const mind = factsOf(ownerId);
  if (!mind) return;
  const existing = mind.facts[fact.key] ?? null;
  const now = Date.now();

  if (fact.action && Object.values(RESOLUTION_ACTIONS).includes(fact.action)) {
    return storeResolved(ownerId, fact, { trace });
  }

  const { action, reason } = resolveMemoryConflict(fact, existing);
  console.log(`[LTM] CONFLICT_RESOLVED owner=${ownerId} key=${fact.key} action=${action} reason=${reason}`);
  trace?.actions?.push({ key: fact.key, action, reason });

  if (action === 'keep' && reason === 'identical_value' && existing) {
    reinforce(existing, now);
    touchMind(mind);
    return;
  }

  if (action === 'keep') return;

  const history = existing ? buildVersionHistory(existing, reason) : [];
  const { isCorrection, action: _drop2, ...persistableFact } = fact;
  const upgraded = upgradeFact(persistableFact, ownerId);
  upgraded.history = history;

  if (existing) {
    upgraded.revision = (existing.revision || 1) + 1;
    upgraded.createdAt = existing.createdAt || upgraded.createdAt;
    upgraded.contradictions = (existing.contradictions || 0) + 1;
    upgraded.supportCount = 1; // fresh value starts its own support count
    if (!isCorrection) {
      upgraded.confidence = contradictionConfidence(fact.confidence, existing);
    }
  }

  mind.facts[fact.key] = upgraded;
  touchMind(mind);
}

export function storeResolved(ownerId, resolved, { trace = null } = {}) {
  if (!resolved || (resolved.confidence ?? 0) < MIN_CONF) {
    trace?.rejected?.push({ key: resolved?.key, reason: 'below_min_confidence' });
    return;
  }
  const mind = factsOf(ownerId);
  if (!mind) return;
  const existing = mind.facts[resolved.key] ?? null;
  const now = Date.now();
  trace?.actions?.push({ key: resolved.key, action: resolved.action, reason: resolved.reason });

  switch (resolved.action) {
    case RESOLUTION_ACTIONS.DUPLICATE: {
      if (existing) {
        reinforce(existing, now);
        touchMind(mind);
      }
      return;
    }
    case RESOLUTION_ACTIONS.MERGE: {
      // The legacy-fact mapper (memoryExtractor.toLegacyFact) folds the merged
      // collection into `value` and does NOT carry `mergedValue` through, so a
      // cross-message merge arriving via the observe pipeline has mergedValue
      // === undefined. Fall back to `value` so the merged array is actually
      // persisted (previously this stored a valueless fact — the collection was
      // silently lost on the SECOND mention).
      const merged = resolved.mergedValue !== undefined ? resolved.mergedValue : resolved.value;
      const history = existing ? buildVersionHistory(existing, 'collection_merge') : [];
      const upgraded = upgradeFact({ ...resolved, value: merged, normalizedValue: merged }, ownerId);
      upgraded.history = history;
      upgraded.revision = (existing?.revision || 0) + 1;
      upgraded.createdAt = existing?.createdAt || now;
      upgraded.lastMentionedAt = now;
      upgraded.supportCount = (existing?.supportCount || 0) + 1;
      upgraded.contradictions = existing?.contradictions || 0;
      mind.facts[resolved.key] = upgraded;
      touchMind(mind);
      return;
    }
    case RESOLUTION_ACTIONS.OVERWRITE:
    case RESOLUTION_ACTIONS.CORRECTION: {
      const history = existing ? buildVersionHistory(existing, resolved.reason) : [];
      const upgraded = upgradeFact(resolved, ownerId);
      upgraded.history = history;
      upgraded.revision = (existing?.revision || 0) + 1;
      upgraded.createdAt = existing?.createdAt || now;
      upgraded.lastMentionedAt = now;
      if (existing) {
        upgraded.contradictions = (existing.contradictions || 0) + 1;
        upgraded.supportCount = 1;
        if (resolved.action === RESOLUTION_ACTIONS.OVERWRITE) {
          upgraded.confidence = contradictionConfidence(resolved.confidence, existing);
        }
      }
      mind.facts[resolved.key] = upgraded;
      touchMind(mind);
      return;
    }
    default: {
      const upgraded = upgradeFact(resolved, ownerId);
      upgraded.createdAt = now;
      upgraded.lastMentionedAt = now;
      mind.facts[resolved.key] = upgraded;
      touchMind(mind);
      return;
    }
  }
}

export function getFacts(ownerId) {
  const mind = factsOf(ownerId, { create: false });
  if (!mind || !Object.keys(mind.facts).length) return [];
  return Object.values(mind.facts).sort((a, b) => (b.importance || 0) - (a.importance || 0));
}

export function getFact(ownerId, key) {
  const mind = factsOf(ownerId, { create: false });
  return mind?.facts?.[key] ?? null;
}

export function clearFacts(ownerId) {
  const mind = factsOf(ownerId, { create: false });
  if (!mind) return;
  mind.facts = {};
  touchMind(mind);
}

export function storeFacts(ownerId, facts = [], { trace = null } = {}) {
  if (!Array.isArray(facts)) return;
  for (const fact of facts) {
    storeFact(ownerId, fact, { trace });
  }
}

export function deleteFact(ownerId, key) {
  const mind = factsOf(ownerId, { create: false });
  if (!mind || !(key in mind.facts)) return false;
  delete mind.facts[key];
  touchMind(mind);
  return true;
}

export function getFactHistory(ownerId, key) {
  const fact = getFact(ownerId, key);
  if (!fact) return [];
  return Array.isArray(fact.history) ? fact.history : [];
}

export function getMemoryStats() {
  // Unified: iterate minds via the single store.
  let owners = 0;
  let facts = 0;
  let contradictions = 0;
  for (const mind of _allMinds()) {
    const f = Object.values(mind.facts || {});
    if (f.length) owners++;
    facts += f.length;
    for (const fact of f) contradictions += fact.contradictions || 0;
  }
  return { owners, facts, contradictions };
}

// Internal: enumerate minds without exporting the raw map from mindStore.
import { _iterateMindsForStats } from '../mind/mindStore.js';
function _allMinds() { return _iterateMindsForStats(); }

/**
 * AQUA Engine Router
 *
 * Single mount point for the entire AQUA AI engine inside the AQUIPLEX
 * platform. The platform (CommonJS index.js) loads this ESM module via
 * dynamic import() and mounts it at /api/aqua behind requireLogin.
 *
 * Route map (all relative to /api/aqua):
 *   /chat              — chat + /chat/stream (SSE)
 *   /provider-health   — provider health probes
 *   /project           — workspace / repository intelligence + patch editing
 *   /conversations     — conversation history (per-user scoped)
 *   /memory            — long-term memory management
 *   /upload            — universal upload (files, archives, media)
 *
 * User identity: the platform sets req.aquaUserId (from the session) before
 * this router runs. Routes read it to scope conversations and memory.
 */
import express from "express";

import chatRoute          from "./src/routes/chat.js";
import healthRoute        from "./src/routes/health.js";
import projectRoute       from "./src/routes/project.js";
import conversationsRoute from "./src/routes/conversations.js";
import memoryRoute        from "./src/routes/memory.js";
import uploadRoute        from "./src/routes/upload.js";
import mindRoute          from "./src/mind/mindRoutes.js";
import { runStartupValidation } from "./src/core/startupValidation.js";
import { migrateLegacyMemory }  from "./src/memory/migrate.js";
import { migrateIdentity }      from "./src/memory/identityMigration.js";

// ── One-time unification migration ──────────────────────────────────────────
// Legacy conversation-scoped facts (.aqua-memory.json) → unified owner-scoped
// Mind store (.aqua-mind.json). Idempotent: source archived after success.
migrateLegacyMemory();

// ── One-time identity repair ─────────────────────────────────────────────────
// Fold any legacy `custom_trait` blobs into canonical identity fields (or
// de-collide them into per-value custom keys). Idempotent: minds are flagged.
migrateIdentity();

// Validate model registry + provider keys once at mount. Never throws —
// misconfigured providers are disabled with a warning, engine still mounts.
runStartupValidation();

const router = express.Router();

router.use("/chat",            chatRoute);
router.use("/provider-health", healthRoute);
router.use("/project",         projectRoute);
router.use("/conversations",   conversationsRoute);
router.use("/memory",          memoryRoute);
router.use("/upload",          uploadRoute);
router.use("/mind",            mindRoute);   // persistent cognitive model (Mind layer)

// JSON 404 for unknown engine routes (never fall through to platform HTML 404)
router.use((req, res) => {
  res.status(404).json({ success: false, error: `Not found: ${req.method} /api/aqua${req.path}` });
});

// JSON error handler — same contract the AQUA frontend expects
router.use((err, req, res, _next) => {
  const status = err.status ?? err.statusCode ?? 500;
  if (err.type === "entity.too.large" || status === 413) {
    return res.status(413).json({
      success: false,
      error: "Upload too large. The request body limit is 50 MB — try a smaller archive, or remove build artifacts (node_modules, dist) before zipping.",
    });
  }
  if (err.type === "entity.parse.failed") {
    return res.status(400).json({ success: false, error: "Invalid request body (malformed JSON)." });
  }
  console.error(`[AQUA] Unhandled error ${req.method} ${req.path}:`, err.stack ?? err.message);
  res.status(status).json({ success: false, error: err.message ?? "Internal server error" });
});

export default router;

