import { create } from 'zustand';
import {
  fetchMind, type MindModel, type CompactBelief, type Dimension,
} from '@/api/mind';

/* ────────────────────────────────────────────────────────────────────────
   Mind store — single source for the dashboard.

   No polling. Refreshes are event-driven:
     • page mount / window focus
     • after every completed chat turn (chatStore.finishTurn → refreshMind())
   Consecutive fetches are diffed to produce the "What AQUA learned" feed
   and to detect a new reflection (→ plays the reflection sequence).
   ──────────────────────────────────────────────────────────────────────── */

export const DIMENSIONS: Dimension[] = [
  'identity', 'personality', 'communication', 'preferences', 'knowledge', 'behavior', 'decision',
];

export interface Learning {
  id: string;
  ts: number;
  kind: 'new' | 'strengthened' | 'shifted' | 'goal' | 'promoted';
  text: string;
}

interface MindState {
  model: MindModel | null;
  loading: boolean;
  error: string | null;
  hasLoadedOnce: boolean;
  learnings: Learning[];           // session-accumulated, newest first
  reflectionPlaying: boolean;
  lastFetchedAt: number;

  refresh: (opts?: { silent?: boolean }) => Promise<void>;
  applyBelief: (b: CompactBelief) => void;   // optimistic local update after edit
  removeBelief: (dimension: string, key: string) => void;
  dismissReflection: () => void;
  clear: () => void;
}

function allBeliefs(m: MindModel): CompactBelief[] {
  return DIMENSIONS.flatMap((d) => m[d] ?? []);
}

/** Composite understanding: confidence mass + dimension coverage + context signals. */
export function understandingScore(m: MindModel | null): number {
  if (!m) return 0;
  const beliefs = allBeliefs(m).filter((b) => b.status !== 'archived');
  if (!beliefs.length && !m.goals.length) return 0;

  const avgConf = beliefs.length
    ? beliefs.reduce((s, b) => s + b.confidence, 0) / beliefs.length
    : 0;
  const coverage = DIMENSIONS.filter((d) => (m[d] ?? []).some((b) => b.status !== 'archived')).length / DIMENSIONS.length;
  const goalSignal = Math.min(1, m.goals.filter((g) => g.status === 'active' || g.status === 'blocked').length / 3);
  const depth = Math.min(1, beliefs.reduce((s, b) => s + b.evidenceCount, 0) / 60);

  return Math.round(100 * (0.45 * avgConf + 0.25 * coverage + 0.15 * depth + 0.15 * goalSignal));
}

export function dimensionConfidence(m: MindModel, d: Dimension): { avg: number; count: number } {
  const list = (m[d] ?? []).filter((b) => b.status !== 'archived');
  if (!list.length) return { avg: 0, count: 0 };
  return { avg: list.reduce((s, b) => s + b.confidence, 0) / list.length, count: list.length };
}

let learningSeq = 0;
function diffLearnings(prev: MindModel | null, next: MindModel): Learning[] {
  const out: Learning[] = [];
  const now = Date.now();
  const push = (kind: Learning['kind'], text: string) =>
    out.push({ id: `l${now.toString(36)}_${learningSeq++}`, ts: now, kind, text });

  const label = (b: CompactBelief) => b.key.replace('tech:', '').replace(/_/g, ' ');
  const val = (v: unknown) => (v === true ? '' : ` — ${String(typeof v === 'object' ? JSON.stringify(v) : v)}`);

  const prevMap = new Map(prev ? allBeliefs(prev).map((b) => [`${b.dimension}:${b.key}`, b]) : []);
  for (const b of allBeliefs(next)) {
    const p = prevMap.get(`${b.dimension}:${b.key}`);
    if (!p) {
      if (prev) push('new', `Noticed ${label(b)}${val(b.value)}`);
    } else if (JSON.stringify(p.value) !== JSON.stringify(b.value)) {
      push('shifted', `Updated ${label(b)}: now${val(b.value) || ` ${String(b.value)}`}`);
    } else if (b.confidence - p.confidence >= 0.04) {
      push('strengthened', `More confident: ${label(b)} (${Math.round(p.confidence * 100)}% → ${Math.round(b.confidence * 100)}%)`);
    }
  }

  const prevGoals = new Map(prev?.goals.map((g) => [g.id, g]) ?? []);
  for (const g of next.goals) {
    const p = prevGoals.get(g.id);
    if (!p && prev) push('goal', `Tracking a goal: “${g.title}”`);
    else if (p && p.status !== g.status && g.status === 'completed') push('goal', `Goal completed: “${g.title}”`);
    else if (p && p.status !== g.status && g.status === 'blocked') push('goal', `Goal blocked: “${g.title}”`);
  }

  const prevPromoted = new Set(prev?.reflections.flatMap((r) => r.promoted) ?? []);
  for (const r of next.reflections) {
    for (const key of r.promoted) {
      if (!prevPromoted.has(key)) push('promoted', `Established: ${key.split(':').slice(1).join(':').replace(/_/g, ' ')}`);
    }
  }

  return out.reverse(); // newest first when prepended
}

export const useMindStore = create<MindState>()((set, get) => ({
  model: null,
  loading: false,
  error: null,
  hasLoadedOnce: false,
  learnings: [],
  reflectionPlaying: false,
  lastFetchedAt: 0,

  refresh: async ({ silent = false } = {}) => {
    const { loading, lastFetchedAt } = get();
    if (loading) return;
    if (silent && Date.now() - lastFetchedAt < 1500) return; // debounce bursts
    if (!silent) set({ loading: true, error: null });
    try {
      const next = await fetchMind();
      const prev = get().model;
      if (next) {
        const fresh = diffLearnings(prev, next);
        const reflectionHappened =
          !!prev && next.reflections.length > prev.reflections.length;
        set((s) => ({
          model: next,
          loading: false,
          error: null,
          hasLoadedOnce: true,
          lastFetchedAt: Date.now(),
          learnings: [...fresh, ...s.learnings].slice(0, 40),
          reflectionPlaying: s.reflectionPlaying || reflectionHappened,
        }));
      } else {
        set({ model: null, loading: false, hasLoadedOnce: true, lastFetchedAt: Date.now() });
      }
    } catch (err) {
      set({
        loading: false,
        hasLoadedOnce: true,
        error: err instanceof Error ? err.message : 'Could not load the mind model.',
      });
    }
  },

  applyBelief: (b) =>
    set((s) => {
      if (!s.model) return s;
      const dim = b.dimension;
      const list = (s.model[dim] ?? []).filter((x) => x.key !== b.key);
      return { model: { ...s.model, [dim]: [b, ...list] } };
    }),

  removeBelief: (dimension, key) =>
    set((s) => {
      if (!s.model) return s;
      const dim = dimension as Dimension;
      return {
        model: { ...s.model, [dim]: (s.model[dim] ?? []).filter((x) => x.key !== key) },
      };
    }),

  dismissReflection: () => set({ reflectionPlaying: false }),
  clear: () => set({ model: null, learnings: [], hasLoadedOnce: false }),
}));

/** Called by chatStore after each completed turn — the "live" in live updates. */
export function refreshMind() {
  void useMindStore.getState().refresh({ silent: true });
}

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { deleteConversation as apiDeleteConversation, listConversations } from '@/api/conversations';
import { normalizeError } from '@/api/client';
import type { UiConversation } from '@/types';

interface ConversationOverlayEntry {
  pinned: boolean;
  renamedTitle?: string;
  /** First user message, truncated — cached at send-time since GET /conversations never returns content. */
  derivedTitle?: string;
}

interface ConversationState {
  items: UiConversation[];
  loading: boolean;
  error: string | null;
  searchQuery: string;

  /** id -> overlay. Persisted — this is the only place pin/rename/title live. */
  overlay: Record<string, ConversationOverlayEntry>;

  fetchConversations: () => Promise<void>;
  removeConversation: (id: string) => Promise<void>;
  clearAll: () => Promise<{ succeeded: number; failed: number }>;
  togglePin: (id: string) => void;
  rename: (id: string, title: string) => void;
  cacheTitle: (id: string, firstMessage: string) => void;
  setSearchQuery: (q: string) => void;
  ensureLocalEntry: (id: string, createdAt: number) => void;
}

function deriveTitle(text: string): string {
  const cleaned = text.trim().replace(/\s+/g, ' ');
  return cleaned.length > 48 ? `${cleaned.slice(0, 48)}…` : cleaned || 'New conversation';
}

export const useConversationStore = create<ConversationState>()(
  persist(
    (set, get) => ({
      items: [],
      loading: false,
      error: null,
      searchQuery: '',
      overlay: {},

      fetchConversations: async () => {
        set({ loading: true, error: null });
        try {
          const res = await listConversations();
          const overlay = get().overlay;
          const items: UiConversation[] = res.conversations.map((c) => {
            const ov = overlay[c.id];
            return {
              id: c.id,
              title: ov?.renamedTitle ?? ov?.derivedTitle ?? `Conversation · ${c.id.slice(0, 8)}`,
              messageCount: c.messageCount,
              createdAt: c.meta?.createdAt ?? Date.now(),
              pinned: ov?.pinned ?? false,
              renamedTitle: ov?.renamedTitle,
            };
          });
          set({ items, loading: false });
        } catch (err) {
          set({ error: normalizeError(err).message, loading: false });
        }
      },

      removeConversation: async (id) => {
        const prev = get().items;
        set({ items: prev.filter((c) => c.id !== id) });
        try {
          await apiDeleteConversation(id);
        } catch (err) {
          set({ items: prev, error: normalizeError(err).message });
          throw err;
        }
      },

      clearAll: async () => {
        const ids = get().items.map((c) => c.id);
        let succeeded = 0;
        let failed = 0;
        for (const id of ids) {
          try {
            await apiDeleteConversation(id);
            succeeded++;
          } catch {
            failed++;
          }
        }
        set({ overlay: {} });
        // Refetch from the server rather than reasoning about which ids
        // survived a partially-failed bulk-delete loop — it's the only
        // source of truth the backend gives us.
        await get().fetchConversations();
        return { succeeded, failed };
      },

      togglePin: (id) =>
        set((s) => {
          const entry = s.overlay[id] ?? { pinned: false };
          const overlay = { ...s.overlay, [id]: { ...entry, pinned: !entry.pinned } };
          const items = s.items.map((c) => (c.id === id ? { ...c, pinned: !entry.pinned } : c));
          return { overlay, items };
        }),

      rename: (id, title) =>
        set((s) => {
          const entry = s.overlay[id] ?? { pinned: false };
          const overlay = { ...s.overlay, [id]: { ...entry, renamedTitle: title } };
          const items = s.items.map((c) => (c.id === id ? { ...c, title, renamedTitle: title } : c));
          return { overlay, items };
        }),

      cacheTitle: (id, firstMessage) =>
        set((s) => {
          const entry = s.overlay[id] ?? { pinned: false };
          if (entry.derivedTitle || entry.renamedTitle) return s;
          const derivedTitle = deriveTitle(firstMessage);
          const overlay = { ...s.overlay, [id]: { ...entry, derivedTitle } };
          const exists = s.items.some((c) => c.id === id);
          const items = exists
            ? s.items.map((c) => (c.id === id ? { ...c, title: derivedTitle } : c))
            : [
                { id, title: derivedTitle, messageCount: 1, createdAt: Date.now(), pinned: false },
                ...s.items,
              ];
          return { overlay, items };
        }),

      ensureLocalEntry: (id, createdAt) =>
        set((s) => {
          if (s.items.some((c) => c.id === id)) return s;
          return {
            items: [
              { id, title: 'New conversation', messageCount: 0, createdAt, pinned: false },
              ...s.items,
            ],
          };
        }),

      setSearchQuery: (searchQuery) => set({ searchQuery }),
    }),
    {
      name: 'aqua-conversation-overlay',
      partialize: (s) => ({ overlay: s.overlay }),
    },
  ),
);

/**
 * Universal upload state — Day 5.
 *
 * Drives the premium upload experience in the composer: per-file staged
 * status (Uploading… → Extracting/Analyzing… → Ready), image thumbnails,
 * repository routing, and explicit per-file failures. Everything flows
 * through ONE endpoint (POST /upload); the server decides how each file is
 * processed. Repository results additionally attach a workspace to the
 * active chat and surface the workspace dashboard — exactly what the old
 * Project Upload dialog did, now with zero manual steps.
 */
import { create } from 'zustand';
import { uploadUnified, deleteConversationAttachment, type ServerAttachment, type UploadWorkspaceResult } from '@/api/upload';
import { classifyFile, readAsBase64, MAX_BYTES_BY_KIND, type UploadKind } from '@/utils/uploadKinds';
import { normalizeError } from '@/api/client';
import { useChatStore } from './chatStore';
import { useUploadStore } from './uploadStore';
import { useUiStore } from './uiStore';
import type { WorkspaceOverview } from '@/types';

export type AttachmentStage = 'uploading' | 'processing' | 'ready' | 'error';

export interface PendingAttachment {
  localId: string;
  name: string;
  kind: UploadKind;
  sizeBytes: number;
  stage: AttachmentStage;
  stageLabel: string;
  error?: string;
  /** Server-side attachment id once ready (documents/images/media/source). */
  serverId?: string;
  /** Object URL for image thumbnails — revoked on remove. */
  previewUrl?: string;
  format?: string;
  pages?: number | null;
}

interface AttachmentState {
  items: PendingAttachment[];
  uploading: boolean;
  /** Overall byte-level upload progress (axios), 0–100. */
  progress: number;

  addFiles: (files: File[]) => Promise<void>;
  remove: (localId: string) => Promise<void>;
  clearForNewConversation: () => void;
}

const STAGE_LABEL: Record<UploadKind, string> = {
  repository: 'Extracting & indexing…',
  document:   'Extracting…',
  image:      'Analyzing…',
  audio:      'Transcribing…',
  video:      'Analyzing…',
  source:     'Reading…',
  unknown:    'Processing…',
};

function makeLocalId() {
  return crypto.randomUUID();
}

export const useAttachmentStore = create<AttachmentState>((set, get) => ({
  items: [],
  uploading: false,
  progress: 0,

  addFiles: async (files) => {
    if (!files.length || get().uploading) return;
    const toast = useUiStore.getState().toast;

    // ── Client-side validation: fail fast with clear reasons ──
    const accepted: Array<{ file: File; kind: UploadKind; localId: string }> = [];
    for (const file of files) {
      const kind = classifyFile(file.name);
      if (kind === 'unknown') {
        toast('warning', `Skipped ${file.name}`, 'Unsupported format. AQUA accepts repositories (zip/tar/tar.gz), documents, images, audio, video, and source files.');
        continue;
      }
      if (file.size > MAX_BYTES_BY_KIND[kind]) {
        toast('warning', `${file.name} is too large`, `${kind === 'repository' ? 'Archives' : 'Files of this type'} are limited to ${Math.round(MAX_BYTES_BY_KIND[kind] / 1e6)} MB.`);
        continue;
      }
      accepted.push({ file, kind, localId: makeLocalId() });
    }
    if (!accepted.length) return;

    // ── Stage 1: Uploading… (with image thumbnails immediately) ──
    const pending: PendingAttachment[] = accepted.map(({ file, kind, localId }) => ({
      localId,
      name: file.name,
      kind,
      sizeBytes: file.size,
      stage: 'uploading',
      stageLabel: 'Uploading…',
      previewUrl: kind === 'image' ? URL.createObjectURL(file) : undefined,
    }));
    set((s) => ({ items: [...s.items, ...pending], uploading: true, progress: 0 }));

    try {
      const encoded = await Promise.all(
        accepted.map(async ({ file }) => ({ name: file.name, content: await readAsBase64(file) })),
      );

      // ── Stage 2: server-side processing labels per kind ──
      const flip = (stage: AttachmentStage, label?: string) =>
        set((s) => ({
          items: s.items.map((it) =>
            accepted.some((a) => a.localId === it.localId)
              ? { ...it, stage, stageLabel: label ?? STAGE_LABEL[it.kind] }
              : it,
          ),
        }));

      const res = await uploadUnified(encoded, {
        conversationId: useChatStore.getState().conversationId,
        onProgress: (pct) => {
          set({ progress: pct });
          if (pct >= 100) flip('processing');
        },
      });

      // The upload may have created the conversation — adopt its id so the
      // next chat turn (and further uploads) land in the same conversation.
      if (res.conversationId && !useChatStore.getState().conversationId) {
        useChatStore.setState({ conversationId: res.conversationId });
      }

      // ── Stage 3: reconcile per-file results ──
      set((s) => ({
        items: s.items.map((it) => {
          const match = accepted.find((a) => a.localId === it.localId);
          if (!match) return it;
          const result = res.results.find((r) => r.name === it.name);
          if (!result) return { ...it, stage: 'error', stageLabel: 'Failed', error: 'No result returned for this file' };
          if (result.status === 'failed') return { ...it, stage: 'error', stageLabel: 'Failed', error: result.error };
          const attachment = res.attachments.find((a: ServerAttachment) => a.id === result.attachmentId);
          return {
            ...it,
            stage: 'ready',
            stageLabel: it.kind === 'repository' ? 'Workspace ready' : 'Ready',
            serverId: result.attachmentId,
            format: result.format ?? attachment?.format,
            pages: result.pages ?? attachment?.pages ?? null,
          };
        }),
        uploading: false,
      }));

      // ── Repository experience: attach workspace + show dashboard ──
      if (res.workspace) {
        adoptWorkspace(res.workspace);
        toast('success', `${res.workspace.name} indexed`, `${res.workspace.filesIngested} files — repository chat is ready.`);
      }

      const failures = res.results.filter((r) => r.status === 'failed');
      for (const f of failures) toast('error', `${f.name} failed`, f.error);
    } catch (err) {
      const message = normalizeError(err).message;
      set((s) => ({
        items: s.items.map((it) =>
          accepted.some((a) => a.localId === it.localId)
            ? { ...it, stage: 'error', stageLabel: 'Failed', error: message }
            : it,
        ),
        uploading: false,
      }));
      toast('error', 'Upload failed', message);
    }
  },

  remove: async (localId) => {
    const item = get().items.find((i) => i.localId === localId);
    if (!item) return;
    if (item.previewUrl) URL.revokeObjectURL(item.previewUrl);
    set((s) => ({ items: s.items.filter((i) => i.localId !== localId) }));
    // Detach server-side too so it stops being injected into chat turns.
    const conversationId = useChatStore.getState().conversationId;
    if (item.serverId && conversationId) {
      try { await deleteConversationAttachment(conversationId, item.serverId); } catch { /* non-fatal */ }
    }
  },

  clearForNewConversation: () => {
    for (const it of get().items) if (it.previewUrl) URL.revokeObjectURL(it.previewUrl);
    set({ items: [], uploading: false, progress: 0 });
  },
}));

/** Wire a workspace produced by unified upload into the existing chat + dashboard flow. */
function adoptWorkspace(ws: UploadWorkspaceResult) {
  useChatStore.getState().setWorkspaceId(ws.id);
  // Reuse the existing uploadStore surface so WorkspaceDashboard renders
  // exactly as it does for the legacy Project Upload dialog.
  useUploadStore.setState({
    status: 'ready',
    workspaceId: ws.id,
    projectName: ws.name,
    fileCount: ws.filesIngested,
    overview: (ws.overview as WorkspaceOverview) ?? null,
    showDashboard: !!ws.overview,
    error: null,
    progress: 100,
  });
}

