import { memo, useMemo, type ReactElement, type ReactNode } from 'react';
import ReactMarkdown, { type Components } from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { CodeBlock } from './CodeBlock';

interface CodeChildProps {
  className?: string;
  children?: ReactNode;
}

/**
 * react-markdown v9 no longer passes an `inline` flag to the `code`
 * renderer, so the reliable way to tell a fenced block from inline code is
 * structural: fenced blocks are always `<pre><code>`, inline code never has
 * a `<pre>` parent. We override `pre` and read the wrapped `<code>` element
 * directly, which also lets us skip react-markdown's own `code` render pass
 * for blocks entirely and hand off straight to the syntax highlighter.
 */
const components: Components = {
  pre({ children }) {
    const codeEl = children as ReactElement<CodeChildProps> | undefined;
    const className = codeEl?.props?.className ?? '';
    const match = /language-(\w+)/.exec(className);
    const raw = codeEl?.props?.children;
    const code = Array.isArray(raw) ? raw.join('') : String(raw ?? '');
    return <CodeBlock language={match?.[1] ?? 'text'} code={code.replace(/\n$/, '')} />;
  },

  code({ className, children, ...props }) {
    return (
      <code
        className={
          'rounded bg-surface-secondary px-1.5 py-0.5 font-mono text-[0.85em] text-foreground before:content-none after:content-none ' +
          (className ?? '')
        }
        {...props}
      >
        {children}
      </code>
    );
  },

  a({ children, ...props }) {
    return (
      <a {...props} target="_blank" rel="noopener noreferrer" className="text-primary underline underline-offset-2 hover:opacity-80">
        {children}
      </a>
    );
  },

  img({ alt, ...props }) {
    return <img {...props} alt={alt ?? ''} loading="lazy" className="my-2 max-w-full rounded-lg border border-border" />;
  },

  table({ children }) {
    return (
      <div className="my-3 overflow-x-auto rounded-lg border border-border">
        <table className="w-full border-collapse text-sm">{children}</table>
      </div>
    );
  },
  thead({ children }) {
    return <thead className="bg-surface-secondary">{children}</thead>;
  },
  th({ children }) {
    return <th className="border-b border-border px-3 py-2 text-left font-semibold text-foreground">{children}</th>;
  },
  td({ children }) {
    return <td className="border-b border-border/60 px-3 py-2 align-top text-foreground-secondary last:border-b-0">{children}</td>;
  },

  blockquote({ children }) {
    return <blockquote className="my-2 border-l-2 border-primary/40 pl-3 text-foreground-secondary italic">{children}</blockquote>;
  },

  ul({ children, className }) {
    const isTaskList = className?.includes('contains-task-list');
    return <ul className={isTaskList ? 'my-2 space-y-1 pl-1' : 'my-2 list-disc space-y-1 pl-5'}>{children}</ul>;
  },
  ol({ children }) {
    return <ol className="my-2 list-decimal space-y-1 pl-5">{children}</ol>;
  },
  li({ children, className }) {
    if (className?.includes('task-list-item')) {
      return <li className="flex list-none items-start gap-2 [&>input]:mt-1 [&>input]:accent-primary">{children}</li>;
    }
    return <li className="leading-relaxed">{children}</li>;
  },

  h1: ({ children }) => <h1 className="mb-3 mt-5 text-xl font-semibold text-foreground first:mt-0">{children}</h1>,
  h2: ({ children }) => <h2 className="mb-2.5 mt-5 text-lg font-semibold text-foreground first:mt-0">{children}</h2>,
  h3: ({ children }) => <h3 className="mb-2 mt-4 text-base font-semibold text-foreground first:mt-0">{children}</h3>,
  h4: ({ children }) => <h4 className="mb-1.5 mt-3 text-sm font-semibold text-foreground first:mt-0">{children}</h4>,

  p: ({ children }) => <p className="leading-relaxed [&:not(:first-child)]:mt-2.5">{children}</p>,
  hr: () => <hr className="my-4 border-border" />,
  strong: ({ children }) => <strong className="font-semibold text-foreground">{children}</strong>,
};

/**
 * Split markdown into stable top-level blocks (blank-line separated, fenced
 * code kept intact). During streaming, appended tokens only ever change the
 * LAST block — memoizing each block means everything above it skips
 * react-markdown's parse + render entirely on every frame. This is what
 * keeps long streaming answers smooth: parse cost stays O(tail block), not
 * O(entire message) per animation frame.
 */
function splitMarkdownBlocks(content: string): string[] {
  const lines = content.split('\n');
  const blocks: string[] = [];
  let current: string[] = [];
  let inFence = false;
  let fenceMarker = '';

  const push = () => {
    if (current.length) {
      blocks.push(current.join('\n'));
      current = [];
    }
  };

  for (const line of lines) {
    const fenceMatch = /^\s*(```+|~~~+)/.exec(line);
    if (fenceMatch) {
      if (!inFence) {
        inFence = true;
        fenceMarker = fenceMatch[1][0].repeat(3);
      } else if (line.trimStart().startsWith(fenceMarker)) {
        inFence = false;
        current.push(line);
        push(); // close the code block as its own unit
        continue;
      }
    }
    if (!inFence && line.trim() === '') {
      push();
      continue;
    }
    current.push(line);
  }
  push();
  return blocks;
}

const MarkdownBlock = memo(function MarkdownBlock({ content }: { content: string }) {
  return (
    <ReactMarkdown remarkPlugins={[remarkGfm]} components={components}>
      {content}
    </ReactMarkdown>
  );
});

export const MarkdownRenderer = memo(function MarkdownRenderer({
  content,
  streaming = false,
}: {
  content: string;
  /** Appends the blinking cursor after the last rendered block. */
  streaming?: boolean;
}) {
  const blocks = useMemo(() => splitMarkdownBlocks(content), [content]);

  return (
    <div className="text-[15px] text-foreground [overflow-wrap:anywhere]">
      {blocks.map((block, i) => (
        // Index keys are correct here: blocks only ever append/extend at the
        // tail during streaming, so indices are stable for finished blocks.
        <MarkdownBlock key={i} content={block} />
      ))}
      {streaming && <span className="streaming-cursor" aria-hidden="true" />}
    </div>
  );
});

import { useState, useEffect, memo } from 'react';
import { PrismAsyncLight as SyntaxHighlighter } from 'react-syntax-highlighter';
import oneDark from 'react-syntax-highlighter/dist/esm/styles/prism/one-dark';
import oneLight from 'react-syntax-highlighter/dist/esm/styles/prism/one-light';
import { Check, ChevronsUpDown, Copy, Download, WrapText } from 'lucide-react';
import { useSettingsStore } from '@/stores/settingsStore';
import { useCopyToClipboard } from '@/hooks/useCopyToClipboard';
import { Tooltip } from '@/components/ui/tooltip';
import { cn } from '@/lib/utils';

interface CodeBlockProps {
  language: string;
  code: string;
}

/** Blocks taller than this auto-collapse with an expand affordance —
 *  keeps a wall of generated code from swallowing the conversation. */
const COLLAPSE_AFTER_LINES = 28;
const COLLAPSED_MAX_HEIGHT = '26rem';

const EXT_BY_LANG: Record<string, string> = {
  javascript: 'js', typescript: 'ts', jsx: 'jsx', tsx: 'tsx', python: 'py', bash: 'sh',
  shell: 'sh', json: 'json', html: 'html', css: 'css', markdown: 'md', yaml: 'yml',
  sql: 'sql', go: 'go', rust: 'rs', java: 'java', c: 'c', cpp: 'cpp', ruby: 'rb', php: 'php',
  diff: 'diff', patch: 'diff', kotlin: 'kt', swift: 'swift', dockerfile: 'Dockerfile',
};

/** Language aliases the model commonly emits, normalized to Prism grammar ids. */
const LANG_ALIASES: Record<string, string> = {
  js: 'javascript', ts: 'typescript', py: 'python', sh: 'bash', zsh: 'bash',
  shell: 'bash', console: 'bash', terminal: 'bash', shellsession: 'bash',
  yml: 'yaml', patch: 'diff', docker: 'dockerfile', 'c++': 'cpp', golang: 'go',
  md: 'markdown', htm: 'html',
};

// Each loader is its own chunk, fetched only the first time that language is
// actually rendered — this is what keeps the main bundle from carrying every
// Prism grammar up front the way the synchronous `Prism` build does.
const LANGUAGE_LOADERS: Record<string, () => Promise<{ default: unknown }>> = {
  javascript: () => import('react-syntax-highlighter/dist/esm/languages/prism/javascript'),
  jsx: () => import('react-syntax-highlighter/dist/esm/languages/prism/jsx'),
  typescript: () => import('react-syntax-highlighter/dist/esm/languages/prism/typescript'),
  tsx: () => import('react-syntax-highlighter/dist/esm/languages/prism/tsx'),
  python: () => import('react-syntax-highlighter/dist/esm/languages/prism/python'),
  bash: () => import('react-syntax-highlighter/dist/esm/languages/prism/bash'),
  shell: () => import('react-syntax-highlighter/dist/esm/languages/prism/bash'),
  json: () => import('react-syntax-highlighter/dist/esm/languages/prism/json'),
  css: () => import('react-syntax-highlighter/dist/esm/languages/prism/css'),
  html: () => import('react-syntax-highlighter/dist/esm/languages/prism/markup'),
  xml: () => import('react-syntax-highlighter/dist/esm/languages/prism/markup'),
  sql: () => import('react-syntax-highlighter/dist/esm/languages/prism/sql'),
  yaml: () => import('react-syntax-highlighter/dist/esm/languages/prism/yaml'),
  markdown: () => import('react-syntax-highlighter/dist/esm/languages/prism/markdown'),
  go: () => import('react-syntax-highlighter/dist/esm/languages/prism/go'),
  rust: () => import('react-syntax-highlighter/dist/esm/languages/prism/rust'),
  java: () => import('react-syntax-highlighter/dist/esm/languages/prism/java'),
  c: () => import('react-syntax-highlighter/dist/esm/languages/prism/c'),
  cpp: () => import('react-syntax-highlighter/dist/esm/languages/prism/cpp'),
  ruby: () => import('react-syntax-highlighter/dist/esm/languages/prism/ruby'),
  php: () => import('react-syntax-highlighter/dist/esm/languages/prism/php'),
  diff: () => import('react-syntax-highlighter/dist/esm/languages/prism/diff'),
  kotlin: () => import('react-syntax-highlighter/dist/esm/languages/prism/kotlin'),
  swift: () => import('react-syntax-highlighter/dist/esm/languages/prism/swift'),
  dockerfile: () => import('react-syntax-highlighter/dist/esm/languages/prism/docker'),
};

const registeredLanguages = new Set<string>();

/** Idempotent — safe to call every render; only fetches/registers once per language. */
async function ensureLanguageRegistered(lang: string): Promise<void> {
  if (registeredLanguages.has(lang) || !LANGUAGE_LOADERS[lang]) return;
  const mod = await LANGUAGE_LOADERS[lang]();
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  (SyntaxHighlighter as any).registerLanguage(lang, mod.default);
  registeredLanguages.add(lang);
}

function download(filename: string, content: string) {
  const blob = new Blob([content], { type: 'text/plain' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

export const CodeBlock = memo(function CodeBlock({ language, code }: CodeBlockProps) {
  const [wrap, setWrap] = useState(false);
  const [expanded, setExpanded] = useState(false);
  const [, forceRerender] = useState(0);
  const { copied, copy } = useCopyToClipboard();
  // System theme resolves via the html.dark class at runtime; reading the
  // store here keeps the highlighter palette in sync with explicit choices.
  const theme = useSettingsStore((s) => s.theme);
  const isDark =
    theme === 'dark' ||
    (theme === 'system' &&
      typeof window !== 'undefined' &&
      window.matchMedia('(prefers-color-scheme: dark)').matches);

  const rawLang = (language || 'text').toLowerCase();
  const lang = LANG_ALIASES[rawLang] ?? rawLang;
  const ext = EXT_BY_LANG[lang] ?? 'txt';

  const lineCount = code.split('\n').length;
  const collapsible = lineCount > COLLAPSE_AFTER_LINES;
  const collapsed = collapsible && !expanded;

  useEffect(() => {
    let cancelled = false;
    ensureLanguageRegistered(lang).then(() => {
      if (!cancelled) forceRerender((n) => n + 1);
    });
    return () => {
      cancelled = true;
    };
  }, [lang]);

  return (
    <div className="group/code my-3 overflow-hidden rounded-lg border border-border bg-surface">
      <div className="flex items-center justify-between border-b border-border bg-surface-secondary px-3 py-1.5">
        <span className="font-mono text-[11px] font-medium text-foreground-secondary">
          {lang}
          {collapsible && (
            <span className="ml-2 text-foreground-secondary/60">{lineCount} lines</span>
          )}
        </span>
        <div className="flex items-center gap-0.5 opacity-70 transition-opacity group-hover/code:opacity-100">
          {collapsible && (
            <Tooltip label={collapsed ? 'Expand' : 'Collapse'}>
              <button
                onClick={() => setExpanded((e) => !e)}
                className="rounded p-1.5 text-foreground-secondary hover:bg-surface hover:text-foreground"
                aria-label={collapsed ? 'Expand code' : 'Collapse code'}
                aria-expanded={!collapsed}
              >
                <ChevronsUpDown className="h-3.5 w-3.5" />
              </button>
            </Tooltip>
          )}
          <Tooltip label={wrap ? 'Disable wrap' : 'Wrap lines'}>
            <button
              onClick={() => setWrap((w) => !w)}
              className={cn(
                'rounded p-1.5 text-foreground-secondary hover:bg-surface hover:text-foreground',
                wrap && 'bg-surface text-primary',
              )}
              aria-label="Toggle line wrap"
            >
              <WrapText className="h-3.5 w-3.5" />
            </button>
          </Tooltip>
          <Tooltip label="Download">
            <button
              onClick={() => download(`snippet.${ext}`, code)}
              className="rounded p-1.5 text-foreground-secondary hover:bg-surface hover:text-foreground"
              aria-label="Download code"
            >
              <Download className="h-3.5 w-3.5" />
            </button>
          </Tooltip>
          <Tooltip label={copied ? 'Copied!' : 'Copy'}>
            <button
              onClick={() => copy(code)}
              className="rounded p-1.5 text-foreground-secondary hover:bg-surface hover:text-foreground"
              aria-label="Copy code"
            >
              {copied ? <Check className="h-3.5 w-3.5 text-success" /> : <Copy className="h-3.5 w-3.5" />}
            </button>
          </Tooltip>
        </div>
      </div>

      <div
        className="relative"
        style={collapsed ? { maxHeight: COLLAPSED_MAX_HEIGHT, overflow: 'hidden' } : undefined}
      >
        <SyntaxHighlighter
          language={lang}
          style={isDark ? oneDark : oneLight}
          showLineNumbers={lineCount > 5}
          wrapLongLines={wrap}
          customStyle={{
            margin: 0,
            padding: '0.875rem 1rem',
            background: 'transparent',
            fontSize: '13px',
            lineHeight: 1.6,
          }}
          codeTagProps={{ style: { fontFamily: 'var(--font-mono)' } }}
          lineNumberStyle={{ opacity: 0.35, minWidth: '2em' }}
        >
          {code.replace(/\n$/, '')}
        </SyntaxHighlighter>

        {collapsed && (
          <div className="absolute inset-x-0 bottom-0 flex justify-center bg-gradient-to-t from-surface via-surface/85 to-transparent pb-2 pt-10">
            <button
              onClick={() => setExpanded(true)}
              className="rounded-full border border-border bg-surface px-3 py-1 text-xs font-medium text-foreground shadow-sm transition-transform hover:scale-[1.03]"
            >
              Show all {lineCount} lines
            </button>
          </div>
        )}
      </div>
    </div>
  );
});

