export const MessageBubble = memo(function MessageBubble({ message, isLast }: { message: UiMessage; isLast: boolean }) {
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(message.content);
  const contentRef = useRef<HTMLDivElement>(null);
  const regenerate = useChatStore((s) => s.regenerate);
  const editAndResend = useChatStore((s) => s.editAndResend);
  const retryLastMessage = useChatStore((s) => s.retryLastMessage);
  const continueGeneration = useChatStore((s) => s.continueGeneration);
  const generating = useChatStore((s) => s.generating);

  const isUser = message.role === 'user';

  if (isUser) {
    return (
      <motion.div
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.2 }}
        className="message-row group flex justify-end px-4 py-2"
      >
        <div className="flex max-w-[85%] flex-col items-end gap-1 sm:max-w-[70%]">
          {editing ? (
            <div className="w-full rounded-xl border border-primary bg-surface p-3 shadow-sm">
              <Textarea
                autoFocus
                value={draft}
                onChange={(e) => setDraft(e.target.value)}
                className="min-h-[60px]"
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    setEditing(false);
                    editAndResend(message.id, draft);
                  }
                  if (e.key === 'Escape') {
                    setDraft(message.content);
                    setEditing(false);
                  }
                }}
              />
              <div className="mt-2 flex justify-end gap-1.5">
                <Button size="sm" variant="ghost" onClick={() => { setDraft(message.content); setEditing(false); }}>
                  <X className="h-3.5 w-3.5" /> Cancel
                </Button>
                <Button
                  size="sm"
                  onClick={() => { setEditing(false); editAndResend(message.id, draft); }}
                  disabled={!draft.trim()}
                >
                  <Check className="h-3.5 w-3.5" /> Save & submit
                </Button>
              </div>
            </div>
          ) : (
            <div className="rounded-xl bg-primary px-4 py-2.5 text-[15px] text-primary-foreground shadow-sm [overflow-wrap:anywhere]">
              {message.content}
            </div>
          )}

          {!editing && message.attachments && message.attachments.length > 0 && (
            <div className="flex flex-wrap justify-end gap-1.5">
              {message.attachments.map((a) => (
                <span
                  key={a.id}
                  className="flex items-center gap-1.5 rounded-md border border-border bg-surface-secondary px-2 py-1 text-[11px] text-foreground-secondary"
                >
                  <Paperclip className="h-3 w-3" /> {a.name}
                </span>
              ))}
            </div>
          )}

          {!editing && (
            <div className="flex items-center gap-2 pr-1 opacity-0 transition-opacity group-hover:opacity-100">
              <span className="text-[11px] text-foreground-secondary/60">{formatTime(message.ts)}</span>
              {!generating && (
                <button
                  onClick={() => setEditing(true)}
                  className="rounded p-1 text-foreground-secondary/60 hover:bg-surface-secondary hover:text-foreground"
                  aria-label="Edit message"
                >
                  <Pencil className="h-3 w-3" />
                </button>
              )}
            </div>
          )}
        </div>
      </motion.div>
    );
  }

  // Assistant message
  const isThinking = message.status === 'sending' && !message.content;
  const isStreaming = message.status === 'streaming';
  const isError = message.status === 'error';
  const wasInterrupted = message.finishReason === 'interrupted';

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.2 }}
      className="message-row group flex gap-3 px-4 py-3"
    >
      <Avatar className="mt-0.5 h-7 w-7 shrink-0">
        <AvatarFallback className="bg-gradient-to-br from-primary to-accent text-[10px] font-bold">AQ</AvatarFallback>
      </Avatar>

      <div className="min-w-0 flex-1">
        {message.workspace && !isThinking && <WorkspaceContextChip workspace={message.workspace} />}

        {isThinking ? (
          <ThinkingIndicator stage={message.stage} />
        ) : isError ? (
          <div className="flex items-start gap-2 rounded-lg border border-danger/20 bg-danger/5 px-3 py-2.5 text-sm text-danger">
            <AlertCircle className="mt-0.5 h-4 w-4 shrink-0" />
            <div className="flex-1">
              <p>{message.error ?? 'Something went wrong.'}</p>
              {message.error !== 'Stopped' && (
                <Button size="sm" variant="outline" className="mt-2 border-danger/30 text-danger hover:bg-danger/10" onClick={() => retryLastMessage()}>
                  <RotateCcw className="h-3 w-3" /> Retry
                </Button>
              )}
            </div>
          </div>
        ) : (
          <>
            <div ref={contentRef}>
              <MarkdownRenderer content={message.content} streaming={isStreaming} />
            </div>

            {message.patch && !isStreaming && <PatchCard patch={message.patch} messageId={message.id} />}

            {message.stoppedByUser && (
              <div className="mt-1.5 flex items-center gap-1.5 text-[12px] text-foreground-secondary/70">
                <CircleSlash className="h-3 w-3" /> Generation stopped
              </div>
            )}

            {!isStreaming && message.truncated && !generating && (
              <div className="mt-2 flex items-center gap-2">
                <Button size="sm" variant="outline" onClick={() => continueGeneration()}>
                  <ArrowRightCircle className="h-3.5 w-3.5" /> Continue
                </Button>
                <span className="text-[11px] text-foreground-secondary/70">
                  {wasInterrupted ? 'Response was interrupted' : 'Response hit the length limit'}
                </span>
              </div>
            )}

            {!isStreaming && (
              <div className="mt-1 flex items-center gap-2">
                <span className="text-[11px] text-foreground-secondary/50 opacity-0 transition-opacity group-hover:opacity-100">
                  {formatTime(message.ts)}
                </span>
                <MessageActions
                  content={message.content}
                  contentRef={contentRef}
                  onRegenerate={isLast && !generating ? () => regenerate(message.id) : undefined}
                  className="opacity-0 transition-opacity group-hover:opacity-100"
                />
              </div>
            )}

            {message.diagnostics && !isStreaming && <DiagnosticsPanel diagnostics={message.diagnostics} />}
          </>
        )}
      </div>
    </motion.div>
  );
});

import { useCallback, useEffect, useRef, useState } from 'react';
import { useDropzone } from 'react-dropzone';
import { ArrowUp, FolderPlus, Paperclip, Square } from 'lucide-react';
import { Textarea } from '@/components/ui/textarea';
import { Tooltip } from '@/components/ui/tooltip';
import { Button } from '@/components/ui/button';
import { AttachmentChip } from '@/components/upload/AttachmentChip';
import { ProjectUploadDialog } from '@/components/upload/ProjectUploadDialog';
import { useChatStore } from '@/stores/chatStore';
import { useAttachmentStore } from '@/stores/attachmentStore';
import { cn } from '@/lib/utils';

const MAX_CHARS = 8000;

/**
 * Day 5 — Universal Upload composer.
 *
 * ONE upload experience: drag ANY supported file into the chat (repository
 * archives, PDFs, slides, spreadsheets, images, audio, video, source
 * files). The unified /upload endpoint classifies and routes each file
 * automatically — archives become indexed workspaces attached to this
 * conversation; everything else becomes conversation attachments whose
 * extracted content grounds the very next turn. The legacy Project Upload
 * dialog remains reachable (folder button) for named multi-file projects.
 */
export function Composer() {
  const [text, setText] = useState('');
  const [projectDialogOpen, setProjectDialogOpen] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const sendMessage = useChatStore((s) => s.sendMessage);
  const stopGenerating = useChatStore((s) => s.stopGenerating);
  const generating = useChatStore((s) => s.generating);
  const workspaceId = useChatStore((s) => s.workspaceId);
  const conversationId = useChatStore((s) => s.conversationId);

  const attachments = useAttachmentStore((s) => s.items);
  const uploading = useAttachmentStore((s) => s.uploading);
  const addFiles = useAttachmentStore((s) => s.addFiles);
  const removeAttachment = useAttachmentStore((s) => s.remove);
  const clearAttachments = useAttachmentStore((s) => s.clearForNewConversation);

  // Attachments are conversation-scoped server-side — when the user starts a
  // fresh conversation (conversationId resets to null), drop the local chips.
  const prevConversationId = useRef<string | null>(conversationId);
  useEffect(() => {
    if (prevConversationId.current && !conversationId) clearAttachments();
    prevConversationId.current = conversationId;
  }, [conversationId, clearAttachments]);

  const autoResize = useCallback(() => {
    const el = textareaRef.current;
    if (!el) return;
    el.style.height = 'auto';
    el.style.height = `${Math.min(el.scrollHeight, 240)}px`;
  }, []);

  const onDrop = useCallback((accepted: File[]) => void addFiles(accepted), [addFiles]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    noClick: true,
    noKeyboard: true,
    disabled: generating,
  });

  function handleSend() {
    if (generating || uploading) return;
    const trimmed = text.trim();
    if (!trimmed) return;

    // Attachment content is injected server-side from the conversation's
    // attachment store — the message goes out as plain text.
    sendMessage(trimmed);
    setText('');
    requestAnimationFrame(autoResize);
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  }

  const overLimit = text.length > MAX_CHARS;
  const readyAttachments = attachments.filter((a) => a.stage === 'ready').length;

  return (
    <div className="mx-auto w-full max-w-3xl px-4 pb-4 pt-2 sm:pb-6">
      {(workspaceId || readyAttachments > 0) && (
        <div className="mb-1.5 flex items-center gap-1.5 px-1 text-[11px] text-foreground-secondary">
          <FolderPlus className="h-3 w-3" />
          {workspaceId && readyAttachments > 0
            ? `Project context + ${readyAttachments} attachment${readyAttachments === 1 ? '' : 's'} active for this chat`
            : workspaceId
              ? 'Project context active for this chat'
              : `${readyAttachments} attachment${readyAttachments === 1 ? '' : 's'} available to this chat`}
        </div>
      )}

      <div
        {...getRootProps()}
        className={cn(
          'relative rounded-2xl border bg-surface shadow-sm transition-colors',
          isDragActive ? 'border-primary ring-2 ring-primary/20' : 'border-border',
        )}
      >
        <input {...getInputProps()} />

        {isDragActive && (
          <div className="pointer-events-none absolute inset-0 z-10 flex flex-col items-center justify-center rounded-2xl bg-surface/90 text-sm font-medium text-primary">
            Drop anything — repos, PDFs, slides, images, audio, video
            <span className="mt-0.5 text-[11px] font-normal text-foreground-secondary">AQUA routes it automatically</span>
          </div>
        )}

        {attachments.length > 0 && (
          <div className="flex flex-wrap gap-1.5 px-3 pt-3">
            {attachments.map((a) => (
              <AttachmentChip key={a.localId} attachment={a} onRemove={() => removeAttachment(a.localId)} />
            ))}
          </div>
        )}

        <Textarea
          ref={textareaRef}
          value={text}
          onChange={(e) => {
            setText(e.target.value);
            autoResize();
          }}
          onKeyDown={handleKeyDown}
          placeholder={readyAttachments > 0 ? 'Ask about your files…' : 'Message AQUA…'}
          rows={1}
          className="max-h-60 min-h-[52px] px-4 py-3.5 pr-14 text-[15px]"
        />

        <div className="flex items-center justify-between px-2.5 pb-2.5">
          <div className="flex items-center gap-0.5">
            <Tooltip label="Attach any file — documents, images, audio, video, archives">
              <button
                onClick={() => fileInputRef.current?.click()}
                disabled={generating || uploading}
                className="rounded-lg p-2 text-foreground-secondary transition-colors hover:bg-surface-secondary hover:text-foreground disabled:opacity-40"
                aria-label="Attach files"
              >
                <Paperclip className="h-4 w-4" />
              </button>
            </Tooltip>
            <input
              ref={fileInputRef}
              type="file"
              multiple
              className="hidden"
              onChange={(e) => {
                if (e.target.files) void addFiles(Array.from(e.target.files));
                e.target.value = '';
              }}
            />

            <Tooltip label="Upload a named project">
              <button
                onClick={() => setProjectDialogOpen(true)}
                disabled={generating}
                className="rounded-lg p-2 text-foreground-secondary transition-colors hover:bg-surface-secondary hover:text-foreground disabled:opacity-40"
                aria-label="Upload project"
              >
                <FolderPlus className="h-4 w-4" />
              </button>
            </Tooltip>

            {text.length > MAX_CHARS - 500 && (
              <span className={cn('ml-1 text-[11px] tabular-nums', overLimit ? 'text-danger' : 'text-foreground-secondary/60')}>
                {text.length}/{MAX_CHARS}
              </span>
            )}
          </div>

          {generating ? (
            <Tooltip label="Stop generating (Esc)">
              <Button size="icon" variant="secondary" onClick={stopGenerating} className="h-8 w-8 rounded-full">
                <Square className="h-3.5 w-3.5 fill-current" />
              </Button>
            </Tooltip>
          ) : (
            <Button
              size="icon"
              onClick={handleSend}
              disabled={!text.trim() || overLimit || uploading}
              className="h-8 w-8 rounded-full"
              aria-label="Send message"
            >
              <ArrowUp className="h-4 w-4" />
            </Button>
          )}
        </div>
      </div>

      <p className="mt-2 text-center text-[11px] text-foreground-secondary/50">
        AQUA can make mistakes. Verify important information.
      </p>

      <ProjectUploadDialog open={projectDialogOpen} onOpenChange={setProjectDialogOpen} />
    </div>
  );
}

