/* ── Evolution heatmap — understanding over time ────────────────────────── */

const HEAT_WEEKS = 12;
const DIM_SHORT = ['Identity', 'Personality', 'Comms', 'Prefs', 'Knowledge', 'Behavior', 'Decision'];

export function EvolutionHeatmap({ model }: { model: MindModel }) {
  const reduce = useReducedMotion();

  const grid = useMemo(() => {
    const now = Date.now();
    const week = 7 * 24 * 3600 * 1000;
    const cells: number[][] = DIMENSIONS.map(() => Array(HEAT_WEEKS).fill(0));

    // Activity sources: timeline events + reflection deltas + belief updates.
    const bump = (dimIdx: number, ts: number, amt: number) => {
      const w = Math.floor((now - ts) / week);
      if (w >= 0 && w < HEAT_WEEKS && dimIdx >= 0) cells[dimIdx][HEAT_WEEKS - 1 - w] += amt;
    };
    const dimIndex = (key: string) => DIMENSIONS.findIndex((d) => key.startsWith(`${d}:`));

    for (const e of model.timeline) {
      if (e.kind === 'belief_established') bump(dimIndex(e.subject), e.ts, 3);
      if (e.kind === 'goal_created' || e.kind === 'goal_completed') bump(0, e.ts, 2);
    }
    for (const r of model.reflections) {
      for (const w of r.weakened) bump(dimIndex(w.key), r.ts, 1);
      for (const p of r.promoted) bump(dimIndex(p), r.ts, 2);
    }
    for (const d of DIMENSIONS) {
      for (const b of model[d] ?? []) bump(DIMENSIONS.indexOf(d), b.updatedAt, 1 + b.confidence);
    }
    const max = Math.max(1, ...cells.flat());
    return { cells, max };
  }, [model]);

  const hasSignal = grid.cells.flat().some((v) => v > 0);
  if (!hasSignal) return <p className="text-sm text-foreground-secondary">Evolution shows up after a little history accrues.</p>;

  return (
    <Card className="overflow-x-auto p-5">
      <div className="min-w-[420px]">
        <div className="grid gap-1" style={{ gridTemplateColumns: `72px repeat(${HEAT_WEEKS}, 1fr)` }}>
          {grid.cells.map((row, ri) => (
            <div key={ri} className="contents">
              <div className="pr-2 text-right text-[11px] leading-4 text-foreground-secondary">{DIM_SHORT[ri]}</div>
              {row.map((v, ci) => (
                <motion.div
                  key={ci}
                  className="aspect-square rounded-[3px] bg-primary"
                  initial={reduce ? false : { opacity: 0 }}
                  whileInView={{ opacity: v === 0 ? 0.06 : 0.15 + 0.85 * (v / grid.max) }}
                  viewport={{ once: true }}
                  transition={{ delay: reduce ? 0 : (ri * HEAT_WEEKS + ci) * 0.004 }}
                  title={v ? `${DIM_SHORT[ri]} · ${v.toFixed(1)} activity` : undefined}
                />
              ))}
            </div>
          ))}
        </div>
        <div className="mt-2 flex justify-between text-[11px] text-foreground-secondary">
          <span>{HEAT_WEEKS} weeks ago</span><span>This week</span>
        </div>
      </div>
    </Card>
  );
}

import { motion, useReducedMotion } from 'framer-motion';
import { Lock } from 'lucide-react';
import type { CompactBelief } from '@/api/mind';
import { Card, ConfidenceBadge, timeAgo } from './primitives';

const IDENTITY_BLURB: Record<string, string> = {
  founder: 'Talks about the company, users and fundraising like an owner.',
  engineer: 'Lives in code, debugging and implementation detail.',
  systems_thinker: 'Reaches for architecture and module boundaries first.',
  builder: 'Ships things — workspaces, prototypes, releases.',
  long_term_planner: 'Plans in roadmaps and milestones, not just next steps.',
  researcher: 'Digs for evidence before deciding.',
  creative: 'Explores ideas laterally before converging.',
  minimalist: 'Consistently strips things back to the essential.',
  profession: 'Stated role, confirmed by how they actually work.',
  organization: 'The company at the center of their work.',
};

export function beliefTitle(b: CompactBelief): string {
  const base = b.key.replace('tech:', '').replace(/_/g, ' ');
  return base.charAt(0).toUpperCase() + base.slice(1);
}

export function beliefValueText(b: CompactBelief): string | null {
  if (b.value === true || b.value === 'true') return null;
  if (b.value == null) return null;
  return typeof b.value === 'object' ? JSON.stringify(b.value) : String(b.value);
}

export function BeliefCard({ belief, onSelect }: { belief: CompactBelief; onSelect: (b: CompactBelief) => void }) {
  const reduce = useReducedMotion();
  const value = beliefValueText(belief);
  const blurb = IDENTITY_BLURB[belief.key] ?? `Inferred from ${belief.evidenceCount} observation${belief.evidenceCount === 1 ? '' : 's'}.`;

  return (
    <motion.button
      layout={!reduce}
      onClick={() => onSelect(belief)}
      className="text-left focus:outline-none focus-visible:ring-2 focus-visible:ring-primary/60 rounded-xl"
      whileHover={reduce ? undefined : { y: -2 }}
      transition={{ type: 'spring', stiffness: 320, damping: 26 }}
      aria-label={`${beliefTitle(belief)} — ${Math.round(belief.confidence * 100)} percent confidence. See why.`}
    >
      <Card className="h-full transition-colors hover:border-primary/40">
        <div className="flex items-start justify-between gap-2">
          <div className="text-sm font-semibold text-foreground">
            {beliefTitle(belief)}
            {belief.locked && <Lock className="ml-1.5 inline h-3 w-3 text-foreground-secondary" aria-label="Pinned" />}
          </div>
          {/* Key micro-moment: confidence animates when it changes */}
          <motion.div
            key={Math.round(belief.confidence * 100)}
            initial={reduce ? false : { scale: 1.25, opacity: 0.4 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ type: 'spring', stiffness: 400, damping: 20 }}
          >
            <ConfidenceBadge value={belief.confidence} />
          </motion.div>
        </div>
        {value && <div className="mt-1 truncate text-sm text-foreground-secondary">{value}</div>}
        <p className="mt-2 line-clamp-2 text-xs leading-relaxed text-foreground-secondary">{blurb}</p>
        <div className="mt-3 text-[11px] text-foreground-secondary/80">Updated {timeAgo(belief.updatedAt)}</div>
      </Card>
    </motion.button>
  );
}

export function IdentitySection({ beliefs, onSelect }: { beliefs: CompactBelief[]; onSelect: (b: CompactBelief) => void }) {
  const visible = beliefs.filter((b) => b.status !== 'archived').slice(0, 8);
  if (!visible.length) {
    return <p className="text-sm text-foreground-secondary">Identity forms as you talk — nothing inferred yet.</p>;
  }
  return (
    <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 lg:grid-cols-3">
      {visible.map((b) => <BeliefCard key={b.key} belief={b} onSelect={onSelect} />)}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';
import { X, Lock, LockOpen, Hourglass, Trash2, Check } from 'lucide-react';
import type { CompactBelief, BeliefExplanation } from '@/api/mind';
import { explainBelief, correctBelief, setBeliefLock, setBeliefTemporary, deleteBelief } from '@/api/mind';
import { useMindStore } from '@/stores/mindStore';
import { ConfidenceBadge, timeAgo } from './primitives';
import { beliefTitle, beliefValueText } from './IdentitySection';

/* Explainability (why Aqua believes this) + corrections (change it) in one
   panel. Every mutation is optimistic through the store, so confidence
   visibly changes the instant you act. */

export function BeliefDrawer({ belief, onClose }: { belief: CompactBelief | null; onClose: () => void }) {
  const reduce = useReducedMotion();
  const applyBelief = useMindStore((s) => s.applyBelief);
  const removeBelief = useMindStore((s) => s.removeBelief);

  const [explanation, setExplanation] = useState<BeliefExplanation | null>(null);
  const [draft, setDraft] = useState('');
  const [busy, setBusy] = useState(false);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    setExplanation(null);
    setSaved(false);
    if (!belief) return;
    setDraft(beliefValueText(belief) ?? '');
    explainBelief(belief.dimension, belief.key).then(setExplanation).catch(() => setExplanation(null));
  }, [belief]);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => e.key === 'Escape' && onClose();
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose]);

  const run = async (fn: () => Promise<CompactBelief | void>, close = false) => {
    if (!belief || busy) return;
    setBusy(true);
    try {
      const updated = await fn();
      if (updated) { applyBelief(updated); setSaved(true); setTimeout(() => setSaved(false), 1400); }
      if (close) onClose();
    } finally {
      setBusy(false);
    }
  };

  return (
    <AnimatePresence>
      {belief && (
        <>
          <motion.div
            className="fixed inset-0 z-40 bg-black/35"
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            onClick={onClose}
            aria-hidden
          />
          <motion.aside
            role="dialog"
            aria-modal="true"
            aria-label={`Why Aqua believes ${beliefTitle(belief)}`}
            className="fixed inset-y-0 right-0 z-50 flex w-full max-w-md flex-col border-l border-border bg-surface shadow-xl"
            initial={reduce ? { opacity: 0 } : { x: '100%' }}
            animate={reduce ? { opacity: 1 } : { x: 0 }}
            exit={reduce ? { opacity: 0 } : { x: '100%' }}
            transition={{ type: 'spring', stiffness: 300, damping: 32 }}
          >
            <header className="flex items-start justify-between gap-3 border-b border-border p-5">
              <div>
                <div className="text-[11px] uppercase tracking-[0.16em] text-foreground-secondary">{belief.dimension}</div>
                <h3 className="mt-1 text-lg font-semibold text-foreground">{beliefTitle(belief)}</h3>
                <div className="mt-1.5 flex items-center gap-2">
                  <ConfidenceBadge value={belief.confidence} />
                  <span className="text-xs text-foreground-secondary">Updated {timeAgo(belief.updatedAt)}</span>
                </div>
              </div>
              <button onClick={onClose} className="rounded-lg p-2 text-foreground-secondary hover:bg-surface-secondary" aria-label="Close">
                <X className="h-4 w-4" />
              </button>
            </header>

            <div className="min-h-0 flex-1 space-y-6 overflow-y-auto p-5">
              {/* Why */}
              <section>
                <div className="mb-2 text-[11px] font-medium uppercase tracking-[0.14em] text-foreground-secondary">Why Aqua believes this</div>
                {explanation ? (
                  <>
                    <p className="text-sm leading-relaxed text-foreground">{explanation.explanation}</p>
                    {explanation.recentEvidence.length > 0 && (
                      <ul className="mt-3 space-y-1.5">
                        {explanation.recentEvidence.slice().reverse().map((ev, i) => (
                          <li key={i} className="flex items-start gap-2 text-xs text-foreground-secondary">
                            <span className={`mt-1 h-1.5 w-1.5 shrink-0 rounded-full ${ev.support === false ? 'bg-warning' : 'bg-primary'}`} />
                            <span>{ev.correction ? 'You corrected this' : ev.signal} · {timeAgo(ev.ts)}</span>
                          </li>
                        ))}
                      </ul>
                    )}
                  </>
                ) : (
                  <p className="text-sm text-foreground-secondary">Tracing evidence…</p>
                )}
              </section>

              {/* Correct */}
              <section>
                <div className="mb-2 text-[11px] font-medium uppercase tracking-[0.14em] text-foreground-secondary">Correct it</div>
                <p className="mb-2 text-xs text-foreground-secondary">Your word outranks inference. Aqua learns from the correction.</p>
                <div className="flex gap-2">
                  <input
                    value={draft}
                    onChange={(e) => setDraft(e.target.value)}
                    placeholder="What’s actually true?"
                    className="min-w-0 flex-1 rounded-lg border border-border bg-background px-3 py-2 text-sm text-foreground placeholder:text-foreground-secondary focus:outline-none focus-visible:ring-2 focus-visible:ring-primary/60"
                  />
                  <button
                    disabled={busy || !draft.trim()}
                    onClick={() => run(() => correctBelief(belief.dimension, belief.key, draft.trim()))}
                    className="inline-flex items-center gap-1.5 rounded-lg bg-primary px-3 py-2 text-sm font-medium text-primary-foreground disabled:opacity-50"
                  >
                    {saved ? <Check className="h-4 w-4" /> : null}{saved ? 'Saved' : 'Save'}
                  </button>
                </div>
              </section>

              {/* Control */}
              <section>
                <div className="mb-2 text-[11px] font-medium uppercase tracking-[0.14em] text-foreground-secondary">Control</div>
                <div className="grid grid-cols-1 gap-2">
                  <button
                    disabled={busy}
                    onClick={() => run(() => setBeliefLock(belief.dimension, belief.key, !belief.locked))}
                    className="flex items-center gap-2 rounded-lg border border-border px-3 py-2 text-sm text-foreground hover:bg-surface-secondary"
                  >
                    {belief.locked ? <LockOpen className="h-4 w-4" /> : <Lock className="h-4 w-4" />}
                    {belief.locked ? 'Unpin — allow it to evolve again' : 'Pin — never changed by inference'}
                  </button>
                  <button
                    disabled={busy}
                    onClick={() => run(() => setBeliefTemporary(belief.dimension, belief.key, !belief.temporary))}
                    className="flex items-center gap-2 rounded-lg border border-border px-3 py-2 text-sm text-foreground hover:bg-surface-secondary"
                  >
                    <Hourglass className="h-4 w-4" />
                    {belief.temporary ? 'Keep — allow it to become permanent' : 'Mark temporary — never made permanent'}
                  </button>
                  <button
                    disabled={busy}
                    onClick={() => run(async () => { await deleteBelief(belief.dimension, belief.key); removeBelief(belief.dimension, belief.key); }, true)}
                    className="flex items-center gap-2 rounded-lg border border-danger/40 px-3 py-2 text-sm text-danger hover:bg-danger/10"
                  >
                    <Trash2 className="h-4 w-4" />
                    Forget this entirely
                  </button>
                </div>
              </section>
            </div>
          </motion.aside>
        </>
      )}
    </AnimatePresence>
  );
}

import { useEffect, useMemo, useRef, useState } from 'react';
import { motion, useReducedMotion } from 'framer-motion';
import { fetchGraph, type GraphNode, type GraphEdge } from '@/api/mind';
import { Card } from './primitives';

/* ────────────────────────────────────────────────────────────────────────
   Relationship graph — radial constellation, no graph library.

   You sit at the center. Node types occupy concentric rings
   (organizations → projects → goals → technologies), so distance from
   the center encodes the kind of relationship. Edges are quiet quadratic
   curves; weight = opacity. Wheel zooms, drag pans, hover highlights the
   1-hop neighborhood.
   ──────────────────────────────────────────────────────────────────────── */

const RING: Record<string, number> = {
  person: 120, organization: 120, project: 200, goal: 275, technology: 275, episode: 340, artifact: 340,
};
const TYPE_LABEL: Record<string, string> = {
  person: 'People', organization: 'Organizations', project: 'Projects',
  goal: 'Goals', technology: 'Technologies', episode: 'Episodes', artifact: 'Artifacts',
};
const W = 760, H = 560, CX = W / 2, CY = H / 2;

interface Positioned extends GraphNode { x: number; y: number; self: boolean }

function layout(nodes: GraphNode[]): Positioned[] {
  const self = nodes.find((n) => n.key === 'person:__self__');
  const others = nodes.filter((n) => n.key !== 'person:__self__');
  const byRing = new Map<number, GraphNode[]>();
  for (const n of others) {
    const r = RING[n.type] ?? 340;
    if (!byRing.has(r)) byRing.set(r, []);
    byRing.get(r)!.push(n);
  }
  const out: Positioned[] = [];
  if (self) out.push({ ...self, x: CX, y: CY, self: true });
  for (const [r, list] of byRing) {
    const sorted = [...list].sort((a, b) => b.weight - a.weight);
    sorted.forEach((n, i) => {
      const angle = (i / sorted.length) * Math.PI * 2 - Math.PI / 2 + (r % 97) * 0.01;
      out.push({ ...n, x: CX + r * Math.cos(angle), y: CY + r * Math.sin(angle), self: false });
    });
  }
  return out;
}

export function RelationshipGraph() {
  const reduce = useReducedMotion();
  const [nodes, setNodes] = useState<GraphNode[] | null>(null);
  const [edges, setEdges] = useState<GraphEdge[]>([]);
  const [error, setError] = useState(false);
  const [hover, setHover] = useState<string | null>(null);
  const [view, setView] = useState({ x: 0, y: 0, k: 1 });
  const drag = useRef<{ x: number; y: number } | null>(null);
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    fetchGraph().then((g) => { setNodes(g.nodes); setEdges(g.edges); }).catch(() => setError(true));
  }, []);

  const positioned = useMemo(() => (nodes ? layout(nodes) : []), [nodes]);
  const posByKey = useMemo(() => new Map(positioned.map((n) => [n.key, n])), [positioned]);
  const neighborhood = useMemo(() => {
    if (!hover) return null;
    const set = new Set([hover]);
    for (const e of edges) {
      if (e.from === hover) set.add(e.to);
      if (e.to === hover) set.add(e.from);
    }
    return set;
  }, [hover, edges]);

  // Wheel zoom (non-passive so preventDefault works)
  useEffect(() => {
    const el = svgRef.current;
    if (!el) return;
    const onWheel = (ev: WheelEvent) => {
      ev.preventDefault();
      setView((v) => ({ ...v, k: Math.min(2.5, Math.max(0.5, v.k * (ev.deltaY < 0 ? 1.1 : 0.9))) }));
    };
    el.addEventListener('wheel', onWheel, { passive: false });
    return () => el.removeEventListener('wheel', onWheel);
  }, []);

  if (error) return <p className="text-sm text-foreground-secondary">The graph couldn’t load — it will return with the next update.</p>;
  if (!nodes) return <Card className="flex h-72 items-center justify-center text-sm text-foreground-secondary">Mapping relationships…</Card>;
  if (positioned.length <= 1) return <p className="text-sm text-foreground-secondary">Mention people, projects and tools — the map draws itself.</p>;

  return (
    <Card className="p-2">
      <svg
        ref={svgRef}
        viewBox={`0 0 ${W} ${H}`}
        className="h-[420px] w-full cursor-grab touch-none select-none active:cursor-grabbing"
        role="img"
        aria-label="Relationship graph: you at the center, connected to organizations, projects, goals and technologies"
        onPointerDown={(e) => { drag.current = { x: e.clientX, y: e.clientY }; (e.target as Element).setPointerCapture?.(e.pointerId); }}
        onPointerMove={(e) => {
          if (!drag.current) return;
          const dx = e.clientX - drag.current.x, dy = e.clientY - drag.current.y;
          drag.current = { x: e.clientX, y: e.clientY };
          setView((v) => ({ ...v, x: v.x + dx / v.k, y: v.y + dy / v.k }));
        }}
        onPointerUp={() => (drag.current = null)}
        onPointerLeave={() => (drag.current = null)}
      >
        <g transform={`translate(${CX},${CY}) scale(${view.k}) translate(${-CX + view.x},${-CY + view.y})`}>
          {/* Ring guides */}
          {[...new Set(Object.values(RING))].map((r) => (
            <circle key={r} cx={CX} cy={CY} r={r} fill="none" stroke="var(--border)" strokeWidth={1} opacity={0.35} strokeDasharray="2 5" />
          ))}
          {/* Edges */}
          {edges.map((e) => {
            const a = posByKey.get(e.from), b = posByKey.get(e.to);
            if (!a || !b) return null;
            const mx = (a.x + b.x) / 2 + (a.y - b.y) * 0.12;
            const my = (a.y + b.y) / 2 + (b.x - a.x) * 0.12;
            const active = !neighborhood || (neighborhood.has(e.from) && neighborhood.has(e.to));
            return (
              <path
                key={e.key}
                d={`M ${a.x} ${a.y} Q ${mx} ${my} ${b.x} ${b.y}`}
                fill="none"
                stroke="var(--primary)"
                strokeWidth={Math.min(2.5, 0.75 + e.weight * 0.25)}
                opacity={active ? Math.min(0.55, 0.18 + e.weight * 0.08) : 0.05}
              />
            );
          })}
          {/* Nodes */}
          {positioned.map((n, i) => {
            const dim = neighborhood ? !neighborhood.has(n.key) : false;
            const r = n.self ? 22 : Math.min(16, 7 + n.weight * 1.2);
            return (
              <motion.g
                key={n.key}
                initial={reduce ? false : { opacity: 0, scale: 0.6 }}
                animate={{ opacity: dim ? 0.15 : 1, scale: 1 }}
                transition={{ delay: reduce ? 0 : Math.min(0.6, i * 0.03), type: 'spring', stiffness: 260, damping: 22 }}
                onPointerEnter={() => setHover(n.key)}
                onPointerLeave={() => setHover(null)}
                style={{ cursor: 'pointer' }}
              >
                <circle cx={n.x} cy={n.y} r={r} fill={n.self ? 'var(--primary)' : 'var(--surface)'}
                        stroke="var(--primary)" strokeWidth={n.self ? 0 : 1.5} />
                <text
                  x={n.x} y={n.y + r + 13} textAnchor="middle"
                  className="fill-[var(--text-secondary)]"
                  style={{ fontSize: 11, fontFamily: 'var(--font-sans)' }}
                >
                  {n.self ? 'You' : n.label.length > 18 ? n.label.slice(0, 17) + '…' : n.label}
                </text>
              </motion.g>
            );
          })}
        </g>
      </svg>
      <div className="flex flex-wrap items-center justify-between gap-2 px-3 pb-2 pt-1">
        <div className="flex flex-wrap gap-x-4 gap-y-1 text-[11px] text-foreground-secondary">
          {[...new Set(nodes.filter((n) => n.key !== 'person:__self__').map((n) => n.type))].map((t) => (
            <span key={t}>{TYPE_LABEL[t] ?? t}</span>
          ))}
        </div>
        <span className="text-[11px] text-foreground-secondary">Scroll to zoom · drag to pan</span>
      </div>
    </Card>
  );
}

import { useEffect, useState } from 'react';
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';
import { BrainCircuit, Download, Trash2, Lock, Hourglass, Eye } from 'lucide-react';
import type { MindModel } from '@/api/mind';
import { exportMindUrl, eraseMind } from '@/api/mind';
import { useMindStore, DIMENSIONS } from '@/stores/mindStore';
import { Card } from './primitives';

/* ── Reflection — watch Aqua think (plays when a reflection lands) ───────── */

const STEPS = ['Reviewing what changed…', 'Updating beliefs…', 'Adjusting confidence…', 'Archiving what went stale…', 'Refreshing predictions…'];

export function ReflectionOverlay() {
  const reduce = useReducedMotion();
  const playing = useMindStore((s) => s.reflectionPlaying);
  const dismiss = useMindStore((s) => s.dismissReflection);
  const [step, setStep] = useState(0);

  useEffect(() => {
    if (!playing) return;
    setStep(0);
    if (reduce) { const t = setTimeout(dismiss, 1600); return () => clearTimeout(t); }
    const iv = setInterval(() => setStep((s) => s + 1), 850);
    const done = setTimeout(dismiss, 850 * STEPS.length + 700);
    return () => { clearInterval(iv); clearTimeout(done); };
  }, [playing, dismiss, reduce]);

  return (
    <AnimatePresence>
      {playing && (
        <motion.div
          role="status"
          aria-live="polite"
          className="pointer-events-none fixed inset-x-0 top-4 z-50 flex justify-center px-4"
          initial={{ opacity: 0, y: -12 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -12 }}
        >
          <div className="pointer-events-auto flex items-center gap-3 rounded-full border border-border bg-surface px-4 py-2.5 shadow-lg">
            <motion.span
              animate={reduce ? undefined : { rotate: 360 }}
              transition={reduce ? undefined : { duration: 3, repeat: Infinity, ease: 'linear' }}
              className="text-primary"
            >
              <BrainCircuit className="h-4 w-4" />
            </motion.span>
            <span className="text-sm font-medium text-foreground">Aqua is reflecting</span>
            <span className="hidden text-sm text-foreground-secondary sm:inline">
              <AnimatePresence mode="wait">
                <motion.span
                  key={Math.min(step, STEPS.length - 1)}
                  initial={{ opacity: 0, y: 4 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -4 }}
                  transition={{ duration: 0.2 }}
                >
                  {STEPS[Math.min(step, STEPS.length - 1)]}
                </motion.span>
              </AnimatePresence>
            </span>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

/* ── Privacy — complete control ─────────────────────────────────────────── */

export function PrivacyPanel({ model }: { model: MindModel }) {
  const clear = useMindStore((s) => s.clear);
  const [confirming, setConfirming] = useState(false);
  const [erasing, setErasing] = useState(false);

  const beliefs = DIMENSIONS.flatMap((d) => model[d] ?? []);
  const permanent = beliefs.filter((b) => !b.temporary && b.status !== 'archived').length;
  const temporary = beliefs.filter((b) => b.temporary).length;
  const pinned = beliefs.filter((b) => b.locked).length;

  const erase = async () => {
    setErasing(true);
    try { await eraseMind(); clear(); } finally { setErasing(false); setConfirming(false); }
  };

  return (
    <Card className="p-5">
      <div className="grid grid-cols-2 gap-4 sm:grid-cols-4">
        <Stat icon={<Eye className="h-3.5 w-3.5" />} label="Remembered" value={beliefs.length + model.goals.length} />
        <Stat icon={<BrainCircuit className="h-3.5 w-3.5" />} label="Permanent" value={permanent} />
        <Stat icon={<Hourglass className="h-3.5 w-3.5" />} label="Temporary" value={temporary} />
        <Stat icon={<Lock className="h-3.5 w-3.5" />} label="Pinned by you" value={pinned} />
      </div>

      <p className="mt-4 text-xs leading-relaxed text-foreground-secondary">
        This model belongs to you. Everything is private to your account, every belief explains its evidence,
        and you can pin, mark temporary, correct or delete any of it — or all of it.
      </p>

      <div className="mt-4 flex flex-wrap gap-2">
        <a
          href={exportMindUrl()}
          download
          className="inline-flex items-center gap-2 rounded-lg border border-border px-3 py-2 text-sm text-foreground hover:bg-surface-secondary"
        >
          <Download className="h-4 w-4" /> Export everything
        </a>
        {!confirming ? (
          <button
            onClick={() => setConfirming(true)}
            className="inline-flex items-center gap-2 rounded-lg border border-danger/40 px-3 py-2 text-sm text-danger hover:bg-danger/10"
          >
            <Trash2 className="h-4 w-4" /> Delete the entire model
          </button>
        ) : (
          <span className="inline-flex items-center gap-2">
            <button
              onClick={erase}
              disabled={erasing}
              className="rounded-lg bg-danger px-3 py-2 text-sm font-medium text-white disabled:opacity-60"
            >
              {erasing ? 'Deleting…' : 'Yes, delete everything'}
            </button>
            <button onClick={() => setConfirming(false)} className="rounded-lg border border-border px-3 py-2 text-sm text-foreground">
              Keep it
            </button>
          </span>
        )}
      </div>
    </Card>
  );
}

function Stat({ icon, label, value }: { icon: React.ReactNode; label: string; value: number }) {
  return (
    <div>
      <div className="flex items-center gap-1.5 text-[11px] uppercase tracking-[0.14em] text-foreground-secondary">{icon}{label}</div>
      <div className="mt-1 text-2xl font-semibold tabular-nums text-foreground">{value}</div>
    </div>
  );
}

@import 'tailwindcss';

/* Manual dark-mode variant — toggled by adding/removing `.dark` on <html>.
   Kept in sync with the bootstrap script in index.html. */
@custom-variant dark (&:where(.dark, .dark *));

/* ──────────────────────────────────────────────────────────────────────
   Design tokens
   Light theme: ChatGPT Light / Linear / Vercel / Notion
   Dark theme:  Claude Dark / ChatGPT Dark / Raycast / Vercel Dark
   ────────────────────────────────────────────────────────────────────── */
:root {
  --background: #fafaf8;
  --surface: #ffffff;
  --surface-secondary: #f3f3f0;
  --border: #e8e6e1;
  --primary: #106b7e;
  --primary-foreground: #ffffff;
  --accent: #0d5967;
  --text: #17191d;
  --text-secondary: #5c6470;

  --danger: #c2453e;
  --warning: #b07a2e;
  --success: #2e7d4f;

  --radius: 0.625rem;

  --font-sans: 'Inter', ui-sans-serif, system-ui, -apple-system, sans-serif;
  --font-mono: 'JetBrains Mono', ui-monospace, 'SF Mono', Menlo, monospace;
}

.dark {
  --background: #0b0e12;
  --surface: #11151b;
  --surface-secondary: #171c24;
  --border: #232a34;
  --primary: #4fa3b8;
  --primary-foreground: #0b0e12;
  --accent: #6fbdd0;
  --text: #e8ecf1;
  --text-secondary: #9aa4b2;

  --danger: #e5726b;
  --warning: #d8a35a;
  --success: #6fbf8f;
}

/* Map tokens into Tailwind's theme so utilities like bg-background,
   text-foreground, border-border, etc. resolve to the variables above and
   switch automatically with the .dark class. Never hardcode hex in
   components — use these utilities instead. */
@theme inline {
  --color-background: var(--background);
  --color-surface: var(--surface);
  --color-surface-secondary: var(--surface-secondary);
  --color-border: var(--border);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-accent: var(--accent);
  --color-foreground: var(--text);
  --color-foreground-secondary: var(--text-secondary);
  --color-danger: var(--danger);
  --color-warning: var(--warning);
  --color-success: var(--success);

  --radius-sm: calc(var(--radius) - 0.375rem);
  --radius-md: calc(var(--radius) - 0.25rem);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 0.25rem);

  --font-sans: var(--font-sans);
  --font-mono: var(--font-mono);

  --animate-fade-in: fade-in 0.15s ease-out;
  --animate-slide-up: slide-up 0.2s cubic-bezier(0.16, 1, 0.3, 1);

  @keyframes fade-in {
    from {
      opacity: 0;
    }
    to {
      opacity: 1;
    }
  }
  @keyframes slide-up {
    from {
      opacity: 0;
      transform: translateY(4px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }
}

@layer base {
  * {
    border-color: var(--border);
  }

  html {
    color-scheme: light;
  }
  html.dark {
    color-scheme: dark;
  }

  html[data-font-size='sm'] {
    font-size: 14px;
  }
  html[data-font-size='md'] {
    font-size: 16px;
  }
  html[data-font-size='lg'] {
    font-size: 18px;
  }

  html[data-compact='true'] .message-row {
    padding-top: 0.375rem;
    padding-bottom: 0.375rem;
  }

  body {
    background-color: var(--color-background);
    color: var(--color-foreground);
    font-family: var(--font-sans);
    font-feature-settings: 'cv11', 'ss01';
    -webkit-font-smoothing: antialiased;
    text-rendering: optimizeLegibility;
  }

  ::selection {
    background-color: color-mix(in srgb, var(--color-primary) 30%, transparent);
  }

  /* Visible, premium focus ring — never remove focus outlines. */
  :focus-visible {
    outline: 2px solid var(--color-primary);
    outline-offset: 2px;
    border-radius: 4px;
  }

  /* Thin, unobtrusive scrollbars matching the surface palette. */
  * {
    scrollbar-width: thin;
    scrollbar-color: var(--color-border) transparent;
  }
  *::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }
  *::-webkit-scrollbar-thumb {
    background-color: var(--color-border);
    border-radius: 999px;
  }
  *::-webkit-scrollbar-track {
    background: transparent;
  }

  @media (prefers-reduced-motion: reduce) {
    *,
    *::before,
    *::after {
      animation-duration: 0.01ms !important;
      animation-iteration-count: 1 !important;
      transition-duration: 0.01ms !important;
      scroll-behavior: auto !important;
    }
  }
}

@layer utilities {
  .text-balance {
    text-wrap: balance;
  }

  /* ── Streaming cursor ─────────────────────────────────────────────────
     Blinking caret appended after the last streamed block — the visual
     signal that tokens are still arriving. */
  .streaming-cursor {
    display: inline-block;
    width: 0.55em;
    height: 1.05em;
    margin-left: 0.15em;
    vertical-align: text-bottom;
    border-radius: 2px;
    background-color: var(--color-primary);
    animation: cursor-blink 1s steps(2, start) infinite;
  }
  @keyframes cursor-blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0; }
  }

  /* ── Thinking-stage shimmer ───────────────────────────────────────────
     Subtle left-to-right sheen over the live pipeline stage label
     ("Reading workspace…"), signalling active work without fake progress. */
  .thinking-shimmer {
    background: linear-gradient(
      90deg,
      var(--color-foreground-secondary) 0%,
      var(--color-foreground) 45%,
      var(--color-foreground-secondary) 90%
    );
    background-size: 200% 100%;
    -webkit-background-clip: text;
    background-clip: text;
    -webkit-text-fill-color: transparent;
    color: transparent;
    animation: shimmer-slide 1.8s linear infinite;
  }
  @keyframes shimmer-slide {
    from { background-position: 180% 0; }
    to { background-position: -20% 0; }
  }

  @media (prefers-reduced-motion: reduce) {
    .streaming-cursor {
      animation: none;
      opacity: 0.7;
    }
    .thinking-shimmer {
      animation: none;
      -webkit-text-fill-color: currentColor;
      color: var(--color-foreground-secondary);
      background: none;
    }
  }
}

