/**
 * Client-side upload classification — mirrors aqua/src/upload/uploadClassifier.js.
 * Used only for instant UI (icons, size limits, hints); the backend
 * re-classifies with magic-byte verification regardless.
 */
export type UploadKind = 'repository' | 'source' | 'document' | 'image' | 'audio' | 'video' | 'unknown';

const ARCHIVE_EXTS  = ['.zip', '.tar', '.tar.gz', '.tgz', '.gz'];
const DOCUMENT_EXTS = ['.pdf', '.docx', '.pptx', '.xlsx', '.csv', '.odt', '.epub'];
const IMAGE_EXTS    = ['.png', '.jpg', '.jpeg', '.webp', '.gif', '.svg', '.heic', '.heif'];
const AUDIO_EXTS    = ['.mp3', '.wav', '.m4a'];
const VIDEO_EXTS    = ['.mp4', '.mov', '.avi'];
const SOURCE_EXTS   = [
  '.js', '.mjs', '.cjs', '.ts', '.tsx', '.jsx', '.py', '.java', '.kt', '.go', '.rs',
  '.cs', '.cpp', '.cc', '.c', '.h', '.hpp', '.php', '.rb', '.swift', '.md', '.mdx',
  '.txt', '.json', '.yaml', '.yml', '.toml', '.xml', '.html', '.htm', '.css', '.scss',
  '.sass', '.less', '.sql', '.graphql', '.gql', '.proto', '.sh', '.bash', '.zsh',
  '.env', '.tf', '.vue', '.svelte', '.log', '.ini', '.cfg', '.conf', '.tsv',
];

export function classifyFile(name: string): UploadKind {
  const lower = name.toLowerCase();
  const has = (exts: string[]) => exts.some((e) => lower.endsWith(e));
  if (has(ARCHIVE_EXTS))  return 'repository';
  if (has(DOCUMENT_EXTS)) return 'document';
  if (has(IMAGE_EXTS))    return 'image';
  if (has(AUDIO_EXTS))    return 'audio';
  if (has(VIDEO_EXTS))    return 'video';
  if (has(SOURCE_EXTS) || ['dockerfile', 'makefile', 'gemfile', 'procfile', 'license', 'readme'].includes(lower)) return 'source';
  return 'unknown';
}

/** Per-kind client-side size limits (backend enforces its own — these fail fast). */
export const MAX_BYTES_BY_KIND: Record<UploadKind, number> = {
  repository: 35_000_000, // base64 inflates 4/3 into the 50 MB JSON body limit
  document:   15_000_000,
  image:      12_000_000,
  audio:      14_000_000,
  video:      14_000_000,
  source:      2_000_000,
  unknown:     1,          // rejected client-side with a clear message anyway
};

export function readAsBase64(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = String(reader.result ?? '');
      const commaIdx = result.indexOf(',');
      resolve(commaIdx >= 0 ? result.slice(commaIdx + 1) : result);
    };
    reader.onerror = () => reject(reader.error ?? new Error('Failed to read file'));
    reader.readAsDataURL(file);
  });
}

/**
 * The composer's "attach" affordance inlines small text files directly into
 * the outgoing /chat message (no backend endpoint needed for this — it's
 * just string content). This is intentionally text/source-only: AQUA's
 * project ingester (aqua/src/project/fileIngester.js) explicitly drops
 * images, PDFs, and other binaries via IGNORE_EXTS + a binary-content
 * sniff, so offering to "attach" them here would silently go nowhere.
 * Bulk source-code ingestion for real project context lives in Project
 * Upload instead, which mirrors the backend's actual capability (zip /
 * multi-file → workspace → indexed).
 */
export const ACCEPTED_TEXT_EXTENSIONS = [
  '.txt', '.md', '.mdx', '.json', '.csv', '.tsv', '.yaml', '.yml', '.toml', '.env',
  '.js', '.mjs', '.cjs', '.ts', '.tsx', '.jsx', '.py', '.java', '.kt', '.go', '.rs',
  '.cs', '.cpp', '.cc', '.c', '.h', '.hpp', '.php', '.rb', '.swift', '.sh', '.bash',
  '.html', '.css', '.scss', '.sql', '.graphql', '.xml', '.vue', '.svelte', '.log',
];

export const MAX_ATTACHMENT_BYTES = 100_000; // mirrors backend MAX_FILE_SIZE in fileIngester.js

export function isAcceptedTextFile(file: File): boolean {
  const lower = file.name.toLowerCase();
  return ACCEPTED_TEXT_EXTENSIONS.some((ext) => lower.endsWith(ext));
}

export function readFileAsText(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result ?? ''));
    reader.onerror = () => reject(reader.error ?? new Error('Failed to read file'));
    reader.readAsText(file);
  });
}

/** Folds attachments into the outgoing message as labeled fenced blocks. */
export function buildMessageWithAttachments(
  text: string,
  attachments: Array<{ name: string; content: string }>,
): string {
  if (attachments.length === 0) return text;
  const blocks = attachments
    .map((a) => `\`${a.name}\`:\n\`\`\`\n${a.content}\n\`\`\``)
    .join('\n\n');
  return text.trim() ? `${text}\n\n${blocks}` : blocks;
}

export function exportMarkdown(content: string, filenameBase = 'aqua-message') {
  const blob = new Blob([content], { type: 'text/markdown;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${filenameBase}.md`;
  a.click();
  URL.revokeObjectURL(url);
}

/**
 * No PDF-generation library is pulled in for this — the browser's own
 * print pipeline already renders headings/code/tables correctly and lets
 * the user pick "Save as PDF" with zero added bundle weight or the layout
 * drift that html2canvas-style rasterization tends to introduce.
 */
export function exportPdf(html: string, title = 'AQUA') {
  const win = window.open('', '_blank', 'width=800,height=1000');
  if (!win) return false;

  win.document.write(`<!doctype html>
<html>
<head>
<meta charset="utf-8" />
<title>${title}</title>
<style>
  body { font-family: -apple-system, Inter, system-ui, sans-serif; color: #0f172a; max-width: 720px; margin: 40px auto; padding: 0 24px; line-height: 1.6; }
  pre { background: #f1f5f9; padding: 12px 14px; border-radius: 8px; overflow-x: auto; font-size: 13px; }
  code { font-family: 'JetBrains Mono', ui-monospace, monospace; }
  :not(pre) > code { background: #f1f5f9; padding: 1px 5px; border-radius: 4px; }
  table { border-collapse: collapse; width: 100%; }
  th, td { border: 1px solid #e2e8f0; padding: 6px 10px; text-align: left; }
  blockquote { border-left: 3px solid #94a3b8; margin: 0; padding-left: 12px; color: #475569; }
  @media print { body { margin: 0; } }
</style>
</head>
<body>${html}</body>
</html>`);
  win.document.close();
  win.focus();
  // Give the new document a tick to paint before invoking print.
  setTimeout(() => win.print(), 300);
  return true;
}

export async function shareText(text: string): Promise<'shared' | 'copied' | 'failed'> {
  if (navigator.share) {
    try {
      await navigator.share({ text });
      return 'shared';
    } catch {
      // user cancelled the native share sheet — not an error worth surfacing
      return 'failed';
    }
  }
  try {
    await navigator.clipboard.writeText(text);
    return 'copied';
  } catch {
    return 'failed';
  }
}

// Mirrors aqua/src/project/fileIngester.js IGNORE_DIRS / IGNORE_EXTS / IGNORE_FILES.
// Keep in sync with the backend — this is a client-side pre-filter only,
// the server re-applies its own rules regardless.
const IGNORE_DIRS = new Set([
  'node_modules', 'vendor', 'build', 'dist', 'target', '.git',
  '__pycache__', '.next', '.nuxt', '.cache', 'coverage', '.nyc_output',
  'out', 'tmp', 'temp', 'logs', '.turbo', '.svelte-kit', '.angular',
]);

const IGNORE_EXTS = new Set([
  '.png', '.jpg', '.jpeg', '.gif', '.svg', '.ico', '.webp', '.bmp',
  '.mp4', '.mp3', '.wav', '.mov', '.avi', '.pdf', '.zip', '.tar',
  '.gz', '.rar', '.7z', '.exe', '.dll', '.so', '.dylib', '.bin',
  '.pyc', '.class', '.o', '.a', '.lib', '.wasm',
  '.ttf', '.woff', '.woff2', '.eot', '.otf', '.map',
]);

const IGNORE_FILES = new Set([
  'package-lock.json', 'yarn.lock', 'pnpm-lock.yaml', 'bun.lockb',
  'poetry.lock', 'Pipfile.lock', 'Cargo.lock', 'composer.lock',
]);

export function shouldIgnoreClientSide(filePath: string): boolean {
  const normalised = filePath.replace(/\\/g, '/');
  const parts = normalised.split('/');
  const basename = parts[parts.length - 1];

  if (IGNORE_FILES.has(basename)) return true;
  if (basename.endsWith('.lock')) return true;
  if (basename.endsWith('.min.js') || basename.endsWith('.min.css')) return true;

  for (const part of parts.slice(0, -1)) {
    if (IGNORE_DIRS.has(part)) return true;
    if (part.startsWith('.') && part !== '.github') return true;
  }

  const dotIdx = basename.lastIndexOf('.');
  const ext = dotIdx >= 0 ? basename.slice(dotIdx).toLowerCase() : '';
  return IGNORE_EXTS.has(ext);
}

export function readAsText(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result ?? ''));
    reader.onerror = () => reject(reader.error ?? new Error('Failed to read file'));
    reader.readAsText(file);
  });
}

/** Returns base64 payload only (strips the `data:...;base64,` prefix). */
export function readAsBase64(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = String(reader.result ?? '');
      const commaIdx = result.indexOf(',');
      resolve(commaIdx >= 0 ? result.slice(commaIdx + 1) : result);
    };
    reader.onerror = () => reject(reader.error ?? new Error('Failed to read file'));
    reader.readAsDataURL(file);
  });
}

import { useEffect, useState } from 'react';
import { MessageSquarePlus, RefreshCcw } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import type { CompactBelief } from '@/api/mind';
import { useMindStore } from '@/stores/mindStore';
import { SectionHeader } from '@/features/mind/primitives';
import { UnderstandingRing } from '@/features/mind/UnderstandingRing';
import { IdentitySection } from '@/features/mind/IdentitySection';
import { GoalsSection, WorkingMemorySection, PredictionsSection } from '@/features/mind/NowSections';
import { KnowledgeSection, CommunicationSection } from '@/features/mind/ModelSections';
import { LearningFeed, MindTimeline, EvolutionHeatmap } from '@/features/mind/StorySections';
import { RelationshipGraph } from '@/features/mind/RelationshipGraph';
import { BeliefDrawer } from '@/features/mind/BeliefDrawer';
import { ReflectionOverlay, PrivacyPanel } from '@/features/mind/ReflectionAndPrivacy';

/* The Mind dashboard — the product view of AQUA's cognitive model.
   Data flows only through mindStore; refreshes are event-driven
   (mount, window focus, after each chat turn). No polling. */

export default function MindPage() {
  const navigate = useNavigate();
  const { model, loading, error, hasLoadedOnce, learnings, refresh } = useMindStore();
  const [selected, setSelected] = useState<CompactBelief | null>(null);

  useEffect(() => {
    void refresh();
    const onFocus = () => void refresh({ silent: true });
    window.addEventListener('focus', onFocus);
    return () => window.removeEventListener('focus', onFocus);
  }, [refresh]);

  // Keep the drawer's belief in sync with live updates
  useEffect(() => {
    if (!selected || !model) return;
    const fresh = (model[selected.dimension] ?? []).find((b) => b.key === selected.key);
    if (fresh && fresh !== selected) setSelected(fresh);
    if (!fresh) setSelected(null);
  }, [model, selected]);

  if (!hasLoadedOnce && loading) {
    return <CenterNote>Reading the model…</CenterNote>;
  }

  if (error && !model) {
    return (
      <CenterNote>
        <p className="text-foreground">The mind model couldn’t load.</p>
        <p className="mt-1 text-sm text-foreground-secondary">{error}</p>
        <button
          onClick={() => void refresh()}
          className="mt-4 inline-flex items-center gap-2 rounded-lg border border-border px-3 py-2 text-sm text-foreground hover:bg-surface-secondary"
        >
          <RefreshCcw className="h-4 w-4" /> Try again
        </button>
      </CenterNote>
    );
  }

  if (!model) {
    return (
      <CenterNote>
        <p className="text-lg font-semibold text-foreground">Nothing here yet — and that’s the point.</p>
        <p className="mx-auto mt-2 max-w-sm text-sm leading-relaxed text-foreground-secondary">
          Aqua builds its understanding of you from real conversations, not a questionnaire.
          Start one, and watch this page come alive.
        </p>
        <button
          onClick={() => navigate('/')}
          className="mt-5 inline-flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground"
        >
          <MessageSquarePlus className="h-4 w-4" /> Start a conversation
        </button>
      </CenterNote>
    );
  }

  return (
    <div className="min-h-0 flex-1 overflow-y-auto">
      <ReflectionOverlay />
      <div className="mx-auto w-full max-w-5xl px-4 py-10 md:px-8 md:py-14">

        {/* 01 — Hero */}
        <section aria-label="Overall understanding" className="mb-16 md:mb-20">
          <UnderstandingRing model={model} />
        </section>

        {/* 02 — What Aqua learned (the magic — kept high on the page) */}
        <section className="mb-14">
          <SectionHeader eyebrow="Live" title="What Aqua learned recently" />
          <LearningFeed learnings={learnings} reflections={model.reflections} />
        </section>

        {/* 03 — Identity */}
        <section className="mb-14">
          <SectionHeader eyebrow="Who you are" title="Identity" />
          <IdentitySection beliefs={model.identity} onSelect={setSelected} />
        </section>

        {/* 04 — Goals */}
        <section className="mb-14">
          <SectionHeader eyebrow="Direction" title="Current goals" />
          <GoalsSection goals={model.goals} />
        </section>

        {/* 05 — Working memory */}
        <section className="mb-14">
          <SectionHeader eyebrow="Right now" title="Aqua’s attention" />
          <WorkingMemorySection model={model} />
        </section>

        {/* 06+07 — Knowledge / Communication */}
        <div className="mb-14 grid grid-cols-1 gap-10 lg:grid-cols-2">
          <section>
            <SectionHeader eyebrow="What you know" title="Knowledge" />
            <KnowledgeSection beliefs={model.knowledge} onSelect={setSelected} />
          </section>
          <section>
            <SectionHeader eyebrow="How to talk to you" title="Communication style" />
            <CommunicationSection beliefs={model.communication} decision={model.decision} onSelect={setSelected} />
          </section>
        </div>

        {/* 08 — Predictions */}
        <section className="mb-14">
          <SectionHeader eyebrow="Forecast" title="What Aqua expects next" />
          <PredictionsSection predictions={model.predictions} />
        </section>

        {/* 09 — Relationships */}
        <section className="mb-14">
          <SectionHeader eyebrow="Connected knowledge" title="Your world, mapped" />
          <RelationshipGraph />
        </section>

        {/* 10+11 — Timeline / Evolution */}
        <div className="mb-14 grid grid-cols-1 gap-10 lg:grid-cols-2">
          <section>
            <SectionHeader eyebrow="The story so far" title="Timeline" />
            <MindTimeline timeline={model.timeline} />
          </section>
          <section>
            <SectionHeader eyebrow="Growth" title="Mind evolution" />
            <EvolutionHeatmap model={model} />
          </section>
        </div>

        {/* 12 — Privacy */}
        <section className="mb-10">
          <SectionHeader eyebrow="Yours" title="Privacy & control" />
          <PrivacyPanel model={model} />
        </section>

        <p className="pb-6 text-center text-xs text-foreground-secondary">
          Tap any belief to see the evidence behind it — or to change it.
        </p>
      </div>

      <BeliefDrawer belief={selected} onClose={() => setSelected(null)} />
    </div>
  );
}

function CenterNote({ children }: { children: React.ReactNode }) {
  return (
    <div className="flex min-h-0 flex-1 items-center justify-center overflow-y-auto p-8 text-center text-sm text-foreground-secondary">
      <div>{children}</div>
    </div>
  );
}

import { useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { MessageList } from '@/components/chat/MessageList';
import { EmptyState } from '@/components/chat/EmptyState';
import { Composer } from '@/components/chat/Composer';
import { WorkspaceDashboard } from '@/components/workspace/WorkspaceDashboard';
import { useChatStore } from '@/stores/chatStore';
import { useUploadStore } from '@/stores/uploadStore';

export function ChatPage() {
  const { conversationId: routeId } = useParams<{ conversationId: string }>();
  const navigate = useNavigate();
  const storeConversationId = useChatStore((s) => s.conversationId);
  const messages = useChatStore((s) => s.messages);
  const loadConversation = useChatStore((s) => s.loadConversation);
  const newConversation = useChatStore((s) => s.newConversation);
  const lastLoadedRef = useRef<string | null>(null);

  useEffect(() => {
    if (routeId && routeId !== lastLoadedRef.current) {
      lastLoadedRef.current = routeId;
      loadConversation(routeId);
    } else if (!routeId && storeConversationId) {
      // Navigated to "/" (New chat) while a conversation was active.
      lastLoadedRef.current = null;
      newConversation();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [routeId]);

  useEffect(() => {
    // First send on "/" just minted a conversationId server-side — reflect
    // it in the URL so refresh, back/forward, and sidebar highlighting all
    // stay in sync with what's actually loaded.
    if (!routeId && storeConversationId) {
      lastLoadedRef.current = storeConversationId;
      navigate(`/c/${storeConversationId}`, { replace: true });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [storeConversationId]);

  const showEmptyState = !routeId && messages.length === 0;

  // Workspace dashboard becomes the landing page after an upload: shown
  // whenever an overview exists, the user hasn't dismissed it, and no
  // conversation is on screen yet. First message (or clicking a suggested
  // question) hands the screen back to the message list.
  const overview = useUploadStore((s) => s.overview);
  const showDashboard = useUploadStore((s) => s.showDashboard);
  const dashboardVisible = showDashboard && !!overview && messages.length === 0;

  return (
    <div className="flex min-h-0 flex-1 flex-col">
      {dashboardVisible ? (
        <WorkspaceDashboard overview={overview} />
      ) : showEmptyState ? (
        <EmptyState />
      ) : (
        <MessageList />
      )}
      <Composer />
    </div>
  );
}

