"use strict";
/**
 * models/Transaction.js
 * AQUIPLEX v2 — Immutable credit ledger entry.
 *
 * Every credit movement creates one Transaction document.
 * Never update/delete transactions — append-only for audit integrity.
 *
 * Types:
 *   DAILY_FREE_GRANT   — system grants free daily credits (lazy on first use each day)
 *   PURCHASE           — paid pack purchased via Razorpay
 *   DEBIT              — credits consumed by AI action
 *   REFUND             — credits returned after failed generation
 *   ADMIN_ADJUST       — manual admin correction
 *   REFERRAL_BONUS     — future referral reward
 */

const mongoose = require("mongoose");

const transactionSchema = new mongoose.Schema(
  {
    user: {
      type:     mongoose.Schema.Types.ObjectId,
      ref:      "User",
      required: true,
      index:    true,
    },

    type: {
      type:     String,
      enum:     ["DAILY_FREE_GRANT", "PURCHASE", "DEBIT", "REFUND", "ADMIN_ADJUST", "REFERRAL_BONUS"],
      required: true,
      index:    true,
    },

    // Credit movement (positive = gain, negative = spend)
    amount: { type: Number, required: true },

    // Snapshot after this transaction
    balanceAfter: {
      freeCredits: { type: Number, required: true },
      paidCredits: { type: Number, required: true },
    },

    // For PURCHASE transactions — links to Payment
    paymentId: {
      type:  mongoose.Schema.Types.ObjectId,
      ref:   "Payment",
    },

    // For DEBIT transactions — what AI action consumed credits
    actionType:  { type: String, default: null },
    actionCost:  { type: Number, default: null },

    // Description for user-facing history
    description: { type: String, default: "" },

    // Source breakdown (for DEBIT: how many from free vs paid)
    breakdown: {
      fromFree: { type: Number, default: 0 },
      fromPaid: { type: Number, default: 0 },
    },

    metadata: { type: mongoose.Schema.Types.Mixed, default: {} },
  },
  {
    timestamps: true,
    // No updates allowed — append only
  }
);

transactionSchema.index({ user: 1, createdAt: -1 });
transactionSchema.index({ paymentId: 1 }, { sparse: true });

module.exports =
  mongoose.models.Transaction ||
  mongoose.model("Transaction", transactionSchema);

"use strict";
/**
 * models/User.js
 * AQUIPLEX v2 — Prepaid Credits / Wallet Model
 *
 * BREAKING CHANGES from v1:
 *   - Removed: plan, subscriptionStatus, currentPeriodEnd, subscriptionCancelledAt
 *   - Removed: cashfreeOrderId, cashfreeSubscriptionId, cashfreeCustomerId
 *   - Removed: razorpaySubscriptionId, razorpayCustomerId
 *   - Removed: monthlyCredits, creditsResetAt (no monthly allocation)
 *   - Added:   wallet.freeCredits     — today's free quota (resets daily)
 *   - Added:   wallet.paidCredits     — purchased credits (never expire)
 *   - Added:   wallet.freeResetAt     — next daily reset timestamp
 *   - Added:   wallet.totalEarned     — lifetime paid credits purchased
 *   - Added:   wallet.totalSpent      — lifetime credits consumed
 *   - Added:   wallet.freeFullBuildUsed — tracks if free build was used this cycle
 *   - Added:   wallet.aiEditLockedUntil — AI editing locked until this timestamp
 *
 * Consumption order: freeCredits first → paidCredits
 */

const mongoose = require("mongoose");
const crypto   = require("crypto");
const { hasUnlimitedAccess, unlimitedAccessReason } = require("../utils/credits/unlimitedAccess");
const { getISTDateStr, nextISTMidnight } = require("../utils/date/getISTDayRange");

const FREE_DAILY_CREDITS = parseInt(process.env.FREE_DAILY_CREDITS || "200", 10);

// ── Per-feature daily limits (free tier) ─────────────────────────────────────
const FREE_LIMITS = {
  imageGen:    parseInt(process.env.FREE_LIMIT_IMAGE    || "2",  10),
  codeMode:    parseInt(process.env.FREE_LIMIT_CODE     || "1",  10),
  webSearch:   parseInt(process.env.FREE_LIMIT_SEARCH   || "3",  10),
  websiteGen:  parseInt(process.env.FREE_LIMIT_WEBSITE  || "1",  10),
  websiteEdit: parseInt(process.env.FREE_LIMIT_WEBEDIT  || "2",  10),
};

const dailyUsageSchema = new mongoose.Schema({
  date:        { type: String, default: () => todayStr() }, // "YYYY-MM-DD"
  imageGen:    { type: Number, default: 0, min: 0 },
  codeMode:    { type: Number, default: 0, min: 0 },
  webSearch:   { type: Number, default: 0, min: 0 },
  websiteGen:  { type: Number, default: 0, min: 0 },
  websiteEdit: { type: Number, default: 0, min: 0 },
}, { _id: false });

const walletSchema = new mongoose.Schema(
  {
    freeCredits: {
      type: Number,
      default: FREE_DAILY_CREDITS,
      min: 0,
    },

    paidCredits: {
      type: Number,
      default: 0,
      min: 0,
    },

    freeResetAt: {
      type: Date,
      default: () => nextDayReset(),
    },

    totalEarned: {
      type: Number,
      default: 0,
      min: 0,
    },

    totalSpent: {
      type: Number,
      default: 0,
      min: 0,
    },
  }
);

const userSchema = new mongoose.Schema(
  {
    email:    { type: String, required: true, unique: true, lowercase: true, trim: true },
    password: { type: String, required: true },
    googleId: { type: String, default: null, sparse: true },
    role: { type: String, default: "user", index: true },
    isUnlimited: { type: Boolean, default: false },

    // ── Wallet ──────────────────────────────────────────────────────────────
    wallet: { type: walletSchema, default: () => ({}) },

    // ── Daily feature usage counters (free tier) ─────────────────────────────
    dailyUsage: { type: dailyUsageSchema, default: () => ({}) },

    // ── Profile ─────────────────────────────────────────────────────────────
    billingEmail: { type: String, default: null },
    phone:        { type: String, default: null },

    // ── Referral (keep for future) ──────────────────────────────────────────
    referralCode: { type: String, default: null, unique: true, sparse: true },
    referredBy:   { type: mongoose.Schema.Types.ObjectId, ref: "User", default: null },
  },
  { timestamps: true }
);

// ── Pre-save: generate referral code ─────────────────────────────────────────

userSchema.pre("save", function () {
  if (!this.referralCode) {
    this.referralCode = crypto.randomBytes(4).toString("hex").toUpperCase();
  }
});

// ── Access helpers ────────────────────────────────────────────────────────────

userSchema.methods.hasUnlimitedAccount = function () {
  return hasUnlimitedAccess(this);
};

userSchema.methods.unlimitedAccessReason = function () {
  return unlimitedAccessReason(this);
};

// ── Wallet methods ─────────────────────────────────────────────────────────────

/**
 * resetFreeCreditsIfNeeded — lazy daily reset.
 * Returns true if reset occurred.
 */
userSchema.methods.resetFreeCreditsIfNeeded = function () {
  if (this.hasUnlimitedAccount()) return false;
  const now = new Date();
  if (this.wallet.freeResetAt && now >= this.wallet.freeResetAt) {
    this.wallet.freeCredits = FREE_DAILY_CREDITS;
    this.wallet.freeResetAt = nextDayReset();



    return true;
  }
  return false;
};

/**
 * totalAvailableCredits — free + paid.
 */
userSchema.methods.totalAvailableCredits = function () {
  if (this.hasUnlimitedAccount()) return Number.MAX_SAFE_INTEGER;
  this.resetFreeCreditsIfNeeded();
  return this.wallet.freeCredits + this.wallet.paidCredits;
};

/**
 * hasEnoughCredits — check without mutating.
 */
userSchema.methods.hasEnoughCredits = function (cost) {
  if (this.hasUnlimitedAccount()) return true;
  this.resetFreeCreditsIfNeeded();
  return this.totalAvailableCredits() >= cost;
};

/**
 * deductCredits — consume free first, then paid.
 * DOES NOT save — caller must save() to allow atomic handling.
 * Throws if insufficient.
 */
userSchema.methods.deductCredits = function (cost) {
  if (this.hasUnlimitedAccount()) return;
  this.resetFreeCreditsIfNeeded();
  const total = this.wallet.freeCredits + this.wallet.paidCredits;
  if (total < cost) throw new Error("INSUFFICIENT_CREDITS");

  // Consume free first
  const fromFree = Math.min(this.wallet.freeCredits, cost);
  this.wallet.freeCredits -= fromFree;
  const remainder = cost - fromFree;
  if (remainder > 0) {
    this.wallet.paidCredits -= remainder;
  }
  this.wallet.totalSpent += cost;
};

/**
 * addPaidCredits — add purchased credits, update totalEarned.
 * DOES NOT save — caller must save().
 */
userSchema.methods.addPaidCredits = function (amount) {
  this.wallet.paidCredits += amount;
  this.wallet.totalEarned += amount;
};

/**
 * walletSummary — safe public-facing snapshot.
 */
userSchema.methods.walletSummary = function () {
  this.resetFreeCreditsIfNeeded();
  return {
    freeCredits:  this.wallet.freeCredits,
    paidCredits:  this.wallet.paidCredits,
    totalCredits: this.wallet.freeCredits + this.wallet.paidCredits,
    freeResetAt:  this.wallet.freeResetAt,
    freeDailyMax: FREE_DAILY_CREDITS,
    totalEarned:  this.wallet.totalEarned,
    totalSpent:   this.wallet.totalSpent,
    isUnlimited:  this.hasUnlimitedAccount(),
    unlimitedReason: this.unlimitedAccessReason(),
    dailyUsage:   this.getDailyUsageSnapshot(),
    freeLimits:   FREE_LIMITS,
  };
};

// ── Daily feature usage methods ───────────────────────────────────────────────

/**
 * resetDailyUsageIfNeeded — lazy daily reset for feature counters.
 */
userSchema.methods.resetDailyUsageIfNeeded = function () {
  const today = todayStr();
  if (!this.dailyUsage || this.dailyUsage.date !== today) {
    this.dailyUsage = {
      date:        today,
      imageGen:    0,
      codeMode:    0,
      webSearch:   0,
      websiteGen:  0,
      websiteEdit: 0,
    };
    return true;
  }
  return false;
};

/**
 * checkFeatureLimit — returns { allowed, used, limit, feature }.
 * Does NOT increment. Call incrementFeatureUsage after successful action.
 */
userSchema.methods.checkFeatureLimit = function (feature) {
  if (this.hasUnlimitedAccount()) return { allowed: true, used: 0, limit: Infinity, feature };
  this.resetDailyUsageIfNeeded();
  const limit = FREE_LIMITS[feature];
  if (limit === undefined) return { allowed: true, used: 0, limit: Infinity, feature };
  const used = this.dailyUsage[feature] || 0;
  return { allowed: used < limit, used, limit, feature };
};

/**
 * incrementFeatureUsage — bump counter. DOES NOT save.
 */
userSchema.methods.incrementFeatureUsage = function (feature) {
  if (this.hasUnlimitedAccount()) return;
  this.resetDailyUsageIfNeeded();
  if (this.dailyUsage[feature] !== undefined) {
    this.dailyUsage[feature] += 1;
  }
};

/**
 * getDailyUsageSnapshot — public snapshot of today's usage + limits.
 */
userSchema.methods.getDailyUsageSnapshot = function () {
  this.resetDailyUsageIfNeeded();
  const snapshot = {};
  for (const [key, limit] of Object.entries(FREE_LIMITS)) {
    snapshot[key] = {
      used:      this.dailyUsage[key] || 0,
      limit,
      remaining: Math.max(0, limit - (this.dailyUsage[key] || 0)),
    };
  }
  return snapshot;
};

// ── Helpers ───────────────────────────────────────────────────────────────────

function nextDayReset() {
  // Use IST midnight so Indian users reset at 00:00 IST, not 00:00 UTC (05:30 IST)
  return nextISTMidnight();
}

function todayStr() {
  // Use IST date string so "today" matches the IST calendar day
  return getISTDateStr(); // "YYYY-MM-DD" in IST
}

module.exports = mongoose.model("User", userSchema);

"use strict";
/**
 * models/Payment.js
 * AQUIPLEX v2 — Razorpay one-time payment record.
 *
 * CRITICAL INDEX NOTES:
 *   - webhookId MUST NOT have default: null — MongoDB indexes null in sparse+unique indexes.
 *   - webhookId sparse+unique defined ONLY at schema field level (not via paymentSchema.index()).
 *   - razorpayPaymentId sparse index defined at field level, no default: null.
 *   - This file is the SINGLE authoritative Payment model.
 */

const mongoose = require("mongoose");

const paymentSchema = new mongoose.Schema(
  {
    user: {
      type:     mongoose.Schema.Types.ObjectId,
      ref:      "User",
      required: true,
      index:    true,
    },

    // Credit pack identifier
    packId: {
      type:     String,
      enum:     ["starter", "growth", "pro", "max"],
      required: true,
    },

    // Amount in paise (₹49 = 4900 paise)
    amountPaise:  { type: Number, required: true },
    creditsToAdd: { type: Number, required: true },

    // Razorpay identifiers
    razorpayOrderId: {
      type:     String,
      required: true,
      unique:   true,
    },

    // sparse: true → field OMITTED from index when value is absent (undefined).
    // DO NOT set default: null — null is indexed and causes E11000 on second null.
    razorpayPaymentId: {
      type:   String,
      sparse: true,
      unique: false, // not unique — retries may reuse same paymentId
    },

    razorpaySignature: { type: String },

    status: {
      type:    String,
      enum:    ["created", "pending", "success", "failed"],
      default: "created",
      index:   true,
    },

    // Set when webhook/verify confirms payment
    paidAt: { type: Date },

    // Idempotency — prevent double credit on duplicate webhooks.
    // sparse: true → documents WITHOUT webhookId are excluded from unique index.
    // NEVER set default: null — that defeats the sparse index entirely.
    webhookId: {
      type:   String,
      sparse: true,
      unique: true,
    },

    // Set atomically when credits are added — primary idempotency guard.
    creditedAt: { type: Date },

    // Failure info
    failureReason: { type: String },

    metadata: { type: mongoose.Schema.Types.Mixed, default: {} },
  },
  { timestamps: true }
);

// Compound index for payment history queries
paymentSchema.index({ user: 1, createdAt: -1 });

// NOTE: razorpayOrderId unique index is defined inline above (unique: true).
// DO NOT add paymentSchema.index({ razorpayOrderId: 1 }) here — duplicate index warning.

// NOTE: webhookId sparse+unique is defined inline above.
// DO NOT add paymentSchema.index({ webhookId: 1 }, { unique: true, sparse: true }) here.
// Defining it both inline AND via paymentSchema.index() creates duplicate conflicting indexes.

module.exports =
  mongoose.models.Payment ||
  mongoose.model("Payment", paymentSchema);

const mongoose = require("mongoose");

// ─────────────────────────────────────────────────────────────────────────────
// Sub-schemas
// ─────────────────────────────────────────────────────────────────────────────

const DecisionSchema = new mongoose.Schema({
  stepIndex:   { type: Number, required: true },
  question:    { type: String, default: "" },
  chosen:      { type: String, default: "" },
  rationale:   { type: String, default: "" },
  timestamp:   { type: Date,   default: Date.now },
}, { _id: false });

const OutputSchema = new mongoose.Schema({
  stepIndex:   { type: Number, required: true },
  title:       { type: String, default: "" },
  content:     { type: String, default: "" },           // Full AI-generated deliverable
  keyInsights: { type: [String], default: [] },         // Extracted insights fed to next step
  nextStepHints: { type: [String], default: [] },       // Dynamic refinements for following steps
  tokensUsed:  { type: Number, default: 0 },
  executedAt:  { type: Date,   default: Date.now },
  durationMs:  { type: Number, default: 0 },
}, { _id: false });

const ProgressSchema = new mongoose.Schema({
  step:   { type: Number, required: true },
  status: {
    type:    String,
    enum:    ["pending", "in-progress", "completed", "failed"],
    default: "pending",
  },
  startedAt:   { type: Date },
  completedAt: { type: Date },
}, { _id: false });

// ─────────────────────────────────────────────────────────────────────────────
// Core Bundle Schema
// ─────────────────────────────────────────────────────────────────────────────

const BundleSchema = new mongoose.Schema(
  {
    userId: {
      type: mongoose.Schema.Types.ObjectId,
      ref:  "User",
      required: true,
      index: true,
    },

    // ── Identity ──────────────────────────────────────────────────────────────
    title:       { type: String, required: true, trim: true },
    goal:        { type: String, default: "" },      // Raw user goal fed into context engine
    answers:     { type: [String], default: [] },    // Onboarding answers from step 1

    // ── Steps (static plan) ───────────────────────────────────────────────────
    steps: { type: Array, default: [] },

    // ── Execution memory ──────────────────────────────────────────────────────
    decisions:      { type: [DecisionSchema], default: [] },
    outputs:        { type: [OutputSchema],   default: [] },
    progress:       { type: [ProgressSchema], default: [] },

    // ── Context engine ────────────────────────────────────────────────────────
    // Rolling summary kept under ~500 tokens — injected at the top of every step prompt
    contextSummary: { type: String, default: "" },

    // Persistent key-value memory that grows across executions
    // e.g. { "target_audience": "indie hackers", "tech_stack": "Node + React" }
    memory: {
      type: Map,
      of:   String,
      default: {},
    },

    // ── State ─────────────────────────────────────────────────────────────────
    currentStep: { type: Number, default: 0 },
    status: {
      type:    String,
      enum:    ["draft", "active", "completed", "paused"],
      default: "draft",
    },
    completedAt: { type: Date },
  },
  {
    timestamps: true,        // createdAt, updatedAt
    minimize:   false,       // preserve empty Maps
  }
);

// ─────────────────────────────────────────────────────────────────────────────
// Virtuals
// ─────────────────────────────────────────────────────────────────────────────

BundleSchema.virtual("completionPercent").get(function () {
  if (!this.steps || this.steps.length === 0) return 0;
  const done = this.progress.filter((p) => p.status === "completed").length;
  return Math.round((done / this.steps.length) * 100);
});

BundleSchema.virtual("lastOutput").get(function () {
  if (!this.outputs || this.outputs.length === 0) return null;
  return this.outputs[this.outputs.length - 1];
});

BundleSchema.set("toJSON",   { virtuals: true });
BundleSchema.set("toObject", { virtuals: true });

// ─────────────────────────────────────────────────────────────────────────────
// Instance helpers
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Mark a step as started.
 */
BundleSchema.methods.markStepStarted = function (stepIndex) {
  const p = this.progress.find((p) => p.step === stepIndex);
  if (p) {
    p.status    = "in-progress";
    p.startedAt = new Date();
  }
  this.currentStep = stepIndex;
  this.status      = "active";
};

/**
 * Mark a step as completed and persist its output.
 */
BundleSchema.methods.markStepCompleted = function (stepIndex, outputData) {
  const p = this.progress.find((p) => p.step === stepIndex);
  if (p) {
    p.status      = "completed";
    p.completedAt = new Date();
  }

  // Remove old output for this step (re-execution support)
  this.outputs = this.outputs.filter((o) => o.stepIndex !== stepIndex);
  this.outputs.push({ stepIndex, ...outputData });

  // Advance pointer
  const nextStep = stepIndex + 1;
  if (nextStep < this.steps.length) {
    this.currentStep = nextStep;
  } else {
    this.status      = "completed";
    this.completedAt = new Date();
  }
};

/**
 * Append a key insight into the persistent memory map.
 */
BundleSchema.methods.mergeMemory = function (newEntries = {}) {
  for (const [k, v] of Object.entries(newEntries)) {
