 * utils/date/getISTDayRange.js
 * AQUIPLEX — IST (Asia/Kolkata, UTC+5:30) day boundary helpers.
 *
 * All daily reset logic MUST use these helpers to avoid UTC/local ambiguity.
 * India is UTC+5:30. A new calendar day starts at 00:00 IST = 18:30 UTC previous day.
 *
 * Exports:
 *   getISTDayRange()  → { start: Date, end: Date }   (UTC Date objects for Mongo queries)
 *   getISTDateStr()   → "YYYY-MM-DD" string in IST
 *   nextISTMidnight() → Date (UTC) of next IST midnight
 *
 * Usage:
 *   const { start, end } = getISTDayRange();
 *   User.find({ createdAt: { $gte: start, $lt: end } })
 */

const IST_OFFSET_MS = 5.5 * 60 * 60 * 1000; // 5h 30m in ms

/**
 * nowIST — current UTC time shifted to IST wall-clock.
 * This is a "fake" local Date; only use for arithmetic, not display.
 */
function nowIST() {
  return new Date(Date.now() + IST_OFFSET_MS);
}

/**
 * getISTDateStr — returns current date as "YYYY-MM-DD" in IST timezone.
 * Fixes User.js todayStr() which used UTC.
 */
function getISTDateStr() {
  return nowIST().toISOString().slice(0, 10); // "YYYY-MM-DD" in IST wall clock
}

/**
 * nextISTMidnight — returns the next IST midnight as a UTC Date.
 * Fixes User.js nextDayReset() which used server local time setHours(0,0,0,0).
 *
 * Algorithm:
 *   1. Get current IST wall-clock date
 *   2. Advance to tomorrow at 00:00 IST
 *   3. Convert back to UTC (subtract IST_OFFSET_MS)
 */
function nextISTMidnight() {
  const ist = nowIST(); // shifted to IST wall clock
  // Build tomorrow 00:00:00.000 IST (as if it were UTC)
  const tomorrowIST = new Date(Date.UTC(
    ist.getUTCFullYear(),
    ist.getUTCMonth(),
    ist.getUTCDate() + 1,
    0, 0, 0, 0
  ));
  // Convert IST wall-clock midnight → actual UTC
  return new Date(tomorrowIST.getTime() - IST_OFFSET_MS);
}

/**
 * getISTDayRange — start/end UTC boundaries for the current IST calendar day.
 *
 * start = today 00:00 IST in UTC
 * end   = tomorrow 00:00 IST in UTC  (exclusive upper bound)
 */
function getISTDayRange() {
  const ist = nowIST();

  // Today 00:00:00.000 IST → UTC
  const startIST = new Date(Date.UTC(
    ist.getUTCFullYear(),
    ist.getUTCMonth(),
    ist.getUTCDate(),
    0, 0, 0, 0
  ));
  const start = new Date(startIST.getTime() - IST_OFFSET_MS);

  // Tomorrow 00:00:00.000 IST → UTC
  const endIST = new Date(Date.UTC(
    ist.getUTCFullYear(),
    ist.getUTCMonth(),
    ist.getUTCDate() + 1,
    0, 0, 0, 0
  ));
  const end = new Date(endIST.getTime() - IST_OFFSET_MS);

  return { start, end };
}

module.exports = {
  getISTDayRange,
  getISTDateStr,
  nextISTMidnight,
};

"use strict";

/**
 * utils/validate.js — Input validation helpers for AQUIPLEX routes
 */

/**
 * validateAquaExecute — validates POST /aqua/execute body
 * @returns {{ valid: boolean, error?: string }}
 */
function validateAquaExecute({ message, projectId, fileName } = {}) {
  if (!message || typeof message !== "string" || !message.trim()) {
    return { valid: false, error: "message is required and must be a non-empty string" };
  }
  if (message.trim().length > 4000) {
    return { valid: false, error: "message must be under 4000 characters" };
  }
  if (projectId !== undefined && projectId !== null) {
    if (typeof projectId !== "string" || !projectId.trim()) {
      return { valid: false, error: "projectId must be a non-empty string" };
    }
  }
  if (fileName !== undefined && fileName !== null) {
    if (typeof fileName !== "string" || !fileName.trim()) {
      return { valid: false, error: "fileName must be a non-empty string" };
    }
    // Block path traversal
    if (fileName.includes("..") || fileName.includes("/") || fileName.includes("\\")) {
      return { valid: false, error: "fileName contains invalid characters" };
    }
  }
  return { valid: true };
}

/**
 * validateSaveFile — validates POST /workspace/save-file body
 */
function validateSaveFile({ projectId, fileName, content } = {}) {
  if (!projectId || typeof projectId !== "string" || !projectId.trim()) {
    return { valid: false, error: "projectId is required" };
  }
  if (!fileName || typeof fileName !== "string" || !fileName.trim()) {
    return { valid: false, error: "fileName is required" };
  }
  if (fileName.includes("..") || fileName.includes("/") || fileName.includes("\\")) {
    return { valid: false, error: "fileName contains invalid characters" };
  }
  if (content === undefined || content === null) {
    return { valid: false, error: "content is required" };
  }
  return { valid: true };
}

/**
 * validateEditFile — validates POST /workspace/edit-file body
 */
function validateEditFile({ projectId, fileName, instruction } = {}) {
  if (!projectId || typeof projectId !== "string" || !projectId.trim()) {
    return { valid: false, error: "projectId is required" };
  }
  if (!fileName || typeof fileName !== "string" || !fileName.trim()) {
    return { valid: false, error: "fileName is required" };
  }
  if (fileName.includes("..") || fileName.includes("/") || fileName.includes("\\")) {
    return { valid: false, error: "fileName contains invalid characters" };
  }
  if (!instruction || typeof instruction !== "string" || !instruction.trim()) {
    return { valid: false, error: "instruction is required" };
  }
  return { valid: true };
}

module.exports = { validateAquaExecute, validateSaveFile, validateEditFile };

"use strict";

/**
 * utils/placeholder.detector.js — SHARED PLACEHOLDER DETECTION
 *
 * Superset pattern list combining the placeholder checks already living in
 * buildProjectV2.js (_hasPlaceholder) and brain.learning.pipeline.js
 * (_hasPlaceholderContent). Those two stay as-is to avoid touching working
 * call sites — this is a new, separate export for the one gap that had no
 * check at all: file.generator.js accepting brain-retrieved content without
 * ever screening it for placeholder text before it lands in a project file.
 *
 * Not a refactor of the existing checkers — an additional gate for a path
 * that previously had none.
 */

const PLACEHOLDER_PATTERNS = [
  /lorem ipsum/i,
  /coming soon/i,
  /sample (project|data)/i,
  /dummy content/i,
  /insert content here/i,
  /project (title|description)/i,
  /your application is being prepared/i,
  /src=["'](placeholder|your-image|undefined)["']/i,
  /\[YOUR\s+(CODE|CONTENT|TEXT)\s+HERE\]/i,
  /\bTODO\b|\bFIXME\b/,
  // Loading-only page text (not attribute values)
  /<[^>]+>\s*Loading[^<]{0,40}[.]{3}/,
  // Hardcoded localhost in fetch/href/src calls
  /fetch\s*\(\s*["']http:\/\/localhost/i,
];

/**
 * hasPlaceholder(content) → boolean
 */
function hasPlaceholder(content) {
  if (!content || typeof content !== "string") return false;
  return PLACEHOLDER_PATTERNS.some((re) => re.test(content));
}

module.exports = { hasPlaceholder, PLACEHOLDER_PATTERNS };

"use strict";
/**
 * utils/startup.js
 * AQUIPLEX — Startup validation and index self-healing.
 *
 * Call await runStartupChecks() inside startServer() after connectDB().
 *
 * Self-heals:
 *   - Drops bad webhookId indexes (non-sparse, or sparse with null entries)
 *   - Recreates correct sparse+unique index
 *   - Validates required env variables
 *   - Logs index health report
 */

const mongoose = require("mongoose");

// ── Env validation ────────────────────────────────────────────────────────────

const REQUIRED_ENV = [
  "MONGO_URI",
  "RAZORPAY_KEY_ID",
  "RAZORPAY_KEY_SECRET",
  "RAZORPAY_WEBHOOK_SECRET",
  "SESSION_SECRET",
];

function validateEnv() {
  const missing = REQUIRED_ENV.filter((k) => !process.env[k]);
  if (missing.length > 0) {
    console.error("❌ STARTUP FAILED — Missing required env variables:");
    missing.forEach((k) => console.error(`   - ${k}`));
    process.exit(1);
  }
  console.log("✅ Env vars validated");
}

// ── Index self-healing ────────────────────────────────────────────────────────

/**
 * fixPaymentIndexes
 *
 * Inspects the payments collection for:
 *   1. Any webhookId index that is NOT sparse (causes E11000 on null)
 *   2. Duplicate index definitions for webhookId
 *
 * Drops bad indexes, then ensures correct index exists.
 */
async function fixPaymentIndexes() {
  const db = mongoose.connection.db;
  if (!db) {
    console.warn("⚠️  fixPaymentIndexes: mongoose not connected");
    return;
  }

  const collection = db.collection("payments");
  let indexes;
  try {
    indexes = await collection.indexes();
  } catch (err) {
    console.warn("⚠️  fixPaymentIndexes: could not list indexes:", err.message);
    return;
  }

  console.log(`📋 payments indexes found: ${indexes.length}`);

  const webhookIndexes = indexes.filter(
    (idx) => idx.key && idx.key.webhookId !== undefined
  );

  let needsDrop = false;
  for (const idx of webhookIndexes) {
    const isSparse = !!idx.sparse;
    const isUnique = !!idx.unique;
    const name     = idx.name;

    if (!isSparse) {
      console.warn(`⚠️  BAD INDEX: ${name} on webhookId is NOT sparse. Dropping...`);
      needsDrop = true;
      try {
        await collection.dropIndex(name);
        console.log(`✅ Dropped bad index: ${name}`);
      } catch (e) {
        console.error(`❌ Failed to drop index ${name}:`, e.message);
      }
    } else if (!isUnique) {
      console.warn(`⚠️  BAD INDEX: ${name} on webhookId is sparse but NOT unique. Dropping...`);
      needsDrop = true;
      try {
        await collection.dropIndex(name);
        console.log(`✅ Dropped bad index: ${name}`);
      } catch (e) {
        console.error(`❌ Failed to drop index ${name}:`, e.message);
      }
    } else {
      console.log(`✅ webhookId index OK: ${name} (sparse=${isSparse} unique=${isUnique})`);
    }
  }

  // Purge null webhookId values from existing documents (from before the fix)
  // Set null → undefined (unset) so sparse index excludes them
  try {
    const result = await collection.updateMany(
      { webhookId: null },
      { $unset: { webhookId: "" } }
    );
    if (result.modifiedCount > 0) {
      console.log(`✅ Cleared ${result.modifiedCount} documents with webhookId=null`);
    }
  } catch (e) {
    console.warn("⚠️  Could not clear null webhookIds:", e.message);
  }

  // Also clear null razorpayPaymentId values (sparse index field)
  try {
    await collection.updateMany(
      { razorpayPaymentId: null },
      { $unset: { razorpayPaymentId: "" } }
    );
  } catch (_) {}

  // Let Mongoose sync indexes (creates missing ones, no-ops on existing correct ones)
  try {
    const Payment = require("../models/Payment");
    await Payment.syncIndexes();
    console.log("✅ Payment model indexes synced");
  } catch (e) {
    console.error("❌ Payment.syncIndexes() failed:", e.message);
  }
}

/**
 * fixWebhookLogIndexes
 * Ensures WebhookLog idempotencyKey index is healthy.
 */
async function fixWebhookLogIndexes() {
  try {
    const WebhookLog = require("../models/WebhookLog");
    await WebhookLog.syncIndexes();
    console.log("✅ WebhookLog model indexes synced");
  } catch (e) {
    console.error("❌ WebhookLog.syncIndexes() failed:", e.message);
  }
}

// ── Main entry ────────────────────────────────────────────────────────────────

async function runStartupChecks() {
  console.log("─────────────────────────────────────────────");
  console.log("🔍 AQUIPLEX STARTUP CHECKS");
  console.log("─────────────────────────────────────────────");

  // 1. Env validation (exits process if missing critical vars)
  validateEnv();

  // 2. Razorpay key health (log only — don't exit, prod may be read-only env)
  console.log(`RAZORPAY_KEY_ID:         ${process.env.RAZORPAY_KEY_ID       ? "✅ OK" : "❌ MISSING"}`);
  console.log(`RAZORPAY_KEY_SECRET:     ${process.env.RAZORPAY_KEY_SECRET   ? "✅ OK" : "❌ MISSING"}`);
  console.log(`RAZORPAY_WEBHOOK_SECRET: ${process.env.RAZORPAY_WEBHOOK_SECRET ? "✅ OK" : "❌ MISSING"}`);
  console.log(`APP_URL:                 ${process.env.APP_URL || "⚠️  not set"}`);

  // 3. Database index self-healing
  await fixPaymentIndexes();
  await fixWebhookLogIndexes();

  console.log("─────────────────────────────────────────────");
  console.log("✅ Startup checks complete");
  console.log("─────────────────────────────────────────────");
}

module.exports = { runStartupChecks, validateEnv, fixPaymentIndexes };

"use strict";

/**
 * utils/file.validator.js — AQUIPLEX V5 File Validation Layer
 *
 * Validates AI-generated file content BEFORE any disk write.
 * Called by safeEditFiles() and generateProjectV2().
 *
 * Exports:
 *   validateFile(fileName, content)        → { valid, errors }
 *   validateFileSet(files)                 → { valid, files, errors }
 *   validateHtmlStructure(content)         → { valid, errors }
 */

const path = require("path");

// ─────────────────────────────────────────────────────────────────────────────
// CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────

const MIN_CONTENT_LENGTH = 10;
const MAX_CONTENT_LENGTH = 500_000; // 500KB per file hard cap

const ALLOWED_EXTENSIONS = new Set([
  ".html", ".htm", ".css", ".js", ".mjs", ".cjs",
  ".ts", ".json", ".svg", ".md", ".txt",
  ".env.example", // allow .env templates, never actual .env
]);

const BLOCKED_FILENAMES = new Set([
  ".env", ".env.local", ".env.production",
  "package-lock.json", "yarn.lock",
]);

// ─────────────────────────────────────────────────────────────────────────────
// INDIVIDUAL FILE VALIDATOR
// ─────────────────────────────────────────────────────────────────────────────

/**
 * validateFile(fileName, content)
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateFile(fileName, content) {
  const errors = [];

  // ── Name checks ────────────────────────────────────────────────────────────
  if (!fileName || typeof fileName !== "string") {
    return { valid: false, errors: ["fileName must be a non-empty string"] };
  }

  const baseName = path.basename(fileName).toLowerCase();
  const ext      = path.extname(baseName).toLowerCase();

  if (BLOCKED_FILENAMES.has(baseName)) {
    errors.push(`Blocked filename: ${baseName}`);
  }

  if (!ALLOWED_EXTENSIONS.has(ext) && ext !== "") {
    errors.push(`Disallowed extension: ${ext || "(none)"}`);
  }

  // Path traversal
  const normalized = path.normalize(fileName);
  if (normalized.includes("..") || normalized.startsWith("/")) {
    errors.push("Path traversal detected in fileName");
  }

  // ── Content checks ─────────────────────────────────────────────────────────
  if (content === null || content === undefined) {
    errors.push("content is null/undefined");
  } else if (typeof content !== "string") {
    errors.push(`content must be string, got ${typeof content}`);
  } else {
    if (content.trim().length < MIN_CONTENT_LENGTH) {
      errors.push(`content too short (${content.trim().length} chars, min ${MIN_CONTENT_LENGTH})`);
    }
    if (content.length > MAX_CONTENT_LENGTH) {
      errors.push(`content too large (${content.length} bytes, max ${MAX_CONTENT_LENGTH})`);
    }

    // Per-extension semantic checks
    if (ext === ".html" || ext === ".htm") {
      const htmlResult = validateHtmlStructure(content);
      if (!htmlResult.valid) errors.push(...htmlResult.errors);
    }

    if (ext === ".json") {
      try { JSON.parse(content); }
      catch (e) { errors.push(`Invalid JSON: ${e.message.slice(0, 80)}`); }
    }

    // Placeholder detection — reject obviously incomplete AI output
    const PLACEHOLDER_PATTERNS = [
      /\/\*\s*(TODO|FIXME|PLACEHOLDER|INSERT|ADD HERE)\s*\*\//i,
      /<!--\s*(TODO|FIXME|PLACEHOLDER|YOUR CODE HERE)\s*-->/i,
      /\[YOUR\s+(CODE|CONTENT|TEXT)\s+HERE\]/i,
    ];
    for (const re of PLACEHOLDER_PATTERNS) {
      if (re.test(content)) {
        errors.push(`Placeholder detected in ${fileName} — AI output incomplete`);
        break;
      }
    }
  }

  return { valid: errors.length === 0, errors };
}

// ─────────────────────────────────────────────────────────────────────────────
// HTML STRUCTURAL VALIDATOR
// ─────────────────────────────────────────────────────────────────────────────

/**
 * validateHtmlStructure(content)
 * Ensures index.html has required tags.
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateHtmlStructure(content) {
  const errors  = [];
  const lower   = content.toLowerCase();

  if (!lower.includes("<!doctype")) {
    errors.push("HTML missing <!DOCTYPE html>");
  }
  if (!lower.includes("<html")) {
    errors.push("HTML missing <html> tag");
  }
  if (!lower.includes("<head")) {
    errors.push("HTML missing <head> tag");
  }
  if (!lower.includes("<body")) {
    errors.push("HTML missing <body> tag");
  }
  if (!lower.includes("</body>")) {
    errors.push("HTML unclosed <body>");
  }
  if (!lower.includes("</html>")) {
    errors.push("HTML unclosed <html>");
  }
  if (!lower.includes("<meta charset")) {
    errors.push("HTML missing charset meta tag (risk: garbled content)");
  }

  // Blank body check — catches AI returning shell with empty body
  const bodyMatch = content.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
  if (bodyMatch && bodyMatch[1].trim().length < 5) {
    errors.push("HTML body is empty or near-empty — AI returned shell without content");
  }

  return { valid: errors.length === 0, errors };
}

// ─────────────────────────────────────────────────────────────────────────────
// FILE SET VALIDATOR
// ─────────────────────────────────────────────────────────────────────────────

/**
 * validateFileSet(files)
 * Validates array of { fileName, content }.
 * Returns sanitized list with per-file validity + set-level errors.
 *
 * @param {Array<{fileName: string, content: string}>} files
 * @returns {{
 *   valid:   boolean,
 *   files:   Array<{fileName, content, valid, errors}>,
 *   errors:  string[],
 *   summary: string,
 * }}
 */
function validateFileSet(files) {
  if (!Array.isArray(files) || files.length === 0) {
    return {
      valid:   false,
      files:   [],
      errors:  ["File set is empty or not an array"],
      summary: "FAIL: no files",
    };
  }

  const setErrors   = [];
  const annotated   = [];
  const fileNames   = new Set();

  for (const f of files) {
    const result = validateFile(f?.fileName, f?.content);
    annotated.push({
      fileName: f?.fileName || "(unknown)",
      content:  f?.content  || "",
      language: f?.language || "",
      valid:    result.valid,
      errors:   result.errors,
    });

    // Duplicate detection
    if (f?.fileName) {
      if (fileNames.has(f.fileName)) {
        setErrors.push(`Duplicate fileName: ${f.fileName}`);
      } else {
        fileNames.add(f.fileName);
      }
    }
  }

  // index.html required in any set containing HTML
  const hasHtml = annotated.some(f => f.fileName?.endsWith(".html") || f.fileName?.endsWith(".htm"));
  const hasIndex = annotated.some(f => f.fileName === "index.html");
  if (hasHtml && !hasIndex) {
    setErrors.push("File set contains HTML but no index.html — preview will fail");
  }

  const allValid = setErrors.length === 0 && annotated.every(f => f.valid);
  const badFiles = annotated.filter(f => !f.valid).map(f => f.fileName);

  const summary = allValid
    ? `OK: ${annotated.length} file(s) validated`
    : `FAIL: ${badFiles.length} invalid file(s) [${badFiles.join(", ")}]` +
      (setErrors.length ? ` | Set errors: ${setErrors.join("; ")}` : "");

  return { valid: allValid, files: annotated, errors: setErrors, summary };
}

// ─────────────────────────────────────────────────────────────────────────────
// EXPORTS
// ─────────────────────────────────────────────────────────────────────────────

module.exports = { validateFile, validateFileSet, validateHtmlStructure };

